INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(310835, 'zhTW', '', '真教人意外，洛索瑪竟然…接受了。\n\n或許我們真的說服他，永歌森林的安危全都依靠著與鄰居維持的良好關係了。不管他們是誰都一樣。', 66384),
(310653, 'zhTW', '', '坎莎開始輕摸炫牙。', 66384),
(310490, 'zhTW', '很高興聽到她平安抵達了！\n\n謝謝你。要是你想的話，就坐下來跟我休息一下吧。\n\n總是跑來跑去會讓你錯過一些微小的事物。', '很高興聽到她平安抵達了！\n\n謝謝你。要是你想的話，就坐下來跟我休息一下吧。\n\n總是跑來跑去會讓你錯過一些微小的事物。', 66384),
(310484, 'zhTW', '<這隻小水豚看起來又害怕又孤獨。>', '', 66384),
(310480, 'zhTW', '不過，你能幫我個忙嗎？\n\n那邊的最後一隻小水豚嚇壞了，對所有東西都怕得不行。我沒辦法把她哄出來。你可以帶她去菲洛聖壇嗎？找一個不錯的水池讓她好好玩耍。\n\n她怕的大部分都是大型生物，所以你可能沒辦法騎坐騎了。要靠雙腳把她送去那裡會是一場漫長的馬拉松…\n\n我想自己去，但我不能打擾到這些小傢伙！', '不過，你能幫我個忙嗎？\n\n那邊的最後一隻小水豚嚇壞了，對所有東西都怕得不行。我沒辦法把她哄出來。你可以帶她去菲洛聖壇嗎？找一個不錯的水池讓她好好玩耍。\n\n她怕的大部分都是大型生物，所以你可能沒辦法騎坐騎了。要靠雙腳把她送去那裡會是一場漫長的馬拉松…\n\n我想自己去，但我不能打擾到這些小傢伙！', 66384),
(310265, 'zhTW', '<一把斷裂的孩童尺寸匕首被放在一隻大角蛙和小水豚的屍體附近。\n\n你發現角蛙身上看起來有很多隻水豚的咬痕，以及數道用小型武器驚慌劃出的小傷口…疑似是用附近的那把斷裂匕首。\n\n通向角蛙並遠離的水豚腳印和小型食人妖足跡表明，角蛙在路上攔住了這個孩童和她的水豚夥伴。\n\n某人在附近的一隻水豚屍體周圍擺放了一些花朵，或許是為了哀悼牠的逝去。\n\n孩童的足跡繼續遠離小徑，向著河流而去，後面則跟著少了一組的水豚腳印。>', '<一把斷裂的孩童尺寸匕首被放在一隻大角蛙和小水豚的屍體附近。\n\n你發現角蛙身上看起來有很多隻水豚的咬痕，以及數道用小型武器驚慌劃出的小傷口…疑似是用附近的那把斷裂匕首。\n\n通向角蛙並遠離的水豚腳印和小型食人妖足跡表明，角蛙在路上攔住了這個孩童和她的水豚夥伴。\n\n某人在附近的一隻水豚屍體周圍擺放了一些花朵，或許是為了哀悼牠的逝去。\n\n孩童的足跡繼續遠離小徑，向著河流而去，後面則跟著少了一組的水豚腳印。>', 66384),
(310237, 'zhTW', '你看不出來我正忙著架設我的設備嗎？', '', 66384),
(310202, 'zhTW', '', '阿拉特已經把發生的事告訴我了。圖拉揚所做的…\n\n<艾蘭里亞的臉上閃過痛苦的神情。>\n\n他們怎麼可以把這件事瞞著我？還瞞了這麼久？', 66384),
(310200, 'zhTW', '原本我不想把阿曼尼小徑發生的事告訴艾蘭里亞，直到我們打敗薩拉塔斯。\n\n在與如此強大的敵人開戰的前夕，我們承擔不起思緒和心靈蒙上陰影產生的影響。', '', 66384),
(310045, 'zhTW', '$n，近來可好？', '', 66384),
(310030, 'zhTW', '', '$n，有什麼事嗎？', 66384),
(309797, 'zhTW', '歡迎，哈巫拉。我們枯木部族對哈拉齊眷顧者充滿感激。', '', 66384),
(309796, 'zhTW', '哈拉齊很高興看到祂的恩澤在枯木崖幫上你的忙。\n\n祂現在想幫你，但你必須先幫祂，哈巫拉。\n\n而且祂認為，你幫祂也是在幫你自己！', '', 66384),
(309775, 'zhTW', '你想多了解劇毒之母嗎？那好吧。\n\n許多食人妖部族對祂的名號一定很熟悉。戰爭期間，祂最常受到人們的信奉，因為祂的劇毒就連眾神都十分懼怕。\n\n不過，根據我們祖先的故事，祂起源自阿曼尼的信仰。許多人依舊信奉祂，而且人數也不少於哈拉齊或菲洛。\n\n謠傳祂好幾年前就死了。但更早之前也傳過這樣的謠言。看來就算祂躲在編織的蛛網裡，死亡也會找上祂。', '', 66384),
(309774, 'zhTW', '『疫病羅亞』莫塔拉的形體是一隻恐怖的盔甲蜥蜴。\n\n莫塔拉和庫爾吉像是事物的一體兩面。當疫病流行時，人們就會需要解藥。許多人對藥理、草藥學和鍊金術感興趣，自然也有人渴求毒藥的知識，並信奉盔甲蜥蜴羅亞。\n\n祂的信徒們跋涉到祂在破碎王座下，位在曲折墓穴的簡陋聖壇。祂會不會也在抵抗邪惡的虛無入侵者呢？', '', 66384),
(309773, 'zhTW', '你必須先思考：「危機」是什麼？\n\n對優秀的哈巫拉來說，危機就是轉機。\n\n雖然你可能不認同我說的話，但我必須說，深海裡的捕魚人就生活在危機與轉機之下。\n\n他們都得思考，究竟該面對危機、繼續探索，還是化為轉機，藉此捕獲更驚人的獵物！', '', 66384),
(309759, 'zhTW', '許多工匠和農夫都信奉豐足羅亞。如果夠格的話，祂會把你當成天選之人一樣看待。如果沒有，祂就會對你棄如敝屣。\n\n大家都說，富足的氣息飄向你只是早晚的事！', '', 66384),
(309757, 'zhTW', '如果你對藥理、草藥學或鍊金術有興趣，庫爾吉永遠會在北方的聖壇守望著你。我以前沒有走過那條路，但多魯長老曾和我說過那裡的景色。\n\n多魯說可以看到整個天空之橋，遠方的樹林還能隱隱看到阿曼尼扎。', '', 66384),
(309754, 'zhTW', '每當阿曼尼離開家裡，偉大猛瑪象就會看顧我們。\n\n若是沒有祂和祂同胞的照顧，我們每次外出狩獵、朝聖或和其他村落交易時，就會膽小得像水豚一樣。', '', 66384),
(309748, 'zhTW', '自有史以來，我們從沙地戰場到祖阿曼尚未開發的地區追獵時，奧耶就在保護我們部族了。我們沒見過祂。我們不了解祂。但祂就在那裡。\n\n那些信奉巨樹之主的人們再也不在神廟或祭壇，而是在巨大松樹生長的地方祭祀。\n\n人們說樹木會這麼高大，都是因為汲取了生長靈魂。但是如果樹木太過貪婪，攝入太多靈魂，它們就會活過來並瘋狂地肆虐。', '', 66384),
(309747, 'zhTW', '菲洛的聖壇就在一座小島上，周遭是能讓人好好放鬆的溫泉。梅薩拉的沼澤南方可以找到三連群島。\n\n祂應該不太會現身，除非你是穿著那身衣服疊羅漢的兩三個孩童。', '', 66384),
(309718, 'zhTW', '我們依照攝政王的命令，全力守護銀月城。\n\n我們的城市現在遭到圍攻，北邊是虛無，南邊則有光綻。我們的船隻和龍鷹僅供像你這樣的勇士使用，用於守護奎爾薩拉斯。\n\n平民若想離開城市，則必須經由傳送門。', '我們依照攝政王的命令，全力守護銀月城。\n\n我們的城市現在遭到圍攻，北邊是虛無，南邊則有光綻。我們的船隻和龍鷹僅供像你這樣的勇士使用，用於守護奎爾薩拉斯。\n\n平民若想離開城市，則必須經由傳送門。', 66384),
(309717, 'zhTW', '我分身乏術，無暇顧及你的訓練，但你隨時都能使用我放在那裡的大鍋。', '', 66384),
(309716, 'zhTW', '', '長老還需要一點時間，才能理清我們在地表的行動會產生什麼後果。\n\n不過，請放心，$n。在我們對哈朗達面臨的危險視而不見的時候，你伸出了援手。那是不容遺忘的善舉。\n\n只要時候一到，哈拉尼爾就會全力以赴，協助你對抗這些敵人。我向你保證。', 66384),
(309702, 'zhTW', '<祝福祭壇休眠中。>', '<祝福祭壇休眠中。>', 66384),
(309690, 'zhTW', '我們…我們應該至少把孩子送走。\n\n像是使用傳送門？\n\n蘇拉瑪爾欠我們一個人情。', '我們…我們應該至少把孩子送走。\n\n像是使用傳送門？\n\n蘇拉瑪爾欠我們一個人情。', 66384),
(309689, 'zhTW', '聽說阿曼尼食人妖和教徒正從南邊進攻。現在撤離是不是太遲了？\n\n我們該逃去哪裡？', '聽說阿曼尼食人妖和教徒正從南邊進攻。現在撤離是不是太遲了？\n\n我們該逃去哪裡？', 66384),
(309678, 'zhTW', '', '了解盟友與其敵人之間的關係是龍隊指揮官的職責之一。然而，無論我對這個世界不同陣營之間的紛爭了解多少，但是來到這裡，就會讓我絕大多數的認知受到衝擊。\n\n聯盟、部落，甚至是那些未與任一陣營結盟的人，似乎未被仇恨或立場擺布，而是健康地追求美酒、美食和對話。\n\n我開始理解，為什麼禁忌之境有這麼多半龍人選擇過著近似平民的生活。埃祖拉瑟或許還不能理解，但總有一天他會的。最重要的是，我們都是半龍人，不分立場、教條或龍隊。', 66384),
(309677, 'zhTW', '隨著越來越多的族人擁抱平民的生活，我必須承認…自己還沒完全融入其中。\n\n對一名士兵來說，放下武器、單純活著，並不是容易的事。但在這個地方，我看到許多英雄擁抱那樣的…生活！即使我不能徹底理解，但這個有點陌生的想法相當有意思。\n\n也許我應該鼓勵黑曜衛隊的其他人去體驗更多事物，別讓人生被士兵這個身分綁住。如果他們見到自己的龍隊指揮官短暫忙裡偷閒，說不定也會想要效法。', '', 66384),
(309669, 'zhTW', '$n！你和大主教和將軍談過了嗎？\n\n你知道我們什麼時候會出擊嗎？這種情況…不能再繼續下去了。', '$n！你和大主教和將軍談過了嗎？\n\n你知道我們什麼時候會出擊嗎？這種情況…不能再繼續下去了。', 66384),
(309668, 'zhTW', '自阿古斯以來，還從未有過性質如此正當的戰鬥。善與惡的對決，勢不兩立，毫不留情。\n\n我們會為敵人帶去毀滅，在他們的堡壘裡對他們降下制裁！我們只需要有人找到進去的方法，讓我們有機會一試。', '自阿古斯以來，還從未有過性質如此正當的戰鬥。善與惡的對決，勢不兩立，毫不留情。\n\n我們會為敵人帶去毀滅，在他們的堡壘裡對他們降下制裁！我們只需要有人找到進去的方法，讓我們有機會一試。', 66384),
(309667, 'zhTW', '據說另一支試圖飛入虛無風暴的探險隊被消滅了。雖然我們可以利用聖光將他們擊退，但從這個空中破洞進入敵方領地的道路似乎也被他們封鎖了。\n\n無所謂。我相信我們偉大的領袖們會找到辦法讓我們的部隊進入虛無風暴。', '據說另一支試圖飛入虛無風暴的探險隊被消滅了。雖然我們可以利用聖光將他們擊退，但從這個空中破洞進入敵方領地的道路似乎也被他們封鎖了。\n\n無所謂。我相信我們偉大的領袖們會找到辦法讓我們的部隊進入虛無風暴。', 66384),
(309666, 'zhTW', '感謝聖光把我們一起召喚來這裡。其他教團的信仰同胞也與我們齊聚一堂。\n\n在這裡，我們不再是聖光軍團，而是聖光先鋒！這不是很令人感到敬畏嗎，勇士？\n\n我期待與你並肩作戰，對抗萬物的終結。', '感謝聖光把我們一起召喚來這裡。其他教團的信仰同胞也與我們齊聚一堂。\n\n在這裡，我們不再是聖光軍團，而是聖光先鋒！這不是很令人感到敬畏嗎，勇士？\n\n我期待與你並肩作戰，對抗萬物的終結。', 66384),
(309643, 'zhTW', '', '在四個地點中，同時只有一個能算做是真正的豐足地點。\n\n當一個地點處於豐足狀態時，我們的豐碩之主敦敦就會賜予你祂最稀有的寶物：純粹豐足。\n\n想要用你的付出換來純粹豐足，首先你必須要獻給祂一個敦敦裂片。\n\n敦敦裂片是羅亞力量的碎片。當你在具有豐足地點的任何土地上製作專業商品，或是採集礦石、草藥、皮革或魚類時，就能獲得這種裂片。\n\n裂片的數量在祖阿曼會更多。你可以在隱藏寶藏中或甚至是稀有野獸的屍體上找到它們！', 66384),
(309642, 'zhTW', '我們的虛無精靈同胞在虛無風暴中建立了一座脆弱不堪的堡壘。去看看你能不能幫他們加強戰力，對抗我們滔滔不絕的敵人。', '', 66384),
(309641, 'zhTW', '你在哈朗達的努力讓你獲得與哈拉尼爾平起平坐的殊榮，不必擔心遭到報復。我想我們可以從他們的故事和傳統中學到很多知識。\n\n去盡量學習吧，然後回來找我。', '', 66384),
(309640, 'zhTW', '阿曼尼發現了一種方式，讓我們可以將自然界中的所有資源提取出來。雖然我更喜歡我們自己的城市和它提供的舒適環境，但如果不去看看我們的盟友能提供什麼，那就太可惜了。\n\n即使這代表要稍微弄髒你的雙手。', '', 66384),
(309639, 'zhTW', '薩瑟里的晚會是個…複雜的場合。上流社會，暗流洶湧。話雖這麼說，他們也是在用自己的方式維持永歌森林的和諧與平靜。去幫他們加固防禦吧。', '', 66384),
(309634, 'zhTW', '去到外面的世界，不論在哪裡遇到敵人都將之討伐！我們的敵人不計其數，但我們的盟友數量眾多。盡你所能幫助他們，不論何時何地。\n\n當然了，之後要回來向我報告。', '', 66384),
(309633, 'zhTW', '', '在你採收和貢獻豐足的同時，豐足祝福不僅能強化你，還會自我成長。\n\n每當你採收到任何豐足時，你的基礎能力就會被加強。這些能力包括移動速度或戰鬥能力等屬性。\n\n當你貢獻足夠的豐足之後，祝福就會進化。你可以從更遠的距離採收豐足球體、同時持有更多豐足，以及進一步強化你的基礎屬性。\n\n我們脆弱的凡人肉體只能短時間維持這股力量。每次我們進入一個豐足地點的時候，才會重新獲得祝福。', 66384),
(309631, 'zhTW', '', '你採收到的豐足可以在任何豐足祭壇上供。\n\n所有貢獻的豐足都會由敦敦收下，並與你侍僧同伴貢獻的豐足結合。\n\n貢獻足夠的豐足後，羅亞就會給予所有參與者豐厚的獎勵！', 66384),
(309630, 'zhTW', '', '想要採收豐足，你可以選擇殺死生物，或是在草藥或礦石等材料節點進行收集。\n\n透過羅亞的力量，所有豐足在被創造出來時都會匯聚成球體。只要走到附近就能把它們收集起來。\n\n查看你的豐足背包，確認你目前身上有多少豐足。', 66384),
(309623, 'zhTW', '', '具體想知道什麼？', 66384),
(309622, 'zhTW', '', '繁榮向你致意，侍僧。\n\n需要什麼嗎？', 66384),
(309612, 'zhTW', '我知道對洛薩之子來說，回到這裡並非一件易事，但這裡有某個我們真的很需要的東西。', '', 66384),
(309607, 'zhTW', '我已經支持攝政王很多年了。\n\n但我開始擔心，末日預言者說的話比他還要更令人信服了。', '我已經支持攝政王很多年了。\n\n但我開始擔心，末日預言者說的話比他還要更令人信服了。', 66384),
(309606, 'zhTW', '我在暗影中聽見了聲音。虛無已經到了。\n\n它們不僅在空中，它們潛伏在我們周圍。無所不在。\n\n暗影會在你不注意的時候行動。', '我在暗影中聽見了聲音。虛無已經到了。\n\n它們不僅在空中，它們潛伏在我們周圍。無所不在。\n\n暗影會在你不注意的時候行動。', 66384),
(309605, 'zhTW', '天空塌下來了。真的塌下來了。\n\n為什麼沒人擔心天空塌下來這件事？！', '天空塌下來了。真的塌下來了。\n\n為什麼沒人擔心天空塌下來這件事？！', 66384),
(309604, 'zhTW', '他們要我們把所有物資通通交給聖光先鋒！\n\n我們憑什麼相信他們？其中大部分的人都曾是聯盟的走狗。很多人現在依然是！', '他們要我們把所有物資通通交給聖光先鋒！\n\n我們憑什麼相信他們？其中大部分的人都曾是聯盟的走狗。很多人現在依然是！', 66384),
(309603, 'zhTW', '今天，憑藉聖光的意志，我們在眨眼間移動了一段匪夷所思的距離來到這裡，只為保衛這個地方。\n\n$p勇士，很榮幸看到你與我們同行。知道你也受到聖光的召喚，就讓人士氣大振。', '今天，憑藉聖光的意志，我們在眨眼間移動了一段匪夷所思的距離來到這裡，只為保衛這個地方。\n\n$p勇士，很榮幸看到你與我們同行。知道你也受到聖光的召喚，就讓人士氣大振。', 66384),
(309594, 'zhTW', '勇士，我剛好在休息。\n\n我最近把我匯聚起來的力量注入太陽之井，所以獲得了休息的機會。\n\n看來這座城市也不像我以為的那麼安全。', '勇士，我剛好在休息。\n\n我最近把我匯聚起來的力量注入太陽之井，所以獲得了休息的機會。\n\n看來這座城市也不像我以為的那麼安全。', 66384),
(309593, 'zhTW', '我們沒有足夠的聖光使用者。我們整個教團幾乎都在這裡了，而我們打從心底知道，這樣還不夠。\n\n但我們還是會在這場戰爭中全力以赴。', '我們沒有足夠的聖光使用者。我們整個教團幾乎都在這裡了，而我們打從心底知道，這樣還不夠。\n\n但我們還是會在這場戰爭中全力以赴。', 66384),
(309592, 'zhTW', '虛無會試圖吞噬整個銀月城和奎爾薩拉斯。然後它會繼續吞噬下去，直到世上什麼都不剩。\n\n這裡是虛無在我們世界的落腳點。我們必須不惜一切代價將之摧毀。', '虛無會試圖吞噬整個銀月城和奎爾薩拉斯。然後它會繼續吞噬下去，直到世上什麼都不剩。\n\n這裡是虛無在我們世界的落腳點。我們必須不惜一切代價將之摧毀。', 66384),
(309591, 'zhTW', '我很同情銀月城居民的遭遇。他們已經受太多苦了。\n\n家園位於聖光與虛無交鋒的前線，肯定不是件輕鬆的事。\n\n我只希望，在我們不惜一切代價拯救艾澤拉斯時，他們的信念能堅定不移。', '我很同情銀月城居民的遭遇。他們已經受太多苦了。\n\n家園位於聖光與虛無交鋒的前線，肯定不是件輕鬆的事。\n\n我只希望，在我們不惜一切代價拯救艾澤拉斯時，他們的信念能堅定不移。', 66384),
(309587, 'zhTW', '', '這能幫上落錘鎮，謝謝你，$p。', 66384),
(309584, 'zhTW', '', '$c，有什麼事？', 66384),
(309557, 'zhTW', '我想我沒辦法再繼續當血騎士了。\n\n永無止境的訓練，不停被打趴在地，被擊日者教官大吼大叫…我覺得我根本沒有成為血騎士的天分。每天我都想著退出，即使是現在，我都在逃避我的勤務。\n\n我感覺自己好失敗。我本該成為一名偉大的戰士，但現在我只想回家找我母親，靠喝酒忘光所有煩惱。更不用說我在受訓期間欠下的所有債務。\n\n我知道有很多人支持我。我的父母，我的朋友，甚至是擊日者教官都希望我能成功。這反而讓我更心痛，因為我覺得我讓他們失望了。\n\n我感覺好迷惘。', '', 66384),
(309536, 'zhTW', '動作快，一旦倒出，粉塵就會開始分解！', '動作快，一旦倒出，粉塵就會開始分解！', 66384),
(309535, 'zhTW', '在每個小瓶子中一次加入一點，直到觸及我在容器上劃下的印記為止。裝好後，就告訴我一聲，我會完成結界的製作。', '在每個小瓶子中一次加入一點，直到觸及我在容器上劃下的印記為止。裝好後，就告訴我一聲，我會完成結界的製作。', 66384),
(309481, 'zhTW', '今天的海象很惡劣。', '', 66384),
(309479, 'zhTW', '', '哦，蒙特。這一定不是你預想中的歡迎方式。', 66384),
(309478, 'zhTW', '我們的地表斥侯帶著某種神奇生物的故事回來，據說牠能在地上跑、在水裡游，還能在天上飛。\n\n這種生物體型雖小，卻有很可怕的喙，而且牠的啼叫聲會響徹整個夜晚。\n\n當然了，我們肯定得幫這樣的生物做一個同樣的玩具。', '', 66384),
(309476, 'zhTW', '我正在努力補充我的玩具庫存。之前的玩具大部分都是武器，不過它們已經被孩子們拿光了。\n\n<英哈尤露出自豪的微笑。>', '', 66384),
(309448, 'zhTW', '啊，請別在意我的二頭肌。如果法術不配合，那…總得靠其他辦法。\n\n我知道，我知道。一個血精靈居然靠蠻力？相信我，我的導師們比任何人都要誇張。不過，我炸掉的練習假人比我施放的正規法術還多，所以只能練肌肉了。\n\n總有一天我的魔法天賦會顯現的。在那之前，我想我只能先把那些我無法讓它們漂浮的東西舉起來了。', '', 66384),
(309432, 'zhTW', '老實說…我一直對我的祖父抱有很深的感情。\n\n小時候，我的父母總是疲於奔命：責任、期望、無止境的要求。我並不怪他們，但這也意味著我和姊姊主要是在祖父的照顧下長大的。\n\n他是第一個指引我接觸秘法的人，我至今仍能聽到他堅持說，我總有一天會超越他的天賦。\n\n提起他，就能感受到他的一部分陪伴著我。彷彿他記憶的光芒依然閃耀著。', '', 66384),
(309378, 'zhTW', '需要我幫忙嗎？', '需要我幫忙嗎？', 66384),
(309330, 'zhTW', '', '你是來幫忙研究的嗎？', 66384),
(309291, 'zhTW', '', '你好。你在尋求剝皮的指導嗎？', 66384),
(309290, 'zhTW', '', '你好。你在尋求草藥學的指導嗎？', 66384),
(309289, 'zhTW', '你好。你在尋求附魔的指導嗎？', '', 66384),
(309288, 'zhTW', '', '你好。你在尋求裁縫的指導嗎？', 66384),
(309287, 'zhTW', '你好。你在尋求珠寶設計的指導嗎？', '', 66384),
(309286, 'zhTW', '你好。你在尋求製皮的指導嗎？', '', 66384),
(309285, 'zhTW', '', '你好。你在尋求工程學的指導嗎？', 66384),
(309284, 'zhTW', '你好。你在尋求鍛造的指導嗎？', '', 66384),
(309283, 'zhTW', '', '你好。你在尋求銘文學的指導嗎？', 66384),
(309282, 'zhTW', '你好。你在尋求鍊金術的指導嗎？', '', 66384),
(309271, 'zhTW', '我猜伊茲坎逃離的原因是真的。', '我猜伊茲坎逃離的原因是真的。', 66384),
(309270, 'zhTW', '她是他們的母親。我沒有資格涉入其中。', '她是他們的母親。我沒有資格涉入其中。', 66384),
(309269, 'zhTW', '她是個非常偉大的首領。相信她也一定對他們很好。', '她是個非常偉大的首領。相信她也一定對他們很好。', 66384),
(309268, 'zhTW', '查娜說的那些，希望都不是真。在伊茲坎離開前，我會去問他。', '查娜說的那些，希望都不是真。在伊茲坎離開前，我會去問他。', 66384),
(309267, 'zhTW', '她對我們所有人都很好。我不想相信那些話。', '她對我們所有人都很好。我不想相信那些話。', 66384),
(309266, 'zhTW', '因為她的堅強意志，才讓許多阿曼尼人活了下來。', '因為她的堅強意志，才讓許多阿曼尼人活了下來。', 66384),
(309265, 'zhTW', '我無法相信查娜說的話…但又有誰更了解她呢？', '我無法相信查娜說的話…但又有誰更了解她呢？', 66384),
(309264, 'zhTW', '他們的母親是位偉大的首領。我們會想念她的。', '他們的母親是位偉大的首領。我們會想念她的。', 66384),
(309263, 'zhTW', '喔，嗨，大朋友。別在意破破。破破正在休息！\n\n破破跟史琦德一起來。這個地方非常忙碌！忙碌是指有太多蠟燭需要重新點燃！\n\n椅子上的灰髮人說，蠟燭和火炬都會自行更換，但破破知道蠟燭不是魔法。\n\n狗頭人更換蠟燭，不是魔法！\n\n你要買嗎？破破有各種蠟燭！', '', 66384),
(309262, 'zhTW', '我並不是很常造訪人類旅店。供應的酒都太淡，椅子也很不牢固，而且米莎經常發現自己…不受歡迎。\n\n但是這個地方？有好酒。有異常堅固的椅子。至於米莎？\n\n<雷克薩回頭看了一眼，一隻巨熊正睡在火堆旁。>\n\n她似乎很喜歡這個地方。我覺得自己應該會再待一下子。看到一些預料之外的友善面孔穿過那扇門，真的很有意思。', '', 66384),
(309261, 'zhTW', '在我的一生中，我去過不少旅店。嚐過了不少酒，遇到了不少朋友，甚至還在酒吧鬥毆中出了幾次拳，丟了幾個杯子。\n\n然而，儘管我造訪過這麼多旅店，卻很少有旅店跟這間一樣獨一無二。\n\n<老陳坐在吧檯椅上轉圈，看著亞肯提納的顧客一陣子，隨後繼續喝他的酒。>\n\n等崇波從四風峽回來之後，我應該帶他來這裡。說不定風暴烈酒酒坊還能供應亞肯提納限定的佳釀？', '', 66384),
(309260, 'zhTW', '', '我必須承認，當叔叔告訴我，他又找到一間非去不可的「魔法旅店」時，我內心是有點懷疑的。畢竟就算是一頂破爛的啤酒節帳篷，只要它供應美酒，他也會說它「很有魔力」。\n\n我其實更想要帶我哥和我爸遊覽四風峽…但我得好好稱讚他。這個地方是名符其實的魔法旅店。我們才剛來不久，就已經遇到幾個我認得的友善面孔！\n\n等到我的家人忙完酒坊的事後，也許我可以說服他們來這裡。我幾乎已經能聽見我叔叔帶了幾款特殊的好酒來這裡兜售。', 66384),
(309259, 'zhTW', '', '這個地方很不一樣，不是嗎？\n\n自從離開卡茲阿爾加後，我造訪了很多地方，每個地方都有獨特的文化和人民。\n\n我聽了許多他們的故事和歷史，很多都讓人心馳神往，少數則是紛爭不斷。\n\n但在這裡，來自四面八方的人齊聚在同一個屋簷下，除了單純與慰藉外，別無其他。這真的很神奇…也讓人很享受。\n\n<黎明臉上帶著溫和的笑意，看了看四周。>\n\n我覺得自己應該試試其他飲料。', 66384),
(309210, 'zhTW', '我在練習我的電擊雲！它現在只能降下一些雨滴而已。\n\n有一天，我會創造好大一場風暴，讓所有人大吃一驚，為家族爭光。\n\n我會努力練習的！', '我在練習我的電擊雲！它現在只能降下一些雨滴而已。\n\n有一天，我會創造好大一場風暴，讓所有人大吃一驚，為家族爭光。\n\n我會努力練習的！', 66384),
(309207, 'zhTW', '', '這麼多名聞遐邇的戰士聚集在此，卻沒發生任何爭執，這狀況本身就說明了從我穿越黑暗之門來到艾澤拉斯之後，世界已經改變許多了。為了和平而戰是高尚的行為。也許有些人認為和平能永遠持續下去。\n\n但我清楚知道，只要刀口下在正確的地方，就能徹底顛覆一個王國。\n\n當戰爭爆發，記得弄清楚你站在哪一邊。我總是會注意這點。', 66384),
(309178, 'zhTW', '嗨。我在等我的愛人拉荷法。\n\n你有什麼事嗎？', '嗨。我在等我的愛人拉荷法。\n\n你有什麼事嗎？', 66384),
(309164, 'zhTW', '', '我們讓那個虛無行者見識到找虛無精靈的麻煩會有什麼下場，但我們已經因為它的詭計損失太多了。\n\n我心懷遠大目標來到這裡作戰，但沒想到會遇到這種事！我沒準備好對付這裡的黑暗。\n\n刃多雷和虛無密不可分，我並不感到後悔，但虛無風暴讓我渾身不對勁。\n\n讓我們完成該做的事，之後就回家吧。', 66384),
(309157, 'zhTW', '', '我打一開始就知道這該死的生物對我們不懷好意。\n\n但我還是想懷抱希望。看來虛無風暴真的是個毫無希望可言的地方。\n\n不管那該死的生物有什麼打算，我們都準備好應付了！', 66384),
(309152, 'zhTW', '', '我從來沒聽過不具攻擊性的虛無行者，但只要有一絲機會能讓它帶領我們找到其他人，我們就得考慮才行。\n\n虛無風暴為我們帶來了這麼多痛苦，也該是時候來點好事了，你說是吧？', 66384),
(309147, 'zhTW', '', '精靈的幻象引領我找到這個虛無行者！\n\n它看起來沒什麼威脅性，但務必保持警戒。暗影編織的謊言就像層層纏繞的蛛網。', 66384),
(309132, 'zhTW', '我們現在理解了…這麼多的暴力會導向無盡的死亡循環。\n\n無窮無盡…就像虛無一樣。', '', 66384),
(309128, 'zhTW', '我沒有辦法證明至尊掠食者存在，但我能感覺到牠在看著我。牠就在那裡！\n\n如果卡莉雅看不出來，她肯定是瞎了！她知道有某種東西就在不遠處。我從她的眼神看得出來。', '', 66384),
(309120, 'zhTW', '有趣的是，這些野獸的肉嚐起來不像虛無。\n\n但當我一口咬下的時候，我們周圍的空氣卻因興奮而顫抖。', '', 66384),
(309118, 'zhTW', '', '身為暗域研究者的職責，就是要了解刃多雷和虛無之間的關係。\n\n虛無的力量讓我們的族人勇往直前…但也有它的風險。\n\n<她把頭歪向一邊，眼神渙散。>\n\n麥崔恩和我決定搭檔進行研究，是因為我們能相輔相成。他會興高采烈地擁抱虛無，而我會保持…務實…謹慎的態度。\n\n工作時，我們完全理解可能會發現什麼樣的瘋狂事物。\n\n這就是為什麼我們會合作。若我被瘋狂支配了，我會很高興有麥崔恩能幫忙處理要事。', 66384),
(309100, 'zhTW', '我早該知道聖光之願的情況會如此危急的，$p，畢竟他們派了這麼多聖騎士到太陽之井。\n\n我們來到這裡對泰羅索斯來說算是幸運，你和阿拉特能提供一些協助。', '', 66384),
(309088, 'zhTW', '', '議會必須講理。風險太高了，他們絕不能袖手旁觀。', 66384),
(309008, 'zhTW', '關於和虛無勢力作戰，我也有點經驗…但我從沒看過這種數目的大軍。和我們攻進燃燒軍團的要塞時不同，我們不常遭遇虛無勢力。\n\n就算是最偏遠的戰場，也潛藏著他們的勢力，就像視野死角的黑影一樣。洛斯拉賽恩告訴我們他對虛無戰術的知識，但即便如此，吞噬之眾仍然技高一籌。', '', 66384),
(309007, 'zhTW', '', '我見過虛無的勢力發動攻擊。我見證了他們的大軍和無盡的惡魔戰鬥。燃燒軍團強在純粹的力量，虛無則是如海浪般無盡地洶湧而至，就像寄生性的暗影，吞噬並滲透它所碰到的一切。\n\n但這個…就算對虛無而言，這也是從所未見。', 66384),
(309005, 'zhTW', '沒有聖光就不會有暗影。', '沒有聖光就不會有暗影。', 66384),
(308999, 'zhTW', '', '我是亞莉，卡德加的朋友。我曾經居住在紫羅蘭城塞的守護者殿堂裡。\n\n我在那裡埋首書籍之間，靜靜地待上了好多年。\n\n但達拉然遭受奈幽蟲族攻擊而陷落時，我…\n\n<亞莉一時陷入沉默。>\n\n和許多人一樣，城市陷落之後，我也一直找不到尋找自己的居所。外界對我而言太過複雜、吵鬧了。\n\n但卡德加帶我到這來，既安全又安靜。我欠他很多。', 66384),
(308996, 'zhTW', '', '卡德加在多恩諾加恢復之後，告訴了我這地方。\n\n跟守護者殿堂比起來可能沒那麼宏偉，但至少挺安靜的。\n\n我忍不住想知道這地方有著什麼樣的秘密。', 66384),
(308995, 'zhTW', '', '擊敗莫爾頓之後，對抗薩拉塔斯的局勢對我們更有利了。', 66384),
(308994, 'zhTW', '我曾經帶領無數英雄在撒塔斯旅遊。有些行程得帶他們在城裡走來走去，還挺耗時間的！\n\n能從中解脫總是讓人感到開心啊。', '', 66384),
(308993, 'zhTW', '', '怎麼啦？沒想到會在艾澤拉斯最棒的旅店看到我啊？\n\n至少到現在為止都沒人趕我出去。不過我懷疑原因不是在我，而是塞西莉亞怡人的笑容。\n\n迪菲亞兄弟會選了他們的路。我也選了我自己的。他們想靠掠奪和搜刮來承繼父親的遺志，那就隨他們去吧。我要靠實際幫助西部荒野的農民來體現父親的遺志。\n\n塞西莉亞想用「正確的方式」做事。但她可不是傻瓜。我們兩個都知道，當敵人用骯髒手段的時候，有時候你也得以毒攻毒。\n\n那就是我來這的理由，這麼多事可做，偏偏在這跟女伯爵打關係。\n\n<凡妮莎極短暫地露出微笑，你差點沒看到。>\n\n這其實也不算太糟啦。一點都不。', 66384),
(308992, 'zhTW', '', '又見面啦，$p！\n\n你最近都還好吧？這段時間我一直在暴風城，盡力協助西部荒野的麵包籃公會。\n\n考慮到現在的情況，這目標並不容易。貴族議會趁國王不在，拖延了所有他們看不順眼的行動。然後，他們還用同樣的藉口加速通過能讓他們從中獲利的事！\n\n<塞西莉亞嘆了口氣。>\n\n原諒我，旅行者。我向凡妮莎保證過，不要在亞肯提納這裡提起那些瑣事。這真是個讓人放鬆的好地方，對吧？凡妮莎堅持不告訴我她怎麼找到這地方的，不過我很懂她，她肯定誇大了這裡的隱密性。我會從她那裡問出真相的。', 66384),
(308991, 'zhTW', '', '你好啊，旅行者。\n\n我是塞西莉亞‧克雷辛頓。我通常都在暴風城，支持西部荒野的麵包籃公會，致力創造一個更公正的政府。\n\n考慮到現在的情況，這目標並不容易。貴族議會趁國王不在，拖延了所有他們看不順眼的行動。然後，他們還用同樣的藉口加速通過能讓他們從中獲利的事！\n\n<塞西莉亞嘆了口氣。>\n\n原諒我，旅行者。我向凡妮莎保證過，不要在亞肯提納這裡提起那些瑣事。這真是個讓人放鬆的好地方啊！凡妮莎堅持不告訴我她怎麼找到這地方的，不過我很懂她，她肯定誇大了這裡的隱密性。我會從她那裡問出真相的。', 66384),
(308990, 'zhTW', '亞肯提納是個好地方，$p。你該時不時來這坐坐！\n\n大家都需要休息一會，放鬆身心。', '', 66384),
(308988, 'zhTW', '願他也指引你。戴斯可在這裡教了我不少東西。如同在曠野中，每一道陽光都很重要，我們所做的每一件小事，也都有其價值。\n\n此外，在安希的光輝下，所做的事有沒有價值，並非由我們來判斷。\n\n在這裡在他身旁做事，我發現幫助需要的人是讓我最有收穫的事。', '', 66384),
(308987, 'zhTW', '現在和發光守衛戰鬥。大家叫他們常勝冠軍，因為…別在意。莫塔不想讓$p難過。\n\n但是莫塔覺得…也許$p可以打敗發光守衛？$p很厲害。大家很認真練習。\n\n莫塔祝$p好運。也許能打敗常勝冠軍！\n\n也許能變成常勝冠軍？不行，之前出局了。\n\n但還是可以打敗發光守衛！', '', 66384),
(308986, 'zhTW', '隊伍怎麼出局了？隊伍輸得好快。計畫太差了。\n\n或許不是計畫的問題？\n\n莫塔參加過，知道坑洞可怕。\n\n出局過。隊友很生氣。\n\n就是為什麼莫塔待在安全的地方，不會再進坑洞。\n\n你要再進坑洞嗎？', '', 66384),
(308985, 'zhTW', '現在有隊名了。\n\n但莫塔…不太確定。菇菇咕咕叫是什麼？\n\n在坑洞的時候，不好叫。可以保留「$p的隊伍」。比較好叫。\n\n但是莫塔還是會叫。', '', 66384),
(308984, 'zhTW', '聽說現在有隊名了！真棒！\n\n選得好。莫塔喜歡。\n\n在坑洞的時候，會喊隊名。不是喊「$p的隊伍！$p的隊伍！」', '', 66384),
(308983, 'zhTW', '很高興見到你，大領主！人生真是世事難料啊。從我們收回白銀之手那時開始就是，但現在…真難以置信，偉大的泰坦守衛者提爾也回歸了。\n\n我很高興能在亞肯提納放鬆，和你跟其他…見證人一起，見識超乎想像的事。', '', 66384),
(308982, 'zhTW', '$p，我叫崔瓦。人生真是世事難料啊。\n\n你知道偉大的泰坦守衛者提爾回歸了嗎？簡直叫我難以置信。\n\n我很高興能在亞肯提納放鬆，和你跟其他…見證人一起，見識超乎想像的事。', '', 66384),
(308980, 'zhTW', '$p，我真想不到我們認識以來，竟然會發生這麼多事。在提爾之墓碰見寇拉諾斯、重建提爾的衛士來取回他的記憶，現在竟然還能看他重新出現在艾澤拉斯。就算你告訴當初的我，我也無法相信。\n\n我很高興能在亞肯提納放鬆，和你跟其他…見證人一起，見識超乎想像的事。', '', 66384),
(308865, 'zhTW', '我該回家了，但…\n\n你猜怎麼樣？不，我改變主意了。\n\n但還是謝謝你。我打算暫時不要亂跑，享受這個時刻。', '我該回家了，但…\n\n你猜怎麼樣？不，我改變主意了。\n\n但還是謝謝你。我打算暫時不要亂跑，享受這個時刻。', 66384),
(308863, 'zhTW', '我正在挑戰離開社區的舒適圈生活。\n\n這很困難。我只靠一根鋒利的棒子和我的智慧活過了某項致命威脅。\n\n而且我覺得現在我只剩下鋒利的棒子了。', '', 66384),
(308862, 'zhTW', '別管我。我只是想弄懂精靈怎麼辦到這檔事的。\n\n我是說，像他們這樣重建城市？還能讓它看起來跟以前一樣老舊？就算有用到魔法，這也算是了不起的工程技術。\n\n這麼大的地方肯定會因為自重而崩垮，帶著我們共赴黃泉才對。\n\n我賭五枚銅幣，肯定是幻象法術。我不是指全部。只有碰不到的地方，還有你沒辦法靠近看的地方而已。', '', 66384),
(308861, 'zhTW', '當娃娃其實有點煩。什麼事都不能做啊！\n\n糟糕，我是說…都是自己人！\n\n沒錯！', '當娃娃其實有點煩。什麼事都不能做啊！\n\n糟糕，我是說…都是自己人！\n\n沒錯！', 66384),
(308859, 'zhTW', '我猜你又想被修理一次，是吧？', '', 66384),
(308857, 'zhTW', '歡迎參加派對！', '', 66384),
(308851, 'zhTW', '帶其他人來吧。讓我的…呃，我們社區聲名遠播！', '', 66384),
(308849, 'zhTW', '都是自己人！', '都是自己人！', 66384),
(308845, 'zhTW', '那個鈕扣應該夠用。我現在要用針線把你修好。\n\n算你運氣好，這根針很利。\n\n好嗎？', '', 66384),
(308843, 'zhTW', '可惜我們這裡的補給都是給龍鷹用的，$c。如果你需要什麼，我妹妹夏拉開的店就在附近。', '可惜我們這裡的補給都是給龍鷹用的，$c。如果你需要什麼，我妹妹夏拉開的店就在附近。', 66384),
(308838, 'zhTW', '<阿瑪拉克從風帽底下露出微微的笑容。>\n\n歐薇娜的朋友，你見多識廣。告訴我吧：信仰會因距離而消亡嗎？\n\n是的，蘇卡之道確實孤獨。但別誤會，我們並不是放棄信仰。我對艾恩哈拉的虔信甚至更甚以往。因為即便我已經聽不見她的聲音，我仍然知道她在呼喚著我。', '', 66384),
(308836, 'zhTW', '不。我們的啟蒙儀式會在靈魂留下傷疤。它會徹底改變我們。讓我們無法聽見女神之歌。\n\n蘇卡是孤獨的存在。但能讓我們踏入其他族人無法進入的地方。在沉默之中，我們也受到庇護，不受裂隙令人發瘋的哭喊影響。', '', 66384),
(308833, 'zhTW', '蘇卡是獵人、治療者，也是導師。我們請求靈魂與暗影的幫助，來對抗艾恩裂隙的危險，保住性命安全。我們也確保裂隙中的危險不會擅自遊蕩，離開他們受詛咒的地盤。\n\n蘇卡的技術得來不易。女神之歌的回音召喚我們，讓我們得到了野性的兇猛和繁茂的成長。但我們現在無法聽見女神的呼喚，所以我們就和其他的聲音溝通…和還能聽得見的聲音溝通。', '', 66384),
(308823, 'zhTW', '艾恩之塵很稀有，而且難以取得。它能強化我們和最純粹的艾恩哈拉恩賜之間的連結，讓我們能記錄歷史供後代學習，還能保護我們不受外界的負面影響。\n\n因為數量甚少，使用艾恩之塵都由哈拉尼爾長老們控管。就算是我們，也只有進行神聖儀式或面對極度危險的時候才能用。\n\n長老們會拒絕歐薇娜的請求，我不訝異。對他們來說，樹根外的世界就跟不存在一樣。為什麼要浪費寶貴的存貨，來救自己一輩子根本不會踏上的土地呢？', '', 66384),
(308821, 'zhTW', '', '酒保問我的酒要有多烈，我都已經死了，有多烈又有什麼差別？\n\n<她緩緩啜飲一口，掃視著房間內的景象。>\n\n這地方真是嘈雜，聞起來像酒糟…感覺像是回到家一樣，真是奇怪。像我這樣的陌生人能和部落跟聯盟的人坐在一起，有種近乎和平的感覺。這地方的熱鬧很不平常，但我不討厭。\n\n如果說我們有什麼共同點，就是我們都珍視能放鬆休憩的一刻。我們盡全力把握這種時光，就好像它隨時會消逝一樣，通常確實如此。\n\n如果你的酒喝起來像毒藥，別看我。我打算好好享受今晚的休假。', 66384),
(308786, 'zhTW', '哈謝之道既漫長又艱辛，充滿著考驗與苦難。\n\n哈巫拉是哈謝的侍僧，跟隨他們踏上哈謝之道。哈巫拉為了哈謝而戰，也為了他們而死。\n\n通常這需要，呃，兩個人。不過，你也看得出來我年事已高，我們的士兵也滿身瘡痍，祖爾詹更是絕不會同意…\n\n我猜第二位哈巫拉只能是莉雅德倫了。\n\n<金德魯猶豫地笑了。>\n\n哈巫拉的榮耀竟然落到一個辛多雷和卡多雷頭上…光是想到就讓我有點頭暈。但我何德何能質疑羅亞的意志？', '', 66384),
(308783, 'zhTW', '哈謝之道既漫長又艱辛，充滿著考驗與苦難。\n\n哈巫拉是哈謝的侍僧，跟隨他們踏上哈謝之道。哈巫拉為了哈謝而戰，也為了他們而死。\n\n通常這需要，呃，兩個人。不過，你也看得出來我年事已高，我們的士兵也滿身瘡痍，祖爾詹更是絕不會同意…\n\n我猜第二位哈巫拉只能是莉雅德倫了。\n\n<金德魯猶豫地笑了。>\n\n哈巫拉的榮耀竟然落到一個精靈頭上…但至少你是第二位，$n，即使你不是祖阿曼的子民、表親，或是我們遠親的後裔！', '', 66384),
(308779, 'zhTW', '我們的社區準備好進行下一個睦鄰任務了。你準備好就來討論吧。', '', 66384),
(308778, 'zhTW', '你是來了解光木武器為什麼延誤出貨的嗎？你來對地方了。\n\n暮光之刃發現我們的營地，他們知道我們為阿曼尼供應強大的光木武器。他們開始一天到晚攻擊我們，中斷我們的工作。\n\n而現在，這個男孩跑來我們的營地，大吼大叫著什麼妹妹。我沒有時間處理暮光之刃，更沒有時間照顧某個精靈農夫走丟的憤怒孩童！\n\n他很年輕，不知天高地厚。這種年輕人我也見過不少…\n\n也許你可以幫我解決這兩個問題。', '', 66384),
(308777, 'zhTW', '', '蠟燭熄掉了，邁里特幫了史琦德。史琦德找到這裡全部的蠟燭！\n\n好多蠟燭。你覺得是有漏掉，還是被借走了？', 66384),
(308776, 'zhTW', '我們應該沒見過，對吧？我是邁里特，這是史琦德。我喜歡認識新朋友，就像發現新寶藏一樣。\n\n你想和我們一起坐坐嗎？我們想在這裡休息一會，直到有人發現我們偷溜進來為止。這裡真是太棒了！', '', 66384),
(308775, 'zhTW', '這是我發現過最美的洞穴了。最棒的是，我的好夥伴們也都在這！$n也在，史琦德也在，還有個很棒的座位。\n\n你看，最棒的就是這些舒適的墊子了。我一直很想念和你一起嗅探尋寶。\n\n我們隨時歡迎你來坐坐！', '', 66384),
(308774, 'zhTW', '不能享受一點旅店時光，冒險還有什麼樂趣呢？就這點來說，旅店時光是越多越好。\n\n一直在戰場上廝殺會讓你的人生不斷在眼前像跑馬燈一般閃過。上次我的跑馬燈上演的，是我在不久後的未來品嚐這檔美酒的景象。我怎麼能視而不見呢？', '', 66384),
(308624, 'zhTW', '', '那是以嶄新勝利來改寫過去的機會。', 66384),
(308623, 'zhTW', '', '我很感激你，哈巫拉。謝謝你提醒托倫多這場戰鬥不是為了羞辱他過去的失敗。', 66384),
(308620, 'zhTW', '那只是你的看法，老傢伙！讓狂戰士加入戰鬥，我就讓你看看年紀不會決定一切！', '', 66384),
(308613, 'zhTW', '他們只是阿塔阿曼的回憶，而且也感受不到疼痛或死亡。', '', 66384),
(308612, 'zhTW', '', '他們才不是你真正的夥伴。', 66384),
(308600, 'zhTW', '', '虛無讓我感到十分噁心。它讓我感到十分痛苦！那些暮光之刃教徒用它摧毀了我最珍視的村莊，還奪走我母親的性命。\n\n現在看到虛無從捕蟹場那裡冒出來，還給我們難民造成的諸多麻煩…讓我不禁想起過去的可怕回憶。\n\n我們要盡快查出真相。', 66384),
(308593, 'zhTW', '', '你應該知道，影松的資源取之不盡。如果必要的話，要我們安全守護聖壇好幾年都不是問題。', 66384),
(308592, 'zhTW', '唯一的問題就是要餵飽他們，但補給品應該足以餵飽我們所有人，讓我們有力氣奮戰下去！', '', 66384),
(308588, 'zhTW', '為了確保年幼的老鷹能活著離巢並飛上天空，每一道傷口都值得。', '', 66384),
(308587, 'zhTW', '', '讓她知道屏障堅不可摧，而我們現在要面對的敵人只有在這牢籠中等待的耐心而已。', 66384),
(308586, 'zhTW', '為了感謝你保護我們，我們想和你的社區分享對藝術的知識，也想看看你們對美學的認知。\n\n你可以裝飾你的房屋嗎？我們很想看看你會如何利用裝飾，同時也會給你更多新裝飾！\n\n我們有些人在銀月城受侵襲的期間受傷了，如果你能治好他們就太好了。\n\n我還記得寇雷需要有人幫忙尋找繪畫的靈感。雖然他這個人很古怪，但也是個絕佳的畫家。', '為了感謝你保護我們，我們想和你的社區分享對藝術的知識，也想看看你們對美學的認知。\n\n你可以裝飾你的房屋嗎？我們很想看看你會如何利用裝飾，同時也會給你更多新裝飾！\n\n我們有些藝術家在銀月城受侵襲的期間受傷了，如果你能治好他們就太好了。\n\n我還記得寇雷需要有人幫忙尋找繪畫的靈感。雖然他這個人很古怪，但也是個絕佳的畫家。', 66384),
(308585, 'zhTW', '', '別再用你的手臂說話了，你這個蠢蛋！一直動來動去，根本沒辦法治療！', 66384),
(308584, 'zhTW', '永歌森林現在受到虛無與聖光的侵襲。\n\n我們需要控制局勢，同時也要確保我們能正常地過生活。\n\n我知道薩瑟里的晚會需要有人幫忙，我們也需要有人協助消除光綻。\n\n但需要幫忙的也不只我們。雖然難以啟齒，就連阿曼尼食人妖也需要幫忙，我還聽說有個新種族也需要協助。\n\n我們也直搗到虛無那裡去了，如果你能去提供協助就更好了。\n\n這…確實是沉重的負擔。不論你怎麼做，我們都很感謝你的協助。', '永歌森林現在受到虛無與聖光的侵襲。\n\n我們需要控制局勢，同時也要確保我們能正常地過生活。\n\n我知道薩瑟里的晚會需要有人幫忙，我們也需要有人協助消除光綻。\n\n但需要幫忙的也不只我們。雖然難以啟齒，就連阿曼尼食人妖也需要幫忙，我還聽說有個新種族也需要協助。\n\n我們也直搗到虛無那裡去了，如果你能去提供協助就更好了。\n\n這…確實是沉重的負擔。不論你怎麼做，我們都很感謝你的協助。', 66384),
(308582, 'zhTW', '', '現在這裡的情況十分危急。\n\n將這些過往回音各個擊破很容易，但它們之後會復生，並再次發起攻擊。', 66384),
(308576, 'zhTW', '謝謝你提供我們的藝術家庇護所，讓我們能協助裝飾你的社區。\n\n你的社區還真是漂亮。這簡直是藝術家的夢幻天堂。', '謝謝你提供我們的藝術家庇護所，讓我們能協助裝飾你的社區。\n\n你的社區還真是漂亮。這簡直是藝術家的夢幻天堂。', 66384),
(308575, 'zhTW', '謝謝你提供我們的藝術家庇護所，讓我們能協助裝飾你的社區。\n\n你看起來還在適應這裡的生活。不如去艾澤拉斯走走看看吧？我們可不想在你的旅途中叨擾你。', '謝謝你提供我們的藝術家庇護所，讓我們能協助裝飾你的社區。\n\n你看起來還在適應這裡的生活。不如去艾澤拉斯走走看看吧？我們可不想在你的旅途中叨擾你。', 66384),
(308573, 'zhTW', '', '你怎麼像個老穿山甲一樣抱怨個沒完？離開屏障之前，你就先坐在那裡好好休息吧。', 66384),
(308572, 'zhTW', '不管我們擊倒多少敵人，他們還是一直朝城市裡進逼。', '', 66384),
(308569, 'zhTW', '年輕的時候，我會樂於抵抗敵人永無止境的襲擊。\n\n但現在…這把老骨頭已經撐不住了。', '', 66384),
(308568, 'zhTW', '', '你在阿塔阿曼或許會看到熟面孔…但我想他們不會像以前那樣友善了。', 66384),
(308566, 'zhTW', '', '不久前，有個枯木部族的小女孩來這裡。可惜我這裡不賣水果或蘑菇…', 66384),
(308565, 'zhTW', '', '啊，我的骨董巨牙海民茶壺。你不是第一個對它感興趣的人…', 66384),
(308564, 'zhTW', '', '跨海而來的貨物！快來看看這些舶來品！', 66384),
(308511, 'zhTW', '這不是普通的蛋。\n\n貝羅倫在虛無的第一次襲擊中陣亡了。薩拉塔斯的部隊知道我們的弱點，也知道該如何精準打擊。\n\n偉大的鳳凰只能被迫涅槃重生。我們以為它們早該孵化了，但來自太陽之井的聖光在…它們治癒的同時…改變了它們。\n\n直到它們翱翔天際之前，我們會一直守在這裡。', '這不是普通的蛋。\n\n貝羅倫在虛無的第一次襲擊中陣亡了。薩拉塔斯的部隊知道我們的弱點，也知道該如何精準打擊。\n\n偉大的鳳凰只能被迫涅槃重生。我們以為它們早該孵化了，但來自太陽之井的聖光在…它們治癒的同時…改變了它們。\n\n直到它們翱翔天際之前，我們會一直守在這裡。', 66384),
(308509, 'zhTW', '退開，$c。\n\n在你眼前的是歐爾的最後一窩蛋。保護它是我們的職責，就算犧牲性命也在所不辭。', '退開，$c。\n\n在你眼前的是歐爾的最後一窩蛋。保護它是我們的職責，就算犧牲性命也在所不辭。', 66384),
(308503, 'zhTW', '<魯亞輕蔑地冷笑。>\n\n你們會在下雨時哀嘆天空崩塌嗎？\n\n有時候有更多根鬚。有時候較少。有時它們會因此改變形狀或性情。但它們始終會朝育所生長。只要哈朗達的根鬚保持完整，我們為什麼要在乎地表上發生什麼事？\n\n你還有什麼愚蠢的問題嗎？還是你只是在拖延命運？', '', 66384),
(308501, 'zhTW', '我是夏達希爾的根莖守望者，魯亞。八十五年來，我一直守護著這片受詛咒的根鬚，就像我的導師在回歸塵土之前一樣。', '', 66384),
(308500, 'zhTW', '', '艾哲早該殺了那個血精靈。\n\n<她上下打量著你，似乎對你不感興趣。>\n\n這裡不歡迎陌生人。尤其是來製造麻煩的傢伙。\n\n你最好小心點。', 66384),
(308496, 'zhTW', '<魯亞在你靠近時露出獠牙，顯然是出於嫌惡。>\n\n你竟敢直視根莖守望者？我應該拿你去餵冷酷山貓。', '', 66384),
(308495, 'zhTW', '不許你提起她，食人妖。\n\n蕾妮亞死了。\n\n<被綁起來的手用力握緊。>\n\n他們就像黑夜裡的鬼魅…\n\n那是阿曼尼食人妖。我很清楚。\n\n攻擊很隨機。所以，何不再來一次？任何阿曼尼食人妖都行。\n\n他們何不再來一次？', '', 66384),
(308494, 'zhTW', '<他死死盯著你。>\n\n你不是他們的人，對吧？\n\n…在一切太遲之前，幫我解決問題。', '', 66384),
(308436, 'zhTW', '若要和我們一樣，你需要一些重要的東西。\n\n首先要有按鈕！', '', 66384),
(308435, 'zhTW', '你不是我們的人。\n\n\n根本就不是。', '你不是我們的人。\n\n\n根本就不是。', 66384),
(308429, 'zhTW', '是不是很漂亮啊？我自己非常喜歡。\n\n但有一點要注意，如果有隻水豚在你腿上睡著了，千萬不要動。\n\n…好啦，這是我瞎掰的，但這樣做也不錯。', '是不是很漂亮啊？我自己非常喜歡。\n\n但有一點要注意，如果有隻水豚在你腿上睡著了，千萬不要動。\n\n…好啦，這是我瞎掰的，但這樣做也不錯。', 66384),
(308413, 'zhTW', '當你亟欲得之，聖光就會消逝而去。你必須放鬆身心，才得以接納它。', '當你亟欲得之，聖光就會消逝而去。你必須放鬆身心，才得以接納它。', 66384),
(308412, 'zhTW', '只有在寂靜的時候，我們才感覺得到聖光的溫暖與力量。', '只有在寂靜的時候，我們才感覺得到聖光的溫暖與力量。', 66384),
(308411, 'zhTW', '『成長羅亞』奧耶。在眾神當中，祂是最不為人知的。\n\n在我們稱為大樹樁的峭壁上尋找巨木。挑戰岩松。奧耶將會評斷你的價值。', '', 66384),
(308404, 'zhTW', '啊，『危機羅亞』普爾。祂會以深海最凶狠的形體之一現身在膽大之人面前：鯊魚。\n\n敢在祖阿曼的兇險水域釣魚的人，將能得到祂的青睞。', '', 66384),
(308399, 'zhTW', '『豐足羅亞』老鼠敦敦…在眾神之中確實獨樹一格。\n\n他大概會在枯木村西邊的羅亞尼特之穴。', '', 66384),
(308398, 'zhTW', '啊…『詭計羅亞』沙德拉。\n\n最近通常不允許信奉祂。如果你想知道更多，就去找惡齒部族的佩爾娜‧斷齒。\n\n聽說她一直在枯木崖調查關於信奉者的謠言。', '', 66384),
(308397, 'zhTW', '聖光並沒有要你活得毫無痛苦，只希望你能走過傷痛。', '聖光並沒有要你活得毫無痛苦，只希望你能走過傷痛。', 66384),
(308396, 'zhTW', '平靜也是一種奉獻。', '平靜也是一種奉獻。', 66384),
(308395, 'zhTW', '讓聖光帶走你沉重的負擔。', '讓聖光帶走你沉重的負擔。', 66384),
(308394, 'zhTW', '把你的哀傷放在中央。聖光會為你承擔。', '把你的哀傷放在中央。聖光會為你承擔。', 66384),
(308393, 'zhTW', '有時寂靜才是導向聖光的正道。', '有時寂靜才是導向聖光的正道。', 66384),
(308392, 'zhTW', '森林部族的許多人都信奉著『旅人羅亞』威拉瑪。\n\n一旦你證明自己是我們族人的盟友，通往偉大猛瑪象的道路必定會為你敞開。', '', 66384),
(308391, 'zhTW', '『疫病羅亞』莫塔拉的形體是一隻盔甲蜥蜴。\n\n我的耳邊聽到低語，提到暮光之刃褻瀆了我們的羅亞。深入位在破碎王座底下的地穴，自己親眼見證吧。', '', 66384),
(308389, 'zhTW', '啊。『童年羅亞』菲洛。祂的形體是頭年長的水豚。\n\n或許枯木崖還有一兩個孩童會以古老的方式祭拜祂。', '', 66384),
(308386, 'zhTW', '', '你應該可以在埃達希爾的樹根找到反思過錯的歐恩肖。', 66384),
(308385, 'zhTW', '『良藥羅亞』庫爾吉的形體是一隻尊貴的穿山甲。\n\n祂的聖壇就座落在阿塔阿曼東邊的山丘上，但已經沒落很久了。', '', 66384),
(308338, 'zhTW', '我只對一部分的羅亞比較熟悉…其他就沒這麼清楚了。\n\n不過我可以告訴你各個羅亞大致的出沒區域。\n\n你對哪位羅亞比較有興趣？', '', 66384),
(308335, 'zhTW', '祝福祭壇是祭拜所有祖阿曼羅亞的地方。\n\n聖壇和神廟有各自的羅亞，但要朝聖也會遇上困難…特別是那些信徒較少的古老羅亞神廟。\n\n有些羅亞會對同時信奉多名羅亞感到不悅，但你是特別的，哈巫拉。\n\n羅亞看到了你的潛力，允許你同時信奉多名羅亞。祂們也會為你施予祝福。', '', 66384),
(308331, 'zhTW', '哈巫拉的到來讓我倍感榮幸。\n\n我能幫什麼忙嗎？', '', 66384),
(308316, 'zhTW', '', '我看看能幫上什麼忙。', 66384),
(308314, 'zhTW', '<你眼前的符文又再次變化，變得更加清晰。>\n\n我的武器…結束了戰爭。\n\n…全都結束了…城市被夷為平地…不再有戰爭…全都沒了…\n\n只有…最小的生命存活下來…歷經萬千年的演化…現在成了怪物…\n\n…在最後一波…在我的末日之前…背叛了我…\n\n…將我封印…\n\n我給了他們想要的東西…卻承受懲罰…', '<你眼前的符文又再次變化，變得更加清晰。>\n\n我的武器…結束了戰爭。\n\n…全都結束了…城市被夷為平地…不再有戰爭…全都沒了…\n\n只有…最小的生命存活下來…歷經萬千年的演化…現在成了怪物…\n\n…在最後一波…在我的末日之前…背叛了我…\n\n…將我封印…\n\n我給了他們想要的東西…卻承受懲罰…', 66384),
(308313, 'zhTW', '', '噢，天啊，你這是我見過最混亂的時間線了。', 66384),
(308312, 'zhTW', '<你眼前的符文又再次變化，直到你能閱讀部分文字。>\n\n帝國…發動攻擊…\n\n…城市…一座又一座…遭到毀滅。直到全都化為灰燼…\n\n…\n\n…他們需要我。他們問我…偉大的阿奇杜德…\n\n…能否打造武器…來拯救他們…', '<你眼前的符文又再次變化，直到你能閱讀部分文字。>\n\n帝國…發動攻擊…\n\n…城市…一座又一座…遭到毀滅。直到全都化為灰燼…\n\n…\n\n…他們需要我。他們問我…偉大的阿奇杜德…\n\n…能否打造武器…來拯救他們…', 66384),
(308190, 'zhTW', '嘿，你來了！莫塔很希望你來。\n\n已經在坑洞看過你戰鬥了。\n\n你上次打得很漂亮。但怨鬥坑洞是個危險的地方！可別被殺掉了，$p！\n\n所以莫塔才待在安全的地方。', '', 66384),
(308181, 'zhTW', '', '聖光先鋒正在集結部隊，準備進攻虛無之尖。你是來加入他們的嗎？\n\n請注意，一旦進攻開始，就無法回頭了。', 66384),
(308176, 'zhTW', '有的，就是我的同胞。進入漩渦之後，你就會懂了。', '', 66384),
(308162, 'zhTW', '<從未見過的符文閃爍著虛無魔法的光芒，然後開始變化。突然之間，你能讀懂那些支離破碎的文字了。>\n\n我們偉大的人民…\n\n…我們打造的城市…無比宏偉…在空中閃閃發光…\n\n普雷達希亞…無與倫比的知識…與學術的成就…\n\n…我們最偉大的武器…在未來的戰爭中將有所發揮。', '', 66384),
(308154, 'zhTW', '現在齊亞丹和我要回去戰鬥了。謝謝你，也希望能在戰場上相會，$c。', '', 66384),
(308153, 'zhTW', '活該，查洛納斯就該死在自己的競技場裡。從你的世界抓捕了這麼多凡人，是該讓他嚐嚐你的怒火。', '', 66384),
(308152, 'zhTW', '', '你的實力真令人欽佩。希望還能在戰場上見到你。', 66384),
(308151, 'zhTW', '', '你表現得很好，凡人。查洛納斯再也不會威脅殺戮者高地，或是從你的世界抓捕凡人來帶到他的競技場戰鬥了。', 66384),
(308132, 'zhTW', '', '殺死維迪奧斯的手下。如果你跟聯盟沒有恩怨，那就集中攻擊虛無爪牙。', 66384),
(308130, 'zhTW', '$c，讓齊亞丹見識聯盟的怒火。要是你不想讓太多部落成員濺血，戰場上也有很多虛無爪牙讓你殺個夠。', '', 66384),
(308129, 'zhTW', '', '有必要的時候。如果我不聽話，我就沒辦法繼續待在這裡了。她已經說得很清楚了。\n\n儘管如此，我和維迪奧斯控制著殺戮者高地。只要我們的衝突繼續製造紛爭和痛苦…為她的虛無風暴製造更多虛無能量，她也不介意讓我們自由過活。這對我們來說是最適合的安排。\n\n沒有哪個多曼納爾樂意服侍她。\n\n就目前來說，我們不會去招惹她。', 66384),
(308127, 'zhTW', '', '我們多曼納爾很喜歡一場痛快的戰鬥，不論是參加還是旁觀。我們常常穿梭於不同世界之間，從其他世界擄走鬥士，讓他們在競技場中戰鬥。\n\n艾澤拉斯曾是「禁區」。不過在薩拉塔斯入侵後就解禁了。\n\n維迪奧斯找到了聯盟。我找到部落了。你們對榮耀的野心吸引著我。我找到了最具實力，不願放下仇恨的人們，那些不接受和平談判和條約的人。\n\n我把他們帶到這裡，實現他們最大的願望：屠殺聯盟。他們為此感謝我。而我僅僅只是在享受他們仇恨的滋味。', 66384),
(308125, 'zhTW', '<維迪奧斯把頭歪向一邊。>\n\n嚴格來說是。\n\n所有多曼納爾都被迫向薩拉塔斯俯首稱臣。這麼做有違多曼納爾的天性，但另一條路只會通向毀滅。那有什麼樂趣可言？\n\n儘管如此，薩拉塔斯很清楚她手中的哪些工具對她最有用。我和齊亞丹只是…變得讓自己對她來說沒有用處。還有其他更強大或更合作的多曼納爾，她可以更好地操控他們。\n\n所以，我和齊亞丹繼續著我們的戰爭，而薩拉塔斯也沒怎麼介入。我們只是…不在她的考慮範圍內。\n\n至少目前是這樣。', '', 66384),
(308124, 'zhTW', '連讓我塞牙縫的資格都沒有…', '', 66384),
(308122, 'zhTW', '哦，單純是利用我們多曼納爾最令人畏懼的力量。我們可以穿越到其他世界，隨心所欲挑選戰鬥者。雖然自願參戰的鬥士最為罕見，但也最有趣…\n\n艾澤拉斯被定義為…「禁區」有一段時間了。自從薩拉塔斯推翻我們之後，這種情況就改變了。\n\n我和齊亞丹馬上就對部落和聯盟產生了興趣。我盡可能尋找聯盟中最嗜血、最憤怒的成員：這些人單純為了抓住機會屠戮部落，自願放棄參加拯救艾澤拉斯免受虛無吞噬的戰鬥。\n\n最令我高興的是，這樣的人竟然還不少。\n\n所以，他們是自願來到這裡的。他們心甘情願地以我的名義戰鬥。而我也樂在其中。', '', 66384),
(308120, 'zhTW', '如果和部落搏命並非你的目的，你也可以考慮幫助我阻止齊亞丹把她的征戰擴大到艾澤拉斯。', '', 66384),
(308110, 'zhTW', '$p，你也聽到那個聲音了嗎？', '', 66384),
(308098, 'zhTW', '', '維迪奧斯是個狡猾的敵人。他精通各種不同的武器。與他的每一場切磋都會有截然不同的體驗。\n\n最近，我們的交鋒都演變成了大規模的戰鬥：決鬥變得更少，戰爭變得更多。我更喜歡決鬥，但這能讓維迪奧斯的頭腦保持敏銳。經過無數的歲月，我們偶爾也需要換換口味。\n\n部落和聯盟的到來，讓我們的遊戲變得更有意思。', 66384),
(308059, 'zhTW', '那就這麼說定了。我們競技場見，$c。', '', 66384),
(308058, 'zhTW', '', '維迪奧斯，這件事搞定之後，我們就繼續進行我們永無止境的戰爭吧…伴隨著嶄新的活力。', 66384),
(308057, 'zhTW', '那確實聽起來是個令人愉悅的景象。你會在自己的競技場裡迎來死亡，查洛納斯。', '', 66384),
(308054, 'zhTW', '確實，你把我的競技場徹底毀掉了！真是好極了！我完全沒料到一個凡人有這樣的實力。我有個提議要給你。', '', 66384),
(308053, 'zhTW', '', '查洛納斯！真是不意外。你總是對影芽情有獨鍾。我們已經除掉你的移植者了。', 66384),
(308052, 'zhTW', '啊，你終於來了！請原諒我的缺席。與某些人不同，我會在受到薩拉塔斯的召喚時去為她辦事。', '', 66384),
(308047, 'zhTW', '這年份還真不得了。', '這年份還真不得了。', 66384),
(308045, 'zhTW', '這個算是我們比較年輕的種類。只有大概一千兩百年而已。', '這個算是我們比較年輕的種類。只有大概一千兩百年而已。', 66384),
(308044, 'zhTW', '哦，是乳酪！這是陳年乳酪嗎？', '哦，是乳酪！這是陳年乳酪嗎？', 66384),
(308034, 'zhTW', '我們以前從來沒有這種研究虛無的機會。', '', 66384),
(308031, 'zhTW', '', '除非她指引你離開我們。', 66384),
(308030, 'zhTW', '', '難道我不該跟隨她的指引嗎？', 66384),
(308029, 'zhTW', '', '我聽見她的聲音了！', 66384),
(308028, 'zhTW', '你的傲慢會讓我們的一切陷入危險！', '', 66384),
(308027, 'zhTW', '但隨之而來的是傲慢，和魯莽。', '', 66384),
(308026, 'zhTW', '顯然艾恩哈拉之手眷顧你，孩子。', '', 66384),
(308025, 'zhTW', '', '女神？', 66384),
(308024, 'zhTW', '', '（驚呼）', 66384),
(308023, 'zhTW', '', '你們就只會整天窩在洞穴裡，哀悼著枯萎的過去嗎？', 66384),
(308022, 'zhTW', '', '難道我們不該效法他們嗎？', 66384),
(308021, 'zhTW', '', '他們為救她而戰！', 66384),
(308020, 'zhTW', '', '他們也能夠聽見女神的歌聲！', 66384),
(308019, 'zhTW', '', '…他們的存在對聖域，就是種褻瀆。', 66384),
(308018, 'zhTW', '', '邀請那些外來者到此…', 66384),
(308017, 'zhTW', '你究竟破壞了多少神聖的傳統，孩子？', '', 66384),
(308016, 'zhTW', '', '你早就拋棄那種東西了，歐薇娜。', 66384),
(308015, 'zhTW', '', '尊重？', 66384),
(308014, 'zhTW', '', '但如果你們想使用暴力…', 66384),
(308013, 'zhTW', '', '這是出於尊重。', 66384),
(308012, 'zhTW', '', '我是來談話的。', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(308011, 'zhTW', '', '現身吧。', 66384),
(308010, 'zhTW', '', '到此為止。', 66384),
(307978, 'zhTW', '…永遠無法救贖。', '', 66384),
(307977, 'zhTW', '兒子，有些事物…', '', 66384),
(307976, 'zhTW', '（嘆氣）', '', 66384),
(307975, 'zhTW', '別放棄希望，父親。', '', 66384),
(307974, 'zhTW', '但別完全投入。', '', 66384),
(307973, 'zhTW', '那部分的我和洛薩一同死去。', '', 66384),
(307972, 'zhTW', '（嘆氣）辦不到。', '', 66384),
(307971, 'zhTW', '我…', '', 66384),
(307970, 'zhTW', '履行你聖騎士的天命。', '', 66384),
(307969, 'zhTW', '再次拿起它。', '', 66384),
(307968, 'zhTW', '怎麼會？你是怎麼…', '', 66384),
(307967, 'zhTW', '我…我的盾。', '', 66384),
(307966, 'zhTW', '是時候，該放下了。', '', 66384),
(307965, 'zhTW', '你背負著這些情緒。', '', 66384),
(307964, 'zhTW', '憤怒…', '', 66384),
(307963, 'zhTW', '罪惡感…', '', 66384),
(307962, 'zhTW', '我知道洛薩身亡時發生什麼事了。', '', 66384),
(307961, 'zhTW', '你是時候該原諒自己了。', '', 66384),
(307960, 'zhTW', '我想…', '', 66384),
(307959, 'zhTW', '你願意原諒我嗎？', '', 66384),
(307958, 'zhTW', '你失去控制了。', '', 66384),
(307957, 'zhTW', '但那個瞬間，', '', 66384),
(307956, 'zhTW', '我知道，你並不是真的想傷害我。', '', 66384),
(307955, 'zhTW', '父親。', '', 66384),
(307954, 'zhTW', '我們可以…', '', 66384),
(307953, 'zhTW', '我原本是想…', '', 66384),
(307952, 'zhTW', '阿拉特，我…', '', 66384),
(307951, 'zhTW', '兒子…', '', 66384),
(307933, 'zhTW', '<小食人妖的足跡通往一個摔碎在地上的陶製茶壺。\n\n看起來像是有人拿著它時絆到腳，把它掉在地上。\n\n壺蓋斷成兩半，把手也不見了，從上面的裂痕不難看出，它已經不能裝水了。\n\n它原本的攜帶者選擇把它留在這裡，而水豚們正好奇地研究它。>', '<小食人妖的足跡通往一個摔碎在地上的陶製茶壺。\n\n看起來像是有人拿著它時絆到腳，把它掉在地上。\n\n壺蓋斷成兩半，把手也不見了，從上面的裂痕不難看出，它已經不能裝水了。\n\n它原本的攜帶者選擇把它留在這裡，而水豚們正好奇地研究它。>', 66384),
(307916, 'zhTW', '', '嗯…沒錯，一定是。一名入侵者。', 66384),
(307906, 'zhTW', '', '說真的，我自己也不太確定。達拉然沉入海底後，白銀誓盟盡力搶救剩餘的部分。在一次救援行動中，我們發現了這些飛龍和一些倖存者！很顯然，達拉然毀滅時，是這些飛龍前來營救他們。從那時起，我們就一直在照顧牠們。\n\n有一個傳聞，說是達拉然的一位藝術家用某種方式創造了這些飛龍。據說她夢見了這些飛龍，並創作了許多以牠們為主題的畫作，但從來沒賣出過半幅。當被問到原因時，她說她是為了達拉然才畫出這些畫…當達拉然的人民需要幫助時，這些畫作就會活過來，而巨龍會現身幫助他們。\n\n真是個離譜的故事，對吧？不過我們也沒機會驗證了。', 66384),
(307904, 'zhTW', '', '哦，請不用理我，勇士$n。\n\n揮動鏟子也是照顧神話野獸的樂趣之一。', 66384),
(307903, 'zhTW', '無數世紀以來，齊亞丹一直都是我的死敵。我們為了爭奪殺戮者高地的統治權，在光榮而難以抗拒的血腥浪潮中廝殺。\n\n我們曾多次差點將對方消滅。大片地盤在我們之間易手無數次。\n\n真是令人愉悅的遊戲。其他方式我可無法接受。', '', 66384),
(307902, 'zhTW', '<一段由水果、小水豚和食人妖腳印構成的蹤跡一路從角蛙屍體延伸到一個掉在地上的空籃子。\n\n籃子上有一個大洞，可能是因為和角蛙爆發衝突造成的。\n\n水豚似乎很喜歡水果，並把籃子的破損當成了一場美好的意外。>', '<一段由水果、小水豚和食人妖腳印構成的蹤跡一路從角蛙屍體延伸到一個掉在地上的空籃子。\n\n籃子上有一個大洞，可能是因為和角蛙爆發衝突造成的。\n\n水豚似乎很喜歡水果，並把籃子的破損當成了一場美好的意外。>', 66384),
(307901, 'zhTW', '即使我的東西被燒毀了，我的耳裡還是能聽到那個聲音。\n\n但現在已經安靜下來了，我又可以自己思考了！', '', 66384),
(307897, 'zhTW', '我還在因為見到納羅拉克而顫抖。看見祂治療皮戈真是太驚人了！\n\n祂告訴我應該用哪一個法術。\n\n我知道該怎麼做來幫助他人。有皮戈的幫忙，我們會一起彌補一切。', '', 66384),
(307892, 'zhTW', '不、不、不，皮戈！\n\n我們要怎麼救皮戈？', '', 66384),
(307858, 'zhTW', '', '還需要什麼理由嗎？\n\n小$rs，你們的領導人看不出我們多曼納爾所擁有的戰鬥價值，屬實是一大悲劇。我們存在於此的目的就是戰鬥。\n\n只有勇敢、有實力，以及腦子有問題的人才明白在這裡拿起武器的勇氣。只有他們才能體會一場酣暢淋漓的戰鬥所帶來的喜悅。\n\n在這個戰場上，你不是為部落而戰。你是為我而戰。你會為了取悅我戰鬥至死，而我們將一起享受這場與維迪奧斯的衝突。\n\n用盡全力奮戰，我將賜給你無上的光榮。', 66384),
(307854, 'zhTW', '我們離凱瑞西非常遙遠。我從來就不想被捲入這麼多的衝突。\n\n恬淡人生的概念似乎像是地平線上的遙遠幻象。', '我們離凱瑞西非常遙遠。我從來就不想被捲入這麼多的衝突。\n\n恬淡人生的概念似乎像是地平線上的遙遠幻象。', 66384),
(307853, 'zhTW', '我不知道自己能否適應這樣的生活。我需要依靠其他人…\n\n<隨著虛無繃緊這名以太族的裹布，他的身體畏縮了一下。>\n\n或許這些精靈中有人能幫我找到忍受這些顫抖的方法。', '這種痛苦簡直難以忍受…就像是我的精華受到扭曲，然後被拉向兩個不同的方向。\n\n我還記得影衛試圖讓迪曼修斯復活…想到這麼做可能帶來的毀滅…\n\n<以太族打了幾個冷顫。>\n\n…然而，我心中的一股黑暗衝動，卻堅持想服從虛無的意志。難道我們注定要永遠臣服於虛無嗎？', 66384),
(307852, 'zhTW', '', '響應我號召的部落叛徒們正在醞釀著對聯盟血肉的嗜血渴望。你也一樣嗎？', 66384),
(307850, 'zhTW', '我越是冥想我的過往，它就變得越是清晰。\n\n要與我們體內的黑暗共存會很艱難…但知道我們並不孤單就很令人欣慰了。', '', 66384),
(307849, 'zhTW', '在這些聯盟叛徒心中燃燒的仇恨真是太美味了。你也是為了復仇而戰嗎？', '', 66384),
(307848, 'zhTW', '我們虛無精靈比大多數人更了解來自虛無的誘惑低語。\n\n儘管有些人對我們嗤之以鼻，但多虧了聯盟的歡迎，我們才不必過著放逐者的生活。\n\n如果我們不接納這些以太族，那我們只不過是殘酷的偽善者。即使是受虛無掌控的生命，也依然值得活下去…也值得拯救。', '我們虛無精靈比大多數人更了解來自虛無的誘惑低語。\n\n儘管有些人對我們嗤之以鼻，但多虧了聯盟的歡迎，我們才不必過著放逐者的生活。\n\n如果我們不接納這些以太族，那我們只不過是殘酷的偽善者。即使是受虛無掌控的生命，也依然值得活下去…也值得拯救。', 66384),
(307846, 'zhTW', '', '那場戰鬥！那種刺激感！\n\n我看到你了，$c。你當時熱血沸騰，就和我一樣。\n\n我為許多死去的惡齒族人哀悼。但我們在戰鬥中面對彼此，而每個祖阿曼的食人妖都知道拔刀所代表的含意。', 66384),
(307845, 'zhTW', '我們與家人共享的羈絆無可取代。你幫助我和妹妹重聚，我欠你一個很大的人情。\n\n如果可以的話，我們會去找更多像維蘭一樣的人。一定還有其他可以從黑暗邊緣救回來的人。', '', 66384),
(307842, 'zhTW', '', '看看四周。就算在這個宇宙荒原裡，這些多曼納爾還是能把部落和聯盟分開。分成藍方與紅方。這就是世界的運作方式。\n\n不論有沒有戰爭，總是會有一些無法放下恩怨的人。無法忘記過去的人。我在布瑞納丹曾有家人。我媽那邊還有很多善良的農戶。他們永遠不會忘記，我也不會。\n\n戰爭或許已經結束，但是對依然需要戰爭的我們來說，戰鬥會不停繼續下去。', 66384),
(307836, 'zhTW', '我們離凱瑞西非常遙遠。我從來就不想被捲入這麼多的衝突。\n\n恬淡人生的概念似乎像是地平線上的遙遠幻象。', '我們離凱瑞西非常遙遠。我從來就不想被捲入這麼多的衝突。\n\n恬淡人生的概念似乎像是地平線上的遙遠幻象。', 66384),
(307834, 'zhTW', '很多年前，我的族人在戰場上贏得榮耀。如今，他們靠在議會中發言來贏得榮耀。雖然那是平穩的生活，但並非適合我的道路。\n\n我來到這陌生的世界，是為了做好準備，面對下一場威脅我族人的戰爭。當那一天到來時，我早已變得銳不可當，身經百戰。\n\n你的到來告訴我，你也有勇氣去追求屬於你自己的榮耀。願你的先祖在戰場上守望著你。', '', 66384),
(307832, 'zhTW', '能幫忙完成奇異點錨是我的榮幸。它能透過將異常虛無能量凝聚在熵槽周圍來將其無效化，有點像一台非常恐怖的除濕機。真是太神奇了！\n\n當然，凝聚矩陣必須保持完好，否則能量很可能會發生內爆。\n\n不過，在調整梵迪卡爾的扭曲產生器時，我學到了一些關於內爆和矩陣加強的知識。不用擔心！', '', 66384),
(307831, 'zhTW', '復仇控制了我的妹妹。她已經被蒙蔽了雙眼。\n\n她對虛無控制的反抗能力越來越強，但她只在乎自己的憤怒。', '', 66384),
(307823, 'zhTW', '我也經歷過黑暗的時期，$p。而且還不少。\n\n可以肯定的是，飛行真的為我的身心靈帶來不少好處，但畢竟不是所有人都有獅鷲獸！\n\n如果你沒有，那麼你得找到屬於你自己的獅鷲獸。\n\n對我來說…講笑話也有幫助。如果能在艱難的時刻大笑幾聲…好吧，我們之後還會遇上不少難關。既然這樣也只能笑了。\n\n還有和朋友們喝上一杯，任何煩惱都會顯得微不足道。朋友本身比喝酒更重要！\n\n而有時候你總是得繼續向前進，飛向遼闊的天空，不管你準備好了沒。我們出發吧？', '', 66384),
(307821, 'zhTW', '許多年前，我曾在這裡和末日錘並肩作戰，對抗洛薩的軍隊。\n\n與那些繼承他姓氏的人合作，感覺很奇妙…應該說與人類合作這件事本身就很奇妙。\n\n然而也是某個人類的奇妙之處改變了我的看法：提里奧‧弗丁。我對人類的了解只有他們對我同胞的憎恨，因為我們將戰火帶到了他們的土地。\n\n但是當其他人只把我視為應該被獵殺的野獸時，弗丁卻有不同的看法。即使在我們初次相遇時差點殺死對方之後，他仍然對我展現出了善意和同情。\n\n透過提里奧，我看見了人類與獸人並沒有區別。有些人有榮譽感，許多人則沒有。隨著時間推移，我發現洛薩之子屬於有榮譽感的那一群人。\n\n我想提里奧也會同意的。', '', 66384),
(307819, 'zhTW', '$p，這片區域裡到處都是黑暗部落的覬覦者。榮耀驅使我們把他們驅逐出去。', '', 66384),
(307806, 'zhTW', '包括在海岸邊釣魚當早餐的枯木孩童！', '', 66384),
(307805, 'zhTW', '祖阿曼各地的枯木族人會前來哈拉齊的神廟朝聖，並留下一件狩獵戰利品祭拜祂。', '', 66384),
(307804, 'zhTW', '從我們來到這片土地，祂就一直指引阿曼尼，一直以來，祂都是我們部族的化身和象徵。', '', 66384),
(307803, 'zhTW', '', '很久以前，當一名古代的羅亞語者在神廟的火焰中看見一道幻象時，他帶領部族遷移到安全的地方，影松便是在那時成為賈納雷的主要信徒。', 66384),
(307802, 'zhTW', '', '等勇士的力量恢復之後再試一次。', 66384),
(307801, 'zhTW', '', '新兵！這項挑戰考驗的是克制力，而不僅僅是蠻力。', 66384),
(307800, 'zhTW', '不，等等！我很抱歉，我不是故意要…', '', 66384),
(307799, 'zhTW', '', '在四大羅亞中，惡齒部族最中意祂，因為祂那直接了當的態度，還有對戰場的精通。', 66384),
(307797, 'zhTW', '一開始，他們不相信我說的半個字。不知為何，洛摩斯以為我在嘲笑他。但艾歐卡的種子激起了他們的興趣。\n\n他們能提出的只有理論。其中最合理的解釋是，太陽之井的過度活躍將聖光的影響力擴散到了大地本身…直接灌入永歌森林的樹木和根系。而既然所有的根系都通往哈朗達…\n\n<赫杜倫指向夏達希爾的樹根。>\n\n在軍團之殞那段期間，夏達希爾的樹根向暗影屈服。或許正是因為這樣，才導致它們更容易受到太陽之井擴散的聖光所影響。', '', 66384),
(307796, 'zhTW', '我唯一想要的，就是為了保護家園而戰的榮耀。\n\n還有一根稱手的長矛。\n\n看看我現在的樣子，如何啊？', '', 66384),
(307794, 'zhTW', '', '你為什麼要站在這裡發呆，嗯？\n\n一名鬥士的訓練永遠沒有盡頭。就算是像你這樣的高手也一樣，$n。', 66384),
(307793, 'zhTW', '哦，這裡一點魔法，那裡一點魔法。失去了我的身體，需要一具新的身體。就和往常一樣！\n\n但這是我們第一次見面。現在說這些也沒意義。\n\n在西南邊的海灘旁有個奇特的地方。有空來拜訪我嗎？', '', 66384),
(307791, 'zhTW', '對啦，我被困在這個娃娃的身體裡面。那又怎樣？', '', 66384),
(307784, 'zhTW', '有話快說，我還有好多事要忙。', '有話快說，我還有好多事要忙。', 66384),
(307780, 'zhTW', '祝你順利找到她。你找到她的時候，她會對你低吼。或是又跑掉一次！', '', 66384),
(307779, 'zhTW', '坎莎？我看見她跑向了我們經常去玩的那座木橋。', '', 66384),
(307773, 'zhTW', '', '這些怪物想讓其他人沉溺於虛無之中…這是我不願讓任何人遭逢的命運！', 66384),
(307771, 'zhTW', '冷靜點，維蘭。為復仇迷失自我和屈服於虛無沒有任何區別。', '', 66384),
(307769, 'zhTW', '你可能有聽說過，我們在太陽之井遇襲的地點附近找到了一個隱藏的護甲和武器貯藏庫。\n\n嗯，就算崔安說大部分裝備都沒有受損，它們也已經被閒置了好幾年。我只是想在實際使用之前，確保它們功能都還正常。\n\n我被要求在這裡設置一個熔爐來為特遣隊員提供協助，所以如果有需要幫忙的地方，就說一聲！', '', 66384),
(307767, 'zhTW', '你好，$r，需要幫忙嗎？', '', 66384),
(307760, 'zhTW', '', '我能看出你一部分的靈魂依然留存於過去，處於一場大戰正在進行中的時刻。\n\n你想穿越到此刻之前的時空嗎？\n\n|cFF0000FF（你可以隨時再次與賈納雷人形對話來回到這個版本的阿塔阿曼。）|r', 66384),
(307757, 'zhTW', '', '我能看出你的靈魂與另一個曾經歷過這場戰鬥的靈魂相連結。\n\n你想穿越到超出此刻的時空嗎？\n\n|cFF0000FF（你可以隨時再次與賈納雷人形對話來回到這場戰鬥。）|r', 66384),
(307751, 'zhTW', '', '維迪奧斯已經收到我的訊息。他不會拖太久的。他最喜歡來一場豪賭。你那邊有什麼消息？', 66384),
(307750, 'zhTW', '這種痛苦簡直難以忍受…就像是我的精華受到扭曲，然後被拉向兩個不同的方向。\n\n我還記得影衛試圖讓迪曼修斯復活…想到這麼做可能帶來的毀滅…\n\n<以太族打了幾個冷顫。>\n\n…然而，我心中的一股黑暗衝動，卻仍想服從虛無的意志。難道我們注定要永遠臣服於虛無嗎？', '這種痛苦簡直難以忍受…就像是我的精華受到扭曲，然後被拉向兩個不同的方向。\n\n我還記得影衛試圖讓迪曼修斯復活…想到這麼做可能帶來的毀滅…\n\n<以太族打了幾個冷顫。>\n\n…然而，我心中的一股黑暗衝動，卻仍想服從虛無的意志。難道我們注定要永遠臣服於虛無嗎？', 66384),
(307746, 'zhTW', '他們在我體內注入的虛無依然在發出尖嘯…但當我看著這枚吊墜時，我在凱瑞西時的記憶便會劈開這道黑暗。\n\n這個珠寶是我母親的東西…是父親送給她的禮物…也是他們無私愛情的象徵。\n\n暗影仍然在誘惑我屈服…去毀滅…但它們現在感覺變得更遠了…它們對我心靈的腐化之握感覺也沒那麼強烈了。', '', 66384),
(307743, 'zhTW', '哦，是的。我是特遣隊中的動物管理員。我們必須做好準備，隨時部署一批飛行動物。\n\n如果這還不夠，他們還告訴我，我得負責照顧特遣隊可能收集到的任何生物。當然了，就連遊俠隊長也沒辦法告訴我會出現什麼。\n\n好了，這就是一個低階士官的日常。要是沒其他問題，我得回去工作了。', '', 66384),
(307740, 'zhTW', '請快一點，我有很多事要做。', '', 66384),
(307738, 'zhTW', '當然是，但付出的代價呢？\n\n一定有兩全其美的辦法，能打敗敵人，又保全我們的史蹟。\n\n不同於暗幽谷女士的意見，我認為我們絕對可以兩者兼顧。她對黑暗力量的執著，已經毀了她曾經纖細的處事手段。', '', 66384),
(307736, 'zhTW', '關於她處事手段的…一切啊！研究歷史古蹟、調查詭異的魔法、還有保存強力聖物的手段都是！\n\n這位暗幽谷「女士」不在乎保存我們的史蹟，她只想理解帶來威脅的黑暗而已。即便要採取破壞性的手段，她也不介意。', '', 66384),
(307734, 'zhTW', '別告訴我你也跟暗幽谷女士同一國吧，$C？', '', 66384),
(307732, 'zhTW', '', '聖匣守護者？我嗎？可惜不是。\n\n我一直都覺得他們的作為很有趣，我甚至還有對泰瑟連為探勘籌錢用的奢侈晚會進行募資呢。\n\n但可惜的是，高階審查員從未讓我正式加入。肯定是我不小心冒犯到他了。\n\n<暗幽谷女士露出靦腆的笑容。>\n\n即便如此，當他們需要熟悉黑暗儀式和歷史知識的人，我仍是第一人選。\n\n他沒辦法否認我的資格，所以派了這位安多連過來，來對我說教…老實說，反正我現在也沒在聽他的鬼話了。', 66384),
(307730, 'zhTW', '', '<暗幽谷女士嘆了口氣。>\n\n考量到銀月城現在的狀況，帶我平常的…隨扈來這座城市實在不太明智。\n\n布羅席尼爾斯不在時，我有替代的選項可用。但在他面前要守規矩，好嗎？他還蠻認真看待自己的職責的。', 66384),
(307728, 'zhTW', '', '<暗幽谷女士打量著你，將頭微傾。>\n\n像你這樣重要的$C能幫我什麼忙？', 66384),
(307727, 'zhTW', '', '年輕嗎…我其實是基地裡最年長的見習探險者！\n\n此外，我從以前就開始和雷亞娜一起研究神器。她同意讓我以學徒的身分入隊。\n\n我從沒來過像銀月城這樣的城市。這裡真是太壯觀了！我們曾經去過沃卓肯，但這裡的熱鬧程度更勝一籌。', 66384),
(307725, 'zhTW', '', '噢，你好啊！', 66384),
(307724, 'zhTW', '', '遊俠隊長認同我在聖物研究方面的經驗，他認為在往後面對威脅時，這將會是寶貴的戰力。\n\n在這之前，我正在為龍鱗遠征隊進行聖物的編目工作。當我們的營地接獲太陽之井遇襲的消息時，我便和那些急忙趕回銀月城的人一起回來。\n\n我從沒有忘記許多年前奎爾薩拉斯的眾人集結起來保衛蘇拉瑪爾的時光。我願意貢獻一己之力。', 66384),
(307722, 'zhTW', '', '你好，$r。', 66384),
(307720, 'zhTW', '我們的人對最近城市遭到襲擊時留下的遺物做了一些研究。這些物品似乎被灌注了隱性虛無魔法，我認為這顯著地提高了物品的潛在能力。\n\n物品的物理性質也受到改變，讓它們看起來超乎尋常！真是有趣，你說是吧？\n\n一旦我們確認這些物品不會造成危險，就能幫我們的士兵著裝，用這股力量反過來對付敵人！', '', 66384),
(307718, 'zhTW', '這真是個有趣的發現！', '', 66384),
(307717, 'zhTW', '', '在薩拉塔斯攻擊太陽之井的期間，附近的一棟建築遭到破壞。等救難隊進去尋找生還者時，他們發現了一個裝滿護甲和武器的秘密貯藏庫，很可能是許多年前燃燒軍團進攻時被藏起來的。\n\n我們正在分類哪些武器依然安全且有效。我們必須盡可能收集更多的武器和護甲。尤其是遊俠隊長組建了一支新特遣隊的當下。', 66384),
(307715, 'zhTW', '', '你好啊，我們現在有點忙，你需要什麼嗎？', 66384),
(307712, 'zhTW', '', '去吧，$rs。等你處理好之後再來和我會合。我們會直接和維迪奧斯正面交鋒。', 66384),
(307708, 'zhTW', '', '快來，$n。我的死敵維迪奧斯的部隊來襲了。', 66384),
(307706, 'zhTW', '', '總之，去憎惡尖塔一趟吧，$rs。我會在那裡。', 66384),
(307691, 'zhTW', '這個$c殺死了我的移植者，還蹂躪了我的老家。真教人欽佩。要是這個凡人召集盟友，在我的競技場上戰鬥，我就讓你們兩個繼續爭吵吧！', '', 66384),
(307689, 'zhTW', '幸好牠被束縛住了。$C，在我們削弱這頭野獸的時候，去找出並殺死移植者。最後一擊會留給你的。', '', 66384),
(307688, 'zhTW', '', '維迪奧斯，就算我們聯手，可能也不足以擊敗這頭怪物。', 66384),
(307687, 'zhTW', '我的製皮商品雖然不像卡莉卡的這麼花俏，但它們保證更堅固！', '我的製皮商品雖然不像卡莉卡的這麼花俏，但它們保證更堅固！', 66384),
(307686, 'zhTW', '針和線就和皮革一樣重要！', '針和線就和皮革一樣重要！', 66384),
(307683, 'zhTW', '', '我們很快就會繼續進行我們的遊戲。在那之前，我只能忍受與你並肩作戰。', 66384),
(307681, 'zhTW', '真是令人不悅的插曲。我原本看部落和聯盟廝殺看得正過癮。', '', 66384),
(307671, 'zhTW', '', '隨著虛無對太陽之井發動攻擊，我們的部隊正集中於對付他們在奎爾薩拉斯各地的主要攻勢。\n\n遊俠將軍赫杜倫‧亮翼交代我建立一支機動特遣隊，以便迅速應對任何新出現的襲擊。我們還發現一些過去的敵人正在趁亂展開行動。我們也會密切監視他們。\n\n第一個任務下達之後，我會馬上和你聯絡。', 66384),
(307669, 'zhTW', '', '$c，你好啊。你是來加入我們的嗎？', 66384),
(307666, 'zhTW', '做生意。\n\n我的生意。跟你無關。', '做生意。\n\n我的生意。跟你無關。', 66384),
(307663, 'zhTW', '這個世界的原生植物…真是邪惡到了極點！\n\n你在這裡找不到任何溫順的花朵。不，完全沒有，即使是虛無風暴的植物也在慢慢地互相吞噬，讓彼此窒息而死，或者用毒素令周圍的植物緩慢地死亡。\n\n我擁抱虛無，是為了找到終結這一切的方法。究竟我能不能培育出足夠頑強的植物，能夠承受這個世界的暴力，卻不會反過來變成掠食者？\n\n為此我把銀月城的靜心花移植到了各處。你可能已經注意到一些了！目前看來效果不錯，雖然我必須注入…少量的虛無能量才能讓它們有成功的機會。\n\n如果你看到任何盛開的植物，請隨意修剪它們，到那個階段它們已經散播好孢子了。', '', 66384),
(307642, 'zhTW', '', '你注意到虛無風暴周圍那些奇怪的漩渦了嗎？它們散發著一股奇怪的海洋氣息。\n\n要是能吃上一塊美味的魚肉，我什麼都願意做。怎樣？我是在海邊長大的。\n\n這些漩渦似乎有輕微的引力。我試著把浮標放在其中一個漩渦上耐心等待…沒想到竟然有魚上鉤了！\n\n我還以為我會釣到什麼巨大的水下巨獸！結果，我釣到的只是一些雖然有趣，卻又有點令人失望的普通魚類。\n\n然而，我並沒有在周圍看到任何水。這些漩渦一定是把空間扭曲到了某個充滿水的地方。\n\n這個世界上的某處有海洋嗎？還是這些漩渦能延伸到其他世界？', 66384),
(307635, 'zhTW', '', '這些祭壇似乎匯聚了死亡和虛無魔法。\n\n我不得不承認…我完全不明白這是怎麼辦到的。這些祭壇顯然是多曼納爾建造的，但它們完全是由虛無魔法構成，而非死亡魔法。\n\n我們唯一的多曼納爾盟友對此閉口不談。這會不會是他們的某種文化迷信或儀式？或者他們根本沒有刻意要在這些祭壇上召喚死亡魔法？或許這一切只是個巧合。\n\n<恰莉皺起眉頭。>\n\n我討厭這種難以理解的謎團。', 66384),
(307634, 'zhTW', '祝你武運昌隆，$rs。我會找機會與齊亞丹正面交戰。等你搞定之後就來和我會合。', '', 66384),
(307605, 'zhTW', '快過來，$n。我的死敵齊亞丹發起了意料之外的奇襲。', '', 66384),
(307604, 'zhTW', '', '<多魯長老無時無刻守望著她身邊的難民。>\n\n我負責殿後，確保所有人都能順利撤離。', 66384),
(307602, 'zhTW', '太陽指引你。', '太陽指引你。', 66384),
(307589, 'zhTW', '我想其中一位博學行者成員已經在銀月城內建立了說故事的地點。他應該能為你講述我們族人和太陽之井的歷史故事。', '我想其中一位博學行者成員已經在銀月城內建立了說故事的地點。他應該能為你講述我們族人和太陽之井的歷史故事。', 66384),
(307562, 'zhTW', '', '這是艾恩哈拉最偉大的餽贈：眾生共享的生命。因此，願你旅途中的每一步都能感受到艾恩哈拉的祝福。謝謝你，$n。', 66384),
(307561, 'zhTW', '', '但是你證明了這是值得的冒險。我們現在不僅了解了艾恩哈拉的土地，也了解了她的人民和文化。他們也同樣了解我們。', 66384),
(307560, 'zhTW', '', '當我想向這個世界的其他種族現出真身的時候，我猶豫了。這樣的傳統應該被打破嗎？', 66384),
(307558, 'zhTW', '', '儘管我們哈拉尼爾踏遍各地，但始終是在陰影和暗地中進行的。', 66384),
(307554, 'zhTW', '圖哈卡，親愛的。把這頂盔帽帶去吧。它是很棒的盔帽。能保護你的安全。拜託了…一定要平安無事。', '', 66384),
(307553, 'zhTW', '精靈會保護他們的城市。部落才不會在意區區幾個叛徒。我們必須讓聯盟認清自己的位置。你必須明白…', '精靈會保護他們的城市。部落才不會在意區區幾個叛徒。我們必須讓聯盟認清自己的位置。你必須明白…', 66384),
(307552, 'zhTW', '我了解。', '', 66384),
(307551, 'zhTW', '還有我的朋友哈拉娜，她也在那場戰鬥中犧牲。我不可能忘掉他們是怎麼屠殺她的！', '還有我的朋友哈拉娜，她也在那場戰鬥中犧牲。我不可能忘掉他們是怎麼屠殺她的！', 66384),
(307550, 'zhTW', '我知道。', '', 66384),
(307549, 'zhTW', '他們殺死了拉斯塔哈。我的王！我發誓要保護的人！你休想讓我放下這個恩怨。', '他們殺死了拉斯塔哈。我的王！我發誓要保護的人！你休想讓我放下這個恩怨。', 66384),
(307542, 'zhTW', '<紅眼盯著你。>\n\n如果你來這裡不是為了追求戰鬥和榮耀，在與部落的戰鬥中贏得最後的勝利，那就離開吧。\n\n所謂的「部落和聯盟必須共同面對的敵人」單純只是煙幕彈。大概只是由部落一手策劃，為了讓我們放鬆戒備的陰謀。\n\n他們肆虐我們的土地，殺死我們的同胞。絕對不能原諒他們。', '', 66384),
(307541, 'zhTW', '我知道我在戰場上只是個累贅，所以我在這裡會盡我所能。除此之外只是懦弱的行為。像你這樣的懦夫才不是我的兒子。', '', 66384),
(307540, 'zhTW', '拜託了，父親。這只是毫無意義的復仇。你根本不是戰鬥的料。媽也很擔心你。快點回家吧。', '', 66384),
(307539, 'zhTW', '你對族人的犧牲就這麼無所謂嗎？你的祖父在艾斯蘭戰死，而你卻袖手旁觀，和怪物一起共進晚餐？', '', 66384),
(307538, 'zhTW', '索姆嘆了口氣。', '', 66384),
(307537, 'zhTW', '我的心中有一種掙扎。\n\n其中一部分認為現在是觀察的時候。看著我的姊姊如何解決問題，並向她學習。\n\n但另外一部分…我不認為這條路是正確的。要是我們不提高警覺，我們的族人就會邁向一個軟弱的時代。', '', 66384),
(307535, 'zhTW', '', '我已經決定要回去並留在祖阿曼。\n\n雖然我長期對抗阿曼尼，深化雙方從過去以來的歷史仇恨，但這段時間也讓我有所感悟。\n\n我很清楚，過去的痛苦和憎恨很難放下。就連現在，我也還在學習。\n\n但…只有這樣才能迎向未來。一步一腳印。', 66384),
(307523, 'zhTW', '有個叫縛魂者娜辛德里的以太族人，他捕捉凱瑞西的靈魂，將它們與虛無綁定在一起。當艾澤拉斯的勢力擊潰了法力熔爐歐美加的影衛時，娜辛德里也一併被阻止。\n\n但是在那之前他已經讓我的很多同胞墮入黑暗。維蘭就是其中一個以太族…她的裹布被注入了虛無能量…靈魂受其意志束縛。\n\n如果他們中的一些人正在發起叛亂…那是不是代表影衛之中還有其他像他們一樣的人？', '', 66384),
(307517, 'zhTW', '', '很好。現在，我要拿走剩下的屍體。', 66384),
(307516, 'zhTW', '祖爾詹的雙眼閃爍著復仇的火光。', '', 66384),
(307496, 'zhTW', '', '看吧，科武？我就知道你做得到。', 66384),
(307495, 'zhTW', '誰，他？$B$B當時我發現老奈庫恩受傷了，還有一頭巨大的樹液迅猛龍正向他逼近。我純粹是靠運氣才把箭射入那頭野獸的脖子。$B$B那時候，我想過要結束老奈庫恩的生命。給予他長眠。不過，感覺就像大自然阻止了我，我沒辦法下手。我始終堅信我那天的決定是正確的。', '', 66384),
(307480, 'zhTW', '', '你殺死了主要的子實體，但我懷疑這不會是我們最後一次見到這種奇怪的真菌。\n\n我們被教導要將所有生命形式當成艾恩哈拉的造物敬重，但這些東西…\n\n<姬蔻嘆了口氣。>\n\n或許是我多慮了。我會暫時待在這裡，確保這種感染不會繼續擴散。', 66384),
(307473, 'zhTW', '', '外來者！看看我們找到了什麼！', 66384),
(307459, 'zhTW', '還需要什麼理由嗎？\n\n小$rs，你們的領導人看不出我們多曼納爾所擁有的戰鬥價值，屬實是一大悲劇。我們存在於此的目的就是戰鬥。\n\n只有勇敢、有實力，以及腦子有問題的人才明白在這裡拿起武器的勇氣。只有他們才能體會一場酣暢淋漓的戰鬥所帶來的喜悅。\n\n在這個戰場上，你不是為聯盟而戰。你是為我而戰。你會為了取悅我戰鬥至死，而我們將一起享受這場與齊亞丹的衝突。\n\n如果這個理由還不夠，那我賜給你的光榮獎勵，會在你保護你那寶貴的世界不被薩拉塔斯奪走時，起到很大的作用。', '', 66384),
(307455, 'zhTW', '無論如何，我都需要你的幫助。$rs，去一趟悲慟尖塔。我會在那裡等你。', '', 66384),
(307421, 'zhTW', '為復仇接受徵招！', '', 66384),
(307418, 'zhTW', '旅行者，你還真是奇特。不過所有人都能在艾恩哈拉的樹根下好好休息。', '旅行者，你還真是奇特。不過所有人都能在艾恩哈拉的樹根下好好休息。', 66384),
(307404, 'zhTW', '我一向比較喜歡在樹根間獨處。', '', 66384),
(307390, 'zhTW', '就我個人來說，我正在試著避免被奇異點開膛破肚、汽化或吞噬。\n\n通俗點來說，我們跟著你穿過傳送門後，在這裡建立了一個灘頭陣地。這可以讓吞噬之眾的注意力從初始地轉移。最好還是不要讓他們奪取我們通往銀月城核心的傳送門。\n\n與此同時，我們的研究員正在努力消滅要將我們全部瓦解的虛無異象。', '', 66384),
(307320, 'zhTW', '', '我們既是歷史學家，也是藝術家。透過我們的畫作，我們能記錄時代的真相…這是一項經由我們之前無數世代的雙手傳承下來的傳統。', 66384),
(307317, 'zhTW', '', '透過畫筆收集歷史需要冷靜的頭腦和穩定的手，正如我們的祖先教導的那樣。', 66384),
(307312, 'zhTW', '一開始，我們從安全的距離進行區域探查。一旦確定這裡的生物不會造成麻煩後，我們就會開始收集樣本。雖然我們可以輕鬆殺掉那些攻擊的生物，但這樣的殺戮也宣告了我們的死期。\n\n裂隙行者羅恩是第一個被感染的人，但等到我們發現時已經太晚了。病原體的效果並不是很明顯，而且也讓我們失去了判斷力。接著，我們一個又一個拋下該負的責任，並被體內那個不斷壯大的東西所驅使。\n\n我們太過相信自己的能耐，反而落入了敵人的隱藏陷阱。千萬別像我們一樣放下戒心。', '', 66384),
(307311, 'zhTW', '我很慶幸能擺脫那個恐怖的經歷。', '', 66384),
(307309, 'zhTW', '', '這麼快就要走了嗎？', 66384),
(307308, 'zhTW', '', '我知道我應該和媽媽談談。但我說話時…只聽得到你的聲音。', 66384),
(307304, 'zhTW', '', '<坎莎指向她為水豚鋪設的墊子。\n\n她似乎是要你坐在正中間。\n\n從她為水豚擺放的盤子和大餐來看，你推斷出她準備了下午茶會，希望能討菲洛開心。>', 66384),
(307303, 'zhTW', '', '<坎莎對著你微笑，用手指梳過頭髮，然後盯著自己的雙腳。>', 66384),
(307291, 'zhTW', '有些歷史不該公諸於世。', '', 66384),
(307285, 'zhTW', '祖阿曼這裡有許多低階的羅亞。去把他們找出來，然後接受他們的祝福。', '祖阿曼這裡有許多低階的羅亞。去把他們找出來，然後接受他們的祝福。', 66384),
(307283, 'zhTW', '你的同胞為了自由奮戰和犧牲性命，這就是你想說的？那就滾吧！', '你的同胞為了自由奮戰和犧牲性命，這就是你想說的？那就滾吧！', 66384),
(307282, 'zhTW', '然後把優勢讓給他們？榮耀是歸辛多雷的…難道你忘了嗎？', '然後把優勢讓給他們？榮耀是歸辛多雷的…難道你忘了嗎？', 66384),
(307281, 'zhTW', '當你的同胞死傷遍野時，你怎麼能有這樣的想法？', '當你的同胞死傷遍野時，你怎麼能有這樣的想法？', 66384),
(307280, 'zhTW', '你是不是忘記歷史的教訓了？阿曼尼只要一逮到機會，就會奪走我們的土地和性命！', '你是不是忘記歷史的教訓了？阿曼尼只要一逮到機會，就會奪走我們的土地和性命！', 66384),
(307279, 'zhTW', '你瘋了嗎？或許我也該把你當成阿曼尼，割掉你的舌頭！', '你瘋了嗎？或許我也該把你當成阿曼尼，割掉你的舌頭！', 66384),
(307278, 'zhTW', '你是不是瘋了？他們世世代代都在威脅我們！', '你是不是瘋了？他們世世代代都在威脅我們！', 66384),
(307277, 'zhTW', '如果你把我殺了，我武器的祕密就會隨我入土。成為我的載體，你就能握有摧毀世界的力量。', '', 66384),
(307276, 'zhTW', '', '你認真的嗎？星辰在上，你和萊希卡斯簡直是難得的奇才。\n\n<梅拉搖搖頭。>\n\n我想我該慶幸，你沒有把我們都炸掉。還請不要碰其他東西。下次我們可能不會這麼好運。', 66384),
(307268, 'zhTW', '好吧，不過你不得不承認這很有趣。', '', 66384),
(307253, 'zhTW', '停下來？我們才剛扭轉局勢而已欸！', '停下來？我們才剛扭轉局勢而已欸！', 66384),
(307252, 'zhTW', '阿曼尼撤退了。我們勝券在握。', '阿曼尼撤退了。我們勝券在握。', 66384),
(307251, 'zhTW', '然後把優勢讓給他們？休想！榮耀是歸辛多雷的！', '然後把優勢讓給他們？休想！榮耀是歸辛多雷的！', 66384),
(307250, 'zhTW', '辛多雷承受阿曼尼的攻擊有好幾千年了，這樣的情況從來都沒變過！', '辛多雷承受阿曼尼的攻擊有好幾千年了，這樣的情況從來都沒變過！', 66384),
(307249, 'zhTW', '我絕不會讓聖光和圖拉揚失望！繼續進攻！', '', 66384),
(307248, 'zhTW', '聖光會為我和你引領道路。', '', 66384),
(307247, 'zhTW', '看看他們做了什麼！我一定會復仇！', '看看他們做了什麼！我一定會復仇！', 66384),
(307246, 'zhTW', '一個阿曼尼用長矛從背後將他刺穿，然後逃跑…懦弱的東西！', '一個阿曼尼用長矛從背後將他刺穿，然後逃跑…懦弱的東西！', 66384),
(307245, 'zhTW', '你沒看到面前的那些敵人嗎？他們膽敢攻擊，我們就會予以報復！', '', 66384),
(307244, 'zhTW', '我們的進攻會受到聖光眷顧！', '', 66384),
(307243, 'zhTW', '我就知道會有這一天！為了奎爾薩拉斯！', '我就知道會有這一天！為了奎爾薩拉斯！', 66384),
(307242, 'zhTW', '阿曼尼對你來說或許不是威脅，但只要有機會，他們就會奪取我們的土地，然後殺了我們所有人！', '阿曼尼對你來說或許不是威脅，但只要有機會，他們就會奪取我們的土地，然後殺了我們所有人！', 66384),
(307241, 'zhTW', '停下來？該停下來的不是我們，是他們才對！', '停下來？該停下來的不是我們，是他們才對！', 66384),
(307240, 'zhTW', '我一個咒語都不會讓他們施放！', '我一個咒語都不會讓他們施放！', 66384),
(307239, 'zhTW', '不是真正的威脅？他們威脅了我們好幾個世代。我絕對無法容忍這種事情！', '不是真正的威脅？他們威脅了我們好幾個世代。我絕對無法容忍這種事情！', 66384),
(307238, 'zhTW', '願你箭無虛發！', '願你箭無虛發！', 66384),
(307222, 'zhTW', '這是什麼聲音？為什麼怪物要吃石頭？我們必須深入調查。快來！', '', 66384),
(307203, 'zhTW', '', '菲洛人很好，你說對不對？', 66384),
(307197, 'zhTW', '', '坎莎…不太一樣。\n\n當她還小的時候都不講話，也不會笑，也不會正眼看其他人。\n\n因為有我母親、她父親，還有她雙胞胎姐姐的幫忙，她才開始說話，也表現得像個普通的孩子。\n\n但我母親過世了。她父親的工作變得越來越繁重，她的姐姐嘉娜卡也因為血液疾病離世了。\n\n嘉娜卡死後，她又再次不說話了。我給了她許多時間，但這樣的情況已經有三年了。', 66384),
(307150, 'zhTW', '<獸群商販向你低頭致意，以表效勞>', '<獸群商販向你低頭致意，以表效勞>', 66384),
(307133, 'zhTW', '能量超載！', '', 66384),
(307127, 'zhTW', '', '謝謝你，哈巫拉…感謝你的付出。', 66384),
(307126, 'zhTW', '什麼？沒關係。反正我覺得好多了。而且你煮的東西很難吃。', '', 66384),
(307125, 'zhTW', '', '你說得對，父親。我不再會為你…找藉口了！滾出我的家！', 66384),
(307124, 'zhTW', '荒唐！這都是藉口！都是謊言！告訴我你沒有召喚菲洛！', '', 66384),
(307123, 'zhTW', '', '我…必須見我姐姐最後一次。', 66384),
(307122, 'zhTW', '嗯。你怎麼現在才說話？你怎麼讓媽媽擔心這麼久？', '', 66384),
(307121, 'zhTW', '', '坎莎！你安然無恙地回來了…你說什麼？', 66384),
(307120, 'zhTW', '', '媽媽…', 66384),
(307113, 'zhTW', '菲洛開心地笑著以示招呼，接著又開始大快朵頤。', '', 66384),
(307112, 'zhTW', '', '再見了，姐姐。我們…會再相見的。', 66384),
(307111, 'zhTW', '', '嘉娜卡點頭，向隨著菲洛離去的坎莎揮揮手。', 66384),
(307108, 'zhTW', '菲洛打哈欠，伸個懶腰後，準備離去。', '', 66384),
(307105, 'zhTW', '', '嘉娜卡微笑，點點頭，但把雙手放到臀部上。', 66384),
(307104, 'zhTW', '', '你…還好嗎？', 66384),
(307103, 'zhTW', '', '嘉娜卡看到坎莎時露出了暖心的微笑。', 66384),
(307102, 'zhTW', '菲洛緩緩點頭，嘴裡滿滿的荊棘菇。', '', 66384),
(307101, 'zhTW', '', '我的姐姐…有跟你來嗎？', 66384),
(307100, 'zhTW', '', '菲洛…', 66384),
(307086, 'zhTW', '我會先探查領地的最遠端，以尋找源頭。', '', 66384),
(307085, 'zhTW', '…', '…', 66384),
(307083, 'zhTW', '這可不一定。', '', 66384),
(307079, 'zhTW', '如果那都是真的，幸好我們讓阿奇杜德的知識隨他長眠了。我會回報我們找到的情報，但現在武器的所有細節都不見了。', '', 66384),
(307070, 'zhTW', '', '<坎莎抬頭看著你，臉上露出短暫的燦爛笑容。\n\n她似乎很開心，有人能耐心傾聽和理解她想表達的意思。>', 66384),
(307054, 'zhTW', '', '<在你離開之前，坎莎清了清喉嚨。你愣住了，以為她要說些什麼。\n\n但她發出了和野豬衝鋒時極為相似的尖嚎聲。\n\n你意會到，她是在提醒你野豬或許會來和你搶這些荊棘菇。>', 66384),
(307052, 'zhTW', '', '<坎莎指著腳邊的蘑菇，從菌柄摘起好避開菌傘上的尖刺。\n\n接著她用小手靈巧地把尖刺從菌傘上拔除。\n\n最後她把蘑菇拿給你聞。\n\n它聞起來有股美味的香氣，介於松露和大蒜之間。>', 66384),
(307041, 'zhTW', '就在這裡！這塊石板一定是碎石的來源！快，你能解讀嗎？', '', 66384),
(307039, 'zhTW', '', '坎莎示意你跟著她。', 66384),
(307034, 'zhTW', '你無畏無懼，又十分強大。我會把知識傳授於你。這個世界曾被稱為普雷達希雅。', '', 66384),
(307031, 'zhTW', '幸會，$c。', '', 66384),
(307030, 'zhTW', '這些犧牲不該由你來承擔，$c。', '', 66384),
(307029, 'zhTW', '沒錯，來我這裡吧。踏入漩渦。', '', 66384),
(307027, 'zhTW', '我希望這座火堆能為我們做一樣的事。', '', 66384),
(307022, 'zhTW', '我可以為你提供許多重要地點的位置。', '我可以為你提供許多重要地點的位置。', 66384),
(307019, 'zhTW', '', '<坎莎興奮地指向熱水池，將你的目光吸引過去。\n\n她像振翅一樣揮舞手臂，然後模仿看著某個東西在空中飛來飛去。接著她假裝抓住那個幻想出來的飛行物體，用雙手把它捏個粉碎。\n\n你注意到有刺蜂在水池邊飛來飛去，造成島外的水豚沒辦法進到水池裡。\n\n或許坎莎是想要你解決掉牠們，這樣就可以有更多水豚進到水池裡放鬆？>', 66384),
(306896, 'zhTW', '', '肯莎放下樹枝，好擺脫過去的回憶。', 66384),
(306895, 'zhTW', '如此活力，又想求知的人…我握有你尋求的解答。快來找我…', '', 66384),
(306894, 'zhTW', '只要羅亞不跟她說話，她就會開始跟我們講話了！', '', 66384),
(306893, 'zhTW', '', '父親…拜託你。這個女孩無法控制。', 66384),
(306886, 'zhTW', '', '肌腱能確保篝火不會解體，直到火焰熄滅為止。', 66384),
(306885, 'zhTW', '它很堅實。讓我想起我堅毅的姐姐。', '', 66384),
(306884, 'zhTW', '', '這很貼切…對某些人來說，她就和石頭一樣頑強。但對我們來說，她和石頭一樣頑固。', 66384),
(306883, 'zhTW', '我們一開始放了一顆石頭，象徵她的生命。', '', 66384),
(306865, 'zhTW', '你在找哪個專業技能訓練師？', '你在找哪個專業技能訓練師？', 66384),
(306863, 'zhTW', '你有什麼事，$c？', '你有什麼事，$c？', 66384),
(306860, 'zhTW', '', '<坎莎瞇著眼，上下打量你。\n\n她握起雙拳，重踏地面。\n\n很明顯，她不願意跟你回去。>', 66384),
(306856, 'zhTW', '', '阿曼尼永遠歡迎你，$n。', 66384),
(306852, 'zhTW', '', '至少邪枝食人妖沒有把我擄走，我父親也活著回來了。\n\n我的家庭遭受過太多不幸。\n\n好了，我的小坎莎去哪裡了？', 66384),
(306851, 'zhTW', '', '看她走的方向就知道了。\n\n還有她帶的東西。\n\n只有小孩才能以最童真的方式呼喚菲洛。\n\n有茶壺、野餐籃…她想跟他玩。\n\n但現在茶壺破了，野餐籃裡的食物也都不見了，我不知道她要怎樣才能跟他玩了…', 66384),
(306849, 'zhTW', '', '如果她到我死都不跟我講一句話，我也會感到開心。\n\n真慶幸她能回來。但我也很遺憾，沒有把她想告訴我的話聽進去。\n\n她要有所了斷。她需要一個安全的空間做自己。', 66384),
(306842, 'zhTW', '', '很長一段時間，躲藏。逃跑。很艱難。\n\n策劃。向可憐的曼那瑞說謊。他們以為，死亡。但是我們沒有。\n\n沒有和平。但之後，更輕鬆。', 66384),
(306841, 'zhTW', '', '數百年來，我們能做的只有生存。原生於這個世界的巨大野獸也開始反抗燃燒軍團，像對待德萊尼一樣獵殺那些惡魔。幸運的是，軍團對原生物種的惡魔轉換實驗總是以死亡告終。\n\n我與一些追殺我們的惡魔勾結，安排了一場孤注一擲的冒險。其中一些惡魔對自己的處境感到不滿。我們策劃了最後的抵抗，欺騙了軍團的指揮階層，讓他們以為我們全滅了。從那些灰燼中，新的事物誕生了。\n\n那不是我們世界的最後一場戰爭。但那是我們首次放下刀刃的日子。', 66384),
(306840, 'zhTW', '', '多虧這個精靈，看來我們終於可以通訊了。請讓我自我介紹一下，並且正式地感謝你。\n\n我是虛空使的圖阿瑪。我出生於阿古斯，之後跟著費倫登上真諾達號。數千年前，當燃燒軍團伏擊了我們避難的世界後，我和大多數的同胞一樣，被我們的次元船艦拋下了\n\n因為有你，我才能確保族人的安全。我不會忘記這份恩情。', 66384),
(306834, 'zhTW', '', '$c，我能幫你什麼忙嗎？', 66384),
(306819, 'zhTW', '等等，他就在那裡！抓住那個小怪物！', '', 66384),
(306818, 'zhTW', '至少他有運動到了。', '', 66384),
(306816, 'zhTW', '它們沒有水就活不久了，動作快！', '', 66384),
(306801, 'zhTW', '', '我想知道…你具備資格嗎？還是你會在獲得餽贈之前就放棄。', 66384),
(306781, 'zhTW', '虛無的氣息都淨化乾淨了。這些力量很實用…也很萬用…副作用似乎…尚可控制。', '', 66384),
(306779, 'zhTW', '我是戰士，不是舞者！他們怎麼會以為我能展現出優雅？\n\n他們該讓我去為戰鬥做好準備。\n\n這根本就在浪費我的時間。', '', 66384),
(306777, 'zhTW', '<科武完全沉浸在旋律之中，不停地跳舞。他對你眨了眨眼。>\n\n我好像知道跳舞的意義何在了。', '', 66384),
(306766, 'zhTW', '', '這樣的狀況下我根本無法教學！', 66384),
(306765, 'zhTW', '', '那裡！他就在那…他要去市集的傳送門！', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(306753, 'zhTW', '該容器上場了。我們會強化它的潛能。把它放在這裡，小心點。', '', 66384),
(306750, 'zhTW', '首先，準備淨化盬巴。這應該能防止苦痛最糟糕的副作用影響我們的騎士。', '', 66384),
(306749, 'zhTW', '苦痛的力量似乎很有可塑性…我們來看看它有什麼用。', '', 66384),
(306746, 'zhTW', '這個血騎士在凶狠的虛無生物入侵時受傷了。他自願奉獻身體讓我進行研究。\n\n來看看苦痛能有什麼效果吧。', '', 66384),
(306742, 'zhTW', '給我滾遠一點，部落畜牲。', '', 66384),
(306741, 'zhTW', '空氣中瀰漫著獸人和謀殺的氣味。這些部落怪物表現得好像自己比這個世界的居民還要高等一樣。\n\n他們想太多了。我們之中的一部分人可不會忘記。', '', 66384),
(306740, 'zhTW', '', '這些可悲的聯盟走狗用盡一切藉口想解決舊怨。\n\n他們想打？我很樂意奉陪。', 66384),
(306739, 'zhTW', '', '我跟你沒什麼話好說，聯盟的走狗。', 66384),
(306738, 'zhTW', '一個人該怎麼待在競技場的頂端？\n\n研究。練習。面對挫折、學習和生存的耐心。\n\n比起理性，那些前來重燃舊怨的人心懷更多的是傲慢。我來這裡就是要讓這些怪物明白，低估我們必將招致滅亡。我們必須變得比他們更強大，並且不停維持下去。\n\n努力奮戰吧，$c。', '一個人該怎麼待在競技場的頂端？\n\n研究。練習。面對挫折、學習和生存的耐心。\n\n比起理性，那些前來重燃舊怨的人心懷更多的是傲慢。我來這裡就是要讓這些怪物明白，低估我們必將招致滅亡。我們必須變得比他們更強大，並且不停維持下去。\n\n努力奮戰吧，$c。', 66384),
(306716, 'zhTW', '達納斯指著你。', '', 66384),
(306712, 'zhTW', '', '這對外來者來說或許沒什麼奇怪的，但他們與過去的不同之處，還有那個危險的感覺，絕對不會錯。\n\n我觀察蘑菇人有好幾年了。確實，腐食是他們的本性，但他們通常會有目的性地攝食。他們對周遭環境還是有意識。他們也曉得如果過度擴張，或是攝食過多，最終和萬物一樣只會招來自身的毀滅。\n\n但這些…東西…他們不太一樣。他們眼神空洞，完全受飢餓感的驅使。他們好像被什麼東西附身一樣，成了腐爛力量的傀儡。\n\n哈拉尼爾不太容易被嚇到，$c。但這個…\n\n我們必須盡快找到源頭。', 66384),
(306709, 'zhTW', '<戴西蒙斯完全無視你，好聆聽艾蘭里亞和阿拉特之間的對話。>', '', 66384),
(306690, 'zhTW', '', '這些蘑菇人比平常要更具攻擊性，而且他們一點聲響也沒有。看看他們空洞的眼神…\n\n我想他們已經死透了。', 66384),
(306689, 'zhTW', '', '蘑菇人很吵…吵得讓人不得安寧…不過，方嘉拉村最近卻陷入寂靜。', 66384),
(306642, 'zhTW', '這個問題還真教人失望。\n\n放棄任務，回到銀月城找我就行了。我想我可以找些適合的任務給你。\n\n\n[若要放棄狩獵：開啟任務日誌並選擇任務後，點選放棄。接著就可以回到銀月城找阿斯塔樂，展開一次新的狩獵。]', '', 66384),
(306641, 'zhTW', '當你越來越靠近目標時，他們的苦痛就會填滿我的水晶。完全填滿之後，我們就能知道他們的位置了。\n\n但苦痛是個難以捉摸又不穩定的力量。有些狩獵很快就會結束，但有些會特別棘手。', '', 66384),
(306640, 'zhTW', '任何能暫時把目標引出躲藏處，或將他們的注意力吸引到你所在位置的行為，都能幫助我的魔法漸漸鎖定他們的準確位置。\n\n\n[狩獵進度的來源包括：在這個區域裡擊敗埋伏者、與陷阱互動、擊敗聚合苦痛、完成世界任務、搜刮寶藏，以及擊敗稀有敵人。]', '', 66384),
(306583, 'zhTW', '', '我一定得解決這次的螃蟹危機。這不只是為了我飢腸轆轆的人民，也是為了我的母親。她十分關心惡齒部族。\n\n她是我們家族的驕傲，也讓惡齒部族蓬勃發展了好幾個世代。如果我破壞人們對我的信任與承諾，他們又能依靠誰呢？讚美納羅拉克，幸好我沒有讓他們失望。\n\n現在我也知道我和先祖一樣，能當個能幹的領導者。', 66384),
(306582, 'zhTW', '', '眾人對我的期望很高。我的母親是最偉大的川行者，她也把她知道的捕蟹技巧都傳授給我。\n\n但暮光之刃奪走了她的性命，而我必須繼承她的衣缽。現在我不能分心思念她，我怕我會難過到無法解決這次的危機。', 66384),
(306581, 'zhTW', '卡哈妮雅解決這次飢荒的危機，也證明了自己的能耐。我一開始還質疑她的領導能力，但我希望現在她能為我感到驕傲！\n\n能有她領導我們，是我們的福氣。她絕對是有史以來數一數二偉大的川行者。', '', 66384),
(306580, 'zhTW', '我是個新的川行者。大家都說卡哈妮雅的母親是個優秀的領導者，但我從沒有那個機會受過她的訓練。\n\n有時候我很擔心大家相信卡哈妮雅，就只是因為她家族的名號。我還不確定她有什麼能耐。', '', 66384),
(306579, 'zhTW', '', '我知道卡哈妮雅一定能解決螃蟹的問題！她一定能辦到，這不只是為了她的人民，也是為了她家族的名聲。\n\n她的母親對她來說無比重要…如果她現在能看到卡哈妮雅，一定會很驕傲，但我知道她也不會很意外。\n\n她和我一樣，一直都相信卡哈妮雅。', 66384),
(306578, 'zhTW', '', '現在處境十分艱難，但我相信卡哈妮雅！她的家族引領了川行者好幾個世代，她的母親也是精英中的精英。\n\n我知道她能帶我們度過難關。', 66384),
(306556, 'zhTW', '聽你老師的話。不聽也行。我很期待吞噬你的每一滴精華。', '', 66384),
(306546, 'zhTW', '這場戰爭的消耗甚鉅，但我會好好記錄下來，並決定何時該找什麼樣的人追討。', '', 66384),
(306545, 'zhTW', '薩拉塔斯！今天，聖光必將勝利！', '', 66384),
(306544, 'zhTW', '', '圖拉揚，你和你的朋友能來真是太好了。我可不希望這些可憐的精靈獨自受死。', 66384),
(306543, 'zhTW', '', '即便那是如此明顯地遙不可及。', 66384),
(306542, 'zhTW', '', '而不論在哪一個未來，你的世界都會歸我所有。', 66384),
(306540, 'zhTW', '', '看看你的周圍，看看你的上方。虛無會讓你看見所有可能的未來。', 66384),
(306539, 'zhTW', '', '艾澤拉斯鼎鼎大名的勇士。我非常敬佩你的決心，還有你追求勝利的意志。', 66384),
(306480, 'zhTW', '', '父親！她就是這樣的人。如果你再這樣說，我會直接把晚餐倒到你頭上。', 66384),
(306473, 'zhTW', '一個死去的朝聖者手裡緊抓著一袋補給品。', '一個死去的朝聖者手裡緊抓著一袋補給品。', 66384),
(306467, 'zhTW', '或許她離開了是件好事。她和她姐姐不一樣。她的個性很狂野，一點都不尊重長者。', '', 66384),
(306455, 'zhTW', '這些多曼納爾能成為出乎意料的盟友。他們之中大多數都曾在某方面受到薩拉塔斯的傷害，或者懷抱著超越她所能提供的野心。\n\n我想，敵人的敵人就是我們的朋友吧。', '', 66384),
(306448, 'zhTW', '空氣中瀰漫著撫慰的薰香氣味。', '空氣中瀰漫著撫慰的薰香氣味。', 66384),
(306447, 'zhTW', '真遺憾，我真希望我不用再經歷上次做的事了。', '', 66384),
(306441, 'zhTW', '你們艾澤拉斯人來得正是時候。薩拉塔斯的到來徹底顛覆了我們對階級的認知。\n\n過去，多曼納爾只需要力量與機智就能獲得成功了，如今我們卻被要求對她忠誠，卑躬屈膝。真是噁心。\n\n無法抗拒薩拉塔斯的多曼納爾不值得活著。殺了他們，奪取他們的財富。', '', 66384),
(306412, 'zhTW', '我知道你能照顧好自己，不過這還真是令人愉悅的景象。', '', 66384),
(306410, 'zhTW', '急躁的獵人常被反咬一口…', '', 66384),
(306408, 'zhTW', '高明的獵人能夠解除眼前的任何陷阱。', '', 66384),
(306406, 'zhTW', '水晶對你的觸碰反應良好。我記下來了。', '', 66384),
(306377, 'zhTW', '', '遠行者？真的嗎？我真不知道他到底喜歡那些滿身泥土的無賴什麼地方…', 66384),
(306263, 'zhTW', '', '很高興你能安全回來，納克特克！現在呢，先回去瞰臺幫忙處理食物的事吧。', 66384),
(306262, 'zhTW', '', '我們在上游設的陷阱都被虛無塞滿了！我試著把其中一個清理乾淨，但這隻瘋狂的螃蟹卻先攻擊我！', 66384),
(306260, 'zhTW', '', '卡甲拉真有趣！一直急著要給我留下好印象。他明明不必那麼著急的！\n\n我都不知道他原來這麼體貼。我等不及要和他一起參加節慶了！\n\n<娜瑪琪停頓了一下。>\n\n我知道薩卡許肯定很失望。我等等會再去找他，謝謝他送的頭飾。希望他也能找到一起參加慶典的伴！', 66384),
(306259, 'zhTW', '', '知道我打算和他一起參加節慶，薩卡許好像很開心。我也等不及要參加了！\n\n我從來不知道薩卡許這麼貼心。這頭飾真漂亮。我打算戴著去參加節慶！\n\n<娜瑪琪停頓了一下。>\n\n我知道卡甲拉肯定很失望。我等等會再去找他，謝謝他送的項鍊。希望他也能找到一起參加慶典的伴！', 66384),
(306258, 'zhTW', '$n，快把阿茲基爾給毀了，不然我們會損失更多。', '', 66384),
(306244, 'zhTW', '這裡面根本沒幾隻螃蟹啊！看起來還有點…生病了？不過有總比沒有好！', '', 66384),
(306243, 'zhTW', '', '提納吉，在納克特克探查納羅拉克之匿的同時，把這些籃子拿去瞰臺吧。要記得讓老人跟小孩先吃！', 66384),
(306239, 'zhTW', '就這工作來說卡哈妮雅還是新手，用得上任何助力。', '', 66384),
(306237, 'zhTW', '', '卡甲拉！謝謝你送的項鍊！我很樂意和你一起參加節慶！', 66384),
(306236, 'zhTW', '', '薩卡許！謝謝你送的頭飾！我很樂意和你一起參加節慶！', 66384),
(306227, 'zhTW', '我叫薩曼。我們很需要幫手。', '', 66384),
(306212, 'zhTW', '我想你可以在北邊的花園找到她。先警告你，蒂芙可不是好惹的。', '', 66384),
(306206, 'zhTW', '我是年輕阿曼尼鬥士之中最強的！很快我就能加入戰士行列，保衛族人了！\n\n不過，我會想念我的朋友…娜瑪琪和卡甲拉的。我們總是互相照顧彼此。跟他們分開感覺一定會很奇怪。', '', 66384),
(306205, 'zhTW', '提夫快樂地唧唧叫。', '', 66384),
(306204, 'zhTW', '<這裡發生過戰鬥。看來馬鈴薯蟾蜍自己打起來了。>', '<這裡發生過戰鬥。看來馬鈴薯蟾蜍自己打起來了。>', 66384),
(306203, 'zhTW', '看來蒂芙需要一點暖身。女孩，你說對不對？', '', 66384),
(306202, 'zhTW', '誰？馬洛？應該吧。\n\n我們從阿塔阿曼逃離的時候，我在森林裡發現他。他看起來受到驚嚇，所以我就帶上他了。\n\n我把他帶到這來，餵他吃東西。我以為他會自己回去森林裡，但他並沒有離開。\n\n你看這個卷軸，寫的是照顧山貓的方法。如果他想繼續待在這，我就得好好照顧他才行。\n\n你可以摸他沒關係。他喜歡被摸頭！直到他被摸膩了為止。', '', 66384),
(306165, 'zhTW', '<看著卷軸的卡甲拉抬起頭來。>\n\n因為我不是鬥士，其他年輕阿曼尼都喜歡開我玩笑。我不夠強、不夠快，而且光是看到血就會讓我頭暈。\n\n不過娜瑪琪和薩卡許都不在乎。我們三個從很小的時候開始就是好朋友。\n\n我或許不是當鬥士的料，但我夠聰明。也許有一天，我能成為羅亞語者！', '', 66384),
(306164, 'zhTW', '', '到外圍和我碰面。我有不好的預感。', 66384),
(306163, 'zhTW', '', '方嘉拉村從來不會這麼安靜。肯定有事發生了。', 66384),
(306160, 'zhTW', '<蹤跡似乎是那隻生物留下的。而且還往入侵的區域深處去。>', '<蹤跡似乎是那隻生物留下的。而且還往入侵的區域深處去。>', 66384),
(306148, 'zhTW', '你來了啊。阿曼尼狩獵大師還沒現身。\n\n現在只有你和我，而且你一定因為剛才的那些戰鬥而精疲力盡了，對吧？\n\n<你可以很清楚看到凱爾沃裘慢慢將手伸向武器，明顯以為你不會注意到。>', '', 66384),
(306146, 'zhTW', '你需要什麼嗎？', '', 66384),
(306145, 'zhTW', '你要跟祖爾賈拉說話嗎？', '', 66384),
(306137, 'zhTW', '', '維迪奧斯的反抗不過是微不足道的障礙。你必須幫我掃除它，鞏固我的統治地位。\n\n馬上出擊！進入戰爭模式，對付那些以他的名義戰鬥的代理人。', 66384),
(306122, 'zhTW', '齊亞丹竟然有種和我對抗。我註定會掌控殺戮者高地。\n\n她的無法無天到此為止了。進入戰爭模式，消滅那些為她而戰的代理人。', '', 66384),
(306100, 'zhTW', '騷動發生的地點離侵噬之綻太近了。', '', 66384),
(305956, 'zhTW', '', '終於有鋒利到符合我們需求的利爪了。', 66384),
(305948, 'zhTW', '', '搞定了。我們把這些材料帶回去給艾萊莉吧。', 66384),
(305938, 'zhTW', '', '燈籠現在正發出力量的嗡鳴。', 66384),
(305905, 'zhTW', '母親永遠不會給我犯錯的機會。', '', 66384),
(305901, 'zhTW', '', '留意你能在水中閉氣的時間有多長。別溺水了！', 66384),
(305898, 'zhTW', '博安可以幫你的忙。\n\n他可是讓杜洛塔生出綠洲的人。', '', 66384),
(305892, 'zhTW', '', '$n，我們快收集夠了。只要再收割幾隻生物。', 66384),
(305891, 'zhTW', '', '這些生物好強大！我們收集到的能量正在暴漲。', 66384),
(305890, 'zhTW', '', '$n，我能感覺到虛無能量在這個燈籠裡匯聚。', 66384),
(305889, 'zhTW', '好大一隻啊。是我看過最大隻的魚人。難道是…羅亞嗎？我才不要親自下去求證！', '', 66384),
(305888, 'zhTW', '你在探索這些土地的時候，請留意還有沒有更多未受汙染的樣本。我們在這裡還能學習很多事。', '', 66384),
(305887, 'zhTW', '你感覺到了嗎？像是某種微妙的…飢餓波動。', '', 66384),
(305886, 'zhTW', '$p，請務必小心！', '', 66384),
(305882, 'zhTW', '', '噢，推薦你去找崔佛。\n\n他是我們這裡的園藝奇才，想要什麼，他應有盡有。', 66384),
(305881, 'zhTW', '外來者！你有空嗎？', '', 66384),
(305876, 'zhTW', '', '可以去法登的商店看看。\n\n他一直都在和當地人合作，打造令人嘆為觀止的在地裝飾。', 66384),
(305867, 'zhTW', '嘿！我能跟你談談嗎？', '', 66384),
(305855, 'zhTW', '眼睛放亮點，夥伴。要找到一隻寵物並不是件容易的事。', '', 66384),
(305818, 'zhTW', '', '首領原來是隻寇拜斯？真有意思…\n\n我還以為寇拜斯喜好黑暗、厭惡光線。這傢伙跑到地表附近來做什麼？\n\n似乎就是牠教會了魚人使用死靈魔法。我從沒聽過像這樣的行為。\n\n這只是一次獨立的個案嗎？還是說寇拜斯有著某種更邪惡的計畫？\n\n<你感覺助手嘎咕嘎咕好像望向了遠方，陷入深思，但因為魚人裝的眼球動也不動，你說不準。>', 66384),
(305809, 'zhTW', '<莫戈莫戈大王壓低聲音。>\n\n看來我會被困在這裡一段時間。但不知道這個詭計還能持續多久？我可不能一直待在這，不然會餓死啊！\n\n總有一天牠們會發現我是吃素的。萬一牠們發現我不是魚人…或是開始模仿我怎麼辦？\n\n魚人的食性幾乎都是肉類。吃素對牠們的身體不好。\n\n<莫戈莫戈大王的聲音聽起來很擔心，但他魚人裝上盯著你的兩顆眼球對著完全不同的方向，讓你看不出任何感情。>\n\n好吧，我還是可以活用這次機會，近距離研究魚人。或許我可以引導牠們…說服牠們，我身為魚人羅亞，必須離開去拯救其他部族！', '', 66384),
(305791, 'zhTW', '', '我們失敗了…', 66384),
(305790, 'zhTW', '', '（喘氣）', 66384),
(305789, 'zhTW', '', '（喘氣）', 66384),
(305788, 'zhTW', '', '（尖叫）', 66384),
(305787, 'zhTW', '', '（吼叫）', 66384),
(305786, 'zhTW', '', '（呼氣）', 66384),
(305785, 'zhTW', '', '（沉重喘息）', 66384),
(305784, 'zhTW', '', '（呼氣）', 66384),
(305783, 'zhTW', '', '我從不希望你看見這幅模樣…', 66384),
(305782, 'zhTW', '', '而你會將他拖入黑暗之中。', 66384),
(305780, 'zhTW', '', '他會看清你是個怪物。', 66384),
(305779, 'zhTW', '', '（呼氣）', 66384),
(305774, 'zhTW', '這裡的風景簡直令人屏息。從小時候開始我就常來這裡。從這裡我可以看見哈朗達的一切。殘忍和溫柔的事物盡收眼底，好壞皆有。\n\n加尼也喜歡上來這裡，我決定要把這裡當成我的家園。', '這裡的風景簡直令人屏息。從小時候開始我就常來這裡。從這裡我可以看見哈朗達的一切。殘忍和溫柔的事物盡收眼底，好壞皆有。\n\n加尼也喜歡上來這裡，我決定要把這裡當成我的家園。', 66384),
(305772, 'zhTW', '在你面前的是一件古怪的多曼納爾科技產物，在虛無中發出輕柔的低鳴聲。', '在你面前的是一件古怪的多曼納爾科技產物，在虛無中發出輕柔的低鳴聲。', 66384),
(305768, 'zhTW', '', '在阿曼尼帝國最輝煌的時期，我們曾是一個部族。但那是很久以前的事了，南方的惡齒部族也選擇走上不同的道路。\n\n我還聽說他們加入部落，並把辛薩羅占為己有。至於這裡的惡齒部族依舊效忠阿曼尼。', 66384),
(305766, 'zhTW', '', '我以斷齒的稱號為傲。', 66384),
(305760, 'zhTW', '<莫戈莫戈大王壓低聲音。>\n\n如果我們能夠阻止深鰭入侵，這些魚人就會繼續和食人妖勉強和平共處了。\n\n「魚人羅亞」就不用再繼續保護他們，我們就能離開了！', '', 66384),
(305743, 'zhTW', '我派勇士去殺深淵羅亞！我們將贏得勝利！', '', 66384),
(305742, 'zhTW', '', '嗯…我想想…寇拜斯啊…', 66384),
(305741, 'zhTW', '英雄回來了…你獲勝了對吧？拜託你說對。我不想再呆站在這裡了。', '', 66384),
(305739, 'zhTW', '或…或者不取回也罷！我可以再待幾天沒關係…', '', 66384),
(305738, 'zhTW', '子民們！現在威脅已經解決，我必須離開了！去取回屬於你們的領地吧！', '', 66384),
(305737, 'zhTW', '勝利的英雄歸來了！你殺死了深淵羅亞，證明本王，莫戈莫戈大王，才是真正的魚人羅亞！', '', 66384),
(305734, 'zhTW', '<深鰭首領的貢品就放在這裡。或許只要引起注意就能引誘首領現身？>', '<深鰭首領的貢品就放在這裡。或許只要引起注意就能引誘首領現身？>', 66384),
(305620, 'zhTW', '河鱗注意到食物而挺起身來。', '', 66384),
(305612, 'zhTW', '終於…流連在這些殿堂裡的靈魂能安息了。我希望我的姊姊們有天也能放下重擔。至於我自己…我會繼續讓這裡充滿音樂，直到她們回家為止。謝謝你們，勇士。', '', 66384),
(305562, 'zhTW', '', '世界之樹會讓周遭的動植物變得健康強況。我們必須好好照料它們。', 66384),
(305561, 'zhTW', '', '早在世界之樹扎根於哈朗達前，我們就定居於此了。', 66384),
(305559, 'zhTW', '<林地爬行者舔了你的臉。>', '', 66384),
(305558, 'zhTW', '<河鱗無視了你。>', '', 66384),
(305553, 'zhTW', '', '希望你在幫忙清除障礙物的時候，有感受到我們先祖世世代代傳承的重量。', 66384),
(305552, 'zhTW', '', '你幫助世界之樹維持樹體健康，更重要的是，你也遵循了傳統。', 66384),
(305550, 'zhTW', '', '河鱗只是需要一個朋友幫牠提振精神。謝謝你，$p。', 66384),
(305535, 'zhTW', '當你觸碰這個寶箱後，一股力量把你的注意力拉到附近的高塔上。', '當你觸碰這個寶箱後，一股力量把你的注意力拉到附近的高塔上。', 66384),
(305531, 'zhTW', '', '和$p玩得開心啊，河鱗！', 66384),
(305497, 'zhTW', '真是太浪費了。影芽技術必須終結。移植者肯定就在附近。', '', 66384),
(305496, 'zhTW', '', '真是頭威猛的野獸，卻被影芽毀於一旦！', 66384),
(305482, 'zhTW', '看啊！見證魚人英雄的凱旋吧！', '', 66384),
(305481, 'zhTW', '', '我由衷感謝你找到了我，$n。或許我們很快就能繼續進行研究了。\n\n只要我們解決這個，呃，羅亞問題就行。', 66384),
(305480, 'zhTW', '當然是為了作秀了。\n\n我們姑且把兇殺路當作銀月城裡最登不上檯面的地區吧。險惡且隱密，是許多惡棍與聲名狼藉之輩的聚集地。\n\n碰巧，也因為這些人很會釀酒，談吐又風趣，所以我跟這些人處得很不錯。\n\n我跟兇殺路外的一個「貿易者」組織關係十分良好。不要誤會，雖然不是什麼軍事力量，但他們在黑暗中的貢獻不比在戰場奮戰的人少。', '', 66384),
(305479, 'zhTW', '遠行者是永歌森林邊境的英勇防衛者，沒有人比他們更了解這片森林了。遊俠將軍自有歷史以來就是個無上的頭銜，你可能已經注意到了。\n\n儘管他們表面上不涉足政治，但我可以保證，他們就跟貴族一樣喜歡選邊站。', '', 66384),
(305478, 'zhTW', '血騎士是我們的精靈戰士。他們是堅毅的英雄，也是太陽選中的勇士。他們跟隨著莉雅德倫女士衝鋒陷陣，殲滅辛多雷的敵人。\n\n他們剿滅過的敵人比我們所有人要多，但也不以此為樂。我敢說，他們對自己坎坷的過去感到光榮。', '', 66384),
(305477, 'zhTW', '博學者是銀月城中的閃耀明珠。他們是我們最為睿智的學者、秘法師和政治家。數百年來對學識的鑽研讓他們的智慧如精雕細琢的匕首一般。\n\n引領他們的是大博學者洛摩斯，但贏得尊重並不是件容易的事。博學者是東部王國裡最為自負的一群人，他們對任何事也都不會有共識。', '', 66384),
(305476, 'zhTW', '', '謝謝、謝謝你。我現在就出發！', 66384),
(305471, 'zhTW', '', '我是莫戈莫戈大王的助手！你可以叫我嘎咕嘎咕。\n\n因為我對魚人學很有興趣，所以被指派負責協助莫戈莫戈大王的研究。這其實是我第一次出任務！\n\n當然，為了要低調行事，我也得穿上魚人裝。你可以想像牛頭人要擠進這件衣服有多難吧。我的拉鍊幾乎拉不起來！', 66384),
(305468, 'zhTW', '', '感謝大地之母！你知道莫戈莫戈大王在哪嗎？\n\n我們原本躲在一片小型廢墟裡觀察當地的原生魚人，但是當我去偵察深鰭魚人的時候，牠們發現了我的行蹤，把我趕走了！\n\n我回到營地的時候，莫戈莫戈大王不見蹤影，入侵的魚人還湧入了這個地區！\n\n我只好躲在這裡保護自己的安全。你知道他去哪了嗎？他被抓住了嗎？', 66384),
(305467, 'zhTW', '', '把那個該死的怪物除掉。我會保護倖存者，確保他們的安危。', 66384),
(305462, 'zhTW', '', '跟我來！', 66384),
(305460, 'zhTW', '', '效果很好。', 66384),
(305459, 'zhTW', '確實，你真的太擅長這麼做了。那你永遠不會放下那把長柄武器嗎？它還真礙眼。', '', 66384),
(305458, 'zhTW', '', '維迪奧斯，你還是這麼喜歡用雙刀嗎？我更喜歡偏轉掉你舊法杖的魔法。', 66384),
(305456, 'zhTW', '', '他們的確是非常堅持。你想看看結果如何嗎？', 66384),
(305450, 'zhTW', '<從這些文件的位置和周遭的腳印看來，此人似乎是受到複數魚人的追趕而匆忙離開。>\n\n我的觀察指出，這些魚人叫做深鰭族，襲擊當地的原生魚人只不過是牠們計畫中的一部份。牠們的另一個目標是阿塔阿巴斯的墓穴。\n\n深鰭魚人展現了駕馭死靈術的能力，至今從未有任何魚人展現過這種能力。牠們能夠讓食人妖的遺骸重生為不死族！牠們究竟是從哪裡得到這種力量的？或許是從附近的邪枝食人妖那學來的？\n\n無論如何，事情刻不容緩。深鰭魚人正在集結不死族的大軍。至於目的為何，我只能用猜的。\n\n<腳印的蹤跡通往西北方。>', '<從這些文件的位置和周遭的腳印看來，此人似乎是受到複數魚人的追趕而匆忙離開。>\n\n我的觀察指出，這些魚人叫做深鰭族，襲擊當地的原生魚人只不過是牠們計畫中的一部份。牠們的另一個目標是阿塔阿巴斯的墓穴。\n\n深鰭魚人展現了駕馭死靈術的能力，至今從未有任何魚人展現過這種能力。牠們能夠讓食人妖的遺骸重生為不死族！牠們究竟是從哪裡得到這種力量的？或許是從附近的邪枝食人妖那學來的？\n\n無論如何，事情刻不容緩。深鰭魚人正在集結不死族的大軍。至於目的為何，我只能用猜的。\n\n<腳印的蹤跡通往西北方。>', 66384),
(305442, 'zhTW', '虛無在呼喚…\n\n我必須攝食、吞噬，獲得滿足。\n\n受到奴役無法讓我擺脫這無盡的饑渴，只會讓我「擺脫」想吞噬你的慾望與自由。\n\n由於我主人施加的枷鎖讓我無法吞噬你，我只好在這裡幫我的主人「調製飲料」了。\n\n讓我獨自承受這痛苦吧。', '', 66384),
(305439, 'zhTW', '<從背包的狀態看來，似乎是在戰鬥中被拋下的。\n\n打開看看，你發現一些典型的旅行者行李：口糧、衣服，還有一些文件。你從中抽出一張。>\n\n莫戈莫戈大王和我一直被動地觀測這片地區的魚人生態，但有種完全不同的深海魚人部族從海中出現。牠們開始野蠻地攻擊當地的原生魚人，把牠們拖進海裡。光是想像牠們會遭到什麼樣的下場就讓我全身發抖。\n\n我也注意到這些入侵者對附近的食人妖廢墟似乎很有興趣。我打算偷偷靠近，看看牠們在打什麼算盤。', '<從背包的狀態看來，似乎是在戰鬥中被拋下的。\n\n打開看看，你發現一些典型的旅行者行李：口糧、衣服，還有一些文件。你從中抽出一張。>\n\n莫戈莫戈大王和我一直被動地觀測這片地區的魚人生態，但有種完全不同的深海魚人部族從海中出現。牠們開始野蠻地攻擊當地的原生魚人，把牠們拖進海裡。光是想像牠們會遭到什麼樣的下場就讓我全身發抖。\n\n我也注意到這些入侵者對附近的食人妖廢墟似乎很有興趣。我打算偷偷靠近，看看牠們在打什麼算盤。', 66384),
(305434, 'zhTW', '我聽說母親死了。這個$rl是誰？', '', 66384),
(305433, 'zhTW', '嗯。裝備不錯，姿勢也很穩，看你用得很順手。\n\n你會是個完美的手下！\n\n可惜的是，自從醉酒牛頭人、魔法典籍，和卡德加的輪椅事件之後，我就被禁止在亞肯提納簽署合約了。\n\n如果你想成為聽人差遣的手下的話，到外頭的世界記得找我。到時我就能簽合約了。', '', 66384),
(305431, 'zhTW', '然後冒著被那些握有聖光的狂熱份子背刺的風險嗎？還來啊？\n\n聽著，我雖然被天譴軍團感染過，但殺死我的是一個聖騎士。我可不想再經歷一次。\n\n我本來打算說服馬里斯去跟那些以虛無為食的獵人一起訓練，跟我一起試試新把戲，結果那個先鋒竟然想逮捕我。\n\n再次感謝你出手相助。下一輪的酒我請客。', '', 66384),
(305428, 'zhTW', '噢，是你啊。\n\n如果你想狩獵惡魔，或是要找邪惡聖物的話，不要找我。我正在放假。\n\n工作狂先生馬里斯想喝點東西，而我需要餵飽自己的惡魔，不論是比喻還是現實意義上的。\n\n自從燃燒軍團瓦解後，我們就屠殺、捕捉或囚禁了一百一十五個惡魔。\n\n我們是該休息，喝上幾杯。', '', 66384),
(305426, 'zhTW', '能有…喘息之機…感覺還真放鬆。\n\n甚至可以說頗有收穫。\n\n我不喜歡這樣。\n\n薩格拉斯被推翻後，燃燒軍團已然成了空殼，卻依舊在黑暗之中苟延殘喘。我們必須追殺他們到扭曲虛空，再遠的地方也在所不辭。\n\n但首先…泰德剛剛在解釋一個名叫刑場佳釀的飲料。聽起來很詭異。我一定要嚐嚐。', '', 66384),
(305419, 'zhTW', '', '謝謝你，$p，我不想自己承擔這件事。', 66384),
(305403, 'zhTW', '不！如果你不想擁有我的力量，我也不會把知識傳授給你！', '', 66384),
(305401, 'zhTW', '艾澤拉斯被一次又一次的戰爭分裂殆盡。這樣的末日也是我們的命運嗎？', '', 66384),
(305400, 'zhTW', '這裡真的曾經有一個帝國嗎？而且會失落全都因為一個人對追求知識的強烈渴望？', '', 66384),
(305399, 'zhTW', '成為你意志的俘虜？不，你的知識將隨你長眠。', '', 66384),
(305397, 'zhTW', '有好多謎團！這是什麼意思？多曼納爾、以太族，還是其他…更遠古的東西？', '', 66384),
(305393, 'zhTW', '亡靈，把所知的分享給我們！帶引我們去找你吧！', '', 66384),
(305390, 'zhTW', '這個法術需要一點時間。亡靈，告訴我，這個名叫普雷達希亞的世界曾有生命存在嗎？', '', 66384),
(305387, 'zhTW', '如果你再問一次的話，我會把你的手指打斷。現在給我回去工作，無名小卒。認清自己的處境。', '', 66384),
(305386, 'zhTW', '見證我的勇士，有了我的祝福，他將前往戰場，為了諸位而戰！', '', 66384),
(305377, 'zhTW', '你已經迷失方向了。就跟你上一個討厭鬼同類問的時候一樣。\n\n別擔心，黑暗主宰會引領我們到我們該去的地方。', '', 66384),
(305375, 'zhTW', '這不是第一次，也不會是最後一次。我聽說這就和部落與聯盟的關係很像。', '', 66384),
(305374, 'zhTW', '', '看來，我們必須再次放下彼此的恩怨，一起對付共同的敵人。', 66384),
(305373, 'zhTW', '', '你這懦夫，竟然墮落到用影芽控制你的手下！你和薩拉塔斯沒兩樣！', 66384),
(305372, 'zhTW', '你怎麼敢說這種…！啊，我懂了。我們被人操縱了。有另一個多曼納爾在搞鬼。', '', 66384),
(305370, 'zhTW', '齊亞丹很快就會到了。她絕對無法拒絕跟我短兵相接的機會。你帶來了什麼東西？', '', 66384),
(305368, 'zhTW', '我懂了！我在跳舞了！', '', 66384),
(305365, 'zhTW', '我的戰鬥教官莉卡莉，強迫我們所有人都去上這些舞蹈課。講些「紀律」、「協調」、「戰鬥之舞」的歪理。\n\n但我真的非常不想來這裡。\n\n做這種事根本毫無意義。', '', 66384),
(305354, 'zhTW', '連你都做得到？…這不可能。我永遠學不會的。', '', 66384),
(305353, 'zhTW', '<莫戈莫戈大王壓低聲音。>\n\n你得幫幫我！\n\n我來這裡研究祖阿曼的魚人，但牠們正受到其他部族攻擊，我出手幫忙之後，牠們就集結到我身旁。現在牠們覺得我是神還是羅亞什麼的！\n\n我不知道怎麼當神啊！我只知道怎麼用這件衣服假裝成魚人！\n\n而且我很肯定，就職業道德來說，研究者不該做這種事。', '', 66384),
(305351, 'zhTW', '歡迎來到我的王國，旅行者。願和平和豐饒眷顧你！', '', 66384),
(305340, 'zhTW', '這…這太可怕了…你的武器毀滅了普雷達希亞上的所有文明？你怎麼能忍受這一切？你怎麼還能活下來？', '', 66384),
(305321, 'zhTW', '我的帝國要我鑄造一把武器來結束戰爭。我做到了。', '', 66384),
(305320, 'zhTW', '亡靈…你是阿奇杜德？你是武器鍛造師嗎？', '', 66384),
(305307, 'zhTW', '一種惡臭的混合物在大鍋中冒泡。', '一種惡臭的混合物在大鍋中冒泡。', 66384),
(305247, 'zhTW', '亡靈，是你雕刻了這塊石板嗎？你們…你們的文明…是因為戰爭而消逝的嗎？', '', 66384),
(305229, 'zhTW', '或許吧。我待在這裡的同時，無論如何，都會盡全力侍奉聖光的。\n\n雖然我還是很想知道為何我沒有受到召喚。', '', 66384),
(305228, 'zhTW', '這個可能性…似乎不錯。或許真是如此。我也很樂意相信這是真的。\n\n但我沒辦法百分之百確定，沒辦法確定的話，我要走的路就很明確：繼續盡力追求聖光、向聖光奉獻，無論發生任何事都一樣。', '', 66384),
(305077, 'zhTW', '', '想下注嗎？', 66384),
(305070, 'zhTW', '你會戰鬥。很好。\n\n我們希望你戰鬥。多戰鬥一點。為鮮血而戰。為死亡而戰。\n\n我們很中意你。', '', 66384),
(305067, 'zhTW', '這裡的狀況…很複雜。\n\n殺戮者高地有三個多曼納爾爭奪著力量。他們和手下的勢力比起跟我們作戰，似乎更想…利用我們來和其他勢力戰鬥。他們似乎對部落和聯盟長久以來的仇恨很有興趣。\n\n某天以來，開始有部落和聯盟的流氓出現。多曼納爾似乎找來了最惡毒嗜血的鬥士，讓他們互相殘殺以作樂。\n\n<裂隙守望者瑟雷蒙搖搖頭。>\n\n我們現在沒有餘力應付這樣的衝突。部落和聯盟雙方的官方代表人都沒有准許這樣的行為。現在狀況這麼多，我甚至不確定他們知道這件事。\n\n有些仇恨根深蒂固啊。', '', 66384),
(305062, 'zhTW', '只有強者得以生存。我的同胞都太弱了。我征服了死亡！而你將協助我重生。', '', 66384),
(305061, 'zhTW', '只有我美麗的武器才能阻止流血衝突。', '', 66384),
(305014, 'zhTW', '你隨時都可以用這個祭壇進行祭拜。', '你隨時都可以用這個祭壇進行祭拜。', 66384),
(304995, 'zhTW', '這些野獸從自然棲息地被引進侵噬之綻深處。我們不能放任光綻繼續壯大。', '', 66384),
(304994, 'zhTW', '薩拉塔斯從我們手上偷走了一座城市。我不會再讓她偷走第二座。', '薩拉塔斯從我們手上偷走了一座城市。我不會再讓她偷走第二座。', 66384),
(304993, 'zhTW', '真怪…我還以為聽到有人在說話。肯定是風聲…', '真怪…我還以為聽到有人在說話。肯定是風聲…', 66384),
(304992, 'zhTW', '我不聽叛徒說話。', '我不聽叛徒說話。', 66384),
(304990, 'zhTW', '部落展開轟炸的時候，我的朋友和家人都在塞拉摩。我們目前只是一時聯手，僅此而已。', '部落展開轟炸的時候，我的朋友和家人都在塞拉摩。我們目前只是一時聯手，僅此而已。', 66384),
(304988, 'zhTW', '我還是聞得到你身上的魔能。我們現在有共同的敵人，算你運氣好。', '我還是聞得到你身上的魔能。我們現在有共同的敵人，算你運氣好。', 66384),
(304987, 'zhTW', '我會為了保衛銀月城而戰，但我永遠不會忘記你們背叛了我們，加入部落。', '我會為了保衛銀月城而戰，但我永遠不會忘記你們背叛了我們，加入部落。', 66384),
(304985, 'zhTW', '背叛我們加入部落感覺如何？', '背叛我們加入部落感覺如何？', 66384),
(304984, 'zhTW', '被遺忘者住在村子裡，我們的族人和食人妖禮尚往來、和獸人和平相處。\n\n這不是我離開時的奎爾薩拉斯。我依然會全力保護它，任何一個奎爾薩拉斯的子民都會這麼做。\n\n只是這地方感覺不再像是我的家鄉了。', '被遺忘者住在村子裡，我們的族人和食人妖禮尚往來、和獸人和平相處。\n\n這不是我離開時的奎爾薩拉斯。我依然會全力保護它，任何一個奎爾薩拉斯的子民都會這麼做。\n\n只是這地方感覺不再像是我的家鄉了。', 66384),
(304983, 'zhTW', '我當初離開永歌森林，是為了保衛它免受戰火的威脅。\n\n現在我們又為了同樣的理由回到這裡。我只希望留下的人們知道我們為何離開，現在又為何回來。', '我當初離開永歌森林，是為了保衛它免受戰火的威脅。\n\n現在我們又為了同樣的理由回到這裡。我只希望留下的人們知道我們為何離開，現在又為何回來。', 66384),
(304982, 'zhTW', '我已經好多年沒看過奎爾薩拉斯的樹林。\n\n我都忘記它們被微風吹拂時的歌聲了。', '我已經好多年沒看過奎爾薩拉斯的樹林。\n\n我都忘記它們被微風吹拂時的歌聲了。', 66384),
(304975, 'zhTW', '真有意思，我從沒聽過這種凡人食物。是像蛋糕一樣的東西嗎？我針對艾澤拉斯的製造技術做的研究之中，最有意思的就是糕點技術了。所以，你喜歡糕點，對吧？我就假設你喜歡吧。\n\n就我個人來說，我喜歡各種口味：心痛、嫉妒、恐懼…\n\n<戴西蒙斯哼了一聲，舔了舔嘴唇。>\n\n接下來呢？我一時想不到你們凡人還會聊什麼無聊的話題。不如就問…\n\n你害怕的東西是什麼？', '', 66384),
(304971, 'zhTW', '', '佩爾娜，我們不該假設他們打算發動攻擊。他們看起來好像需要幫忙。', 66384),
(304931, 'zhTW', '$n，一叢新的光綻正要入侵回憶裂口。它們還受到一群危險的巨大孢龍保護著。\n\n除了蠻力強大之外，牠們散播的孢子只要落到地面，就會爆開變成狂暴的生長物。\n\n但要是你能夠先發制人，那股能量也許可以用來對付牠們的至親。', '$n，一叢新的光綻正要入侵回憶裂口。它們還受到一群危險的巨大孢龍保護著。\n\n除了蠻力強大之外，牠們散播的孢子只要落到地面，就會爆開變成狂暴的生長物。\n\n但要是你能夠先發制人，那股能量也許可以用來對付牠們的至親。', 66384),
(304930, 'zhTW', '', '我現在很忙，勇士。有重要的事嗎？', 66384),
(304922, 'zhTW', '邪枝似乎在烹煮一種燉肉。它散發著各種肉類和草藥的強烈氣味。', '邪枝似乎在烹煮一種燉肉。它散發著各種肉類和草藥的強烈氣味。', 66384),
(304906, 'zhTW', '至少沒比創造幽影這主意還糟。那東西徹底失控了，$p，我們得解決它，否則它只會一直散播痛苦而已。', '', 66384),
(304901, 'zhTW', '繼續，我會讓裂隙保持開啟。如果發生了什麼事，我會把你拉出來的。', '', 66384),
(304900, 'zhTW', '幽影是什麼？問十個暗裂隙行者，你會得到二十個不同的答案。化身、黑暗倒影、幻象…想了解他們就像用手去抓影子一樣。\n\n如果幾週前你問我同樣的問題，我會說我很了解他們。我甚至以為我能自己創造一個。但我卻創造出了某種…只知道折磨和痛苦的東西。\n\n所以，關於你的問題，我的答案是「不知道」。我只想要它從我眼前消失。', '', 66384),
(304897, 'zhTW', '', '那個孩子需要有人示範。讓他看看偉大的$c是怎麼跳舞的吧！', 66384),
(304895, 'zhTW', '如果來這裡對我有好處，那也行。但我實在看不出這跟跳舞有什麼關係。', '', 66384),
(304894, 'zhTW', '等等，我好像感覺到節奏了。', '', 66384),
(304872, 'zhTW', '', '很久以前，名為諾達希爾的巨樹在魔法水域的上方扎根。我們在一旁看著樹根穿透大地。當它們鑽入世界時，我們靜靜等待它們尋求艾恩哈拉的光芒…就像所有樹根那樣。\n\n當諾達希爾的樹根抵達哈朗達時，它們同時帶來了閃閃發光的雨水。多年過去，涓涓細流變成了你如今看到的流瀑和湖泊。\n\n歡迎來到哈檜，陌生人。這裡很歡迎你。', 66384),
(304841, 'zhTW', '', '我需要你幫忙，雷歐娜。拿好這個薰香，放在平台的各個方位上。', 66384),
(304837, 'zhTW', '真不知道他們會在遠征途中找到什麼獨特的樣本。', '', 66384),
(304827, 'zhTW', '', '我會和你並肩作戰，$n。', 66384),
(304824, 'zhTW', '如果我們能弄來足夠的能量，這些多曼納爾裝置就能找到你的斥侯。', '', 66384),
(304812, 'zhTW', '等等，我、我很抱歉。', '', 66384),
(304811, 'zhTW', '', '我也和你一樣毫無頭緒。說不定你還比我清楚呢。連經驗最豐富的裂隙行者，接觸過的奇怪文物恐怕都沒你多。\n\n我的建議是：用你的意志來掌控虛無。套句萊希卡斯可能會說的：瞄準，然後射擊。', 66384),
(304809, 'zhTW', '', '大多數刃多雷都很自由奔放，不過萊希卡斯簡直就是叛逆。\n\n我不想離開崗位去追查他的下落。要不是他射擊技術優秀，我會直接開啟一道傳送門，把他丟回特洛古斯。\n\n他最好不要浪費我們的時間。', 66384),
(304789, 'zhTW', '哈拉希爾是一座古老的村莊。無數世代以來，我們會將艾恩之塵磨成鮮豔的顏料，將記憶本身保存在顏色之中。這裡就是哈朗達的所有歷史展開成為岩石紀錄之旅的地方。\n\n不過最近，我們的村莊獲得了一項新的殊榮。被你們稱為埃達希爾的巨樹之根如今向育所延伸而去。身為根莖守望者，我的工作就是確保其平安健康，這是為了哈朗達眾生的福祉。', '', 66384),
(304782, 'zhTW', '<這具屍體剛被殺死沒多久。聖光孢子才剛寄生不久。>', '<這具屍體剛被殺死沒多久。聖光孢子才剛寄生不久。>', 66384),
(304754, 'zhTW', '你可以在法師區西北邊延伸出去的陽台上找到伊利達瑞。你要找的人是索松‧末日撕裂者。\n\n但別告訴他是我派你去的。', '你可以在法師區西北邊延伸出去的陽台上找到伊利達瑞。你要找的人是索松‧末日撕裂者。\n\n但別告訴他是我派你去的。', 66384),
(304740, 'zhTW', '', '不管你做了什麼，似乎有效果了。', 66384),
(304644, 'zhTW', '是母親派你來的嗎？\n\n告訴她我吃晚餐前就會回家。\n\n我手邊還有重要的事得處理呢！', '', 66384),
(304641, 'zhTW', '這裡是我思考和觀察的位置。\n\n如果你也想做同樣的事，那就去找自己的位置！', '', 66384),
(304602, 'zhTW', '', '他們是有可能在求助沒錯。但他們的村落就在附近。有可能是一場埋伏。$n，小心點。', 66384),
(304599, 'zhTW', '', '你的確活過了納羅拉克之穴。你比我想的還要強。你有資格和我們合作。\n\n但依然是個入侵者。', 66384),
(304597, 'zhTW', '', '雖然她假裝漠不關心，我覺得祖爾賈拉還是深深希望她的神明會現身。', 66384),
(304593, 'zhTW', '盡情探索吧，我們歡迎你，旅行者。\n\n我從沒見過你的同類，或許是艾恩哈拉讓我們的道路交織？', '盡情探索吧，我們歡迎你，旅行者。\n\n我從沒見過你的同類，或許是艾恩哈拉讓我們的道路交織？', 66384),
(304592, 'zhTW', '風瑪利昂不只是一座要塞，更是儀式場地。吞噬之眾在這裡進行虛無的實驗…多數想找出把我們殺了的新方式。他們讓這地方變得破敗不堪，就像是破舊的風帆一樣。幾百道小小的裂縫，隨著時間逐漸擴大。\n\n奇異點是最危險的裂縫。大到能夠自行維持，吞噬物質與能量來彈射到其他地方。\n\n在穩定狀態下，它們就能當作傳送門，但傳送點卻無法預測。不幸的是，它們十分不穩定，還會爆炸。\n\n我們有反制方案，但是開銷昂貴，而且只是暫時性的。', '', 66384),
(304529, 'zhTW', '我成功了！我是說，謝謝你，莉卡莉。你一直是很出色的老師。', '', 66384),
(304528, 'zhTW', '', '達拉克，你讓我刮目相看。恭喜你，士兵。', 66384),
(304523, 'zhTW', '', '夠了。你們兩個都做得很好。', 66384),
(304522, 'zhTW', '', '達拉克，讓我看看你的實力！$n，不要手下留情！', 66384),
(304521, 'zhTW', '我會和我的指揮官一起上樓找你。希望你和看上去一樣強大！', '', 66384),
(304513, 'zhTW', '', '啊啊啊啊啊啊啊啊！', 66384),
(304510, 'zhTW', '', '我一定可以的。或許你幫我加油的力道不夠？', 66384),
(304509, 'zhTW', '', '閉嘴，布沃！', 66384),
(304508, 'zhTW', '我就說吧！', '', 66384),
(304507, 'zhTW', '', '三！', 66384),
(304505, 'zhTW', '', '好啦，一、二…', 66384),
(304504, 'zhTW', '', '對吧，$n？', 66384),
(304503, 'zhTW', '', '才、才沒有！我有新朋友幫我加油打氣。', 66384),
(304502, 'zhTW', '哎呀，小安妮又要臨陣退縮了嗎？', '', 66384),
(304490, 'zhTW', '', '催化器可以為物品灌注強勁的力量，讓它們釋放出比過去更強大的潛能！', 66384),
(304489, 'zhTW', '', '壯觀的景象，不是嗎？\n\n自達斯雷瑪時代以來，精靈們便以這座偉大的熔爐打造出無與倫比的鎧甲。據說，這裡最初的火焰是由一隻覺得這裡適合築巢的鳳凰之魂點燃，而牠的力量至今仍流轉於每一件作品之中。\n\n我們允許你也能分享這份賜予。', 66384),
(304488, 'zhTW', '我們辦到了，$n。我成為卡達尼了，多虧了你的幫助。\n\n但盛大的慶祝同時也帶來悲傷。這就是狩獵之道。獵物得走上生命的盡頭，才能滿足獵人的需求。\n\n獵人不該因為殺死獵物而感到快樂。靈敏的飄泊者和巨大的野獸，在狩獵之道中都是平等的。\n\n拉杜尼的肉體所提供的材料與食物夠我們用上好幾週。我感謝那頭野獸的犧牲。', '我們辦到了，$n。我成為卡達尼了，多虧了你的幫助。\n\n但盛大的慶祝同時也帶來悲傷。這就是狩獵之道。獵物得走上生命的盡頭，才能滿足獵人的需求。\n\n獵人不該因為殺死獵物而感到快樂。靈敏的飄泊者和巨大的野獸，在狩獵之道中都是平等的。\n\n拉杜尼的肉體所提供的材料與食物夠我們用上好幾週。我感謝那頭野獸的犧牲。', 66384),
(304487, 'zhTW', '', '現在的情形不是自然發生的。\n\n我在這裡看到的，還有從在身上得知的所有事情，讓我推導出了真相：這座城市正在淨化自己。\n\n短短幾十年中，阿塔阿曼受到瑪拉克雷斯的黑暗魔法荼毒、莫爾頓可怕的虛無力量侵害，也與失聯的羅亞重新連繫。\n\n現在它正對此做出反應。把汙染物通通排出來，就像在火焰節前夕吃了太多甜莓的小孩一樣。\n\n只不過它嘔出的是早已不復存在的戰士和冒險者的回憶…', 66384),
(304486, 'zhTW', '多魯說他對這些回音的來歷有概念了。他有非常特殊、非常明確的理由。\n\n但要說我覺得是為什麼，它們肯定是因為先祖要給我們一計當頭棒喝。\n\n我們從未面對真相。我們當時就知道，祖爾金和瑪拉克雷斯在做的事不太對勁。沒有人能說得清楚…但是到頭來，你就是知道他們有些見不得人的地方。', '', 66384),
(304457, 'zhTW', '', '萬事小心！我不確定這個問題的真面目究竟是什麼。', 66384),
(304438, 'zhTW', '', '祝你在那東西手上死得愉快啊。', 66384),
(304437, 'zhTW', '', '哈哈！才不要。那東西已經纏上你了，那現在是「你」的問題了。我要閃人了！', 66384),
(304436, 'zhTW', '', '<坎莎不願和你四目相對。她專注地盯著自己的腳，並把雙手擰在一起。>', 66384),
(304435, 'zhTW', '', '我的家園和往常一樣，鬱鬱蔥蔥，生氣勃勃。但哈拉提不能對此感到自滿。\n\n我們必須守護女神的所有造物，不只是我們最熟悉的部分。', 66384),
(304434, 'zhTW', '', '我不覺得這招有用。\n\n但那東西現在沒在追我了…算是可以接受啦。', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(304429, 'zhTW', '', '我承認，知道那東西的注意力現在在你身上，讓我放心許多。我感覺又開始有活力了。', 66384),
(304428, 'zhTW', '我在這個地點的狩獵已經結束了。在我感到滿意之前，我還有一個地方想去。', '我在這個地點的狩獵已經結束了。在我感到滿意之前，我還有一個地方想去。', 66384),
(304427, 'zhTW', '', '哈！這樣大膽的話竟然出自一個老人之口，還真難接受！', 66384),
(304426, 'zhTW', '我們拚死也要讓阿塔阿曼重現往日榮光！', '', 66384),
(304425, 'zhTW', '', '那個人…', 66384),
(304424, 'zhTW', '森林部族再次感謝你，哈巫拉。', '', 66384),
(304423, 'zhTW', '我正在尋找更多材料。我之後再回哈拉希爾找你。', '我正在尋找更多材料。我之後再回哈拉希爾找你。', 66384),
(304422, 'zhTW', '$n，你的狩獵進行得如何了？\n\n我正在為愛雅特收集藤蔓，他是哈拉希爾的鐵匠。請工匠大師出手的時候，獻上禮物是一項傳統。\n\n鞭笞者藤蔓取之不易，而且非常強韌，當作禮物送給愛雅特應該能滿足他。', '$n，你的狩獵進行得如何了？\n\n我正在為愛雅特收集藤蔓，他是哈拉希爾的鐵匠。請工匠大師出手的時候，獻上禮物是一項傳統。\n\n鞭笞者藤蔓取之不易，而且非常強韌，當作禮物送給愛雅特應該能滿足他。', 66384),
(304419, 'zhTW', '', '把最好的屍骸放在桌上，這樣莉珊才能開始把它剁碎。', 66384),
(304413, 'zhTW', '', '我以靈魂向你致敬，博學者。', 66384),
(304412, 'zhTW', '我的前弟子啊，刃多雷正受到全面包圍。真高興我們有你，還有足夠強大的追隨者能守護我們的未來。', '', 66384),
(304411, 'zhTW', '', '有了這力量，我能夠訓練更多同胞，讓他們追隨我的腳步。', 66384),
(304410, 'zhTW', '', '她成功了，奧姆里克。伊利達瑞的力量和決心現在是她不可或缺的一部份了。', 66384),
(304409, 'zhTW', '我感受到雷文諾的黑暗存在已經消失了。你成功了嗎？', '', 66384),
(304408, 'zhTW', '', '雷歐娜，要是你在這裡倒下，你就會死。我是不會救你的。', 66384),
(304404, 'zhTW', '', '就是這裡，$n。反曲點。', 66384),
(304403, 'zhTW', '請退後一點。我們需要確保空間。', '', 66384),
(304402, 'zhTW', '能被邀請到這樣的地方真不錯啊！你試過狼人之鬃的酒嗎？真的很烈！\n\n我們以前的旅行日誌該添加不少新紀錄了。謝謝你幫我們處理酒債啊！', '', 66384),
(304401, 'zhTW', '基德和我曾想在這裡打鬥一兩次，但我感覺這裡不是那種適合打架的地方。\n\n不過，這裡可以從真正的老古董口中聽到很多故事。啊，我沒有冒犯的意思。', '', 66384),
(304400, 'zhTW', '能被邀請到這樣的地方真不錯啊！你試過狼人之鬃的酒嗎？真的很烈！', '', 66384),
(304399, 'zhTW', '哼！你的故事漏洞百出啊。說起來，巫妖王到底是怎麼召喚那麼多死亡騎士的？', '', 66384),
(304398, 'zhTW', '你認識基德，只要有超厲害的騎士，我想有多少不死族也不重要了。', '', 66384),
(304395, 'zhTW', '見到歐薇娜的故鄉後，很多事情突然都說得通了。我懂那種很想擺脫一個地方，最後卻還是回到原點的感覺。\n\n能來到這裡對我而言意義重大。', '', 66384),
(304394, 'zhTW', '', '蒙特在幽坑城帶我四處參觀他的家鄉，在那裡我與其他人截然不同。\n\n在這裡，我也想讓他感覺到自己是受到歡迎的。至少我能做到這件事。', 66384),
(304388, 'zhTW', '', '哈檜是充滿秘密與神話的村落。雖然祖拉夏守護著我們的記憶、長老們守護著傳統，垂根的子民最常表達敬意的對象，是我們尚未完全理解的女神創造的事物。', 66384),
(304387, 'zhTW', '光綻新生的枝芽擴散速度之快，讓我們來不及清除。\n\n把這些艾恩蛾帶上。牠們獨特的生理構造和強烈的食慾應該能在幼芽進一步擴散之前斬草除根。\n\n牠們的進食過程可能會帶來某些副作用，但你看起來還挺強壯的。', '光綻新生的枝芽擴散速度之快，讓我們來不及清除。\n\n把這些艾恩蛾帶上。牠們獨特的生理構造和強烈的食慾應該能在幼芽進一步擴散之前斬草除根。\n\n牠們的進食過程可能會帶來某些副作用，但你看起來還挺強壯的。', 66384),
(304375, 'zhTW', '科坦的興奮表現突然被他臉上的嚴肅表情取代。', '科坦的興奮表現突然被他臉上的嚴肅表情取代。', 66384),
(304373, 'zhTW', '拉杜尼死了。我們成功了！那頭野獸死了！', '拉杜尼死了。我們成功了！那頭野獸死了！', 66384),
(304372, 'zhTW', '', '我們以為應該會又快又安靜。魚人倒是有別的打算。', 66384),
(304342, 'zhTW', '還教會我們在菌帽下要堅強，因為偶爾也會覺得可怕。', '', 66384),
(304341, 'zhTW', '吉尼很感謝$p。教會我們在可怕的坑洞勇敢戰鬥。', '', 66384),
(304339, 'zhTW', '孢子滑翔者在池子附近。我們要是在途中戰鬥會掀起水花！', '', 66384),
(304338, 'zhTW', '嘿，想回到池子裡嗎？很舒服。很溫暖。而且還會濕濕的！', '', 66384),
(304337, 'zhTW', '', '吞噬之眾正在捕捉當地的生物並加以強化，他們應該是打算用來攻擊敵人。我們得小心點。', 66384),
(304336, 'zhTW', '蓬衛，真是最棒的選擇，$p！', '', 66384),
(304335, 'zhTW', '孢誓是個好名字。會讓我們更努力。我們現在發誓。', '', 66384),
(304334, 'zhTW', '選擇了環帽。菌帽是我們最棒的部分！', '', 66384),
(304332, 'zhTW', '你下次會說對的。是個很難的名字。', '', 66384),
(304331, 'zhTW', '從孢子誕生。向彼此起誓。讓我們成為最強隊伍！', '', 66384),
(304330, 'zhTW', '環帽這個名字代表布拉寇的菌帽。非常好看。', '', 66384),
(304328, 'zhTW', '', '我們那邊見，$n。', 66384),
(304324, 'zhTW', '一個嬌小的林地爬行者在樹根之下發出哀號。', '一個嬌小的林地爬行者在樹根之下發出哀號。', 66384),
(304302, 'zhTW', '<當你把這些液體混合之後，產生出來的是冒著泡泡、嘶嘶作響的混合物，你懷疑它甚至能溶解頑強的黏稠物質。>', '<當你把這些液體混合之後，產生出來的是冒著泡泡、嘶嘶作響的混合物，它似乎可以溶解任何東西。>', 66384),
(304301, 'zhTW', '<混合之後，這些液體快速蒸發，最後什麼也不剩。>', '<混合之後，這些液體快速蒸發，最後什麼也不剩。>', 66384),
(304300, 'zhTW', '<當混合物沉澱下來時，液體似乎消除了彼此的活性，創造出一團沒有效用的棕色黏液。沒半點用。>', '<當混合物沉澱下來時，液體似乎消除了彼此的活性，創造出一團沒有效用的棕色黏液。沒半點用。>', 66384),
(304283, 'zhTW', '謝謝你，長老。我不會辜負你和$n的。', '謝謝你，長老。我不會辜負你和$n的。', 66384),
(304277, 'zhTW', '<這個瓶子看起來足夠強韌，可以用來裝腐蝕性液體。>', '<這個瓶子看起來足夠強韌，可以用來裝腐蝕性液體。>', 66384),
(304268, 'zhTW', '你有沒有曾經很想要某個東西，最後卻錯失機會？而且還不是因為自己的過失。\n\n<科坦交叉著雙臂嘆了口氣。>\n\n我現在也對此無能為力了。', '你有沒有曾經很想要某個東西，最後卻錯失機會？而且還不是因為自己的過失。\n\n<科坦交叉著雙臂嘆了口氣。>\n\n我現在也對此無能為力了。', 66384),
(304266, 'zhTW', '你好，陌生人。身為哈拉尼爾，你肯定聽說過卡達尼試煉，對吧？\n\n<科坦交叉著雙臂嘆了口氣。>\n\n這些試煉是為了讓哈拉希爾有機會加入一個名為卡達尼的精英獵人團體。試煉每個週期會舉辦一次，但是想要參加，就必須找到一個願意擔任導師的卡達尼成員。\n\n我本該是其中一位受選者，但現在我得等到下一個週期了。', '你好，陌生人。身為哈拉尼爾，你肯定聽說過卡達尼試煉，對吧？\n\n<科坦交叉著雙臂嘆了口氣。>\n\n這些試煉是為了讓哈拉希爾有機會加入一個名為卡達尼的精英獵人團體。試煉每個週期會舉辦一次，但是想要參加，就必須找到一個願意擔任導師的卡達尼成員。\n\n我本該是其中一位受選者，但現在我得等到下一個週期了。', 66384),
(304264, 'zhTW', '比較適合朗誦，而不是讓人閱讀的詩。\n\n這個地方不會隨便讓人進來。不用擔心。', '', 66384),
(304261, 'zhTW', '那是讀詩活動，$g先生:小姐;。\n\n我們會邀請城市裡的詩人來把自己寫的作品分享給…志同道合的人。\n\n一首好詩確實能發人深省，你不覺得嗎？', '', 66384),
(304260, 'zhTW', '花苞發育不良，無法接觸到聖光。', '花苞發育不良，無法接觸到聖光。', 66384),
(304258, 'zhTW', '歡迎光臨。慢慢看，慢慢逛。\n\n如果有什麼東西想帶回家，我可以幫你包起來。', '', 66384),
(304254, 'zhTW', '雖然他們生前讓我們蒙羞，但你的努力或許能讓從前偷走羅亞力量的人們重獲榮耀。', '', 66384),
(304253, 'zhTW', '', '拋下你的同情心吧，$n。', 66384),
(304252, 'zhTW', '從這裡，我也看得出來戰況正在好轉。', '', 66384),
(304251, 'zhTW', '', '哈！我只想起了當年得一次又一次，拖著全身是傷的你脫離戰場而已。', 66384),
(304250, 'zhTW', '承認吧，多魯。這讓你想起了過往的日子，讓你覺得很懷念吧。', '', 66384),
(304249, 'zhTW', '', '你回來了。很好。神廟也守住了吧？', 66384),
(304248, 'zhTW', '保持警戒，$n。回音雖然很弱，但一不小心就可能被包圍。', '', 66384),
(304236, 'zhTW', '', '我還有一個哈拉尼爾傳統想要展示給你看。就在這個方向的壁畫上。', 66384),
(304232, 'zhTW', '', '來吧。我們繼續深入大巢穴。', 66384),
(304231, 'zhTW', '意思是我們可以砸爛它！', '', 66384),
(304230, 'zhTW', '', '這是我想的那個意思嗎？', 66384),
(304229, 'zhTW', '沒錯，孩子們。你們很快就能破壞這台機甲的結構完整度了！', '', 66384),
(304228, 'zhTW', '', '我們待會再回來！現在，蒙特，大巢穴裡，我還有許多東西要給你看。', 66384),
(304219, 'zhTW', '', '…好，爸爸。', 66384),
(304218, 'zhTW', '你下次得自己去採，好嗎？', '', 66384),
(304217, 'zhTW', '', '喔，嗨！歡迎回來！你全部找到了嗎？', 66384),
(304216, 'zhTW', '安嘉莉，快進來！友善的$c帶你的草藥回來了。', '', 66384),
(304215, 'zhTW', '你得先完成作業才能去。讓我看看你學了什麼。', '', 66384),
(304214, 'zhTW', '', '但是，爸爸，我想跟其他人去玩！', 66384),
(304213, 'zhTW', '感謝你幫助侍僧。', '', 66384),
(304212, 'zhTW', '羅亞會透過那個圖騰出力。你只是在轉移祂的力量。', '', 66384),
(304211, 'zhTW', '阿奇爾森。勝利羅亞。天空、疾風、驟雨和雷霆的霸主！', '', 66384),
(304210, 'zhTW', '哈拉齊。狩獵羅亞。敏捷、狡詐、有耐心。不論在何地，都是追蹤任何獵物的理想獵人。', '', 66384),
(304209, 'zhTW', '', '賈納雷，火焰羅亞。魔法的主宰，也是存在於所有生物體內的烈焰。', 66384),
(304208, 'zhTW', '', '納羅拉克。戰爭羅亞。固執且毫不寬容，但對他的信徒絕對忠誠。', 66384),
(304207, 'zhTW', '隨著每一筆，我都承載著信念、希望…以及你分享的一切。', '', 66384),
(304206, 'zhTW', '要是沒有你，我絕對辦不到這件事，你的善良幫助我重新找回自己。', '', 66384),
(304200, 'zhTW', '我知道在你的照料下，這些材料或許能帶來新生…而不是造成我引起的毀滅。', '', 66384),
(304199, 'zhTW', '我很難信任其他人…但你人真善良。', '', 66384),
(304197, 'zhTW', '我辜負了大家，最糟糕的是辜負了自己，不過你卻挺身而出、改正錯誤。謝謝你。', '', 66384),
(304195, 'zhTW', '', '很高興你能來這一趟。\n\n這是個有趣的故事。是這樣的，我在調查其他受虛無干擾的案例時，也帶上了那個生物。結果其他生物就被牠引出來了！我覺得牠們的好奇心挺旺盛的。\n\n也可能是牠們兇蠻無比，打算吃掉彼此，我還在調查這個可能性。\n\n雖然我只是想增進知識而已，但這樁清除鬼怪事物的生意說不定很有賺頭呢。\n\n很快我就能收集一整倉的這些生物了。我得找個合適的地方放牠們進去才行！', 66384),
(304191, 'zhTW', '', '我的研究囊括關於虛無的任何案例。我向來都喜歡神秘的個案。', 66384),
(304159, 'zhTW', '安嘉莉，等等，你應該自己去採…別再偷懶了。', '', 66384),
(304150, 'zhTW', '', '你可以在村莊四周找到草藥！好，謝了，掰！', 66384),
(304143, 'zhTW', '', '等你準備好了就挑戰她。', 66384),
(304110, 'zhTW', '$n，這邊。', '', 66384),
(304060, 'zhTW', '', '我去找他。你去看看，比起哥布林，英哈尤有沒有什麼納霍特更想抱的東西。', 66384),
(304059, 'zhTW', '真奇怪！我也不知道是怎麼一回事。', '', 66384),
(304058, 'zhTW', '嘿，庫德蘭，$p來了。但這些斧頭是怎麼回事？', '', 66384),
(304056, 'zhTW', '<這一堆板子和繩索似乎是惡齒螃蟹籃毀壞的殘骸。\n\n上頭佈滿了巨大的爪痕，而且被粗魯地拆得四分五裂。被摧毀的虛無神器裂片深深陷入木材之中。\n\n雖然殘骸因為在河中流動而亂糟糟的，但河水沒有洗去上頭的髒污：裂片讓木材充滿了虛無的氣息。>', '', 66384),
(304047, 'zhTW', '<螃蟹屍體散落在四周。有些肢體被撕開，有些被某種巨大的東西砸碎了…也許是下顎？或是爪子？\n\n傷口中有虛無神器的裂片，屍體還散發著虛無的能量。>', '', 66384),
(304005, 'zhTW', '', '那個陷阱應該夠用。', 66384),
(304002, 'zhTW', '', '來吧，金克絲，我們趕快離開這裡！', 66384),
(304001, 'zhTW', '<這個蜥蜴頭骨被一塊石頭砸到凹陷了。>', '<這個蜥蜴頭骨被一塊石頭砸到凹陷了。>', 66384),
(304000, 'zhTW', '我們有機會跟阿曼尼對話的時候，影松請我代表他們出席，但我不認為自己是首領。', '', 66384),
(303999, 'zhTW', '', '我知道！', 66384),
(303997, 'zhTW', '<雖然只是過去的回音，這個鐵砧還能使用。>', '<雖然只是過去的回音，這個鐵砧還能使用。>', 66384),
(303996, 'zhTW', '', '哇，你超勇敢！', 66384),
(303994, 'zhTW', '', '我就用這個大石頭砸他的眼睛！', 66384),
(303993, 'zhTW', '哇啊！', '', 66384),
(303990, 'zhTW', '', '像這樣。砰！', 66384),
(303989, 'zhTW', '', '你接下來要做什麼，安妮？', 66384),
(303988, 'zhTW', '', '然後牠就突然朝我身上跳了過來！', 66384),
(303986, 'zhTW', '', '我們不會遺忘任何枯木族人！我會在梅薩拉洞穴和你碰面。', 66384),
(303974, 'zhTW', '這些回音比水豚還要弱！這給了我的鬥士絕佳的練習機會！', '', 66384),
(303973, 'zhTW', '有這些補給品真是太好了，我們的戰士在保護那些老鷹時受了重傷。', '', 66384),
(303972, 'zhTW', '你從多魯和托倫多那裡帶來什麼消息？', '', 66384),
(303970, 'zhTW', '殺不完的敵人？這可是訓練的好機會！', '', 66384),
(303969, 'zhTW', '', '這是一場對歷史的狩獵。哈巫拉，你願意加入我們嗎？', 66384),
(303968, 'zhTW', '', '多魯時機算得真準。我們薩滿的補給品也快用完了。', 66384),
(303966, 'zhTW', '', '謝謝你，哈巫拉。也替我們謝謝多魯。', 66384),
(303963, 'zhTW', '', '烈焰正在問好，哈巫拉。', 66384),
(303954, 'zhTW', '你必須…阻止我。', '', 66384),
(303925, 'zhTW', '我女兒在植物和配方方面的才華無與倫比，但是就算性命交關，她還是無法集中注意力。\n\n看著這個瘋狂世界正在發生的一切，我擔心她有一天真的會丟了性命。\n\n我不想對她太嚴厲，但…她必須精通這些技巧。我們製造的藥膏和藥水能夠保障人們的安全，延續他們的性命。', '', 66384),
(303923, 'zhTW', '我唯一想要的，就是為了保護家園而戰的榮耀。\n\n還有一根稱手的長矛。', '', 66384),
(303911, 'zhTW', '', '我以為當藥劑師是件有趣的事。我喜歡照料植物。\n\n不過，工作量遠超我的預料。', 66384),
(303910, 'zhTW', '就算已經老了，還是能從羅亞語者那裡學到很多事。\n\n我奮戰的歲月已經過去了，但我還是有方法可以近距離感受到羅亞。', '', 66384),
(303904, 'zhTW', '', '一開始，達拉克的狂熱讓我很擔心。太過心急的戰鬥者通常很魯莽。他們欠缺必要的紀律，無法成為偉大的戰士。\n\n不過他出乎我的意料。他總是第一個到，最後一個離開。他擅長提問，也比我的其他學生更加刻苦訓練。\n\n如果他們當中有任何人能贏得我的尊敬，絕非他莫屬。對此，我自己也感到很驚訝。', 66384),
(303902, 'zhTW', '', '有什麼事不太對勁。', 66384),
(303901, 'zhTW', '', '入侵者，我不跟血精靈說話。走開。', 66384),
(303898, 'zhTW', '', '你有看過暮光之刃嗎？哼。我能對付他們。我還見過更強的敵人。他們跟血精靈相比不值一提。\n\n我的父親教過我怎麼用斧頭。我會打敗任何想奪取阿曼尼土地的人！', 66384),
(303897, 'zhTW', '', '我一直夢到我變成一條蛇。我不喜歡蛇。我晚上不想上床睡覺了。', 66384),
(303895, 'zhTW', '', '我看到一個納爾丁！他從河的附近經過村子，但是我哥說我在瞎掰。我才沒有！', 66384),
(303893, 'zhTW', '', '你總是穿成這樣嗎？你有穿過靴子嗎？我覺得它們看起來很蠢。', 66384),
(303892, 'zhTW', '', '我的弓被鳥偷走了！我想努力訓練，幫助我媽媽戰鬥，這樣她就能快點回家了。我好想她！', 66384),
(303891, 'zhTW', '', '嘎啊啊啊！我有嚇到你嗎？我爸爸說我很像納羅拉克！', 66384),
(303890, 'zhTW', '', '爸爸說之後會辦一場盛大的宴會！你會來參加嗎？小孩優先，但你可以跟在我後面。', 66384),
(303887, 'zhTW', '', '村子裡的阿曼尼太多，我只能跟我的妹妹睡同一張床。煩耶！', 66384),
(303885, 'zhTW', '', '我媽媽說不能跟入侵者說話。抱歉。', 66384),
(303870, 'zhTW', '', '退後！', 66384),
(303869, 'zhTW', '', '你還在等什麼？快走！\n\n<她腳下的地面沾滿了鮮血。雖然她嘗試過止血，但顯然效果不彰。>\n\n我們已經盡力了。有些事物，即便聖光也無法治療。', 66384),
(303860, 'zhTW', '', '我示範一次給你看，然後你也可以試試！', 66384),
(303856, 'zhTW', '', '你好！你有帶吃的來嗎？\n\n我好餓。', 66384),
(303846, 'zhTW', '做得好。看你戰鬥真是一如往常地令人興奮。\n\n你的朋友真讓人遺憾。為何信仰聖光的傢伙總是這麼急著送命呢？', '', 66384),
(303844, 'zhTW', '啊，一整隊信仰聖光的傢伙們要攻擊虛無的無盡大軍。有好戲可看了。', '', 66384),
(303837, 'zhTW', '', '我可以教你一些基本知識。足夠使用這個染料台，但其他就不行了。如果你想真正成為鍊金師，就得回暴風城去。穿過傳送門回到暴風城，在巫師聖所的東邊，有間叫鍊金材料店的店。那裡的訓練師比我更懂鍊金術。\n\n找不到的話，請守衛幫你標記地圖。', 66384),
(303825, 'zhTW', '', '我對殺影衛沒有意見。注意觀察屍體被標記時會發生什麼事。', 66384),
(303823, 'zhTW', '<這具屍體好像全身蓋滿了光綻孢子。>', '<這具屍體好像全身蓋滿了光綻孢子。>', 66384),
(303816, 'zhTW', '若要證明自己的能耐，前往羅亞的聖地，並從古代偉大戰士的安息之處取回四個信物。', '若要證明自己的能耐，前往羅亞的聖地，並從古代偉大戰士的安息之處取回四個信物。', 66384),
(303814, 'zhTW', '<獵人靈魂帶著敬意鞠躬。他已經充分準備好展開下一場狩獵了，那將是他人生壯闊旅程的下一步。>', '<獵人靈魂帶著敬意鞠躬。他已經充分準備好展開下一場狩獵了，那將是他人生壯闊旅程的下一步。>', 66384),
(303813, 'zhTW', '<孩童靈魂伸了伸懶腰，就像是剛從一場漫長的睡眠中醒來。它眨眨眼後環顧四周，不確定自己在哪裡。它一看見你，嘴巴就彎成了一抹大大的微笑。>', '<孩童靈魂伸了伸懶腰，就像是剛從一場漫長的睡眠中醒來。它眨眨眼後環顧四周，不確定自己在哪裡。它一看見你，嘴巴就彎成了一抹大大的微笑。>', 66384),
(303812, 'zhTW', '我們失去了那魯！', '', 66384),
(303811, 'zhTW', '這個怪物也掙脫束縛了！', '', 66384),
(303788, 'zhTW', '迎來重生。', '迎來重生。', 66384),
(303787, 'zhTW', '到死亡。', '到死亡。', 66384),
(303786, 'zhTW', '從生命。', '從生命。', 66384),
(303785, 'zhTW', '理解女神。', '理解女神。', 66384),
(303784, 'zhTW', '展開一段旅程。', '展開一段旅程。', 66384),
(303783, 'zhTW', '從謙遜的開始。', '從謙遜的開始。', 66384),
(303775, 'zhTW', '秘法能量在絆索的控制面板周圍發出嗡嗡聲。\n\n很可惜，你無法理解這個裝置的複雜結構。', '秘法能量在絆索的控制面板周圍發出嗡嗡聲。\n\n很可惜，你無法理解這個裝置的複雜結構。', 66384),
(303774, 'zhTW', '秘法能量在絆索的控制面板周圍發出嗡嗡聲。', '秘法能量在絆索的控制面板周圍發出嗡嗡聲。', 66384),
(303773, 'zhTW', '', '當然了。', 66384),
(303772, 'zhTW', '', '瓦麗拉嘆了口氣。', 66384),
(303770, 'zhTW', '你好啊，年輕人。你需要寄放寵物，或是幫忙尋找失蹤的夥伴嗎？', '你好啊，年輕人。你需要寄放寵物，或是幫忙尋找失蹤的夥伴嗎？', 66384),
(303769, 'zhTW', '你好啊，年輕人。你需要幫忙尋找失蹤的夥伴嗎？', '你好啊，年輕人。你需要幫忙尋找失蹤的夥伴嗎？', 66384),
(303767, 'zhTW', '你知道的，有一艘托爾托船很久以前在這失蹤了。也許我能找到古老的遺物！', '你知道的，有一艘托爾托船很久以前在這失蹤了。也許我能找到古老的遺物！', 66384),
(303766, 'zhTW', '啊，你好啊，旅行者。這或許不是什麼好地方，但若有需要，隨時歡迎你在這休息。\n\n我正忙著紀錄新發現，沒辦法停下來！', '啊，你好啊，旅行者。這或許不是什麼好地方，但若有需要，隨時歡迎你在這休息。\n\n我正忙著紀錄新發現，沒辦法停下來！', 66384),
(303764, 'zhTW', '你長大之後想要當什麼？我想當枯木族。說不定我能長出像他們一樣的大牙齒！', '', 66384),
(303763, 'zhTW', '追斯特吉好難啊！你的腿挺壯的。能幫我追她嗎？我累死了！', '', 66384),
(303762, 'zhTW', '嘿，我很忙！斑斑想知道村子裡最好的躲藏點。去煩其他人！', '嘿，我很忙！斑斑想知道村子裡最好的躲藏點。去煩其他人！', 66384),
(303761, 'zhTW', '入侵者，別來煩我！我得抓到比我兄弟更多的魚！', '入侵者，別來煩我！我得抓到比我兄弟更多的魚！', 66384),
(303760, 'zhTW', '潔兒阿姨不讓我和娜拉用長矛捕魚。但她說如果我能抓到一百條魚，她或許會教我怎麼做！', '潔兒阿姨不讓我和娜拉用長矛捕魚。但她說如果我能抓到一百條魚，她或許會教我怎麼做！', 66384),
(303756, 'zhTW', '幫幫忙！芬利被綁架了！', '', 66384),
(303754, 'zhTW', '我會讓你好看…', '', 66384),
(303751, 'zhTW', '放開他！', '', 66384),
(303750, 'zhTW', '要是隊伍跑出去，就不能當贏家了。很重要的規則。', '', 66384),
(303749, 'zhTW', '$p，跑出去是新手錯誤。', '', 66384),
(303747, 'zhTW', '$p，隊伍名字想好了嗎？取什麼好？', '', 66384),
(303746, 'zhTW', '$p！我們需要一個隊伍名稱。進坑洞可不能沒有響亮的名字！', '', 66384),
(303745, 'zhTW', '讓蘑菇人見識$r的能耐。如果你很強的話。', '', 66384),
(303744, 'zhTW', '$p，進入怨鬥坑洞吧。', '', 66384),
(303743, 'zhTW', '長老靈魂將捲起的枕頭擺放在祭壇上。', '長老靈魂將捲起的枕頭擺放在祭壇上。', 66384),
(303742, 'zhTW', '一個人類，還真是無趣。我發現我最近都快被他們淹沒了。', '', 66384),
(303741, 'zhTW', '我會盯著你的。', '', 66384),
(303740, 'zhTW', '不過，這個！真是有趣的小標本，值得納入我的收藏。', '', 66384),
(303739, 'zhTW', '獵人靈魂將小刀擺放在祭壇上。', '獵人靈魂將小刀擺放在祭壇上。', 66384),
(303738, 'zhTW', '孩童靈魂將球擺放在祭壇上。', '孩童靈魂將球擺放在祭壇上。', 66384),
(303737, 'zhTW', '虛無之尖的力量會吞沒一切！', '', 66384),
(303727, 'zhTW', '<一位獵人坐在溫暖火堆旁的幻象逐漸在你腦中形成。他身邊堆放著從狩獵中收集而來的皮革、骨頭和其他資源。獵人悠閒地靠坐著，偶爾將一大塊肉在篝火上翻轉。這場狩獵很成功。>', '<一位獵人坐在溫暖火堆旁的幻象逐漸在你腦中形成。他身邊堆放著從狩獵中收集而來的皮革、骨頭和其他資源。獵人悠閒地靠坐著，偶爾將一大塊肉在篝火上翻轉。這場狩獵很成功。>', 66384),
(303726, 'zhTW', '<你的幻象中先是出現一道耀眼的光芒，接著一個熟睡孩童的形象逐漸在你腦中形成。它身邊有一顆破爛的球。雖然孩童正在熟睡，它依然面露微笑，對於可以玩球玩到精疲力盡而感到快樂和滿足。>', '<你的幻象中先是出現一道耀眼的光芒，接著一個熟睡孩童的形象逐漸在你腦中形成。它身邊有一顆破爛的球。雖然孩童正在熟睡，它依然面露微笑，對於可以玩球玩到精疲力盡而感到快樂和滿足。>', 66384),
(303725, 'zhTW', '', '我不會放任他們不管的。', 66384),
(303721, 'zhTW', '別踩到我！我認真的！', '', 66384),
(303720, 'zhTW', '保持距離！', '', 66384),
(303718, 'zhTW', '我認真的！別踩到我！', '', 66384),
(303717, 'zhTW', '離我遠一點！', '', 66384),
(303716, 'zhTW', '退開！別靠太近！', '', 66384),
(303714, 'zhTW', '我是認真的！不要！', '', 66384),
(303710, 'zhTW', '告訴我發生了什麼事。', '告訴我發生了什麼事。', 66384),
(303709, 'zhTW', '他綁架了芬利爵士！\n\n我們必須去救他。', '', 66384),
(303708, 'zhTW', '', '拿穩了！我再試一次。', 66384),
(303707, 'zhTW', '<影芽與野獸的毛皮融合為一。英普利亞能完全掌控牠，驅使牠為了取悅自己而戰。\n\n安娜絲似乎嘗試過除去這暗影金屬。但野獸沒能活下來。>', '<影芽與野獸的毛皮融合為一。英普利亞能完全掌控牠，驅使牠為了取悅自己而戰。\n\n安娜絲似乎嘗試過除去這暗影金屬。但野獸沒能活下來。>', 66384),
(303702, 'zhTW', '我沒時間廢話。你有什麼事嗎？', '我沒時間廢話。你有什麼事嗎？', 66384),
(303701, 'zhTW', '入侵者，你最好對剝皮技術很熟悉，不然你就會反過來被剝皮。', '入侵者，你最好對剝皮技術很熟悉，不然你就會反過來被剝皮。', 66384),
(303699, 'zhTW', '完美狩獵是一種心境與本領合而為一的狀態。它需要獵人保持冷靜和專注。它將獵人的武器視為自身的延伸。它是獵物無法分辨出周遭是自然環境還是獵人的那個時刻。\n\n獵人必須奮力追求自身潛能的極限。只有到那時，才能真正獲得狩獵之靈本尊的祝福。', '完美狩獵是一種心境與本領合而為一的狀態。它需要獵人保持冷靜和專注。它將獵人的武器視為自身的延伸。它是獵物無法分辨出周遭是自然環境還是獵人的那個時刻。\n\n獵人必須奮力追求自身潛能的極限。只有到那時，才能真正獲得狩獵之靈本尊的祝福。', 66384),
(303697, 'zhTW', '菲力克正受到衛地飄泊者獵殺！', '', 66384),
(303696, 'zhTW', '惱怒的鞭笞者正想吃掉娜菈！', '', 66384),
(303695, 'zhTW', '投機的林地爬行者正在攻擊托姆！', '', 66384),
(303692, 'zhTW', '躁躁因衛地飄泊者的存在而發怒。', '', 66384),
(303649, 'zhTW', '', '我懂。在凱瑞西發生那些事之後…\n\n暗域行者雖然說服了我們和薩拉塔斯合作，但我卻一直反對信任虛無生物。\n\n我是正確的嗎？暗域行者已經不在了。但是如果我們沒和薩拉塔斯合作，迪曼修斯就會吞噬一切。或者我們能找到別的方法？\n\n如果我一開始就相信暗域行者，他是不是就不會喪命了？\n\n在這裡度過的每個寒冷長夜中，我從未安穩入睡。我只會自問這些問題。\n\n我告訴暗域行者，他不再是我的導師了。但這不是真的。我…打算再接受一次他的教訓。\n\n虛無生物的目的只有一個：生存。我們能夠好好運用這個知識。', 66384),
(303647, 'zhTW', '腐化幾乎都來自於死亡之域。我們改善了城市附近的環境，但是許久以來，南邊幾乎都被放置不管。直到最近遠行者才重新開始巡邏。\n\n殘留在土壤裡的所有邪惡魔法都會長到植物裡面。動物會吃掉這些植物，魔法濃度就會跟著提高。\n\n然後動物會再被其他動物吃掉…我想你也看得出來，這問題是怎麼來的。', '', 66384),
(303645, 'zhTW', '身為遠行者就是要做這種苦差事！我不會逃避的。', '', 66384),
(303644, 'zhTW', '噢，這裡什麼都有！\n\n草藥跟綠葉會先萌芽，然後是莓果叢和堅果樹會結果。一旦葉影遮住土壤之後，蘑菇就會從樹根長出來。但這只不過是個開端罷了！\n\n兔子和小鳥會躲在草叢裡，山貓和陸行鷹會獵食牠們，再把種子傳播到更遠的地方…這是一整個生態循環！我們吃東西的時候，所有生物也都在進食。', '', 66384),
(303611, 'zhTW', '', '或許我們能拯救凱瑞西更多的部分，並遵守那些誓言。', 66384),
(303610, 'zhTW', '', '你是對的，齊凡。謝謝你恪守誓言。', 66384),
(303609, 'zhTW', '', '好吧。帶我們到你說的抵抗者那裡吧。', 66384),
(303608, 'zhTW', '', '選擇…', 66384),
(303607, 'zhTW', '你的力量真是耀眼。還有其他人也正奮力抵抗。活下去吧，我會讓你親眼見證的！', '', 66384),
(303606, 'zhTW', '拜託了，維蘭！如何讓導體運作的知識已經隨著迪薩的死入土了。你不用這麼做！', '', 66384),
(303605, 'zhTW', '', '集中在內部的火焰。把這個導體徹底摧毀吧！', 66384),
(303604, 'zhTW', '去吧，$n，我們會注意安全的！', '', 66384),
(303603, 'zhTW', '你都成功控制住黑暗到現在了！拜託你…別虛擲你的生命…', '', 66384),
(303602, 'zhTW', '', '謝謝你幫我們走到這裡，齊凡。但我們該分道揚鑣了。', 66384),
(303601, 'zhTW', '', '我感受得到它就在裡面…隨時可能爆開…', 66384),
(303595, 'zhTW', '我想我該去…幫一些掃帚附魔了。', '', 66384),
(303594, 'zhTW', '', '我應該派人通報的，但你也看得出來，我們有點人手不足。', 66384),
(303593, 'zhTW', '來吧，大熊！為了遠行者！', '', 66384),
(303573, 'zhTW', '<這株壯碩幼苗的頭正集中在附近草叢底下的黑暗角落。你一靠近，牠便發出嘶嘶聲，明確向你表達牠想要獨處。>', '<這株壯碩幼苗的頭正集中在附近草叢底下的黑暗角落。你一靠近，牠便發出嘶嘶聲，明確向你表達牠想要獨處。>', 66384),
(303572, 'zhTW', '<這株幼芽高舉著頭。三顆頭上下打量你的同時，牠發出一聲嘲諷般的短促鼻息。感到厭煩後，牠接著抬頭看向育所，或許是在等待女神親自賜給牠祝福。>', '<這株幼芽高舉著頭。三顆頭上下打量你的同時，牠發出一聲嘲諷般的短促鼻息。感到厭煩後，牠接著抬頭看向育所，或許是在等待女神親自賜給牠祝福。>', 66384),
(303571, 'zhTW', '<多頭樹妖幼芽正熟睡著。原先聽起來像是吼聲或哼聲的聲音，原來只是響亮的鼾聲。>', '<多頭樹妖幼芽正熟睡著。原先聽起來像是吼聲或哼聲的聲音，原來只是響亮的鼾聲。>', 66384),
(303570, 'zhTW', '<這隻多頭樹妖幼芽就是坐不住。牠對每一個聲響、動作、氣味都充滿興趣。>', '<這隻多頭樹妖幼芽就是坐不住。牠對每一個聲響、動作、氣味都充滿興趣。>', 66384),
(303568, 'zhTW', '你只需要四個幼芽。每隻多頭樹妖各一個。或是十二個。取決於你怎麼數牠們。', '你只需要四個幼芽。每隻多頭樹妖各一個。或是十二個。取決於你怎麼數牠們。', 66384),
(303567, 'zhTW', '你聽起來很驚訝！要是你知道在那之下…就是，牠們的…深層內在，牠們是受到嚴重誤解、溫柔且忠誠的野獸。最後一個部分取決於牠們早上醒來時的心情，但大部分時候，我們會把牠們視為危險的野獸。\n\n牠們值得更好的待遇，也應當回到牠們的自然棲地。', '你聽起來很驚訝！要是你知道在那之下…就是，牠們的…深層內在，牠們是受到嚴重誤解、溫柔且忠誠的野獸。最後一個部分取決於牠們早上醒來時的心情，但大部分時候，我們會把牠們視為危險的野獸。\n\n牠們值得更好的待遇，也應當回到牠們的自然棲地。', 66384),
(303565, 'zhTW', '謝謝你幫我做的一切。\n\n重新引入這些神奇的野獸，將會幫助叢林流瀑的生態系恢復原有的平衡。\n\n我的寶貝多頭樹妖幼芽們應該可以輕鬆適應。多頭樹妖強韌且機智，假以時日，牠們就能重回正常的數量。', '謝謝你幫我做的一切。\n\n重新引入這些神奇的野獸，將會幫助叢林流瀑的生態系恢復原有的平衡。\n\n我的寶貝多頭樹妖幼芽們應該可以輕鬆適應。多頭樹妖強韌且機智，假以時日，牠們就能重回正常的數量。', 66384),
(303564, 'zhTW', '你好啊，陌生人。你大概在想，為什麼這些美麗的多頭樹妖會包圍著我。我叫奈塔，我是附近流瀑的保育者。\n\n你在那片區域內沒有見過多頭樹妖，對吧？這很難說出口，但蘭花多頭樹妖消失都是我的錯。我放任牠們遭到捕殺，怠於管理，導致牠們的數量大幅減少了。\n\n我希望能彌補過錯，將美艷動人的蘭花多頭樹妖重新引入諾達希爾樹根的流瀑。', '你好啊，陌生人。你大概在想，為什麼這些美麗的多頭樹妖會包圍著我。我叫奈塔，我是附近流瀑的保育者。\n\n你在那片區域內沒有見過多頭樹妖，對吧？這很難說出口，但蘭花多頭樹妖消失都是我的錯。我放任牠們遭到捕殺，怠於管理，導致牠們的數量大幅減少了。\n\n我希望能彌補過錯，將美艷動人的蘭花多頭樹妖重新引入諾達希爾樹根的流瀑。', 66384),
(303562, 'zhTW', '我們所有的戰爭法師和有戰鬥經驗的博學者都被派往了前線，而其他人則被撤離到了銀月城或這裡。\n\n我的專業是共鳴水晶理論，不是朝來自另一個世界的怪物丟火球。', '我們所有的戰爭法師和有戰鬥經驗的博學者都被派往了前線，而其他人則被撤離到了銀月城或這裡。\n\n我的專業是共鳴水晶理論，不是朝來自另一個世界的怪物丟火球。', 66384),
(303553, 'zhTW', '我在這打包一下。去南塔看看泰明是否需要協助。', '我在這打包一下。去南塔看看泰明是否需要協助。', 66384),
(303550, 'zhTW', '', '我們在這裡烹調動物的所有部位。\n\n你嚐過野豬心嗎？我從小到大一直聽說它很難咬，因為吃了它，你就能獲得動物的力量。\n\n我不確定那是不是真的，不過它真的很美味。', 66384),
(303549, 'zhTW', '', '蛻皮啊！\n\n法力龍鰻每年會蛻皮好幾次。一旦攝取足夠的法力之後，牠們就會蛻下舊的甲殼，長出新的。\n\n這些舊甲殼會分解，把秘法魔法散布到森林之中，最後再重新回歸地脈流動。這是永歌森林生態系重要的一部分！\n\n現在狀況太過混亂，干擾了法力自然的流動，我們遠行者必須介入。', 66384),
(303541, 'zhTW', '', '法力龍鰻的密集度比我預計的還要高。\n\n不知道是不是因為光綻影響了牠們的遷徙模式？幸好我們來了。牠們可能比平常更需要幫手。', 66384),
(303539, 'zhTW', '', '希望可憐的泰明在南塔也跟我們一樣好運。', 66384),
(303538, 'zhTW', '', '不知道瓦薩林忙完了沒？你應該去北塔看看狀況。', 66384),
(303537, 'zhTW', '', '我覺得我們的努力真的算是有成果！', 66384),
(303532, 'zhTW', '希望可憐的泰明在南塔的狀況還好。', '', 66384),
(303530, 'zhTW', '阿斯特雷應該用得上幫手。我在這忙的同時，你到中央塔看看吧。', '', 66384),
(303529, 'zhTW', '這成果算是相當不錯！', '', 66384),
(303523, 'zhTW', '已經在坑洞看過你戰鬥了。你上次打得很漂亮。\n\n但怨鬥坑洞是個危險的地方！可別被殺掉了，$p！\n\n所以莫塔才待在安全的地方。', '', 66384),
(303515, 'zhTW', '你大概會死，但莫塔會為你加油。或許就不會死了！', '', 66384),
(303514, 'zhTW', '很高興見到$p。會去怨鬥坑洞看你戰鬥的。', '', 66384),
(303505, 'zhTW', '我打算寫出關於家人的歌。在我心中，這首歌會蘊含我母親的旋律，還有她在我們小時候照顧我們時的期望。\n\n然後還要包括晚年生活的旋律，也就是我反過來照顧她的那段時候。在這條路上，我思考著我的歌，也想起了我們生命中的點點滴滴。', '', 66384),
(303504, 'zhTW', '我們影松人數太少，無法參戰。我們把精力都用在生存上。', '', 66384),
(303503, 'zhTW', '我打算寫一首關於野性的歌。它必須要有壯闊的音調，但也要呈現出缺乏控制的興奮感。\n\n它將擁抱前路，還有沿途扣人心弦的事件。', '', 66384),
(303502, 'zhTW', '這些森林裡處處充滿危險。別離開道路。', '', 66384),
(303499, 'zhTW', '真是個好名字。', '', 66384),
(303495, 'zhTW', '大家都很驚訝$p打敗發光守衛。\n\n發光守衛從來沒輸過。\n\n直到$p訓練了一支隊伍。\n\n然後就輸了。', '', 66384),
(303494, 'zhTW', '你需要藥水，還是你想學怎麼自己調配？', '你需要藥水，還是你想學怎麼自己調配？', 66384),
(303493, 'zhTW', '請別在意這團亂，$n。\n\n讓尖塔恢復為防禦營地的努力…效果並不理想。\n\n不過，我們會繼續嘗試的。', '', 66384),
(303492, 'zhTW', '你在尋找樹根和孢子的故事嗎？', '你在尋找樹根和孢子的故事嗎？', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(303491, 'zhTW', '記憶固然重要，但你不能沉浸在過去。我們為了未來創作歌曲！', '', 66384),
(303489, 'zhTW', '我打算寫出關於傳承的歌。為此，我們必須回首過去…以我們或許不願意的方式。傳承既包括了我們的勝利，也包括了我們曾犯下的錯誤。\n\n當我們離開這裡時，它是否有變得比我們來時還要好？\n\n這首歌大概會是這樣的內容。', '', 66384),
(303485, 'zhTW', '我打算寫出關於悲傷的歌。並非是沉浸於悲傷，而是留在這裡，感受超脫麻木的情感。\n\n不過，或許這是一首關於愛情的歌。因為當悲傷越強烈，就代表愛情甚至更勝一籌。', '', 66384),
(303484, 'zhTW', '我打算寫出關於山峰的歌。這首歌必須為那些陷入低潮，或覺得自己被拋棄的人帶來希望。\n\n勇氣可以催生出勝利！我是來這裡找靈感的。', '', 66384),
(303477, 'zhTW', '這些雕紋和我們的圖畫沒有太大的不同。\n來吧，把你的羽毛筆浸入墨水中，我們來把文字轉化成力量吧。', '這些雕紋和我們的圖畫沒有太大的不同。\n來吧，把你的羽毛筆浸入墨水中，我們來把文字轉化成力量吧。', 66384),
(303473, 'zhTW', '請原諒我，我現在因為近在咫尺的光綻入侵忙得焦頭爛額。\n\n要是這些該死的傀儡能正常運作，我們就能輕易構築一道防線，更好地防守這個哨站了。\n\n唉，執著於過去毫無意義。我們還是專注於當下能做的事吧。', '', 66384),
(303472, 'zhTW', '偏偏在這種時候…', '', 66384),
(303471, 'zhTW', '至少還需要再幾個小時，博學者！', '至少還需要再幾個小時，博學者！', 66384),
(303470, 'zhTW', '魔像的修理工作進展如何？', '', 66384),
(303469, 'zhTW', '解決一個特務了。很好。接下來是禁忌之雨。\n\n我們可以穿過這裡進去。', '', 66384),
(303460, 'zhTW', '<一塊嚴重腐蝕的格柵遮住了一間漆黑牢房的入口。\n\n你沒辦法看到底下潛伏著什麼，但你能聽到其中有動靜。鎖鏈的鏗鏘聲和濕潤的腳步聲從黑暗中迴盪而來。\n\n一個飢餓的聲音從底下的某處傳來。>\n\n吃…肉…', '<一塊嚴重腐蝕的格柵遮住了一間漆黑牢房的入口。\n\n你沒辦法看到底下潛伏著什麼。\n\n一個飢餓且微弱的聲音從底下的某處傳來。>\n\n吃…肉…', 66384),
(303459, 'zhTW', '我們影松的族人遍布這片土地。包括最高聳的山巔！', '', 66384),
(303458, 'zhTW', '這個山谷裡有太多同行了。我今天一首歌都沒找到。', '', 66384),
(303457, 'zhTW', '', '也許真的是。我們可以去某個有趣的地方…', 66384),
(303456, 'zhTW', '泰莎，關鍵不在於終點。', '', 66384),
(303455, 'zhTW', '', '父親，這趟路好長。大海好無聊。', 66384),
(303454, 'zhTW', '好啦，好啦。我在處理了！', '', 66384),
(303453, 'zhTW', '', '上次是我點火的。這次輪到你了。', 66384),
(303449, 'zhTW', '', '我們到了嗎？', 66384),
(303448, 'zhTW', '父親說這是個神聖的地方。我們應該保持安靜！', '', 66384),
(303446, 'zhTW', '影松沒有固定的家。我們會在旅行的途中建立家園。', '', 66384),
(303443, 'zhTW', '', '遠行者之所以存在，是為了保護永歌森林不受任何威脅，無論程度大小。小的威脅不會因為巨大威脅存在就消失。\n\n雖然泰明對我們行事之道的想法有點太天真，但我願意冒險選擇泰明，就是因為他了解我們的存在理由。', 66384),
(303437, 'zhTW', '$p幫圖圖回到隊伍。\n\n謝謝你說服圖圖，就算輸，也還是$p的朋友。\n\n我們怨鬥坑洞見！', '', 66384),
(303436, 'zhTW', '布拉寇原本害怕孢子滑翔者。$p幫助布拉寇嘗試。現在布拉寇可以跟牠們戰鬥了！', '', 66384),
(303431, 'zhTW', '吉尼原本害怕讓隊伍失望，但是和$p訓練。變得更勇敢了！', '', 66384),
(303428, 'zhTW', '要是我們輸了，我們就是一起訓練的朋友！', '', 66384),
(303427, 'zhTW', '如果我們贏了，布拉寇跟圖圖還是朋友！', '', 66384),
(303426, 'zhTW', '必須先變得更濕一點。', '', 66384),
(303420, 'zhTW', '怨鬥坑洞好可怕。池子溫暖又安全。', '', 66384),
(303419, 'zhTW', '$p？為什麼在這裡？圖圖退出隊伍了。', '', 66384),
(303415, 'zhTW', '柏特斯不覺得會贏。\n\n沒有惡意。\n\n但是不能從坑洞逃跑，隊伍卻逃跑了。\n\n所以$p輸了。', '', 66384),
(303414, 'zhTW', '希望你可以幫真菌隊尋找新的吹箭。', '', 66384),
(303413, 'zhTW', '原本是最棒的隊伍名稱。', '', 66384),
(303412, 'zhTW', '希望你可以幫蓬衛尋找新的吹箭。', '', 66384),
(303411, 'zhTW', '希望你可以幫孢誓尋找新的吹箭。', '', 66384),
(303375, 'zhTW', '是我的錯，隊長！我剛剛在向$n介紹圖書館，但一如往常又被故事害得分心了。', '', 66384),
(303368, 'zhTW', '', '我怎麼了？我還以為這很明顯。我已經死了。\n\n無數的遠行者在與叛徒王子的戰爭中喪命。接下來的幾年間，更多人為了保衛我們所剩無幾的家園，在對抗天譴軍團殘黨的戰鬥中逝去。有些人能光榮殞命。有些倒沒這麼幸運。\n\n塔蘭卓曾經是位博學者。但她著力於學習更為褻瀆的技術，用來減輕倖存者的痛苦。', 66384),
(303364, 'zhTW', '', '噢？冒險者竟然跟卑微的女妖說話。難怪塔蘭卓這麼喜歡你。', 66384),
(303350, 'zhTW', '我們會一起搞定這遊俠的問題！', '', 66384),
(303346, 'zhTW', '<菲力克的多顆頭正在與自己進行由吼叫、呼嚕聲和喉音組成的有趣對話。\n\n之後這頭蘭花多頭樹妖注意到你的存在。菲力克的三顆頭流著口水，吐出舌頭。不知道牠是很高興看到你，還是只是很餓。>', '<菲力克的多顆頭正在與自己進行由吼叫、呼嚕聲和喉音組成的有趣對話。\n\n之後這頭蘭花多頭樹妖注意到你的存在。菲力克的三顆頭流著口水，吐出舌頭。不知道牠是很高興看到你，還是只是很餓。>', 66384),
(303342, 'zhTW', '<蘭花多頭樹妖正在打鼾。牠看起來更圓滾滾、更豐滿，就多頭樹妖的基準來看也是。托姆哼了一口氣，抬起一顆頭。牠聞了聞你周圍的空氣，之後又睡起回籠覺了。>', '<蘭花多頭樹妖正在打鼾。牠看起來更圓滾滾、更豐滿，就多頭樹妖的基準來看也是。托姆哼了一口氣，抬起一顆頭。牠聞了聞你周圍的空氣，之後又睡起回籠覺了。>', 66384),
(303341, 'zhTW', '', '那封信並不是空白的…其中有一張地圖，從路線看來可以直接進入祖阿曼。', 66384),
(303339, 'zhTW', '<你一靠近，牠的三顆頭便用看著獵物的眼神盯著你看。躁躁發出嘶嘶聲和哼聲。\n\n這頭野獸對突如其來的造訪作何感想不得而知。>', '<你一靠近，牠的三顆頭便用看著獵物的眼神盯著你看。躁躁發出嘶嘶聲和哼聲。\n\n這頭野獸對突如其來的造訪作何感想不得而知。>', 66384),
(303336, 'zhTW', '<蘭花多頭樹妖認出了你。她站直身軀，好幾顆頭朝下看著你。中間的頭聞了聞你周圍的空氣，然後輕推你的肩膀。>', '<蘭花多頭樹妖認出了你。她站直身軀，好幾顆頭朝下看著你。中間的頭聞了聞你周圍的空氣，然後輕推你的肩膀。>', 66384),
(303335, 'zhTW', '當然了！\n\n我的工作十分重要且…非常有趣…那就是確保適量的秘法水晶能夠運送到每個符石的後勤作業。\n\n不過，由於光綻對各個地點的猛烈攻勢，水晶存量已經告急了。儘管情況到了這種地步，那些天殺的博學者…\n\n<特勒捏了捏鼻子並皺起眉頭，然後才鎮定下來。>\n\n請無視我求助的哭喊。這只是我應對工作壓力的方式。', '', 66384),
(303334, 'zhTW', '不行…連結正在崩解！', '', 66384),
(303333, 'zhTW', '等等，不對，那個連結…', '', 66384),
(303332, 'zhTW', '', '這條項鍊…打我從夢魘中喚醒…但虛無依舊從其中進行折磨。你和我們在一起不安全！', 66384),
(303329, 'zhTW', '你看得到我嗎？魔法好像…', '', 66384),
(303327, 'zhTW', '符石水晶的補給偏偏要挑在這個時候出問題！那些白癡博學者到底在搞什麼鬼？\n\n而且更不用說，最後還是特勒要扛所有責任…\n\n哦！抱歉。你什麼時候開始在那裡的？', '', 66384),
(303326, 'zhTW', '維蘭…當我們取回你的項鍊時，我就知道是你。來吧…', '', 66384),
(303324, 'zhTW', '', '小心點。那東西很稀有，而且可燃性高。不過燒起來的顏色還挺好看的。', 66384),
(303323, 'zhTW', '奈塔陷入沉思。', '奈塔陷入沉思。', 66384),
(303322, 'zhTW', '現在幼芽全都沒了，一下子變得好安靜。我在考慮要不要領養一隻林地爬行者。', '現在幼芽全都沒了，一下子變得好安靜。我在考慮要不要領養一隻林地爬行者。', 66384),
(303321, 'zhTW', '拜託了，請確保我的幼芽得到良好的保護。', '拜託了，請確保我的幼芽得到良好的保護。', 66384),
(303320, 'zhTW', '注意別在密閉空間打開。那些煙霧會喚醒死者。', '', 66384),
(303318, 'zhTW', '圖圖小時候總是最後被選上。\n\n謝謝你選圖圖。\n\n圖圖會在坑洞中向$p證明自己是正確的選擇。', '', 66384),
(303317, 'zhTW', '吉尼希望我們在坑洞拿下好成績！\n\n坑洞很危險。很多厲害的蘑菇人。\n\n會離$p近一點的。', '', 66384),
(303315, 'zhTW', '我的幼芽怎麼樣了？牠們還好嗎？', '我的幼芽怎麼樣了？牠們還好嗎？', 66384),
(303313, 'zhTW', '布拉寇很期待能進入怨鬥坑洞！\n\n會保護$p、吉尼和圖圖。', '', 66384),
(303312, 'zhTW', '他們或許從影衛叛離，但虛無仍在這些以太族體內流動。\n\n至於維蘭…她甚至看都不看我一眼…', '', 66384),
(303311, 'zhTW', '我由衷地感謝你。', '', 66384),
(303310, 'zhTW', '你的勇氣與堅毅又一次維護了永歌森林的安全。', '', 66384),
(303309, 'zhTW', '我說對的名字：蓬衛。你們兩個卻說其他名字！', '', 66384),
(303308, 'zhTW', '$p，我說…我們需要幫忙。大家都想要不一樣的名字！', '', 66384),
(303307, 'zhTW', '你們都說錯名字了。', '', 66384),
(303306, 'zhTW', '等等，什麼？', '', 66384),
(303282, 'zhTW', '老實說，你知道自己在做什麼嗎？或者你只是隨便使用工具，然後希望老天保佑？', '', 66384),
(303280, 'zhTW', '', '太驚人了！不管你做了什麼，似乎都很有用。這個奇異點應該會暫時保持穩定。\n\n幸好你有挺身而出。如果萊希卡斯使用那些工具的話，我們應該也不會安然在這裡說話了。', 66384),
(303279, 'zhTW', '我必須承認，比起第一次看到它時，它似乎變得更…活躍。也許是該有點恐慌。', '', 66384),
(303278, 'zhTW', '', '這個奇異點已經開始瓦解了。但在崩解之前我們都不會知道。我可以下令撤離，但是…\n\n<梅拉瞇起眼睛，默默清點刃多雷的部隊。>\n\n不行，這樣拖太久了。我們的部隊還是會被爆炸波及。我、你、萊希卡斯…我們現在必須先處理這一個。', 66384),
(303277, 'zhTW', '早該知道，我不可能不被梅拉發現就偷溜。在我確認狀況之前，我不想讓任何人擔心，但我認為，堡壘下層有另一個不穩定的奇異點。', '', 66384),
(303266, 'zhTW', '', '萊希卡斯，你要去哪裡？', 66384),
(303265, 'zhTW', '我們會穿過戰壕，伺機攻擊目標，再從下方襲擊堡壘。', '', 66384),
(303264, 'zhTW', '時機正好。我在襲擊之間進行了探查，但我們該擔心的不只有奇異點而已。我想你不介意深入敵陣吧？\n\n反正這個哨站已經夠危險了。梅拉也許很樂意跟敵人正面對決，不過，我只想透過瞄準鏡看到他們。', '', 66384),
(303263, 'zhTW', '', '萊希卡斯…繼續偵察。不過，下次你發現危險的東西，麻煩立刻告訴我。', 66384),
(303262, 'zhTW', '', '我們歡迎你協助防守奇異點錨，$p。', 66384),
(303246, 'zhTW', '', '只是暫時的。堡壘上層還有奇異點。', 66384),
(303245, 'zhTW', '它似乎…很穩定？', '', 66384),
(303242, 'zhTW', '菇傘衝擊會贏的，因為大家都在訓練。\n\n另外，還會給建議。\n\n互相提醒「躲開劍！」和「用劍攻擊！」\n\n把訓練和建議結合。', '', 66384),
(303241, 'zhTW', '別來煩我。必須專注。\n\n要大喊建議。\n\n不大喊，要怎麼進步！', '', 66384),
(303231, 'zhTW', '維蘭的情況恐怕不容樂觀…她一定是在影衛手中。\n\n不過，說不定還有一絲希望…', '', 66384),
(303230, 'zhTW', '新盾牌打不壞！\n\n已經試過好多次了。\n\n有足夠的盾牌後，菇傘衝擊就贏定了。', '', 66384),
(303200, 'zhTW', '腐沼是孢子風暴的一員，不會逃跑的。\n\n而且，腐沼有柵欄。\n\n$r，真是笨問題。', '', 66384),
(303198, 'zhTW', '看見腐沼了嗎？\n\n等腐沼準備好，孢子風暴就會打敗所有人。\n\n就算是發光守衛也毫無勝算。\n\n現在，我們教它戰鬥。把它養大。\n\n然後…就是在怨鬥坑洞勝利。\n\n沒人能阻擋腐沼。', '', 66384),
(303196, 'zhTW', '等我們完成吹箭筒，蘑菇部隊就會在怨鬥坑洞百戰百勝。\n\n射程更遠。\n\n彈道更直。\n\n吹箭更多。\n\n只有贏的可能。', '', 66384),
(303185, 'zhTW', '出發！', '', 66384),
(303184, 'zhTW', '聽我號令！', '', 66384),
(303183, 'zhTW', '你。', '', 66384),
(303182, 'zhTW', '而現在我總算是找到了…', '', 66384),
(303181, 'zhTW', '過了這麼多年…', '', 66384),
(303180, 'zhTW', '我的心絕對不會受到黑暗的影響…', '', 66384),
(303179, 'zhTW', '那是不可能的。', '', 66384),
(303178, 'zhTW', '', '就像我一樣。', 66384),
(303177, 'zhTW', '', '心灰意冷。', 66384),
(303176, 'zhTW', '', '我擔心你來到這裡、和怪物戰鬥，會精疲力盡。', 66384),
(303175, 'zhTW', '母親，我…', '', 66384),
(303174, 'zhTW', '', '你現在的模樣，真讓我驕傲。', 66384),
(303173, 'zhTW', '', '聽我說…', 66384),
(303172, 'zhTW', '', '你真是個奇蹟，阿拉特。', 66384),
(303171, 'zhTW', '我就知道會成功。', '', 66384),
(303170, 'zhTW', '我會信守承諾的，凡人。', '', 66384),
(303169, 'zhTW', '該換你實現諾言…', '', 66384),
(303168, 'zhTW', '戴西蒙斯，我們破壞水晶塔網路了。', '', 66384),
(303144, 'zhTW', '我沒辦法帶她回來，但我們或許可以設置某種信標，讓她找到我們的位置。', '', 66384),
(303143, 'zhTW', '抱歉。最好的毒藥只能給蘑菇部隊。\n\n為了在坑洞取勝。\n\n不能分享。也不能賣你。', '', 66384),
(303142, 'zhTW', '$n，謝謝你為我做的一切。願你的狩獵永遠對你有利。', '$n，謝謝你為我做的一切。願你的狩獵永遠對你有利。', 66384),
(303141, 'zhTW', '挺身展開狩獵吧，卡達尼科坦。願女神在你未來的狩獵中指引你。', '挺身展開狩獵吧，卡達尼科坦。願女神在你未來的狩獵中指引你。', 66384),
(303140, 'zhTW', '科坦，你的使命感、熱忱以及毅力讓你走到今天的位置。', '科坦，你的使命感、熱忱以及毅力讓你走到今天的位置。', 66384),
(303139, 'zhTW', '$n，你現在是卡達尼的一員了。願女神在你未來的狩獵中指引你。', '$n，你現在是卡達尼的一員了。願女神在你未來的狩獵中指引你。', 66384),
(303134, 'zhTW', '', '$n，你有空的時候盡快到那裡和我們碰面。', 66384),
(303130, 'zhTW', '', '那魯想招募伊利丹來對抗虛無？真有意思。', 66384),
(303127, 'zhTW', '', '好極了。試試解毒劑，確認一下是否有效。', 66384),
(303122, 'zhTW', '我對你感激不盡，$n。如果你在那裡，我相信奧斯崔就不會跟你的族人開戰。', '', 66384),
(303120, 'zhTW', '相信我，我希望我是錯的，但我覺得我們沒這麼幸運。帶路吧。', '', 66384),
(303119, 'zhTW', '', '動身吧。你的直覺最好別浪費我們的時間。', 66384),
(303118, 'zhTW', '卡達尼是一支精英獵人團體。在對待狩獵和獵物方面，他們力求完美。雖然人數不多，卻在我們族人的心中有很高的名聲，在其之上的只有蘇卡…儘管那可能是惡名，這取決於你如何看待他們。\n\n只有最頂尖的卡達尼可以成為他人的導師，而這樣的機會在數個狩獵季節的循環中只會發生一次。對哈拉希爾的所有獵人來說，卡達尼就是他們畢生追求的目標。', '卡達尼是一支精英獵人團體。在對待狩獵和獵物方面，他們力求完美。雖然人數不多，卻在我們族人的心中有很高的名聲，在其之上的只有蘇卡…儘管那可能是惡名，這取決於你如何看待他們。\n\n只有最頂尖的卡達尼可以成為他人的導師，而這樣的機會在數個狩獵季節的循環中只會發生一次。對哈拉希爾的所有獵人來說，卡達尼就是他們畢生追求的目標。', 66384),
(303116, 'zhTW', '是誰在山脊上偷偷摸摸？你別想妨礙我復仇。', '', 66384),
(303114, 'zhTW', '我得說，幾小時前，它還沒這麼大。', '', 66384),
(303113, 'zhTW', '', '你看到這個，然後不打算回報？', 66384),
(303108, 'zhTW', '', '如果有危險，你就先告訴我。你可不能因為「直覺」就怠忽職守。', 66384),
(303106, 'zhTW', '我認為最好避免陷入恐慌。', '', 66384),
(303056, 'zhTW', '我不會以科坦的身分回去找阿卡齊長老，而是作為卡達尼科坦。', '我不會以科坦的身分回去找阿卡齊長老，而是作為卡達尼科坦。', 66384),
(303052, 'zhTW', '是時候證明我能成為卡達尼了。', '是時候證明我能成為卡達尼了。', 66384),
(303050, 'zhTW', '<這顆巨大的赤紅水晶摸起來十分溫暖。你感受到細微的能量脈動。它徘徊在你面前，充滿期待與渴望。>', '<這顆巨大的赤紅水晶摸起來十分溫暖。你感受到細微的能量脈動。它徘徊在你面前，充滿期待與渴望。>', 66384),
(303048, 'zhTW', '拉杜尼是棲息在哈拉希爾外圍最危險的野獸之一。\n\n我不怕牠，反倒是敬畏。\n\n<科坦看著你點點頭。>\n\n$n，等你準備好就說吧。身為導師，必須由你來宣布狩獵開始，我再加入其中。', '拉杜尼是棲息在哈拉希爾外圍最危險的野獸之一。\n\n我不怕牠，反倒是敬畏。\n\n<科坦看著你點點頭。>\n\n$n，等你準備好就說吧。身為導師，必須由你來宣布狩獵開始，我再加入其中。', 66384),
(303047, 'zhTW', '', '暮光之刃會為他們葬送的生命付出慘痛的代價。', 66384),
(303040, 'zhTW', '', '但…出手別太重了。我們還得問出聖騎士們在哪裡。', 66384),
(303039, 'zhTW', '', '告訴我們他們在哪裡，教徒渣滓！否則後果自負！', 66384),
(303035, 'zhTW', '', '<崔亞尼斯一邊看著某個在空中移動的東西，一邊啜飲一口飲料。>\n\n我早晚…會逮到你。', 66384),
(303022, 'zhTW', '別動，讓牠們好好料理你。', '', 66384),
(303021, 'zhTW', '看看牠們因為你的疼痛興奮不已！', '', 66384),
(303020, 'zhTW', '我的寵物今天還真有活力。', '', 66384),
(303011, 'zhTW', '你永遠無法離開這個地方。', '', 66384),
(303004, 'zhTW', '來，讓我好好大吃一頓。', '', 66384),
(303003, 'zhTW', '我是預示者，而你是一頓盛宴。', '', 66384),
(302997, 'zhTW', '我聽說過關於拉杜尼的故事。無論如何，我都會心懷榮耀接受這項任務！', '我聽說過關於拉杜尼的故事。無論如何，我都會心懷榮耀接受這項任務！', 66384),
(302996, 'zhTW', '你必須去狩獵強大的拉杜尼，當試煉完成之時，你就正式成為一名卡達尼了。', '你必須去狩獵強大的拉杜尼，當試煉完成之時，你就正式成為一名卡達尼了。', 66384),
(302995, 'zhTW', '科坦，卡達尼永遠不會懼怕自己的獵物。你今天的獵物便是令人生畏的存在。', '科坦，卡達尼永遠不會懼怕自己的獵物。你今天的獵物便是令人生畏的存在。', 66384),
(302963, 'zhTW', '', '拉克圖被毀了。你拯救的人們活了下來，那些不幸喪生的也得以安息。這個洞穴能暫時回歸寧靜了。', 66384),
(302960, 'zhTW', '', '很好，割下牠的皮吧。', 66384),
(302959, 'zhTW', '', '這頭野獸還是有牠的價值。', 66384),
(302958, 'zhTW', '', '為野獸剝皮的方法不只一種。', 66384),
(302957, 'zhTW', '', '來自大地的珍寶。', 66384),
(302955, 'zhTW', '', '自然的恩惠，真有用。', 66384),
(302954, 'zhTW', '', '需要黃金嗎？…我還有必要問嗎？', 66384),
(302953, 'zhTW', '', '那裡有黃金。', 66384),
(302952, 'zhTW', '', '我們現在有條魚了。', 66384),
(302939, 'zhTW', '', '我們繼續吧。', 66384),
(302938, 'zhTW', '', '還有很多要做的事。', 66384),
(302937, 'zhTW', '', '謝謝你。', 66384),
(302936, 'zhTW', '', '我不行了…對不起…', 66384),
(302935, 'zhTW', '', '我撐不住了…', 66384),
(302934, 'zhTW', '', '該死！', 66384),
(302932, 'zhTW', '', '我們不要浪費時間了。', 66384),
(302929, 'zhTW', '', '現在你可以從容應對了。', 66384),
(302926, 'zhTW', '', '看來在作白日夢啊。', 66384),
(302925, 'zhTW', '', '你還清醒著嗎？', 66384),
(302924, 'zhTW', '', '我現在能幫更多忙了。', 66384),
(302923, 'zhTW', '', '這是我應得的。', 66384),
(302922, 'zhTW', '', '這樣好多了。', 66384),
(302921, 'zhTW', '', '稍候。', 66384),
(302917, 'zhTW', '現在加入孢子蝙蝠的尾巴，同時科坦用鞭笞者的藤蔓把它們全部綁在一起。', '現在加入孢子蝙蝠的尾巴，同時科坦用鞭笞者的藤蔓把它們全部綁在一起。', 66384),
(302915, 'zhTW', '', '動作快。', 66384),
(302913, 'zhTW', '', '抓不到我們。', 66384),
(302911, 'zhTW', '', '快到無法反擊。', 66384),
(302909, 'zhTW', '', '該睡覺了。', 66384),
(302908, 'zhTW', '', '他們連自己怎麼死的都不知道。', 66384),
(302907, 'zhTW', '', '我會把敵人處理好。', 66384),
(302906, 'zhTW', '', '想都別想。', 66384),
(302905, 'zhTW', '', '閉嘴吧。', 66384),
(302904, 'zhTW', '', '安靜。', 66384),
(302901, 'zhTW', '', '帷幕守護你。', 66384),
(302900, 'zhTW', '', '陰影保護你。', 66384),
(302899, 'zhTW', '', '黑暗護住你。', 66384),
(302898, 'zhTW', '', '別浪費了。', 66384),
(302897, 'zhTW', '', '獲得力量吧。', 66384),
(302896, 'zhTW', '', '勇敢點。', 66384),
(302894, 'zhTW', '', '我來驅散這個魔法。', 66384),
(302892, 'zhTW', '', '我驅散它了。', 66384),
(302891, 'zhTW', '', '嘖嘖，真是麻煩的魔法。', 66384),
(302890, 'zhTW', '', '我會止住流血。', 66384),
(302889, 'zhTW', '', '振作點。', 66384),
(302888, 'zhTW', '', '待在這裡恢復吧。', 66384),
(302887, 'zhTW', '', '你的痛苦是我的快樂。', 66384),
(302886, 'zhTW', '', '你的命是我的了。', 66384),
(302885, 'zhTW', '', '我收下了。', 66384),
(302881, 'zhTW', '', '接住。', 66384),
(302880, 'zhTW', '', '吃我一記。', 66384),
(302879, 'zhTW', '', '深呼吸。', 66384),
(302875, 'zhTW', '真是優秀的武器。確實是件傑作。', '真是優秀的武器。確實是件傑作。', 66384),
(302873, 'zhTW', '', '你失手了。', 66384),
(302872, 'zhTW', '', '下次再努力些。', 66384),
(302871, 'zhTW', '', '你就只有這點能耐嗎？', 66384),
(302869, 'zhTW', '', '下次得快些。', 66384),
(302868, 'zhTW', '', '還不夠快。', 66384),
(302867, 'zhTW', '', '我鎖定你了。', 66384),
(302866, 'zhTW', '', '就是現在，攻擊！', 66384),
(302865, 'zhTW', '成為卡達尼不只是一種象徵或號召，而是所有獵人的典範。哈拉希爾重視狩獵勝過其他村莊。\n\n一些最著名的蘇卡便是來自哈拉希爾。', '成為卡達尼不只是一種象徵或號召，而是所有獵人的典範。哈拉希爾重視狩獵勝過其他部族。\n\n一些最著名的蘇卡便是來自哈拉希爾。', 66384),
(302864, 'zhTW', '', '我會好好享受這一擊。', 66384),
(302862, 'zhTW', '', '別想發現我。', 66384),
(302861, 'zhTW', '他們派了泣歌和其他人到影衛崗哨。只有恐懼和虛無在等著他們。', '他們派了泣歌和其他人到影衛崗哨。只有恐懼和虛無在等著他們。', 66384),
(302859, 'zhTW', '', '我們必須讓奧姆里克知道。', 66384),
(302858, 'zhTW', '', '我的終極型態…在此完成！', 66384),
(302853, 'zhTW', '這把卡達尼武器絕對是傑作。就算是阿卡齊肯定也無法反駁。', '這把卡達尼武器絕對是傑作。就算是阿卡齊肯定也無法反駁。', 66384),
(302850, 'zhTW', '我們先從$n加入骨頭開始，接著科坦再加入尖牙。', '我們先從$n加入骨頭開始，接著科坦再加入尖牙。', 66384),
(302849, 'zhTW', '這條項鍊很特別嗎？上面有附魔嗎？', '', 66384),
(302848, 'zhTW', '她只不過是第一個…', '她只不過是第一個…', 66384),
(302847, 'zhTW', '他們的價值無可估量。', '他們的價值無可估量。', 66384),
(302846, 'zhTW', '泣歌是你的首領嗎？', '', 66384),
(302831, 'zhTW', '不，我不知道你是誰。不，我們不接受預約。沒有，例外。\n\n和其他人一樣乖乖排隊，不然就離開。畢竟，這是城裡最熱門的早午餐店。\n\n你也不想因為沒辦法忍受要站幾個小時就錯過，對吧？', '不，我不知道你是誰。不，我們不接受預約。沒有，例外。\n\n和其他人一樣乖乖排隊，不然就離開。畢竟，這是城裡最熱門的早午餐店。\n\n你也不想因為沒辦法忍受要站幾個小時就錯過，對吧？', 66384),
(302830, 'zhTW', '孩子是我們的未來。\n\n現在，我必須變出更多蛋糕和咖啡，我們才能保住這樣的未來。\n\n<泰蘭的臉上浮現惆悵的神情。>\n\n我記得我年輕的時候，學校沒這麼痛苦啊…', '', 66384),
(302829, 'zhTW', '我才沒有因為壓力而暴飲暴食！就算是又怎樣？！就算我被當掉又怎樣…啊啊啊…啊…奶油加量的小蛋糕，我的最愛…', '我才沒有因為壓力而暴飲暴食！就算是又怎樣？！就算我被當掉又怎樣…啊啊啊…啊…奶油加量的小蛋糕，我的最愛…', 66384),
(302825, 'zhTW', '愛雅特，這把武器真是太美了。$n，身為我的導師，你必須把長矛帶去給阿卡齊長老。我會在那裡等你。', '愛雅特，這把武器真是太美了。$n，身為我的導師，你必須把長矛帶去給阿卡齊長老。我會在那裡等你。', 66384),
(302803, 'zhTW', '', '我還需要收集一些材料。到前方跟我會合。', 66384),
(302800, 'zhTW', '這個審問者閃登一定知道更多詳情。', '', 66384),
(302799, 'zhTW', '', '你的虛無靈魂是我的了。', 66384),
(302798, 'zhTW', '我正在試著說服我的朋友，把所有的薪水都花在文具、筆刷和顏料上也沒有關係。\n\n<這位藝術家強忍著情緒，臉上掛著平靜的微笑，雙眼卻透露出瘋狂。>\n\n沒事的。這都是值得的。我們會畫很多畫。', '我正在試著說服我的朋友，把所有的薪水都花在文具、筆刷和顏料上也沒有關係。\n\n<這位藝術家強忍著情緒，臉上掛著平靜的微笑，雙眼卻透露出瘋狂。>\n\n沒事的。這都是值得的。我們會畫很多畫。', 66384),
(302797, 'zhTW', '博學者血誓和他的賓客在下面等你。', '博學者血誓和他的賓客在下面等你。', 66384),
(302793, 'zhTW', '許多叛亂者都被帶去其他地方了。', '', 66384),
(302790, 'zhTW', '但現在他們不再受到控制，並由一個名叫泣歌的以太族帶領。', '', 66384),
(302789, 'zhTW', '影衛當中有一群叛亂者。他們全部都曾在法力熔爐歐美加受到虛無的控制。', '', 66384),
(302786, 'zhTW', '這裡的影衛陷入了恐慌。\n\n你有找到什麼有用的東西嗎？', '', 66384),
(302785, 'zhTW', '這裡的多曼納爾似乎很擅長任意形塑虛無。也許這把鑿子是他們的其中一個造物？\n\n對於透過虛無改變自身的本質和發現自我，刃多雷並不陌生。其他生物有同樣的感受又有什麼好奇怪的？對他們來說，像這把鑿子這樣的工具，就跟梳子對我們一樣平凡無奇。\n\n這絕對不是為我們一族製作的。它現在已經徹底失效，跟石頭沒兩樣。\n\n但我的幽影為什麼知道要帶我來這裡？虛無會對虛無召喚嗎？我們還有很多事需要釐清。', '', 66384),
(302780, 'zhTW', '', '我會免費治療他們，單純出於善意。算是對未來的一種投資吧。\n\n總有一天，他們會欠我人情！', 66384),
(302779, 'zhTW', '要迎接毀滅的是你，小不點。還有你注定消亡的同伴。', '', 66384),
(302777, 'zhTW', '', '那就準備好失望吧，虛無怪物。迎接你的毀滅。', 66384),
(302773, 'zhTW', '我能成為真正的阿曼尼戰士了！還有你也是，對吧？', '', 66384),
(302770, 'zhTW', '', '我來掩護你！', 66384),
(302769, 'zhTW', '', '躲到我後面！', 66384),
(302768, 'zhTW', '愛雅特上下打量著你，隨後認可地點了點頭。', '愛雅特上下打量著你，隨後認可地點了點頭。', 66384),
(302767, 'zhTW', '$n是我的導師。他來了。', '$n是我的導師。他來了。', 66384),
(302766, 'zhTW', '阿卡齊跟我說過關於你的導師的事，但是他不在場，我就無法鍛造武器。', '阿卡齊跟我說過關於你的導師的事，但是他不在場，我就無法鍛造武器。', 66384),
(302763, 'zhTW', '或許一根矛插在肚子上幾年會讓你學到教訓。', '', 66384),
(302762, 'zhTW', '', '$n，我們虛無之尖見。', 66384),
(302753, 'zhTW', '我要開始狩獵了。願女神保佑，我們在獵場上再會吧。', '我要開始狩獵了。願女神保佑，我們在獵場上再會吧。', 66384),
(302752, 'zhTW', '創造這個幽影之後我感到十分恐懼。當我在虛無中尋求指引時，還想把它摧毀掉。\n\n但回應…並非來自虛無。而是從這個幽影來的。這也是為什麼聲音會如此熟悉。那根本就是我的聲音。\n\n雖然它處在痛苦之中，但還是想嘗試幫助我。', '', 66384),
(302745, 'zhTW', '你太弱。去死吧！', '你太弱。去死吧！', 66384),
(302744, 'zhTW', '我是最強的。我會殺光所有挑戰者！', '我是最強的。我會殺光所有挑戰者！', 66384),
(302741, 'zhTW', '你找到適合做成武器的骨頭了嗎？\n\n別擔心，$n。沒有任何野獸的屍體會被白白浪費。我們的採集者會把所有獵物製成材料和食物。', '你找到適合做成武器的骨頭了嗎？\n\n別擔心，$n。沒有任何野獸的屍體會被白白浪費。我們的採集者會把所有獵物製成材料和食物。', 66384),
(302740, 'zhTW', '又來偷奪牙者的寶物！', '又來偷奪牙者的寶物！', 66384),
(302738, 'zhTW', '', '我們絕不能靠犧牲無辜來對抗虛無。\n\n戰爭不請自來地降臨於這座城市，就像當初羅德隆的狀況一樣。我沒能拯救我的族人，但我不會讓這些孩子就此喪命的。', 66384),
(302724, 'zhTW', '歡迎來到洛索瑪‧塞隆和薩莉瑟拉的莊園。', '歡迎來到洛索瑪‧塞隆和薩莉瑟拉的莊園。', 66384),
(302723, 'zhTW', '你在出手之前，應該先削弱$n，也不該在事情不如你所願的時候，像個穿山甲一樣嘰嘰叫。', '', 66384),
(302722, 'zhTW', '凱爾沃裘，懲罰你不只是因為作弊，還有手法過於拙劣。', '', 66384),
(302712, 'zhTW', '你拿到大傢伙的戰利品之後，我會幫你一把的。', '', 66384),
(302710, 'zhTW', '你拿到戰利品之後，我們就能結束試煉了。', '', 66384),
(302702, 'zhTW', '我…還不曉得當時發生了什麼事。但我得之後再煩惱。我們得去救人。', '', 66384),
(302701, 'zhTW', '我的發明能讓我不暴露行蹤，但沒有你的幫忙，我永遠找不回維蘭的項鍊。', '', 66384),
(302700, 'zhTW', '咩水輪流轉。', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(302696, 'zhTW', '等你準備好後，就來找我和阿卡齊長老。', '等你準備好後，就來找我和阿卡齊長老。', 66384),
(302694, 'zhTW', '願狩獵之靈指引你們二人。', '願狩獵之靈指引你們二人。', 66384),
(302690, 'zhTW', '我們需要一位卡達尼來指導和訓練我們的年輕獵人。這份需求不是出自傳統，而是因為我們追尋的偉大狩獵的危險。\n\n我知道你對世界上的危險並不陌生。雖然我很清楚科坦的決心和毅力，但我不太了解你。\n\n能讓我允許你指導科坦的唯一辦法，就是你必須親自成為一名名譽卡達尼。\n\n你是否願意接下這項任務，不僅是為了自己，也為了科坦的未來？要是你們之中有一人失敗，就不會再有第二次機會了。', '我們需要一位卡達尼來指導和訓練我們的年輕獵人。這份需求不是出自傳統，而是因為我們追尋的偉大狩獵的危險。\n\n我知道你對世界上的危險並不陌生。雖然我很清楚科坦的決心和毅力，但我不太了解你。\n\n能讓我允許你指導科坦的唯一辦法，就是你必須親自成為一名名譽卡達尼。\n\n你是否願意接下這項任務，不僅是為了自己，也為了科坦的未來？要是你們之中有一人失敗，就不會再有第二次機會了。', 66384),
(302688, 'zhTW', '終於，我自由了！', '', 66384),
(302683, 'zhTW', '歡迎來到哈拉希爾。你怎麼會來這裡，陌生人？', '歡迎來到哈拉希爾。你怎麼會來這裡，陌生人？', 66384),
(302681, 'zhTW', '快追它！別讓它傷害其他人。', '', 66384),
(302680, 'zhTW', '什麼？不！它應該消失才對！', '', 66384),
(302667, 'zhTW', '', '感謝你讓我的希望得以延續，$p。因為我們所做的一切，或許有一天，這些根會再度成長。', 66384),
(302666, 'zhTW', '$n，你失心瘋了嗎？！那傢伙是一隻怪物！你居然幫助它逃避聖光的制裁？\n\n我信任你，讓你指揮這麼一次。我還稱呼你為大領主。或許你根本不是我認為的那種聖騎士。', '', 66384),
(302648, 'zhTW', '<你的腦海中充滿了一道神聖水池的幻象。孩童、獵人和根莖守望者全都對你表達敬意。這真是美好的一生，或許不完美，卻令你感覺到這輩子圓滿了。一陣溫暖而輕柔的微風在你耳邊低語：「該走了。」\n\n你的親朋好友和摯愛之人帶你到聖池邊，他們將你泡入水中接受最後一次沐浴。\n\n這道幻象是循環的終結，也象徵著死亡。>', '<你的腦海中充滿了一道神聖水池的幻象。孩童、獵人和根莖守望者全都對你表達敬意。這真是美好的一生，或許不完美，卻令你感覺到這輩子圓滿了。一陣溫暖而輕柔的微風在你耳邊低語：「該走了。」\n\n你的親朋好友和摯愛之人帶你到聖池邊，他們將你泡入水中接受最後一次沐浴。\n\n這道幻象是循環的終結，也象徵著死亡。>', 66384),
(302646, 'zhTW', '<你的腦海中被雲霧籠罩，你的身體感受到衰老的痛楚。隨之而來的，是彷彿自己已經度過一生的體悟。你在清晨醒來，看著孩子玩耍，獵人從狩獵中滿載而歸，而根莖守望者則是在聊著日常瑣事。\n\n在你的上方，育所正在呼喚你的名字。在內心深處，你知道這就是生命的本質，當你回到女神身邊之後，你將獲得新生重返人間，或許是作為哈拉尼爾，也可能只是隻蝴蝶…畢竟生命就是一個巨大的謎團。>', '<你的腦海中被雲霧籠罩，你的身體感受到衰老的痛楚。隨之而來的，是彷彿自己已經度過一生的體悟。你在清晨醒來，看著孩子玩耍，獵人從狩獵中滿載而歸，而根莖守望者則是在聊著日常瑣事。\n\n在你的上方，育所正在呼喚你的名字。在內心深處，你知道這就是生命的本質，當你回到女神身邊之後，你將獲得新生重返人間，或許是作為哈拉尼爾，也可能只是隻蝴蝶…畢竟生命就是一個巨大的謎團。>', 66384),
(302644, 'zhTW', '<長老靈魂露出微笑，隨後帶著敬意微微鞠躬。她疲憊的眼睛先是看向你身後的育所，接著又回到你身上。你感覺自己需要休息。\n\n一個形狀在你的腦海中形成。它變成了附近住家裡的枕頭。>', '<長老靈魂露出微笑，隨後帶著敬意微微鞠躬。她疲憊的眼睛先是看向你身後的育所，接著又回到你身上。你感覺自己需要休息。\n\n一個形狀在你的腦海中形成。它變成了附近住家裡的枕頭。>', 66384),
(302642, 'zhTW', '<這個古老的祭壇描繪著一幅哈拉尼爾長老的壁畫。她舒適地坐在編織地毯上冥想。她的身邊圍繞著一個球體，也許是象徵著世界或女神。>', '<這個古老的祭壇描繪著一幅哈拉尼爾長老的壁畫。她舒適地坐在編織地毯上冥想。她的身邊圍繞著一個球體，也許是象徵著世界或女神。>', 66384),
(302637, 'zhTW', '走開！給我消失！', '', 66384),
(302635, 'zhTW', '我知道，相信我。我無法解釋，但那個聲音…它聽起來像是某個我應該信任的人。感覺很熟悉，好像從夢中醒來一樣。\n\n如果它能讓我擺脫這個幽影，我必須看看它能引領我到哪裡去。', '', 66384),
(302632, 'zhTW', '那個幽影是我造成的…我的錯。這裡的虛無如此純淨，如此…鮮活，而我卻如此愚蠢。我之前看過幽影：刃多雷的暗影化為實體。我以為能自己製造一個。\n\n但我錯了，失敗了。我再也無法逃離它，就像我無法逃離自己的思緒。\n\n所以我來到這裡。我向虛無尋求解決辦法，有個聲音指引我向北走。它向我保證，有個神器能幫我除掉這個失敗品。', '', 66384),
(302628, 'zhTW', '<靈魂帶著敬意對你點頭。你贏得了它的信任，對獵人來說，最高的榮耀莫過於和自己身分的延伸重聚，也就是用來快速終結獵物的工具。\n\n接著你看到一個非常重要的建築物的幻象，獵人和長老們聚集在一個神聖的水池邊。他們分享著故事和人生智慧。獵人景仰著長老，希望有一天自己也有幸能成為他們之中的一員。\n\n這道幻象象徵著人生壯闊旅程的中間點。>', '<靈魂帶著敬意對你點頭。你贏得了它的信任，對獵人來說，最高的榮耀莫過於和自己身分的延伸重聚，也就是用來快速終結獵物的工具。\n\n接著你看到一個非常重要的建築物的幻象，獵人和長老們聚集在一個神聖的水池邊。他們分享著故事和人生智慧。獵人景仰著長老，希望有一天自己也有幸能成為他們之中的一員。\n\n這道幻象象徵著人生壯闊旅程的中間點。>', 66384),
(302626, 'zhTW', '<短暫片刻間，你的腦中陷入沉寂。接著你聽見鳥兒和小動物的歌聲。有什麼東西在你的腳上爬，但你把注意力全部集中在獵物上，決心要實現一場成功的狩獵。\n\n隨後你屏住呼吸，拉動弓弦的聲音蓋過了一切雜音。你的箭矢準備好了。這箭完美命中。野獸倒地不起。你從藏身處跑出，拔出那把拿在手上沒有違和感的狩獵小刀。\n\n隨著你靠近，你發現野獸還活著，準備好嚥下最後一口氣。牠很痛苦。你靠著牠，一邊撫摸牠的鬃毛，一邊在牠耳邊低語著安慰和感謝的話語。\n\n你將小刀刺入，野獸於是死去，對你迅速給予的仁慈心懷感謝。>', '<短暫片刻間，你的腦中陷入沉寂。接著你聽見鳥兒和小動物的歌聲。有什麼東西在你的腳上爬，但你把注意力全部集中在獵物上，決心要實現一場成功的狩獵。\n\n隨後你屏住呼吸，拉動弓弦的聲音蓋過了一切雜音。你的箭矢準備好了。這箭完美命中。野獸倒地不起。你從藏身處跑出，拔出那把拿在手上沒有違和感的狩獵小刀。\n\n隨著你靠近，你發現野獸還活著，準備好嚥下最後一口氣。牠很痛苦。你靠著牠，一邊撫摸牠的鬃毛，一邊在牠耳邊低語著安慰和感謝的話語。\n\n你將小刀刺入，野獸於是死去，對你迅速給予的仁慈心懷感謝。>', 66384),
(302624, 'zhTW', '<一個成年哈拉尼爾的靈魂在你面前盤旋。他帶著敬意對你點頭。你的腦海深處形成了一個狩獵工具的意象，隨後慢慢地變成一把狩獵小刀的形狀，被遺棄在附近的瀑布中。>', '<一個成年哈拉尼爾的靈魂在你面前盤旋。他帶著敬意對你點頭。你的腦海深處形成了一個狩獵工具的意象，隨後慢慢地變成一把狩獵小刀的形狀，被遺棄在附近的瀑布中。>', 66384),
(302621, 'zhTW', '$p，你曾經感到孤單嗎？住在銀月城的時候，我一直覺得很孤單。加入刃多雷後，我以為自己終於找到歸屬。\n\n<歐林向前看了一眼潛伏的幽影。>\n\n結果孤單的感覺卻還是揮之不去。這個幽影和一切事物一樣，都是個錯誤。我為它感到惋惜。把它消除才是最好的。', '', 66384),
(302619, 'zhTW', '<靠近查看後，這個祭壇描繪的是獵人和獵物。環狀排列的畫像顯示一名獵人正在追蹤獵物，接著躲在附近準備出擊。下一張畫是獵人以勝利者的姿態站在獵物旁，隨後他帶著獵物回家，有需要的話可以重新開始這個循環。>', '<靠近查看後，這個祭壇描繪的是獵人和獵物。環狀排列的畫像顯示一名獵人正在追蹤獵物，接著躲在附近準備出擊。下一張畫是獵人以勝利者的姿態站在獵物旁，隨後他帶著獵物回家，有需要的話可以重新開始這個循環。>', 66384),
(302617, 'zhTW', '', '就在一瞬之間，我所知道的一切都…不可信了。\n\n幸好這趟旅程能讓我保持專注。', 66384),
(302614, 'zhTW', '', '祖爾賈拉可能不相信羅亞會現身，但我看得出來她心中如此希望。', 66384),
(302609, 'zhTW', '必須制定…更狡詐的計畫。', '', 66384),
(302608, 'zhTW', '哇啊，真陰險！死吧。', '', 66384),
(302607, 'zhTW', '', '怎麼可能？我早該想到的…', 66384),
(302606, 'zhTW', '圍困受傷的動物是很危險的…', '', 66384),
(302605, 'zhTW', '', '好虛弱…', 66384),
(302604, 'zhTW', '不該這樣結束！不該這樣結束！', '', 66384),
(302603, 'zhTW', '', '我經歷過更糟的處境。給我消失！', 66384),
(302602, 'zhTW', '覺得痛嗎？', '', 66384),
(302601, 'zhTW', '你膽敢挑戰我？', '', 66384),
(302600, 'zhTW', '可悲的小傢伙…你的生命屬於我！', '', 66384),
(302599, 'zhTW', '呃！被黑暗吞噬吧！', '', 66384),
(302598, 'zhTW', '頑抗的小東西…', '', 66384),
(302597, 'zhTW', '', '野蠻的小…！', 66384),
(302596, 'zhTW', '我才不會對你卑躬屈膝！', '', 66384),
(302595, 'zhTW', '在下已經對你的追殺感到無趣了。', '', 66384),
(302594, 'zhTW', '太快了！太快了！', '', 66384),
(302593, 'zhTW', '', '這樣你也能稱為狩獵？', 66384),
(302592, 'zhTW', '你是怎麼…也不重要了！', '', 66384),
(302591, 'zhTW', '', '喀嘎？！', 66384),
(302590, 'zhTW', '吼嘎！', '', 66384),
(302589, 'zhTW', '', '我不是獵物！', 66384),
(302588, 'zhTW', '什麼？！', '', 66384),
(302587, 'zhTW', '又是你？怎麼可能？', '', 66384),
(302586, 'zhTW', '', '刺客才不講求榮譽。', 66384),
(302585, 'zhTW', '', '你的力量…真令人著迷…', 66384),
(302584, 'zhTW', '虛無…會了結你…', '', 66384),
(302583, 'zhTW', '', '防禦能力只發揮了百分之七十八。這還不是最佳狀態！', 66384),
(302582, 'zhTW', '走開，你這無聊的蠢貨！', '', 66384),
(302581, 'zhTW', '', '所有烈焰都有燒完的一天…', 66384),
(302580, 'zhTW', '烈焰…熄滅了…', '', 66384),
(302572, 'zhTW', '呃…誰想得到當遠行者竟然需要做這麼多肉體勞動？', '', 66384),
(302570, 'zhTW', '', '你踩碎那些葡萄了！現在就加入希麗賣的魔法酵母，或者你可以等它花好幾年天然發酵…', 66384),
(302569, 'zhTW', '我解決掉兩個，但是又來了更多…', '我解決掉兩個，但是又來了更多…', 66384),
(302567, 'zhTW', '他們的力量太黑暗了…我沒辦法集中…', '他們的力量太黑暗了…我沒辦法集中…', 66384),
(302564, 'zhTW', '我們試著阻擋…他們的力量太強大了…', '我們試著阻擋…他們的力量太強大了…', 66384),
(302557, 'zhTW', '你希望獵物進行多激烈的掙扎？', '', 66384),
(302554, 'zhTW', '<你的腦海中充斥著一團迷霧。你現在可以透過其他人的眼睛看世界了。你是一個孩童。一個哈拉尼爾孩童。\n\n你環顧四周，看見一個遙遠的地方，還有一座山和一棵巨樹。你的族人正在收拾行李，準備好啟程。你雖感覺到焦慮，但同時也湧出了強烈的興奮之情和冒險精神。>', '<你的腦海中充斥著一團迷霧。你現在可以透過其他人的眼睛看世界了。你是一個孩童。一個哈拉尼爾孩童。\n\n你環顧四周，看見一個遙遠的地方，還有一座山和一棵巨樹。你的族人正在收拾行李，準備好啟程。你雖感覺到焦慮，但同時也湧出了強烈的興奮之情和冒險精神。>', 66384),
(302551, 'zhTW', '<一個水池的幻象在你的腦海中形成，或許背景中的成年哈拉尼爾將這裡視為聖地。\n\n你可以看到玩耍的哈拉尼爾孩童，正在追逐你剛才交給孩童靈魂的球。他們在水池邊嬉戲，直到一個成人把他們趕走。\n\n這道幻象象徵著出生以及一段生命之旅的開始。>', '<一個水池的幻象在你的腦海中形成，或許背景中的成年哈拉尼爾將這裡視為聖地。\n\n你可以看到玩耍的哈拉尼爾孩童，正在追逐你剛才交給孩童靈魂的球。他們在水池邊嬉戲，直到一個成人把他們趕走。\n\n這道幻象象徵著出生以及一段生命之旅的開始。>', 66384),
(302549, 'zhTW', '<雖然孩童靈魂沒有說話，但一股純真的感覺，還有強烈的冒險精神湧上你的心頭。\n\n你可以看到一個形狀在你的腦海中形成，隨後慢慢地變成一顆被丟在附近草叢中經歷風吹日曬的球。>', '<雖然孩童靈魂沒有說話，但一股純真的感覺，還有強烈的冒險精神湧上你的心頭。\n\n你可以看到一個形狀在你的腦海中形成，隨後慢慢地變成一顆被丟在附近草叢中經歷風吹日曬的球。>', 66384),
(302548, 'zhTW', '啊，太好了！新來的點心，正適合端上我的餐桌。現身吧，否則我會親自追殺你！', '', 66384),
(302547, 'zhTW', '這不是重點…', '', 66384),
(302546, 'zhTW', '邪教徒來得太快了！我們沒時間建立防線！', '邪教徒來得太快了！我們沒時間建立防線！', 66384),
(302545, 'zhTW', '', '是嗎？看看她的皮膚吧，奧姆里克。烙印儀式成功了。', 66384),
(302543, 'zhTW', '<這個古老的祭壇描繪著哈拉尼爾孩童玩耍的畫像。>', '<這個古老的祭壇描繪著哈拉尼爾孩童玩耍的畫像。>', 66384),
(302542, 'zhTW', '雷歐娜，你擅自跳進傳送門真是太愚蠢了。', '', 66384),
(302539, 'zhTW', '我在育所中傾聽女神的聲音。我將她告訴我的記憶銘記於心。\n\n世世代代，都有人像我這樣守護這些記憶，只將其傳承給值得之人。\n\n其中有些記憶過於危險，不該讓所有人知曉。', '', 66384),
(302522, 'zhTW', '', '我一定會救他！', 66384),
(302519, 'zhTW', '$p，聖光不只回應於我、法奧，和泰羅索斯領主，它也回應於血色十字軍，這對我來說感覺很奇怪。', '', 66384),
(302495, 'zhTW', '', '你揮舞武器。我揮舞你。', 66384),
(302494, 'zhTW', '你…殺了她…', '', 66384),
(302492, 'zhTW', '', '沒錯，眼前的就是金霧村裡的第一具釀酒缸，也是阿爾茵用來釀第一批酒的酒缸。\n\n噢，當然可以摸了。要用也是沒問題的！\n\n猜各式各樣的訪客會釀什麼樣的酒最有趣了。去摘一些葡萄，然後開始釀酒吧！', 66384),
(302490, 'zhTW', '', '她從那時候開始就釀出了成千上百種酒，但如果你真的了解她的話，就知道色澤純淨的紅酒依舊是她的最愛。', 66384),
(302489, 'zhTW', '', '把酵母加到釀酒缸裡之後，阿爾茵的第一批酒就準備好了。', 66384),
(302488, 'zhTW', '', '作為導覽的一部份，你可以向我們的雜貨商希麗購買一包魔法酵母。沒有用的話，我們一定讓你退費。', 66384),
(302487, 'zhTW', '', '發酵可以花上好幾年的時間。但我們的葡萄酒商製作了一種特殊的酵母，不但能快速有效地發酵，還不會破壞酒的品質。', 66384),
(302486, 'zhTW', '', '她接著依照傳統，用腳把葡萄踩碎，製成釀酒的混合物！', 66384),
(302485, 'zhTW', '', '她釀造出來的第一批酒，就只用了十把葡萄。', 66384),
(302484, 'zhTW', '', '旅店老闆阿爾茵是這片莊園的創始人。', 66384),
(302475, 'zhTW', '<這具大石缸是金霧村釀酒史中最珍貴，也最堅不可摧的珍寶。>', '', 66384),
(302474, 'zhTW', '<釀酒缸裡滿滿都是葡萄混合物的香氣。\n\n但除非有人加快發酵的速度，否則這只是一缸葡萄汁而已…>', '', 66384),
(302473, 'zhTW', '<釀酒缸裡裝滿了葡萄還有其他釀酒的基本材料。\n\n得有人好好踩踏那些葡萄！>', '', 66384),
(302471, 'zhTW', '<這具大石缸是金霧村釀酒史中最珍貴，也最堅不可摧的珍寶。\n\n它到現在還有人在使用。觀光客可以在石缸用腳踩葡萄，來體驗最傳統的釀酒工法！\n\n你會需要十把葡萄才能開始…>', '', 66384),
(302464, 'zhTW', '', '這可不一定！', 66384),
(302463, 'zhTW', '我什麼都不會告訴你的！', '我什麼都不會告訴你的！', 66384),
(302460, 'zhTW', '願這根蠟燭不只能為對抗天譴軍團的英雄們發光發熱，也能為那些在餘波中失去性命的受害者帶來慰藉。', '願這根蠟燭不只能為對抗天譴軍團的英雄們發光發熱，也能為那些在餘波中失去性命的受害者帶來慰藉。', 66384),
(302457, 'zhTW', '', '俘獲一個邪教徒吧。我們會在明月聖所後頭和你碰面。', 66384),
(302453, 'zhTW', '', '盡我所能的一切，$p，無論結果會是什麼。\n\n或許有些根還能保存下來。或許它們能再度成長，成為一棵偉大的樹。或許這樣的一棵樹能承載我一生的奉獻。\n\n又或許什麼也不留下，除了能安心地死去，心知我已竭盡所能。', 66384),
(302450, 'zhTW', '', '嘿！離我遠點，你這黏黏的咬鱗鬼！', 66384),
(302442, 'zhTW', '', '直到星辰都黯淡失色…', 66384),
(302437, 'zhTW', '他在那裡！他要去薩拉斯大學！', '', 66384),
(302423, 'zhTW', '', '謝啦，琪詹吉！金克絲，來吧。', 66384),
(302422, 'zhTW', '', '別擔心，小安妮。我會留一點給你。', 66384),
(302421, 'zhTW', '', '好吃！這是炙烤咬鱗者嗎？', 66384),
(302420, 'zhTW', '', '但比寂靜更可怕的，是明白。明白這份寂靜，將會伴隨我直到生命盡頭。\n\n那感覺很像恐懼，可恐懼是對未來的可能，是你心底祈求別發生的事。泰達希爾已經消逝，我再也無法…\n\n所謂「明白」，即是我難以言喻的沉重。', 66384),
(302418, 'zhTW', '', '是那份寂靜啊，$p。泰達希爾不是用言語與我交談，但我總能聽見她的聲音，就像我們能聽到大自然的呼吸。我與你說話時，同時也能聽見潛獵者的腳步，還有周遭溪流的波動。\n\n泰達希爾的存在比這更深刻，她總在我心中縈繞多年。直到…徹底消失。', 66384),
(302416, 'zhTW', '', '噢，他壞掉了。', 66384),
(302414, 'zhTW', '', '我必須集中精神，跟隨他的聖光。我們先回到營地吧。', 66384),
(302413, 'zhTW', '', '寇朗和我心心相繫。我要帶他回家。', 66384),
(302412, 'zhTW', '', '你知道我們一族的壽命有多長嗎？我們浪費了多少時間，還稱其為「慢活」？當我遇見寇朗的那一天，我就發誓再也不會浪費一分一秒。我絕不會把他拱手讓人。', 66384),
(302404, 'zhTW', '<奧斯崔和瑟朵娜似乎沒有注意到你的影子。>\n\n<你打算對自己說什麼？>', '<奧斯崔和瑟朵娜似乎沒有注意到你的影子。>\n\n<你打算對自己說什麼？>', 66384),
(302380, 'zhTW', '蠢蛋好強！', '', 66384),
(302379, 'zhTW', '想得美。後會有期。', '', 66384),
(302378, 'zhTW', '', '不行！不該這樣結束。', 66384),
(302377, 'zhTW', '你還真有點本事。', '', 66384),
(302376, 'zhTW', '', '好餓…無法思考。', 66384),
(302375, 'zhTW', '不！不！', '', 66384),
(302374, 'zhTW', '', '我不會輕易死掉的。', 66384),
(302373, 'zhTW', '哈！痛苦只會讓我更強大。', '', 66384),
(302372, 'zhTW', '我不會讓她失望的。你等著。', '', 66384),
(302371, 'zhTW', '哼。我一直在等夠格的對手來挑戰。', '', 66384),
(302370, 'zhTW', '我會把你給吃了。等著瞧。', '', 66384),
(302369, 'zhTW', '你永遠躲不過命運的鎖鏈。', '', 66384),
(302368, 'zhTW', '', '黎明就要來了，$c。', 66384),
(302367, 'zhTW', '我一定會懲戒你！', '', 66384),
(302366, 'zhTW', '在下的樹根被弱化了…', '', 66384),
(302365, 'zhTW', '在下會回來的…', '', 66384),
(302364, 'zhTW', '', '差一點就得手了…', 66384),
(302363, 'zhTW', '下次得用不一樣的方法…', '', 66384),
(302362, 'zhTW', '', '時機未到。', 66384),
(302361, 'zhTW', '我會回來的。一定會。', '', 66384),
(302360, 'zhTW', '', '還真了不起。', 66384),
(302359, 'zhTW', '哎呀呀…', '', 66384),
(302358, 'zhTW', '還真了不起。', '', 66384),
(302357, 'zhTW', '', '這只是一點小挫折。', 66384),
(302356, 'zhTW', '', '你逃不過低語的…', 66384),
(302355, 'zhTW', '虛無會一直監視你…', '', 66384),
(302354, 'zhTW', '', '啟動重新校正程序！', 66384),
(302353, 'zhTW', '嘖！我得調整一下交戰模組了。', '', 66384),
(302352, 'zhTW', '', '儘管逃吧，小火花…我最喜歡獵殺了！', 66384),
(302351, 'zhTW', '我是永不熄滅的餘燼，我的烈焰會再次熊熊燃燒！', '', 66384),
(302335, 'zhTW', '逮到你了，蠢貨！', '', 66384),
(302334, 'zhTW', '嚇到了嗎？希望如此。', '', 66384),
(302333, 'zhTW', '', '我會把你剷除掉！', 66384),
(302332, 'zhTW', '看看這是誰啊？你迷路了嗎？', '', 66384),
(302330, 'zhTW', '', '我會奪走你肉體裡的魔法！', 66384),
(302329, 'zhTW', '黑暗中的閃光…我一定要親自嚐嚐！', '', 66384),
(302328, 'zhTW', '', '你有覺得背脊發涼嗎？', 66384),
(302327, 'zhTW', '死亡降臨！', '', 66384),
(302325, 'zhTW', '我會把你的屍體交給薩拉塔斯！', '', 66384),
(302324, 'zhTW', '把命交出來吧！', '', 66384),
(302323, 'zhTW', '我會吞噬你！', '', 66384),
(302322, 'zhTW', '你會成為鬥技場的砲灰。', '', 66384),
(302321, 'zhTW', '', '異端分子，燃燒吧！', 66384),
(302320, 'zhTW', 'Archenon poros（祝你好運），罪人！', '', 66384),
(302319, 'zhTW', '在下一定能讓你倒下！', '', 66384),
(302318, 'zhTW', '這就是你的末日！', '', 66384),
(302317, 'zhTW', '', '要躲已經來不及了！', 66384),
(302316, 'zhTW', '你這個獵物還真好追殺。', '', 66384),
(302315, 'zhTW', '', '嘎！！！', 66384),
(302314, 'zhTW', '我抓，我抓，我抓抓抓。', '', 66384),
(302313, 'zhTW', '', '受死吧。', 66384),
(302312, 'zhTW', '把你破壞！', '', 66384),
(302311, 'zhTW', '來看看你有什麼真本事。', '', 66384),
(302310, 'zhTW', '', '你一腳踏入了我的陷阱…', 66384),
(302309, 'zhTW', '', '逮到你了！早就知道你會在這裡。', 66384),
(302308, 'zhTW', '你逃不過虛無的！', '', 66384),
(302306, 'zhTW', '', '看看這裡都有什麼？更多零件！', 66384),
(302305, 'zhTW', '哈！出色的預測造就了絕佳的埋伏！', '', 66384),
(302304, 'zhTW', '', '烈焰服從於我，你也該如此！', 66384),
(302303, 'zhTW', '烈焰總能先發制人！', '', 66384),
(302299, 'zhTW', '', '我可沒有忘記過去，但要是視機會而不見，我們永遠都不會成長。', 66384),
(302284, 'zhTW', '', '知道自己錯了…我鬆了一口氣。我們一起對抗真正的敵人。同時找回過去的盟友。', 66384),
(302283, 'zhTW', '沒錯，讓沙德拉回歸是極大的恩澤。也許她需要一、二個語者？啊！我們必須告訴酋長！', '', 66384),
(302278, 'zhTW', '', '$p，我怎麼可能不責怪自己呢？我曾是根莖守望者。泰達希爾交給我守護，本該是我的職責。\n\n我無數次安慰自己，說那場威脅來自根部上方，是誰也無法預料的。某種程度來說，確實如此。\n\n但我心裡明白，身為根莖守望者，我本該將自己徹底奉獻給泰達希爾。只要我還活著，泰達希爾就不該燃燒。', 66384),
(302273, 'zhTW', '', '$n，在這裡！', 66384),
(302270, 'zhTW', '', '我們需要一支搜索隊！我不會放棄找他。', 66384),
(302241, 'zhTW', '', '歐薇娜調整了她的過濾器，強迫自己再次承受裂隙的壓迫感。', 66384),
(302236, 'zhTW', '追上他們！駕！', '', 66384),
(302230, 'zhTW', '哈。難怪他們要你來處理這個任務。你讓事情變得超簡單。', '', 66384),
(302229, 'zhTW', '', '<莉雅德倫凝視下方的地面。>\n\n她毫不猶豫地直接跳下去了。\n\n不久前，她堅稱這裡什麼都沒有，只有「鳥和刺藤」。\n\n不過，既然阿奇爾森開口了，我想她展示了她真正的想法。\n\n至於你…你打算追隨她嗎？', 66384),
(302220, 'zhTW', '', '哈拉齊是現存中最強大的羅亞之一。\n\n要是與祂為敵那就太愚蠢了。我們若聯手，確實會令人畏懼！', 66384),
(302213, 'zhTW', '', '我們沒有祭壇可用，但它應該還能用。先把毒牙放好。', 66384),
(302207, 'zhTW', '', '虛無奪走了我的一切。現在它要來毀滅整個銀月城了。', 66384),
(302205, 'zhTW', '', '$n！他們都還好嗎？聖壇那裡發生什麼事了？', 66384),
(302202, 'zhTW', '我感覺…好多了…的樣子。我會馬上走。充滿希望的感覺真好。', '', 66384),
(302195, 'zhTW', '很高興見到你，$n。\n\n能和老朋友見面，確實不錯。還有像瑟朵娜這樣的新朋友也是。修復這些關係是最好的手段。這就是西爾朗想要的。\n\n你還要的話，我再幫你倒一杯鬼魂花茶。', '', 66384),
(302193, 'zhTW', '多虧有你，我們還算撐得住。我衷心希望你在接下來的戰爭中也能和我們並肩作戰。', '', 66384),
(302187, 'zhTW', '', '他屬於我！', 66384),
(302186, 'zhTW', '', '不行！我要帶你回家。', 66384),
(302184, 'zhTW', '啊啊啊！', '', 66384),
(302183, 'zhTW', '哈！逮到你了。等等…那是什麼？', '', 66384),
(302182, 'zhTW', '真是走運的$r。', '', 66384),
(302181, 'zhTW', '把我放出去，看看誰才是真正的「獵物」。', '', 66384),
(302179, 'zhTW', '', '把中毒的人都送來我這裡，快點去！', 66384),
(302176, 'zhTW', '', '又見面了，$n。你帶來的茶一直對我幫助很大。它是很好的替代品，這樣一來我就不用一直喝酒了。\n\n奧斯崔不時會送些鬼魂花葉子來，可以給你一點。他已經成為我不時就想見一見的朋友。\n\n順便一提。既然你是讓那封信免於被虛無怪物摧毀的人…如果你想看信，我不介意給你看。它就在樓上的床上。', 66384),
(302174, 'zhTW', '', '達奇看起來還走得動，但我們需要解毒劑！', 66384),
(302172, 'zhTW', '我得休息。我走好長一段路了。', '', 66384),
(302168, 'zhTW', '', '我們首次召喚艾恩夏倫的嘗試沒有成功。但是沒關係！我想我知道問題出在哪裡。\n\n艾恩夏倫是一條很大的蛇。一條超級大的蛇！所以也許我們只是需要收集更多天空裂片。也許我們還需要…我也不確定。五百吧！五百個天空裂片！這樣艾恩夏倫一定會注意到的。\n\n艾恩哈拉在上，我要怎麼樣才能收集到這麼多…？', 66384),
(302167, 'zhTW', '安娜絲…拜託。別過來。', '', 66384),
(302166, 'zhTW', '', '喔，他是你的嗎？不過，我還沒玩得盡興。', 66384),
(302162, 'zhTW', '', '計畫很簡單：我們找到寇朗，制住他，然後把他拖回銀月城。到時候再來搞清楚狀況。\n\n有必要的話，我會把英普利亞溺死在太陽之井。你要加入嗎？', 66384),
(302154, 'zhTW', '什麼？她可能正漂流在虛無之中，或是落在這個星球的某處。', '', 66384),
(302153, 'zhTW', '', '奧姆里克！雷歐娜掉進不穩定的虛無傳送門了。你一定有辦法救回她吧。', 66384),
(302135, 'zhTW', '', '不，$n，你受到女神標記，註定要面對與我們其他人都不一樣的命運。你的旅程會帶你離開哈朗達，前往樹根之上的世界。女神是這麼說的。', 66384),
(302124, 'zhTW', '感謝你的守護，哈拉齊。', '', 66384),
(302123, 'zhTW', '邪枝持續在製造強力毒藥。他們身上有蜘蛛的味道。你的狩獵還未告終。', '', 66384),
(302121, 'zhTW', '啊，你想要看透無形啊…一場有趣的狩獵正在等候著你。', '', 66384),
(302105, 'zhTW', '哈謝之道既漫長又艱辛，充滿著考驗與苦難。\n\n哈巫拉是哈謝的侍僧，跟隨他們踏上哈謝之道。哈巫拉為了哈謝而戰，也為了他們而死。\n\n通常這需要，呃，兩個人。不過，你也看得出來我年事已高，我們的士兵也滿身瘡痍，祖爾詹更是絕不會同意…\n\n我猜第二位哈巫拉只能是莉雅德倫了。\n\n<金德魯猶豫地笑了。>\n\n哈巫拉的榮耀竟然落到兩個血精靈頭上。希望這不會更加觸怒羅亞…', '', 66384),
(302101, 'zhTW', '哈謝之道既漫長又艱辛，充滿著考驗與苦難。\n\n哈巫拉是哈謝的侍僧，跟隨他們踏上哈謝之道。哈巫拉為了哈謝而戰，也為了他們而死。\n\n通常這需要，呃，兩個人。不過，你也看得出來我年事已高，我們的士兵也滿身瘡痍，祖爾詹更是絕不會同意…\n\n我猜第二位哈巫拉只能是莉雅德倫了。\n\n<金德魯猶豫地笑了。>\n\n哈巫拉的榮耀竟然落到一個精靈頭上。真沒想到能活著看到這種景象。', '', 66384),
(302100, 'zhTW', '我們試過用你的方式，不過我會照我知道的做。\n\n對於我這群野獸，只有最恐怖的才能成長茁壯。', '', 66384),
(302098, 'zhTW', '', '刀刃出鞘。', 66384),
(302097, 'zhTW', '', '起舞吧。', 66384),
(302096, 'zhTW', '', '你要小心點。', 66384),
(302092, 'zhTW', '菲德菲可用懇求的大眼看著你。', '', 66384),
(302084, 'zhTW', '', '「直到星辰消逝。」我說真的。我們會找到他。', 66384),
(302083, 'zhTW', '', '他的盾牌…好多血。該死。繼續找。', 66384),
(302082, 'zhTW', '', '寇朗的引火盒，有打鬥痕跡。她強迫他戰鬥。', 66384),
(302081, 'zhTW', '', '這樣我要怎麼教學？', 66384),
(302080, 'zhTW', '', '他們總是會死…', 66384),
(302078, 'zhTW', '', '拜託，一定要有用！', 66384),
(302077, 'zhTW', '', '不！去找別人。', 66384),
(302076, 'zhTW', '魚雖然美味，但也十分具有觀賞價值。你不覺得日鯉很美嗎？', '', 66384),
(302074, 'zhTW', '', '在我移除金屬的時候，制住它。', 66384),
(302069, 'zhTW', '菲德害怕地嗚咽著。', '', 66384),
(302062, 'zhTW', '我曾說過，訓練一條狗能有多難？\n\n看來我得少說兩句了。', '', 66384),
(302061, 'zhTW', '蠻錘的地盤，鷹巢山，就在這條路的前方！那邊常常有矮人和聯盟在戰鬥。\n\n我不是什麼牧師，所以我不會靠近沙德拉洛。有人認為如今那裡充滿邪惡和詛咒的氣息。\n\n<奧格巴做了幾個應該是預防詛咒的手勢。>\n\n我沒打算談那地方。你去問其他人吧。', '', 66384),
(302060, 'zhTW', '沙德拉洛？不盡然。\n\n隱匿石在北邊。離沙德拉洛遠點。那邊現在都是邪枝的領地了。', '', 66384),
(302058, 'zhTW', '祖瓦沙離沙德拉洛很近…沒錯。\n\n<混合者賈曼加皺著眉頭，仔細地打量你。>\n\n但我們現在不提那個地方。羅亞已死。', '', 66384),
(302055, 'zhTW', '', '我會偵察路徑。動作要快，時機就是一切。', 66384),
(302051, 'zhTW', '', '跟隨呼喚。', 66384),
(302050, 'zhTW', '隨著一陣微弱的歌聲在你腦海深處響起，你感到稍微失去平衡。', '隨著一陣微弱的歌聲在你腦海深處響起，你感到稍微失去平衡。', 66384),
(302048, 'zhTW', '菲德菲可用力地抓抓自己的脅腹。', '', 66384),
(302045, 'zhTW', '菲德菲可好奇地把頭歪向一邊。', '', 66384),
(302042, 'zhTW', '<蘑菇人搖了搖頭。>\n\n小孢子…', '', 66384),
(302021, 'zhTW', '', '斥候內菲娜專注地凝視著火焰。', 66384),
(302020, 'zhTW', '', '虛無對這個地方的影響太大了。我現在也感覺得到，它在拉扯我的存在…', 66384),
(302015, 'zhTW', '', '我們或許成功防止它成為更加恐怖的事物。', 66384),
(302014, 'zhTW', '', '那隻生物正在收集能量…以我們許多人的精華為食。', 66384),
(302010, 'zhTW', '咳咳。我們的幫手來了。', '', 66384),
(302009, 'zhTW', '喔，太狡詐了！我無法想像你…', '', 66384),
(302008, 'zhTW', '…於是我告訴他：「你的耳朵或許很長，但我的尾巴更長！」', '', 66384),
(302007, 'zhTW', '動身狩獵吧！不過要小心，別讓自己成為獵物。', '', 66384),
(302006, 'zhTW', '只要稍微讓步，他們就會得寸進尺。', '', 66384),
(302005, 'zhTW', '勇士，當心，我們的魔法就和我們的獵物一樣致命。', '', 66384),
(302003, 'zhTW', '我追蹤境內的威脅好一段時間了。他們還挺頑強的。', '', 66384),
(302002, 'zhTW', '在港口附近和我見面，我會告訴你另一條途徑…', '', 66384),
(302001, 'zhTW', '我的同事們正在尋找保護城市的方法，我則有自己的一套解決方法。', '', 66384),
(302000, 'zhTW', '', '雖然有點唐突，但我希望你先離開一下。在法術失效前，我們有好多話想說…還想共飲一瓶非常稀有的酒。', 66384),
(301999, 'zhTW', '', '謝謝你，旅行者。在極其珍貴的幾小時中，我再次感受到一切。', 66384),
(301997, 'zhTW', '', '成功了。我…再次完整了。雖然只有一下子，我確實感受到海風的吹拂。', 66384),
(301996, 'zhTW', '', '…結束了。不過結果…', 66384),
(301995, 'zhTW', '', '好了。接下來是最困難的環節。Anar\'sin arkhana！Anar\'endal belore！', 66384),
(301994, 'zhTW', '', '很好。現在使用水銀繪製儀式法陣。', 66384),
(301992, 'zhTW', '', '當然了。金一定很想念他。', 66384),
(301991, 'zhTW', '來去把我們的薩滿帶回家吧。', '', 66384),
(301990, 'zhTW', '達克，你得拿捏好分寸。你很幸運你的母親是我最中意的姐妹。', '', 66384),
(301989, 'zhTW', '只是想緩和一下氣氛。在黑暗的時刻，笑聲能提醒眾人，太陽終將再度升起。', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(301988, 'zhTW', '你為什麼是這個樣子？他們必須知道一切都在酋長的掌控之中。', '', 66384),
(301987, 'zhTW', '有沙德拉的幫忙，要解決邪枝食人妖的毒液就簡單多了！', '', 66384),
(301986, 'zhTW', '我們無法對抗梅薩拉散發出來的劇毒和詛咒。\n\n但我會盡力治癒一切傷痛。', '', 66384),
(301985, 'zhTW', '', '這樣是沒辦法找到她的。先回咆哮峰吧。想要找回她，我們只能向奧姆里克求助了。', 66384),
(301984, 'zhTW', '', '可惡！她不在這。傳送門的目的地肯定不穩定。', 66384),
(301983, 'zhTW', '', '你準備好了嗎，$r？', 66384),
(301982, 'zhTW', '時候到了。', '', 66384),
(301981, 'zhTW', '我們根本就不知道他們會從哪個方向偷偷潛進來！', '', 66384),
(301980, 'zhTW', '梅薩拉就在附近。我們得好好觀察有誰進出那個地方。', '', 66384),
(301977, 'zhTW', '跟暗幽谷女士一同前去探索的成員似乎有些疲憊，但至少記錄虛無風暴的過程有進展了。\n\n女士還送來了一些路上找到的奇妙樣本，但其他人不太願意進一步說明。', '', 66384),
(301971, 'zhTW', '', '不是讓勇敢的英雄幫忙，就是像微不足道的教徒一樣被打倒。', 66384),
(301970, 'zhTW', '', '塔蘭卓，這樣的行為明智嗎？', 66384),
(301969, 'zhTW', '', '用你收集的龍血塗抹蠟燭。', 66384),
(301961, 'zhTW', '', '在你英勇地打倒我之前，如果我說我可以解釋，你願意相信我嗎？', 66384),
(301960, 'zhTW', '', '她被拉進去了。快，在傳送門關閉前追上她！', 66384),
(301959, 'zhTW', '', '雷歐娜，等等！', 66384),
(301958, 'zhTW', '', '我們需要更高密度的虛無能量！', 66384),
(301957, 'zhTW', '', '這樣不夠。', 66384),
(301953, 'zhTW', '', '多麼疲憊卻又激勵人心的一場戰鬥！如今所有的羅亞都已加入我們的陣營。到外面來與我會合。我們將決定接下來的道路。', 66384),
(301950, 'zhTW', '別急。你需要什麼？', '', 66384),
(301949, 'zhTW', '不，小傢伙，那就是她所希望的。', '', 66384),
(301948, 'zhTW', '', '你覺得媽媽會對我慶幸你能回家而感到失望嗎？', 66384),
(301946, 'zhTW', '', '爸爸！你必須聽我說。', 66384),
(301945, 'zhTW', '', '爸爸。', 66384),
(301944, 'zhTW', '我理解，我的朋友。美麗往往伴隨著痛苦。', '', 66384),
(301943, 'zhTW', '有…有人向我保證，一切都合乎動物倫理！牠們都受到善待！', '', 66384),
(301942, 'zhTW', '需要先打敗這些龍鰻？看來有捨才有得。', '', 66384),
(301941, 'zhTW', '', '我們來到這個死屍遍布的地區，好研究這些龐大的殘留物並收集樣本。\n\n我們為了對付虛無風暴中危險殘暴的掠食者做好了萬全的準備，卻還是措手不及。跟隨我的刃多雷斥侯們一個又一個地受到某種東西影響。他們突然變得激動、四處亂跑，進了蛻殼的深處。\n\n我擔心他們即便沒被野獸殺死，還是會因為這個…病原體而死。', 66384),
(301939, 'zhTW', '只要我還有一口氣在，我們的村莊就會心懷無比的榮耀將坦金之名傳承下去。', '', 66384),
(301929, 'zhTW', '<只有你能感知到這個部分的自己。>\n\n<你打算對自己說什麼？>', '<只有你能感知到這個部分的自己。>\n\n<你打算對自己說什麼？>', 66384),
(301928, 'zhTW', '能跟這個小傢伙一起在家的感覺真好，但只有我一個人還真是難過。你幫忙做出了改變，$r。', '', 66384),
(301918, 'zhTW', '', '來看看這些教徒想對莎草做什麼吧。我不會暴露行蹤，我保證。', 66384),
(301909, 'zhTW', '', '好了。有用嗎？如果沒用，我可以調整法術。\n\n抱歉，我對這個還不太熟…最近，那些在達拉然開發的舊法術不太容易取得。', 66384),
(301907, 'zhTW', '', '我不懂。你和赫杜倫看到的一切，我早就知道了。那麼，祖拉夏所說的龐大恥辱究竟在哪裡？\n\n既然你已經取得了鑰匙碎片，最後的記憶也將向我們揭曉。或許我們倆都能在這裡找到答案。', 66384),
(301905, 'zhTW', '還沒完…你的鎖鍊綁住我們了，快停止！', '', 66384),
(301903, 'zhTW', '待在這裡。注意安全。', '', 66384),
(301897, 'zhTW', '我們收拾一下，然後去找坦金吧。', '', 66384),
(301895, 'zhTW', '', '你知道我不會的。', 66384),
(301894, 'zhTW', '我的愛是不會被遺忘的。', '', 66384),
(301893, 'zhTW', '我答應過我的妻子：我們的女兒會藉由她的力量成長。', '', 66384),
(301892, 'zhTW', '', '虛無風暴實在不是休息的好地方。\n\n這地方對所有人來說都很危險。我一離開營帳，就差點被這裡的虛無力量吞噬。所以，我打算待在這裡。無論如何，我都會盡全力幫忙的。\n\n為了銀月城。', 66384),
(301878, 'zhTW', '就像是熊熊燃燒的復仇欲望。這不是西爾朗的情緒。那太殘酷，太可憎了。', '', 66384),
(301875, 'zhTW', '我感受到…憤怒。我們更靠近那個回音一點吧。', '', 66384),
(301825, 'zhTW', '', '塔蘭卓，這是誰？你的另一個計畫嗎？', 66384),
(301824, 'zhTW', '', '啊！你來了。你…喔，親愛的。', 66384),
(301812, 'zhTW', '這些教徒自以為聰明，不過我的智商跟我的長矛一樣高。', '', 66384),
(301811, 'zhTW', '<告解者瑞維克的長袍被俐落地劃開。這種劃痕可不是野獸能做到的，應該是訓練有素的劍士才能辦到。\n\n暗影掠過固定在他額頭上的奇異金屬的表面。>', '<告解者瑞維克的長袍被俐落地劃開。這種劃痕可不是野獸能做到的，應該是訓練有素的劍士才能辦到。\n\n暗影掠過固定在他額頭上的奇異金屬的表面。>', 66384),
(301810, 'zhTW', '<里安隆的胸甲上有多處穿孔。傷口像是阿拉希步槍造成的。\n\n金屬環沿著他的持劍手臂纏繞而上。暗影沿著奇異金屬的稜線若隱若現。>', '<里安隆的胸甲上有多處穿孔。傷口像是阿拉希步槍造成的。\n\n金屬環沿著他的持劍手臂纏繞而上。暗影沿著奇異金屬的稜線若隱若現。>', 66384),
(301809, 'zhTW', '嘿！救我離開這裡！', '', 66384),
(301807, 'zhTW', '', '膽敢攻擊惡齒的人都是蠢蛋！', 66384),
(301805, 'zhTW', '', '我不會告訴佩爾娜，你讓我離開你身邊！', 66384),
(301804, 'zhTW', '', '我看到他了，$n！他們把伊達戈帶進墓穴了！', 66384),
(301801, 'zhTW', '', '納羅拉克教導我們學會堅忍，克服災難，克服心痛。\n\n但我不能讓伊達戈的回憶就這樣消逝或者遭到羞辱。', 66384),
(301796, 'zhTW', '', '可以的話，就跟上來，$n！', 66384),
(301790, 'zhTW', '', '如果這是你的願望，我別無選擇，只能聽令行事，年輕的酋長。', 66384),
(301789, 'zhTW', '', '這位勇士會護送我到村莊。留在這裡，保護部族的其他人，佩爾娜。', 66384),
(301785, 'zhTW', '', '伊達戈被遺棄在村莊中！這樣他怎麼可能安息？', 66384),
(301781, 'zhTW', '你會是一個明理又體貼的首領，莉拉菊。你父母一定會很驕傲。', '', 66384),
(301780, 'zhTW', '', '我不會要求你再次拋下自己的職責了，佩爾娜。你讓我學到教訓了。', 66384),
(301779, 'zhTW', '', '身為你的榮譽守衛，我們的責任就是保護你，就像你保護部族一樣。', 66384),
(301763, 'zhTW', '這是…', '', 66384),
(301762, 'zhTW', '', '回到村莊後，我明白我的冒險行為太過魯莽了。', 66384),
(301753, 'zhTW', '', '謝謝你的幫忙，$n。我們該回去了。', 66384),
(301748, 'zhTW', '', '你說的對，伊達戈。我很抱歉。等我們回去，我會向其他人道歉。', 66384),
(301747, 'zhTW', '', '可是伊達戈…', 66384),
(301734, 'zhTW', '你是惡齒部族的酋長！你必須具備熊的韌性，甚至能克服你的悲傷。', '', 66384),
(301729, 'zhTW', '藥茶，是嗎？', '', 66384),
(301727, 'zhTW', '很高興能見到你，莉拉菊，不過你冒險來到這裡，可不是首領該有的行為！', '', 66384),
(301726, 'zhTW', '啊，好多了。等等，你說是那孩子派你來的？她到底在想什麼？', '', 66384),
(301725, 'zhTW', '', '我們是殺手。', 66384),
(301724, 'zhTW', '', '但伊利達瑞不是單純聽從命令的士兵。我們是掠食者。', 66384),
(301723, 'zhTW', '', '他們想招募伊利丹，來抵禦艾澤拉斯所面臨的最強大的威脅。', 66384),
(301722, 'zhTW', '', '所以那魯警告過伊利丹要提防虛無？', 66384),
(301721, 'zhTW', '虛無會吞噬你。就像它吞噬西爾朗一樣。', '', 66384),
(301719, 'zhTW', '', '<戴著眼鏡的女性謹慎地看著你的武器。>\n\n在你像個「過度狂熱的冒險者」一樣插手之前，先給我一點時間解釋。\n\n沒錯，我是一名死靈法師。我刪去了購物清單上的一些關鍵部分，讓你更有可能對我伸出援手。不過，我向你保證，我沒有不軌的企圖。\n\n你面前這個女妖曾是一名遠行者，奎爾薩拉斯的英雄。如今她深陷在痛苦之中。\n\n求求你，讓我完成這個儀式。一切結束後，看你是要逮捕我，還是打倒我，怎麼樣都行。\n\n我們達成共識了嗎？', 66384),
(301715, 'zhTW', '', '我們回去之後再談吧。挖掘過去的秘密常會引來不必要的注意。', 66384),
(301714, 'zhTW', '我的宿命由不得你決定，那魯。', '', 66384),
(301713, 'zhTW', '', '虛無是更強大的敵人。面對虛無就是你的宿命。', 66384),
(301712, 'zhTW', '真是好極了。說得好像他們還不夠強大似的。', '', 66384),
(301711, 'zhTW', '', '伊利丹，你的敵人遠比薩格拉斯和他的燃燒軍團還要強大。', 66384),
(301696, 'zhTW', '$p，我原本希望父親會收下這面盾牌，重新扮演保衛者的角色。\n\n但他顯然還沒準備好。或許他永遠都不會。', '', 66384),
(301690, 'zhTW', '', '暗幽谷女士看了這個景象最後一眼，嘆了口氣。', 66384),
(301689, 'zhTW', '', '嗯，我想我應該先行一步了。再會，還有謝謝你。', 66384),
(301688, 'zhTW', '', '我已經派其他人回去找威里吉恩，順便帶著我精選的收藏去進行編目。相信他一定會很高興。', 66384),
(301687, 'zhTW', '', '邪枝部族用強大的詛咒圖騰玷汙了阿奇爾森的神殿。這些圖騰正在將阿奇爾森拉向此地，邪枝部族意圖將她囚禁。\n\n阿奇爾森正在反抗，而她的力量已經危及阿塔阿曼！\n\n已經快沒時間了！馬上摧毀那些詛咒圖騰，並在儀式把這個地方毀掉之前消滅邪枝部族。', 66384),
(301674, 'zhTW', '阿曼尼扎村還真是熱鬧！在我們奪回惡齒村莊之前，我很樂意待在這裡。', '阿曼尼扎村還真是熱鬧！在我們奪回惡齒村莊之前，我很樂意待在這裡。', 66384),
(301672, 'zhTW', '我正在散播沙德拉回歸的消息，多虧了你和妮嘉！', '', 66384),
(301670, 'zhTW', '', '我不願成為羅亞語者，我目前必須把注意力放在惡齒部族上。\n\n此外，賈曼加已經是羅亞語者了。', 66384),
(301668, 'zhTW', '', '<這本書含有很多封信，夾在儀式研究的書頁之間，上面的符文讓你起雞皮疙瘩。看起來最新的信墨跡似乎還沒乾。>\n\n艾瑪希爾，\n\n你的生日就快到了，不過我得承認，近來的日子越來越難過了。很多事都今非昔比。而且一切很可能都回不到過去了。\n\n儘管如此，我的研究還在繼續。我們敵人的工具或許能讓你得到某種程度的安息。如果我能讓這個儀式照我的預期進行，也許就能把你應得的禮物送給你。\n\n勿忘太陽之井，\n\n塔蘭卓', 66384),
(301667, 'zhTW', '<你並不清楚這個甕裡面的東西究竟是什麼。不過它很難聞，還散發出某種奇怪的焦躁感。\n\n不禁讓你後頸的寒毛直豎。>', '<你並不清楚這個甕裡面的東西究竟是什麼。不過它很難聞，還散發出某種奇怪的焦躁感。\n\n不禁讓你後頸的寒毛直豎。>', 66384),
(301665, 'zhTW', '說不定我下一個故事的主角就是你喔！', '', 66384),
(301664, 'zhTW', '', '只要有無法彌補的缺憾，我就喝一杯。\n\n其實還真不少！', 66384),
(301661, 'zhTW', '<你面前的架子似乎倍受重視，上面放了許多看似毫無關係的奇特裝置。\n\n園藝用具跟一些似乎是手術用品的東西擺在一起。它們都相對乾淨，不過有經常使用和磨損的跡象。>', '<你面前的架子似乎倍受重視，上面放了許多看似毫無關係的奇特裝置。\n\n園藝用具跟一些似乎是手術用品的東西擺在一起。它們都相對乾淨，不過有經常使用和磨損的跡象。>', 66384),
(301657, 'zhTW', '', '我是瓦麗拉‧桑古納爾，一名追尋己道的血精靈。\n\n我的過去…很複雜，但我一向都忠於自己的本心。\n\n我與烏瑞恩家族並肩作戰，也是銀月城及其攝政王的盟友。\n\n我並非奴僕，也不是任何人的間諜…只是我所信任之人的盟友。\n\n如果這樣對你來說已經足夠了，那麼或許我們有機會可以好好合作一下。', 66384),
(301651, 'zhTW', '博學者！維持符石充能的秘法水晶快用光了！', '博學者！維持符石充能的秘法水晶快用光了！', 66384),
(301650, 'zhTW', '別擔心！我想新的補給品送到了！', '別擔心！我想新的補給品送到了！', 66384),
(301647, 'zhTW', '', '那些東西在他體內生長？$n，拿著這個解毒劑，用在附近其餘受影響的斥侯身上。我來監測他的狀況。', 66384),
(301646, 'zhTW', '我的…身體。它們消失了嗎？', '', 66384),
(301645, 'zhTW', '', '現在，一邊稍微攪拌，一邊進行微調。', 66384),
(301643, 'zhTW', '', '接著，我們必須搗碎肝臟，釋放其中的酵素。', 66384),
(301642, 'zhTW', '', '先讓我們弄碎血花瓣。', 66384),
(301634, 'zhTW', '', '因為我懂一些語言魔法，於是，自從這個德萊尼女性來了，奧姆里克就派我去照顧她。不過，她卻一直瞪著我…\n\n她似乎比較喜歡你。如果你不懂她的語言。我可以跟你分享我的秘法語言學家專業知識。不過，這只會對她有用。', 66384),
(301632, 'zhTW', '在外域的時候，沒有我的笑話，我們根本撐不到今天！', '', 66384),
(301631, 'zhTW', '庫德蘭會喜歡這個的，$p。', '', 66384),
(301626, 'zhTW', '不用擔心，我會讓沙德拉立刻恢復實力。', '', 66384),
(301625, 'zhTW', '', '記得…你是不是收集我的毒液去做一些壞事。\n\n我會暫時先放你一馬。', 66384),
(301624, 'zhTW', '', '當然記得。你在亞登曠野幫助我重生。\n\n我們永遠是盟友，淵喉行者。', 66384),
(301620, 'zhTW', '', '是時候增加我的信徒了。\n\n我應該同時接納枯木部族和惡齒部族。他們非常合適。', 66384),
(301619, 'zhTW', '', '我重生了！', 66384),
(301615, 'zhTW', '我真的希望你跟我一樣享受自我。我可以擅自認為我們正在成為朋友嗎？', '', 66384),
(301610, 'zhTW', '', '他們絕對不會發現我們的到來，哈拉齊。我們一定會玩得很開心，就像以前一樣。', 66384),
(301609, 'zhTW', '', '首要之務是向邪惡的邪枝部族復仇。', 66384),
(301607, 'zhTW', '', '納羅拉克的惡齒部族準備好跟你、枯木部族和哈拉齊合作，一起對抗共同的敵人。', 66384),
(301605, 'zhTW', '你拿到甲殼了？那我們開始吧！', '', 66384),
(301604, 'zhTW', '我永遠只為自己打算，不過，我很肯定，世上最安全、最有趣的地方…就是你身邊。', '', 66384),
(301603, 'zhTW', '我不會要求你相信我，凡人。如果你真的有學到什麼，那應該是我們多曼納爾是無法相信的。', '', 66384),
(301602, 'zhTW', '讓我們拋開這個小小的不快，$n。畢竟，我仍站在你這邊。', '', 66384),
(301600, 'zhTW', '請把這裡當自己家。', '', 66384),
(301599, 'zhTW', '', '妮嘉‧斷齒並未回答，不過一抹笑意在她的唇邊浮現。', 66384),
(301598, 'zhTW', '我把一切恩怨都留在辛特蘭。我們現在有共同目標：奪回我們的土地和羅亞。', '', 66384),
(301593, 'zhTW', '', '辛特蘭的枯木族人和惡齒族人，會一起做這件事。', 66384),
(301592, 'zhTW', '喔不…儀式失敗了。沙德拉！我們會找到你的甲殼！', '', 66384),
(301591, 'zhTW', '', '我相信哈拉齊。\n\n沙德拉或許需要一些時間，但我會用我在這裡看到的一切，好好指引惡齒部族。', 66384),
(301583, 'zhTW', '別激動。我了解你的不爽，不過我們必須繼續當盟友。\n\n為了艾澤拉斯好，對嗎？拿去，刀刃給你…', '', 66384),
(301582, 'zhTW', '我想我無法責怪你。\n\n不過，這還是一趟愉快的旅程。至少，對我來說是這樣。', '', 66384),
(301581, 'zhTW', '啊，你的內心平衡又健康，對嗎？真無聊。\n\n顯然，我必須去找個更病態的人來折磨。', '', 66384),
(301579, 'zhTW', '真有趣…這個滋味就只有這樣？我承認，我很失望。\n\n也許殘忍暴力的滋味終究比凡人的苦難更美味。', '', 66384),
(301578, 'zhTW', '沒錯，沒錯！這就是你的痛苦的滋味。令人回味無窮！謝謝你。', '', 66384),
(301577, 'zhTW', '嘖嘖，$n。你無法對我說謊。我嚐到了你的痛苦。\n\n實在太美味了。', '', 66384),
(301576, 'zhTW', '是這樣嗎？我嚐到的那股滋味純粹是我自己的渴望嗎？真有意思。\n\n我應該反省一下自己見識不足。', '', 66384),
(301568, 'zhTW', '了解，我從未真的背叛你。\n\n恐懼、後悔、背叛、悲傷…你們凡人感受到如此純粹、深刻的痛苦。\n\n受苦是你們的天性，正如我的天性是渴望品嚐你們的苦難。\n\n我利用你們凡人對信任和友情的偏好，引誘你將藏得最深的秘密展露無遺。我塑造了啃食之境中的虛無，讓你見識傷你最深的事物。\n\n現在，告訴我實話…這是不是你最極致的折磨？\n\n我們這趟旅程對你留下多深的傷口？', '', 66384),
(301567, 'zhTW', '真希望我記得這個該死的箱子到底要送去哪裡…', '真希望我記得這個該死的箱子到底要送去哪裡…', 66384),
(301566, 'zhTW', '我必須確保萬無一失。博學者血誓這裡的後勤行動實在…難以言喻。', '我必須確保萬無一失。博學者血誓這裡的後勤行動實在…難以言喻。', 66384),
(301565, 'zhTW', '你看不到我很忙嗎？\n\n如果我夠努力，博學者血誓一定會知道我天賦異稟！\n\n這將會是全銀月城最乾淨的地板。', '你看不出來我很忙嗎？\n\n如果我夠努力，博學者血誓一定會知道我天賦異稟！\n\n這將會是全銀月城最乾淨的地板。', 66384),
(301563, 'zhTW', '我馬上就衝過來查看那隻眼睛，結果卻發現邪枝部族在這裡！', '', 66384),
(301562, 'zhTW', '', '有話快說，沙德拉的信徒。', 66384),
(301561, 'zhTW', '我知道這看起來不怎麼樣，但是先聽我說！', '', 66384),
(301553, 'zhTW', '', '啊！一個冒險者。在這個多事之秋，正是我想看到的那種人。\n\n我的藥劑室恐怕得暫時收攤了。不過，如果你想找點事做，我正好有些小事需要人幫忙。', 66384),
(301552, 'zhTW', '', '我們早點來就好了。把剩下的人送回暗域點吧。', 66384),
(301551, 'zhTW', '芬德爾試著把那生物引開…讓我們逃走…但我們太弱了…', '我們會永遠哀悼我們失去的事物…讓這個成為我們的教訓。這裡的虛無是充滿欺詐與毀滅之物。', 66384),
(301550, 'zhTW', '', '許多人都因為這邪惡的生物失去性命…看到你們還安全，我很慶幸。', 66384),
(301545, 'zhTW', '不要分心！補給品很快就會到了！', '不要分心！補給品很快就會到了！', 66384),
(301543, 'zhTW', '這個木箱裡應該有每個符石所需的補給品。等你準備好就把東西帶上吧。', '', 66384),
(301534, 'zhTW', '別害怕，我會好好解釋。如果你還願意相信我，就回到咆哮峰找我，我會把刀刃給你。', '', 66384),
(301533, 'zhTW', '夠了！你的憤怒讓我享用了美味的一餐。謝謝你。', '', 66384),
(301532, 'zhTW', '夠了！你顯然比我想的還要聰明。', '', 66384),
(301530, 'zhTW', '那些血精靈為什麼不能自立自強？這些該死的低語。', '', 66384),
(301529, 'zhTW', '', '你最好說到做到。', 66384),
(301528, 'zhTW', '別擔心。我們不會把他丟在這裡。', '', 66384),
(301527, 'zhTW', '', '別叫我冷靜，達克。其他人都死了。只剩他一個人還在堅持。', 66384),
(301526, 'zhTW', '你冷靜一點，姐妹。', '', 66384),
(301525, 'zhTW', '你…你對刀刃做了什麼？啊…！', '', 66384),
(301524, 'zhTW', '沒錯，沒錯！你的憤怒非常可口！', '', 66384),
(301523, 'zhTW', '我從未如此靈感湧現過。我馬上就去畫畫！', '', 66384),
(301522, 'zhTW', '這個地方還真是宜人。我夏天一定要來這裡住上幾天。', '', 66384),
(301520, 'zhTW', '', '到底有多少精靈為了拯救朋友被引來這裡，力量全被汲取？', 66384),
(301519, 'zhTW', '', '虛無生物的饑渴永無止境。有如此的操縱能力…確實少見。', 66384),
(301511, 'zhTW', '', '盡你所能做好準備吧。', 66384),
(301510, 'zhTW', '', '我再次尋求你的協助，我們得站穩腳步。', 66384),
(301509, 'zhTW', '我們從來就不需要祂們。我們可以依靠自己的力量！', '', 66384),
(301507, 'zhTW', '', '那羅亞呢？你不能呼喚祂們來協助嗎？', 66384),
(301506, 'zhTW', '', '原諒我…', 66384),
(301505, 'zhTW', '我向同胞們發出呼喚了，我們就等著看吧。', '', 66384),
(301504, 'zhTW', '', '惡齒也承受了巨大的損失。', 66384),
(301503, 'zhTW', '沒有多少阿曼尼活著回來這裡。', '', 66384),
(301502, 'zhTW', '', '沒時間逞凶鬥狠了。我們需要個計畫。托倫多？', 66384),
(301501, 'zhTW', '', '我們正受到攻擊。邪枝…', 66384),
(301499, 'zhTW', '', '到高地的下方找我。我們不會再次被偷襲成功！', 66384),
(301498, 'zhTW', '', '阿塔阿曼淪陷了。', 66384),
(301497, 'zhTW', '', '我的力量被汲取得一乾二淨了。你似乎比我還要堅強。', 66384),
(301495, 'zhTW', '', '「相信虛無行者？」這很明顯就是個陷阱。', 66384),
(301494, 'zhTW', '沒錯。相信我。我們會在高地上會合。', '', 66384),
(301493, 'zhTW', '我們在暗域點東南方的高地上。相信那個虛無行者！', '', 66384),
(301492, 'zhTW', '有隻虛無風暴的野獸在追擊我們小隊。我們快被追上了。快逃！', '', 66384),
(301484, 'zhTW', '', '我加入不是為了餵食虛無行者…但如果有機會可以幫忙的話…', 66384),
(301443, 'zhTW', '我們都為藝術做了犧牲。我只希望犧牲的不是創作的能力！\n\n<他眨了眨眼。>\n\n哎喲。', '我們都為藝術做了犧牲。我只希望犧牲的不是創作的能力。\n\n<他眨了眨眼。>\n\n哎喲。', 66384),
(301442, 'zhTW', '我雖然在繪製光綻時受傷了，但要重來一次我也願意。那個壯觀的景象實在太難抗拒了！', '我雖然在繪製光綻時受傷了，但要重來一次我也願意。那個壯觀的景象實在太難抗拒了！', 66384),
(301441, 'zhTW', '我從沒想過我會如此慶幸自己聽了安達的建議，去上擊劍課程。我的命差點就沒了。', '我從沒想過我會如此慶幸自己聽了安達的建議，去上擊劍課程。我的命差點就沒了。', 66384),
(301440, 'zhTW', '憤怒、痛苦、恐懼和暴力是我藝術的媒介。那比水彩顏料要複雜多了。', '憤怒、痛苦、恐懼和暴力是我藝術的媒介。那比水彩顏料要複雜多了。', 66384),
(301439, 'zhTW', '虛無襲擊之時，我理解到繪畫技巧固然重要，但現實還是很殘酷。', '虛無襲擊之時，我理解到繪畫技巧固然重要，但現實還是很殘酷。', 66384),
(301438, 'zhTW', '虛無生物的色彩十分鮮明。可惜的是，每當我要畫它們的時候就會受到攻擊。', '虛無生物的色彩十分鮮明。可惜的是，每當我要畫它們的時候就會受到攻擊。', 66384),
(301437, 'zhTW', '這個傷其實沒有想像的那麼糟。這是我為藝術做的犧牲。', '這個傷其實沒有想像的那麼糟。這是我為藝術做的犧牲。', 66384),
(301435, 'zhTW', '謝謝你，妮嘉。只要我們通力合作，誰都別想奪走。', '', 66384),
(301434, 'zhTW', '', '你不在的時候，我會好好守護墓穴和這裡的聖物。', 66384),
(301430, 'zhTW', '我或許是來自辛特蘭，但我信奉哈拉齊和沙德拉。\n\n枯木部族的盟友越多越好。其中包括惡齒部族，以及妮嘉。', '', 66384),
(301425, 'zhTW', '被我背叛的滋味是否讓你的舌頭感到苦澀？來吧，你對復仇的渴望將會對這個刀刃進行最後的回火！', '', 66384),
(301424, 'zhTW', '現在，面對駭人的真相！你這個愚蠢的凡人，我一直在利用你！', '', 66384),
(301415, 'zhTW', '我甚至沒發現那根毒牙不見了！當你向我展示那根毒牙時，我丟臉到不敢跟你說。', '', 66384),
(301413, 'zhTW', '', '混合者賈曼加一定是沙德拉洛的祭司。\n\n他到底想對我們說什麼？', 66384),
(301412, 'zhTW', '', '這可一點都不簡單。\n\n哈拉齊要我們去狩獵沙德拉，不過，要是這是為了跟沙德拉結盟呢？\n\n正因為這樣，惡齒部族才更喜歡納羅拉克…有巨熊羅亞在你背後，只要戰到底就好！\n\n不過，或許有更多盟友，也是一件好事。', 66384),
(301411, 'zhTW', '沒錯，我們把她的兩個聖物一起帶走。我們希望她會回歸，不過邪枝部族現在正試圖利用她和她的孩子對付我們。', '', 66384),
(301410, 'zhTW', '', '你知道沙德拉一直都在這裡！', 66384),
(301409, 'zhTW', '', '牠們為什麼不會攻擊我們？跟我預期的完全不一樣。', 66384),
(301403, 'zhTW', '', '暮光之刃最初攻擊祖阿曼時，惡齒莎草被摧毀了。大部分的惡齒族人想要留在祖阿曼，而不是去南方，但我們還能去哪？\n\n我原本打算把惡齒難民帶來這裡，不過，如果枯木部族像他們在辛特蘭那時候一樣，對我們充滿惡意，我們豈不是自投羅網。\n\n部族之間一直相安無事，不過，如果祖阿曼這裡有外來的枯木族人…', 66384),
(301401, 'zhTW', '', '在那場與人類和精靈的大戰中，食人妖軍隊在奧特蘭克分崩離析，有些枯木部族、惡齒部族甚至是邪枝部族向南逃到辛特蘭。\n\n邪枝部族大多待在辛薩羅這座城市，不過枯木部族和惡齒部族卻為了土地和神廟而互相爭鬥，包括蜘蛛羅亞沙德拉的神廟。枯木部族對惡齒部族十分殘忍，用蛛毒攻擊我的族人。\n\n不久前，惡齒部族將辛薩羅占為己有。因此，當部落摧毀了辛特蘭的許多村莊後，枯木部族離開了那裡。有些人前往西方。而有些人則一定在這裡，藏身在這些枯木部族中。如果他們在這裡，我們無法信任他們。', 66384),
(301400, 'zhTW', '不接受殺價…除非你能逆天改命。', '', 66384),
(301397, 'zhTW', '不是死亡，而是凋零。蘑菇人和你們不同。\n\n我們在受傷太重時就會停手。\n\n停手之後，有時候會被救治。比如…強壯的隊友會被救治。\n\n也可能就這樣倒在地上凋零。失敗的隊伍、外來者、各種生物，都會在坑洞裡凋零。\n\n我們會吃掉那些凋零的東西。對大家都好。\n\n怨鬥坑洞真是個好地方！', '', 66384),
(301396, 'zhTW', '怨鬥坑洞是個用來戰鬥的地方。\n\n也是用來觀戰的地方。\n\n戰鬥結束時用來歡呼的地方。\n\n還有…用來吃掉那些戰敗者的地方。\n\n另外…柏特斯押注誰會輸。', '', 66384),
(301395, 'zhTW', '這裡是怨鬥坑洞。\n\n怨鬥坑洞是是蘑菇人，呃…啊。\n\n坑洞和什麼都有關！', '', 66384),
(301391, 'zhTW', '柏特斯能做些什麼？\n\n想打一場？\n\n還是想下注？', '', 66384),
(301389, 'zhTW', '', '我的職責是保護整個永歌森林。', 66384),
(301380, 'zhTW', '你的運氣似乎很差。你要買嗎？', '', 66384),
(301378, 'zhTW', '如果你非問不可，或許你本來就不是它的目標客群。', '', 66384),
(301376, 'zhTW', '做好準備！這可不會太輕鬆。一旦開始，就沒辦法停下來了。你準備好了嗎？', '', 66384),
(301372, 'zhTW', '', '我知道沙德拉可能參與其中。我們必須繼續查。', 66384),
(301371, 'zhTW', '真菌遠征隊是新冠軍。我們就該待在水池裡。濕濕活該！', '', 66384),
(301370, 'zhTW', '蓬衛是新冠軍。我們就該待在水池裡。濕濕活該！', '', 66384),
(301369, 'zhTW', '孢誓是新冠軍。我們就該待在水池裡。濕濕活該！', '', 66384),
(301368, 'zhTW', '環帽是新冠軍。我們就該待在水池裡。濕濕活該！', '', 66384),
(301367, 'zhTW', '如果你需要毒鏢，記得告訴圖圖！一切都會準備好。', '', 66384),
(301366, 'zhTW', '很高興能從$p身上學到戰鬥的技巧，也學會了不再害怕孢子滑翔者。', '', 66384),
(301363, 'zhTW', '圖圖毒倒了所有人！少了圖圖就贏不了！', '', 66384),
(301361, 'zhTW', '吉尼治療了大家。沒人死！', '', 66384),
(301360, 'zhTW', '布拉寇打敗了孢子滑翔者！菇傘安全。', '', 66384),
(301354, 'zhTW', '將跟$p和真菌遠征隊戰鬥！', '', 66384),
(301352, 'zhTW', '將跟$p和蓬衛戰鬥！', '', 66384),
(301349, 'zhTW', '將跟$p和孢誓戰鬥！', '', 66384),
(301343, 'zhTW', '將跟$p和環帽戰鬥！', '', 66384),
(301342, 'zhTW', '蘑菇人們，期待已久的比賽終於到來！發光守衛回來了！', '', 66384),
(301339, 'zhTW', '', '作為斷齒的一員，我是此處惡齒部族在祖阿曼的驕傲，但斷齒族人的足跡並未侷限在祖阿曼，而我們也記得枯木部族和惡齒部族互相敵對的黑暗歷史。', 66384),
(301320, 'zhTW', '', '在你進去哈拉齊的神廟時，我的雙眼會好好盯著這裡的枯木部族。', 66384),
(301319, 'zhTW', '辛特蘭的蠻錘矮人一直在迫害我們，奪走屬於我們的土地。不過，我們也教會他們不好好待在那些岩洞裡面，就準備被砍頭！\n\n我希望把他們徹底趕走，但也享受跟他們的戰鬥。我跟我們的薩滿一起受訓，對抗矮人的雷電攻擊。他們臉上露出驚訝的表情！我就是得好好收藏他們的頭顱。至少到它們腐爛為止。\n\n現在我就只留下那些錘子。', '', 66384),
(301311, 'zhTW', '人們說我的想法古怪又不合常理，說真的，也許他們是對的！\n\n我的計畫本來很單純：運來幾箱光綻孢子，把它們放到這裡，讓強大的聖光徹底淨化這裡。\n\n結果完全沒用。\n\n現在這裡都是光綻生物。它們瘋狂繁殖，多曼納爾也利用它們來對付我！\n\n你能幫我在這場混亂擴散出去之前，將它控制住嗎？', '', 66384),
(301295, 'zhTW', '', '隨著虛無之尖陷入混亂，我們有機會能奪下聖所。\n\n利用微型奇異點的重力牽引在聖所中移動。它們應該能讓你在奇異點之間飛越。\n\n收集奇異點線圈可以讓你破壞艾修里圖斯的屏障，這樣就能把他引出來了。', 66384),
(301289, 'zhTW', '', '這裡遍布著大量的充能核心，裡面還殘留著虛無之尖的能量。絕不能讓這些落入敵人手中。\n\n多曼納爾也注意到了，並派出吞噬之眾來回收這些核心。\n\n雖然戒備森嚴，但我成功奪取了一個奇異點傳送門網路。可以用來前往設施的不同區域，搶在吞噬之眾之前收集核心。', 66384),
(301288, 'zhTW', '這附近有很多頭顱要獵，畢竟邪枝部族正在製造混亂。', '', 66384),
(301264, 'zhTW', '祖瓦沙是一個小村莊，我們在那裡調製各式各樣的混合物。當我們離開辛特蘭時被迫拋下它，但我盡可能把配方都帶走了。我跟我的表親老祖拉雷克一起住在那裡。\n\n我懷念那些日子…祖拉雷克利用混合物把他的黃頭髮染得更黃…\n\n<混合者賈曼加皺起眉頭，搖搖頭。>\n\n我再也沒看過他。也許他還在那裡。或者死了。\n\n不是每個人都會跑來這裡。有些人覺得跑回枯木崖很沒面子。', '', 66384),
(301261, 'zhTW', '隱匿石原先是辛特蘭的某個藏身處的一部分，大概是在第二次大戰的時候。那時聯盟攻勢猛烈，殺了很多人。\n\n現在呢？那是一個充滿軟泥的地方。我住在附近的時候，大家都對那裡避之唯恐不及，除非你需要摘一些鬼魂菇。\n\n軟泥會讓長矛變得黏糊糊的，不過你得小心別讓自己的武器被分解了，哈！', '', 66384),
(301257, 'zhTW', '你想上狩獵課嗎？\n\n太不巧了，我正忙著磨利我的長矛，好刺穿邪枝的頭顱。', '', 66384),
(301256, 'zhTW', '', '$r，你對枯木部族的了解有多少？', 66384),
(301255, 'zhTW', '', '我聽一些人說過，辛特蘭的兄弟是住在小屋裡。小屋的牆很薄。你在搜索的時候，順便張大耳朵，看看能不能聽到沙德拉的消息。', 66384),
(301228, 'zhTW', '無論你認為我犯下了多少罪…我當初根本不知道自己正在參與什麼，但等我明白時已經太遲了。', '無論你認為我犯下了多少罪…我當初根本不知道自己正在參與什麼，但等我明白時已經太遲了。', 66384),
(301227, 'zhTW', '我曾試著逃跑一次…但他們讓我明白，別再妄想了。', '我曾試著逃跑一次…但他們讓我明白，別再妄想了。', 66384),
(301226, 'zhTW', '他們承諾給我真理，但我所見到的只有鮮血。', '他們承諾給我真理，但我所見到的只有鮮血。', 66384),
(301225, 'zhTW', '我不是為了崇拜暗影才來的。我只是想要一個目標。', '我不是為了崇拜暗影才來的。我只是想要一個目標。', 66384),
(301203, 'zhTW', '', '我會暫時顧好它。不過，之後記得來看看我們。回頭見。', 66384),
(301179, 'zhTW', '布拉寇害怕的時候不用再躲起來了。謝謝你陪布拉寇一起練習對付孢子滑翔者！', '', 66384),
(301178, 'zhTW', '其實不算太糟。他們打起來的時候，還會發出噗通聲。', '', 66384),
(301177, 'zhTW', '看不到菇傘上面！孢子滑翔者可能會傷害它，布拉寇都不知道！', '', 66384),
(301176, 'zhTW', '菇傘沒事吧？布拉寇最喜歡自己的菇傘了！', '', 66384),
(301171, 'zhTW', '要再練習嗎？吉尼也想要多練習。', '', 66384),
(301170, 'zhTW', '不算太壞。吉尼能治療，就算大戰也能應付！', '', 66384),
(301169, 'zhTW', '或許吉尼能做到。', '', 66384),
(301168, 'zhTW', '嗯，還算順利。你還好嗎？吉尼還好嗎？', '', 66384),
(301165, 'zhTW', '好吧，朋友。圖圖會在怨鬥坑洞和你會合。', '', 66384),
(301148, 'zhTW', '我的野獸會繼續在暴力的威脅下成長茁壯。這才是多曼納爾的做法。', '', 66384),
(301147, 'zhTW', '無論這個培養方式是否有效，它顯然不適合我。', '', 66384),
(301146, 'zhTW', '所以呢？那隻野獸表現得如何？', '', 66384),
(301145, 'zhTW', '如果圖圖不去嘗試，就不會失敗。\n\n這樣最安全。\n\n$p和隊伍不會生氣。\n\n也不會失去新朋友$p、布拉寇和吉尼。\n\n而圖圖在營地裡，也不會覺得難過。', '', 66384),
(301143, 'zhTW', '圖圖覺得圖圖做不到。\n\n沒辦法像$p一樣強。\n\n只有強一點點，但還不夠強。\n\n就算經過訓練，還是不夠好。', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(301141, 'zhTW', '<斥候丹娜的護甲被聖光灼燒。只有經驗豐富的牧師才能以這樣的力量懲擊對手。\n\n她的雙手扭曲變形，被與皮膚融為一體的金屬牢牢鎖死。>', '<斥候丹娜的護甲被聖光灼燒。只有經驗豐富的牧師才能以這樣的力量懲擊對手。\n\n她的雙手扭曲變形，被與皮膚融為一體的金屬牢牢鎖死。>', 66384),
(301140, 'zhTW', '$p是來告訴圖圖，圖圖逃跑是不好的嗎？\n\n圖圖知道圖…圖圖對團隊來說不夠優秀。\n\n圖圖只能逃跑。\n\n在池子裡很安全。\n\n待在池子裡就夠了。', '', 66384),
(301139, 'zhTW', '', '<當你靠近時，洛希亞的目光完全沒離開桌子。>\n\n大博學者洛摩斯是我的贊助者。我的任務是找到並釀造世上最棒的酒，然後獻給他。\n\n因此，我非常忙。<洛希亞終於抬起頭，漠不關心地看著你。>你來這裡有什麼事嗎？', 66384),
(301138, 'zhTW', '先是天譴軍團、燃燒軍團，現在是虛無…你根本不知道，當那些來自宇宙的勢力不斷試圖踐踏葡萄園時，維持葡萄酒的品質到底有多困難。', '', 66384),
(301137, 'zhTW', '燈花？繩藤？炸彈種子？你想要？\n\n完全沒問題，我的朋友。只要你有足夠的金幣。', '', 66384),
(301136, 'zhTW', '', '如果你有門路，就能在永歌森林找到各式各樣的東西。有些東西甚至沒被詛咒。', 66384),
(301132, 'zhTW', '', '<瑪莉琳女士看著你。儘管她毫無動作，目光卻很犀利。她不會浪費能量在不必要的動作上。>\n\n哈囉。歡迎來到我的地窖。我從我的家鄉蘇拉瑪爾帶來商品和專業技術。阿爾茵女士一眼就看出我的價值，給了我永久居留資格。\n\n如果你想品嚐任何酒，就跟我說一聲。', 66384),
(301128, 'zhTW', '', '告訴你一個秘密！我一開始其實是乳酪商，直到最近才投入釀酒事業。兩者大同小異：都是發酵產品，種類繁多，對環境極為敏感。而且可以無限消耗，尤其是搭在一起。', 66384),
(301126, 'zhTW', '', '你知道烹飪最重要的東西是什麼嗎？鹽。很多很多鹽。比一般廚師想的還要多放好幾把。\n\n我把同樣的哲學套用在釀酒。我很喜歡經典的紅色，但我致力於讓酒越紅越好…濃郁風味不只是輕輕掠過鼻尖，而是充滿你的鼻腔且久久不散，從聞到的那一刻起，就經歷一次複雜的感官之旅。\n\n你永遠不會忘記我的酒。很少有東西能跟它們相提並論，通常只有新鮮乳酪，而且應被視為菜單上的主打品項。我的酒是用來喝的，而不是小口啜飲，而且非常適合在煙霧繚繞的昏暗室內獨自品嚐。', 66384),
(301124, 'zhTW', '喔，你甚至一個字都不用說。\n\n你是來尋找愛情的，不是嗎？那你找對人了。我這裡應有盡有。', '', 66384),
(301123, 'zhTW', '', '哈囉，你好啊！美好的一天，不是嗎？美好的村莊！我們精靈確保每天都像今天一樣。多麼美好的共識。\n\n你想要什麼？', 66384),
(301122, 'zhTW', '我很慶幸能像這樣活著…在經歷過去那些事後。現在是我人生最開心的時候。看到其他人享受我的作品，讓我湧現出難以言喻的感受。\n\n你願意試試看嗎？', '', 66384),
(301120, 'zhTW', '我過去曾是販賣雜貨的普通商人…過著平凡的人生。<赫隆露出微笑，一個歡迎陌生人的制式表情。不過裡面有更深刻且極度真摯的情感。赫隆很高興你在這裡。>\n\n然後有一天，我突發奇想，打算試點新東西。創造只屬於我的東西。人生只有一次，何不試著摘下星星呢？', '', 66384),
(301119, 'zhTW', '', '歡迎你到處看看你感興趣的東西。我一直在試驗一種新開發的紅酒…看看這個深紫色，不覺得很迷人嗎？\n\n<莎嵐尼突然變得驚恐，用手遮著嘴巴。>\n\n喔，這跟虛無完全沒關係，我保證。洛摩斯會把我從金霧村流放。', 66384),
(301118, 'zhTW', '', '歡迎來到金霧村，這裡有東部王國最好的葡萄酒和葡萄酒商…包括我。<阿爾茵的一舉一動都輕鬆寫意。她咬了一口形狀完美的葡萄。>我專門在艾蘭達瀑布旁種植當地水果。走進銀月城的每一間酒館，都能找到正在享用艾蘭達葡萄酒的顧客。我的酒老少咸宜，不限場合。\n\n現在，我能幫你什麼忙嗎？你會在這裡待上幾天？', 66384),
(301107, 'zhTW', '<這名光鑄德萊尼倒臥地上，屍體被某些野獸撕裂。\n\n你注意到一小塊水晶與聖光能量產生共鳴。\n\n你可以用這個水晶來為刀刃灌注更多聖光，讓平衡變得不穩定。\n\n下次戴西蒙斯嘗試進行回火時，它可能會直接爆炸。>', '', 66384),
(301093, 'zhTW', '圖圖謝謝$p…給圖圖這個機會。', '', 66384),
(301092, 'zhTW', '希望你可以幫環帽尋找新的吹箭。', '', 66384),
(301091, 'zhTW', '$p，圖圖受不了。圖圖退出。', '', 66384),
(301086, 'zhTW', '他真的已經盡力了！', '他真的已經盡力了！', 66384),
(301068, 'zhTW', '你…傷害我…', '', 66384),
(301067, 'zhTW', '你…糾纏我…', '', 66384),
(301066, 'zhTW', '你讓我…受傷…', '', 66384),
(301065, 'zhTW', '還是…很可悲…', '', 66384),
(301064, 'zhTW', '你永遠…不夠強…', '', 66384),
(301063, 'zhTW', '你還是…很弱…', '', 66384),
(301062, 'zhTW', '你…救不了任何人…', '', 66384),
(301061, 'zhTW', '你…沒救我…', '', 66384),
(301057, 'zhTW', '你應得的！', '', 66384),
(301056, 'zhTW', '死吧！', '', 66384),
(301055, 'zhTW', '惡劣的野獸…', '', 66384),
(301054, 'zhTW', '怪物！', '', 66384),
(301053, 'zhTW', '沒用的廢物…', '', 66384),
(301052, 'zhTW', '可憐的弱者…', '', 66384),
(301051, 'zhTW', '太弱了！', '', 66384),
(301043, 'zhTW', '', '$p，我對你的幫助心懷感激。我會繼續在這裡努力，看看是否能有所成果。', 66384),
(301042, 'zhTW', '', '然而，今天你讓我得以守住心中的希望。僅此一點，便已彌足珍貴。', 66384),
(301041, 'zhTW', '', '$p，我們無法得知這一切是否會帶來我所期盼的重生…亦或泰達希爾是否還有一部分仍然存活，或是能再度復甦。', 66384),
(301007, 'zhTW', '走到底。綠火炬。別聲張。', '', 66384),
(301006, 'zhTW', '', '你喜歡你後面的房子插著的綠色火炬嗎？也許我應該去弄一些來。', 66384),
(301005, 'zhTW', '外面插著綠色火炬的地方可能有一些龍鰻。', '', 66384),
(300995, 'zhTW', '', '應該算是…我們的恩人。\n\n我們替他的大事業生產必需品。作為回報，這個小小天地將完全屬於我們。\n\n時機到了，你就會知道更多內幕。', 66384),
(300985, 'zhTW', '', '啊，新的客人。薇拉想親自跟你交談。她在樓上。', 66384),
(300984, 'zhTW', '', '事前準備對完成試煉有幫助。', 66384),
(300983, 'zhTW', '', '非常好。或許你能活下來。', 66384),
(300982, 'zhTW', '', '很好。資源能讓你活過冬天。', 66384),
(300979, 'zhTW', '保鏢對你的璽戒點點頭。', '', 66384),
(300974, 'zhTW', '贊恩會把希歐的分紅給他。進去吧。', '', 66384),
(300973, 'zhTW', '贊恩會把德諾寧的分紅給他。進去吧。', '', 66384),
(300972, 'zhTW', '贊恩會把蘭達利的分紅給她。進去吧。', '', 66384),
(300965, 'zhTW', '給我滾遠一點。', '', 66384),
(300964, 'zhTW', '滾開，你不夠資格！', '', 66384),
(300951, 'zhTW', '', '我了解自己的弟弟。我打算給他改過自新的機會，這是他應得的。', 66384),
(300950, 'zhTW', '', '你要我砍下他的人頭？雖然這確實是祖阿曼的做法。', 66384),
(300949, 'zhTW', '', '他能自己做決定，而且也夠聰明，知道自己的行動會有什麼後果。', 66384),
(300948, 'zhTW', '', '他會這樣，我也難辭其咎。一直以來我不應該對他，如此的嚴苛。', 66384),
(300947, 'zhTW', '', '我們姊弟之間會計較的事情多的是，但很快就會放下。', 66384),
(300946, 'zhTW', '', '你弟弟會因為你和羅亞的關係耿耿於懷嗎？', 66384),
(300945, 'zhTW', '', '失去追隨者和看到我成為哈謝…這樣的懲罰對他來說就夠了。', 66384),
(300944, 'zhTW', '', '大多數都因為莫爾頓喪命。其他人？我不想因為懲罰我弟弟，讓部族再度分裂。', 66384),
(300943, 'zhTW', '', '祖爾詹也是祖爾金的孫子，他擁有力量。他善於言詞，受人追隨。', 66384),
(300938, 'zhTW', '', '$p，有些日子我會感覺，甚至盼望泰達希爾有一天能再度生長。但那樣的日子並不常有。大多數時候，我毫無頭緒，也沒有理由去懷抱希望。\n\n我唯一能確定的就是，若我放棄了，泰達希爾便只能存在於我逐漸消逝的記憶與夢境中。我不能如此…\n\n所以，即便在毫無希望的日子裡，我也依然為了希望而努力。', 66384),
(300933, 'zhTW', '$n勇士。\n\n我不確定這事值得你花時間關注。永歌森林保證我們會得到食糧和補給品，而我們的聖騎士和牧師僅存的資源越來越少了。\n\n明明他們的城市…事實上，甚至艾澤拉斯的一切能否存活，都取決於我們成功與否。但這些…人們…似乎不太想幫助我們，或是信任我們。\n\n如果我們想要繼續保護太陽之井，抵禦虛無的無盡大軍來襲，我們會需要魔餅和幻象零食之外的補給品。\n\n你可以替我們去和那些人談談嗎？或許他們更信任你。', '$n勇士。\n\n我不確定這事值得你花時間關注。永歌森林保證我們會得到食糧和補給品，而我們的聖騎士和牧師僅存的資源越來越少了。\n\n明明他們的城市…事實上，甚至艾澤拉斯的一切能否存活，都取決於我們成功與否。但這些…人們…似乎不太想幫助我們，或是信任我們。\n\n如果我們想要繼續保護太陽之井，抵禦虛無的無盡大軍來襲，我們會需要魔餅和幻象零食之外的補給品。\n\n你可以替我們去和那些人談談嗎？或許他們更信任你。', 66384),
(300912, 'zhTW', '等我找到解決方法的時候，我會聯繫你們。', '', 66384),
(300911, 'zhTW', '這些筆記裡面一定有答案！凱西雅…我一定會確保你沒有白白犧牲。阿拉特，告訴洛索瑪我會提供協助。', '', 66384),
(300887, 'zhTW', '', '看到這樣雄偉的東西被火焰吞噬…簡直是無比痛苦。然而，痛苦本身並不是最難承受的。隨著時間流逝，這份痛也漸漸變得遲鈍。$p，對我而言，最難的是我失去了生命的意義。身為根莖守望者，我清楚自己為何而生，也清楚自己願意為何而死。\n\n但隨著泰達希爾的消逝…空虛與失落遠比我想像的更難以承受。在哈瑪拉幫助年輕的哈拉尼爾讓我找到了更遠大的目標，也讓我不至於被悲傷完全吞沒。', 66384),
(300886, 'zhTW', '', '我當時在大巢穴，與其他根莖守望者在一起…\n\n<哈嘉爾停頓了一下，才繼續說下去。>\n\n其他人看見了濃煙，便派人來叫我。在哈瑪拉唯一能看見的光芒，來自頭頂那燃燒著的樹根。\n\n火最後才燒到那裡，整棵樹早就毀了。', 66384),
(300874, 'zhTW', '', '這或許聽起來有些奇怪。但許多年來，泰達希爾就是我的一切。自那場大火以後，她的消逝便在我心中揮之不去。\n\n當你將人生奉獻給某個事物，尤其是像泰達希爾這樣偉大而充滿生命的存在，用「它」來稱呼，顯得遠遠不足。', 66384),
(300870, 'zhTW', '', '又見面了，$p。那個鼠輩就在前面…準備好結束狩獵了嗎？', 66384),
(300867, 'zhTW', '嘿。這個問題雖然簡單，但不好回答。\n\n我猜是我姊姊要你來找我。她很了解我。有時候真希望她別這麼了解我。\n\n告訴祖爾賈拉，她那個不成材的弟弟沒事，入侵者…不，$n。至少你讓我願意給你一點敬意。\n\n我很快就會回去阿曼尼扎。在我花了夠多的時間回顧過去後。', '', 66384),
(300861, 'zhTW', '', '但我永遠不會放棄希望，盼望有一天能透過我的努力讓它得以重生。', 66384),
(300860, 'zhTW', '', '當初沒能及早察覺泰達希爾的危機，也沒能做出不同的抉擇，這將成為我心中永遠的遺憾。', 66384),
(300859, 'zhTW', '', '去阿古斯。親眼見證伊利丹所見的事物。', 66384),
(300858, 'zhTW', '', '我們要去哪裡？', 66384),
(300857, 'zhTW', '', '跟我來。你必須理解伊利達瑞是為了什麼而犧牲。', 66384),
(300850, 'zhTW', '對於那些看得見的人來說，翠綠墳塚和它的洞穴埋藏著許多秘密。', '對於那些看得見的人來說，翠綠墳塚和它的洞穴埋藏著許多秘密。', 66384),
(300849, 'zhTW', '', '成為根莖守護者是我一生中最驕傲的事，也是我最大的喜悅。', 66384),
(300848, 'zhTW', '', '我不知道你經歷過什麼失去，也不知道你背負著什麼痛苦。', 66384),
(300842, 'zhTW', '', '我們會哀悼逝者的。但現在我們應該先珍惜他們用生命換來的勝利。', 66384),
(300841, 'zhTW', '', '偉大的羅亞。你幫我們走到這一步。但最後必須由我們自己來做個了斷。', 66384),
(300838, 'zhTW', '$p，有空嗎？', '', 66384),
(300836, 'zhTW', '', '是時候採取最後手段了。難道你不願意為了拯救族人，嘗試所有可能性嗎？', 66384),
(300833, 'zhTW', '你有工作要給我？我們去酒吧談吧。這種事可不能太張揚。', '', 66384),
(300832, 'zhTW', '哈，抓到了。聽說你到處在打聽我。', '', 66384),
(300817, 'zhTW', '$p，其他引導師有些疲憊了。\n\n希望你跟法奧有帶來解決方案？', '', 66384),
(300816, 'zhTW', '謝謝你，$p。我會把這些聖物分配給需要的人。', '', 66384),
(300813, 'zhTW', '我無法進入太陽之井，$p。謝謝你幫忙處理聖物的事。', '', 66384),
(300808, 'zhTW', '虛無最終會把這些回憶扭曲成殘暴的事物，這一點都不讓人意外。', '', 66384),
(300806, 'zhTW', '可悲！', '', 66384),
(300805, 'zhTW', '我無法想像這會如何影響你…', '', 66384),
(300804, 'zhTW', '真是可怕。', '', 66384),
(300801, 'zhTW', '啊，我嚐得到那個靈魂的心痛。因為你過去做的一些事嗎？真令人傷心。', '', 66384),
(300800, 'zhTW', '你就應該…受盡折磨…', '', 66384),
(300799, 'zhTW', '你失敗了…你不夠強…', '', 66384),
(300798, 'zhTW', '怪物…你是怪物…', '', 66384),
(300797, 'zhTW', '你永遠…不夠強…', '', 66384),
(300796, 'zhTW', '別丟下…我…', '', 66384),
(300795, 'zhTW', '你既弱小…又可悲…', '', 66384),
(300794, 'zhTW', '幫幫…我…', '', 66384),
(300789, 'zhTW', '', '有時候，希望是我們僅剩的一切。', 66384),
(300788, 'zhTW', '', '希望我們能幫助根系重獲生機。', 66384),
(300784, 'zhTW', '也謝謝你願意把這麼重要的任務交給我…這對你和對我都很重要。', '', 66384),
(300783, 'zhTW', '再次謝謝你，替我修補這件披風。', '', 66384),
(300781, 'zhTW', '他很喜歡美好的事物。希望看到它被徹底修補，能讓他得到安息。', '', 66384),
(300780, 'zhTW', '這件披風的原主人曾是我很親近的人。', '', 66384),
(300779, 'zhTW', '很抱歉。那一定很美麗…但我必須讓頭腦清醒一下。', '', 66384),
(300778, 'zhTW', '嘉爾里？你沒事吧？', '', 66384),
(300777, 'zhTW', '我成功了！這件披風再次完好無缺，我敢說它看起來…', '', 66384),
(300775, 'zhTW', '那些化身…它們是那件披風的回憶！', '', 66384),
(300774, 'zhTW', '大家，快點！我已經開始了！', '', 66384),
(300773, 'zhTW', '索爾溫‧亮縫匆忙跑走，不想讓任何人發現他臉紅。', '', 66384),
(300772, 'zhTW', '不管遭遇什麼狀況，我都會保護你。', '', 66384),
(300771, 'zhTW', '有了這麼強大的力量，我們應該能製造一些…化身。', '', 66384),
(300767, 'zhTW', '你有什麼問題？', '你有什麼問題？', 66384),
(300766, 'zhTW', '怎樣？', '怎樣？', 66384),
(300765, 'zhTW', '<精靈上下打量你，然後發出輕笑。>', '<精靈上下打量你，然後發出輕笑。>', 66384),
(300764, 'zhTW', '給我滾遠一點。', '給我滾遠一點。', 66384),
(300763, 'zhTW', '我真希望再也不用面對這個回憶…', '', 66384),
(300762, 'zhTW', '很抱歉事情居然變成這樣，老朋友。', '', 66384),
(300717, 'zhTW', '你看到這塊絲綢注入了多少純粹法力。修補過程可能會…相當驚險刺激。\n\n確定你做好萬全準備。一旦開始，我就無法停止編織。', '', 66384),
(300697, 'zhTW', '你確定你是法師嗎？你的姿勢太糟糕了。它在吸取時，請不要移動。否則會扭曲以太流動。', '', 66384),
(300677, 'zhTW', '隨著我研究得越深入，辛多雷也變得昌盛。我的工作是銀月城存續的基礎。', '', 66384),
(300675, 'zhTW', '帶著晶化容器，使用它將苦痛注入我們的實驗對象。\n\n武器、傀儡、法力龍鰻…我們可以為其注入魔法，產生令人愉悅的效果。', '', 66384),
(300672, 'zhTW', '抱歉，我只喝五百年的陳釀。', '', 66384),
(300671, 'zhTW', '', '很高興見到你，賈厄斯。要來一杯嗎？', 66384),
(300668, 'zhTW', '', '$n，你到這個星球很久了嗎？這些虛無至尊掠食者正好適合磨練我使用鐮刀的功夫。', 66384),
(300653, 'zhTW', '', '但既然你是我的哈巫拉，我想…謝謝你說的話。', 66384),
(300652, 'zhTW', '', '榮幸？因為我嗎？哼。你說的話還真的有股魔力。', 66384),
(300651, 'zhTW', '', '我很榮幸看到你沒有犯下你祖父和我曾經犯過的錯，和能夠陪伴你前行。', 66384),
(300646, 'zhTW', '', '我也體驗過你的處境。就像你的祖父一樣，我也渴求力量，甚至不在乎傷害到其他人。', 66384),
(300644, 'zhTW', '', '你們缺乏資源。就算是我，應該也會在暴力的威脅之下，優先保護自己的家鄉。', 66384),
(300642, 'zhTW', '', '我只希望我能早點學會這些教訓，當一個更好的領袖。', 66384),
(300641, 'zhTW', '', '或許吧。阿奇爾森考驗了我的信念。哈拉齊逼我使用頭腦，而不是蠻力。', 66384),
(300640, 'zhTW', '', '看來你對羅亞的信心越來越深了。', 66384),
(300632, 'zhTW', '', '哈拉齊沒辦法袖手旁觀。如果狀況惡化，阿奇爾森也不會坐視不管。', 66384),
(300631, 'zhTW', '', '幸好，儘管被你祖父背叛，哈拉齊還是忍不住出手幫了枯木部族。', 66384),
(300624, 'zhTW', '', '枯木需要我的幫助。我卻沒聽進去。我太在乎自己的族人了。', 66384),
(300623, 'zhTW', '', '為什麼？我們幫了枯木部族。你也找到了哈謝聖壇，離成為哈謝更近一步。', 66384),
(300622, 'zhTW', '', '我很樂意取得哈拉齊祝福，但我待在這裡很可恥。', 66384),
(300608, 'zhTW', '', '快去吧，$p。沒有什麼比阻止那些火焰更重要了！', 66384),
(300604, 'zhTW', '', '保護泰達希爾殘存的一切是首要之務。誰知道哪些樹根還能救回來？', 66384),
(300603, 'zhTW', '', '這裡有許多飢餓的生物，想要啃食裸露的樹根。', 66384),
(300602, 'zhTW', '', '祖爾賈拉，我看得出來你有心事。我是真心想幫忙。', 66384),
(300601, 'zhTW', '', '$p，我不希望有任何東西傷害到附近的樹根。', 66384),
(300600, 'zhTW', '', '精靈，現在是怎樣？你覺得自己是我的哈巫拉，可以問我私人問題了嗎？', 66384),
(300506, 'zhTW', '', '難道我什麼事都得自己來嗎？', 66384),
(300492, 'zhTW', '不要打擾我工作！', '', 66384),
(300490, 'zhTW', '如果阿拉迪斯像個弱者一樣倒向某一側，那他活該落入悲慘的下場。', '', 66384),
(300489, 'zhTW', '所有術士都必須遊走在怯懦與誘惑的鋼絲上。', '', 66384),
(300487, 'zhTW', '不過工具也必須謹慎使用。我們不能握得太鬆，或是被它反客為主。', '', 66384),
(300483, 'zhTW', '更多盲目的入侵者！', '', 66384),
(300465, 'zhTW', '前進。羅亞語者允許你進去。', '前進。羅亞語者允許你進去。', 66384),
(300464, 'zhTW', '停下！', '停下！', 66384),
(300412, 'zhTW', '我是良藥羅亞，而治病涉及全面且仔細的診斷。\n\n我會針對你的疾病提供自己的見解，可以的話，還會建議解決方案，不過聽不聽全看病人自己的意思。\n\n有時候也會遇到無藥可救的情況。那就是人生。', '', 66384),
(300372, 'zhTW', '…蜘蛛腿、黏稠液體和普通的碎石都放在裡面了，你要的東西都齊了。很高興和你做生意。', '', 66384),
(300352, 'zhTW', '我在兩個誓言之間陷入兩難。\n\n對羅亞立下的誓言。對阿庫土立下的誓言。\n\n我只能履行其中一個。', '', 66384),
(300329, 'zhTW', '', '我已經開啟一道傳送門，$p，它能讓你進入校區的上層。', 66384),
(300326, 'zhTW', '喔，$n。你有西爾朗和其他人的消息嗎？', '', 66384),
(300325, 'zhTW', '把壞掉的法杖交給我，$n。', '', 66384),
(300303, 'zhTW', '', '我衷心感激你願意幫助泰達希爾和我，$p。', 66384),
(300299, 'zhTW', '', '$p，我等下就去聖壇找你。', 66384),
(300291, 'zhTW', '老兄！\n\n妖術食人妖在幹壞事，正在玩弄超出掌控的力量。\n\n他們束縛了一位羅亞聽命於己。但你能阻止他們，砸碎他們的圖騰，殺掉糾纏者。\n\n還有拿著這瓶藥！它會以各種方式改變你。你將能看見受縛羅亞，但要在祂靠近前喝下，每一口都只能短暫保護你。', '', 66384),
(300283, 'zhTW', '…現在一大堆人都認為板岩和頁岩是同一種東西，不過板岩其實…等等，你要去哪裡？', '', 66384),
(300282, 'zhTW', '…你提到了法術穿透？我必須找來相關領域的專家。幾天後再回來。', '', 66384),
(300281, 'zhTW', '我只想知道真相。', '我只想知道真相。', 66384),
(300274, 'zhTW', '這是羅亞慫恿你做的。祂就在那上面，對不對？我會殺了祂！', '', 66384),
(300271, 'zhTW', '你會為此付出代價，庫爾吉！', '', 66384),
(300259, 'zhTW', '它喚起你的痛苦回憶。我們來解放它們吧，好嗎？', '', 66384),
(300258, 'zhTW', '喔，親愛的，我很擔心這個。這地方似乎有辦法看穿你的內心。', '', 66384),
(300187, 'zhTW', '', '在這峽谷的峭壁之內，藏著我們稱之為家園的地方。那是部落的心臟，是我們族人的精神所在。\n\n今天我們磨練自己的戰鬥技巧，這麼一來當戰爭找上我們的時候，我們可以及時做好準備。', 66384),
(300136, 'zhTW', '不不，我堅持！你去找點樂子。我會在這裡，盡情品味你殘暴的氣味。', '', 66384),
(300134, 'zhTW', '他知道自己不能到處抓人，但是兇殺路的精靈不見一、二個，根本沒人在意。', '', 66384),
(300130, 'zhTW', '不能再浪費時間了。等你準備好離開，就告訴我一聲。', '', 66384),
(300118, 'zhTW', '我尋求解答，不過這些回憶…', '', 66384),
(300117, 'zhTW', '幾位教授正在研究一件從奎爾達納斯入侵中回收的神器，結果它毫無預警地觸發，打開了一道虛空傳送門。\n\n形形色色的生物正從裡面蜂擁而出…這是一場全面入侵！\n\n我們需要你幫忙關閉這道傳送門，不只是為了拯救校園，更是為了整個銀月城！', '', 66384),
(300115, 'zhTW', '庫爾吉是穿山甲羅亞，也是良藥羅亞。那意味著，我們帶著問題去找祂，祂就會給我們解決方案。早在祖爾金成為酋長之前，我就是祂的羅亞語者。\n\n庫爾吉的藥物知識可以追溯到很久以前。祂能夠診斷任何疾病或弱點。想知道誰身上出了什麼問題時，我們就向庫爾吉提問。但現在，祂卻不回應我們。結果祂說阿庫土已經死了？祂是背叛羅亞、沉默羅亞。呸！\n\n<席塔生著悶氣，同時繼續開口道。>\n\n如果見死不救，這個良藥羅亞還有何用？\n\n羅亞不會告訴我們如何治療阿庫土。不過我們並不是束手無策。', '', 66384),
(300112, 'zhTW', '阿庫土是祖爾金的戰士之一。他在部落和聯盟進攻阿塔阿曼時受了傷。\n\n阿庫土說，還沒到他光榮死去的時候，所以我們必須快點行動，救他的命。', '', 66384),
(300111, 'zhTW', '別拿問題來煩我。酋長快死了！', '', 66384),
(300109, 'zhTW', '小心一點。那裡的靈魂非常憤怒。', '', 66384),
(300108, 'zhTW', '', '明智的選擇。同情是致命弱點。快去吧，我們沒有多少時間了。', 66384),
(300105, 'zhTW', '', '還不要下到洞穴裡。在地表的這裡強化我的聖物，在下方戰鬥時，我會用它來強化我們。', 66384),
(300090, 'zhTW', '', '威脅我的新夥伴？延長到二百年吧。', 66384),
(300088, 'zhTW', '真菌遠征棄賽出局！', '', 66384),
(300087, 'zhTW', '蓬衛棄賽出局！', '', 66384),
(300086, 'zhTW', '孢誓棄賽出局！', '', 66384),
(300085, 'zhTW', '環帽棄賽出局！', '', 66384),
(300084, 'zhTW', '$p，你的隊伍已經拋下你跑掉了。', '', 66384),
(300083, 'zhTW', '', '這趟旅程考驗著我們所有人，我們應該趕快動身。對吧，哈巫拉？', 66384),
(300082, 'zhTW', '', '但是這並不會讓我們成為朋友。', 66384),
(300081, 'zhTW', '', '如果你說那是引導你雙手的原動力，我相信你。你的意見很不錯，和你一起行動的夥伴也十分可靠。', 66384),
(300079, 'zhTW', '', '哈哈哈哈哈。你還真會說笑。你就和長矛一樣直截了當，但又和穿山甲皮盾一樣難以洞穿。', 66384),
(300078, 'zhTW', '數量太多了，他們撐不了太久的！', '', 66384),
(300077, 'zhTW', '', '現在呢！$n和我是你的哈巫拉。我們會照顧你…', 66384),
(300075, 'zhTW', '', '這樣說，有些奇怪，但我覺得自己多少和你一樣。並且希望你能更接近你們的神一點。', 66384),
(300074, 'zhTW', '', '我們在暗域點會合吧，$n。', 66384),
(300072, 'zhTW', '一定會有人來幫忙，大家都能平安脫困。', '', 66384),
(300070, 'zhTW', '', '這段過去讓我耿耿於懷，我也不會引以為傲。', 66384),
(300069, 'zhTW', '', '但我沒有跟你說，他俘虜了我、嚴刑拷打我。嚴刑拷打我的同胞還殺了他們。', 66384),
(300068, 'zhTW', '', '我和你說過，我曾與你的祖父戰鬥。', 66384),
(300067, 'zhTW', '', '夠了，祖爾賈拉。我承認自己的過去讓我…很難完全站在你們的立場去想。', 66384),
(300066, 'zhTW', '', '我明明警告過他們，別去招惹那東西！', 66384),
(300065, 'zhTW', '他們的毒更厲害。圖圖無法應付怨鬥坑洞，壓力太大了！', '', 66384),
(300064, 'zhTW', '', '這樣就離鏟除祖阿曼的暮光之刃更近一步了。', 66384),
(300063, 'zhTW', '吉尼無法獨自扛下整個隊伍。吉尼必須撤退，你也快跑！', '', 66384),
(300062, 'zhTW', '', '別裝作好像很在乎我或是阿曼尼的樣子。', 66384),
(300061, 'zhTW', '', '你現在打算奉承我？我知道你為什麼會來這裡：你要保護永歌森林那寶貴的金黃田野。', 66384),
(300060, 'zhTW', '', '等等…我不是這個意思…祖爾賈拉，成為哈謝會是個很棒的成就。', 66384),
(300058, 'zhTW', '', '入侵者，是的。我們快要達成你們的目標了。走吧。', 66384),
(300057, 'zhTW', '', '你還要繼續服侍我，卡爾葛。過來看，$n。', 66384),
(300056, 'zhTW', '', '如果金德魯說得沒錯，藉由「哈謝」這條途徑聯繫羅亞是行不通的。', 66384),
(300055, 'zhTW', '有必要的話，我會逃入扭曲虛空！', '', 66384),
(300054, 'zhTW', '布拉寇得逃跑，孢子滑翔者會吞掉菇傘！布拉寇很抱歉！', '', 66384),
(300048, 'zhTW', '這些石頭通常用來保護我們的森林，不過突然爆發的光綻…所有變異的生物…這些石頭完全不堪一擊！', '這些石頭通常用來保護我們的森林，不過突然爆發的光綻…所有變異的生物…這些石頭完全不堪一擊！', 66384),
(300046, 'zhTW', '算了。我們的約定作廢，破夜者。我會親自進入巢穴，取得其中的力量。', '', 66384),
(300034, 'zhTW', '啊，我的弦幾乎快用完了。', '', 66384),
(300033, 'zhTW', '太完美了，這正是我需要的。', '', 66384),
(300032, 'zhTW', '非常好，$c。這樣我就不用停下手邊的工作去忙別的事了。', '', 66384),
(300030, 'zhTW', '', '非常感謝你，$c。畢竟沒人喜歡太單薄的衣服。', 66384),
(300021, 'zhTW', '啊，祖爾賈拉。你是要來找我們的薩滿幫忙嗎？', '', 66384),
(300019, 'zhTW', '', '我不是在取得你的信任。我是在叫你離開我的辦公室，不然我就叫警衛把你帶走。\n\n你之後要不要親自調查阿拉迪斯完全不關我的事。\n\n不過，我會建議你，阿拉迪斯給了你一個無法完成的任務。你最好在他把你供出來前把事情辦好。畢竟他可不是什麼信守承諾的人。', 66384),
(300018, 'zhTW', '', '我不是在取得你的信任。我是在叫你離開我的辦公室，不然我就叫警衛把你帶走。\n\n你之後要不要親自調查阿拉迪斯完全不關我的事。\n\n不過，我會建議你，阿拉迪斯給了你一個無法完成的任務。你最好在他出手前把事情辦好。畢竟他可不是什麼寬宏大量的人。', 66384),
(300015, 'zhTW', '', '我可以問一下你為什麼還在這裡嗎？', 66384),
(300012, 'zhTW', '', '你什麼都改變不了。拉克圖必將崛起！', 66384),
(300008, 'zhTW', '', '逃不出去，他們把我們徹底包圍了。', 66384),
(299979, 'zhTW', '', '結束了。你將會分擔它們的苦難，而這些怪物不會因此感激你。', 66384),
(299976, 'zhTW', '', '同情是致命弱點，不過你顯然游刃有餘。很好。', 66384),
(299975, 'zhTW', '我會回村裡去，跟姐姐一起慶祝。', '', 66384),
(299972, 'zhTW', '我可不想在他開始亂丟那些東西的時候待在這裡。', '', 66384),
(299969, 'zhTW', '感謝你的幫忙！', '', 66384),
(299968, 'zhTW', '相信我，這是好東西！', '', 66384),
(299967, 'zhTW', '可能會有一點火花，不過那正好能幫忙清除所有痕跡！', '', 66384),
(299958, 'zhTW', '', '這裡的空氣不一樣。在虛無的影響下，就連重力都只能當做參考。\n\n先不要下去。我們得在地表做些準備。', 66384),
(299953, 'zhTW', '', '你認真？心腸未免太好了。就我所知，虛無可不講究心懷慈悲。\n\n無論如何，你是同謀者，也是盟友。我可以改造聖物，從受害者吸取少一點能量。這會讓牠們元氣大傷，但至少能保住小命。\n\n不過，作為交換，聖物會需要吸取一部分持有者的精華。換句話說，只要你持有聖物，你的活力就會受損。你同意嗎？', 66384),
(299948, 'zhTW', '', '卡爾葛進入這裡了，不過先不要進去洞穴。我們得在地表做些準備。', 66384),
(299943, 'zhTW', '這簡直是場惡夢！大家明天就要回來了，可是校園簡直一團糟！\n\n有人把光之球莖丟在實驗室裡不管，結果現在光綻爬得到處都是！\n\n我找到一個哥布林商人，買到了一些工業級除草裝置，就是他們在幽坑城用的那種。\n\n能請你用這些除草裝置幫我清理一下嗎？', '', 66384),
(299924, 'zhTW', '真菌遠征隊！', '', 66384),
(299923, 'zhTW', '真菌遠真隊！', '', 66384),
(299922, 'zhTW', '真菌隊！', '', 66384),
(299921, 'zhTW', '蓬衛！', '', 66384),
(299920, 'zhTW', '孢誓！', '', 66384),
(299919, 'zhTW', '環帽！', '', 66384),
(299918, 'zhTW', '我們一起喊隊名！', '', 66384),
(299917, 'zhTW', '我們在坑洞中戰鬥。', '', 66384),
(299916, 'zhTW', '我們現在是一隊！', '', 66384),
(299902, 'zhTW', '有許多事要做。在坑洞做好準備。$p覺得我們該先做什麼？\n\n吉尼會聽。', '', 66384),
(299888, 'zhTW', '喔…隊名是什麼？', '', 66384),
(299880, 'zhTW', '名字很重要。它告訴觀眾我們是誰，也告訴我們自己是誰。\n\n「綻光守衛」？「孢光」？\n\n不，「孢誓」感覺最棒。', '', 66384),
(299879, 'zhTW', '希望到時候，布拉寇準備好。布拉寇會準備好！\n\n$p要什麼？$p準備好了嗎？', '', 66384),
(299878, 'zhTW', '好問題。我們需要名字。沒有名字，不能戰鬥！也不能在坑內一起喊出名字！\n\n「根結者」可以當名字。「柄衛隊」？\n\n不對，「環帽」！環帽是最好的隊名！', '', 66384),
(299876, 'zhTW', '好多好多！要最好名字！要想很多名字，找最好！\n\n「蘑菇部隊」很好，但已經被…「蘑菇部隊」用了。「噴孢仔」？「碎傘者」？「蓬衛」！\n\n蓬衛是最好名字！', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(299874, 'zhTW', '能組成隊伍真是令人興奮！我等不及要和$p一起去坑內，展現…我們的強大。\n\n圖圖的毒很厲害！', '', 66384),
(299872, 'zhTW', '', '別讓它利用你的疑慮！', 66384),
(299862, 'zhTW', '祖爾賈拉，我上次去阿奇爾森神廟的時候，你也跟著我去了。', '', 66384),
(299861, 'zhTW', '', '以前的很多做法都跟現在不一樣。', 66384),
(299860, 'zhTW', '在我們那個時候，我們學習使用武器時，一次只揮一下！', '', 66384),
(299829, 'zhTW', '', '哈瓦札就在附近。她看起來更強大了，那個生物也不打算吃她。', 66384),
(299828, 'zhTW', '喔！今天的風兒很平靜，我的小寶貝到處都是！\n它們是不是很賞心悅目？\n\n所以，你是帶了閃亮粉塵來進行交易，或只是來這裡被我的珍藏迷倒？', '喔！今天的風兒很平靜，我的小寶貝到處都是！\n它們是不是很賞心悅目？\n\n所以，你是帶了閃亮粉塵來進行交易，或只是來這裡被我的珍藏迷倒？', 66384),
(299824, 'zhTW', '', '我們走吧。', 66384),
(299820, 'zhTW', '趕快做修繕工作。如果不小心點，我們就會落得那樣的下場！', '', 66384),
(299814, 'zhTW', '', '$n！小心點，別讓它逃了。快抓住它！', 66384),
(299813, 'zhTW', '', '哈瓦札，你可以來…', 66384),
(299812, 'zhTW', '抓住他們！！', '', 66384),
(299810, 'zhTW', '他們快要掙脫了…！', '他們快要掙脫了…！', 66384),
(299809, 'zhTW', '等等…', '等等…', 66384),
(299807, 'zhTW', '完美的犧牲品！', '', 66384),
(299806, 'zhTW', '', '真是慘不忍睹！你們全都失職了！', 66384),
(299804, 'zhTW', '', '講羅亞的事已經沒意義了。祂們很久以前就拋下我們。去看看難民的狀況吧。', 66384),
(299802, 'zhTW', '', '它感覺不像是鬼魂，比較像是復仇的怪物。虛無風暴裡都是這些東西。\n\n我記得自己看過相關的資料。我需要更多情報來縮小範圍。把你的觀察紀錄都帶來給我。', 66384),
(299800, 'zhTW', '', '我記得自己有關於卡到陰的資料。或者說，假冒成卡到陰的東西。\n\n我正在查看我的筆記。', 66384),
(299788, 'zhTW', '', '真可憐。沒有任何藥水可以矯正你的體態…或體味。', 66384),
(299787, 'zhTW', '', '別把任何東西打破了。這裡的草藥比你還有價值。', 66384),
(299786, 'zhTW', '', '如果你在找戀愛藥水，先試試看面帶微笑。有效又實惠。', 66384),
(299785, 'zhTW', '', '對啦，對啦，所有東西都是有機的。除了我的耐心，在兩個客人之前就用光了。', 66384),
(299784, 'zhTW', '你好，尊貴的旅行者！\n\n要來一杯檸檬水嗎？只要兩枚銀幣就好，保證清涼爽口，還能幫助我們為托育所購置書本！你也支持托育所事業，對吧？\n\n美味和善行全都濃縮在這一杯裡！', '你好，尊貴的旅行者！\n\n要來一杯檸檬水嗎？只要兩枚銀幣就好，保證清涼爽口，還能幫助我們為托育所購置書本！你也支持托育所事業，對吧？\n\n美味和善行全都濃縮在這一杯裡！', 66384),
(299764, 'zhTW', '偶爾跟老朋友聚一聚的感覺真不錯。', '', 66384),
(299762, 'zhTW', '', '這樣就行了。這生物真可怕。', 66384),
(299761, 'zhTW', '', '老實說，在一切開始出錯之前，這個地方其實已經變得有點無聊了。\n\n哦，對啦，這裡很美。還有其他優點嗎？', 66384),
(299760, 'zhTW', '', '每年的這個時候，樹葉都很美。應該說，一年四季都很美。', 66384),
(299759, 'zhTW', '即使過去這麼多年，還是要有人盯緊這些精靈。\n\n<塔泰發出輕笑。>', '', 66384),
(299758, 'zhTW', '', '這麼奢華的城市會讓人漸漸習慣。', 66384),
(299748, 'zhTW', '這只不過是原型！', '', 66384),
(299747, 'zhTW', '風暴未曾停歇，但你可以在這稍作休息。', '', 66384),
(299746, 'zhTW', '', '如果我沒有被它大幅削弱，絕對能輕鬆擊敗它。', 66384),
(299745, 'zhTW', '去吧。動作快，莉雅德倫手上的阿曼尼問題急需協助。', '', 66384),
(299744, 'zhTW', '這地方的寒冷、飢餓…這個世界非常適合我們。但我卻毫無感覺。\n\n我羨慕同族的熱情。但我知道自己的真面目。我是一個怪物，只為了殺戮而生。\n\n如果你還沒接受的話，現在接受吧。我們只剩下這些了。', '', 66384),
(299740, 'zhTW', '', '我知道它喜歡吃什麼了。熾熱裹布能讓它以為是能吞噬的靈魂。', 66384),
(299739, 'zhTW', '我了解。就算是在我們刃多雷當中，細節還是很模糊。\n\n就像我一樣，我們很多人都曾在博學者殿堂學習。洛摩斯曾是我的導師。\n\n我覺得我們必須了解我們的敵人，才能擊敗他們。於是我帶領一群研究人員研究虛無。我們發現了達克汗‧崔希爾的日誌，也就是那個背叛銀月城、投靠巫妖王的精靈。在第三次大戰中，他的行動導致許多我們珍視的事物毀於一旦。而他對虛無的研究促成了這個結果。\n\n所以，你可以理解，即使血精靈使用魔能等危險魔法的歷史很漫長，我們的研究卻還是遭到指責。我們拒絕停止，於是就遭到流放。\n\n我不後悔自己的選擇，雖然這讓我的同伴飽受折磨。', '', 66384),
(299738, 'zhTW', '', '你這麼做到底是跟誰學的？', 66384),
(299737, 'zhTW', '謝謝你，$p。\n\n希望你不會後悔踏上把我和你一起引來這裡的道路。如果你願意讓我肉麻一下…我會說我很高興你在這裡。\n\n在這條路上，我們失去了許多。有些人臣服於虛無，有些人在瘋狂中迷失自我…\n\n不過你在這裡。如果你曾經懷疑自己的力量、自己的韌性，請記住：\n\n你在這裡。那樣就夠了。\n\n謝謝你。', '', 66384),
(299735, 'zhTW', '其他人休息的時候我可以負責站哨。\n\n那些野獸還不知道何謂恐懼。我們會教他們的。', '', 66384),
(299734, 'zhTW', '博學者殿堂。\n\n我在這裡渡過我的年輕歲月。在這裡學會第一個法術。在仲夏舞廳，與莎蘿法‧金幕共舞，感覺…\n\n<奧姆里克嘆了口氣。>\n\n那些歲月早已不復存在。這個地方變了，我也變了。像你我這樣的人不再受到歡迎。\n\n過往一去不復返。刃多雷必須打造自己的傳統，自己的家庭。\n\n自己的未來。', '', 66384),
(299733, 'zhTW', '好的核心工匠會隨時準備好工具。', '', 66384),
(299729, 'zhTW', '我得救了！\n\n暮光之刃綁架了我，還有其他人受困！你必須在為時已晚前救出他們！\n\n鑰匙在那裡，先幫幫我，好嗎？', '我得救了！\n\n暮光之刃綁架了我，還有其他人受困！你必須在為時已晚前救出他們！\n\n鑰匙在那裡，先幫幫我，好嗎？', 66384),
(299728, 'zhTW', '那邊的！拜託快來幫我！', '那邊的！拜託快來幫我！', 66384),
(299726, 'zhTW', '力量強度最大化！', '', 66384),
(299724, 'zhTW', '你怎麼敢？!\n\n馬上把我的大鍋還給我，否則遠超你想像的後果將會降臨在你身上。\n\n遠超你想像，我告訴你！', '', 66384),
(299723, 'zhTW', '那些惱人的馬鈴薯蟾蜍從實驗中逃脫了。我正在調配全新的超肥沃土壤。\n\n你不用在意這個。那是魯坦尼的事。順便警告你…別亂動我的大鍋！\n\n<克梅特大聲地喃喃自語，彷彿你不在現場。>\n\n這個地方太危險了。我們應該做點什麼。現在，我要怎麼回到綻放臺地？', '', 66384),
(299721, 'zhTW', '', '噢，我能放心了。它想要$n，不是我。', 66384),
(299719, 'zhTW', '它快來了…', '', 66384),
(299718, 'zhTW', '虛無...太震撼了...', '虛無...太震撼了...', 66384),
(299712, 'zhTW', '再等一下下...', '', 66384),
(299711, 'zhTW', '', '我從沒看過羅阿克連續傳送那麼多次。光是魔法的反作用就讓我牙痛地好厲害。這裡虛無滿溢，不分善惡。\n\n他會沒事的。我會確保他沒事。', 66384),
(299702, 'zhTW', '你拿到最後一個導體了嗎？記得把它送過來。', '', 66384),
(299701, 'zhTW', '別忘了傳送導體。', '', 66384),
(299699, 'zhTW', '', '不！它來找我了。', 66384),
(299698, 'zhTW', '', '就在那裡！在我們後面！', 66384),
(299696, 'zhTW', '', '還記得可怕的椅子嗎？這次一定要讓它待在地上。', 66384),
(299694, 'zhTW', '', '不能無差別亂吃了，小傢伙。', 66384),
(299693, 'zhTW', '', '奧姆里克的追隨者見過了許多的世界。我們擊潰了虛無的前線戰力。勝過了影衛。\n\n星外暗界的孤獨中常有著獨特的美。憂傷。沉靜。\n\n在這裡就沒那麼好運了。這個世界是個獵食場。你必須隨時保持警戒。', 66384),
(299692, 'zhTW', '總有一天，我就不需要自己買花來畫了。', '', 66384),
(299687, 'zhTW', '總有一天，我會把這些花送給某人…', '', 66384),
(299679, 'zhTW', '', '洛斯拉賽恩！別再執迷不悟了。我們已經獲勝了！', 66384),
(299674, 'zhTW', '', '你打斷我的儀式了。', 66384),
(299673, 'zhTW', '金此刻需要你，兄弟。', '', 66384),
(299669, 'zhTW', '我…謝謝你，姐姐。希望你是對的。', '', 66384),
(299668, 'zhTW', '', '往日不再，詹，但我不會讓你在我之下枯萎。你仍舊是我的副手和弟弟。', 66384),
(299667, 'zhTW', '祖爾詹瞇起雙眼。', '', 66384),
(299666, 'zhTW', '', '這也代表忘卻我們自己。但還是得和羅亞合作，還有入侵者。', 66384),
(299665, 'zhTW', '', '我不是故意要吼你。我知道你的立場是什麼。我們都很難忘懷祖父的形象。', 66384),
(299664, 'zhTW', '', '祂們離開是因為差點被殺掉…被我們的祖父和那個瑪拉克雷斯。', 66384),
(299663, 'zhTW', '是的。但如果我們變得依賴他們，而祂們又消失了呢？祂們上次離開，我們備受打擊。', '', 66384),
(299661, 'zhTW', '$p，抗拒它！是你控制著暗影，不要被它控制了！', '', 66384),
(299660, 'zhTW', '', '都不是！你難道不曉得我們和羅亞的關係建立於信任，而非力量嗎？', 66384),
(299659, 'zhTW', '我來問問妳，姐姐：是你臣服於羅亞，還是羅亞聽命於你？', '', 66384),
(299658, 'zhTW', '', '你不喜歡羅亞的回歸。為什麼呢？羅亞一直都是我們文化的一部分。', 66384),
(299657, 'zhTW', '我很高興能擊潰暮光之刃，也很高興你快樂。', '', 66384),
(299656, 'zhTW', '', '為什麼呢？你不為勝利開心嗎？那羅亞的回歸呢？還有你的姐姐成為哈謝呢？', 66384),
(299655, 'zhTW', '姐姐，原諒我，我沒有什麼心情慶祝。', '', 66384),
(299654, 'zhTW', '', '啊，弟弟，看來哈巫拉找到你了。你怎麼沒來派對？我知道你很愛跳舞！', 66384),
(299649, 'zhTW', '我看到你的眼睛睜大了，「哈巫拉」。你是對的。忘了我說的話吧。我們贏了。祖爾賈拉贏了。', '', 66384),
(299648, 'zhTW', '祂們拋棄了我們。是祂們、拋棄了、我們！誰知道會不會重演？', '', 66384),
(299646, 'zhTW', '羅亞說我們的祖父，偉大的祖爾金背叛了祂們。但憑什麼相信祂們？相信傻子叔叔？或是任何入侵者？', '', 66384),
(299644, 'zhTW', '祖爾賈拉不懂我的遠見，但這是唯一的方法。羅亞？哼。', '', 66384),
(299643, 'zhTW', '莫爾頓出現時，我看見我對阿曼尼未來的夢想成真。有了光木，我們就能征服暮光之刃，再來就是永歌森林。', '', 66384),
(299637, 'zhTW', '我卻看見了阿曼尼的力量…我們的力量。我們應該征服周圍的一切！祖爾賈拉就是不懂。', '', 66384),
(299635, 'zhTW', '我們對阿曼尼意見不同。祖爾賈拉重視壯大和保存祖阿曼內部的阿曼尼部族。', '', 66384),
(299632, 'zhTW', '我永遠沒辦法成為像祖爾賈拉的戰士。我靠口才解決問題。她，卻總是自己動手。', '', 66384),
(299630, 'zhTW', '母親去世時，我們都還小。姐姐靠著意志力讓部族免於分裂…不需要羅亞。', '', 66384),
(299617, 'zhTW', '希望他們不會忘記我的存在…', '希望他們不會忘記我的存在…', 66384),
(299616, 'zhTW', '我不知道要躲在哪裡比較好！', '我不知道要躲在哪裡比較好！', 66384),
(299615, 'zhTW', '噓！別讓追尋者找到你！', '噓！別讓追尋者找到你！', 66384),
(299614, 'zhTW', '1... 2... 3...\n\n7... 8... 9...', '1... 2... 3...\n\n7... 8... 9...', 66384),
(299613, 'zhTW', '陰險幻影前來吞噬死者！', '陰險幻影前來吞噬死者！', 66384),
(299607, 'zhTW', '好啦！好啦，我招了！他們在死亡之域！', '好啦！好啦，我招了！他們在死亡之域！', 66384),
(299606, 'zhTW', '', '動手吧，$p。', 66384),
(299605, 'zhTW', '', '至少，如果不告訴我們，你一定會後悔。', 66384),
(299604, 'zhTW', '', '我們甚至會饒你一命！', 66384),
(299603, 'zhTW', '', '要是你告訴我們他們在哪裡，就不會這麼痛苦了。', 66384),
(299602, 'zhTW', '', '我們知道你抓走了我的…你抓走了我們的朋友。他們在哪裡？', 66384),
(299601, 'zhTW', '', '你有看到它對標記的失敗者做些什麼嗎？\n\n我才不會是下一個！', 66384),
(299600, 'zhTW', '對，因為布拉寇已經很強。但也需要隊伍，也需要老師。\n\n等看完後去找你。', '', 66384),
(299599, 'zhTW', '在找強者嗎？', '', 66384),
(299598, 'zhTW', '好，我們加入。\n\n一直都想要隊伍，交朋友！\n\n等等去找你。', '', 66384),
(299597, 'zhTW', '你！之前在坑中見過你。', '', 66384),
(299596, 'zhTW', '好機會！要打起精神。\n\n快去組隊。等看完比賽再見！', '', 66384),
(299595, 'zhTW', '有什麼事嗎？', '', 66384),
(299593, 'zhTW', '走開！我只是觀眾。', '', 66384),
(299592, 'zhTW', '呃...下次吧！', '', 66384),
(299591, 'zhTW', '我不強。', '', 66384),
(299590, 'zhTW', '不要，我很忙。', '', 66384),
(299576, 'zhTW', '仔細看，但千萬別掉進坑洞裡！那會要了你的命。', '', 66384),
(299573, 'zhTW', '我在怨鬥坑洞見過你！你很強。', '', 66384),
(299569, 'zhTW', '坑洞中有許多強大的生物。', '', 66384),
(299561, 'zhTW', '', '對屍體使用烙印。那會引誘它去吃屍體。', 66384),
(299560, 'zhTW', '', '如果餵飽它，它應該會暫時不再纏著我…我是說你啦。我相信一定有辦法擺脫它。', 66384),
(299559, 'zhTW', '', '我是在一場決鬥中得到的。有人想讓它吃我，但我把他們都殺了。之後，它就一直跟著我，不斷汲取我的力量。\n\n起初我以為它會吃掉我的對手，這點我覺得無傷大雅。它也確實做到了，不過它都會回來繼續想吞噬我。我曾是…現在也是…練武場最厲害的決鬥者。', 66384),
(299557, 'zhTW', '', '我太虛弱了，沒辦法跟你戰鬥。我們可以談談嗎？', 66384),
(299536, 'zhTW', '你發現的真相…太驚人了！我們的神聖圖畫不單純只是混合…還能被喚醒。而在回音大鍋中，它們獲得第一縷生氣。', '', 66384),
(299523, 'zhTW', '我現在知道了。你帶回來給我們的不只是聖物的故事…還提醒我們偉南的教訓。謝謝你！', '', 66384),
(299522, 'zhTW', '艾恩哈拉未意外留下任何痕跡。花並不是禮物…而是承諾。鮮活、神聖、真實。謝謝你揭露其故事的真相。', '', 66384),
(299521, 'zhTW', '回音不會說謊。它們循環往復，只讓夠有勇氣的人聽見。去吧，帶著過去的聲音回來。', '', 66384),
(299520, 'zhTW', '去吧。把你的手放在石頭上，用你的靈魂經歷回憶。迎接你的或許並不友好…但必定真實。', '', 66384),
(299519, 'zhTW', '靜靜地站在她曾經降臨的地方…是莫大的殊榮。去吧，用耳朵聽，也用心聽。', '', 66384),
(299497, 'zhTW', '', '來吧，穿過傳送門。', 66384),
(299496, 'zhTW', '', '結束了…', 66384),
(299493, 'zhTW', '這是我的！別想搶走它！', '這是我的！別想搶走它！', 66384),
(299491, 'zhTW', '<血騎士的臉上浮現出邪惡的猙獰表情，紅光在眼中閃爍。>', '<血騎士的臉上浮現出邪惡的猙獰表情，紅光在眼中閃爍。>', 66384),
(299490, 'zhTW', '全是妄想和謊言！我知道試圖偷走我胸針的人是你。', '全是妄想和謊言！我知道試圖偷走我胸針的人是你。', 66384),
(299489, 'zhTW', '原本一切都很好…直到我意識到我的訓練夥伴試著偷走我的寶石！', '原本一切都很好…直到我意識到我的訓練夥伴試著偷走我的寶石！', 66384),
(299487, 'zhTW', '<那些大師正在激烈爭執。>', '<那些大師正在激烈爭執。>', 66384),
(299486, 'zhTW', '城市的色彩更加明亮，食物的香氣更加豐富。太美妙了！', '城市的色彩更加明亮，食物的香氣更加豐富。太美妙了！', 66384),
(299484, 'zhTW', '<那個精靈手中緊抓著一條珠寶項鍊，呆滯地看著四周。>', '<那個精靈手中緊抓著一條珠寶項鍊，呆滯地看著四周。>', 66384),
(299455, 'zhTW', '嗯。你對工藝有什麼了解？', '', 66384),
(299454, 'zhTW', '很榮幸能夠看到這種精湛工藝出自何人之手。', '', 66384),
(299416, 'zhTW', '索爾溫‧亮縫臉紅了，但並未再多說什麼。', '', 66384),
(299415, 'zhTW', '我堅持跟你一起去。你的麻煩就是我的麻煩。', '', 66384),
(299414, 'zhTW', '你知道的，為了這個，我得繞很大一圈。', '', 66384),
(299393, 'zhTW', '侍僧啊，這真是傑出的成果！', '', 66384),
(299391, 'zhTW', '偵測到威脅！', '', 66384),
(299386, 'zhTW', '…好吧。我會幫忙修補，不過，這是因為處理這種華麗織物的機會太難得了。', '', 66384),
(299385, 'zhTW', '這件披風純粹由薩拉斯奧紋布製成！是難得一見的精緻織物…', '', 66384),
(299384, 'zhTW', '我的需求很簡單。這件披風從我加入破碎之日起一直用到現在，它需要修補一下。', '', 66384),
(299367, 'zhTW', '', '謝謝你的協助。$n，下次見。', 66384),
(299366, 'zhTW', '', '我們這次的行動對他們造成重創。希望這能夠趕跑他們。', 66384),
(299365, 'zhTW', '', '暮光之刃出手不分黑白，無論哪個陣營都一樣。', 66384),
(299364, 'zhTW', '', '我們回到銀月城吧。這地方…讓我想起討厭的回憶。', 66384),
(299363, 'zhTW', '', '殺得漂亮。對這傢伙來說太奢侈了。', 66384),
(299362, 'zhTW', '', '大致上算是一場簡單的救援行動。但免不了還是藏著許多難題。', 66384),
(299310, 'zhTW', '', '住手！', 66384),
(299301, 'zhTW', '', '這應該有用了。我的研究從來沒失敗過！', 66384),
(299300, 'zhTW', '', '我已經在這裡放好不祥之物。過來看看。', 66384),
(299297, 'zhTW', '讓光綻吞噬我，或是將我從這個光輝的成長中釋放，但是別用空虛的話語浪費我的時間！', '', 66384),
(299281, 'zhTW', '', '小心點，她是影衛。帶著多疑的心收集情報。', 66384),
(299277, 'zhTW', '', '我們應該談談。', 66384),
(299271, 'zhTW', '', '嘿！你被什麼看不見的東西弄傷了嗎？', 66384),
(299267, 'zhTW', '<歐薇娜的瓣翼鳥充滿期待地看著你。>', '<歐薇娜的瓣翼鳥充滿期待地看著你。>', 66384),
(299258, 'zhTW', '', '歡迎來到我們的藥劑室，$p。這裡是休息和探索的地方。\n\n至於那些秘能樣本，我不清楚它們的原主人是誰，所以我其實無法歸還它們。\n\n我正在嘗試進行注入。每個人的秘法味道各有不同…可能甜甜的、酸酸的，或者說比起味道，更像是一種感覺…我最常聽說的是氣泡感。', 66384),
(299257, 'zhTW', '<遊俠維多蘭的眼睛失去神采，他的呼吸極淺，不過至少還算穩定。>\n\n克羅南？…克羅南，我們這次是惹到什麼麻煩了？', '', 66384),
(299256, 'zhTW', '瀕臨死亡可不在我今天的待辦事項上。維多蘭差一點就能把箭矢直直射入那個納迦的頭顱，但她反應太快了，就像是她早就知道我們在那裡。她在戲耍我們。\n\n<克羅南喝了一口酒。>\n\n嗯，這的確讓我覺得好多了。\n\n謝謝你，$p。我們欠你一個人情。', '', 66384),
(299255, 'zhTW', '如果不是你出手相助，我早就失去我麾下的兩個遊俠…兼朋友。\n\n正是像金霧村這樣的村莊，讓銀月城立於不敗之地。如果我們的小鎮淪陷，城市本身一定也無法倖免。這就是遠行者之道。\n\n遊俠維多蘭或許不會徹底痊癒。無論我們與魔法的關係為何，秘法都是我們生命精華的關鍵部分。納迦公主本來會抽乾他身上的秘法能量。\n\n<海斯維利看了努米雅一眼，神情變得輕鬆。>\n\n努米雅告訴我她正在研究一些東西。注入秘法的酒…聽起來很值得期待。', '', 66384),
(299253, 'zhTW', '你很清楚影松不聽從任何指示。我們隨意而行，只遵循心中火焰的指引。', '', 66384),
(299252, 'zhTW', '', '祖爾賈拉，惡齒最優秀的鐵匠正在修理我們的武器。', 66384),
(299251, 'zhTW', '', '我們正在盡速趕工。但是我們的武器很多都因為襲擊壞掉了。', 66384),
(299244, 'zhTW', '', '事情還沒結束。幕後的主謀過於危險，不能讓他活下去。', 66384),
(299243, 'zhTW', '', '用能量讓他們的裝置超載！', 66384),
(299242, 'zhTW', '', '多麼脆弱的裝置。用秘法能量讓它超載，然後準備看煙火吧。', 66384),
(299241, 'zhTW', '', '過度好奇的蠢貨。他們竟然在對虛無能量進行實驗！', 66384),
(299240, 'zhTW', '', '快把能量送到傳送門去！', 66384),
(299239, 'zhTW', '', '這麼想要阻止我們，啟動那座傳送門來看看原因吧。', 66384),
(299238, 'zhTW', '', '刻不容緩。我該回到哈朗達了。', 66384),
(299233, 'zhTW', '祖爾詹怒視著祖爾賈拉。', '', 66384),
(299232, 'zhTW', '', '戰士們，放心回到家人的身邊吧。我們會照顧死者的。', 66384),
(299228, 'zhTW', '', '我會跟布雷克一起待在這裡。以防他突然恢復正常。或是決定出去亂跑。', 66384),
(299201, 'zhTW', '我認為戴上它們的人會精力旺盛、體魄強健。', '', 66384),
(299200, 'zhTW', '', '太好了。我們到那邊見。', 66384),
(299199, 'zhTW', '', '你在邪教這裡坐夠久了。該走了。', 66384),
(299198, 'zhTW', '', '他們馬上就會開始找你了。快跑吧。', 66384),
(299197, 'zhTW', '', '你自由了。趁還來得及快走吧。', 66384),
(299196, 'zhTW', '', '鎖鍊解開了。快走，別回頭。', 66384),
(299193, 'zhTW', '', '我看得夠多了。我們必須立刻解放俘虜。折磨他們的人可有得受了。', 66384),
(299192, 'zhTW', '', '他們還蓋了一座堡壘…', 66384),
(299190, 'zhTW', '紅菇說要停止打架，不過蘑菇不聽，植物不聽，沒人願意聽！\n\n打得越來越激烈，植物打蘑菇，蘑菇打植物。\n\n紅菇有阻止這一切的計畫…奇怪的傢伙，可能有用。\n\n首先，需要變大！', '紅菇說要停止打架，不過蘑菇不聽，植物不聽，沒人願意聽！\n\n打得越來越激烈，植物打蘑菇，蘑菇打植物。\n\n紅菇有阻止這一切的計畫…奇怪的傢伙，可能有用。\n\n首先，需要變大！', 66384),
(299189, 'zhTW', '', '他剛剛是…直接用手把燃燒的柴薪交給你嗎？', 66384),
(299162, 'zhTW', '', '勇士。\n\n我的時間不多。需要什麼？', 66384),
(299145, 'zhTW', '你！有腦子的鬥士！快來，需要和談！', '你！有腦子的鬥士！快來，需要和談！', 66384),
(299135, 'zhTW', '在你想的時候，我不介意吃點東西、喝點酒。孩子，跟我們一起來吧。$n，你也是。', '', 66384),
(299134, 'zhTW', '看來我得想想該怎麼處理這面盾牌。', '', 66384),
(299130, 'zhTW', '太陽之井不能再這樣下去。我們開始在這場僵局中落入下風了。\n\n很快，薩拉塔斯就會大舉進攻。', '', 66384),
(299121, 'zhTW', '噢，別擔心，這堂課並非由我來傳授。', '', 66384),
(299110, 'zhTW', '我現在沒辦法面對集結在太陽之井的那些人。', '', 66384),
(299105, 'zhTW', '血色十字軍是由我任命的一位聖騎士成立的。長久以來，我都認為他是我判斷錯誤的後果。也許我仍然這麼覺得。', '', 66384),
(299078, 'zhTW', '', '在下知道了…不拿起武器。\n\n真有趣。', 66384),
(299077, 'zhTW', '你來這裡卻沒有帶肥料？\n太可疑了…', '你來這裡卻沒有帶肥料？\n太可疑了…', 66384),
(299076, 'zhTW', '', '如果你再繼續亂動，就會迎來漫長且痛苦的死亡！', 66384),
(299068, 'zhTW', '聖光先鋒對聖光有信念，我也一樣。但我也感覺到它讓我充滿怒火，我…我不知道該怎麼面對這件事。', '', 66384),
(299062, 'zhTW', '', '我們急需你的幫助。讓聖光帶你到奎爾達納斯找我吧。', 66384),
(299060, 'zhTW', '', '我們去看看萊希卡斯有什麼發現。讓那些野獸自己盡情「玩耍」吧。', 66384),
(299059, 'zhTW', '', '挺有效的，不過下次要炸東西之前，先跟我說一聲。', 66384),
(299058, 'zhTW', '', '屏障？所以他們的領袖既是小偷，也是個懦夫。', 66384),
(299057, 'zhTW', '', '從不情願的受害者身上榨取法力？真可悲，這種罪行對我的族人而言再熟悉不過。', 66384),
(299056, 'zhTW', '不，我親愛的姪女賈拉。我清楚知道你有那把火焰。而且我愛你勝過一切。', '', 66384),
(299055, 'zhTW', '', '那我走了。為了族人，也為了你，叔叔。', 66384),
(299053, 'zhTW', '', '作為「哈謝」？我不是什麼祭司。也沒辦法凝聚眾人。', 66384),
(299052, 'zhTW', '如果有人能從羅亞那裡得到答覆，那一定是你。', '', 66384),
(299045, 'zhTW', '', '你會需要風瑪利昂核心來建構堡壘內部的防禦工事。這些防禦工事是奇異點錨啟動之後確保安全的關鍵。\n\n你想進一步了解防禦工事的細節嗎？', 66384),
(299042, 'zhTW', '', '風瑪利昂堡壘對傳送門和虛無異象做了無數次的實驗。\n\n我們製造的奇異點錨，可以用來消除這個區域的危險。一旦啟動，它就能中和此處殘留的虛無能量。\n\n薩拉塔斯和吞噬之眾肯定會很火大的！', 66384),
(299015, 'zhTW', '', '孤身於黑暗中，絕望，卻仍渴求力量。真是合適的結局。', 66384),
(298877, 'zhTW', '聖光會淨化一切！', '', 66384),
(298876, 'zhTW', '你將會嚐到聖光的怒火！', '', 66384),
(298875, 'zhTW', '撐著點！我來救你了！', '', 66384),
(298874, 'zhTW', '呃…聖光守護者…我們…最後…像他們…', '', 66384),
(298872, 'zhTW', '你無法阻止聖光的意志！', '', 66384),
(298866, 'zhTW', '你等著看吧。', '', 66384),
(298863, 'zhTW', '你為什麼要背棄聖光？', '', 66384),
(298862, 'zhTW', '你的死亡只會讓我感到愉悅。', '', 66384),
(298861, 'zhTW', '你自己選擇違背聖光的意志。', '', 66384),
(298860, 'zhTW', '這太有趣啦！', '', 66384),
(298858, 'zhTW', '看來你需要推一把。', '', 66384),
(298854, 'zhTW', '怎麼了？太重了嗎！', '', 66384),
(298845, 'zhTW', '', '北方的以太能量正受到干擾。去拿一把以太工具。你就能收穫那些能量，還能完成其他工作。', 66384),
(298844, 'zhTW', '', '以太力量正在恢復，但依然受到干擾。拿把工具開挖，看看究竟是怎麼回事。', 66384),
(298843, 'zhTW', '', '干擾停止了，至少目前如此。', 66384),
(298839, 'zhTW', '小心水花。', '', 66384),
(298836, 'zhTW', '好吵啊！', '', 66384),
(298835, 'zhTW', '歐薇娜、$n！謝天謝地啊！永歌森林狀況危急！', '', 66384),
(298834, 'zhTW', '正當你在艾恩裂隙中尋找答案時，我回了銀月城一趟，向博學者請教。\n\n我們還來不及討論我們的發現，就收到來自遠行者居所北邊的符石的消息。有某種事物讓光綻陷入暴走。如果我們不立刻行動，整個永歌森林可能都會淪陷。\n\n我只盼望歐薇娜的長老能夠認清威脅正在步步進逼的現實。', '', 66384),
(298833, 'zhTW', '', '同進退。', 66384),
(298832, 'zhTW', '', '不論何種形式，我都會帶著你們一起走向明天。', 66384),
(298831, 'zhTW', '', '加雷爾…我希望你找到了生前始終無法得到的平靜。', 66384),
(298830, 'zhTW', '', '但已經癒合的傷疤，依然會存在。', 66384),
(298829, 'zhTW', '', '你教我的不只如此。你的指導，讓我知道怎麼活下去。', 66384),
(298828, 'zhTW', '最好把耳朵遮住！', '', 66384),
(298827, 'zhTW', '', '我不想問你是否以我為傲。你看得到我的雙手，沾滿了鮮血。', 66384),
(298826, 'zhTW', '', '但我的雙手因為恐懼而顫抖，疑慮依然蒙蔽著我的心靈。', 66384),
(298825, 'zhTW', '', '聖光回應了，凡德洛。我毫不退縮，所以它回應了我。', 66384),
(298824, 'zhTW', '你擊敗了我的奧托薩斯？真是可口啊！', '', 66384),
(298821, 'zhTW', '有我、維多蘭和$p在，你沒什麼好擔心的，隊長。', '', 66384),
(298820, 'zhTW', '我們會帶著好消息回來，隊長。', '', 66384),
(298819, 'zhTW', '你的下場如此是非常合理的。', '', 66384),
(298818, 'zhTW', '見識我的奧托薩斯吧！', '', 66384),
(298817, 'zhTW', '別被打中了。', '', 66384),
(298816, 'zhTW', '勇敢點。', '', 66384),
(298815, 'zhTW', '我都忘記那尊雕像在這裡了。', '', 66384),
(298814, 'zhTW', '你撐得住的！', '', 66384),
(298797, 'zhTW', '這會很痛的。', '', 66384),
(298796, 'zhTW', '別鬆懈！', '', 66384),
(298794, 'zhTW', '我在這！', '', 66384),
(298792, 'zhTW', '', '攻擊個別的光綻是沒用的。我們必須採取激烈手段。', 66384),
(298791, 'zhTW', '女神啊…', '', 66384),
(298790, 'zhTW', '', '他們看來迫不及待想為他而死。我們就別讓他們久等了。', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(298789, 'zhTW', '', '我已經調集所有牧師來對抗虛無了。雖然無法擊退吞噬之眾，但應該能防止不速之客前來玷汙這個地方。', 66384),
(298788, 'zhTW', '', '我很擔心虛無精靈會偷偷回來這裡，破壞我們在太陽之井的計畫。', 66384),
(298787, 'zhTW', '維諾，你說的算。只是感覺我們好像已經惹毛不少人了。', '', 66384),
(298785, 'zhTW', '謝謝你的擔憂。對我的族人來說，聖光與太陽之井是一樣的。他們或許會抱怨，但還是會接納聖光先鋒。', '', 66384),
(298782, 'zhTW', '我的死期怎麼還沒到？', '', 66384),
(298781, 'zhTW', '你為什麼這麼弱？', '', 66384),
(298780, 'zhTW', '艾恩之塵讓我們族人的力量勝過大自然。這應該足以對抗光綻的迅速生長。', '', 66384),
(298776, 'zhTW', '我迫不及待看到你們全都去死！提拉，摧毀他們！', '', 66384),
(298774, 'zhTW', '即使在我勝利的這個瞬間，我依然得在她面前低聲下氣！', '', 66384),
(298773, 'zhTW', '', '當然，前提是你願意接受它。', 66384),
(298772, 'zhTW', '', '又來找我麻煩。我上次的傷口都還沒復原！', 66384),
(298770, 'zhTW', '', '這一切…都是為了那個該死的薩拉塔斯…', 66384),
(298769, 'zhTW', '', '暮光之刃會為他們傷害的每個人付出代價。', 66384),
(298767, 'zhTW', '', '這全是因為你的影衛沒在她取得力量之前把她抓起來。', 66384),
(298766, 'zhTW', '我的工作還沒完成…還沒…', '', 66384),
(298764, 'zhTW', '', '薩哈達爾，看來你有客人來了。記得我們剛剛說好的。', 66384),
(298759, 'zhTW', '', '你會受到無止盡的折磨。', 66384),
(298746, 'zhTW', '', '隊長，接下來的二十四小時，請別再逞英雄了。好好休息，喝點小酒。如果痛苦加劇，馬上來找我。', 66384),
(298745, 'zhTW', '但他們卻沒這麼做。他們消耗了一些，剩下的送上船運到無盡之海。', '', 66384),
(298744, 'zhTW', '', '納迦已經收集到夠多的秘能，足以毀滅整座村莊。', 66384),
(298741, 'zhTW', '她就是這麼告訴薩哈達爾的。或許真相正是如此。', '', 66384),
(298733, 'zhTW', '即便是普通大小的化身，產出的艾恩之塵也非常少。只是一根針頭的份量，也需要花上好幾年的時間收集。', '', 66384),
(298732, 'zhTW', '', '不能從比較弱的獵物身上收集艾恩之塵嗎？', 66384),
(298729, 'zhTW', '', '他正在利用它們打開傳送門！別讓他逃走！', 66384),
(298728, 'zhTW', '', '那個懦夫製造了一道屏障，去摧毀虛無法器來讓它失效。', 66384),
(298727, 'zhTW', '溫度太高了！在盾牌上灑點冷水降溫吧。', '', 66384),
(298726, 'zhTW', '', '安諾里恩這臭蟲，爬到這裡來真是再合適不過。', 66384),
(298725, 'zhTW', '聖物已經送達，至少太陽之井現在是安全的。', '', 66384),
(298721, 'zhTW', '$n，謝謝你。我們意志堅定，但肉身有其極限。這些聖物能支撐我們一段時間。', '', 66384),
(298719, 'zhTW', '$n，你能幫忙遞送聖物嗎？我需要跟阿拉特私下談談。', '', 66384),
(298717, 'zhTW', '阿拉特，我不是刻意要增加你的負擔。前往教堂是拯救太陽之井必經的旅程。', '', 66384),
(298714, 'zhTW', '不，阿拉特。我衷心希望你能找到另一條路。', '', 66384),
(298713, 'zhTW', '這就是屬於聖騎士的命運嗎？死去化為傳奇，或是活著被狂熱與憤怒吞噬？', '', 66384),
(298712, 'zhTW', '', '能走到這裡都是多虧了你的幫助。', 66384),
(298709, 'zhTW', '', '我感覺得到這生物裡面有她的聲音。牠生自艾恩哈拉！牠不會傷害我的！', 66384),
(298705, 'zhTW', '影衛為了強化吞噬之眾的勢力賭上了一切。要是被風行者發現我們在做什麼…', '', 66384),
(298702, 'zhTW', '', '噢，沒有什麼「陷阱」。只要完成任務，你…和你的人民都會沒事。', 66384),
(298691, 'zhTW', '我還聽得見…那聲音…', '我還聽得見…那聲音…', 66384),
(298689, 'zhTW', '寧靜…我需要寧靜。', '寧靜…我需要寧靜。', 66384),
(298686, 'zhTW', '呃啊…我聽得到她的歌聲！', '呃啊…我聽得到她的歌聲！', 66384),
(298683, 'zhTW', '', '太粗糙了！你的魔杖和朋友都配不上我！', 66384),
(298667, 'zhTW', '你準備好了再來找我。還有歐薇娜…萬事小心。', '', 66384),
(298662, 'zhTW', '我必須回到太陽之井。聖光先鋒需要我的意見。', '', 66384),
(298660, 'zhTW', '侍僧，閃耀吧！你豐足的時間所剩不多了！', '', 66384),
(298659, 'zhTW', '哎，哎呀，哎呀呀！你豐足的時間就快用完了！', '', 66384),
(298655, 'zhTW', '動作快！豐足馬上就會吞沒你脆弱的軀體！', '', 66384),
(298653, 'zhTW', '你的表現使我光榮。你將得到慷慨豐足的回報！', '', 66384),
(298652, 'zhTW', '', '我知道，但這也無法改變過去。', 66384),
(298649, 'zhTW', '我的侍僧們，真是驚人的貢獻啊！盡情享受神聖豐足的恩賜吧！', '', 66384),
(298648, 'zhTW', '榮耀歸於如此豐足的收穫！', '', 66384),
(298646, 'zhTW', '進入我的領域吧！追求無盡豐足的榮耀！', '', 66384),
(298645, 'zhTW', '別浪費時間！否則豐足就沒你的份了！', '', 66384),
(298644, 'zhTW', '你在找豐足嗎？這裡滿滿都是！你只需要動手收穫就行了。', '', 66384),
(298643, 'zhTW', '侍僧，真是飽滿豐足啊！願我的豐足與榮耀賦予你遠勝自身價值的材料。', '', 66384),
(298641, 'zhTW', '幫我個小忙，用我送你的純粹豐足跟我交易吧。', '', 66384),
(298640, 'zhTW', '要知道這個材料可是獨一無二的。我只會犒賞最為豐足的表現。', '', 66384),
(298639, 'zhTW', '真正豐足的成果將能得到純粹豐足作為回報。', '', 66384),
(298637, 'zhTW', '令人印象深刻的開始。但要記住：只有腳踏實地、勤奮實踐，才能真正知曉豐足的一切。', '', 66384),
(298636, 'zhTW', '糟了。你脆弱的身軀到極限了。我得強制你離開…當然，這是為了保護你的安全。', '', 66384),
(298634, 'zhTW', '你感受到了嗎？那股力量？還有苦痛？', '', 66384),
(298632, 'zhTW', '你收集、貢獻得越多，我的豐足祝福就能使你的技能變得更強。你感受到它的力量了嗎？', '', 66384),
(298631, 'zhTW', '你已經學會豐足的基本知識了。現在，試著在這個特製的小型領域內證明你的能耐吧。', '', 66384),
(298630, 'zhTW', '我很擅長把痛苦轉化為力量…', '', 66384),
(298629, 'zhTW', '靠近任何豐足祭壇，就可以迅速有效地貢獻你收集的資源。', '', 66384),
(298628, 'zhTW', '當然，只把收穫到的豐足塞在你的背包裡是沒有意義的。', '', 66384),
(298627, 'zhTW', '你沒聽錯，敵人也是。別害怕，這一隻是專為了教導你召喚的。', '', 66384),
(298626, 'zhTW', '礦石、藥草、可剝皮的生物，還有其他很多來源都充滿了豐足。', '', 66384),
(298625, 'zhTW', '豐足可以從許多來源找到…像是這個礦石。去吧，動手開挖。', '', 66384),
(298623, 'zhTW', '戰鬥結束後，他放下了長矛，請求哈拉尼爾停止屠殺。這是紅菇帶給所有人的教訓：力量可以贏得勝利，但唯有慈悲，才能讓雙方獲益。', '', 66384),
(298622, 'zhTW', '紅菇的體型十分龐大，這個蘑菇人用他的力量阻止了戰爭。他把雙方的鬥士都拉開，而不是擊敗他們。', '', 66384),
(298621, 'zhTW', '這個人就是紅菇，他是慈悲的倡導者，但他的請求被戰鼓聲所淹沒。不過，紅菇很清楚該如何向眾人表達自己的訊息。', '', 66384),
(298620, 'zhTW', '第一場爭鬥雖然停下來了，怒火卻沒有熄滅。雙方的領袖都不願談和，只有一個人願意放下執念。', '', 66384),
(298619, 'zhTW', '蘑菇人的凶狠對上魯坦尼的荊棘，哈朗達卻為此受苦。我們哈拉尼爾介入不是為了贏得戰爭，而是趕在腐化吞噬一切之前加以阻止。', '', 66384),
(298618, 'zhTW', '去吧。靠近過去，它就會聽從你的呼喚。', '', 66384),
(298617, 'zhTW', '侍僧，做得好。在我的領域之中，你可以找到無數的豐足。', '', 66384),
(298616, 'zhTW', '這就是豐足。', '', 66384),
(298615, 'zhTW', '年輕的侍僧，來吧。我們開始上課吧。', '', 66384),
(298614, 'zhTW', '沒有指引就走進裂隙的人，都冒著永遠迷失的風險。', '', 66384),
(298613, 'zhTW', '歐薇娜，我求求你。你知道艾恩之塵在哪。', '', 66384),
(298611, 'zhTW', '但這是我們唯一可以控制的事。', '', 66384),
(298610, 'zhTW', '和我完成這個小任務。我保證一定會讓你的心境有所變化。', '', 66384),
(298609, 'zhTW', '但是這不代表你無法讓這個世界和你自己變得更好。', '', 66384),
(298608, 'zhTW', '這個世界有許多部份早已破碎。你是該感到憤怒。', '', 66384),
(298607, 'zhTW', '你在說什麼？', '', 66384),
(298606, 'zhTW', '我每天受到我引導的聖光灼燒的時候，都會想起我的每一次失敗。', '', 66384),
(298605, 'zhTW', '什麼？', '', 66384),
(298604, 'zhTW', '噢，你說的完全沒錯。我的確是惹出了不少麻煩。', '', 66384),
(298603, 'zhTW', '你發明了這套戰爭哲學。我一直遵循著你的教誨，直到我被自己的怒火灼傷。', '', 66384),
(298602, 'zhTW', '你成立了白銀之手。你訓練了我的父親。我想我也應該要責怪你。', '', 66384),
(298601, 'zhTW', '受訓來把聖光當成武器。這就是聖騎士的本質嗎？', '', 66384),
(298600, 'zhTW', '願紅菇延伸提醒我們手下留情，只有心存仁慈，哈朗達才能長久地存續下去。', '', 66384),
(298599, 'zhTW', '$n，發現這把蘑菇人長矛背後的秘密，會是你極大的榮譽。我很期待你會發現什麼。', '', 66384),
(298598, 'zhTW', '我…完成了…使命…', '', 66384),
(298597, 'zhTW', '我不會像他們一樣白白喪命！', '', 66384),
(298596, 'zhTW', '我忠實的勇士，無須畏懼。有你的力量，我就能開拓新的道路！', '', 66384),
(298595, 'zhTW', '沒有所謂的救贖！我們必須自救！', '', 66384),
(298594, 'zhTW', '滲透者打算毀了我們辛苦的成果！殺光他們！', '', 66384),
(298415, 'zhTW', '難道我們對阿拉特的真相視而不見嗎？', '', 66384),
(298410, 'zhTW', '', '沒錯。不過，很可能有其他原因導致它被丟棄。', 66384),
(298404, 'zhTW', '唉…他們封鎖了前進的路。$n，來吧。我們必須跟上他們。', '', 66384),
(298403, 'zhTW', '', '吞噬之眾來襲！勇士，站穩了！', 66384),
(298402, 'zhTW', '', '影衛來了！', 66384),
(298401, 'zhTW', '', '部落獲得控制權了，讓他們受苦吧。', 66384),
(298400, 'zhTW', '', '有額外的防禦系統可用，啟動它們吧！', 66384),
(298352, 'zhTW', '', '艾尼斯，隊長包紮好了。我們來研究你帶回來的這些樣本吧。', 66384),
(298329, 'zhTW', '我們收集到足夠的份量了！這樣就行了。真是英勇。', '', 66384),
(298269, 'zhTW', '我們還需要一些虛無汙染的殘留物。幸好，殺戮者高地滿滿都是。', '', 66384),
(298238, 'zhTW', '', '必須警告祖爾詹。我們對小徑的攻擊開始了！把他們解決掉！', 66384),
(298228, 'zhTW', '部落贏了？怎麼會這樣？', '', 66384),
(298189, 'zhTW', '信標即將關閉！', '', 66384),
(298187, 'zhTW', '以太族信標所儲藏的能量會暫時開放。看看誰能收集到最多。', '', 66384),
(298186, 'zhTW', '', '長老掌控了艾恩之塵。我想他們應該不會和外來者分享。', 66384),
(298181, 'zhTW', '入侵者！拿起武器！', '', 66384),
(298180, 'zhTW', '虛無會吞噬你們所有人！', '', 66384),
(298179, 'zhTW', '', '時間快到了。', 66384),
(298177, 'zhTW', '', '這次部落技高一籌。如我所料。', 66384),
(298175, 'zhTW', '', '收下種子，讓其他人看看，答案或許就會揭曉。', 66384),
(298173, 'zhTW', '', '親族變異了，我依舊不變。', 66384),
(298138, 'zhTW', '', '聯盟收集了最多的虛無能量。聯盟獲勝。', 66384),
(298108, 'zhTW', '', '那些桶子裡儲藏著虛無能量。吸收那些能量之後帶回你的營地。', 66384),
(298092, 'zhTW', '聯盟獲勝！正如我所料！', '', 66384),
(298087, 'zhTW', '我不會讓這種事發生。去看看你族人的情況吧，我必須把這裡發生的事告訴銀月城。我到時再跟你會合。', '', 66384),
(298086, 'zhTW', '沒想到部落竟然這麼有本事。', '', 66384),
(298074, 'zhTW', '我還沒找到失蹤的金霧村村民的下落。現在，遊俠維多蘭也失蹤了。', '', 66384),
(298069, 'zhTW', '桑凱隊長！有海岸傳來的消息！', '', 66384),
(298059, 'zhTW', '測試看看你的戰鬥技巧吧！護送多曼納爾到終點，先到先贏！', '', 66384),
(298047, 'zhTW', '$p，把他們趕走！', '', 66384),
(298036, 'zhTW', '完全沒用！我不能在這種情況下工作。這些人一點都不尊重我的專業！', '', 66384),
(298034, 'zhTW', '', '$n，赫杜倫…我們必須保衛哈瑪拉！', 66384),
(298017, 'zhTW', '這個問題我無能為力…只能用亮片蓋住，稍微補救一下！', '', 66384),
(298015, 'zhTW', '嗯…不太對，其實，我比較喜歡毛絨絲絨！', '', 66384),
(298009, 'zhTW', '我需要看起來很經典！而且又有品味…我需要閃亮薄綢！', '', 66384),
(297972, 'zhTW', '這看起來不夠貴…請給我毛絨絲絨！', '', 66384),
(297969, 'zhTW', '這裡的材料未免太多了，把我的布料剪丟給我！', '', 66384),
(297968, 'zhTW', '下一個！', '', 66384),
(297967, 'zhTW', '許多人都避而不答…但一定有什麼壞事要發生了。', '', 66384),
(297966, 'zhTW', '至少，有人幫忙的話，就能更快處理好這些外行人…', '', 66384),
(297964, 'zhTW', '邪教？…在這裡的該不會是暮光之刃？', '', 66384),
(297963, 'zhTW', '旅行者，希望你的狀況比我上一位客人要好一點。', '', 66384),
(297962, 'zhTW', '', '我們為什麼要囤積資源？', 66384),
(297960, 'zhTW', '', '如果魯坦尼在你的家園肆虐，也許同族會知道詳細狀況。你可以在這找到一些魯坦尼。', 66384),
(297957, 'zhTW', '歐薇娜…那是什麼東西？', '', 66384),
(297956, 'zhTW', '', '魯坦尼出現在這裡？他拿的是什麼？', 66384),
(297954, 'zhTW', '', '我把信留在箱子上了。你看一下。', 66384),
(297953, 'zhTW', '我接到太陽之井的報告，說法奧的計畫奏效了。保衛者們再次擋下了虛無風暴。', '', 66384),
(297952, 'zhTW', '洛薩之子暫時會待在這。亞肯提納需要我們保護。或者我需要再喝一輪。', '', 66384),
(297951, 'zhTW', '$n，感謝你的幫助。我想銀月城現在需要我們。我們回去吧。', '', 66384),
(297950, 'zhTW', '我原本打算把盾牌掛在牆上。但現在，我打算自己舉起它。我想要保護艾澤拉斯的人民。', '', 66384),
(297949, 'zhTW', '謝謝你們所有人。我不會讓大家失望的。', '', 66384),
(297947, 'zhTW', '或許我能像戴斯可一樣，向其他人宣揚聖騎士的義務。這面重鑄的盾可以在保護艾澤拉斯的同時，隨時提醒我這點。', '', 66384),
(297946, 'zhTW', '我會收下它的。法奧告訴過我，無論是在戰亂之中、或是和平之世，白銀之手存在的目的都是為了保護無助之人。', '', 66384),
(297944, 'zhTW', '確實蠻合適的。', '', 66384),
(297938, 'zhTW', '既然你父親拒絕接受，如果你想要的話可以收下。', '', 66384),
(297937, 'zhTW', '阿拉特，你打算怎麼處理圖拉揚的盾牌？', '', 66384),
(297932, 'zhTW', '哈哈哈…完全沒道理啊。哈哈哈。', '', 66384),
(297929, 'zhTW', '…然後我就說：「如果那是我的獅鷲獸，那坐在蛋上的傢伙是誰？」', '', 66384),
(297928, 'zhTW', '我們學會變成野獸的形態。', '', 66384),
(297927, 'zhTW', '看看四周吧。部落、聯盟…這裡是厭倦戰爭之人的避風港。', '', 66384),
(297926, 'zhTW', '$n，你能幫我們買第一輪酒嗎？算在我的帳上。', '', 66384),
(297925, 'zhTW', '我們可不只是擅長躲躲藏藏而已。', '', 66384),
(297924, 'zhTW', '卡德加帶我們來的。是什麼巫師的詭異次元之類的鬼地方。熱騰騰的食物、清涼的好酒，還有魔法般的入口。', '', 66384),
(297923, 'zhTW', '這是哪裡？看起來不像是艾澤拉斯。', '', 66384),
(297920, 'zhTW', '在你想的時候，我不介意吃點東西、喝點酒。孩子，跟我們一起來吧。$n，你也是。', '', 66384),
(297919, 'zhTW', '我只需要想想該怎麼處理這面盾牌。', '', 66384),
(297918, 'zhTW', '阿拉特…讚美聖光，也許這一切都有其發生的理由。', '', 66384),
(297917, 'zhTW', '所以我打算貫徹這個信念。我父親不打算改變，但我可不一樣。', '', 66384),
(297916, 'zhTW', '我也是…但一位智者曾告訴我：「人只能改變自身的感受。」', '', 66384),
(297914, 'zhTW', '真是…讓人失望。我原本希望他能有不同的反應。', '', 66384),
(297913, 'zhTW', '我試過了。他說「有些事物永遠無法救贖」，然後拒絕收下它。', '', 66384),
(297912, 'zhTW', '盾牌怎麼還在你手上？你沒有還給你父親嗎？', '', 66384),
(297911, 'zhTW', '停！溫度不對。我們從頭開始吧。準備好了就告訴我。', '', 66384),
(297910, 'zhTW', '加入鳳凰之羽來提升溫度。', '', 66384),
(297909, 'zhTW', '我還需要一塊鋼錠。', '', 66384),
(297907, 'zhTW', '加入龍鰻塵粉，增加強度。', '', 66384),
(297906, 'zhTW', '動手吧！我拿錘子，你控制火力！', '', 66384),
(297905, 'zhTW', '我會給阿拉特一些時間，重鑄他父親的盾牌。他可能會需要你的協助。', '', 66384),
(297904, 'zhTW', '我會讓圖拉揚暫停手邊的工作。當然這不會太容易。', '', 66384),
(297902, 'zhTW', '歐薇娜，你忘掉傳統的價值了。去回音之穴吧，提醒你自己，身為哈拉尼爾的意義。', '', 66384),
(297900, 'zhTW', '$n，請跟我到熔爐碰面吧。我需要你幫忙修復盾牌。', '', 66384),
(297895, 'zhTW', '這是個好主意。', '', 66384),
(297894, 'zhTW', '我想…我想修好這面盾牌，再還給他。', '', 66384),
(297892, 'zhTW', '我毫無頭緒。我完全不知道父親經歷了些什麼。', '', 66384),
(297890, 'zhTW', '你的表現可說是…非常精湛。', '', 66384),
(297889, 'zhTW', '稍等一下。我得做好戰鬥的準備。', '', 66384),
(297888, 'zhTW', '太漂亮了！真是厲害！來吧！讓你看看更有趣的東西。', '', 66384),
(297887, 'zhTW', '繼續讓我見識你的潛力吧。', '', 66384),
(297886, 'zhTW', '我期望你至少能讓他活動一下筋骨。', '', 66384),
(297885, 'zhTW', '看來你勝出了！來吧，在我準備讓奧托薩斯進行下一場戰鬥時，先殺殺時間吧！', '', 66384),
(297884, 'zhTW', '啊！我的新玩具，塔茲拉！這會是一場令人難忘的戰鬥。', '', 66384),
(297883, 'zhTW', '看來這對你來說輕而易舉。布魯托克，讓他後悔吧。', '', 66384),
(297882, 'zhTW', '奇提戈斯應該是完美的暖身對象。證明你的價值吧。', '', 66384),
(297881, 'zhTW', '隨你想怎麼樣吧，只要有趣就好。開始戰鬥吧！', '', 66384),
(297871, 'zhTW', '', '在最深處，我們的族人勇敢面對外敵。他們撕裂血肉、吞噬心靈。許多人都喪命了。但哈拉尼爾依舊跟隨那個歌聲。', 66384),
(297860, 'zhTW', '', '他們越深入，敵人就變得越可怕。但他們是哈拉尼爾，他們不會淪為獵物。', 66384),
(297858, 'zhTW', '', '我們的祖先旅行了好幾週，在海加爾山下尋找奇特的人。對方也覺得哈拉尼爾很奇特。', 66384),
(297855, 'zhTW', '', '最後一幅壁畫蘊藏著我們最神聖的記憶，但也是我們最久遠的恥辱。想完整見證的話，你會需要我們藏起來的碎片。', 66384),
(297852, 'zhTW', '', '哼。你又給了我不錯的意見。也許我們比表面上看起來更相似。', 66384),
(297851, 'zhTW', '勇士，晴風村需要你。他們遇上光綻的麻煩了。', '', 66384),
(297849, 'zhTW', '', '我們坐下之後就開始儀式…但要準備好。這可是戰爭羅亞。不論祂的夢境如何，我們都必須完成試煉。', 66384),
(297848, 'zhTW', '', '你是說我該為他感到難過嗎？因為他有情緒問題，所以就該被原諒？', 66384),
(297847, 'zhTW', '', '這一定是莉拉菊說的火堆。', 66384),
(297846, 'zhTW', '', '不。我是說我們能夠從中學習。放下你對羅亞和祖爾金的怒火吧。那只會害你走上錯誤的路。', 66384),
(297845, 'zhTW', '', '但我發現，祖爾金也是一樣。他的憤怒是有原因的。這種憤怒逐漸惡化，最終完全掌控了他。', 66384),
(297844, 'zhTW', '我去和聖光先鋒談談，其他的事就交給你了。', '', 66384),
(297843, 'zhTW', '', '我也曾經因憤怒而失控，許多年來我一直試著對祖爾金復仇。', 66384),
(297842, 'zhTW', '赫杜倫加入了你哈拉尼爾朋友的陣線，協助終結這場威脅。他們在晴風村等你。', '', 66384),
(297841, 'zhTW', '我們無法同時對抗虛無風暴和光綻的威脅。', '', 66384),
(297840, 'zhTW', '想想這無窮的可能性…還有什麼生物能擁有如此強大的力量？', '', 66384),
(297839, 'zhTW', '你也許已經猜到，這是你父親的盾。它粉碎四散，被遺留在戰場上。', '', 66384),
(297837, 'zhTW', '如果暮光之刃握有其他情報，就需要有人盡可能把情報都帶回來。剩下的都燒光。', '', 66384),
(297834, 'zhTW', '你救了你弟弟。你守住了身為祖爾金孫女的領導權…全靠你自己。', '', 66384),
(297833, 'zhTW', '我才剛開始進行壓力測試。來吧，見識看看它能變成什麼樣。', '', 66384),
(297832, 'zhTW', '看來你弄清楚為什麼法奧帶你來這了。', '', 66384),
(297830, 'zhTW', '拜託…我已經等很久了，我很需要亮縫先生的專業。', '', 66384),
(297828, 'zhTW', '', '你已經打擾我太久了。', 66384),
(297827, 'zhTW', '', '僕從，不要再讓我失望了。', 66384),
(297826, 'zhTW', '', '殺光這些入侵者，否則就被吞噬吧。', 66384),
(297825, 'zhTW', '', '給我上。向我證明為什麼要容忍你們的無能。', 66384),
(297824, 'zhTW', '', '證明你們的價值，這群可悲的奴僕。', 66384),
(297822, 'zhTW', '', '一群廢物！至少你們可以助長我的力量。', 66384),
(297820, 'zhTW', '', '聖光依舊在燃燒！詛咒那個該死的納斯雷茲姆！', 66384),
(297819, 'zhTW', '', '阿奇爾森指引你踏上哈謝之路是正確的決定。祖爾賈拉，你的火焰正熾烈燃燒。', 66384),
(297818, 'zhTW', '放好柴薪！見證烈焰升起，火焰重生！', '', 66384),
(297815, 'zhTW', '我以為你會有更好的表現。', '', 66384),
(297759, 'zhTW', '', '我真好奇下一個會是誰…', 66384),
(297709, 'zhTW', '', '來看看火焰對我的靈魂有什麼想法吧。', 66384),
(297708, 'zhTW', '', '我們會持續提防邪枝食人妖。跟我回去吧。酋長有東西要獎賞你。', 66384),
(297707, 'zhTW', '', '那個怪物已經死了，邪枝食人妖也不在了，我們枯木食人妖可以暫時安穩度日了。', 66384),
(297702, 'zhTW', '', '小心點，$n。他看起來很強大…也很不穩定。', 66384),
(297699, 'zhTW', '我的靈魂在哪裡？你們做了什麼？', '', 66384),
(297698, 'zhTW', '拉克圖…醒了！拉克圖…好餓！', '', 66384),
(297693, 'zhTW', '', '但這隻怪物就要靠你解決了。', 66384),
(297692, 'zhTW', '', '還有許多憤怒的靈魂。我會拖住它們，讓它們無法餵養怪物。', 66384),
(297690, 'zhTW', '', '她雖然已死，但她的惡行卻無法抹滅。', 66384),
(297685, 'zhTW', '', '我們還能拯救更多靈魂。你去吸引她的注意。我去釋放其他靈魂。', 66384),
(297684, 'zhTW', '我們可不能忽視這樣的惡行，但我必須保護太陽之井。我需要你的協助。找到那些逃亡者，然後放了他們。', '', 66384),
(297683, 'zhTW', '', '她在做什麼？她在撕裂靈魂，扭曲它們！然後拿去餵養怪物！', 66384),
(297677, 'zhTW', '', '這比我們想的還要嚴重。到底有多少族人死在這裡？', 66384),
(297669, 'zhTW', '', '如果那個怪物的製造者在這裡，那我們必須阻止他。然後一定要解決掉他的怪物。', 66384),
(297668, 'zhTW', '這些意志薄弱的蠢貨開始讓我厭煩了，不過既然這是社會的期望，那我就會繼續撐下去。\n\n那個服務生去哪了？我需要來一杯。', '這些意志薄弱的蠢貨開始讓我厭煩了，不過既然這是社會的期望，那我就會繼續撐下去。\n\n那個服務生去哪了？我需要來一杯。', 66384),
(297662, 'zhTW', '', '利用亡靈來施展強大的法術…希望他們不是為此帶我的族人來這裡。', 66384),
(297661, 'zhTW', '', '那…太詭異了。還有流動的能量…這是妖術魔法。', 66384),
(297650, 'zhTW', '我相信你會做該做的事。', '', 66384),
(297649, 'zhTW', '', '這是我拿手的。', 66384),
(297647, 'zhTW', '籠罩的風暴已經讓銀月城陷入動盪。我不想再給我的人民另一個恐慌的理由。', '', 66384),
(297645, 'zhTW', '暮光之刃握有高機密的情報。不只是安寧地，整個奎爾薩拉斯都有危險。', '', 66384),
(297642, 'zhTW', '', '還真是低調啊。攝政王，這次的任務是什麼？', 66384),
(297635, 'zhTW', '', '在我們剷除邪惡之前，綁架事件不會結束。跟我來。', 66384),
(297633, 'zhTW', '', '$n，殺得好。我把還活著的人都救出來了。但為什麼穆羅金要帶他們來這裡？', 66384),
(297629, 'zhTW', '今天的港口很平靜。真是稀奇的禮物。', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(297623, 'zhTW', '又一個枯木食人妖，穆羅金又有賞金可以領了。', '', 66384),
(297618, 'zhTW', '我的老鷹都看到些什麼了？入侵者。闖入者！你們休想奪走我的獵物！', '', 66384),
(297617, 'zhTW', '光綻受到控制，代表少了一個前線需要防守。我們可以專心對付薩拉塔斯的部隊了。', '', 66384),
(297616, 'zhTW', '', '我幾乎站不直身子了，但我們還是不知道芬德爾在哪…', 66384),
(297615, 'zhTW', '我…充滿了力量！', '', 66384),
(297613, 'zhTW', '是誰把我的獵物奪走了？是誰把哈拉齊的小貓放走了？', '', 66384),
(297611, 'zhTW', '', '應該就是他帶我的同胞來這裡的…暫時別惹他。', 66384),
(297605, 'zhTW', '', '呵。我太熟悉「古怪」的羅亞語者了。馮薩拉，謝謝你。或許這個試煉會比較容易。', 66384),
(297603, 'zhTW', '', '他們像是被什麼黑暗儀式獻祭了。來吧。我會引導你。我們得拯救我的同胞。', 66384),
(297601, 'zhTW', '', '我探查了洞穴。我的同胞都在裡面…死活都有。', 66384),
(297599, 'zhTW', '', '$n。Oraka\'zul！真慶幸有你和我一起狩獵。', 66384),
(297581, 'zhTW', '先是魚人，現在是納迦！嘖，接下來呢？', '', 66384),
(297576, 'zhTW', '吃過古老穀物可頌嗎？吃起來的口感比正中紅心更讓人滿足。', '', 66384),
(297574, 'zhTW', '', '那是洛摩斯的最愛。如果它不見了，他會親自傳送到這裡。', 66384),
(297572, 'zhTW', '納迦正在走私黑市水果？不，不可能有這種事…', '', 66384),
(297546, 'zhTW', '又一個。過來。', '', 66384),
(297538, 'zhTW', '', '做得好。但我們必須保持警覺，以防光綻再次擴散。', 66384),
(297534, 'zhTW', '', '我們必須飛上空中，對抗光綻！', 66384),
(297532, 'zhTW', '我們就快要結束這一切了。最好先把戴西蒙斯解決掉，別讓他有機會背叛我們。', '', 66384),
(297520, 'zhTW', '她死得很光榮。但忠心信眾們的死…就是我的重擔。現在你身為哈謝，這是你的了。', '', 66384),
(297519, 'zhTW', '', '薩拉塔斯…曾經是凡人？', 66384),
(297516, 'zhTW', '透過力量，你所見的幻象變得更加清晰…', '', 66384),
(297514, 'zhTW', '', '年輕的阿曼尼，做得好。你…通過試煉了。接受納羅拉克的重擔吧。', 66384),
(297509, 'zhTW', '它來了。就在虛無那邊！有人可以幫忙嗎？', '', 66384),
(297506, 'zhTW', '我們可是曾經從灰燼中重建。現在沒了艾恩之塵，我們還有什麼資源？', '', 66384),
(297503, 'zhTW', '領導者必須做出犧牲。即使是我們珍重的事物也一樣。', '', 66384),
(297502, 'zhTW', '', '停下。在你面對羅亞之前，你必須先面對我…然後殺了我。', 66384),
(297501, 'zhTW', '', '怎麼耽擱這麼久，嗯？少了你羅亞不願意和我戰鬥。', 66384),
(297487, 'zhTW', '', '回到火堆旁吧。最後一項試煉等著你。', 66384),
(297485, 'zhTW', '', '了不起。你證明了自己的力量和耐性。但你的忠誠心又如何呢？', 66384),
(297482, 'zhTW', '', '阿曼尼已經坐視枯木的求助太久了。該到此為止了。', 66384),
(297481, 'zhTW', '', '羅亞心中的季節變幻莫測。你只能想辦法躲避吹拂的寒風。', 66384),
(297480, 'zhTW', '', '寒冬不在乎你是誰。哈謝、老人、小孩、乞丐都一樣。它會考驗一切。', 66384),
(297479, 'zhTW', '', '哈哈哈！敵人的項上人頭啊。向我們的勝利致敬。', 66384),
(297478, 'zhTW', '', '做得好。就像藤蔓一樣，必須切除某些枝葉才能存活。部族倖存了…至少現在如此。', 66384),
(297477, 'zhTW', '有人想逞英雄啊，為他們的故事畫下句點吧。', '', 66384),
(297476, 'zhTW', '這整趟旅程都跟我的父親有關係，是吧？', '', 66384),
(297475, 'zhTW', '要隨時注意有戰利品可拿的時機，像現在就是！', '', 66384),
(297474, 'zhTW', '', '阿曼尼哈謝會靠最信任的戰士來消滅他們。這是為了部族好。', 66384),
(297473, 'zhTW', '你喜歡收集寶物對吧？那就去找吧。', '', 66384),
(297472, 'zhTW', '', '在冬天，像囤積者的那種貪婪會成為其他人的負擔。', 66384),
(297470, 'zhTW', '發生什麼事了？看來應該是大事。', '', 66384),
(297464, 'zhTW', '那是什麼味道？去看看是什麼東西。', '', 66384),
(297463, 'zhTW', '那塊肉肯定擺在外面很久了吧？你竟然把它吃掉了？真有趣。', '', 66384),
(297461, 'zhTW', '看啊，我的計畫成功了！', '', 66384),
(297459, 'zhTW', '說到那些以太族，他們有我們可以利用的資源。快，把它們搶過來。', '', 66384),
(297458, 'zhTW', '', '你在想什麼？我們必須先對付防線。', 66384),
(297456, 'zhTW', '看吧？牠們還是有用的。可別忘了。', '', 66384),
(297455, 'zhTW', '可以好好馴服一下那些野獸。之後牠們就能上戰場了。', '', 66384),
(297452, 'zhTW', '你就這樣站在那裡？我還以為聯盟有的是戰士！證明我是對的吧。', '', 66384),
(297451, 'zhTW', '', '羅亞在夢境中看著阿曼尼的過去。當時寒冬是唯一的敵人。準備好過冬就是你的第一項試煉。', 66384),
(297449, 'zhTW', '', '哈謝的力量取決於戰士的實力。所以你也必須在納羅拉克的夢中接受考驗。', 66384),
(297447, 'zhTW', '', '將來的哈謝，不必為你的朋友擔心。作夢者，戰爭羅亞納羅拉克會親自測試她的力量。', 66384),
(297443, 'zhTW', '', '老鷹正飛向山頂的神廟。說不定是在邀請我們。', 66384),
(297440, 'zhTW', '', '聖壇點燃，老鷹展開行動了。', 66384),
(297437, 'zhTW', '', '做得好。我們必須保持警惕，時刻觀察炫盲之地。', 66384),
(297436, 'zhTW', '', '苦澀花一個晚上就長滿了哈拉諾。快把它們燒了，以防進一步擴散。', 66384),
(297433, 'zhTW', '', '這應該能重創他們的計畫。', 66384),
(297432, 'zhTW', '', '雖然我們盡力阻撓，但影衛的陰謀依然在進行。破壞他們的計畫吧。', 66384),
(297429, 'zhTW', '$p？感謝聖光。風暴逐漸瓦解，我們或許能打贏這場仗。', '', 66384),
(297428, 'zhTW', '', '我們一起以風行者之名，拯救銀月城。', 66384),
(297427, 'zhTW', '畢竟，我們是風行者。沒有任何外界的指令能夠影響我們的行動。', '', 66384),
(297426, 'zhTW', '我…我理解。但我保證，這絕對不會發生。我不會，你也不會。', '', 66384),
(297425, 'zhTW', '', '我怕在危機時，你，會像洛斯拉賽恩，因為憤怒而失控。就像我冒著風險，墮入虛無。', 66384),
(297424, 'zhTW', '', '這就是我，最害怕會發生的事，阿拉特。不是怕你受到傷害，而是害怕聖光，改變你。', 66384),
(297423, 'zhTW', '', '洛斯拉賽恩顯然不是例外。圖拉揚也是如此。', 66384),
(297422, 'zhTW', '', '或許吧。上千年來，我看過聖光強化勇士們的意志。但也改變了…他們。', 66384),
(297421, 'zhTW', '或許只有他的信念，能夠讓他在這種地方保持自我。', '', 66384),
(297420, 'zhTW', '想想洛斯拉賽恩在擁抱聖光前的樣子…', '', 66384),
(297419, 'zhTW', '我見過這種情況。不論是血色十字軍、父親、甚至我自己。', '', 66384),
(297418, 'zhTW', '', '現在他的狂熱卻威脅著整個銀月城。', 66384),
(297417, 'zhTW', '', '這段時間以來，洛斯拉賽恩一直以為我的判斷力受虛無影響。', 66384),
(297416, 'zhTW', '', '準備好。是時候取得掠食披肩了。', 66384),
(297415, 'zhTW', '我試著把他們引走。但計畫有點太成功了。', '', 66384),
(297414, 'zhTW', '', '別浪費我的時間！', 66384),
(297407, 'zhTW', '那好吧，我們後會有期。', '', 66384),
(297404, 'zhTW', '聖光軍團之前曾經迅速鏟除影衛。這次也不會有什麼不同。', '', 66384),
(297403, 'zhTW', '薩拉塔斯。誘惑如此動人。就連敵人都會臣服於她的低語。\n\n想聽細節嗎？', '', 66384),
(297399, 'zhTW', '我跟你說個小秘密。殺掉那些戴面具的妖術師，就能得到他們的一部分守護聖靈。', '', 66384),
(297398, 'zhTW', '呃啊！', '', 66384),
(297392, 'zhTW', '哈哈哈！呃…我…好餓…', '', 66384),
(297391, 'zhTW', '呃！需要…能量…', '', 66384),
(297390, 'zhTW', '呃啊！給我…你的靈魂…', '', 66384),
(297389, 'zhTW', '把你的靈魂交出來！', '', 66384),
(297388, 'zhTW', '我逮到你了！', '', 66384),
(297387, 'zhTW', '必須…吞食靈魂…', '', 66384),
(297386, 'zhTW', '啊！哈哈哈哈！', '', 66384),
(297385, 'zhTW', '壓扁你！', '', 66384),
(297384, 'zhTW', '粉碎！', '', 66384),
(297383, 'zhTW', '猛擊！', '', 66384),
(297382, 'zhTW', '你還真有兩把刷子。考慮把它當正職嗎？', '', 66384),
(297381, 'zhTW', '所有靈魂都是我的。', '', 66384),
(297380, 'zhTW', '', '是部落變得這麼虛弱，還是你不想要寶物了？快去找。', 66384),
(297379, 'zhTW', '我是最強大的。就是我！', '', 66384),
(297377, 'zhTW', '幫忙把這些…可愛的小傢伙訓練成可靠的坐騎吧。', '', 66384),
(297376, 'zhTW', '呃啊！哈哈！', '', 66384),
(297375, 'zhTW', '靈魂…不…太多了…', '', 66384),
(297373, 'zhTW', '我…覺得…不太妙。', '', 66384),
(297372, 'zhTW', '我要失去…一切了…', '', 66384),
(297368, 'zhTW', '誰都別想阻止我！', '', 66384),
(297366, 'zhTW', '我的能量增長了。', '', 66384),
(297364, 'zhTW', '嗯。真美味。', '', 66384),
(297363, 'zhTW', '啊…沒錯。就是這股力量…', '', 66384),
(297361, 'zhTW', '需要更多力量。更多靈魂！', '', 66384),
(297359, 'zhTW', '我聞到鮮活靈魂的味道了！', '', 66384),
(297358, 'zhTW', '必須…收割…更多！', '', 66384),
(297356, 'zhTW', '', '你的靈魂是我的了。', 66384),
(297350, 'zhTW', '', 'Ma\'ako！Ma\'ako ka shadra！', 66384),
(297349, 'zhTW', '', '看起來有寶物出現在遠處。別錯過這個大好機會！', 66384),
(297348, 'zhTW', '', '搶占先機，贏取戰利品。', 66384),
(297346, 'zhTW', '', '我要毒害你的靈魂！', 66384),
(297344, 'zhTW', '', '夠了！你是抵擋不了邪枝食人妖的！', 66384),
(297342, 'zhTW', '', '我感覺到來者不善。去殺戮者高地看看究竟是什麼吧。', 66384),
(297339, 'zhTW', '', '苦痛重擊。', 66384),
(297335, 'zhTW', '', '晦影傾瀉！', 66384),
(297334, 'zhTW', '', '暗影奔騰！', 66384),
(297332, 'zhTW', '', '虛無渴望吞噬！', 66384),
(297331, 'zhTW', '', '黑暗吞噬一切！', 66384),
(297329, 'zhTW', '', '粉碎暗影！', 66384),
(297325, 'zhTW', '', '封印在黑暗之中吧。', 66384),
(297324, 'zhTW', '', '你…怎麼可能…', 66384),
(297323, 'zhTW', '', '你這是徒勞無功。', 66384),
(297322, 'zhTW', '', 'An\'daka taz no shada。Ke zulo numra kan！Ne\'hideh。Ne\'hideh！', 66384),
(297321, 'zhTW', '', '預料之中的弱小。', 66384),
(297320, 'zhTW', '', '真沒用。我早就知道了。', 66384),
(297319, 'zhTW', '', '你豈敢？受死吧！', 66384),
(297315, 'zhTW', '我絕不屈服！', '', 66384),
(297314, 'zhTW', '我絕不鬆懈！', '', 66384),
(297313, 'zhTW', '你注定要殞命！', '', 66384),
(297312, 'zhTW', '這是失敗的印記！', '', 66384),
(297308, 'zhTW', '閉嘴！', '', 66384),
(297307, 'zhTW', '安靜！', '', 66384),
(297306, 'zhTW', '你不該…', '', 66384),
(297305, 'zhTW', '我的任務尚未完成。我的守望會繼續下去。', '', 66384),
(297304, 'zhTW', 'Selama am\'oronor！(奉行正義！)', '', 66384),
(297303, 'zhTW', '把這當作警告吧。', '', 66384),
(297302, 'zhTW', '別癡心妄想了！Diel fin\'al！(你必敗無疑！)', '', 66384),
(297299, 'zhTW', '享受囚禁時間。', '', 66384),
(297298, 'zhTW', '請不要亂動。', '', 66384),
(297297, 'zhTW', '採取必要壓制措施。', '', 66384),
(297296, 'zhTW', '持續壓制。', '', 66384),
(297295, 'zhTW', '規定一定要遵守。', '', 66384),
(297294, 'zhTW', '遵守紀律是唯一選擇。', '', 66384),
(297293, 'zhTW', '恢復紀律措施。', '', 66384),
(297292, 'zhTW', '補充燃料。請稍候。', '', 66384),
(297291, 'zhTW', '', '你死後也會受到折磨。', 66384),
(297290, 'zhTW', '安全系統…故障…', '', 66384),
(297288, 'zhTW', '回到教室。', '', 66384),
(297286, 'zhTW', '', '愚蠢的精靈，我告訴你羅亞已經沉默了！如果你要證據，叫老羅亞語者自己告訴你吧！', 66384),
(297285, 'zhTW', '安靜是必須的。', '', 66384),
(297283, 'zhTW', '擾亂份子解決掉了。', '', 66384),
(297282, 'zhTW', '所有學生都必須遵守規定。', '', 66384),
(297281, 'zhTW', '做得好。還是你願意做遠行者的工作？', '', 66384),
(297280, 'zhTW', '', '去吧。讓他們受苦。', 66384),
(297279, 'zhTW', '晴風村的遠行者需要人協助。看看你能不能解決那邊的野生動物。', '', 66384),
(297276, 'zhTW', '', '任務完成。', 66384),
(297274, 'zhTW', '', '這裡的重力能夠提供額外的效果。利用這股力量來把以太族解決掉。', 66384),
(297273, 'zhTW', '我的愛人，我現在要帶你回家了。', '', 66384),
(297272, 'zhTW', '', '聖光帶來光綻！', 66384),
(297271, 'zhTW', '', '光綻充滿能量！', 66384),
(297267, 'zhTW', '', '你們這群蛆蟲還真會同心協力。', 66384),
(297266, 'zhTW', '', '那個巨獸不只會奪走你的性命。快找人來幫忙把它解決掉。', 66384),
(297263, 'zhTW', '', '我們的計畫得繼續下去。靈魂收割不能停。', 66384),
(297262, 'zhTW', '', '真是弱小的靈魂。但還算湊合吧。', 66384),
(297261, 'zhTW', '', '讓靈魂收割繼續下去。', 66384),
(297260, 'zhTW', '', '更多獻給拉克圖的靈魂！', 66384),
(297258, 'zhTW', '', '這是什麼？讓我實驗的新靈魂嗎？', 66384),
(297255, 'zhTW', '', '讓他們起舞吧！', 66384),
(297254, 'zhTW', '', '別讓他們閒著！', 66384),
(297253, 'zhTW', '', '被魔能淹沒吧！', 66384),
(297252, 'zhTW', '', '魔能會吞噬你！', 66384),
(297251, 'zhTW', '', '待著別動…', 66384),
(297249, 'zhTW', '', '燒死你！', 66384),
(297248, 'zhTW', '', '嚐嚐這個！', 66384),
(297247, 'zhTW', '', '天空…仍是…威脅…', 66384),
(297246, 'zhTW', '', '一如往常…回去工作。', 66384),
(297244, 'zhTW', '', '解決掉了…真外行。', 66384),
(297243, 'zhTW', '', '你只能怪自己。', 66384),
(297242, 'zhTW', '種下他們的命運！', '', 66384),
(297241, 'zhTW', '', '感受魔能的力量！', 66384),
(297240, 'zhTW', '正中要害！', '', 66384),
(297239, 'zhTW', '', '所以我們的戰士、武器跟薩滿都沒剩多少了…', 66384),
(297238, 'zhTW', '不堪一擊！', '', 66384),
(297237, 'zhTW', '夠了！', '', 66384),
(297236, 'zhTW', '到此為止！', '', 66384),
(297235, 'zhTW', '裂地之怒！', '', 66384),
(297234, 'zhTW', '劈砍重擊！', '', 66384),
(297233, 'zhTW', '我的主人…逃走了…', '', 66384),
(297232, 'zhTW', '就這樣？浪費時間。', '', 66384),
(297230, 'zhTW', '預料之中。', '', 66384),
(297229, 'zhTW', '又幹掉一個。', '', 66384),
(297228, 'zhTW', '很快就結束了。', '', 66384),
(297227, 'zhTW', '該走了…', '', 66384),
(297226, 'zhTW', '開始吧…', '', 66384),
(297225, 'zhTW', '還不夠隱密。', '', 66384),
(297224, 'zhTW', '無處可躲。', '', 66384),
(297223, 'zhTW', '我有說可以休息了嗎？把箱子丟下來！', '', 66384),
(297222, 'zhTW', '上面那個！把箱子丟下來，摔碎它們！', '', 66384),
(297221, 'zhTW', '噢…不會吧…', '', 66384),
(297220, 'zhTW', '這就是兇殺路名稱的由來。', '', 66384),
(297219, 'zhTW', '又有爛攤子要清了。', '', 66384),
(297218, 'zhTW', '這是你自找的。', '', 66384),
(297217, 'zhTW', '什麼事都要我親自出馬！', '', 66384),
(297216, 'zhTW', '', '尼波斯！放下！', 66384),
(297215, 'zhTW', '', '小淘氣尼波斯！', 66384),
(297214, 'zhTW', '', '畏懼魔能吧！', 66384),
(297213, 'zhTW', '', '逃離火焰吧！', 66384),
(297212, 'zhTW', '適者生存，但輪不到你。', '', 66384),
(297211, 'zhTW', '就算我逮不到你，奈卡雷斯也會！', '', 66384),
(297210, 'zhTW', '', '搞清楚你的身份！', 66384),
(297209, 'zhTW', '', '人渣，給我回來！', 66384),
(297208, 'zhTW', '', '啊，正好是我要的。', 66384),
(297206, 'zhTW', '', '尼波斯，讓媽媽嘗一口！', 66384),
(297202, 'zhTW', '', '我…的…魔法…', 66384),
(297201, 'zhTW', '重傷要害。', '', 66384),
(297200, 'zhTW', '正中心臟。', '', 66384),
(297199, 'zhTW', '', '魔能會征服一切。', 66384),
(297198, 'zhTW', '正中目標。', '', 66384),
(297197, 'zhTW', '', '尼波斯？吃點心了。', 66384),
(297196, 'zhTW', '', '告密者都該死。', 66384),
(297193, 'zhTW', '呃啊！', '', 66384),
(297192, 'zhTW', '你要付出代價！', '', 66384),
(297190, 'zhTW', '回到我身邊！', '', 66384),
(297189, 'zhTW', '奈卡雷斯！不！', '', 66384),
(297188, 'zhTW', '猛力擊殺。', '', 66384),
(297186, 'zhTW', '致命一擊。', '', 66384),
(297183, 'zhTW', '奈卡雷斯，飛吧！', '', 66384),
(297182, 'zhTW', '奈卡雷斯，拿下他們！', '', 66384),
(297181, 'zhTW', '收割吧！', '', 66384),
(297180, 'zhTW', '', '如果光木武器還沒準備好，或許影松的薩滿能幫得上忙。', 66384),
(297179, 'zhTW', '奈卡雷斯，攻擊！', '', 66384),
(297178, 'zhTW', '奈卡雷斯，跟我上！', '', 66384),
(297177, 'zhTW', '', '保持下去。這些武器是我們對抗虛無的關鍵。', 66384),
(297176, 'zhTW', '奈卡雷斯，上吧！', '', 66384),
(297174, 'zhTW', '正中陷阱。', '', 66384),
(297173, 'zhTW', '嚇到不能動彈了。', '', 66384),
(297172, 'zhTW', '凍住！', '', 66384),
(297171, 'zhTW', '真是好消息啊。來吧，兄弟們。重溫痛苦回憶的時候到了。', '', 66384),
(297170, 'zhTW', '黑暗部落肯定已經拿走了聖物碎片，當成戰利品分贓。', '', 66384),
(297165, 'zhTW', '', '你族人的狀況比我想的還要危急。', 66384),
(297164, 'zhTW', '你是在開玩笑吧！', '', 66384),
(297163, 'zhTW', '這裡唯一的聖物只有…', '', 66384),
(297161, 'zhTW', '我需要更大的獵物。', '', 66384),
(297159, 'zhTW', '哼。狩獵得不夠過癮。', '', 66384),
(297156, 'zhTW', '哎呀。我忘記要讓他們活命了。', '', 66384),
(297155, 'zhTW', '這樣就死了？看來我對待俘虜要更小心了。', '', 66384),
(297152, 'zhTW', '太可惜了。他們活著還比較有意思。', '', 66384),
(297151, 'zhTW', '為了協助銀月城的保衛者，我們正在執行尋找聖物的任務。', '', 66384),
(297149, 'zhTW', '噢，看起來是個輕鬆的獵物。', '', 66384),
(297147, 'zhTW', '又有人頭送上門了。奈卡雷斯，準備好了嗎？', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(297146, 'zhTW', '奈卡雷斯，怎麼了？有新鮮的獵物？哈哈哈！', '', 66384),
(297144, 'zhTW', '', '很好。別忘了你在這裡得知的情報。', 66384),
(297143, 'zhTW', '', '這裡有奇怪的光環。驅逐這些以太族，然後進行調查。', 66384),
(297138, 'zhTW', '', '自從祖爾金死去之後，部族就四分五裂了。因為我們不再團結，暮光之刃才能夠各個擊破。', 66384),
(297133, 'zhTW', '情況不太好。只剩下老人、傷患和餓肚子的了。', '', 66384),
(297111, 'zhTW', '', '無論永歌森林還是阿曼尼都無法容忍破壞和平協議的行為。做得好。', 66384),
(297110, 'zhTW', '', '有邪枝食人妖試圖潛入永歌森林。找到他們魔法的來源，然後把他們解決掉。', 66384),
(297103, 'zhTW', '哈！笑啊，$r，我覺得蠻好笑的。', '', 66384),
(297102, 'zhTW', '把那個邪惡的戰利品帶回枯木崖。小沙德拉需要磨牙玩具。', '', 66384),
(297101, 'zhTW', '馮老大說我們應該要除掉邪枝部族的首領，而你確實辦到了！', '', 66384),
(297100, 'zhTW', '', '我們暫時跟著他…如果這個虛無行者想搞花招，就放馬過來。', 66384),
(297099, 'zhTW', '', '我從未聽說過虛無行者這麼…願意幫忙…', 66384),
(297096, 'zhTW', '', '呃啊！救命！', 66384),
(297092, 'zhTW', '', '無處可逃！', 66384),
(297091, 'zhTW', '', '翻動大地！', 66384),
(297089, 'zhTW', '', '再見了，老朋友…', 66384),
(297086, 'zhTW', '控制臺發揮作用了，快點啟動那座橋！', '', 66384),
(297085, 'zhTW', '可惜你也受到虛無腐化了。', '', 66384),
(297084, 'zhTW', '阿拉特，在所有人之中，我以為只有你能理解。 ', '', 66384),
(297083, 'zhTW', '想想有多少人會因此喪命，相信我們吧。', '', 66384),
(297082, 'zhTW', '洛斯拉賽恩，這不是聖光賜予我們的使命。', '', 66384),
(297081, 'zhTW', '', '你們這些侵入者有完沒完？在我親自動手之前幫個忙，自己去死一死。', 66384),
(297080, 'zhTW', '', '洛斯拉賽恩，我的視野從未如此清晰，但我不願意接受眼前的景象。 ', 66384),
(297079, 'zhTW', '一如既往，你的雙眼被虛無蒙蔽了！', '', 66384),
(297078, 'zhTW', '艾蘭里亞，你會知道我是正確的。', '', 66384),
(297077, 'zhTW', '首席核心工匠，水晶塔快發生嚴重故障了！', '', 66384),
(297076, 'zhTW', '看來似乎缺少了什麼。我們必須找到它們才能阻止洛斯拉賽恩！', '', 66384),
(297075, 'zhTW', '你讓整座銀月城都陷入危險。這樣的風險根本不值得！', '', 66384),
(297073, 'zhTW', '聖光…消失了…', '', 66384),
(297066, 'zhTW', '', '成長茁壯，照耀一切吧！', 66384),
(297065, 'zhTW', '', '滋養土地吧！', 66384),
(297064, 'zhTW', '光綻將持續擴張！', '', 66384),
(297062, 'zhTW', '', '保護光綻！', 66384),
(297056, 'zhTW', '', '去吧，$n。我會盯緊他的。', 66384),
(297054, 'zhTW', '還太弱了…無法專注…', '', 66384),
(297023, 'zhTW', '我父親也是學徒之一。但他從沒跟我說過這些事。', '', 66384),
(297022, 'zhTW', '這場戰爭結束之後，我…我想回來這裡幫你。我認為這和面對虛無的威脅一樣，是我的使命。', '', 66384),
(297020, 'zhTW', '阿拉特，你想成為怎麼樣的聖騎士？你想成為什麼樣的人？', '', 66384),
(297019, 'zhTW', '人生歷練會深深影響我們。但我們可以選擇日子該怎麼過。', '', 66384),
(297017, 'zhTW', '我和大主教並不熟識。但我知道他去過離這裡很遠的世界，長時間都在苦苦奮戰。', '', 66384),
(297015, 'zhTW', '我真希望能見見當時的他。', '', 66384),
(297014, 'zhTW', '阿隆索斯告訴我他第一批學生的故事。傳奇人物烏瑟顯然對照顧傷患也很在行。', '', 66384),
(297010, 'zhTW', '', '如果我們能協助消滅暮光之刃，那麼對光木的需求也會終止，永歌森林也不會遭到入侵。', 66384),
(297005, 'zhTW', '', '我們能一次終結內外的威脅。如果你真的想參戰，那就跟我來吧。', 66384),
(297004, 'zhTW', '凡人的武器無法傷害薩拉塔斯的偉大榮光！', '', 66384),
(297003, 'zhTW', '呃啊！你的武器竟然有聖光的力量？', '', 66384),
(296970, 'zhTW', '異端份子！', '', 66384),
(296969, 'zhTW', '我掌握了艾恩哈拉和光綻的力量！', '', 66384),
(296964, 'zhTW', '流血吧！', '', 66384),
(296963, 'zhTW', '為你的罪孽流血吧！', '', 66384),
(296962, 'zhTW', '別忘了這對爪子！', '', 66384),
(296961, 'zhTW', '聽聽我的怒吼！', '', 66384),
(296960, 'zhTW', '想都別想！', '', 66384),
(296957, 'zhTW', '你們都將會受到懲罰！', '', 66384),
(296955, 'zhTW', '聖光聽我號令！', '', 66384),
(296953, 'zhTW', '聖光之怒！', '', 66384),
(296947, 'zhTW', '', '祖爾賈拉，如果你願意接受，我能出手幫忙。$n，等你完成任務之後再來找我。', 66384),
(296946, 'zhTW', '為我燃燒吧！', '', 66384),
(296945, 'zhTW', '這是…為了哈朗達…', '', 66384),
(296943, 'zhTW', '接下來輪到你的朋友了。', '', 66384),
(296941, 'zhTW', '認清自己的身份！', '', 66384),
(296940, 'zhTW', '我是天選之人！', '', 66384),
(296938, 'zhTW', '見識我的力量！', '', 66384),
(296930, 'zhTW', '摧毀阿曼尼！擊潰他們！為了薩拉塔斯的榮耀散播混亂吧！', '', 66384),
(296922, 'zhTW', '', '最後一個。走吧，我們去找他們的領袖。', 66384),
(296889, 'zhTW', '', '這些野獸渴望復仇。', 66384),
(296887, 'zhTW', '你逃不出戰神的熊掌。', '', 66384),
(296886, 'zhTW', '我的怒火會找到你。', '', 66384),
(296883, 'zhTW', '做得好。你的力量和我不相上下。夢境…即將結束。', '', 66384),
(296878, 'zhTW', '', '是關於你祖父，祖爾金嗎？', 66384),
(296875, 'zhTW', '', '沒錯。祖父的憤怒讓他背棄了羅亞，嘗試奪取祂的力量，切斷了我們跟祂們的連結！', 66384),
(296850, 'zhTW', '你的懦弱讓氏族蒙羞。', '', 66384),
(296849, 'zhTW', '哈巫拉，真讓人失望。', '', 66384),
(296848, 'zhTW', '你還不夠強。', '', 66384),
(296841, 'zhTW', '最後的試煉就在眼前。準備好面對我的利爪，測試你的力量了嗎？', '', 66384),
(296835, 'zhTW', '現在終於有個乾淨的地方可以給遠行者休息了。謝謝你。', '', 66384),
(296834, 'zhTW', '我們很喜歡戶外，但堡壘裡面就還好。你可以清掉這些害蟲嗎？', '', 66384),
(296824, 'zhTW', '', '結束了。我的夥伴現在要離開了。', 66384),
(296822, 'zhTW', '', '是這樣嗎？那就讓他先死吧！', 66384),
(296820, 'zhTW', '', '無意義的威脅。枯木部族不畏邪枝部族。', 66384),
(296818, 'zhTW', '', '帶他回去，你的部族就會迎來死亡。', 66384),
(296803, 'zhTW', '白銀之手成立的目的就是在戰鬥中運用聖光。這難道不是成為聖騎士典範的標準嗎？', '', 66384),
(296802, 'zhTW', '結果它們是一些稀鬆平常的東西，與戰爭一點關聯都沒有。', '', 66384),
(296801, 'zhTW', '我以為這些聖物是強大的武器。', '', 66384),
(296800, 'zhTW', '還是…把它們奪回來比較好。', '', 66384),
(296799, 'zhTW', '不過…他們握有的聖物能強化我們太陽之井的保衛者。', '', 66384),
(296792, 'zhTW', '看看誰來了！朋友，我正好說到你呢。當然是在誇你了！來，快來啊！', '', 66384),
(296791, 'zhTW', '大家注意！該來歡慶了，我們親愛的勇士回來了！', '', 66384),
(296790, 'zhTW', '我們的貴賓回來了！真令人開心！我們來敬他一杯！', '', 66384),
(296789, 'zhTW', '也是為什麼他們能把我對友誼和守護的教誨，轉化成你我皆能清楚判斷為邪惡的事物。', '', 66384),
(296786, 'zhTW', '這就是為什麼血色十字軍會聲稱自己是遵循聖光的意志行事。', '', 66384),
(296785, 'zhTW', '但是聖光無法區分愛與恨。', '', 66384),
(296767, 'zhTW', '真菌腐爛…必須淨化…', '', 66384),
(296765, 'zhTW', '我們會長回來！', '', 66384),
(296764, 'zhTW', '紅菇會折斷你的嫩枝！', '', 66384),
(296756, 'zhTW', '回憶裂口', '回憶裂口', 66384),
(296684, 'zhTW', '嗯，真驚人。絲紋更是點睛之筆。', '', 66384),
(296683, 'zhTW', '我很渴望下一次的合作機會。來吧，我們來為你的盟友鑄造武器。', '', 66384),
(296669, 'zhTW', '這裡的現實結構混亂且扭曲。我們需要你的幫忙來研究這種異象的本質。', '', 66384),
(296668, 'zhTW', '我們在這裡還有很多事要學。做得好！', '', 66384),
(296667, 'zhTW', '', '這場勝利雖然短暫，卻意義重大。', 66384),
(296666, 'zhTW', '', '我們已經深入敵人的領地。該發動攻擊了！', 66384),
(296665, 'zhTW', '', '影衛在守護那個屏障裡的新武器。把它摧毀掉，免得他們用它來對付我們。', 66384),
(296664, 'zhTW', '', '只要我們同心協力，就沒有力量能阻止我們。', 66384),
(296659, 'zhTW', '', '不計代價生存下去。終於找到一個有合理法則的世界了。', 66384),
(296658, 'zhTW', '', '虛無對這個世界的生物產生了奇特的影響。狩獵這些生物，奪取它們的精華。我必須知道是什麼力量在驅使它們。', 66384),
(296637, 'zhTW', '暗影領區', '暗影領區', 66384),
(296636, 'zhTW', '$n，你去收集可用的資源，阿拉特和我會把熔爐準備好。', '', 66384),
(296635, 'zhTW', '昔日戰爭遺棄的武器四散在戰場之中，讓農耕變得困難重重。', '', 66384),
(296634, 'zhTW', '我的菌傘斷了…紅菇會報仇…', '', 66384),
(296627, 'zhTW', '', '這項報告可能會…引來洛索瑪的懷疑。你最好跟我一起去找他。', 66384),
(296623, 'zhTW', '', '我們快去聖光會堂吧。', 66384),
(296620, 'zhTW', '戮日者聖所', '戮日者聖所', 66384),
(296595, 'zhTW', '最受人尊敬的聖騎士不會透過戰鬥來激發對聖光的信念。他們會為了自己所珍視的一切奮戰。', '', 66384),
(296579, 'zhTW', '暴力傾向？這只是個小小的副作用罷了。它帶來的力量簡直不容小覷！', '', 66384),
(296575, 'zhTW', '我們來看看這些充滿苦痛的飾品有什麼效果。', '', 66384),
(296569, 'zhTW', '這股力量雖然很不穩定，但為了成果，冒一點風險也值得！', '', 66384),
(296564, 'zhTW', '附魔還需要多加完善，但為了發展，有所犧牲是必要的！', '', 66384),
(296562, 'zhTW', '', '影松部族沒有村莊，他們是祖阿曼的流浪者。在他們失去龍鷹羅亞後，他們就失去了精神支柱。', 66384),
(296561, 'zhTW', '', '率先失去村莊的是惡齒部族…他們位於暮光之刃襲擊的前線。', 66384),
(296556, 'zhTW', '', '所有的阿曼尼人都很勇猛，但這些難民大多都不是受過訓練的鬥士。', 66384),
(296554, 'zhTW', '', '我願意為了阿曼尼族人盡一切努力。', 66384),
(296541, 'zhTW', '$n，我們正處於一個發掘魔法的新時代。你做得很好。', '', 66384),
(296540, 'zhTW', '我們的傀儡也能有所強化！', '', 66384),
(296538, 'zhTW', '附上這種魔法的武器能對血肉和心靈造成不小的傷害。', '', 66384),
(296536, 'zhTW', '只要輕觸一下，我們就能產出修復與維繫這座城市所需的能量。', '', 66384),
(296532, 'zhTW', '$n，做得好。你證明了自己也為守護銀月城付出了心力。', '', 66384),
(296531, 'zhTW', '這好像是專門為承受不穩定的苦痛而生的…真是好消息。', '', 66384),
(296530, 'zhTW', '這個水晶容器…是用出奇堅韌的宇宙材料製成的。太驚人了。', '', 66384),
(296529, 'zhTW', '', '我要！這是我應得的。我跟戴斯可和瑪魯在這裡努力做事…做得比我想的還久。\n\n雖然當個勞動者，戴斯可和瑪魯似乎就心滿意足了，但我可不是。我奉行太陽之道，不是為了搬運瓦礫，重建建築。\n\n我是日行者。我信仰安希，我的錘子是揮舞的工具，而不是槌子和鏟子。在被黑暗圍困的世界中，我們不是我們本應成為的那道陽光。\n\n我目前並不想待在這個地方。', 66384),
(296525, 'zhTW', '', '$p，需要什麼嗎？', 66384),
(296524, 'zhTW', '戴斯可在這裡教了我不少東西。如同在曠野中，每一道陽光都很重要，我們所做的每一件小事，也都有其價值。\n\n此外，在安希的聖光下，所做的事有沒有價值，並非由我們來判斷。\n\n在這裡在他身旁做事，我發現幫助需要的人是讓我最有收穫的事。', '', 66384),
(296509, 'zhTW', '', '那裡！你看到了嗎？', 66384),
(296507, 'zhTW', '卡鏘，卡鏘！', '', 66384),
(296506, 'zhTW', '粉碎吧！', '', 66384),
(296495, 'zhTW', '薩拉塔斯萬歲！', '薩拉塔斯萬歲！', 66384),
(296494, 'zhTW', '向我們展現你的榮耀！', '向我們展現你的榮耀！', 66384),
(296490, 'zhTW', '我可以看見它！', '我可以看見它！', 66384),
(296488, 'zhTW', '再等一下下…', '', 66384),
(296471, 'zhTW', '', '如果你找到祖爾詹…記得提醒他，無論發生什麼事，我們都還是家人。', 66384),
(296469, 'zhTW', '', '$n，謝謝你。就算你是入侵者，阿曼尼的領地也永遠會以榮耀歡迎你。', 66384),
(296436, 'zhTW', '', '洛索瑪承諾，他的博學者會找到解答。機不可失！', 66384),
(296434, 'zhTW', '如果我們直搗薩拉塔斯，她一定會被如此龐大的陣仗嚇到躲回匕首裡。', '', 66384),
(296432, 'zhTW', '', '所有聖光先鋒部隊，馬上前往太陽之井！', 66384),
(296431, 'zhTW', '不！這些虛無成癮者才不是我們的救贖。只有聖光才能阻止邪惡的薩拉塔斯。', '', 66384),
(296430, 'zhTW', '情況危急！我們需要一切幫助。就算是博學者奧姆里克也可以。', '', 66384),
(296425, 'zhTW', '薩拉塔斯的虛無風暴渴望對太陽之井傾瀉怒火。', '', 66384),
(296396, 'zhTW', '那段時光至今還是會讓我做惡夢。經歷了那麼多事之後，我還是會夢見這個地方。', '', 66384),
(296391, 'zhTW', '$n，你必須找到聖光先鋒的領袖。太陽之井正在全力抵擋薩拉塔斯的襲擊。', '', 66384),
(296383, 'zhTW', '薩拉塔斯的攻勢越來越猛烈了！', '', 66384),
(296379, 'zhTW', '聖光需要藉由使用者才能釋放最大的力量。聖光能讓人更加堅定，也會對信念有所回應。', '', 66384),
(296378, 'zhTW', '我也常常在思考這件事。', '', 66384),
(296376, 'zhTW', '雖然在理念上與聖光教會不同，但都能引導相同的能量。', '', 66384),
(296375, 'zhTW', '看看艾澤拉斯各地引導聖光的文化，伊露恩、格拉爾和安希等等。', '', 66384),
(296374, 'zhTW', '你該不會以為我會讓你獨佔所有樂子吧？', '', 66384),
(296372, 'zhTW', '聖光會尋求道路，而不是決定方向。', '', 66384),
(296371, 'zhTW', '我向來被教導聖光代表正義。十字軍…是一群無恥之徒。', '', 66384),
(296370, 'zhTW', '我簡直不敢相信，聖光竟然會回應他們的呼喚。', '', 66384),
(296369, 'zhTW', '但無論我多努力嘗試…恐怕我都無法達到那個境界。', '', 66384),
(296368, 'zhTW', '每一個都是不朽的傳奇。他們的英勇事蹟是所有聖騎士的典範。', '', 66384),
(296367, 'zhTW', '我從小就聽說過這些聖騎士的故事。', '', 66384),
(296359, 'zhTW', '', '祖爾賈拉，前進吧。接受我們的祝福，摧毀你的獵物！', 66384),
(296357, 'zhTW', '飯是做好了，不過我的背需要休息。你知道有什麼療法嗎？', '', 66384),
(296350, 'zhTW', '所以你責怪聖光，而不是你父親？', '', 66384),
(296347, 'zhTW', '我被教導要敬畏那道聖光。但在它的指引下…我差點，就被殺了。', '', 66384),
(296346, 'zhTW', '我難過的是他這麼做的時候…我看到他的眼神中，閃耀著聖光。', '', 66384),
(296345, 'zhTW', '我並不是因為我的父親傷害我而難過。', '', 66384),
(296344, 'zhTW', '有話就說吧！免得這些情緒在你心中鬱悶難解。', '', 66384),
(296343, 'zhTW', '你的鬱悶情緒快要比薩拉塔斯的虛無風暴凝重了。', '', 66384),
(296322, 'zhTW', '也許我們做的單調工作才是真正的魔法。', '', 66384),
(296321, 'zhTW', '就算沒有做出什麼大事或英雄事蹟，多虧了我們的努力，永歌森林的魔法依然生生不息。', '', 66384),
(296315, 'zhTW', '阿隆索斯‧法奧主教有個支援太陽之井，以及協助阿拉特的計畫。', '', 66384),
(296314, 'zhTW', '太陽之井暫時守住了，這全都要靠保衛者的努力不懈。但要是他們的力量受到動搖…', '', 66384),
(296307, 'zhTW', '', '被苦痛淹沒吧！', 66384),
(296306, 'zhTW', '', '懺悔吧！', 66384),
(296305, 'zhTW', '', '亡者…悲泣…', 66384),
(296304, 'zhTW', '', '逝者…哀悼…', 66384),
(296303, 'zhTW', '', '悔恨…之念！', 66384),
(296302, 'zhTW', '', '悲慟…狂風！', 66384),
(296300, 'zhTW', '', '苦痛…暴風！', 66384),
(296299, 'zhTW', '', '終…於…', 66384),
(296297, 'zhTW', '', '忘卻…這個地方…', 66384),
(296296, 'zhTW', '', '苦痛…', 66384),
(296295, 'zhTW', '', '悲痛…', 66384),
(296294, 'zhTW', '', '終結…痛苦！', 66384),
(296293, 'zhTW', '', '離開這裡！', 66384),
(296292, 'zhTW', '無盡怒火！', '', 66384),
(296291, 'zhTW', '灰飛煙滅！', '', 66384),
(296288, 'zhTW', '毀滅！', '', 66384),
(296287, 'zhTW', '破壞！', '', 66384),
(296286, 'zhTW', '解決他們！', '', 66384),
(296285, 'zhTW', '集合！', '', 66384),
(296284, 'zhTW', '列隊！', '', 66384),
(296283, 'zhTW', '擋我者死！', '', 66384),
(296282, 'zhTW', '嚐嚐我的斧頭！', '', 66384),
(296281, 'zhTW', '見識我的利刃！', '', 66384),
(296279, 'zhTW', '弱者必敗！', '', 66384),
(296278, 'zhTW', '無恥的…敗類…', '', 66384),
(296276, 'zhTW', '和風行者一樣弱小。', '', 66384),
(296275, 'zhTW', '浪費時間。', '', 66384),
(296274, 'zhTW', '倒下吧！', '', 66384),
(296273, 'zhTW', '我會親自解決你！', '', 66384),
(296272, 'zhTW', '風行者！我要你付出代價！', '', 66384),
(296269, 'zhTW', '好噁心…', '', 66384),
(296268, 'zhTW', '拉奇很想吐…', '', 66384),
(296267, 'zhTW', '一起玩啊！', '', 66384),
(296266, 'zhTW', '抓到了！', '', 66384),
(296265, 'zhTW', '呃喔。', '', 66384),
(296264, 'zhTW', '哎呀！', '', 66384),
(296262, 'zhTW', '給我過來！', '', 66384),
(296261, 'zhTW', '拉奇…很抱歉…', '', 66384),
(296260, 'zhTW', '拉奇好無聊。', '', 66384),
(296259, 'zhTW', '都死光了嗎？', '', 66384),
(296258, 'zhTW', '好痛。', '', 66384),
(296257, 'zhTW', '掰掰。', '', 66384),
(296255, 'zhTW', '', '黑暗籠罩！', 66384),
(296254, 'zhTW', '', '暗影降臨！', 66384),
(296251, 'zhTW', '', '你做了什麼！', 66384),
(296250, 'zhTW', '', '白癡！', 66384),
(296249, 'zhTW', '', '心靈穿刺！', 66384),
(296247, 'zhTW', '', '女王…我們…失敗了…', 66384),
(296246, 'zhTW', '', '她的聖殿不會受到玷汙。', 66384),
(296245, 'zhTW', '', '你根本不夠格。', 66384),
(296242, 'zhTW', '', '你絕不能玷汙女王的神聖殿堂！', 66384),
(296241, 'zhTW', '', '你竟敢褻瀆她的神殿？給我滾！', 66384),
(296236, 'zhTW', '事情不像看起來那麼糟…看起來這麼糟是因為其他地方急需遊俠的支援…\n\n<曦奔隊長嘆了一口氣。>\n\n不過，旅行者營地代表著我們。最起碼應該要保持乾淨整齊。', '', 66384),
(296235, 'zhTW', '等一下…又是那種奇怪的魔法！', '', 66384),
(296234, 'zhTW', '我原本期待會更有…英雄的氛圍，你知道嗎？', '', 66384),
(296230, 'zhTW', '', '我們今天在這裡做得很不錯。我只希望這符合泰明的期望。', 66384),
(296229, 'zhTW', '我們不能再繼續等羅亞了。如果情況危急，那就只能行動了！', '', 66384),
(296228, 'zhTW', '你想挑戰我？哈！你連我的屏障都沒辦法突破！', '', 66384),
(296227, 'zhTW', '看你拼命掙扎…是很有趣。但你得為了薩拉塔斯的榮耀受死！', '', 66384),
(296226, 'zhTW', '呸！我的手下只不過是些廢物！愛殺多少隨便你！', '', 66384),
(296225, 'zhTW', '', '哈！幼鳥們，儘管逃吧！在火焰真正的力量面前竄逃！', 66384),
(296224, 'zhTW', '', '哈巫拉，來吧！讓他們見識你心中的火焰！', 66384),
(296223, 'zhTW', '這些虛無雜種真是有趣的玩具！', '', 66384),
(296222, 'zhTW', '你好，小小的哈巫拉。想來和我們玩玩嗎？', '', 66384),
(296221, 'zhTW', '', '漂亮。我們的利爪可以撕碎這些弱者的血肉了。', 66384),
(296220, 'zhTW', '', '我的風將清除暮光之刃的一切。摧毀導體吧！', 66384),
(296219, 'zhTW', '哈巫拉，像個真正的阿曼尼戰鬥吧！', '', 66384),
(296218, 'zhTW', '終於加入戰局啦？讓敵人看看你從我這裡學到什麼！', '', 66384),
(296196, 'zhTW', '喂！我知道你在想啥。\n\n對啦，我腳卡住了，我不想再談這件事。\n\n「加入探險者協會吧，會很好玩，能對世界做出貢獻」，他們說。早知道聽奶奶的話，我們腿固家的人最好還是遠離危險比較好。\n\n營地裡的夥伴們這回肯定會笑我一輩子。\n\n要小心啊！看到我的下場就該引以為戒。這裡陷阱一堆，還有暮光之刃的人，走路看清楚點！', '', 66384),
(296180, 'zhTW', '對於許多像西爾朗這樣的虛無精靈，那其實不是抉擇。在特洛古斯裂隙，奧姆里克的追隨者無預警地被聖物轉化。那是不可逆的過程。絕大多數的人都接受改變，擁抱虛無的力量。\n\n像我這樣的其他人，則是之後才成為奧姆里克的追隨者。在那之前，我的人生一直都是被規劃好的。我極其痛恨。我在自己決定的道路上找到慰藉，並決意追求對虛無的精通。我去了特洛古斯，接受轉化。我自願成為刃多雷。\n\n虛無象徵著潛能與改變。它很危險。如同世上的所有武器。', '', 66384),
(296170, 'zhTW', '', '沒錯，叔叔。羅亞還是不願意和我們對話。', 66384),
(296156, 'zhTW', '', '戰場很安靜。看來你的戰士解決暮光之刃的殘黨了。', 66384),
(296154, 'zhTW', '光木、羅亞、入侵者…有了這些幫助，卻還是流了這麼多阿曼尼的血才換來勝利。', '', 66384),
(296153, 'zhTW', '', '終於。結束了。', 66384),
(296148, 'zhTW', '凡人，我不會死在你們手上。只有神才殺得了我！', '', 66384),
(296147, 'zhTW', '看我的刀刃先送你上路！', '', 66384),
(296146, 'zhTW', '', '那受四個神明祝福的凡人怎麼樣？', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(296143, 'zhTW', '我會親自把你的屍體帶給薩拉塔斯！', '', 66384),
(296134, 'zhTW', '', '根莖看起來更強壯了。謝謝你的協助。', 66384),
(296133, 'zhTW', '', '哈瑪拉的根莖看管者需要協助。你可以去幫幫忙嗎？', 66384),
(296128, 'zhTW', '', '抱歉，親愛的，每人只能點一首歌！你得等到明天再來了。', 66384),
(296120, 'zhTW', '', '讓撤離繼續下去。', 66384),
(296119, 'zhTW', '', '嘿，親愛的。想點個歌嗎？我的歌單還有空位哦。', 66384),
(296110, 'zhTW', '一杯鬼魂花茶佐太陽果。\n\n想像你最大的掙扎，然後喝下去。', '一杯鬼魂花茶佐太陽果。\n\n想像你最大的掙扎，然後喝下去。', 66384),
(296107, 'zhTW', '', '非常好。我們來除去莫爾頓的虛無屏障。', 66384),
(296106, 'zhTW', '謝謝你所做的一切，$n。我明天會回咆哮峰跟你會合。', '', 66384),
(296104, 'zhTW', '<奧斯崔和瑟朵娜一起追憶過去，緬懷那個他們都深愛的男人。>', '', 66384),
(296103, 'zhTW', '情況比我預期的好多了。', '', 66384),
(296099, 'zhTW', '', '我懇求羅亞破除莫爾頓的虛無屏障。\n\n沒有羅亞，我們是不可能走這麼遠的。\n\n但這場和莫爾頓的最終決戰，我們必須親自戰勝。\n\n屏障將會瓦解，屆時戰鬥也會打響。\n\n你準備好了嗎，哈巫拉？', 66384),
(296097, 'zhTW', '', '奧斯崔和瑟朵娜繼續他們的對話，迷失在他們共同的白日夢中。', 66384),
(296096, 'zhTW', '哈。在特洛古斯，很難弄到那種茶葉。', '', 66384),
(296095, 'zhTW', '', '他也會叫你起床喝菊花茶嗎？', 66384),
(296094, 'zhTW', '', '看信不急。留下來，奧斯崔。你不介意的話，我想再跟你喝一下茶。', 66384),
(296093, 'zhTW', '我們給你一些個人空間，看西爾朗的信，瑟朵娜。', '', 66384),
(296092, 'zhTW', '', '瑟朵娜和奧斯崔都笑了起來。', 66384),
(296091, 'zhTW', '太陽果能讓味道變柔和。好主意，瑟朵娜。看來我們的品味果然一致。', '', 66384),
(296089, 'zhTW', '坑洞是個充滿混亂的地方。謝謝你讓那裡恢復寧靜。', '', 66384),
(296087, 'zhTW', '', '莫爾頓以為有屏障就安全了。他是大錯特錯。', 66384),
(296086, 'zhTW', '坑洞吸引了許多威脅。別讓情勢變得難以處理。', '', 66384),
(296083, 'zhTW', '', '很好。更好喝了。這讓我想起從前的日子。', 66384),
(296081, 'zhTW', '', '他說過同樣的事。我曾試著接受它。但我失敗了。', 66384),
(296079, 'zhTW', '喝口茶。它很有用。$n，你要不要也試試？畢竟是你泡的茶。', '', 66384),
(296074, 'zhTW', '聖光自有其代價。嚴格的秩序。令人窒息，處處受限。我們本質上就不一樣。', '', 66384),
(296072, 'zhTW', '', '虛無的誘惑。伴隨代價的力量。該死的代價，對嗎？太陽之井…重獲新生。我們的法力成癮…治好了。我們族人戰鬥的理由真的還不夠嗎？', 66384),
(296071, 'zhTW', '待在虛無風暴的時候，這種茶會讓我們負面情緒的陰影化成實體。不過，它很有用。', '', 66384),
(296068, 'zhTW', '', '聞起來像很苦的藥。加入一點產自永歌森林的柑橘，或許能平衡味道。', 66384),
(296063, 'zhTW', '$G他:她;也有來自西爾朗的東西。$n，你還有很多茶葉，對吧？', '', 66384),
(296058, 'zhTW', '', '你們都去了虛無風暴嗎？拜託，請進。', 66384),
(296057, 'zhTW', '瑟朵娜，這位是$n。你介意$G他:她;在場嗎？', '', 66384),
(296038, 'zhTW', '你需要什麼嗎？\n\n我在照顧我主人的陸行鷹，所以挺忙的。', '', 66384),
(296035, 'zhTW', '不是我。\n\n我不知道他們以為我做了什麼，但不是我。我很肯定。\n\n聖光先鋒的人把我團團包圍，就像是他們以前從未聽過術士一樣。\n\n我不知道是不是因為我是不死族，我穿紫色衣服，或是因為我召喚了虛無行者。', '', 66384),
(296034, 'zhTW', '這些聖騎士歸我管轄，我會派他們去最需要他們的地方。\n\n如果銀月城的領導層不願意淨化這個邪惡，那就由我們來幫他們做。', '', 66384),
(296033, 'zhTW', '這座城市到處都是滲透者。虛無最喜歡的就是見縫插針，偽裝成友軍，悄悄潛入。\n\n我不會放任我的城市遭遇背叛。', '', 66384),
(296032, 'zhTW', '也許營地有人可以照顧他們…哇！那是什麼？', '', 66384),
(296021, 'zhTW', '這會很危險…但面對危險就是當遠行者的醍醐味！', '', 66384),
(296020, 'zhTW', '那台裝置會測試生物的潛在腐化程度。我們分頭行動的話能涵蓋更大的範圍。', '', 66384),
(296001, 'zhTW', '你在西爾朗身上找到的信是寫給瑟朵娜‧暮塔的。她是西爾朗的前妻。他們是在西爾朗變成刃多雷的時候分開的。\n\n信中用到「背叛」之類的字眼。雖然他們已經別離，西爾朗還是愛著她。\n\n<奧斯崔看向瑟朵娜，忍不住洩漏了苦澀的情緒。>\n\n從銀月城被流放讓許多人的狀況都變得很複雜。資產跟寶物被沒收，家庭也分崩離析。\n\n這是他的選擇，不是我們能干涉的。', '', 66384),
(295994, 'zhTW', '真是一朵美麗的花。多虧了我們的努力，土壤一定相當健康。', '', 66384),
(295975, 'zhTW', '', '聖光，我…很遺憾，奧斯崔。你想進來嗎？我們可以聊聊。', 66384),
(295971, 'zhTW', '我們被派去虛無風暴。我們的任務是…算了，不重要。他為了保護同伴而死。', '', 66384),
(295969, 'zhTW', '西爾朗不在了，瑟朵娜。', '', 66384),
(295968, 'zhTW', '', '山貓吃飽了，長老也很滿意。朋友，做得好。', 66384),
(295964, 'zhTW', '', '大巢穴裡都是害蟲。只要能解決這個問題，長老對我們的觀感應該就會變好。帶著冷酷山貓，牠準備好飽餐一頓了。', 66384),
(295963, 'zhTW', '我們必須阻止這些爭執。', '', 66384),
(295962, 'zhTW', '', '太好了，這些食材絕對能做出美味的和談餐點。謝謝你！', 66384),
(295961, 'zhTW', '', '我需要食材來製作我們與魯坦尼和蘑菇人的和談餐點。幫我收集一些吧。', 66384),
(295960, 'zhTW', '同意。這座城市隨時都會引爆戰火。', '', 66384),
(295959, 'zhTW', '', '什麼，來表示慰問？他也拋棄你了嗎？', 66384),
(295957, 'zhTW', '我來這裡只是為了送信。不過…有些事或許不得不說。\n\n如果你不想的話，其實沒必要留在這裡，$n。這可能涉及個人隱私。反正我不會有事，我保證。', '', 66384),
(295956, 'zhTW', '他們的狂熱真令人欽佩。我一定會讓他們的犧牲有價值。', '', 66384),
(295955, 'zhTW', '博學者奧姆里克的視線從奧斯崔轉向你。', '', 66384),
(295951, 'zhTW', '我已經在銀月城經歷過不少口水戰。不過，我認為最好跟我們的辛多雷同胞維持表面的和諧。\n\n但奧斯崔並不認同這一點。他獨自前往銀月城會讓我有點擔心。', '', 66384),
(295949, 'zhTW', '太棒了！一次狩獵，我們就削弱了吞噬之眾，還強化了我們的防禦。', '', 66384),
(295947, 'zhTW', '面對如此棘手的獵物，我早就料到這場狩獵會不輕鬆。', '', 66384),
(295946, 'zhTW', '他們可悲的存在變成了我們保護城市的力量。不覺得很有詩意嗎？', '', 66384),
(295945, 'zhTW', '你終結了他們的苦難，還壯大了我們的力量。真有效率！', '', 66384),
(295944, 'zhTW', '滄海一粟。虛無中的一道閃光。或許這樣就夠了…', '', 66384),
(295943, 'zhTW', '這股能量！要是我能駕馭這份力量的分毫…', '', 66384),
(295942, 'zhTW', '成果真豐碩。做得好。', '', 66384),
(295941, 'zhTW', '真可惜，但這是必須的。他們的犧牲將名留千古。', '', 66384),
(295939, 'zhTW', '元素？秘法？我只要能汲取苦痛就好了。', '', 66384),
(295938, 'zhTW', '噢，看他們發狂的樣子！真有趣。', '', 66384),
(295937, 'zhTW', '刺殺刺客…真是別有一番趣味。', '', 66384),
(295936, 'zhTW', '如此純粹的力量…或許刃多雷確實有點能耐。', '', 66384),
(295935, 'zhTW', '金屬根本比不過魔法。', '', 66384),
(295934, 'zhTW', '火燒得越旺，過程就越痛苦。', '', 66384),
(295933, 'zhTW', '雖然暮光之刃的主人是薩拉塔斯，不過就連那些無名小卒也有力量。把他們的力量搶過來吧。', '', 66384),
(295932, 'zhTW', '這些棘語者已經偏離正道。收割他們的力量為我們所用吧。', '', 66384),
(295931, 'zhTW', '惡癮者…形容得真貼切。他們漂泊了這麼久，卻還是存活下來。好好利用他們的韌性。', '', 66384),
(295930, 'zhTW', '這名死亡騎士已經失去利用價值。讓我們徵用他的痛苦吧。', '', 66384),
(295929, 'zhTW', '這個吞噬之眾的成員必須永遠從世上消失。', '', 66384),
(295928, 'zhTW', '多曼納爾是薩拉塔斯的精英，也讓他們成為最誘人的目標…', '', 66384),
(295927, 'zhTW', '啊，聖光。這是我很熟悉的力量。讓我們從迷惘的人身上搶奪那股力量吧。', '', 66384),
(295926, 'zhTW', '魯坦尼被灌注了世界的力量。是時候把它汲取過來了。', '', 66384),
(295925, 'zhTW', '就連遠行者也無法抵抗腐化和邪惡的力量。', '', 66384),
(295924, 'zhTW', '我不會忽視食人妖的力量。就讓我們好好利用吧。', '', 66384),
(295923, 'zhTW', '這個生物可說是…喜怒無常。', '', 66384),
(295922, 'zhTW', '凱瑞西造就了宇宙中最致命的掠食者。這便是其中之一。', '', 66384),
(295921, 'zhTW', '我很欣賞我墮落虛無之中的同袍。我們好好利用他們的韌性吧。', '', 66384),
(295920, 'zhTW', '這個獵物雖然體型嬌小，但力量卻很強大。可別低估他了。', '', 66384),
(295919, 'zhTW', '這個獵物的力量之火熊熊燃燒。熄滅他的火焰吧。', '', 66384),
(295913, 'zhTW', '哇哈哈哈…', '', 66384),
(295907, 'zhTW', '沒錯。在銀月城的時候看好奧斯崔。確保他不會隨便跟人開戰。為了他好，也為了我好。洛摩斯已經給了我足夠的苦頭了。', '', 66384),
(295905, 'zhTW', '我不會久待。那裡並不歡迎我。', '', 66384),
(295902, 'zhTW', '封住裂隙了。朧暗堡壘對銀月城不再是威脅。', '', 66384),
(295897, 'zhTW', '黑暗部落就和洛薩之子一樣，還活在第二次大戰的那段過去。', '', 66384),
(295896, 'zhTW', '', '多麼奇異又漂亮的花！龍鰻一定很感激你的幫忙。', 66384),
(295895, 'zhTW', '', '龍鰻的數量還真不少！你可以回來了！', 66384),
(295893, 'zhTW', '只有我們同心協力才能辦到。我們回咆哮峰吧。', '', 66384),
(295892, 'zhTW', '', '小傢伙，你有東西要給我們嗎？', 66384),
(295891, 'zhTW', '', '這是什麼？我從沒見過這麼奇怪的龍鰻！', 66384),
(295879, 'zhTW', '', '我會從這裡監控牠們的進食模式。去幫那些龍鰻吧！', 66384),
(295857, 'zhTW', '一群…骯髒的…動物…！', '', 66384),
(295854, 'zhTW', '如果你能找到直搗薩拉塔斯的路…聖光先鋒就會離開。更不用說你的人會獲得多強大的力量了。', '', 66384),
(295843, 'zhTW', '銀月城全靠我們了。一起加油！', '', 66384),
(295842, 'zhTW', '我在城市裡可以保護你，但聖光先鋒不會讓你靠近太陽之井的。研究結果會改變這點。', '', 66384),
(295841, 'zhTW', '研究結果？我什麼工具和支持都沒有，但雙方的狂熱者還是追著我不放…', '', 66384),
(295804, 'zhTW', '我已不再是戰士，也不再是領袖，那些日子已經過去了。\n\n但我仍有雙手，仍有時間，仍在我的族人中有一席之地。和平共享的一餐，可以和戰場上出鞘的利刃一樣強而有力。\n\n所以我去找食材、煮飯，盡我所能地付出，這就足夠了。', '', 66384),
(295803, 'zhTW', '哈瑪拉的建立並非出於友誼，而是出於必要。\n\n哈拉尼爾、魯坦尼、蘑菇人…彼此之間毫無情誼。無休止的流血衝突只會讓這片土地陷入荒蕪。\n\n於是我們築起了一個脆弱的寄託，一個能勉強維繫和平的地方。', '', 66384),
(295794, 'zhTW', '升好火了，我的背卻在抗議。如果你願意伸出援手，我將會感激不盡。', '', 66384),
(295761, 'zhTW', '我只是想靠近一點觀察虛無風暴…\n\n聽著。我們沒時間等待他們認可我的做法了。你感覺不到嗎？虛無風暴並未逐漸削弱，反而越來越強。\n\n太陽之井的防禦機制維持不了多久。我必須想辦法進入虛無風暴，為此，我需要評估我剛剛收集的資料，而且不被狂熱者殺掉。\n\n你可以幫忙說服他們嗎？', '', 66384),
(295757, 'zhTW', '', '我們不會被你「自願」協助給騙的，虛無精靈。', 66384),
(295755, 'zhTW', '勇士，謹慎行事。我們需要奧姆里克和聖光先鋒。', '', 66384),
(295741, 'zhTW', '我們幫助了…扭傷腳踝的隊長。我們從塵土和拾荒者手中…拯救了旅行者營地。\n\n我想我終於證明自己是真正的遠行者了？', '', 66384),
(295738, 'zhTW', '阿斯特雷、瓦薩林，你們去幫助這裡的其他遊俠。', '', 66384),
(295718, 'zhTW', '打從一開始我就沒希望了。有薩卡許這樣的優秀鬥士在，她根本就不可能會選我這種人。\n\n<卡甲拉盯著自己的腳。>\n\n我不認為我會參加節慶。但…還是謝謝你的幫忙。', '', 66384),
(295717, 'zhTW', '我完全不曉得娜瑪琪為什麼選我！但我好開心啊！我相信她應該有更好的選擇。\n\n<薩卡許試圖讓自己冷靜下來。>\n\n好吧！既然得到難得的機會，我就應該好好把握！\n\n祝我好運！', '', 66384),
(295715, 'zhTW', '我已經努力過了。娜瑪琪很聰明，卡甲拉也是。他們一定很聊得來的。\n\n她做了正確的選擇。\n\n我應該邀請其他人嗎？我還要繼續參加節慶嗎？\n\n也許我應該暫時把心力放在訓練上。', '', 66384),
(295714, 'zhTW', '好吧。出事就算你的。', '', 66384),
(295713, 'zhTW', '現在是該大膽行事了。放了他，責任我來承擔。', '', 66384),
(295712, 'zhTW', '喜歡「大膽」行事。大博學者，這是你想說的嗎？', '', 66384),
(295711, 'zhTW', '但奧姆里克…', '', 66384),
(295709, 'zhTW', '你沒有時間囚禁他，也沒有理由處決他。', '', 66384),
(295708, 'zhTW', '娜瑪琪選了我？而不是薩卡許？我還以為他們很親近的…\n\n我一直夢想這一天的來臨，但是從沒想到這會成真！\n\n這一切都是真的嗎？還是我已經死了？\n\n<卡甲拉的呼吸變得急促。>\n\n我現在該怎麼辦？我該說什麼？\n\n我該稱讚她的獠牙嗎？還是給她一個擁抱？\n\n幫幫我吧！', '', 66384),
(295706, 'zhTW', '確實如此。他效忠的正是我。儘管對聯盟有歧見和不信任，但奧姆里克和刃多雷一次又一次地展現了對聯盟的忠誠。', '', 66384),
(295705, 'zhTW', '不。這個…精靈…已經表明自己效忠誰了。', '', 66384),
(295704, 'zhTW', '高階指揮官。請你釋放博學者奧姆里克。', '', 66384),
(295701, 'zhTW', '我調查虛無是為了幫助你！', '', 66384),
(295696, 'zhTW', '真的嗎？\n\n如果我們不盡快主動出擊，我們就註定被虛無所吞噬。\n\n但是伊利丹說過：「有時就是需要左右命運的安排。」', '', 66384),
(295695, 'zhTW', '我贊同洛索瑪的看法，不過，我也了解這之中涉及複雜的政治角力。\n\n博學者奧姆里克並非銀月城的居民。他和刃多雷都是流放者，意味著洛索瑪無權管轄。\n\n即使奧姆里克是居民，但他也是博學者。這意味著他歸大博學者洛摩斯所管，而洛摩斯似乎將奧姆里克使用虛無魔法的行為視為個人背叛。', '', 66384),
(295694, 'zhTW', '多曼納爾一定偷走了西爾朗的法術集核。看來那就足夠用來窺探銀月城了。\n\n我們必須馬上行動。', '', 66384),
(295673, 'zhTW', '聖光先鋒抓到博學者奧姆里克試圖靠近太陽之井。我必須介入，以免他們一看到他，就將他處決。\n\n我和洛斯拉賽恩都很熟悉某些魔法的腐化本質，以及其影響力。不過，我們從那些經驗得到的教訓卻似乎截然不同。', '', 66384),
(295669, 'zhTW', '', '精靈，那就看看誰更能享受戰鬥的快感吧！', 66384),
(295666, 'zhTW', '', '還真是典型的阿曼尼台詞。但…要說我不這麼覺得那就是在騙人。', 66384),
(295664, 'zhTW', '', '羅亞賦予我力量。但是，只有戰鬥的快感才能滿足我！', 66384),
(295653, 'zhTW', '謝謝…你…', '', 66384),
(295648, 'zhTW', '別讓這擊敗你。', '', 66384),
(295625, 'zhTW', '薩拉塔斯…原諒我的失敗。', '', 66384),
(295622, 'zhTW', '虛無軍團為數眾多。你們根本還沒準備好！', '', 66384),
(295593, 'zhTW', '蘑菇讓你變得更高！', '', 66384),
(295592, 'zhTW', '', '我們回家吧！', 66384),
(295591, 'zhTW', '', '哈拉尼爾永不氣餒！', 66384),
(295590, 'zhTW', '…我想我們必須想個自己的標語。', '', 66384),
(295586, 'zhTW', '…真誘人。\n\n太誘人了。\n\n我不確定我們能不能信賴由虛無的爪牙打通的道路，不過，我們必須做點什麼。\n\n太陽之井暫時安全，但這並非陷入僵持。如果保持現狀，虛無風暴很快就會開始侵入我們的防線。\n\n我們必須主動出擊。', '', 66384),
(295585, 'zhTW', '大夥們！我們怎麼說？', '', 66384),
(295584, 'zhTW', '我不認為洛索瑪有權插手此事。這個虛無精靈是流放者，而且基於其本質，被視為是對太陽之井和此地部隊的威脅。\n\n奧姆里克不是銀月城的居民，而且涉及與虛無的戰爭時，我們不服從攝政王的統轄。\n\n他可以諮詢，但別想命令我們。', '', 66384),
(295583, 'zhTW', '而且你是受到太陽之井的召喚。奧姆里克卻不是，這意味著他腐化得太嚴重，或是他沒有資格享有這份榮耀。', '', 66384),
(295582, 'zhTW', '我們保持謹慎，不讓像博學者奧姆里克這麼強大的虛無精靈靠近太陽之井是有原因的。幾年前，艾蘭里亞‧風行者曾接近太陽之井，她的存在直接使魔法出現變化。\n\n誠然，她的體內藏著一個黑暗那魯，不過我不願意冒一絲風險，讓與虛無如此密切的生物靠近太陽之井。', '', 66384),
(295571, 'zhTW', '', '我們的占兆師正在研究這個。他們沒有解決方案，但這個被虛無玷汙的精靈也沒有。\n\n由於抑制魔法，我們無法把梵迪卡爾運用在這裡。傳送和飛行魔法也無法突破風暴。\n\n不過我們會找到進去的辦法。我們必須相信我們一定會想到辦法。', 66384),
(295568, 'zhTW', '', '我不懷疑其真實性。不過，我們能夠相信他會幫我們打通一條能用的路嗎？或者，這只是為了他自己的利益？\n\n我們必須主動出擊，不過問題又來了，這正是虛無蠶食世界的方式。他們在你需要的時候伸出援手，然後奪走你的一切。\n\n安蘇芮克女王、艾薩拉女王、奈薩斯王薩哈達爾，這些人都在他們最絕望的時候接受幫助。\n\n我們絕不能重蹈覆轍。', 66384),
(295564, 'zhTW', '', '我們的部隊已經為了銀月城做出足夠的讓步。\n\n洛索瑪的眼界太小了。我們不是來這裡拯救一座城市，而是為了拯救整個艾澤拉斯。', 66384),
(295556, 'zhTW', '', '談到與虛無戰鬥，聖光先鋒絕對是專家。那裡的部隊掠奪成性、防不勝防、蠶食鯨吞。\n\n這就是他們的戰鬥方式。他們偽裝成友軍或提出交易，然後在你還來不及反應時，另一個世界就被吞噬了。', 66384),
(295534, 'zhTW', '我會盯好他的一舉一動。', '', 66384),
(295533, 'zhTW', '好啊！繼續敲你們的鼓吧。再送更多食人妖弱雞來讓我殺！', '', 66384),
(295532, 'zhTW', '殺掉傳送門法師也沒用！我們還是會踩扁你可悲的沼澤村子！', '', 66384),
(295530, 'zhTW', '很有用。不過需要打一架。試試看…你就明白了。', '', 66384),
(295529, 'zhTW', '洛索瑪被他的絕望蒙蔽了。的確，我們必須拯救銀月城和太陽之井。但是，投向虛無…\n\n不。奧姆里克不只是運用虛無，還仰賴我們最糟糕的背叛者開發的技巧。\n\n透過聖光或秘法的手段進入虛無風暴確實比較難，但是比起奧姆里克的計畫，它們會可靠許多。', '', 66384),
(295527, 'zhTW', '我知道你們凡人會透過分享這種個人資訊，建立深厚、有意義的羈絆。謝謝你對我開誠布公。', '', 66384),
(295526, 'zhTW', '洛索瑪或許認為自己有權插手這裡的事，但奧姆里克是博學者，因此由「我」全權審判和管轄。\n\n還有，他和他的同伴是因為他們的行為而被流放。虛無魔法不只是禁忌。其本質更是全然的邪惡。', '', 66384),
(295525, 'zhTW', '趁著刀刃冷卻的時候，我們休息一下。來吧，說說你自己吧。', '', 66384),
(295523, 'zhTW', '能夠多花一些時間相處，是多美好的事。', '', 66384),
(295522, 'zhTW', '洛索瑪派你來的？\n\n奧姆里克曾是我的…同事，在他投入虛無之前。他一直很莽撞。\n\n他可能會稱之為「大膽」，但他鑽研魔法的方式完全無視我們為了保護世界而設下的界限。\n\n如今，他做得太過火了。', '', 66384),
(295512, 'zhTW', '', '那就這樣決定了！', 66384),
(295511, 'zhTW', '', '卡甲拉？或薩卡許？\n\n卡甲拉送了我一條蛇頸龍牙項鍊作為禮物。他不是鬥士，但很靈巧又聰明。聊起來也很開心，他總是能逗我笑。\n\n薩卡許給了我這件羽飾頭飾。這是他給我的驚喜。他是強壯的鬥士。知道他也有重感情的一面，讓我對他刮目相看了。\n\n你覺得我應該選誰呢？', 66384),
(295509, 'zhTW', '別開玩笑了。你們凡人都會後悔。我可以透過空氣嚐出來。\n\n你殺了許多生命，不是嗎？當中一定有你後悔痛下殺手的目標。', '', 66384),
(295503, 'zhTW', '多麼有趣的選擇。\n\n我自己？我們虛無生物也並非對恐懼免疫。如果出現更強大的力量，我們就會恐懼。我怕薩拉塔斯。\n\n我怕你。\n\n<戴西蒙斯露出大大的微笑。>\n\n多告訴我一點，我必須知道。那麼後悔呢？你有後悔的事嗎？', '', 66384),
(295487, 'zhTW', '真有趣。我個人喜歡很多氣味：心痛、忌妒、恐懼…\n\n<戴西蒙斯哼了一聲，舔了舔嘴唇。>\n\n不過，我也迫不及待想嚐嚐你提到的一些實體「食物」。\n\n接下來呢？我一時想不到你們凡人還會聊什麼無聊的話題。不如就問…\n\n你害怕的東西是什麼？', '', 66384),
(295478, 'zhTW', '你們凡人的生存之道既有趣又複雜。你們的內在世界激發出如此強烈、美味的情感。\n\n我深切地希望，能多了解你們一點。\n\n我們來聊些客套話吧。告訴我關於你自己的事。\n\n你最喜歡的食物是什麼？', '', 66384),
(295462, 'zhTW', '', '說真的，我覺得艾蘭里亞的心臟是黑暗那魯的傳聞其實解釋了很多事情。', 66384),
(295453, 'zhTW', '大夥們！幫幫忙！', '', 66384),
(295452, 'zhTW', '有蹤跡。還有東西在外面。我們走吧！', '', 66384),
(295451, 'zhTW', '', '在那裡！我們找到小莫了！', 66384),
(295449, 'zhTW', '等等…我感應到…銀月城。快看！就在下面！', '', 66384),
(295448, 'zhTW', '這是多曼納爾造成的。西爾朗傷了它，不過它一定從他身上拿走了什麼東西。', '', 66384),
(295447, 'zhTW', '走這邊！', '', 66384),
(295446, 'zhTW', '這些裂隙…就像傷口一樣。給人似曾相識的感覺。', '', 66384),
(295445, 'zhTW', '', '不管那是什麼，都是來自這個方向。', 66384),
(295444, 'zhTW', '我們在數十年前與精靈和部落的大戰中損失了很多族人，但當時我們的人口依然興盛。\n\n如今，我們人數稀少。少得可憐。我擔心，這種程度的損失要是繼續下去的話，阿曼尼和其他森林部族很快就會消失了。\n\n我向阿奇爾森祈禱，希望那一天永遠不會到來。', '', 66384),
(295442, 'zhTW', '', '你們兩個不會以為我們會讓你們孤軍奮戰，對吧？', 66384),
(295427, 'zhTW', '請幫我準備草藥和靈魂顏料，這樣我們才能為死去的族人做好準備，幫助他們踏上穿越莊嚴之谷的旅程。', '', 66384),
(295425, 'zhTW', '', '如果我去找納羅拉克的時候，你又做了什麼蠢事，我發誓會親手把你的腦袋砍下來。', 66384),
(295424, 'zhTW', '', '你需要什麼？', 66384),
(295421, 'zhTW', '', '這麼多的傷亡…詹，你做了什麼好事？', 66384),
(295420, 'zhTW', '今天死去之人的鮮血將會化為洪流，沖走我們領地所有的入侵者！', '', 66384),
(295415, 'zhTW', '', '村莊最近經歷了不少風波。希望規劃中的節慶能讓大家轉換心情！\n\n從我出生以來，我們都沒舉辦過羅亞慶典。長老們有說過慶典有什麼活動，但我還是好緊張啊！', 66384),
(295407, 'zhTW', '如果曦奔隊長陷入了什麼麻煩，那能拯救她的只有我們了。', '', 66384),
(295405, 'zhTW', '嗯！當時有個古怪的魔法，然後…等等。曦奔隊長出什麼事了嗎？', '', 66384),
(295404, 'zhTW', '', '別大驚小怪！只不過是扭傷腳踝而已。這個地方的情況有點失控了。', 66384),
(295403, 'zhTW', '隊長！你…沒事？', '', 66384),
(295402, 'zhTW', '', '這些繪畫對每個人來說都有不同的意義。', 66384),
(295401, 'zhTW', '希望卡甲拉不喜歡她，不然我根本毫無勝算。他是村子裡最聰明的孩子！', '', 66384),
(295378, 'zhTW', '在典禮結束之前，你不能離開哈瑪拉。', '在典禮結束之前，你不能離開哈瑪拉。', 66384),
(295377, 'zhTW', '我一直在等父親親自告訴她。但…看來這件事必須由我來。', '', 66384),
(295376, 'zhTW', '', '勇士！艾蘭里亞才剛過來，就出發去找我們失蹤的軍官了。', 66384),
(295361, 'zhTW', '$n，謝謝你所做的一切。不論是為了聖光先鋒、為了銀月城…還是為了我。', '', 66384),
(295360, 'zhTW', '謝謝你！我們會重整態勢，準備再次出擊。', '', 66384),
(295359, 'zhTW', '多虧你我們才能保住小命！', '', 66384),
(295358, 'zhTW', '聖光會保護我們，但得盡快行動！', '', 66384),
(295357, 'zhTW', '盡快進行治療。到集合點會合！$n，保護他們！', '', 66384),
(295356, 'zhTW', '薩卡許是最優秀的年輕鬥士。如果他對娜瑪琪感興趣，我的計畫絕不可能奏效！', '', 66384),
(295355, 'zhTW', '如果說這個地方讓我學到了什麼，那就是吞噬之眾隨時準備獵食我們的信念。', '', 66384),
(295354, 'zhTW', '這些受害者都是不幸脫隊遇害的。我們應該一起行動。', '', 66384),
(295353, 'zhTW', '願聖光祝福逝者、守護生者，讓我們保衛這個世界不受邪惡危害。', '', 66384),
(295351, 'zhTW', '我們必須去救援還在戰場上的同伴們。', '', 66384),
(295349, 'zhTW', '喔，$n。你來了，太好了。我需要你的幫助。', '', 66384),
(295348, 'zhTW', '', '嗯，防止世界毀滅而戰？\n\n如果他們能夠好好解釋，而不是像普通的強盜或聯盟入侵者一樣直接拿走貨物，我一定會免費大放送。\n\n我們可以捨棄一車的貨物。不過我希望他們記住他們現在所在的城市是誰的。', 66384),
(295344, 'zhTW', '我懂聖光為什麼召喚你參加戰鬥了。你是我們對抗虛無的典範。', '', 66384),
(295338, 'zhTW', '虛無火炮一直把我們困在這裡。是時候該以牙還牙了。你想試試看嗎？', '', 66384),
(295336, 'zhTW', '', '你！我聽過你的名號。你是那位勇士！\n\n他們說你是來幫忙擊退虛無的。\n\n這些士兵告訴我，為了太陽之井，他們需要我的貨物，然後試圖拿走一整車的東西。太誇張了，沒說謝謝，也沒補償。\n\n我不認識他們！我怎麼知道這是不是聯盟為了予取予求編出來的藉口？', 66384),
(295335, 'zhTW', '奧姆里克，你是對的。解放你的同伴正好創造了突破口，方便我們發動攻擊。', '', 66384),
(295324, 'zhTW', '把虛無操控者放了。他們雖然能在城市裡自由活動，但我們不允許他們接近太陽之井。', '', 66384),
(295323, 'zhTW', '我是術士，不是邪教徒。', '', 66384),
(295318, 'zhTW', '', '你們已經奪走我們的博學者、騎士和武器，現在連食物也要奪走嗎？', 66384),
(295315, 'zhTW', '這是為了太陽之井。我們不能只依靠法力點心生存。', '', 66384),
(295308, 'zhTW', '', '我們雖然都以聖光為指引，但你的信仰卻空洞而冷酷，我幾乎認不出這是信仰。', 66384),
(295307, 'zhTW', '', '我們留下少量的部隊來抵禦虛無風暴。若聖光願意保佑，這應該就夠了。', 66384),
(295306, 'zhTW', '', '你一再要求我們，找到方法追擊薩拉塔斯就得離開。我們現在要走了。', 66384),
(295304, 'zhTW', '我的士兵太習慣和聖光對練了。他們應該要學學其他招式。', '', 66384),
(295303, 'zhTW', '$n，做得好！聖光先鋒絕對該仿效你的力量與信念。', '', 66384),
(295286, 'zhTW', '我派莉雅德倫女士去告知聖光先鋒的指揮官，他們可以立即部署，好讓我們的城市恢復安寧。', '', 66384),
(295251, 'zhTW', '', '我好像聽到北方傳來食人妖的吼聲。情況不太對。', 66384),
(295238, 'zhTW', '', '泰明！我們在找隊長…噢，那些是小熊嗎？', 66384),
(295237, 'zhTW', '戰士們，進攻！', '', 66384),
(295230, 'zhTW', '拯救小熊的謝禮…就像故事裡寫的一樣！', '', 66384),
(295229, 'zhTW', '入侵者，你得先殺了我才能奪走光木。光木武器可是…', '', 66384),
(295228, 'zhTW', '這能量太過強大了。我跟奧姆里克不一樣，撐不住的。', '', 66384),
(295225, 'zhTW', '換上偽裝，把貨物找出來。', '', 66384),
(295218, 'zhTW', '血精靈居住在從我們手中偷走的土地上。\n\n你是不會懂的。光木是屬於我們的。我們需要它！', '', 66384),
(295208, 'zhTW', '忽視他的慘叫。有看到刀刃是如何自行汲取力量的嗎？我們還有更多事要做，$n。到啃食之境找我。', '', 66384),
(295207, 'zhTW', '喔，沃坦西昂，你氣憤的滋味就跟我預期的一樣甜美。', '', 66384),
(295206, 'zhTW', '戴西蒙斯，找到新玩具了？你總是喜歡玩食物。', '戴西蒙斯，找到新玩具了？你總是喜歡玩食物。', 66384),
(295204, 'zhTW', '你好，侍僧。', '', 66384),
(295202, 'zhTW', '$c，你還在等什麼？來看看這個憎惡體會不會流血！', '', 66384),
(295189, 'zhTW', '真是美味。', '', 66384),
(295188, 'zhTW', '喔，我太微不足道了，沒資格跟舊領主一起被消滅。就像你一樣。', '', 66384),
(295186, 'zhTW', '戴西蒙斯？你還活著？我以為薩拉塔斯聯同其他領主把你消滅了。', '戴西蒙斯？你還活著？我以為薩拉塔斯聯同其他領主把你消滅了。', 66384),
(295185, 'zhTW', '別誤會了，$n。諾席恩對薩拉塔斯沒有忠誠，有的只是羨慕和貪婪。', '', 66384),
(295184, 'zhTW', '叛徒？諾席恩，我們什麼時候在乎過忠誠了？', '', 66384),
(295182, 'zhTW', '戴西蒙斯！叛徒！', '戴西蒙斯！叛徒！', 66384),
(295181, 'zhTW', '戴西蒙斯聳了聳肩。', '', 66384),
(295172, 'zhTW', '哈！那會取決於你能為我們提供多少價值。', '', 66384),
(295171, 'zhTW', '你的盟友真有意思，戴西蒙斯。或許我們可以達成協議。', '你的盟友真有意思，戴西蒙斯。或許我們可以達成協議。', 66384),
(295079, 'zhTW', '你心中有火，火焰越燃越烈！哈哈哈哈哈！', '', 66384),
(295078, 'zhTW', '面對你的火焰！面對你的火焰！如果不面對你的火焰就表示你沒那個火焰！', '', 66384),
(295077, 'zhTW', '嗯。看來你沒死。那…我看這算是可以吃吧！', '', 66384),
(295076, 'zhTW', '托爾托人給了我們食物要幫助難民。你可以幫忙確認一下這能不能吃嗎？', '', 66384),
(295069, 'zhTW', '讚美庫爾吉。你帶給我們的樹根和莖葉能讓我們的傷患有所好轉。', '', 66384),
(295068, 'zhTW', '許多人還在從暮光之刃的襲擊中恢復。幫我們從庫爾吉聖壇附近收集草藥吧。', '', 66384),
(295067, 'zhTW', '火焰之子滿足了！火焰之母也很滿意！滿艙的鮮魚終於到來了！', '', 66384),
(295066, 'zhTW', '火焰之子尋求新鮮的食物！游泳吧！潛水吧！狩獵吧！幫我們找來好多鮮魚！', '', 66384),
(295061, 'zhTW', '', '暮光之刃躲在語者之憩。讓他們見識哈巫拉是怎麼保衛祖阿曼的！', 66384),
(295060, 'zhTW', '', '$n，你解決他們了。多虧你，我們的領地又少了幾個暮光混帳。', 66384),
(295059, 'zhTW', '', '你把我們的傳家寶跟文物都找回來了。哈巫拉，謝謝你…惡齒部族和先祖感謝你。', 66384),
(295058, 'zhTW', '我們需要矯正一些事。', '', 66384),
(295057, 'zhTW', '', '暮光之刃正在洗劫我們的村子，搶走珍貴的文物。把它們討回來！', 66384),
(295049, 'zhTW', '好多人都死了。為了什麼？你應該加入他們。', '', 66384),
(295019, 'zhTW', '', '要動用武力還真可惜。但話語也不能解決所有問題。', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(295018, 'zhTW', '', '這些入侵者不會受到祖爾賈拉的保護。他們選擇入侵時就放棄那個權利了。別輕易放過他們！', 66384),
(295009, 'zhTW', '', '但我知道我的族人與我同在。他們會支持我，反之亦然。', 66384),
(295008, 'zhTW', '', '我知道你是什麼東西。我曾試著擺脫你，卻沒有成功。', 66384),
(295007, 'zhTW', '', '你已經毀了。你是虛無的一分子。', 66384),
(295006, 'zhTW', '', '我參與過更糟糕的實驗。', 66384),
(295000, 'zhTW', '但我們必須戰鬥。只要我們還沒倒下，那些犧牲就不是徒勞無功。這杯茶讓我想起了這點。謝謝你。', '', 66384),
(294997, 'zhTW', '阿曼尼、天譴軍團、燃燒軍團…我埋葬了我的許多同伴。', '', 66384),
(294996, 'zhTW', '鬼魂花？有意思。應該不會太糟吧？', '', 66384),
(294984, 'zhTW', '', '就這樣？也許我們能找到一些真正的戰士。', 66384),
(294979, 'zhTW', '我們可不能讓他們占上風，對吧？', '', 66384),
(294978, 'zhTW', '你的目標在這裡汲取力量。摧毀源頭，解決掉他們的守衛。', '', 66384),
(294977, 'zhTW', '他們會撤退去照料傷口，這時我們再趁勝追擊。', '', 66384),
(294976, 'zhTW', '讓獵物相信你無法看透他們的攻擊，接著再讓他們後悔低估你的實力。', '', 66384),
(294975, 'zhTW', '如此美妙的恐懼。', '', 66384),
(294974, 'zhTW', '還不要了結他們。沉浸在狩獵中，讓聖物吞噬他們的恐懼。', '', 66384),
(294972, 'zhTW', '大家都在看天空，我卻聽到了來自南方、步步進逼的腳步聲。\n\n聖光灌注的植物？食人妖？全都在太陽之井出問題的時候？\n\n如果我們實力太弱，不足以守護家園，何不接受虛無，還有它帶來的力量？', '大家都在看天空，我卻聽到了來自南方、步步進逼的腳步聲。\n\n聖光灌注的植物？食人妖？全都在太陽之井出問題的時候？\n\n如果我們實力太弱，不足以守護家園，何不接受虛無，還有它帶來的力量？', 66384),
(294971, 'zhTW', '「聖光先鋒」帶著一個聯盟聖騎士一起來，我知道他正是在異國海岸殺死我家人的屠夫。\n\n結果因為天空的異狀比他還要糟糕，我們就要歡迎他進入我們的城市？', '「聖光先鋒」帶著一個聯盟聖騎士一起來，我知道他正是在異國海岸殺死我家人的屠夫。\n\n結果因為天空的異狀比他還要糟糕，我們就要歡迎他進入我們的城市？', 66384),
(294970, 'zhTW', '聖光先鋒出現在我們的街道。虛無籠罩天空。我們自己的血騎士和博學者人數稀少，守不住永歌森林。\n\n我們珍視的一切怎麼可能不會毀於一旦呢？', '聖光先鋒出現在我們的街道。虛無籠罩天空。我們自己的血騎士和博學者人數稀少，守不住永歌森林。\n\n我們珍視的一切怎麼可能不會毀於一旦呢？', 66384),
(294969, 'zhTW', '你，你就是許多辛多雷對你歌功頌德的那個「勇士」。\n\n你怎麼能看著那片天空，然後肯定地告訴我們，除了逼近的末日外，還有其他更重要的事？', '你，你就是許多辛多雷對你歌功頌德的那個「勇士」。\n\n你怎麼能看著那片天空，然後肯定地告訴我們，除了逼近的末日外，還有其他更重要的事？', 66384),
(294894, 'zhTW', '瓦麗拉，我收到情報，有暮光之刃的教徒想要逃出來。但他們害怕在過程中被抓到。', '', 66384),
(294889, 'zhTW', '你的智慧拯救了你。運用我的祝福幫助他們恢復。告訴他們以後只聽我和娜妮說的話。', '', 66384),
(294888, 'zhTW', '我必須親眼看看。', '', 66384),
(294887, 'zhTW', '特蒙諾斯被擊敗了，但朧暗堡壘還是混亂不堪。你會很危險，奧斯崔。', '', 66384),
(294885, 'zhTW', '我們都有需要彌補的事。我會到朧暗堡壘找你，$n。', '', 66384),
(294883, 'zhTW', '我已經接受現實，認清我帶到特洛古斯的那些人面臨艱難處境。只要我活著的一天，我就會對我們的族人負責。', '', 66384),
(294882, 'zhTW', '啊。又見面了。不，我跟這傢伙已經鬥了太多次了。', '', 66384),
(294874, 'zhTW', '危險是交易的一部分，所以才有前所未有的獲利。', '', 66384),
(294856, 'zhTW', '', '在多曼納爾的老巢，我不能說自己覺得特別自在。不過，我們的訓練必須繼續。', 66384),
(294853, 'zhTW', '謊言失控！看向天空！死星現蹤！', '謊言失控！看向天空！死星現蹤！', 66384),
(294852, 'zhTW', '聖光先鋒讓太陽之井痛苦哀嚎！你們感覺不到嗎？', '聖光先鋒讓太陽之井痛苦哀嚎！你們感覺不到嗎？', 66384),
(294851, 'zhTW', '聖光先鋒會拋下我們！他們只在乎太陽之井！', '聖光先鋒會拋下我們！他們只在乎太陽之井！', 66384),
(294850, 'zhTW', '虛無要來了！', '虛無要來了！', 66384),
(294841, 'zhTW', '', '那我就先離開了。我的家人好久沒有像這樣團聚了，阿拉特也想和我聊聊。', 66384),
(294840, 'zhTW', '', '現在野獸死了，我可以自己回去營地。', 66384),
(294836, 'zhTW', '你應該放慢腳步。', '', 66384),
(294818, 'zhTW', '', '暮光之刃。就像其他邪教一樣。躲在面具和借來的力量之後。', 66384),
(294782, 'zhTW', '我不會再讓你乾等了。你證明了自己的資格。', '', 66384),
(294781, 'zhTW', '就這樣？你就這點能耐？真是可悲。', '', 66384),
(294780, 'zhTW', '你靠太近了！', '', 66384),
(294777, 'zhTW', '', '為了榮譽。為了榮耀。為了部落！', 66384),
(294776, 'zhTW', '', '很高興見到你。也許有朝一日，我們會在戰場上並肩作戰。', 66384),
(294772, 'zhTW', '該繼續履行我的職責了。我們回頭見。或許可以到隱士去喝一杯。', '', 66384),
(294693, 'zhTW', '', '鮮血與雷霆！我從沒想過會在這裡看到你。', 66384),
(294692, 'zhTW', '', '$n，我在這裡！我剛剛才在聊你的事蹟呢。', 66384),
(294690, 'zhTW', '營火搖曳著，好像在低聲述說還未定下的命運，吸引你過去。', '營火搖曳著，好像在低聲述說還未定下的命運，吸引你過去。', 66384),
(294688, 'zhTW', '', '我理解傳統，但你做了很光榮的事。出於對你祖先的尊重，我不會繼續干擾你的儀式。', 66384),
(294686, 'zhTW', '', '如果這些文件不見了，攝政王或許要頭痛一輩子了。', 66384),
(294685, 'zhTW', '', '$n，你真有兩把刷子。很期待再次與你合作。', 66384),
(294684, 'zhTW', '這就是我說的那位。嘿$n，我在這裡。', '', 66384),
(294683, 'zhTW', '對於你為我所做的一切，我真的是感激不盡。\n\n很高興能有你在身邊，$n。聯盟一向尊重責任感和傳統，不過在必要的情況下，我們也尊重榮耀和自由選擇的意願。\n\n願我們的道路能在未來再度交會。', '', 66384),
(294681, 'zhTW', '其他人都到咆哮峰集合了，對吧？我會到那裡找你。', '', 66384),
(294680, 'zhTW', '', '我還記得我加入部族的起始儀式。它給了我目標，不過並不是我現在追尋的目標。', 66384),
(294677, 'zhTW', '', '沒有觸發裝置，也沒有引發毒氣…做得好。我們來看看裡面有什麼。', 66384),
(294676, 'zhTW', '', '我來打開那道鎖。你去處理陷阱。', 66384),
(294643, 'zhTW', '', '$n，不錯嘛。現在就來看看他們還有什麼計畫。', 66384),
(294642, 'zhTW', '', '我會待在暗處，從上方留意。別擔心，如果情況危急，還有我在。', 66384),
(294641, 'zhTW', '', '這座山丘能給予我們優勢。別浪費了。', 66384),
(294627, 'zhTW', '', '還有倖存者！我們趕上了！', 66384),
(294618, 'zhTW', '雖然我很感謝你的同伴對我的生存技巧很有信心，但我其實更加感謝你的及時介入。\n\n我絕對不會阻撓你進行儀式。', '', 66384),
(294616, 'zhTW', '除了名字，對世界之根的了解其實少之又少。我們必須一起發掘更多真相。', '', 66384),
(294615, 'zhTW', '樹根找到回家的路，這會讓根莖守望者很高興。', '', 66384),
(294613, 'zhTW', '露伊拉成了第一個根莖守望者和根莖行者。', '', 66384),
(294612, 'zhTW', '為了立下這個誓約，樹根和露伊拉把自己的一部份結合在一起，世界之根就此誕生。', '', 66384),
(294611, 'zhTW', '源途與所有的巨樹相互連結，遍布艾澤拉斯和更遙遠的地方。', '', 66384),
(294610, 'zhTW', '現在她成為樹根的盟友與守護者。樹根也向這位新的守望者揭露了源途的奧秘。', '', 66384),
(294609, 'zhTW', '有了嶄新的力量，她驅散了毒害、治癒灼燒的傷痕，也解開了糾纏的樹根。', '', 66384),
(294608, 'zhTW', '樹根開始反抗，這場肉體的對抗轉變成精神上的搏鬥。', '', 66384),
(294607, 'zhTW', '她掌控了樹根，讓它們聽從自己的意志，進而與世界的精魂相連接。', '', 66384),
(294605, 'zhTW', '她發現我們用來變形成野獸的力量能與樹根連結。', '', 66384),
(294604, 'zhTW', '露伊拉和她的追隨者絕不會讓家園遭到摧毀。', '', 66384),
(294603, 'zhTW', '獵手露伊拉是第一個發現樹根瀕死的人。大地受到灼燒與毒害。', '', 66384),
(294602, 'zhTW', '我們以前對艾澤拉斯地表上的戰爭所知甚少，但它們確實會影響到這裡。', '', 66384),
(294587, 'zhTW', '這個人絕對能在啟蒙儀式大放異彩。', '', 66384),
(294586, 'zhTW', '我在緬懷之穴見識過許多啟蒙儀式壁畫。而且每一幅都像一顆種子，各自衍生出獨特的故事。不知道你的故事會是什麼。', '', 66384),
(294583, 'zhTW', '', '有時候，我的確很懷念冒險。這裡是我們的家，我們與歐薇娜一起展開的旅行充滿挑戰，但我也見識到在哈朗達永遠看不到的事物。\n\n至於你呢？你正在做對的事。傳統是最重要的。', 66384),
(294582, 'zhTW', '為你在哈拉提找到一席之地是一件大事。很多人指望我，因為我曾跟著歐薇娜前往外面的世界，不過事情跟他們想的不一樣。\n\n在我們的旅程中，很多人都傷痕累累地歸來，不過你只聽說冒險的部分。\n\n但這是你的大日子。你旅程的開始將會添加到緬懷之穴。', '', 66384),
(294577, 'zhTW', '我還記得部族幫我舉行成年禮的時候。現在，我擔任埃達希爾的根莖守望者。今天，我們會開始幫你在哈拉提找到一席之地。', '', 66384),
(294564, 'zhTW', '', '原來你就是那個大家津津樂道的勇士。\n\n多虧了你在太陽之井的努力，我的許多族人才能存活下來。感激不盡。\n\n現在，我會努力說服這些精靈相信，這場戰爭比他們的城市更重要。', 66384),
(294563, 'zhTW', '等等！回來這裡！', '', 66384),
(294562, 'zhTW', '那是我的聲音。這是…什麼？', '', 66384),
(294561, 'zhTW', '你們真弱。現在只剩你一個了。', '', 66384),
(294557, 'zhTW', '苦澀。濃烈。呃。我的頭…', '', 66384),
(294553, 'zhTW', '$n，做得好！多虧奧姆里克的幫助，你成功對吞噬之眾造成了沉痛的打擊。', '', 66384),
(294534, 'zhTW', '我迫不及待想再次見識你的身手。', '', 66384),
(294533, 'zhTW', '讓我們繼續在奧核點瑟納斯快樂地觀光吧。我會去那裡找你。', '', 66384),
(294532, 'zhTW', '為什麼我不在那裡？他每一次都在我身邊…', '', 66384),
(294531, 'zhTW', '', '聖光先鋒們，收集可用的武器，我們出發了！', 66384),
(294530, 'zhTW', '', '大主教，如你所願。', 66384),
(294529, 'zhTW', '將軍，或許你該去視察太陽之井的部隊。我有其他事要和攝政王討論。', '', 66384),
(294528, 'zhTW', '', '那就確保我們能掌握一切資源，防止敵人從背後偷襲。', 66384),
(294527, 'zhTW', '太陽之井絕不能陷落。', '', 66384),
(294526, 'zhTW', '', '我也告訴你，這根本不夠。只有部隊的信念才能讓太陽之井抵禦虛無。', 66384),
(294525, 'zhTW', '你已經派許多血騎士去增援太陽之井了！奎爾薩拉斯根本無人防守！', '', 66384),
(294521, 'zhTW', '我們很少有機會交流彼此的名字或互開玩笑，不是嗎？\n\n西爾朗在朧暗堡壘丟了性命。他犧牲自己救了其他人，包括我和梅拉。阿拉特派你去找他，你帶回來的只有他的日記。\n\n如果要用一個詞來描述西爾朗，我認為是可靠。他總是在照看著其他人。尤其是奧斯崔。他們彼此深愛。', '', 66384),
(294516, 'zhTW', '我們按照當初的希望，給了虛無重重一擊。不過代價卻是…', '', 66384),
(294512, 'zhTW', '我必須繼續前進。他也一定是這樣希望。', '', 66384),
(294511, 'zhTW', '', '這一定是他們間諜網路的核心。', 66384),
(294510, 'zhTW', '', '我猜洛索瑪需要有人暗中行事。別忘了，太陽也能產生最黑暗的影子。', 66384),
(294508, 'zhTW', '我必須面對自己的那部分。我會回到營地跟你會合，$n。我們有工作要做。', '', 66384),
(294507, 'zhTW', '西爾朗不在了。但我還在這裡。', '', 66384),
(294503, 'zhTW', '', '女神已經開口。透過祂的話語，我了解你踏上了截然不同的道路。\n\n你將會看到女神的山脈、海洋、森林、沙漠、生物和文明。你必須體驗祂創造的一切，屆時，你才能找到祂。', 66384),
(294482, 'zhTW', '', '我來自一個薩滿氏族。儘管我從來就聽不到靈魂的聲音，只能追求武道，但我的確很尊重你的傳統和儀式。\n\n我們也有類似的整套儀式，稱為成年儀式。也許我們彼此間的差異並不是那麼大。\n\n如果能夠再次相會，我會倍感光榮。前提是你下定決心離開哈朗達，到奧格瑪尋找自我。\n\n<蓋爾嘉點點頭，然後滿懷敬意地鞠躬。>', 66384),
(294481, 'zhTW', '我跟其他人不一樣，並不重視精神層面，這些儀式對我幾乎毫無作用。也許德萊尼能夠理解。你知道德萊尼，對吧？\n\n哈嘉爾和歐薇娜向我保證，只要我不出手干擾，他們會在你加入後送我回家。\n\n在暴風城，我們會舉行慶典，有一大堆食物，一大堆音樂和喧鬧，還有一大堆麥酒。也許你跟家人一起去狩獵，或是交到一些朋友，然後…\n\n<奧頓停頓，然後發出令人難受的苦笑。>\n\n別在意我說的。你正在這裡進行一件大事。我知道至少有四個人會興味盎然地聽你分享你的文化。', '', 66384),
(294478, 'zhTW', '她的孩子沒事…不過是哪一種魔法，就連我都不知道！', '', 66384),
(294475, 'zhTW', '好可憐的生物…我們來得太遲了。', '', 66384),
(294474, 'zhTW', '<露伊拉是對的。樹根正在死亡。\n\n如同樹根的其他部分，以及這片土地的生物，它因地表世界的爭鬥而燒焦或中毒。\n\n露伊拉決定親自插手，也許她能幫助這片土地對抗來自艾澤拉斯的傷害。>', '<露伊拉是對的。樹根正在死亡。\n\n如同樹根的其他部分，以及這片土地的生物，它因地表世界的爭鬥而燒焦或中毒。\n\n露伊拉決定親自插手，也許她能幫助這片土地對抗來自艾澤拉斯的傷害。>', 66384),
(294469, 'zhTW', '被抓走的刃多雷就像鎖鍊上的環節。切斷鎖鍊，我們才能正式發動攻擊。', '', 66384),
(294442, 'zhTW', '影衛已經走投無路了。他們不分敵我地抽取能量，把各種魔法混合起來，為他們的科技提供動力。\n\n幸好，這些混合物既危險又脆弱。\n\n我從他們的一名工程師那裡「借來」了這把步槍。用它射擊，就能讓法力容器變得不穩定。', '影衛已經走投無路了。他們不分敵我地抽取能量，把各種魔法混合起來，為他們的科技提供動力。\n\n幸好，這些混合物既危險又脆弱。\n\n我從他們的一名工程師那裡「借來」了這把步槍。用它射擊，就能讓法力容器變得不穩定。', 66384),
(294440, 'zhTW', '真美味。這樣一來，它絕對是值得記住的刀刃了。', '', 66384),
(294409, 'zhTW', '你聽見了嗎？某種生物在求救…伸出援手是遠行者的職責！', '', 66384),
(294407, 'zhTW', '', '我們早就聽過了。什麼時候才能學會呢？', 66384),
(294406, 'zhTW', '快完成了！你在聖光先鋒的朋友留下了一些光之裂片。去弄一枚來，好嗎？', '', 66384),
(294404, 'zhTW', '莫塔卡雖然被困住了，但艾恩裂隙至今依舊受到這些生物的荼毒。', '', 66384),
(294393, 'zhTW', '', '你說這個簡陋的小屋？我選擇這個位於哈瑪拉社群中心的建築物，好讓我能靠近強大泰達希爾的樹根。自那棵世界之樹誕生以來，它和它的樹根便歷經了痛苦與創傷的磨難。儘管如此，它的樹根依然強健，也願意繼續生長下去。\n\n我向外看去，想著族人在來到哈朗達的旅途中經歷的苦難。他們捨棄了許多祝福。許多人在路途中消亡。隨後還有瘋狂的到來。\n\n但是我們依然在此屹立不倒，正如我們強韌的傳統賦予我們的身分。\n\n至於泰達希爾，它的樹根會漸漸復原的，如同整個世界一樣。', 66384),
(294391, 'zhTW', '一路上一直嘰嘰喳喳。我快笑死了。', '', 66384),
(294390, 'zhTW', '那是我的動物吸引力。', '', 66384),
(294389, 'zhTW', '', '她幾乎快跟蹤你一個小時了。', 66384),
(294388, 'zhTW', '地圖上寫洞穴已經廢棄了！', '', 66384),
(294387, 'zhTW', '那次真的很搞笑。你得承認，那確實是個不錯的故事。', '', 66384),
(294386, 'zhTW', '', '希望這次不會遇上氣噗噗的河狸。', 66384),
(294385, 'zhTW', '你一定會很喜歡瀑布的。', '', 66384),
(294382, 'zhTW', '虛無意味著流血、混沌和暴力。它很美麗。有大量多曼納爾願意為了它形神俱滅也是理所當然的事。\n\n這個世界到處充斥著虛無，它甚至滲透到大地本身。因此，我們想到辦法去形塑它，利用我們對虛無的精通，改造土地的地貌。\n\n居然能用非真實的力量去影響實物，這種感覺太讓人難以自拔了。', '', 66384),
(294381, 'zhTW', '傳統讓我們能夠保持團結、強大，並且以決心和野心渡過難關。它讓我們專注在追尋自我，維持自我的平衡。也能指引我們有效處理威脅、決策，以及族人的未來。', '', 66384),
(294331, 'zhTW', '追尋者靜靜坐著。即使在那裡，我們也能聽見她的歌聲。', '', 66384),
(294330, 'zhTW', '她並不在火光裡，而在她留下的暖意之中。', '', 66384),
(294328, 'zhTW', '看起來是一面舊盾牌的碎片。', '', 66384),
(294308, 'zhTW', '在那些充滿傲慢血精靈的城市中的某個傲慢的血精靈。瑟朵娜‧暮塔。西爾朗從前認識的人。\n\n在我們來到銀月城前不久，西爾朗寫了那封信。他告訴我，他想親自把信交給她。在我們踏進虛無風暴傳送門前，他原本打算這麼做。\n\n現在一切都不重要了。', '', 66384),
(294301, 'zhTW', '原來如此。西爾朗不在了。', '', 66384),
(294300, 'zhTW', '這個任務就是個錯誤。', '', 66384),
(294299, 'zhTW', '一切都不盡如人意。你有其他人的消息嗎？', '', 66384),
(294298, 'zhTW', '慢著點！陸行鷹很固執，而且速度很快！', '', 66384),
(294296, 'zhTW', '你到底灑了什麼種子？這些花跟我以前見過的完全不一樣。', '', 66384),
(294284, 'zhTW', '使用晶化虛無，強化鋒刃！', '', 66384),
(294273, 'zhTW', '用虛無火盆加熱刀刃！', '', 66384),
(294272, 'zhTW', '從那個虛無容器中抽取能量。在暗影中進行淬火！', '', 66384),
(294271, 'zhTW', '把巨獸的骨粉均勻灑在虛無燃燒的刀刃上。這會使金屬硬化。', '', 66384),
(294270, 'zhTW', 'Anu bala belore\'alon, malanore。（溫暖的陽光在等待我們，旅行者。）', '', 66384),
(294269, 'zhTW', '做得好！植物已經發芽了，有些還長得很奇特！', '', 66384),
(294259, 'zhTW', '下次，我會直接問當地人！', '', 66384),
(294258, 'zhTW', '在無響火焰的影響下，沒有人能聽見女神的歌聲。', '', 66384),
(294257, 'zhTW', '歐巴悠知道無響火焰是他們唯一的希望。', '', 66384),
(294253, 'zhTW', '擊殺哈拉尼爾！摧毀哈朗達！一切都會加入混亂合音！', '', 66384),
(294239, 'zhTW', '很可惜，我們沒有相關知識，無法重新點燃無響火焰。也許有一天能…', '', 66384),
(294236, 'zhTW', '真羨慕你有機會見到歐巴悠，了解關於無響火焰的事，$p。', '', 66384),
(294235, 'zhTW', '但她領會到這不是痛苦，而是一種責任。不受回音影響的她在裂隙中獵殺暗影，也訓練那些付出相同犧牲的人。', '', 66384),
(294234, 'zhTW', '不過，在此同時，請好好照顧牠。那或許是讓牠健康成長的最好方式。', '', 66384),
(294233, 'zhTW', '歐巴悠發現被犧牲的不只是火焰而已。她再也聽不到女神的歌聲，她心中的連結被燒斷了。', '', 66384),
(294232, 'zhTW', '總有一天，菲德菲可一定會成為恐怖的存在。', '', 66384),
(294231, 'zhTW', '我很高興聽到這個。我很不想說出口，但你做得很好，凡人。', '', 66384),
(294230, 'zhTW', '$n！我才正要開始。這會是一場技藝的試煉，但我一定能修好這面盾牌。', '', 66384),
(294229, 'zhTW', '火焰反而被分成三個困住怪物的結界，哈朗達也因此獲救。', '', 66384),
(294228, 'zhTW', '歐巴悠知道無響火焰中剩餘的力量不足以消滅莫塔卡。', '', 66384),
(294225, 'zhTW', '', '$p，離開十字軍時，我充滿了疑問、恐懼和不安。\n\n那是我一生中做過最困難的事。\n\n但現在，我知道自己所知道和相信的一切都是錯的。\n\n我很高興能幫艾莉賽走上相同的路途。', 66384),
(294224, 'zhTW', '', '$p，我曾試著建立被遺忘者與人性之間的橋樑，卻因此喪生。這很值得，我至今也在追尋這個目標。\n\n所以我很謝謝你和阿隆索斯送艾莉賽來我這裡。\n\n她似乎很有學習的熱忱，也很認真地彌補她犯下的過錯。', 66384),
(294223, 'zhTW', '這些實體受到裂隙失諧歌聲的折磨，但無響火焰帶給了它們平靜。', '', 66384),
(294222, 'zhTW', '', '謝謝你在我逃離血色十字軍時放我一馬。\n\n這些年來，我一直有著疑慮，但我卻從未正視。\n\n跟卡莉雅和瑪莉拉談過後，徹底顛覆了我對世界的看法，$p。\n\n這感覺就像向下墜落，但同時也很像掙脫束縛。\n\n有了他們幫忙，我知道我會落在更好的地方。', 66384),
(294221, 'zhTW', '但率領裂隙化身的是名叫莫塔卡的怪物，對整個哈朗達造成威脅。', '', 66384),
(294220, 'zhTW', '哈拉尼爾會避開艾恩裂隙。女神歌聲的失諧回音會帶來瘋狂。其中的兇殘化身會帶來死亡。', '', 66384),
(294219, 'zhTW', '', '小心腳下！我正在採集一些暮葉，可以把其他兩人收集的東西包起來。\n\n小莫可能早就想出計畫了。他一直是這樣。不過，他不在這裡，現在只能靠我了。\n\n<納耶里停頓了一下。>\n\n無論如何，我會把他帶回來。真高興你在這裡…我們會需要彼此。', 66384),
(294218, 'zhTW', '', '喔！我沒聽見…我還以為你是瓣翼鳥。\n\n我…正在摘火葉和低語花。它們聞起來甜甜的，如果正確燃燒，它們會提高你的反應時間。\n\n小莫總是說，我的手很靈巧，適合做細膩的工作…我想要他回來。我好想他。所以，就算很可怕，我也會幫忙。', 66384),
(294215, 'zhTW', '嘖。別像那樣悄悄出現在我背後！我差點弄掉發光之根。\n\n這些植物？它們能讓你的腳步更有活力。如果那隻巨大的羽毛生物回來，可能幫得上忙…我才不是害怕。只是…必須有人做好準備。\n\n小莫總是會找到我們。現在輪到我們去找他了。懂嗎？', '', 66384),
(294214, 'zhTW', '現在，你們兩個都滾吧！你們不再值得我關注。', '', 66384),
(294213, 'zhTW', '如果我認為那隻野獸擁有值得我納為己有的力量，我就會親自吞噬牠！', '', 66384),
(294211, 'zhTW', '我真是太蠢了，居然把時間浪費在一隻如此可悲的蟲子上！', '', 66384),
(294209, 'zhTW', '他是什麼？', '', 66384),
(294202, 'zhTW', '第二次大戰幾十年前就結束了。我不會讓他們破壞你努力實現的和平。', '', 66384),
(294201, 'zhTW', '黑暗部落準備好要突襲另一個邊境營地了。取得最後一塊盾牌碎片，擊潰敵人的部隊。', '', 66384),
(294192, 'zhTW', '', '光綻十分頑強，我們也必須如此。', 66384),
(294191, 'zhTW', '', '精準攻擊？我應該召集所有人的。', 66384),
(294190, 'zhTW', '不…你還沒見識到我真正的實力！', '', 66384),
(294186, 'zhTW', '告訴我…那隻野獸可怕嗎？兇猛嗎？致命嗎？', '', 66384),
(294185, 'zhTW', '', '這些生物可以帶我們下去，但動作要快。我不想讓牠們暴露在光綻之下太久。', 66384),
(294184, 'zhTW', '', '他對女神的信仰轉化成憎恨。這就是光綻造成的影響嗎？', 66384),
(294183, 'zhTW', '', '我會封鎖源途。他再也逃不掉了。', 66384),
(294182, 'zhTW', '透過光綻，我可以讓哈拉尼爾變得更強大。但你阻撓了我的計畫。', '', 66384),
(294181, 'zhTW', '', '魯亞在這裡？', 66384),
(294180, 'zhTW', '光綻不受任何控制。你無法永遠抑制它。', '', 66384),
(294177, 'zhTW', '', '原來魯亞就是躲在這裡…', 66384),
(294175, 'zhTW', '入侵我們的庭園得付出代價，光綻會確保你老實交出來。', '', 66384),
(294174, 'zhTW', '', '那看起來很危險。我們必須在他們完成灌注前將它摧毀。', 66384),
(294173, 'zhTW', '安杜因‧洛薩戰死後，我的父親便召集聯盟贏得勝利。', '', 66384),
(294172, 'zhTW', '我的父親圖拉揚曾參與過這場戰鬥，但他很少和我提起。', '', 66384),
(294171, 'zhTW', '', '全面攻擊只會讓光綻蔓延出去。精準打擊最危險的部分區域才是最好的辦法。', 66384),
(294170, 'zhTW', '', '艾恩之塵數量有限，所以我們必須掃蕩光綻最活躍的區域。', 66384),
(294169, 'zhTW', '黑暗部落似乎走不出這場戰爭的陰影。他們還在這裡打一場早已輸掉的仗。', '', 66384),
(294167, 'zhTW', '你在這！法奧，你為什麼要帶我們回到這片廢墟？', '', 66384),
(294166, 'zhTW', '我沒為戴西蒙斯做任何事。我來這裡是為了監視他。\n\n我們多曼納爾永遠都在進行權力鬥爭。就算你表面上看不出來，我們其實都在一較高下。\n\n戴西蒙斯的庇護讓我有需要的資源來培養這群怪物。作為回報，我的怪物會幫忙保護戴西蒙斯。所以，我們暫時是盟友。\n\n我很清楚情況一定會改變。戴西蒙斯也很清楚這點。\n\n比多曼納爾還要致命的，就是一個帶著一群猛獸的多曼納爾。', '', 66384),
(294164, 'zhTW', '讓牠們自相殘殺，一定能催化牠們的殘暴和恐怖！\n\n不過，你們凡人提過另一種策略。你們稱為…感化。或許我應該試一下。', '', 66384),
(294163, 'zhTW', '現在讓我見識「征服」！', '', 66384),
(294162, 'zhTW', '讓我見識「兇殘」！', '', 66384),
(294161, 'zhTW', '我…但這盾牌不是我的。', '', 66384),
(294160, 'zhTW', '孩子，他說的對。這麼好的盾牌能夠保護士兵，這樣他們才能保護其他人。', '', 66384),
(294158, 'zhTW', '人都會受到打擊，但我們可以重新振作起來，變得更堅強。', '', 66384),
(294157, 'zhTW', '呸！這點子真爛！這是我聽過最爛的點子了。', '', 66384),
(294156, 'zhTW', '這場冒險的結局不該是這樣。但這是很適合的回報。', '', 66384),
(294155, 'zhTW', '嗯…我一直在想這件事。我想把它掛在這面牆上，以作提醒。', '', 66384),
(294147, 'zhTW', '菲德菲可在吉托克的屍體上發出勝利的吼聲。', '', 66384),
(294145, 'zhTW', '菲德菲可準備好證明他自己。到那隻生物在南方的巢穴找他，見證我們培育出來的猛獸。', '', 66384),
(294139, 'zhTW', '這個地方真棒，$p。\n\n謝謝你在我的旅程中出手相助。\n\n我們為其他人做了許多好事，我也從中獲益良多。', '', 66384),
(294132, 'zhTW', '菲德菲可向迷你的發泡蠕行蟲發出充滿自信的吼聲。', '', 66384),
(294120, 'zhTW', '難道說，這就是你們凡人口中的…友誼？希望如此。', '', 66384),
(294119, 'zhTW', '好奇怪，我發現自己想要多了解你一點。也想要你了解我。', '', 66384),
(294118, 'zhTW', '把烏瑟的治療包託付給我…它或許能再進行一次治療。', '', 66384),
(294117, 'zhTW', '從那時候起，我已經盡我所能侍奉聖光，但我所看過的苦難，卻也讓我被失望和痛苦糾纏。', '', 66384),
(294116, 'zhTW', '', '關於她啟發我信仰聖光的故事。我從未見過她，但我會好好愛惜這個，$p。謝謝你。', 66384),
(294115, 'zhTW', '', '就算是隊長，有時也不得不跪在地上，替獨木舟上蠟。', 66384),
(294113, 'zhTW', '', '告訴你吧，使魔。一百年後，如果你還是不喜歡我們的安排，我會讓你重新協商條款。', 66384),
(294112, 'zhTW', '', '瑪銳德是我們一族的英雄，$p。我能感覺到他的聖光，它還留在水晶中。', 66384),
(294111, 'zhTW', '菲德菲可對虛無精靈露出明顯的敵意。', '', 66384),
(294109, 'zhTW', '', '$p，你還撐得住嗎？我知道你面臨許多沉重的負擔。\n\n我必須承認，我自己…已經快撐不下去了。', 66384),
(294108, 'zhTW', '$p，多年來，我一直為了烏瑟培養阿薩斯的事對他冷嘲熱諷，但他原諒了我。雖然那讓我更生氣了。', '', 66384),
(294106, 'zhTW', '$p，這並不是我第一次見到強大的邪惡打太陽之井的主意。我或許精疲力竭，但我會像之前那樣，堅持下去。', '', 66384),
(294105, 'zhTW', '', '這樣子就很好了，不過，別忘記誰才是做主的人。也許讓你稍微吃點苦頭能讓你想起來。', 66384),
(294104, 'zhTW', '', '謝謝你，$p。我已經能感受到它的力量。我會善加利用。', 66384),
(294101, 'zhTW', '', '我不會說謊，$p，雖然能來到太陽之井這裡是莫大的榮幸，但未免太累人了。\n\n希望你帶來的是好消息，或是更多的幫助。', 66384),
(294098, 'zhTW', '無恥的精靈！我會回去，這樣我才能見證你的下場！', '', 66384),
(294097, 'zhTW', '', '我敬佩你的精神，卡爾葛。正因如此，我要求你回到我身邊。', 66384),
(294096, 'zhTW', '你以為你贏了？我永遠不滅！我是虛無！你們兩個只不過是卑賤的雜種！', '', 66384),
(294092, 'zhTW', '規則很簡單。當你找到我們的其中一個，我們就會到峽谷的末端等待。很簡單吧？\n\n<小莫的神情變得認真。>\n\n準備好開始了嗎？', '', 66384),
(294091, 'zhTW', '菲德停了下來，然後蜷縮在露齒的骸骨前方。', '', 66384),
(294081, 'zhTW', '', '你在這裡啊，泰明！我差點就要先派其他人出去了！', 66384),
(294080, 'zhTW', '等你結束後，我會回到我的野獸附近跟你會合。', '', 66384),
(294071, 'zhTW', '', '現在別嘗試做任何蠢事，布羅席尼爾斯。', 66384),
(294063, 'zhTW', '<卡爾葛用一種邪怨的眼神看著你。>', '', 66384),
(294058, 'zhTW', '希望不是…無論如何，我們在永歌森林的職責還是沒變。', '', 66384),
(294057, 'zhTW', '但是，自從那場戰亂後，已經很多年沒見過那些生靈了。也許它們死了，就像我們的許多族人一樣。', '', 66384),
(294054, 'zhTW', '過去的遊俠曾是森林的照護者，在他們的努力下，無數奇妙生靈在那裡漫遊。', '', 66384),
(294053, 'zhTW', '這也因此激勵了我…我也想成為那些古老故事的一部分。去看看吧。', '', 66384),
(294052, 'zhTW', '你可能沒料到遊俠也會有圖書館，但他們的歷史就和辛多雷一樣悠久。', '', 66384),
(294043, 'zhTW', '餵食這隻野獸，然後帶他到附近散步，讓他行使…他的統御力。', '', 66384),
(294042, 'zhTW', '我已經把材料放在桌上了。你將會進行烹飪。並且負責餵食。之後還要照顧這隻生物。', '', 66384),
(294037, 'zhTW', '', '呃…！我的天之玻璃收集工作可能會稍微延誤…！', 66384),
(294035, 'zhTW', '', '你有不服輸的精神，庫里。我以你為傲。不過，下次別叫陌生人幫你收集樹液迅猛龍葉片，好嗎？你下週欠我兩倍。', 66384),
(294034, 'zhTW', '', '我們的家園是個充滿驚奇的地方。所有事物都是如此奇特且古老！我確定艾恩夏倫就在某個地方。我只是需要找出召喚他的方式！', 66384),
(294033, 'zhTW', '', '我們的第一次嘗試失敗了。那並不表示艾恩夏倫不是真的！那只表示我漏掉了一些東西。', 66384),
(294032, 'zhTW', '', '失望？才不會！', 66384),
(294031, 'zhTW', '', '希望你沒太失望，小傢伙。謎團和傳說都是半真半假的東西。', 66384),
(294029, 'zhTW', '', '…等等。就這樣？不…不可能會這樣！我明明這麼確定…', 66384),
(294028, 'zhTW', '', '快看！產生作用了！', 66384),
(294020, 'zhTW', '迴旋孢子！', '', 66384),
(294019, 'zhTW', '狂野真菌！劇毒旋風！菇中王者！', '', 66384),
(294018, 'zhTW', '真菌與菌絲，巨菇降臨！', '', 66384),
(294015, 'zhTW', '', '你來了！來吧。把裂片丟進池子！', 66384),
(294013, 'zhTW', '<這隻生物發出一聲低吼。如果牠不是這麼小隻，感覺會很有威脅性。>', '', 66384),
(294007, 'zhTW', '<這隻小巨獸抬頭看著你，迫不及待想吃到營養的點心。>', '', 66384),
(294006, 'zhTW', '準備好就告訴我！', '', 66384),
(293986, 'zhTW', '好極了！到寧靜之憩找我談話，我們會為你的陸行鷹上鞍。', '', 66384),
(293982, 'zhTW', '', '別離我太遠。我會用黑暗聖匣強化你。我們來為這次違抗劃下句點吧。', 66384),
(293980, 'zhTW', '', '什麼…簡直難以置信。她是我的祖母。她親自護送難民從暴風城逃到羅德隆。', 66384),
(293978, 'zhTW', '', '無論這種蘑菇是什麼，我想它會把最大的手下留在身邊。提高警惕。', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(293977, 'zhTW', '', '希望你帶回了好消息，$p。我們都疲憊不堪了。\n\n先前要是沒有法奧法杖提供的加持，我們早就撐不住了。', 66384),
(293976, 'zhTW', '', '燒掉它，$c。在它擴散之前燒掉。', 66384),
(293975, 'zhTW', '', '小心點，我覺得情況不太妙。', 66384),
(293929, 'zhTW', '這片土地離理想情況還有一大段距離，但和過去相比已經改善了不少。\n\n這裡的生物正逐漸煥發生機。', '', 66384),
(293886, 'zhTW', '', '感受你周圍的虛無，$n。我們不能讓卡爾葛奪取它的力量。', 66384),
(293840, 'zhTW', '法奧，希望你知道自己在做什麼。', '', 66384),
(293839, 'zhTW', '如果我把盾牌修好，或許就能讓父親回想起他心目中聖騎士的樣子。', '', 66384),
(293837, 'zhTW', '聯盟…圖拉揚…一瞬間，一切都變了。', '', 66384),
(293829, 'zhTW', '如果那孩子找到盾牌的所有碎片，我們就可以開始了。', '', 66384),
(293824, 'zhTW', '我會把這些材料丟進大鍋，不過你要負責烹飪。', '', 66384),
(293820, 'zhTW', '選擇你想要邀請的人來贏得宮廷的青睞。但要注意：辛多雷可不喜歡被冷落。', '', 66384),
(293819, 'zhTW', '啊，辛多雷政治還真是有趣，不是嗎？', '', 66384),
(293793, 'zhTW', '', '粉絲們衝進坑洞了！', 66384),
(293792, 'zhTW', '', '小心！這些觀眾看起來不只會口出惡言！', 66384),
(293791, 'zhTW', '有些生物被貪婪給吞噬，只為了填補她離去的空虛。', '', 66384),
(293790, 'zhTW', '有些生物忘記了她的歌聲，只聽得見無聲的寂靜。', '', 66384),
(293789, 'zhTW', '有些生物依然吟唱著她和諧的旋律。', '', 66384),
(293788, 'zhTW', '這些生物還記得她曾經去過的地方。', '', 66384),
(293787, 'zhTW', '', '一點髒亂都會讓我的兄弟很煩躁。拜託，請清理地面和天空。', 66384),
(293778, 'zhTW', '哈！薩瑟里竟邀請謀殺路的人參加宴會？也許我的商品可以換來一些金幣。我加入。', '', 66384),
(293777, 'zhTW', '我鄙視這樣的運作方式。但血騎士需要為這場戰爭蒐集物資，我們快出發吧。', '', 66384),
(293776, 'zhTW', '', '幫助泰明？那裡面有幾段詩句，我想他應該會很喜歡。', 66384),
(293775, 'zhTW', '', '親愛的，就算沒有他的邀請，我也會參加。我和他已經為貴族們演過這場戲好幾次了。我去準備一下。', 66384),
(293774, 'zhTW', '我一直有打算把書還回去！反正很快就會全是野外烹飪了。', '', 66384),
(293773, 'zhTW', '', '謝了！為了訓練這些小傢伙，我根本沒時間可以看書！', 66384),
(293765, 'zhTW', '', '這是為了那個戰爭債券的宴會？好吧。我可以花點時間去那裡套套交情，好讓遠行者的金庫進帳一些貴族金幣。', 66384),
(293764, 'zhTW', '要幹嘛？都死光啦。想殺更多就等等再來。', '', 66384),
(293758, 'zhTW', '從來沒有外來者成功通過這些試煉。也許你真的像大家說的，得到了艾恩哈拉的青睞，', '', 66384),
(293757, 'zhTW', '這是我父親的盾牌，對不對？它是怎麼碎掉的？', '', 66384),
(293748, 'zhTW', '你是我的救星！先讓我…找個地方安置這東西，然後再去圖書館跟你會合。', '', 66384),
(293746, 'zhTW', '', '秘法渴望我！', 66384),
(293745, 'zhTW', '曦奔隊長真的在我身上下了很大的賭注，竟然讓法師成為遠行者。\n\n跑腿的工作比我預期的還要多。還有搬東西。更不用說那些塵土！\n\n不過我不會讓遊俠們失望的！', '', 66384),
(293737, 'zhTW', '噢，寄到兇殺路的邀請函並不是失誤。我最喜歡曲折離奇的事件了。', '', 66384),
(293736, 'zhTW', '辛多雷政治需要巧妙的處理手段。就像是一種精妙的舞蹈，而我們就是天生的舞者。', '', 66384),
(293733, 'zhTW', '好主意，努米雅。試著用它對付納迦，或許這能會剝奪他們的力量。', '', 66384),
(293732, 'zhTW', '', '這根魔杖與秘法十分契合…', 66384),
(293731, 'zhTW', '敬我們的…商人、謹慎行事的…大師，和永歌森林防衛者！Anu belore dela\'na！(願永恆的太陽指引我們！)', '', 66384),
(293730, 'zhTW', '敬遠行者、荒野保護者，和永歌森林防衛者！Anu belore dela\'na！(願永恆的太陽指引我們！)', '', 66384),
(293729, 'zhTW', '敬血騎士、聖光虔信者，和永歌森林防衛者！Anu belore dela\'na！(願永恆的太陽指引我們！)', '', 66384),
(293728, 'zhTW', '敬博學者、秘法大師，和永歌森林防衛者！Anu belore dela\'na！(願永恆的太陽指引我們！)', '', 66384),
(293727, 'zhTW', '', '忘恩負義的野獸！你以為能夠違反我們的契約嗎？追上它！', 66384),
(293724, 'zhTW', '', '當我們進入這個世界時，卡爾葛開始反抗我。幫我獻祭它。它對我們已經沒用了。', 66384),
(293721, 'zhTW', '', '每個發現都能讓我們離清除異象、恢復環境的平衡更近一步。', 66384),
(293714, 'zhTW', '啊啊，小心！殘虐腐柄來打架了。', '', 66384),
(293713, 'zhTW', '記住，你是壞蛋！要惹毛觀眾。', '', 66384),
(293712, 'zhTW', '我們會找出答案的。狩獵之路可能極為漫長。', '', 66384),
(293707, 'zhTW', '', '你看到他們了嗎？把那些間諜趕出這座村莊！', 66384),
(293706, 'zhTW', '', '哈拉齊是狩獵羅亞，而沙德拉是他的對手。獵殺沙德拉或許能取悅祂。', 66384),
(293690, 'zhTW', '誰會把好好的魔杖丟掉呢？你們博學者都這麼挑剔嗎？', '', 66384),
(293687, 'zhTW', '不穩定的秘能…這一定就是我們在找的東西！', '', 66384),
(293680, 'zhTW', '要我說的話，這是個搞破壞的大好機會。如果你願意讓我加入的話就跟我說。', '', 66384),
(293679, 'zhTW', '山裡的獸人不只握有碎片，還囤積了一堆武器。', '', 66384),
(293669, 'zhTW', '有兩種戰士：菇傘和菇柄。菇傘是英雄，觀眾為他歡呼。菇柄是壞蛋，會被噓。\n\n你想當英雄？可惜，英雄太無聊了！太多歡呼會讓戰鬥變得乏味。\n\n你現在是菇柄了。當個壞蛋，讓觀眾憤怒吧。', '', 66384),
(293665, 'zhTW', '', '妮嘉‧斷齒大笑，點頭表示同意。', 66384),
(293664, 'zhTW', '說得沒錯。有了我們的羅亞，我們能做的將不只有對抗！', '', 66384),
(293663, 'zhTW', '', '我們必須一起對抗邪枝部族。', 66384),
(293662, 'zhTW', '這裡不一樣。無論過去或未來，枯木部族都會是你的盟友。我們盡我們所能保障所有人的安全。邪枝部族是我們真正的敵人。', '', 66384),
(293661, 'zhTW', '', '不，我來自辛特蘭，那裡的枯木部族慣於獵殺惡齒部族。我想知道，這裡的枯木部族是否也是如此，或者像我這樣的難民真的能安心度日。', 66384),
(293660, 'zhTW', '妮嘉。我一直在想你為什麼來到我們村莊。是為了沙德拉嗎？', '', 66384),
(293659, 'zhTW', '', '我跟你一起去，$n。', 66384),
(293658, 'zhTW', '沙德拉，枯木部族很榮幸再次迎回你。', '', 66384),
(293657, 'zhTW', '你已經開始結網了！這都在我的預料之中。歡迎來到祖阿曼，沙德拉。', '', 66384),
(293656, 'zhTW', '', '嗯。似乎有很多事要做。我應該重生得正是時候。', 66384),
(293655, 'zhTW', '形成一顆卵了！', '', 66384),
(293654, 'zhTW', '你現在必須協助祂孵化…別出錯了！', '', 66384),
(293653, 'zhTW', '請回到你忠誠的枯木部族和惡齒部族身邊！', '', 66384),
(293652, 'zhTW', '沙德拉，我們再一次集齊你的毒牙、眼睛和甲殼。', '', 66384),
(293651, 'zhTW', '站在那裡的中心，把注意力放在三個儀式物品上。', '', 66384),
(293650, 'zhTW', '沙德拉是我很熟悉的羅亞。在她死亡前，她一直看顧著辛特蘭的枯木部族，增強他們的武器，透過她孩子的許多眼睛傳授知識。不幸的是，她經常被凡人利用，導致她變得很激進。只要她協助我的族人對抗邪枝部族，這裡就歡迎她。\n\n蜘蛛羅亞現在或許很弱小，但她會迅速成長。我會留意她。她曾度過辛苦的孤獨歲月，還受到許多虐待。我會引導她把力量用在好的地方。', '', 66384),
(293648, 'zhTW', '你的狩獵結束了。', '', 66384),
(293640, 'zhTW', '', '這正是我想聽到的。等我處理完旅行者營地的事之後，我會去那裡看看你的情況。', 66384),
(293637, 'zhTW', '我一定會讓遠行者驕傲的，隊長！', '', 66384),
(293634, 'zhTW', '', '泰明，你的任務會更加艱鉅…但你的秘法天賦會在南塔派上用場。', 66384),
(293618, 'zhTW', '', '從梅薩拉的深淵取回我的甲殼，我們再一起懲罰邪枝部族。', 66384),
(293617, 'zhTW', '', '討人厭的邪枝部族正在阻撓我的孩子，還有我的回歸。', 66384),
(293616, 'zhTW', '', '啊，我的枯木部族。還有惡齒部族。太有趣了。', 66384),
(293615, 'zhTW', '', '沙德拉！求求你，與我們對話。', 66384),
(293614, 'zhTW', '', '等你準備好要開始的時候就告訴我。', 66384),
(293612, 'zhTW', '桑凱隊長派你來的嗎？喔，他一定擔心死了。\n\n等我回報我的發現後，我不認為他的心情會有所好轉。\n\n納迦正在從各種來源收集秘能，再集中到這裡…顯然，他們當中的某些成員正在用它來強化自己，不過絕大部分的秘能都是被送上船運到海上。\n\n至於目的地和收貨人，只有時間才能解答了。', '', 66384),
(293611, 'zhTW', '我…我嚴重失算了！\n\n在這至暗的時刻，我以為我們都死定了…也許納迦掌握著活下來的關鍵。\n\n他們不想分享一絲一毫的力量。我現在明白了。我不曉得他們為什麼讓我活著…拜託，放我出去！', '', 66384),
(293610, 'zhTW', '', '但是，我們也需要眼睛。希望這足以連繫到她。', 66384),
(293609, 'zhTW', '', '羅亞注意到我們了！', 66384),
(293608, 'zhTW', '', '啊！如果你看到我，那麼我的潛行藥水一定正在逐漸失效。我得快閃了。很高興你先找到我。\n\n我偷了他們秘能的樣本…當然是為了進行調查。這應該夠了…', 66384),
(293607, 'zhTW', '', '我認為邪枝部族已經意識到沙德拉還是可以接受召喚，而且正試著阻止我們，或甚至是把她偷走！', 66384),
(293606, 'zhTW', '', '我同意，一切都是邪枝部族搞的鬼。我們來與羅亞交流吧。', 66384),
(293605, 'zhTW', '', '賈庫是…曾是哈拉尼爾最出色的畫家之一。他很少收學生，不過他說過我很有潛力。\n\n我從小時候就跟他住在一起。嗯，應該說非常小的時候。我會整天都在混合顏料，學習如何繪製我們的神聖壁畫。\n\n他已經走了…我卻還有好多要學。沒有他，我完全不知道要怎麼走下去。', 66384),
(293602, 'zhTW', '你遲到了！快去打卡！', '', 66384),
(293577, 'zhTW', '沒有其他人了。幾乎所有聖騎士都受聖光指引，來到太陽之井。\n\n在某種意義上，達瑞安欠了我一個人情，因為他曾試著殺死我，把提里奧的屍體轉化成他麾下的騎士之一。\n\n而且他完全不想看到虛無在艾澤拉斯大獲全勝。\n\n所以，當我向他求助時，黯刃騎士團就立刻站出來幫助我們。', '', 66384),
(293491, 'zhTW', '', '回到哈檜找我。我們要為自己召喚一隻飛蛇！', 66384),
(293446, 'zhTW', '想找什麼很難找的東西嗎？那你找對精靈了。', '', 66384),
(293444, 'zhTW', '', '親愛的，你有預約嗎？辦公時間是明天晚上。', 66384),
(293442, 'zhTW', '', '<她先是一臉嚴肅地打量著你，然後又露出淡淡的微笑。>\n\n護甲不錯。\n\n你在找人嗎？我的任務是幫這些遊俠為龍鷹套上鞍具，但我可以暫停一下。', 66384),
(293440, 'zhTW', '如果你需要什麼，就快說吧。我們的行程很緊湊。', '', 66384),
(293437, 'zhTW', '', '邪枝部族正在攻擊墓穴，偷走一切！讓我解釋給你聽…', 66384),
(293416, 'zhTW', '我會去通知薩瑟里領主你很快就會到了。', '', 66384),
(293408, 'zhTW', '', '快，守住西部前線！', 66384),
(293407, 'zhTW', '', '敵人從東方進逼了！', 66384),
(293406, 'zhTW', '', '北方防線受到攻擊！', 66384),
(293405, 'zhTW', '', '他們在猛攻南方防線！', 66384),
(293398, 'zhTW', '我先前沒向你全盤托出。', '', 66384),
(293395, 'zhTW', '', '奇異點錨應該能暫時封印虛無異象。我們必須在它充能的時候全力防守。', 66384),
(293393, 'zhTW', '', '裝置被毀了。重新做好準備。我們之後再試一次。', 66384),
(293392, 'zhTW', '', '奇異點錨受到嚴重損害！已經快支撐不住了！', 66384),
(293391, 'zhTW', '', '擊退他們，奇異點錨受到損害了！', 66384),
(293390, 'zhTW', '', '敵人來了。保護奇異點錨！', 66384),
(293385, 'zhTW', '我們…專注在啟動哨兵上吧。', '', 66384),
(293384, 'zhTW', '我的母親艾蘭里亞比任何人都清楚要如何對抗虛無。但我有好幾週沒看到她了。我只希望…', '', 66384),
(293383, 'zhTW', '大主教圖拉揚是個鼎鼎大名的戰場指揮官。不過…我想他有時候也會忘記該如何扮演其他角色。', '', 66384),
(293382, 'zhTW', '請原諒我父親的冒犯。可以確定的是，我們也時常意見相左。', '', 66384),
(293379, 'zhTW', '', '希望這樣能阻止他們繼續擴散，對其他區域造成威脅。', 66384),
(293378, 'zhTW', '', '這些凶狠的魯坦尼在綻放晶格的數量有點太多了。必須削減他們的數量。', 66384),
(293339, 'zhTW', '', '牠們都逃向同一個地方。來看看牠們的目的地究竟在哪。', 66384),
(293336, 'zhTW', '噢，我可不會讓你這麼快就被殺掉。', '', 66384),
(293335, 'zhTW', '你就不能敏銳一點嗎？', '', 66384),
(293334, 'zhTW', '別這麼快就被抓到。我想好好享受一番。', '', 66384),
(293325, 'zhTW', '我賜予你看見沙德拉的隱藏耳目的能力。', '', 66384),
(293324, 'zhTW', '', '安靜，兄弟。', 66384),
(293322, 'zhTW', '殺死那株該死的發光雜草。', '', 66384),
(293321, 'zhTW', '你懂我的意思，$p。', '', 66384),
(293320, 'zhTW', '那個發光的毒婦必須付出代價！鬼鬼祟祟的，把魚都嚇跑了。', '', 66384),
(293319, 'zhTW', '這會是最新鮮的一批！', '', 66384),
(293315, 'zhTW', '你必須消滅這些害蟲，不然我的名聲會徹底完蛋！', '', 66384),
(293310, 'zhTW', '', '世界之樹其實不需要太多就能茁壯成長。哈朗達正是它們的完美家園。但乾旱、寄生蟲等等威脅也變得越來越多。\n\n這對哈拉尼爾來說，與對世界之樹一樣重要。它賦予我們存在的意義，並提醒我們家園的重要。我們將以生命捍衛此地，因為我們深知，自己所做的一切是為了更大的使命。', 66384),
(293309, 'zhTW', '從你取回的武器中引導聖光！把這個怪物趕回虛無去！', '', 66384),
(293306, 'zhTW', '', '你是黑暗中的信標。我們會不記代價，取得成功。', 66384),
(293305, 'zhTW', '但兩噸重的光祝機甲還是能讓我的勇氣倍增。', '', 66384),
(293303, 'zhTW', '我的奶奶教導我要為正義而戰，就算希望渺茫，也要相信聖光。', '', 66384),
(293295, 'zhTW', '', '你的想法太狹隘了。我們必須拿出聖光先鋒的全力才能擊敗薩拉塔斯。', 66384),
(293291, 'zhTW', '', '你的重新部署只留少數人固守太陽之井！', 66384),
(293281, 'zhTW', '我找到黑暗部落的領袖了。最後一個碎片在她手上。', '', 66384),
(293280, 'zhTW', '為什麼法奧要帶我來這裡？他一定隱瞞了這個聖物的真相。', '', 66384),
(293279, 'zhTW', '我研究過第二次大戰，但對這裡的所有人來說，那不只是一段歷史。他們親身經歷過。', '', 66384),
(293277, 'zhTW', '除非你想吃點苦頭，否則別碰我的狩獵長矛。它的尖端塗著來自隱匿石的劇毒。', '', 66384),
(293276, 'zhTW', '喜歡我的戰利品嗎？蠻錘矮人不自量力地攻擊我們的村莊。當我們北上回到祖阿曼時，我都把它帶在身上！', '', 66384),
(293275, 'zhTW', '', '當我們逃離辛特蘭時，我順便帶走一些祖瓦沙的配方和聖物，不過這裡的材料截然不同。', 66384),
(293273, 'zhTW', '孩子，你該不會以為我會洩漏他的計畫吧？我會被他臭罵一頓的。', '', 66384),
(293272, 'zhTW', '這是法奧的第三個教誨。你們這些老傢伙又幫我準備了什麼？', '', 66384),
(293270, 'zhTW', '', '能生活在哈朗達，是我們的福分，同時也是我們肩上的責任。世界之樹的根盤繞於這片土地，我們必須細心照料，確保它們能持續繁盛。\n\n我是席娜，諾達希爾的充能護理師。我始終以最認真的態度承擔這份使命。', 66384),
(293267, 'zhTW', '', '我認得這根毒牙。這是來自沙德拉洛的沙德拉毒牙！真讓人擔心。邪枝部族是怎麼拿到它的？它應該被藏在很安全的地方。', 66384),
(293266, 'zhTW', '', '你說，這些毒液出自當地的青蛙？我可以用這些樣本製作抗毒藥劑，不過，這根毒牙…', 66384),
(293265, 'zhTW', '', '讓我們瞧瞧…', 66384),
(293263, 'zhTW', '枯木部族不只研究毒液和毒藥，也研究藥物和治療藥水。', '', 66384),
(293259, 'zhTW', '', '為托巴尼報仇。', 66384),
(293258, 'zhTW', '哈拉齊派你來的？', '', 66384),
(293257, 'zhTW', '去找混合者賈曼加。他對整個東部王國的各種劇毒都有很深的了解。', '', 66384),
(293246, 'zhTW', '她沒有回來。但她的一部分依舊存在，為那些記得她的人悄然綻放。', '', 66384),
(293245, 'zhTW', '我們朝歌聲呼喚，她也不曾回應。但她留下的事物會回應我們。這樣就夠了。', '', 66384),
(293242, 'zhTW', '他們跟隨的不是道路，而是一種心境的回音。', '', 66384),
(293241, 'zhTW', '石頭之間迴盪著她的歌聲，但這次不太一樣。這次的歌聲慷慨激昂，好像有什麼想分享一樣。', '', 66384),
(293239, 'zhTW', '枯木部族不會輕易屈服於邪枝部族和暮光之刃…但我們的戰士筋疲力盡。', '', 66384),
(293238, 'zhTW', '追尋者不會乞求女神的回報。他們會在記憶繚繞之地靜靜等待、聆聽。', '', 66384),
(293234, 'zhTW', '', '我們出了村莊，沿著路走，就遭到躲在森林裡的不明人士埋伏。我聽見一個聲音提到要測試新型毒液。\n\n達奇立刻就被某個東西命中，幾乎無法行走。我用最快的速度把他拖來這裡！', 66384),
(293233, 'zhTW', '這是最後一塊盾牌碎片。我想我知道它是誰的。', '', 66384),
(293232, 'zhTW', '他拖著那個東西到處走，還真奇怪。', '', 66384),
(293231, 'zhTW', '這是我們要找的其中一塊碎片。應該是來自一件護甲或一面盾牌。', '', 66384),
(293219, 'zhTW', '', '池塘就位在南方。祝你好運，$c。', 66384),
(293196, 'zhTW', '據我所知，艾羅薩‧諾‧沙德拉是一位古老羅亞。她是蜘蛛之后。我知道她已經死了，被贊達拉食人妖殺死的。\n\n在祖阿曼，並沒有太多人信奉沙德拉。前往南方的一些阿曼尼食人妖找到她，並在那裡崇拜她。我不清楚邪枝部族是否崇拜沙德拉。他們或許不知道這根毒牙是她的。\n\n不過，如果他們知道，那就很讓人擔心了。他們可能想阻止她的回歸，或是藉此達成自己的目的。要是她的毒液落入邪枝部族手中，後果不堪設想。\n\n沙德拉的軀體或許非常脆弱，但她的毒液絕不容小覷。', '', 66384),
(293194, 'zhTW', '邪枝部族持續襲擊我的山貓和枯木部族。', '', 66384),
(293192, 'zhTW', '現在安全了，只要你準備好了，隨時都能回到村莊。', '', 66384),
(293190, 'zhTW', '我覺得毒液正在逐漸失效。我在這裡，看得到，也有感覺…但不能說話，也不能動！', '我覺得毒液正在逐漸失效。我在這裡，看得到，也有感覺…但不能說話，也不能動！', 66384),
(293137, 'zhTW', '', '查娜露出微笑。', 66384),
(293136, 'zhTW', '蛙毒不像蛛毒那麼強效，不過還不錯…', '', 66384),
(293135, 'zhTW', '劇毒妖術師雷希斯愉快地哼著小調。', '', 66384),
(293124, 'zhTW', '', '敵人就要攻破我們的西邊防線了，那裡的人需要協助！', 66384),
(293121, 'zhTW', '', '敵人從北邊發動攻擊了。$p，保持警惕！', 66384),
(293116, 'zhTW', '', '敵人在東邊集結起來了，到那裡做好防禦準備！', 66384),
(293107, 'zhTW', '', '我會在莊嚴谷地的河對岸和你會合。', 66384),
(293098, 'zhTW', '$c，做好準備。', '', 66384),
(293084, 'zhTW', '啊，$c。你應該為接下來的戰鬥做好準備了吧？', '', 66384),
(293083, 'zhTW', '快把改造零件裝上去，否則我們就要窒息而死了！另一頭的空氣比一整間乳酪的味道還濃。', '', 66384),
(293075, 'zhTW', '我說的我們，指的就是你。', '', 66384),
(293070, 'zhTW', '', '他從出生的那一刻起就在無視他的大姐了。', 66384),
(293068, 'zhTW', '就差一點！那些活潑的魚真的對你很熱情。', '', 66384),
(293067, 'zhTW', '沒錯，這真是非常不錯的魚。不過，我們可以做得更好。', '', 66384),
(293066, 'zhTW', '如果我告訴你任務會讓你到很遙遠的地方呢？', '', 66384),
(293055, 'zhTW', '', '你的弟弟不止一次違抗你的命令了。我知道他是你的家人，但他都不用受到懲罰嗎？', 66384),
(293054, 'zhTW', '', '祖爾賈拉深深嘆了口氣。', 66384),
(293036, 'zhTW', '$n，庫德蘭飛到黑石塔的入口了。他已經找到下一個碎片了。', '', 66384),
(293035, 'zhTW', '黑暗部落把它們當成戰利品一樣展示，但這只預示了他們的失敗。', '', 66384),
(293032, 'zhTW', '', '哈哈哈！謝謝你，莉雅德倫。要是沒有你，沒有兩位哈巫拉，我可能撐不到現在。', 66384),
(293030, 'zhTW', '', '態度？你難道以為納羅拉克會樂意讓我走上前，用斧頭威脅他？', 66384),
(293029, 'zhTW', '只有在你理解我們的生活方式有多麼重要時，你才能確實做好你被要求的事。或許你還太年輕、太天真了。\n\n沒關係，我們的傳統和儀式會將你塑造成堂堂正正的哈拉尼爾。\n\n開始與外來者交流後，這些傳統已經變得更加重要。他們的想法…他們的理念…對我們的生活方式來說是個威脅。', '', 66384),
(293027, 'zhTW', '', '聖光為你做出了安排，$n。我感覺得到。', 66384),
(293026, 'zhTW', '我像其他侍奉聖光的人一樣讚美它，$n。\n\n但我也會穿上重甲，操作一些戰爭機器。', '', 66384),
(293023, 'zhTW', '你踏上了另一條道路。我們其他人會遵循傳統。雖然你踏上的道路並非傳統，但卻能引領我們的未來。祝你順利，願女神能在道路上指引你。', '', 66384),
(293020, 'zhTW', '肯定就是這個了吧？', '', 66384),
(293019, 'zhTW', '啊，又一個！來看看吧。', '', 66384),
(293017, 'zhTW', '哈囉！真高興再次見到你！\n\n遠行者的訓練非常艱苦。訓練內容有很多長途跋涉、無聲觀察，還有學習聆聽大地的聲音，不過我覺得很不錯。每踏出一步，我都能感覺更了解自己。\n\n我很感謝你幫助我看清…謝謝你幫我找到這條道路！', '', 66384),
(293015, 'zhTW', '我已經作為遠行者、博學者助理，以及無數有志之士的導師服侍銀月城數十年了。\n\n現在，身為首席講師，我的職責並不是為他們選擇前路，而是引導他們踏上呼喚著他們的靈魂的路途。每一條路的需求都各有不同，而我也在每一條路上都走得足夠遠，知道該尋找什麼。\n\n我做的並非塑造英雄…我會幫助他們認清他們本就擁有的力量。', '', 66384),
(293013, 'zhTW', '', '或許吧。但我想他大概也會不想被一個高傲的「入侵者」精靈問候。', 66384),
(293012, 'zhTW', '', '達尼爾的做法看似嚴格，但他秉持傳統不是沒有原因的。在我們進行儀式的時候，你必須真心看待我們族人的做法。歐薇娜進行她的儀式時，我也給了她同樣的建議。', 66384),
(293011, 'zhTW', '我們不停受到干擾。你的啟蒙儀式才是優先事項。我們的傳統正是哈朗達繁榮昌盛的原因，與此同時，其他土地只會陷入衝突的泥沼。', '', 66384),
(293010, 'zhTW', '', '你的動機是好的。只要能改變一下態度就更好了。', 66384),
(293009, 'zhTW', '', '還剩最後一個試煉。真的嗎？哈謝究竟是什麼？我有辦法幫助族人嗎？', 66384),
(292997, 'zhTW', '走開，你這長過頭的捲心菜！', '', 66384),
(292996, 'zhTW', '', '野獸，你該慶幸我沒有帶斧頭！', 66384),
(292992, 'zhTW', '', '但當我在最黑暗的時刻，懷著善意向聖光祈求時，聖光就會出現。', 66384),
(292991, 'zhTW', '我會好好享受的。幫我個忙，把他殺了。', '', 66384),
(292990, 'zhTW', '一次失誤就會一敗塗地。讓他後悔放棄那可悲的抵抗。', '', 66384),
(292989, 'zhTW', '噢，他就在附近。你可以感覺到他的恐懼嗎？我已經感覺到了…真是美妙至極。', '', 66384),
(292987, 'zhTW', '我的魔法揭露了他的小小藏身地。用鮮血染紅那裡吧。', '', 66384),
(292986, 'zhTW', '啊，那個亂竄的鼠輩停下來想喘口氣了。去把他大卸八塊。', '', 66384),
(292985, 'zhTW', '', '我握有聖光。卻抱持理所當然的態度對待它，那是我的過失。', 66384),
(292983, 'zhTW', '啊，學徒來了！我們今天為你跨出了一大步。', '', 66384),
(292964, 'zhTW', '', '但無論成功與否，只要是發自內心，虔誠完成的靈性之旅，都有價值。', 66384),
(292963, 'zhTW', '歡迎，$n。你的步伐中透露出目的。你今天來找我有什麼事嗎？', '', 66384),
(292958, 'zhTW', '遠行者優雅無比，在森林中暢行無阻，彷彿與環境合而為一。\n\n他們與自然的連結，還有守護人們的方式，都令人讚嘆。\n\n我一直都很佩服他們在力量和隱蔽之間取得的平衡，悄無聲息地行動卻從來不會失手。', '', 66384),
(292957, 'zhTW', '血騎士勇猛、自豪，對自己的使命絕不動搖。\n\n我很佩服他們不惜一切代價，引導太陽之井的力量守護銀月城的舉動。\n\n他們的力量和榮耀激勵著我，他們真的將保護和服務的意義體現得淋漓盡致。', '', 66384),
(292956, 'zhTW', '博學者真是驚人，能夠精通秘法、隨意控制魔法，彷彿那是他們的第二天性。\n\n我一直都很佩服他們的紀律和智慧，還有他們毫無迷惘地控制龐大力量的方式。\n\n要是我能學到他們的一點皮毛，我就覺得很幸運了。', '', 66384),
(292955, 'zhTW', '', '我…無法形容。我不清楚。', 66384),
(292951, 'zhTW', '', '遠行者是奎爾薩拉斯的眼睛和刀刃。我們在暗處行動，出手迅速，在危機靠近之前保護我們的族人。\n\n我們不會等到敵人兵臨城下…我們會在荒野中對敵，在戰爭爆發前將其扼殺。這份職責需要技巧、直覺，還有在必要時獨自行動的意志。\n\n但如果你有這個意願，沒有什麼比穿上綠色和金色制服更高的榮耀。', 66384),
(292942, 'zhTW', '血騎士是銀月城的劍與盾，受到使命、力量和榮譽的約束。\n\n我們是受到選召的少數，能夠運用太陽之井的力量和永不動搖的信念守護我們的族人。我們的道路是由紀律、犧牲，以及保護那些無法自保之人的堅定意志所構成。\n\n如果你想加入我們，那就必須做好面對來自內部和外部挑戰的準備…因為血騎士的忠誠和力量無時無刻都會受到考驗。', '', 66384),
(292941, 'zhTW', '', '看著你進行賈納雷的試煉讓我很不安。你還好嗎？', 66384),
(292940, 'zhTW', '', '我很好。感覺好像卸下了一個重擔，但又有了新的責任。', 66384),
(292938, 'zhTW', '博學者是真正的學者和秘法的大師，受託引導銀月城的魔法命運。\n\n我們塑造魔法的流動，駕馭其龐大的力量，用以保護我們的族人並拓展我們的知識。我們並非單純是法術的使用者，我們是古老秘密的守護者，受到智慧與紀律的約束。\n\n踏上博學者之路，就是要展開對知識的無盡追求，並掌控能夠形塑世界的力量。', '', 66384),
(292934, 'zhTW', '', '$n，他們正在綁走聖光先鋒的軍官。這純粹是因為野獸的飢餓，還是薩拉塔斯在收集情報？', 66384),
(292922, 'zhTW', '', '先鋒制服的碎片…軍官紋章…正如我所料。', 66384),
(292921, 'zhTW', '', '我猜是阿拉特派你來幫我的？我確實不介意多一點幫手。', 66384),
(292908, 'zhTW', '$n，借一步說話。請你不要在母親面前提起阿曼尼小徑發生的事。', '', 66384),
(292907, 'zhTW', '', '我讓大家…失望了…', 66384),
(292904, 'zhTW', '很久很久以前，阿曼尼帝國控制著祖阿曼周邊的所有土地。這些地區就是你後來所知的辛特蘭和阿拉希高地。\n\n那裡有我們的殖民地…但當祖爾金戰死，羅亞不再發聲之後，我的弟弟前往了辛特蘭和阿拉希高地，希望奪回那些地區的控制權，讓我們回到曾經的生活方式。我們都屬於枯木部族，但現在卻又都不盡相同，他們甚至崇拜其他羅亞。\n\n不久前，我們在辛特蘭的一些表親被逐出那裡。有些人追求暴力，前往阿拉希高地，加入同樣喜歡逞凶鬥狠的族人。那些追求和平的人，則回到祖阿曼，成為我們的家人。', '', 66384),
(292901, 'zhTW', '怨鬥坑洞是觀戰的最佳地點！', '', 66384),
(292850, 'zhTW', '', '我會留在這裡…呃…觀察情況。等你找到一大堆天之玻璃就大喊，我會飛奔過去！', 66384),
(292834, 'zhTW', '聖光先鋒滿懷信念出擊，士兵們卻負傷回到醫護站。', '', 66384),
(292830, 'zhTW', '$n，去向山拳指揮官回報。我們希望你能加入機甲突襲行動。', '', 66384),
(292824, 'zhTW', '', '我們會連續好幾週都在收集樹液迅猛龍葉片…', 66384),
(292823, 'zhTW', '噢，可是根莖守望者！', '', 66384),
(292822, 'zhTW', '', '你們兩個，跟我來。這個旅行者得去收拾你留下的殘局。然後我們得來談談尊重這件事。', 66384),
(292821, 'zhTW', '', '嗯，你想幹什麼？之前生意興隆，所有人都需要空氣！\n\n結果，現在人人都有空氣，就沒人要付錢跟我買了。\n\n別擔心，我已經開始籌備我的下一次創業了。我把它取名為「瓶中水」。\n\n想像一下標籤：一些風景優美的林地，一位精靈在顯眼的位置休憩。純粹。自然。\n\n用對銷售手法，人們就會花五十金來買幽坑城的自來水。', 66384),
(292811, 'zhTW', '', '歡迎，$n。\n\n今天對你來說是至關重要的一天。你將迎來成年禮，在我們的社會中獲得一席之位，並在我們遵循女神意志的道路上，協助維護傳統。', 66384),
(292810, 'zhTW', '呃喔…哈、哈囉，根莖守望者卡瑪瑞。', '', 66384),
(292809, 'zhTW', '', '庫里，等等！喔，女神啊，她跑走了。', 66384),
(292808, 'zhTW', '', '艾恩夏倫絕對存在！我會向你們所有人證明！', 66384),
(292807, 'zhTW', '', '庫里憤怒地啜泣。眼角掛著晶瑩的淚水。', 66384),
(292806, 'zhTW', '面對現實吧，庫里！艾恩夏倫這種東西根本不存在！', '', 66384),
(292805, 'zhTW', '', '想都別想！像你這樣的小鬼才不知道怎麼用天之玻璃。而且，你居然還以為它們來自會飛的蜥蜴！', 66384),
(292804, 'zhTW', '', '好了，你們這些傢伙！還給我！那些天空裂片是我的！', 66384),
(292793, 'zhTW', '我解鎖更強大秘法能力的秘密？洋蔥和香蕉果汁！', '', 66384),
(292785, 'zhTW', '我收到博學者奧姆里克的消息。前往虛無風暴的路開通了！', '', 66384),
(292773, 'zhTW', '', '原來你在這裡。希望你不怕鳥。不會嗎？很好。', 66384),
(292771, 'zhTW', '', '$n，該繪製你的故事了。', 66384),
(292770, 'zhTW', '旋律？外來者？這些干擾玷汙了$n的心靈！', '', 66384),
(292769, 'zhTW', '', '我也聽到了。', 66384),
(292768, 'zhTW', '', '是女神！', 66384),
(292767, 'zhTW', '那是什麼旋律？', '', 66384),
(292764, 'zhTW', '', '但在你的啟蒙儀式完成前，他們應該很安全。', 66384),
(292763, 'zhTW', '', '我會尋找外來者的下落。', 66384),
(292759, 'zhTW', '你還不賴，$n。謝謝你幫助我哥哥。\n\n下一次，我也會讓自己樂在其中！', '你還不賴，$n。謝謝你幫助我哥哥。\n\n下一次，我也會讓自己樂在其中！', 66384),
(292758, 'zhTW', '你做了別人不會做的事，我欠你一命。\n\n希望我們還能再見面。', '', 66384),
(292757, 'zhTW', '你幫助了恩萊亞，更重要的是，你幫助我們處理裂隙的事務。\n\n對此，我由衷感謝你，$n。', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(292754, 'zhTW', '裂隙帶給我們最致命的教誨。你如今更加睿智了。', '', 66384),
(292753, 'zhTW', '阿瑪拉克，我很抱歉。我剛剛沒有想清楚。', '', 66384),
(292752, 'zhTW', '恩萊亞在儀式後還太過虛弱，他應該再等一下的。\n\n莫塔卡肯定會殺了他。', '', 66384),
(292751, 'zhTW', '', '$n，跟隨幻象。遵從你的內心。尋找女神。', 66384),
(292750, 'zhTW', '', '達尼爾，我們的傳統是跟隨女神的歌聲。', 66384),
(292749, 'zhTW', '不行！我們的傳統就是要待在哈朗達！', '', 66384),
(292748, 'zhTW', '', '外來者、歌聲，今天在這裡發生的一切…', 66384),
(292747, 'zhTW', '', '歐薇娜，讓源途保持開啟。', 66384),
(292745, 'zhTW', '什麼？', '', 66384),
(292743, 'zhTW', '這是你與艾恩裂隙的連結。讓它帶路吧。', '', 66384),
(292742, 'zhTW', '我準備好開始了。', '', 66384),
(292741, 'zhTW', '恩萊亞，你找到儀式地點了。', '', 66384),
(292738, 'zhTW', '法奧！你和你的朋友怎麼來落錘鎮了？別告訴我這個世界又要毀滅了。', '', 66384),
(292734, 'zhTW', '我們得在這些小裂口擴張之前封住它們。', '', 66384),
(292721, 'zhTW', '這是我跟你提過的$p。', '', 66384),
(292711, 'zhTW', '我的弟弟奇雅不小心闖入了艾恩裂隙。我進去將他救了出來，但自己卻被擊暈。\n\n當我醒來時，奇雅已經不見了，但他很安全。幸運的是，我被一位蘇卡所救，而他現在成了我的導師。\n\n然而，我在裂隙中待得太久，與艾恩哈拉的聯繫變得格外強烈，裂隙的歌聲逐漸將我逼瘋。我無法僅僅靠離開就擺脫它。\n\n這就是為什麼我必須斷絕與女神的聯繫。\n\n當我再也聽不見女神的歌聲時，我又怎能回到我的族人身邊？回到我兄弟身邊？所以，我將成為蘇卡的一員，與他們一同留在裂隙之中，守護哈朗達免受其中瘋狂的侵蝕。', '', 66384),
(292709, 'zhTW', '', '你們兩個安靜！而你，外來者，跟我來。', 66384),
(292708, 'zhTW', '', '他們做的是對的。', 66384),
(292707, 'zhTW', '$n，這次要保持專注！', '', 66384),
(292704, 'zhTW', '你有什麼事？', '', 66384),
(292688, 'zhTW', '恩萊亞看起來不太舒服。他需要幫忙。\n\n$n，拜託你去找他吧。', '恩萊亞看起來不太舒服。他需要幫忙。\n\n$n，拜託你去找他吧。', 66384),
(292684, 'zhTW', '謝謝你出手相助，$n。你是最強的！\n\n<用竊竊私語的音量。>\n\n別告訴任何人我溜去找恩萊亞。', '謝謝你出手相助，$n。你是最強的！\n\n<用竊竊私語的音量。>\n\n別告訴任何人我溜去找恩萊亞。', 66384),
(292683, 'zhTW', '', '女神啊，讓我們有勇氣面對未來的謎團吧。去揭開那個不可知的真相。', 66384),
(292682, 'zhTW', '', '這個地方。她的聲音好響亮。而且很…害怕。一直都是這樣嗎？', 66384),
(292681, 'zhTW', '', '阿克尚說我們必須拋開對女神的臆測是什麼意思？究竟有什麼這麼可怕，才要對我們隱瞞真相？', 66384),
(292679, 'zhTW', '', '把水和精華準備好。準備好之後，我們在這裡會合。', 66384),
(292678, 'zhTW', '如果他們沒這麼做，我早死了。', '', 66384),
(292676, 'zhTW', '', '他們救了我一命。', 66384),
(292674, 'zhTW', '$n！你應該直接來這裡，而不是介入外來者的事。', '', 66384),
(292670, 'zhTW', '我還以為完蛋了。多謝出手相救！', '', 66384),
(292669, 'zhTW', '', '陌生人,謝謝你。我欠你一條命。', 66384),
(292666, 'zhTW', '回到緬懷之穴完成你的啟蒙儀式。', '', 66384),
(292663, 'zhTW', '你必須專注在傳統儀式，而不是粗心的冒險者身上！', '', 66384),
(292657, 'zhTW', '', '達尼爾從來就不喜歡我。從我與外界建立聯繫之前就是了。\n\n至少，他曾有一段時間把這件事藏在心裡。他並不是唯一一個。\n\n不過，讓我告訴你…假如我有機會回到過去，不與外來者聯繫，我也不會改變我的決定。外來者能教會我們的寶貴知識實在是太多了。\n\n先這樣吧，現在的時機或場合都不適合分享這些想法。', 66384),
(292656, 'zhTW', '', '你正在參與儀式嗎？太棒了！\n\n我還記得我的。達尼爾和哈嘉爾在最後給了我他們的祝福。我原本受到傳統拘束，後來卻聽到呼喚，我被撕裂並頻頻回頭，不過它感覺更加強大，彷彿是來自我最核心的部分。\n\n別讓我的行動影響你，作為全新旅程的起點，你今天應該好好慶祝。', 66384),
(292655, 'zhTW', '外來者不該來這裡，特別是今天。', '', 66384),
(292654, 'zhTW', '', '他們不了解哈朗達的危險所在。我們必須找到他們。', 66384),
(292646, 'zhTW', '', '這是外來者的戰裝。沒了它們，他們對小型掠食者來說只是手到擒來的獵物。著實令人擔憂。', 66384),
(292645, 'zhTW', '', '你怎麼來了？你有聽到…？嗯。', 66384),
(292644, 'zhTW', '在你的內心深處聽到的模糊歌聲，讓你不由自主升起一股急切感。', '在你的內心深處聽到的模糊歌聲，讓你不由自主升起一股急切感。', 66384),
(292643, 'zhTW', '', '跟隨呼喚。跟隨你的心。', 66384),
(292642, 'zhTW', '修剪樹根需要細心和耐心，這正是良好傳統的兩大基石。', '', 66384),
(292638, 'zhTW', '', '風暴讓我的卡爾葛變得蠻橫任性。寵物，這就是你的本性嗎？一頭未受訓練的野獸？\n\n老實說，我本對你有更高的期待。', 66384),
(292626, 'zhTW', '在治療祭壇找到破碎的法杖，你就會知道更多事情。', '', 66384),
(292622, 'zhTW', '', '朋友，勝利或死亡。謝謝你。', 66384),
(292621, 'zhTW', '後會有期。', '', 66384),
(292620, 'zhTW', '', '啊，沒錯，旅程。你該回家了。', 66384),
(292613, 'zhTW', '', '你已被女神標記了，$n。是時候展開你這趟旅程了。', 66384),
(292611, 'zhTW', '', '不。我不認為我想。你已經沒有需要向我證明的事了，除非你想做些真的很蠢的事。', 66384),
(292608, 'zhTW', '', '賽菈嘆了口氣。', 66384),
(292607, 'zhTW', '', '我會跟隨女神的呼喚。', 66384),
(292606, 'zhTW', '', '歐薇娜，你總有一天得停止再到這裡來。', 66384),
(292604, 'zhTW', '你必須準備好改變自己對女神的認知。一旦得知真相，就無法改變。屆時就沒有回頭路了。', '', 66384),
(292603, 'zhTW', '', '我們要做什麼心理準備嗎？', 66384),
(292602, 'zhTW', '時候到了。你展現了對我們歷史的奉獻精神，還有強大的實力。你已經準備好知曉育所最隱晦的真相了。', '', 66384),
(292597, 'zhTW', '', '你的儀式即將結束，$n。你看到了什麼？傳承石向你展示了什麼？', 66384),
(292588, 'zhTW', '', '一棵樹可不只有樹根而已。這個世界也不只有哈朗達這個地方。', 66384),
(292579, 'zhTW', '你是「羅亞語者」，對吧？那就跟祂說話！讓庫爾吉為我們效力！你發過誓了！', '', 66384),
(292578, 'zhTW', '妖術之王法杖？但是，每個使用法杖的人…這是一件邪物…', '', 66384),
(292577, 'zhTW', '別白費口舌。我不需要你。我會找到辦法！', '', 66384),
(292576, 'zhTW', '你應該使用它，席塔！毀誓者！', '', 66384),
(292575, 'zhTW', '不！治療我，你這個無能的羅亞。你要為阿曼尼效力。', '', 66384),
(292574, 'zhTW', '不是我把你困在這裡。是你必須決定是否前進。', '', 66384),
(292573, 'zhTW', '還是由血肉構成，沒有資格享受永生。你必須理解這點。', '', 66384),
(292572, 'zhTW', '我是酋長。我的父親是酋長。我們都是神聖的戰士…', '', 66384),
(292570, 'zhTW', '沒錯。這是用來傷害羅亞的妖術之王法杖。當我弄壞它時…黑暗魔法反噬了。我並不打算傷害任何人。', '', 66384),
(292569, 'zhTW', '我不可能會死。這是騙局。你錯了！', '', 66384),
(292568, 'zhTW', '席塔，你現在知道這根法杖代表什麼了吧？', '', 66384),
(292567, 'zhTW', '有時候我無能為力。任何人都幫不上忙。', '', 66384),
(292566, 'zhTW', '我的解藥並非無限。生命也是。', '', 66384),
(292565, 'zhTW', '那我呢？放我走！', '', 66384),
(292562, 'zhTW', '我不得不在我的誓言之間做出選擇。現在輪到阿庫土了。我沒有責任強迫他接受。', '', 66384),
(292561, 'zhTW', '永別了，阿庫土。我把法杖…我的內疚…都投入火中。', '', 66384),
(292557, 'zhTW', '當席塔準備離開的時候，他就能離開。這也適用於其他人。', '', 66384),
(292554, 'zhTW', '', '讓我們並肩作戰。為了艾澤拉斯！', 66384),
(292553, 'zhTW', '所有人團結一心！為了奎爾薩拉斯！為了艾澤拉斯！', '', 66384),
(292552, 'zhTW', '', '我與你同在！', 66384),
(292550, 'zhTW', '$n，這是你的本性嗎？尋找真實的自己吧。', '$n，這是你的本性嗎？尋找真實的自己吧。', 66384),
(292547, 'zhTW', '暮光之刃對永歌森林的滲透有多徹底？', '', 66384),
(292528, 'zhTW', '<你感覺到心中傳來一陣寂靜的歌聲。雖然你無法理解其中涵義，卻能感受到來自內心深處的呼喚。某種東西在牽引著你，它想要與你交流。>', '', 66384),
(292504, 'zhTW', '', '如此強烈的氣勢…竟出自一名外來者。法杖就交給你了。你證明了自己的實力。', 66384),
(292503, 'zhTW', '', '我接受挑戰！', 66384),
(292501, 'zhTW', '', '阿克尚認為你有資格學習知識。知識就是力量，但你是否具備駕馭知識的力量呢？', 66384),
(292500, 'zhTW', '', '來吧。看看阿克尚挑選學生的眼光好不好。', 66384),
(292499, 'zhTW', '', '哈朗達是個危險的地方，每個瀑布之後都藏有秘密。話雖如此，你也要有膽量去探索。', 66384),
(292498, 'zhTW', '<你沒發現什麼值得注意的東西。看來你可能被派來進行一趟瘋狂的哈拉尼爾追尋之旅。>', '<你沒發現什麼值得注意的東西。看來你可能被派來進行一趟瘋狂的哈拉尼爾追尋之旅。>', 66384),
(292497, 'zhTW', '<你發現破損的碎木片，但它們沒什麼特別之處。法杖不在這裡。>', '<你發現破損的碎木片，但它們沒什麼特別之處。法杖不在這裡。>', 66384),
(292496, 'zhTW', '<你發現一些失竊雜物的證據，但沒有完好無缺的東西。>', '<你發現一些失竊雜物的證據，但沒有完好無缺的東西。>', 66384),
(292494, 'zhTW', '酋長，我們的要求是對庫爾吉的褻瀆。祂說死亡已經降臨於你…', '', 66384),
(292493, 'zhTW', '那個羅亞會照我說的做。來吧，拿著這根妖術之王法杖。為了祖爾金的榮耀，我們會奪走庫爾吉的力量！', '', 66384),
(292485, 'zhTW', '他們創造了自己的詛咒。\n\n那其實比想的還簡單。', '', 66384),
(292481, 'zhTW', '他們內心深處確實知道實情。他們是否能面對現實，那是他們的難關。', '', 66384),
(292479, 'zhTW', '我是庫爾吉。阿奇爾森在風中呼喊你的名字，$n。\n\n很榮幸能邀請你來。\n\n你並不需要為我聖壇的情況負責。那是他們選擇的命運。他們拒絕承認事實。他們早已忘記自己的死因…以及導致死亡的背叛。\n\n不過，如果你想要代表他們插手此事，我也不會阻止。', '', 66384),
(292476, 'zhTW', '我們可以談談。', '', 66384),
(292475, 'zhTW', '你是羅亞的朋友。', '', 66384),
(292464, 'zhTW', '我想要答案。我會親自去跟庫爾吉對質！', '', 66384),
(292456, 'zhTW', '', '等等！我投降！我很久以前就對這個組織失去信念了。我可不想為他們賠上性命。', 66384),
(292444, 'zhTW', '', '我正在梣谷的外圍巡邏，結果有一道超亮的綠光閃瞎我的眼睛。我醒來就來到這裡了。\n\n跟那隻野獸對戰時，我弄丟了我的斧頭。我欠你一命。', 66384),
(292442, 'zhTW', '我正在艾爾文森林的大樹附近進行例行巡邏。突然有道綠光一閃而逝，然後我就跑到這裡了。\n\n這個地方的大自然既野蠻又無情。', '', 66384),
(292430, 'zhTW', '祖爾賈拉會做出對族人最好的選擇。\n\n但羅亞？嗯…也許我們都心知肚明。', '', 66384),
(292424, 'zhTW', '喔，親愛的，不了。再試一次這個吧。', '', 66384),
(292421, 'zhTW', '太棒了！來看看你帶了什麼吧！', '', 66384),
(292420, 'zhTW', '阿拉特，聖光或許會強化其信徒，但這股力量的道義取決於每個人的內心。', '', 66384),
(292417, 'zhTW', '', '當你在忙的時候，我一直在採收生長在這裡的藥用植物的葉子。上次見到魯格時，他讓我看過它們長什麼樣子。\n\n它們可以製成很好的敷料，讓你敷在傷口上。似乎能夠縮短治療時間。', 66384),
(292413, 'zhTW', '我已經開始期待你的歸來。', '', 66384),
(292412, 'zhTW', '卡爾，親愛的姊姊，找到這麼好用的旅行者，不是一件好事嗎？', '', 66384),
(292411, 'zhTW', '', '說得沒錯，瓦爾。', 66384),
(292410, 'zhTW', '我的朋友！你幫了我們很大的忙。這會為索勒之名帶來榮耀。', '', 66384),
(292406, 'zhTW', '謝謝你救了我，$G兄弟:姊妹;。我欠你一命，或至少欠你一個擁抱，哈。\n\n圖阿瑪一直在想辦法帶我們回家。請原諒她如此提防你。我們跟之前唾棄燃燒軍團的曼那瑞結盟，但這並非沒有代價。\n\n<裘拉斯握住他的那魯墜飾，深深吐出一口氣。>\n\n我們都知道被丟下的感覺有多糟。', '', 66384),
(292405, 'zhTW', '', '我曾聽說過那些光鑄同胞的故事，但在這之前我從來沒親眼見識過。$G兄弟:姐妹;，能在這樣的地方見到你真是奇蹟。\n\n我是圖阿瑪。我的職責是保護我的族人「虛空使」，讓他們安全回家。', 66384),
(292400, 'zhTW', '聖光之願有危險了，整個世界也有危險了。我必須全心投入戰鬥。', '', 66384),
(292399, 'zhTW', '但握有聖光又有什麼意義？要永無止境地對抗邪惡嗎？', '', 66384),
(292398, 'zhTW', '我不該讓我的困惑成為守住這個地方的絆腳石。', '', 66384),
(292397, 'zhTW', '我怕我在這裡對抗天譴軍團，就會變得和我父…我會陷入無盡怒火之中。', '', 66384),
(292396, 'zhTW', '我已經請求黯刃騎士團前來協助，但我們也需要你幫忙抵禦這次進攻。', '', 66384),
(292395, 'zhTW', '許多防衛者都被調去太陽之井，天譴軍團差點攻破這座禮拜堂。', '', 66384),
(292394, 'zhTW', '泰羅索斯領主，我不知道情況會變得如此嚴重。我們可以幫什麼忙嗎？', '', 66384),
(292392, 'zhTW', '', '切莫懼怕生或死的試煉，$n。\n\n萬物皆為一個循環。一切都會在不滅之焰中重獲新生。', 66384),
(292391, 'zhTW', '祂現身了。祂。\n\n新的賈納雷是一隻母雞！咯咯，咯咯！\n\n這是個好兆頭。這是治癒的象徵，也是羅亞恢復平衡的象徵。', '', 66384),
(292390, 'zhTW', '影衛崗哨', '影衛崗哨', 66384),
(292389, 'zhTW', '', '賈納雷，Mado\'ru（謝謝你）。這些試煉讓我更加了解我自己。希望之後的試煉能讓我學到更多。', 66384),
(292310, 'zhTW', '見識最後的試煉吧！面對你的挑戰，與你自己正面對決！', '', 66384),
(292309, 'zhTW', '', '不。接受協助讓我們變得更強。我不會讓自己的傲慢害族人滅亡。', 66384),
(292308, 'zhTW', '', '祖爾賈拉發出一聲令人毛骨悚然的戰吼。', 66384),
(292259, 'zhTW', '我真的很喜歡看牠們逃命的樣子。', '', 66384),
(292257, 'zhTW', '為了落錘鎮的居民，還有很多事要做，$p。\n\n幫助那些需要幫助的人，正是安希的教誨。', '', 66384),
(292241, 'zhTW', '啊！什麼都…感覺不到。席塔又失敗了。', '', 66384),
(292240, 'zhTW', '庫爾吉！我獻祭給你這部分的肉體，治療我，抗拒死亡。我需要你的治癒之力！', '', 66384),
(292208, 'zhTW', '給我那個肝臟。我什麼都會試。', '', 66384),
(292206, 'zhTW', '痛苦。痛苦！\n\n永無止盡。\n\n讓痛苦…停下。', '', 66384),
(292203, 'zhTW', '好好享受吧。', '', 66384),
(292202, 'zhTW', '我最喜歡的小玩物到底會跑去哪…', '', 66384),
(292196, 'zhTW', '', '曼那瑞。你將裘拉斯歸還給我們的舉動，證明你已經脫離了薩格拉斯的燃燒軍團。\n\n很好。$G兄弟:姐妹;，能在這樣的地方見到你真是奇蹟。\n\n我是圖阿瑪。我的職責是保護我的族人「虛空使」，讓他們安全回家。', 66384),
(292184, 'zhTW', '讓他們進來吧！我正在等快遞。快！', '', 66384),
(292180, 'zhTW', '祖爾賈拉已經成為我一直認為他會成為的哈謝了。', '', 66384),
(292176, 'zhTW', '', '我需要的…是傷害…這些殺人犯！', 66384),
(292175, 'zhTW', '如果這些飾品能激起對抗虛無影響力的記憶，那就還有希望！我們需要點時間。', '', 66384),
(292174, 'zhTW', '', '黑暗在我體內…吞噬一切…最終空無一物…', 66384),
(292172, 'zhTW', '<這名聖騎士被不知名的虛無部隊殘忍地殺害。她無神的眼睛望著天空。>', '<這名聖騎士被不知名的虛無部隊殘忍地殺害。她無神的眼睛望著天空。>', 66384),
(292170, 'zhTW', '', '只有我能開啟道路，也只有我能確保沒有人尾隨他們。', 66384),
(292169, 'zhTW', '', '只有我能開啟道路，也只有我能確保沒有人尾隨他們。', 66384),
(292168, 'zhTW', '心中之火，柴中之火。\n\n摒除疑慮，淨化靈魂！', '', 66384),
(292166, 'zhTW', '', '謎語交織重疊。\n\n至少聖光更加…直白。', 66384),
(292165, 'zhTW', '', '必須開啟。也必須關閉。只有我。', 66384),
(292164, 'zhTW', '你沒聽到心跳聲嗎？', '', 66384),
(292163, 'zhTW', '', '來吧，新朋友！我們得去收集天之玻璃！', 66384),
(292160, 'zhTW', '在畫布上的每一筆，都是來自過去的低語，等待再次發聲的回憶片段。這些聖物沉默且靜止，保留被時間的洪流淹沒的真相。\n\n當它們的回音被激起時，究竟會喚醒什麼故事？\n\n來吧，讓你的好奇心成為解鎖失落過去的鑰匙。', '', 66384),
(292159, 'zhTW', '隱藏在這些石壁中的真相，只會對準備好承擔它們的人顯露。', '', 66384),
(292158, 'zhTW', '這裡的壁畫反映我們過去的陰影，模糊但持久。\n\n有朝一日，你也可能為它們增光。', '', 66384),
(292157, 'zhTW', '我們周圍的聖物都陷入沉眠，等待一隻了解其重要性的手。\n\n有朝一日，你或許也會成為喚醒其故事的一員。', '', 66384),
(292152, 'zhTW', '', '<圖阿瑪帶著內疚和決心，與裘拉斯目光交會。>', 66384),
(292147, 'zhTW', '我會帶維蘭去安全的地方。到前面找我們。', '', 66384),
(292146, 'zhTW', '', '齊凡？是你嗎？', 66384),
(292145, 'zhTW', '這裡，$n！', '', 66384),
(292136, 'zhTW', '', '哇…以一個魯坦尼來說，你長得超詭異的。你的花朵和葉片都跑去哪了？', 66384),
(292101, 'zhTW', '多年前曾是。但天譴軍團已不再是個威脅，而我也被建議退休。\n\n而且是強烈建議。\n\n要習慣…還挺困難的。', '', 66384),
(292099, 'zhTW', '近來安寧地似乎變得更加安寧了。希望這能保持下去吧。', '', 66384),
(292098, 'zhTW', '我不喜歡這份寂靜。', '我不喜歡這份寂靜。', 66384),
(292097, 'zhTW', '我們的小鎮能對抗即將到來的風暴嗎？', '我們的小鎮能對抗即將到來的風暴嗎？', 66384),
(292096, 'zhTW', '或許我該趁還有機會的時候離開這裡…', '或許我該趁還有機會的時候離開這裡…', 66384),
(292095, 'zhTW', '鄰居失蹤…為什麼管理者什麼事都不做？', '鄰居失蹤…為什麼管理者什麼事都不做？', 66384),
(292080, 'zhTW', '如果維蘭在影衛崗哨，那或許還有時間。到那裡找我！', '', 66384),
(292072, 'zhTW', '', '我不敢相信賈庫居然留了一顆幻象之石給我！不知道裡面存了什麼回憶。\n\n我們首須快點行動，因為魯坦尼很快就會發現我們在這上面。', 66384),
(292066, 'zhTW', '', '暮光之刃造成的影響是如此之大，就連納爾丁都被迫離開他們的地盤。阿曼尼完全不是對手。\n\n希望那個祖爾賈拉像她的外表一樣強大。', 66384),
(292065, 'zhTW', '多虧有光木武器，莫爾頓倉皇敗逃了。我們應該善用當前的優勢。', '', 66384),
(292064, 'zhTW', '我們會等祖爾賈拉酋長。', '', 66384),
(292063, 'zhTW', '會議本可以有更好的結果。\n\n竟敢提到羅亞…那個精靈不該干涉我們的事。', '', 66384),
(292062, 'zhTW', '我們只剩幾個人。我們影松在行動之前會先等待。\n\n我們會傾聽火焰的聲音。當戰鬥的時機來臨時，我們就會參戰。', '', 66384),
(292061, 'zhTW', '', '阿曼尼對枯木有太多的期待，但我們正處於邪枝的威脅下。', 66384),
(292060, 'zhTW', '', '我是惡齒的戰士，但部族的發言人是莉拉菊。', 66384),
(292059, 'zhTW', '', '我為惡齒發聲！', 66384),
(292058, 'zhTW', '', '讓我們用盡全力對抗暮光之刃吧。\n\n我們和阿曼尼有共同的敵人。與他們起爭端對我們沒有好處。', 66384),
(292057, 'zhTW', '維蘭還活著…但她堅強的靈魂足以對抗虛無的影響嗎？', '', 66384),
(292055, 'zhTW', '', '我們可以搭推車耶！', 66384),
(292040, 'zhTW', '', '弩砲雖然是很好的分心手段，但莫爾頓會更難忽視我朝他的頭顱揮去的斧頭。\n\n我們開始吧。我的族人準備好出發了。', 66384),
(292039, 'zhTW', '準備好見識我們的光木火砲有多強大吧！', '', 66384),
(292038, 'zhTW', '', '祖爾賈拉想要正面迎戰莫爾頓。我打算跟她一起去。這次攻擊一定得成功。\n\n準備好就發射箭矢。願你箭無虛發。', 66384),
(292037, 'zhTW', '他們沒事。我讓他們躲在附近，遠離戰場。\n\n等有機會，我會把他們救出去。', '', 66384),
(292035, 'zhTW', '維蘭…泣歌…你們和其他人可能是許多人的先驅。', '', 66384),
(292034, 'zhTW', '看看你周圍。這些虛無精靈是學會與虛無共存的群體。', '', 66384),
(292033, 'zhTW', '如果你能夠抵抗，或許其他人也能抵抗。更多迷失的姊妹…父親…', '', 66384),
(292032, 'zhTW', '', '賈庫曾是我的導師，但他也是我的朋友。我不會容許魯坦尼留下從他那裡偷走的東西！', 66384),
(292031, 'zhTW', '', '不過，黑暗仍潛伏在我們四周。此地不宜久留。', 66384),
(292030, 'zhTW', '我們有足夠的箭可以攻擊莫爾頓的盾牌幾次。', '', 66384),
(292028, 'zhTW', '', '齊凡…你的回憶…家的回憶…它們喚醒我們。', 66384),
(292027, 'zhTW', '', '顏料已經備妥，但它們能夠維持形狀嗎？拿起刷子，使它們附著在畫布上。我們必須在回音激起前，看看圖畫是否如預期般流動。', 66384),
(292024, 'zhTW', '', '接收我的力量，讓它流過你的手！呼喚圖畫，支配它，然後把它送回回音大鍋，讓我能夠用這個手印封印它。', 66384),
(292023, 'zhTW', '', '不不不！事情不該是這個樣子！圖畫正試著逃跑！踩住它們！別讓它們逃跑，不然它們會把故事一起帶走！', 66384),
(292022, 'zhTW', '隨著哈拉尼爾的記憶不斷褪去，她尋找其他方法讓它們能與世界合而為一。顏色本身無法承載歷史，她需要更好的方式。', '', 66384),
(292015, 'zhTW', '很美的景色，對不對？', '', 66384),
(292012, 'zhTW', '我在銀月城服侍執政官多年，但我一向更喜歡這裡。\n\n我漸漸愛上這座城鎮。這裡是如此平靜，完全沒有城市中的窺探之眼。\n\n那個虛無風暴籠罩著我們所有人，但銀月城卻沒有採取任何行動幫助我們。這是我無法接受的。\n\n這些人需要某個能給予他們應得權利的人。', '', 66384),
(292007, 'zhTW', '這個答案有跟沒有一樣。哼。', '', 66384),
(292003, 'zhTW', '', '這算不上什麼勝利。我們用鮮血換來了市民的安全。', 66384),
(291996, 'zhTW', '', '到主宰棲所找我，外界者。多曼納爾有我們需要的東西。', 66384),
(291993, 'zhTW', '', '托倫多，在這裡等到祖爾詹開火，然後趁亂帶著倖存者離開。', 66384),
(291986, 'zhTW', '', '沒時間擔心祖爾詹了。我們得專注在納羅拉克上。快走吧。', 66384),
(291980, 'zhTW', '犧牲？他們可是英雄。奪回阿塔阿曼的光木，作為真正的阿曼尼死去。', '', 66384),
(291972, 'zhTW', '把孩子們送到安全的地方之後，我會幫祖爾詹準備弩砲。', '', 66384),
(291970, 'zhTW', '我們得確保最德高望重的人安全無虞，也就是我們的長老！\n\n長老傳承我們的智慧。還有我們光榮的歷史！', '', 66384),
(291968, 'zhTW', '', '這裡是瑪拉克雷斯多年前被殺死的地方，當時他的勇士試圖奴役阿曼尼的羅亞來對付聯盟和部落。\n\n在那場失敗後，對永歌森林的突襲次數變得越來越少，最終完全停止。真不知道阿曼尼之後都在做些什麼？', 66384),
(291967, 'zhTW', '$n！我們會回到咆哮峰與你會合。', '', 66384),
(291966, 'zhTW', '我認識他很多年了，但從沒和他有近距離的接觸。他一定是聽說我們回到了永歌森林。\n\n安諾里恩對安寧地有很強的保護欲，也很擔心虛無風暴帶來的威脅。這就是為什麼他會主動聯繫。我猜他認為這裡的設施對我更有用，還有我的研究事實上是有意義的。\n\n他知道我們越早解決這個問題，他的人民就會越安全。我完全理解這點，我也很感謝他的理解。', '', 66384),
(291960, 'zhTW', '', '提高警覺，$c。\n\n這片沼澤充滿了魚人。\n\n牠們奪走我們的貨物，還有托巴尼的命。\n\n備好你的武器。', 66384),
(291958, 'zhTW', '凱西雅是我的學生，但她在我們抵達永歌森林後不久就消失了。我本以為她是因為我們依然被孤立而感到沮喪…某種程度上也可以說是被排斥。所以她會因此回到特洛古斯。\n\n她是如此地樂觀，致力於自己的研究…從這本筆記剩餘的部分來看，她終於取得了很大的進展。\n\n<奧姆里克看起來很痛苦。>\n\n真希望我能在一旁見證。', '', 66384),
(291954, 'zhTW', '阿曼尼必須大膽採取行動。光木有這個價值。\n\n當你讓暮光之刃在光木長矛的尖端掙扎時，你就會看到聖光了。哈！\n\n這本來就是我們的，我們也比精靈更能發揮它們的利用價值。', '', 66384),
(291948, 'zhTW', '', '阿克尚很看好你。去尋找大型的盜竊者巢穴，找出能告訴你法杖所在地的任何線索。', 66384),
(291937, 'zhTW', '你竟敢跟我說話？我應該把你的舌頭割下來。', '', 66384),
(291936, 'zhTW', '', '你正行走於危險之地。', 66384),
(291935, 'zhTW', '先看清腳放下的位置，再踏上階梯。', '', 66384),
(291921, 'zhTW', '如果它消失了，對哈拉尼爾的歷史來說會是不可抹滅的損失。', '', 66384),
(291920, 'zhTW', '每個樹根法杖的持有者都為其灌注了新生命。它是所有前任持有者的實體紀錄。', '', 66384),
(291919, 'zhTW', '', '瑟蘭德雅，等一下！', 66384),
(291918, 'zhTW', '', '曦心的時間可能不多了！我們走吧！', 66384),
(291917, 'zhTW', '當世界充滿各種混亂時，家人的羈絆能為我們帶來安慰。\n\n我無法原諒影衛犯下的罪，但我選擇珍惜我妹妹維蘭的回憶。', '', 66384),
(291916, 'zhTW', '', '我準備好了。我也知道這條路上不會只有我。', 66384),
(291915, 'zhTW', '你準備好進行儀式，了解無法遺忘之事了嗎？', '', 66384),
(291914, 'zhTW', '你不只要保護哈拉尼爾，還有與女神同在的事物。包括艾恩哈拉的子民。包括全世界的人們。', '', 66384),
(291913, 'zhTW', '想選擇這條路，想了解女神的神諭，你必須變得更強。變強代表著保護，而非犧牲。', '', 66384),
(291912, 'zhTW', '', '其他人跟隨我，是因為他們和我一樣，相信可以找到女神，還可以拯救她。我應該要做什麼？', 66384),
(291911, 'zhTW', '犧牲自己十分高尚，但犧牲他人就太瘋狂了。你還是願意走上這條道路嗎？', '', 66384),
(291910, 'zhTW', '', '我…我會…', 66384),
(291909, 'zhTW', '所以，你不怕做出必要的犧牲嗎，歐薇娜？就算犧牲你自己也不怕？那其他人呢？', '', 66384),
(291908, 'zhTW', '', '我非常樂意遵從女神下達的旨意。我一點也不怕。', 66384),
(291907, 'zhTW', '就算要冒著危險前往你的家園，我也要了解更多關於光綻的事。', '', 66384),
(291900, 'zhTW', '姐妹，山貓羅亞保護了我們，帶我們來到這裡。祂欽點我成為羅亞語者。', '', 66384),
(291898, 'zhTW', '嘿。\n\n$p，賈納雷在等你們所有人。準備好見祂了嗎？', '', 66384),
(291897, 'zhTW', '在傳送門穩定下來時，裘拉斯滿懷希望地盯著它。', '', 66384),
(291896, 'zhTW', '', '是哈謝聖壇。就跟我們在阿奇爾森神廟點燃的一樣。', 66384),
(291895, 'zhTW', '她的理論是對的。真的有用！', '', 66384),
(291894, 'zhTW', '你知道警戒傀儡嗎？還在阿古斯的時候，警戒傀儡是為了滿足喚醒者的徒然野心所設計，但在我們飛離母星時，它們變成重要的工具，確保我們死去的兄弟不會為惡魔所用。\n\n警戒傀儡寄宿著那些亡者的靈魂，讓他們能夠繼續對抗我們的敵人。我想，這一個再也無法上戰場了，不過，它繼續作為容器，容納數十個德萊尼的靈魂。\n\n這不是理想的安排。這麼多靈魂擠在小小的空間，會讓它們陷入混亂，不過，我打算把它們安全地帶回家，讓它們能葬在我們的浩瀚陵墓中。', '', 66384),
(291870, 'zhTW', '', '如果我老實說出自己的感受，你打算告訴我怎麼壓抑阿奇爾森害我感受到的憤怒和恥辱嗎？', 66384),
(291868, 'zhTW', '', '祖爾賈拉，你看起來…心事很重。阿奇爾森的祝福沒讓你放心嗎？', 66384),
(291858, 'zhTW', '', '憤怒是強烈的情感。我的同胞也曾經被憤怒吞噬過。', 66384),
(291856, 'zhTW', '', '叔叔，我很喜歡聽故事。但以前我就懷疑著真實性。', 66384),
(291855, 'zhTW', '你還記得多少，阿奇爾森神廟的事？', '', 66384),
(291854, 'zhTW', '我試著為你們兩個…你跟祖爾詹，灌輸對羅亞的愛。', '', 66384),
(291853, 'zhTW', '', '我還記得阿奇爾森、哈拉齊、賈納雷和納羅拉克，守護我們的故事。', 66384),
(291852, 'zhTW', '', '我們爬上了神廟。祖爾詹掉下去了。我沒得到羅亞的祝福。母親也死了。', 66384),
(291850, 'zhTW', '阿奇爾森賦予我莫大的殊榮，欽點我為羅亞語者。', '', 66384),
(291847, 'zhTW', '', '對抗阿曼尼多年，我對他們的文化也有一些認識。\n\n多數人不知道「阿曼尼帝國」是由多個部族結合而成，而且是以創建當時最強大的部族命名。\n\n各個部族都有各自信奉的羅亞，也有不同的習俗，看來他們的「帝國」也不是那麼團結。\n\n我想我也不該感到意外。我只想知道祖爾賈拉是否能真的讓這些人團結起來。', 66384),
(291844, 'zhTW', '<溫和的帕赫既困惑又無辜地看著你。\n\n血不夠所有德萊尼用。也許不是每一個人都需要浸入？>', '', 66384),
(291843, 'zhTW', '…朋友…？', '', 66384),
(291814, 'zhTW', '', '等等，祖爾賈拉！你瘋了嗎？', 66384),
(291806, 'zhTW', '', '想獲得我的恩寵，必須攀上高處而不畏懼墜落。', 66384),
(291799, 'zhTW', '', '阿瓦是我那荒唐的兄弟，我之後還有更多精彩的可以說。', 66384),
(291798, 'zhTW', '你好啊，我熱愛冒險的朋友！今天我們能如何款待你呢？', '', 66384),
(291797, 'zhTW', '繼續深入了解哈拉尼爾和我們的歷史吧。我很想看看你，或是另一個人，是否有資格共享那些記憶。', '', 66384),
(291796, 'zhTW', '女神把她的記憶共享給我，而我只會與了解它們重要性的人分享。', '', 66384),
(291795, 'zhTW', '我是阿克尚。我聆聽育所的聲音，還擁有多數哈拉尼爾都不知道的知識。', '', 66384),
(291790, 'zhTW', '', '哦。情況不妙。\n\n那魯…無法信任。他清楚明白。不想死。\n\n但，無法信任。', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(291789, 'zhTW', '', '納夏博爾。很棒的地方。有很多…鹽？紅色的鹽。紫色的水。巨大的野獸，很多，很聰明。兄弟姐妹還小時，就要狩獵。\n\n有時候，不安全。但我們結交、建立。結交可憐的曼那瑞朋友。只有一點。建立我們的家園。', 66384),
(291788, 'zhTW', '', '…提拉？我知道。那魯。沒錯。\n\n來自我們。與我們同在。但不是朋友。想要我們離開家，回到從前。這，呃…\n\n<圖阿瑪想要解釋的概念似乎過於複雜。她沮喪地吐了一口氣，決定放棄。>\n\n你懂嗎？', 66384),
(291787, 'zhTW', '', '呸。\n\n<圖阿瑪不屑地抬起手。>\n\n聖光之徒。屬於他們的戰鬥。不幫助我們。我還以顏色。', 66384),
(291786, 'zhTW', '', '待在這裡。幫助兄弟姐妹們。你幫我。我幫你。\n\n<圖阿瑪給了你一個罕見的微笑。>\n\n然後回家。', 66384),
(291785, 'zhTW', '', '我的族人是虛空使。在我們最安全的故鄉時，我是他們的一員。\n\n然而，我渴望直視費倫的眼睛，讓他看見我們依然屹立不倒。與或許能從我在星外暗界的發現中受益的族人分享這些知識。親眼見識分開數千年後，其他的秘法師和虛空術師在自己的魔法領域取得的進步。\n\n只要能滿足我保護族人的需要，我都可以接受。雖然無法長久，但是我辦得到。', 66384),
(291784, 'zhTW', '', '嗯。不管她應該有什麼下場，都絕對不是那樣。他們正在用自己的方式，試著幫助那魯。我當然看得出來這點。\n\n不過。正是我的直覺告訴我拒絕阿克蒙德和基爾加丹，令我的同僚們大感意外。這同樣適用於那魯。當關鍵時刻來臨，若我們無法成為他們所要求的容器，他們一定會用某種方式「改造」我們。\n\n我所要求的，只有和我的族人平靜度日。但如果我必須行使力量才能生存，那我也要靠自己的力量。', 66384),
(291782, 'zhTW', '', '納夏博爾。刀鋒之地。那是一個充滿自然之美的世界。赤紅色的鹽盤逐漸轉變為清涼的紫色湖泊。我們的河流長滿了結實的巨大睡蓮。在和平年代，常常可以看到打瞌睡的德萊尼躺在上面順流而下。我們的年輕人很早就學會了戰鬥，比他們在阿古斯時還要更早。想要在聰明且強大的野獸攻擊下存活，武術和秘法本領至關重要。\n\n我們經歷了多次衝突和復興的循環。我們與少數和我們共存的燃燒軍團叛逃者結成了意想不到的盟友。我們也在很大程度上將當初開啟我們偉大飛航的力量摒棄了…無論那是魔能、虛無，還是聖光。\n\n我們的薩亞德是傑頂摔角的天生好手。觀賞他們的比賽是一大享受。', 66384),
(291781, 'zhTW', '我會先去尋找維蘭。', '', 66384),
(291777, 'zhTW', '對你來說，沒用，卻能讓我們回想起家的溫暖。', '對你來說，沒用，卻能讓我們回想起家的溫暖。', 66384),
(291776, 'zhTW', '她給你的這些小珠有什麼用意？', '', 66384),
(291775, 'zhTW', '我聽見她了…\n\n也許我很快就必須調班。', '我聽見她了…\n\n也許我很快就必須調班。', 66384),
(291774, 'zhTW', '在我們最腐敗的夢境和最糟糕的夢魘中，艾恩裂隙是個危險的地方。因此我們隨時保持警戒。我們必須保障族人的安全。', '在我們最腐敗的夢境和最糟糕的夢魘中，艾恩裂隙是個危險的地方。因此我們隨時保持警戒。我們必須保障族人的安全。', 66384),
(291773, 'zhTW', '離邊緣遠一點。掉下去的人都會死，而且哈拉尼爾死得更快。', '離邊緣遠一點。掉下去的人都會死，而且哈拉尼爾死得更快。', 66384),
(291771, 'zhTW', '哈拉齊告訴過我你會來。歡迎，哈巫拉！', '', 66384),
(291765, 'zhTW', '', '你是說因為迷霧讓你逃離邪枝的攻擊？不是害你迷路？', 66384),
(291763, 'zhTW', '', '…是的。她找到方法進入我們的世界，渴望帶我們迎向更美好的命運。\n\n在是否應該歡迎她的這個問題上，我們的族人之間產生分歧。我持反對意見，但我的弟弟卻因她的到來得到慰藉。我們被多曼納爾抓走時，她也在場。\n\n裘拉斯說我腦中全是陰謀論，就因為我懷疑是否存在仁慈的生物，他們會贈予我們次元飛船和舒心的靈魂旋律，單純是因為他們本質上是善良的。\n\n你是怎麼認識她的？', 66384),
(291762, 'zhTW', '', '看來是這樣沒錯。我曾經從遠處看過他們閃閃發光的戰爭武器。\n\n<圖阿瑪不屑地抬起手。>\n\n儘管秘法是個可靠的盟友，但聖光卻無法為我所用。我很高興能還以顏色。', 66384),
(291760, 'zhTW', '多曼納爾從多個次元抓來凡人鬥士投入他們的鬥技場。我們之所以能自由站在這裡，單純是因為我們願意展現的暴力。\n\n如果你想加入競技場，我希望那是出於你個人的意願。讓他們見識一下，我們無堅不摧的精神。', '', 66384),
(291759, 'zhTW', '', '這表示我們很接近了。你有感覺到被監視嗎？', 66384),
(291754, 'zhTW', '', '我衷心希望你能成功。但要是你被吃掉我也不會覺得難過。', 66384),
(291751, 'zhTW', '', '好吧。要跟沉眠的戰爭羅亞對話，你必須在祂的火堆旁坐下。但至今從來沒有人回來過。', 66384),
(291749, 'zhTW', '', '莉拉菊，我以性命發誓。我會以納羅拉克的祝福，驅逐祖阿曼所有的威脅。', 66384),
(291740, 'zhTW', '阿曼尼援軍？無所謂。有更多的混沌和死亡能獻給薩拉塔斯！', '', 66384),
(291736, 'zhTW', '我們將乘著阿奇爾森之風而行…就像過去的日子一樣。', '', 66384),
(291713, 'zhTW', '勇士，你發掘出了奎爾薩拉斯面臨的許多威脅。我們必須一起思考接下來的計畫。', '', 66384),
(291711, 'zhTW', '我感謝你至今為止付出的努力。你暫時解決了那該死的光綻、揪出了邪教，還幫助我們的人抵禦阿曼尼的入侵。\n\n但每個事件都還需要採取進一步的行動。如果我們想擁有更光明的未來，就必須瞭解更多詳情。讓我們考慮下一步該怎麼做吧。', '', 66384),
(291710, 'zhTW', '', '我會按照攝政王的命令繼續在這裡看守。我只希望我們決定性的勝利可以嚇阻阿曼尼，讓他們不要發動另一次攻擊。\n\n阿拉特…我很擔心他。\n\n如果真的如他所說，阿曼尼是在和暮光之刃戰鬥，那麼我們就很有必要重新思考對策。我雖然不是祖阿曼的盟友，但也知道該同仇敵愾。\n\n$p，找到阿拉特。他的直覺是對的。', 66384),
(291709, 'zhTW', '當我第一次跟她離開哈朗達時，我體認到歐薇娜的決心所代表的價值。\n\n我不會讓她孤軍奮戰。\n\n艾恩裂隙是個危險無比的地方…但我會想辦法幫上忙。', '', 66384),
(291708, 'zhTW', '目前還算平靜…但如果暮光之刃有這片區域的地圖，這樣的情況維持不久。', '', 66384),
(291707, 'zhTW', '我會向伊利達瑞回報。你今天表現得很好。', '', 66384),
(291706, 'zhTW', '快！我們得趕回兇殺路。我們必須找到禁忌之雨，追查贊恩的下落，終結這個魔能交易。', '', 66384),
(291702, 'zhTW', '$p，這可不是什麼好兆頭。', '', 66384),
(291701, 'zhTW', '快滾。去換個工作。', '', 66384),
(291700, 'zhTW', '', '我…不知道。我只負責搬貨。我發誓！', 66384),
(291699, 'zhTW', '贊恩在哪裡？', '', 66384),
(291693, 'zhTW', '你真的以為我很笨嗎？贊恩會割開我的喉嚨！', '', 66384),
(291689, 'zhTW', '找到碼頭管理員。去跟他聊天。為了預防萬一，我會躲在這裡。', '', 66384),
(291671, 'zhTW', '', '你準備好去找納羅拉克了嗎？我們沒時間可以浪費了。', 66384),
(291657, 'zhTW', '', '我記得你。你是阿曼尼扎的那個入侵者。\n\n金德魯讓你和莉雅德倫成為哈巫拉這件事是真的嗎？哼。\n\n你們幫助祖爾賈拉踏上哈謝之道，還有羅亞們回歸的消息已經傳開了。\n\n但是我還沒聽見納羅拉克的獸穴傳來任何聲音。\n\n<莉拉菊把她的手放在嘴唇上。>\n\n又來了。你最後才來找我們，對不對？我們也很需要幫忙啊！', 66384),
(291645, 'zhTW', '前往港口，告訴他們你要領取贊恩的貨物。我們會中斷他們的供應線，並把它當成證據。我們在那裡會合。', '', 66384),
(291644, 'zhTW', '不！不該在這裡，還沒有結束！', '', 66384),
(291642, 'zhTW', '入侵者，阿曼尼現在居住的地方曾是我們輝煌的所在。\n\n或許我們現在只有這片山地，但在很久以前，我們的王國龐大到拓展到陸地的邊界。\n\n你看到那些遺跡了嗎？我們把那些遺跡稱作故鄉。', '', 66384),
(291636, 'zhTW', '', '在確定我的所有同胞擺脫多曼納爾的掌控之前，我會繼續留在這個世界。為此，我希望你可以提供協助。作為回報，我也會為你提供支援。\n\n然後，等這裡不再需要我的時候，我就會回到我的故鄉。', 66384),
(291631, 'zhTW', '班弗斯，你這蠢貨！我就知道你不配獲得女王的恩寵！', '', 66384),
(291630, 'zhTW', '你的城市早已淪陷。為何還要抗拒薩拉塔斯的擁抱？', '', 66384),
(291629, 'zhTW', '在痛苦中哀嚎吧！讓薩拉塔斯聽見你們城市燒成灰燼的慘叫聲！', '', 66384),
(291622, 'zhTW', '', '這裡有好多阿曼尼的族人…來自所有的部族。\n\n我已經很久沒有看到我們像這樣聚集在一起了。\n\n哈巫拉，比起休息的時刻，這看起來更像是一場慶典。我想，我們慶祝莫爾頓的戰敗也是件合理的事。\n\n<祖爾賈拉露出淘氣的笑容。>\n\n你準備好像個阿曼尼一樣享受派對了嗎？', 66384),
(291616, 'zhTW', '你在那個地方待了一陣子。找到線索了嗎？', '', 66384),
(291597, 'zhTW', '', '在此同時，歡迎你仔細觀察未加工的魔能，確認它的品質。', 66384),
(291596, 'zhTW', '', '不過，別擔心。很快就會有更多龍鰻送來。我會幫你保留一些，讓你購買。', 66384),
(291595, 'zhTW', '', '可惜的是，由於虛無越來越接近，因此供給遲遲無法滿足需求。', 66384),
(291594, 'zhTW', '', '一個庇護所，讓那些有共同目標和癖好能夠自由交流的地方。\n\n當然，還有讓他們沉迷於…興趣中。\n\n不用害怕被發現。贊恩會確保我們的行動安全無虞。', 66384),
(291591, 'zhTW', '', '啊，新面孔。很高興看到有越來越多辛多雷開始注意到我們的優質服務。\n\n放縱之穴能幫你什麼忙？', 66384),
(291590, 'zhTW', '', '啊，我還以為自己貴客一到，就會察覺。\n\n很抱歉未能及時服務你，尊貴的$g先生;小姐;。放縱之穴能幫你什麼忙？', 66384),
(291589, 'zhTW', '', '克絲提雅離開時，不屑地看了你一眼。', 66384),
(291588, 'zhTW', '', '很好。準備好了，就把粉塵交給我。別讓我久等。', 66384),
(291585, 'zhTW', '', '還有一批貨，不過我們就快完工了。', 66384),
(291584, 'zhTW', '', '我現在急需趕工。你能多快分解這些聖物？', 66384),
(291583, 'zhTW', '', '我們必須主動攻擊莫爾頓。走吧。', 66384),
(291573, 'zhTW', '他還沒完全迷失自我。但必須馬上帶他離開裂隙。', '', 66384),
(291572, 'zhTW', '艾恩之塵的力量源自女神本人。歐薇娜，如果它能幫上忙，我會幫你收集。', '', 66384),
(291571, 'zhTW', '是你們！你們把她帶走了，把她偷走了！我要殺了你們！', '', 66384),
(291568, 'zhTW', '戰鼓響起的時候你們都跑去哪了？就是你們害阿塔阿曼淪陷！', '', 66384),
(291566, 'zhTW', '阿曼尼怎敢再次威脅辛多雷！', '', 66384),
(291512, 'zhTW', '', '為了你的安全，我建議你在阿曼尼扎的時候把武器收好，待在我身邊。', 66384),
(291506, 'zhTW', '', '$n，我們有許多事情要談。\n\n但我們應該先前往村莊。', 66384),
(291492, 'zhTW', '', '有了羅亞的祝福，我們會將暮光之刃從祖阿曼徹底剷除。為了阿曼尼！', 66384),
(291485, 'zhTW', '祖爾賈拉！你弟弟耐不住性子，把戰士都帶走了。這會害死他們的！', '', 66384),
(291483, 'zhTW', '', '為阿塔阿曼復仇！讓入侵者記住這片土地是我們的！', 66384),
(291449, 'zhTW', '', '追蹤還是打靶練習？你有什麼需求？', 66384),
(291448, 'zhTW', '血騎士之路注重的是平衡。你打算開創什麼樣的道路？', '', 66384),
(291447, 'zhTW', '追尋魔法是一條既充滿探索又需要保持謹慎的道路。你想鑽研的是什麼？', '', 66384),
(291446, 'zhTW', '哇喔，他們全都好了不起。\n\n遠行者英勇無比，運用自身本領和自然之力保護我們的族人。\n\n血騎士強大且無所畏懼，心懷榮耀和堅定不移的使命站在最前線。\n\n而博學者…他們聰明絕頂，利用幾乎無窮無盡的知識和秘法之力改變世界。\n\n你曾在近距離下見過他們。你覺得我應該追隨哪一條道路？你在我身上看到了哪一項特質？', '', 66384),
(291371, 'zhTW', '放輕鬆。感受節奏，而不是韁繩。', '', 66384),
(291363, 'zhTW', '', '謝謝你，$n。你在這裡交了很多朋友，有羽毛的和沒羽毛的都有。', 66384),
(291361, 'zhTW', '這是暮光之刃的成員。阿拉特，你是對的…快點，回去安寧地！', '', 66384),
(291360, 'zhTW', '', '這次要找個好地方把他們埋了。', 66384),
(291359, 'zhTW', '', '無足輕重的小人物，問題倒是問不少。把他們都解決掉。', 66384),
(291312, 'zhTW', '希歐將璽戒悄悄放入你手中。', '', 66384),
(291311, 'zhTW', '你問問題的聲音未免太大了。', '', 66384),
(291310, 'zhTW', '德諾寧將璽戒悄悄放入你手中。', '', 66384),
(291309, 'zhTW', '我們剛好賣完了。如果你感興趣的話，我還有其他生物。', '', 66384),
(291308, 'zhTW', '', '蘭達利小姐將璽戒悄悄放入你手中。', 66384),
(291307, 'zhTW', '', '不管你在暗示什麼，我們都沒涉獵那種魔法。', 66384),
(291306, 'zhTW', '透過艾恩之塵的閃光，賽艾尤解開了活體畫作的奧秘。當力量與危機相互交織，她把這份傳承託付給祖拉夏。', '', 66384),
(291305, 'zhTW', '賽艾尤在顏料留下的痕跡中尋找答案，試圖找出尚未揭露的啟示。', '', 66384),
(291304, 'zhTW', '這不是普通的顏料。裡頭的艾恩之塵開始肆虐！混沌噴湧而出，回音大鍋劇烈晃動，顏料也不斷噴濺出來。', '', 66384),
(291303, 'zhTW', '透過大鍋裡的顏料，賽艾尤就能把她的靈魂注入每幅繪畫裡，然後探尋其他人的回憶。', '', 66384),
(291302, 'zhTW', '回音大鍋原屬於祖拉夏「賽艾尤」。她可不是什麼普通的藝術家，她是與被遺忘的過去連結的橋樑。', '', 66384),
(291301, 'zhTW', '火焰正熊熊燃燒。面對挑戰，淨化你的靈魂吧！', '', 66384),
(291299, 'zhTW', '柴薪準備好燃燒了。焚燒柴薪，進行淨化。聖壇會指引你道路。', '', 66384),
(291298, 'zhTW', '沒錯！火焰回來了。賈納雷之火熊熊燃燒！飛回家吧，火焰的主宰者與女主人！飛吧！', '', 66384),
(291297, 'zhTW', '我在你之中看見了火焰。找到更多柴薪，更多火焰。重新點燃火焰化身！', '', 66384),
(291296, 'zhTW', '這難道…是火花嗎？我們需要的火焰？', '', 66384),
(291291, 'zhTW', '火焰化身熄滅，燒灼許多心靈。淨化己身，祂將現身！', '', 66384),
(291290, 'zhTW', '在此同時，我會持續監視街道。', '', 66384),
(291288, 'zhTW', '我不能把我的士兵交給祖爾賈拉，但我可以在她成為哈謝的旅途中提供幫助。', '', 66384),
(291286, 'zhTW', '枯木對賈納雷不熟悉，但祂古怪的羅亞語者依然待在東邊的神廟。', '', 66384),
(291283, 'zhTW', '哈謝之道？我小時候祖母在火堆旁說過這個故事。', '', 66384),
(291282, 'zhTW', '祖爾詹怒視著庫阿瑪拉。', '', 66384),
(291237, 'zhTW', '', '又是你？還有精靈。\n\n<庫阿瑪拉嘲弄地上下打量著你。>\n\n如果祖爾賈拉放任你們到處跑，而且沒有把你們倆的內臟掛在身上，那就代表情況一定很危急。\n\n作為枯木軍隊的指揮官，我會從這個哨崗盯緊那些邪枝食人妖。\n\n<庫阿瑪拉指向遠方邪枝食人妖的臨時沼澤小屋。>', 66384),
(291236, 'zhTW', '', '我們的戰士正一個個消失，你竟然要我去找羅亞的鬼魂？', 66384),
(291227, 'zhTW', '', '詹，但他們全都死了！', 66384),
(291225, 'zhTW', '', '那你為了從邪教徒手上奪回光木，犧牲了多少戰士？', 66384),
(291224, 'zhTW', '', '哈！哈拉齊？$r，你忘記帶耳朵出門了嗎？我早就跟你說過羅亞已經不在了！\n\n就算祂們還在，現在沒有人到得了哈拉齊神廟。邪枝部族和暮光之刃聯合起來打算消滅我們。\n\n我們被分割成兩個戰場，現在邪枝部族每晚都會來攻擊我的村莊。\n\n除此之外，還有這陣迷霧。邪枝部族和暮光之刃利用它來遮蔽哈拉齊亞洛和神廟周圍的區域。\n\n許多戰士都進入其中，卻沒有一個人能回來。', 66384),
(291223, 'zhTW', '姐姐，你回來了！在你忙著對羅亞卑躬屈膝的時候，我得到真正的力量了！', '', 66384),
(291220, 'zhTW', '', '魯坦尼如其外觀所示：人形，但完全是由植物生命構成的。它們原生於我的家鄉。據我所知，它們從來沒有來到地表過…直到現在。\n\n而且這些魯坦尼似乎也和我知道的不一樣。這些變化。變異。這讓我有點擔憂。', 66384),
(291199, 'zhTW', '我的魔法持續時間不久，不過能幫你追蹤魔能。我們很快就會再會。', '', 66384),
(291198, 'zhTW', '利用你的視覺追蹤魔能，$ct。我們很快就會再會。', '', 66384),
(291197, 'zhTW', '好好善用你的…天性，惡魔。我們很快就會再會。', '', 66384),
(291193, 'zhTW', '但沒有人清楚實情。拜託你幫幫恩萊亞吧。', '', 66384),
(291189, 'zhTW', '據說莫塔卡是第一位墮入裂隙瘋狂的哈拉提之影。', '', 66384),
(291184, 'zhTW', '入侵者！快，快來幫我滅火！', '', 66384),
(291179, 'zhTW', '', '他們源源不絕！艾恩哈拉，傾聽我們的聲音…援助我們！', 66384),
(291172, 'zhTW', '', '那是曾由哈謝持有過的法杖…此人能夠團結人民並使用羅亞的力量。\n\n如果羅亞有再次對我們說話的可能，那我們會需要這根法杖。\n\n我們已經有…很長一段時間沒有真正的哈謝了。\n\n不過老食人妖也是可以抱持希望的！', 66384),
(291166, 'zhTW', '', '祂們是兩位神聖的羅亞！哈拉齊是狩獵羅亞，阿奇爾森則是勝利羅亞！\n\n阿奇爾森有雙銳眼。哈拉齊會隱藏在陰影中。但是祂能揭露隱藏的事物！\n\n我是…應該說曾是，勝利羅亞阿奇爾森的代言者！\n\n哦，我真希望能再次聽到羅亞的聲音。就在此刻，趁著暮光之刃還沒摧毀這座神廟。\n\n但羅亞如今一言不發…或許祂們有聽到我們，或許沒有。或許祂們試著說些什麼，但我們因為自己的所作所為而無法聽見。\n\n要是我們有一位哈謝…說不定…', 66384),
(291161, 'zhTW', '但戰爭改變了他的聖騎士背負的使命。', '', 66384),
(291155, 'zhTW', '最好是。不管怎樣，我們是兄弟，永遠都是。', '最好是。不管怎樣，我們是兄弟，永遠都是。', 66384),
(291154, 'zhTW', '我會的。雖然我的職責不會留給我太多時間，但也不至於不去探望。', '', 66384),
(291153, 'zhTW', '他們無法阻止我偷溜出去。懂嗎？', '他們無法阻止我偷溜出去。懂嗎？', 66384),
(291152, 'zhTW', '我一點都不想你離開我，笨蛋。我好想你。', '我一點都不想你離開我，笨蛋。我好想你。', 66384),
(291151, 'zhTW', '多虧阿瑪拉克和$p，我現在好多了。但我已經成為蘇卡的一員，我必須留在裂隙裡，算是一種流放吧。', '', 66384),
(291150, 'zhTW', '對不起。裂隙的力量幾乎將我逼入瘋狂，讓我成為一個危險的存在。', '', 66384),
(291149, 'zhTW', '你從我身邊跑開。我以為你死了！', '你從我身邊跑開。我以為你死了！', 66384),
(291148, 'zhTW', '你在這裡做什麼？你不該來的！', '', 66384),
(291144, 'zhTW', '法奧，知道了。我會去召集其他人，等待你的到來。', '', 66384),
(291143, 'zhTW', '奇雅？奇雅！', '', 66384),
(291142, 'zhTW', '恩萊亞！', '恩萊亞！', 66384),
(291133, 'zhTW', '', '[德萊尼語]Dioniss aca，弟弟。', 66384),
(291132, 'zhTW', '', '德萊尼。流放者。\n\n我的第一次流放是我們開始飛離母星的那一天。費倫的話觸動了我的心。所有踏上真諾達號的人，都一起從阿古斯被流放了。我祈禱自己的選擇是正確的。\n\n第二次是燃燒軍團伏擊我們世界的那一天。我那時跟裘拉斯一起到地下尋找礦物，取代損壞的能量核心。他求我們的母親離開飛船，一起來幫他的姊姊。惡魔劫奪者的腳步讓大地劇烈搖晃。等到我們回到地表，魔焰火砲迫使真諾達號升空。他們必須離開。他們別無選擇。我很清楚。\n\n然後現在…又來了。\n\n我需要獨處一下，不過我會去找你…某個安全的地方，可以促膝長談的地方。', 66384),
(291131, 'zhTW', '', '我們的族人創造出我們一直在等的機會。我們會直接向多曼納爾開戰。', 66384),
(291130, 'zhTW', '', '到主宰棲所找我，外界者。多曼納爾有我們需要的東西。', 66384),
(291129, 'zhTW', '如果這是有意為之，那他們在日冠村陷落後早該發動攻擊了。一定還有什麼隱情。', '', 66384),
(291128, 'zhTW', '別放棄希望，奧姆里克，他們不可能把所有東西都偷走的。', '', 66384),
(291127, 'zhTW', '就算我現在向銀月城提供協助，能幫的也不多。', '', 66384),
(291126, 'zhTW', '', '遠行者去調查聲響的來源了。日冠村現在無人把守。', 66384),
(291125, 'zhTW', '我會查看你們的調查報告。之後我們再來交流交流。', '', 66384),
(291124, 'zhTW', '謝謝有你們三位如此重視城鎮的安全。', '', 66384),
(291121, 'zhTW', '<這本日記的最後一頁寫著昨天的日期。>\n\n他們知道我打算離開。我不知道他們是怎麼發現的。\n\n我得快點逃跑。現在沒有人可以救我了。我竟然相信了那些誘人的謊言…這全是我的錯。我太害怕了。我早該猜到的。\n\n我不能讓他們得到我的研究成果。我不能再為他們提供更多武器了。\n\n原諒我。', '<這本日記的最後一頁寫著昨天的日期。>\n\n他們知道我打算離開。我不知道他們是怎麼發現的。\n\n我得快點逃跑。現在沒有人可以救我了。我竟然相信了那些誘人的謊言…這全是我的錯。我太害怕了。我早該猜到的。\n\n我不能讓他們得到我的研究成果。我不能再為他們提供更多武器了。\n\n原諒我。', 66384),
(291120, 'zhTW', '祖爾詹發出受挫的哼聲。', '', 66384),
(291117, 'zhTW', '你確定還沒收進行李嗎？', '', 66384),
(291116, 'zhTW', '我的法杖！你和我們神聖的阿奇爾森一樣，有雙明亮的眼睛。', '', 66384),
(291115, 'zhTW', '小詹，等一下。', '', 66384),
(291114, 'zhTW', '叔叔，拜託。我們正受到攻擊！拿好必要的東西就快走吧！', '', 66384),
(291112, 'zhTW', '我們的土地？這些以前都是「我們的土地」。上頭的東西也是！', '', 66384),
(291111, 'zhTW', '', '沒有繼續流血的必要了。停止攻擊行動，交出光木，回到你們的土地吧。', 66384),
(291101, 'zhTW', '等我回歸時，小哈拉尼爾，你將屬於我。', '', 66384),
(291100, 'zhTW', '結束了。我在外面與你會合。', '', 66384),
(291095, 'zhTW', '', '德萊尼，是一個詞，你知道嗎？意指：流放者。\n\n<圖阿瑪吐出一口氣，然後看往別處。>\n\n需要獨處。需要時間。\n\n待會見。去找你。安全的地方。', 66384),
(291090, 'zhTW', '來吧。我要把你的精華納為己有。', '', 66384),
(291089, 'zhTW', '只要殺了你，我就能成為蘇卡。', '', 66384),
(291087, 'zhTW', '', '[德萊尼語]Dioniss aca，dolos。', 66384),
(291083, 'zhTW', '', '我們不能再浪費時間！', 66384),
(291082, 'zhTW', '', '$p，我們到那裡見。', 66384),
(291071, 'zhTW', '家鄉…', '', 66384),
(291068, 'zhTW', '', '洞穴充滿輕柔海風的氣味。', 66384),
(291064, 'zhTW', '我的妹妹維蘭可能迷失在虛無中，不過我們或許可以喚回她的記憶。', '', 66384),
(291062, 'zhTW', '影衛的讀數來自那個方向。', '', 66384),
(291061, 'zhTW', '阿隆索斯告訴我，他一直想讓白銀之手著重在為民服務上。', '', 66384),
(291060, 'zhTW', '這不是白銀之手該插手的事吧？', '', 66384),
(291058, 'zhTW', '但是讓無辜的人受苦…這是最惡劣的行徑。', '', 66384),
(291056, 'zhTW', '很抱歉，$g先生:女士;。這後面是員工區。我們這裡的行程非常緊。\n\n你在找什麼東西嗎？', '', 66384),
(291052, 'zhTW', '', '騎士們，在這裡保衛好永歌森林。$n，我們跟他們走吧。', 66384),
(291051, 'zhTW', '', '你的邊境？哈。如果你想死在祖阿曼的暮光之刃手上，我不會阻止你。但你的軍隊不准前進一步。', 66384),
(291049, 'zhTW', '', '跟我來，兄弟姊妹。記得保持安靜。', 66384),
(291048, 'zhTW', '', '『二度流放者』圖阿瑪對你點點頭，表示感謝，然後轉身帶領她的族人前往安全處。', 66384),
(291037, 'zhTW', '', '我們能抽調出來的大部分遠行者正在西邊的日冠樹建立防線。\n\n赫杜倫率領一匹人馬來這個源途。他說我們可以利用它呼叫援軍。不過我承認，我原本以為不會只有一個$c和一個…不知道是什麼的生物過來。\n\n<瓦麗雅針對性地看向歐薇娜。>', 66384),
(291028, 'zhTW', '', '$n，在這裡！現在的情況…正在惡化。', 66384),
(291009, 'zhTW', '入侵者，你在這裡做什麼？\n\n你不是還要去討好一些羅亞嗎？', '', 66384),
(291006, 'zhTW', '恩萊亞，不行！你太虛弱了！', '', 66384),
(291005, 'zhTW', '我知道接下來該做什麼。我必須殺了莫塔卡。', '', 66384),
(290993, 'zhTW', '', '別讓他們攻打奇異點錨！', 66384),
(290989, 'zhTW', '我會派人去調查的。不過我很慶幸有你在，我需要你幫我個忙。', '', 66384),
(290988, 'zhTW', '真的嗎？那真是太奇怪了。', '', 66384),
(290987, 'zhTW', '邪教？這是很嚴重的指控。', '', 66384),
(290986, 'zhTW', '對一些人來說是。其他人只是很享受用巨錘打擊惡人。', '', 66384),
(290985, 'zhTW', '這就是成為日行者的意義嗎？', '', 66384),
(290981, 'zhTW', '想到我們寧靜的小鎮可能正在發生某種不幸的事就讓我感到痛苦。', '', 66384),
(290980, 'zhTW', '快啊，$n。告訴他。', '', 66384),
(290979, 'zhTW', '博學者奧姆里克！你的研究有進展嗎？', '', 66384),
(290975, 'zhTW', '$n，回到聖光會堂吧。這場仗還沒結束。', '', 66384),
(290953, 'zhTW', '', '<在你靠近時，圖阿瑪睜開眼睛，並向你點頭致意。\n\n接著她看向你身後，對一個經過的虛無生物發出冷笑。>', 66384),
(290950, 'zhTW', '', '啊，你是出乎意料的訪客，但並非不受歡迎的奧客。\n\n放縱之穴能幫你什麼忙？', 66384),
(290949, 'zhTW', '裘拉斯開始哭泣。圖阿瑪轉向一旁，擦去眼角的淚水。', '', 66384),
(290948, 'zhTW', '', '我不能讓多曼納爾跟上你。沒有其他辦法了，兄弟。', 66384),
(290947, 'zhTW', '你說你不來是什麼意思？！', '', 66384),
(290946, 'zhTW', '', '當然。只要有需要，聖匣守護者就會提供援助。如果你們有需要的話就告訴我。', 66384),
(290945, 'zhTW', '阿曼尼小徑的事優先。我不會讓他們再次入侵奎爾薩拉斯。', '', 66384),
(290944, 'zhTW', '你要回去那裡？請小心點，圖阿瑪。', '', 66384),
(290942, 'zhTW', '阿拉特，如果有必要的話就去調查吧。但我希望你可以盡速抵達小徑。', '', 66384),
(290941, 'zhTW', '', '去找虛無之人。再會。', 66384),
(290939, 'zhTW', '', '圖阿瑪看向你，然後往上指。', 66384),
(290938, 'zhTW', '', '多曼納爾有我們用得到的東西。我們會找到它。別因為血的事而對那個外來者不滿，兄弟姊妹。', 66384),
(290937, 'zhTW', '', '太陽之井爆發的能量…雖然我博學多聞，但我從沒見過這麼強大的魔法。他們說那支軍隊會保護我們，但我聽說那次波動就是他們造成的！他們清楚自己在做什麼嗎？', 66384),
(290935, 'zhTW', '', '發生了那麼多事，那個…天空中無比瘋狂的暗影漩渦把客人都嚇跑了。要不是因為這裡是我管的，不然我也早就離開了。這裡的房間就隨便你挑吧。', 66384),
(290934, 'zhTW', '洛索瑪！我奪下了這個區域，但他們朝阿曼尼小徑推進了。', '', 66384),
(290932, 'zhTW', '多謝你的幫助。洛索瑪已經把日冠發生的事跟我說了。\n\n日冠本來在我的守望之下，但我們聽見樹倒下，因此去調查那個聲音。我本以為那或許是光綻造成的…我從沒想過阿曼尼食人妖會如此明目張膽地來犯。\n\n我會去對付光綻。洛索瑪可以去對付阿曼尼食人妖…希望他不會在過程中失去他的另一隻眼睛。\n\n<赫杜倫眨了眨眼。>', '', 66384),
(290931, 'zhTW', '太陽之井的波動會嚇跑龍鷹，牠們能夠感知到危險。我從未看過牠們這麼驚慌。如果對動物的影響都這麼大了，永歌森林又會如何？', '', 66384),
(290929, 'zhTW', '', '我上次看到暗影降臨奎爾達納斯，是阿薩斯率領天譴軍團攻打我們王國的時候。現在城裡又有一支軍隊，說是為了保護我們…你確定嗎？', 66384),
(290927, 'zhTW', '', '『二度流放者』圖阿瑪仔細觀察在她面前形成的不良傳送門。', 66384),
(290926, 'zhTW', '', '別抱怨了。快看，發揮作用了。', 66384),
(290925, 'zhTW', '下次先警告我！', '', 66384),
(290924, 'zhTW', '', '在這裡，裘拉斯。', 66384),
(290923, 'zhTW', '裘拉斯面無表情地盯著圖阿瑪，任她將自己浸入血中。', '', 66384),
(290921, 'zhTW', '<用倒下的光綻樹雕刻而成的整齊木材堆。>', '', 66384),
(290916, 'zhTW', '<他上下打量著你，不發一語。\n\n你聽見房裡的其他人低聲輕笑。>', '', 66384),
(290915, 'zhTW', '啊，歡迎來到我們的動物園。我們網羅了奎爾薩拉斯和世界各地的一些生物。\n\n如果你想要的品種需要特殊的證照才能購買也不必擔心。我們非常樂意替你解決這小小的不便，當然，這需要另外付費。', '', 66384),
(290906, 'zhTW', '', '你有預約嗎？目前很難穩定供貨。因為有絡繹不絕的居民願意花大錢一窺自己的未來。', 66384),
(290905, 'zhTW', '<這名阿曼尼食人妖因光綻生物而落入悲慘的下場。>', '<這名阿曼尼食人妖因光綻生物而落入悲慘的下場。>', 66384),
(290892, 'zhTW', '', '魯亞已經撤退，艾恩之塵也拿到手，我們可以擊退這股狂潮了。', 66384),
(290889, 'zhTW', '', '那個袋子…裡面有種子嗎？', 66384),
(290888, 'zhTW', '', '看來魯格在倒下之前，還殺了幾個。', 66384),
(290883, 'zhTW', '聖光先鋒會需要營房和補給品。', '', 66384),
(290882, 'zhTW', '$p，如果你準備好了，我就開始儀式。', '', 66384),
(290881, 'zhTW', '首先，我們要設下結界。我已經感覺到那些化身開始聚過來了。', '', 66384),
(290879, 'zhTW', '', '真菌裂縫的水池原本是個美麗的地方。這就是失去平衡之後的結果。蘑菇人的數量過多，也污染了池子。', 66384),
(290878, 'zhTW', '', '魯格獻出自己的生命，但那不足以打贏這場仗。他曾是強悍的戰士，但是，只要數量夠多，就連他也可能被打倒。\n\n顯然蘑菇人是幕後凶手，還偷走魯格和他的同伴搬運的種子。\n\n這條路再過去就是真菌裂縫。我們必須靠近一點。等你準備好了，就告訴我一聲。', 66384),
(290876, 'zhTW', '有入侵者？守衛，保護長老！', '', 66384),
(290875, 'zhTW', '', '歐薇娜，靜下來。魯亞會受到制裁的。來吧，我們必須撤退到日冠樹。', 66384),
(290874, 'zhTW', '', '我可以感覺到他想透過樹根逃離。我們必須…', 66384),
(290872, 'zhTW', '', '我們擊退他們。奇異點錨也啟動了！', 66384),
(290871, 'zhTW', '', '勇士，動作快。在敵人來臨前，在奇異點錨附近做好防禦準備！', 66384),
(290870, 'zhTW', '', '滋養光綻！', 66384),
(290868, 'zhTW', '那個生物一定是從光綻誕生的！一定要讓博學者知道這件事。', '', 66384),
(290867, 'zhTW', '儀式地點在那裡！', '', 66384),
(290866, 'zhTW', '這是…我不太確定。我們好像得走回另一邊。', '', 66384),
(290865, 'zhTW', '呃…我能感覺到儀式地點就在附近。', '', 66384),
(290864, 'zhTW', '我們得小心，這裡有東西會把我們撕成碎片。', '', 66384),
(290863, 'zhTW', '那感覺像是撕裂了我身上的一部分，痛得難以忍受。', '', 66384),
(290861, 'zhTW', '它在帶我們往裂隙深處走，我們得跟上。', '', 66384),
(290858, 'zhTW', '我能感覺到附近有什麼…好像正拉著我。', '', 66384),
(290857, 'zhTW', '', '敵人從南方進逼了。別讓他們推進到奇異點錨！', 66384),
(290855, 'zhTW', '…然後為差點釀的禍跟他道歉。', '', 66384),
(290854, 'zhTW', '成功了！我們找到進入虛無風暴的方法了。我們必須告訴洛索瑪。', '', 66384),
(290853, 'zhTW', '那…是什麼怪物？$p，你去拖住它，我來引導法術，了結這場混亂！', '', 66384),
(290852, 'zhTW', '$p，我知道該怎麼做了！我必須讓標的和虛無風暴同調。', '', 66384),
(290851, 'zhTW', '好像出了嚴重的差錯…快走。我找到解決的方法後再跟你會合。', '', 66384),
(290850, 'zhTW', '幫我移除標的周圍的結界！', '', 66384),
(290849, 'zhTW', '制服他！我來解決這些屏障。', '', 66384),
(290848, 'zhTW', '騙人！沒有人能碰到標的！', '', 66384),
(290847, 'zhTW', '薩拉奈爾！退下！我有洛索瑪的准許令！', '', 66384),
(290844, 'zhTW', '手法雖然粗糙，但十分有效。標的應該就在前面了。', '', 66384),
(290843, 'zhTW', '我似乎被…困住了。前方的傀儡正在強化洛摩斯的法術。快把它毀掉。', '', 66384),
(290842, 'zhTW', '奧姆里克，你不許再前進了。提醒你，這些新的防禦措施是專為你設計的。', '', 66384),
(290841, 'zhTW', '沒想到洛摩斯會想方設法阻止我進來…', '', 66384),
(290840, 'zhTW', '祝你…有個…美好的…一天…', '祝你…有個…美好的…一天…', 66384),
(290838, 'zhTW', '未授權進入。', '未授權進入。', 66384),
(290837, 'zhTW', '我真想念這座圖書館。但我們不能久留。', '', 66384),
(290835, 'zhTW', '噢，小心那些圖書管理員。雖然他們平常都在讀書…但也不容小覷。', '', 66384),
(290834, 'zhTW', '既然都來了，我想拿一點東西。我們到出口會合。', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(290833, 'zhTW', '他當然有留訊息給我了。恐怕你得解決這些守衛了。', '', 66384),
(290832, 'zhTW', '奧姆里克，我警告過你！殿堂永遠不會為你敞開！馬上給我離開，不然的話…', '', 66384),
(290831, 'zhTW', '未授權進入。請稍等。', '未授權進入。請稍等。', 66384),
(290830, 'zhTW', '這座殿堂裡藏有進入虛無風暴的關鍵…暮光標的。', '', 66384),
(290801, 'zhTW', '好吧…但要是這堂課和其他的沒什麼不同…', '', 66384),
(290800, 'zhTW', '阿拉特，我有跟你說過尋找另一條道路。我想是時候開始了。', '', 66384),
(290693, 'zhTW', '', '這批貨物是什麼？', 66384),
(290676, 'zhTW', '', '艾恩哈拉的根部，這個地方發出惡臭。果然是蘑菇人會喜歡的地方。', 66384),
(290671, 'zhTW', '假裝成手頭闊綽買家。你應該就會找到魔能商人。', '', 66384),
(290660, 'zhTW', '看來安諾里恩領主會為大家提供庇護。', '', 66384),
(290646, 'zhTW', '', '新來客，補給品…他們好像在準備什麼。', 66384),
(290645, 'zhTW', '', '別擔心。安諾里恩領主會照顧所有人。', 66384),
(290644, 'zhTW', '聖光會戰勝一切。我們必須有信心。', '', 66384),
(290643, 'zhTW', '', '快看天空！聖光拋棄我們了。', 66384),
(290637, 'zhTW', '', '小心腳下…別踩到牠們！\n\n是什麼風把你吹來棲息地？', 66384),
(290636, 'zhTW', '$n，你看看。我接近的時候，有些精靈就跑走了，不過他們留下了一些東西。', '', 66384),
(290629, 'zhTW', '', '安寧地的居民在恐懼中哭喊。他們想要尋求慰藉。\n\n他們所走過的道路是如此漫長，而太陽的聖光也早已拋棄了他們…', 66384),
(290626, 'zhTW', '所以大家才會討論這麼熱烈。我們需要盡可能收集武器。', '所以大家才會討論這麼熱烈。我們需要盡可能收集武器。', 66384),
(290625, 'zhTW', '虛無不會等人。學院訓練我們的速度太慢了。', '虛無不會等人。學院訓練我們的速度太慢了。', 66384),
(290624, 'zhTW', '再兩年就要畢業？銀月城很可能連兩個月都撐不到！', '再兩年就要畢業？銀月城很可能連兩個月都撐不到！', 66384),
(290623, 'zhTW', '不管任何代價都值得。我們的人上次正是因此僥倖存活。這可以再救我們一次。', '不管任何代價都值得。我們的人上次正是因此僥倖存活。這可以再救我們一次。', 66384),
(290622, 'zhTW', '你的關係很有用。我的侍者順利從兇殺路取得穩定的供貨。這是價格高昂的必要之惡。', '你的關係很有用。我的侍者順利從兇殺路取得穩定的供貨。這是價格高昂的必要之惡。', 66384),
(290621, 'zhTW', '沒錯，不過那需要金幣。魔能可不便宜。也許我們可以替贊恩工作。跟他達成買賣協議。', '沒錯，不過那需要金幣。魔能可不便宜。也許我們可以替贊恩工作。跟他達成買賣協議。', 66384),
(290620, 'zhTW', '如果虛無像天譴軍團一樣攻擊城市，沒人會來防守兇殺路。我們需要自己的武器。', '如果虛無像天譴軍團一樣攻擊城市，沒人會來防守兇殺路。我們需要自己的武器。', 66384),
(290619, 'zhTW', '遠行者的短缺對我們的兇手來說似乎是件好事。', '', 66384),
(290602, 'zhTW', '', '魯格曾是戰士、名聲響亮的獵人和導師。他教導我各式各樣的事。他是我們當中最厲害的人，直到他變得年邁體衰。\n\n最近，他一直在照料他的花園。他正…曾跟魯坦尼合作培育新種特拉塔克，那是一種成長週期極度緩慢的根莖蔬菜，相當美味。\n\n魯格堅稱自己能夠縮短週期，同時提高產量。現在他再也不知道他到底對不對。', 66384),
(290600, 'zhTW', '', '我無法相信魯格已經死了。我們原本應該一起去狩獵。\n\n<她低下頭來，一言不發。過一陣子後，她喘了幾口氣，並站起身子。>\n\n不過，跟他一起出去的魯坦尼魯格可能還活著，除了倒在這裡的這個。我們不能放他們不管。這裡的蘑菇人舉止十分詭異。', 66384),
(290598, 'zhTW', '跟我來。', '', 66384),
(290593, 'zhTW', '<蘑菇人因身上謎樣的傷口而死。腐敗和發霉的味道瀰漫在空氣中。>', '', 66384),
(290592, 'zhTW', '自從那隻貓狩獵歸來後，牠一直表現得很反常…', '自從那隻貓狩獵歸來後，牠一直表現得很反常…', 66384),
(290589, 'zhTW', '絕對不是。', '絕對不是。', 66384),
(290588, 'zhTW', '牠一直是那樣嗎？', '牠一直是那樣嗎？', 66384),
(290586, 'zhTW', '', '不！我們必須查清這裡出了什麼事。', 66384),
(290585, 'zhTW', '', '動作快，$n。', 66384),
(290582, 'zhTW', '', '聖光…燃燒…', 66384),
(290572, 'zhTW', '', '金德魯…希望你是對的。為了阿曼尼！', 66384),
(290560, 'zhTW', '', '哇，那真是個迅速的道別！', 66384),
(290559, 'zhTW', '我會把這顆種子帶回銀月城。博學者或許知道些什麼。', '', 66384),
(290558, 'zhTW', '我終其一生都虔誠地侍奉聖光，$p，即使在過程中失去了一隻眼睛。\n\n的確有比我厲害的聖騎士，但不多。\n\n但是，除了幾個防衛者和我們的侍從外，幾乎所有人都被調到銀月城，以便阻止虛無。\n\n我不禁懷疑起，我是不是在某些時候辜負了聖光而不自覺。', '', 66384),
(290557, 'zhTW', '', '小心點。上次遇到這種事的時候，我最後收養了那隻小搗蛋鬼。', 66384),
(290556, 'zhTW', '我不知道牠是想吃杯子蛋糕，還是以為它是牠的手足。', '', 66384),
(290553, 'zhTW', '我沒被調到太陽之井，好處之一是能夠統整聖光之願的防務。', '', 66384),
(290552, 'zhTW', '', '那不重要了。你需要幫忙。', 66384),
(290551, 'zhTW', '我們還有兩個孩子在外頭！', '', 66384),
(290548, 'zhTW', '嚴禁帶外來者到哈朗達！光是前往地表，讓你的世界得知我們的存在，歐薇娜就已經違背了我們的律法。現在居然變本加厲！\n\n你該慶幸有歐薇娜這個朋友，不然我一定會把你纏在樹根之中，給樹液迅猛龍當點心吃。', '', 66384),
(290545, 'zhTW', '<遠行者偵察報告，其中提出了幾起令人擔憂的事件。死亡之域中的古怪活動跡象、異常虛無生物的現身、人們的失蹤…這類事件不勝枚舉。\n\n儘管報告內容龐雜，卻沒有採取什麼行動來解決這些事件。>', '<遠行者偵察報告，其中提出了幾起令人擔憂的事件。死亡之域中的古怪活動跡象、異常虛無生物的現身、人們的失蹤…這類事件不勝枚舉。\n\n儘管報告內容龐雜，卻沒有採取什麼行動來解決這些事件。>', 66384),
(290544, 'zhTW', '<昨晚排定好的守衛巡邏被劃掉。一張來自守衛隊長的紙條寫道：>\n\n今晚我會親自巡視周圍。這是管理者的命令。好好享受今晚的休假。\n\n雷', '<昨晚排定好的守衛巡邏被劃掉。一張來自守衛隊長的紙條寫道：>\n\n今晚我會親自巡視周圍。這是管理者的命令。好好享受今晚的休假。\n\n雷', 66384),
(290542, 'zhTW', '<這本書裡寫滿了奇怪的佈道，其內容一點都不像精靈該有的風格。\n\n其中似乎強調了聖光所投射出的影子的重要性，以及一場即將到來的日蝕必須被安撫的警告。>', '<這本書裡寫滿了奇怪的佈道，其內容一點都不像精靈該有的風格。\n\n其中似乎強調了聖光所投射出的影子的重要性，以及一場即將到來的日蝕必須被安撫的警告。>', 66384),
(290541, 'zhTW', '歡迎來到安寧地！\n\n即使是在最黑暗的時刻，安寧地依舊屹立不倒。好好休息，尋求慰藉，艱苦的日子已經過去了。\n\n某種新的事物即將到來。一切都會好起來的。\n\n或許你會來到這裡是有原因的，即使你還不知道這個原因是什麼。', '歡迎來到安寧地！\n\n這座小鎮曾經歷過許多磨難。\n\n艱苦的日子已經過去了。某種新的事物即將到來。\n\n你會來到這裡是有原因的，即使你還不知道那是什麼。', 66384),
(290540, 'zhTW', '<這些看起來是守衛隊長偶爾會放進新來客的歡迎包裡的紙條。>\n\n未來或許充滿未知，但真相就擺在你的眼前。\n\n到安寧地的南邊加入我們。確保你沒有被跟蹤。', '<這些看起來是守衛隊長偶爾會放進新來客的歡迎包裡的紙條。>\n\n未來或許充滿未知，但真相就擺在你的眼前。\n\n到安寧地的南邊加入我們。確保你沒有被跟蹤。', 66384),
(290539, 'zhTW', '', '把艾恩之塵分給這裡的戰士。這能強化他們，幫助他們擊退光綻。', 66384),
(290536, 'zhTW', '這個光綻或許對聖光先鋒有用處。至少，我得去查清楚。', '', 66384),
(290535, 'zhTW', '', '貓咪，快下來！', 66384),
(290534, 'zhTW', '我們在太陽之井的行動是否成功，將會影響到許多人，$p。\n\n這是很沉重的負擔，但是拒絕背負的後果會更加沉重。\n\n謝謝你幫我們分擔。', '', 66384),
(290531, 'zhTW', '光綻正在永歌森林擴散，如果要阻止它，我們必須馬上行動。情況很險峻，歐薇娜。', '', 66384),
(290522, 'zhTW', '', '金德魯要我們留下祭品。敵人的腦袋正好合適。', 66384),
(290521, 'zhTW', '我們得找到祖爾詹，不然就太遲了。', '', 66384),
(290520, 'zhTW', '等等！沒有必要刀劍相向。', '', 66384),
(290518, 'zhTW', '', '不過，老鷹又回到這裡似乎是個好兆頭。', 66384),
(290513, 'zhTW', '', '我準備好進行蘇卡的儀式了。它在我們進入艾恩裂隙後…會暫時保護我們。', 66384),
(290511, 'zhTW', '洛索瑪，我們發現附近有藏身處的證據…', '', 66384),
(290498, 'zhTW', '利用你的感官追蹤魔能，$c。我們很快就會再會。', '', 66384),
(290488, 'zhTW', '痕跡很模糊…但我還可以感應到它在這裡。', '', 66384),
(290487, 'zhTW', '嗯…\n\n老實說，我們會擠壓裂隙流出的黏液，一旦我們被裂隙的影響壓垮時，就會互相幫助。\n\n那是我們唯一能做的。', '嗯…\n\n老實說，我們會擠壓裂隙流出的黏液，一旦我們被裂隙的影響壓垮時，就會互相幫助。\n\n那是我們唯一能做的。', 66384),
(290485, 'zhTW', '艾恩裂隙對哈拉尼爾很危險。在那裡，女神的聲音太過清晰，我們可能迷失在她的呼喚中。就連逃脫的生物也會分泌可能傷到我們的黏液。\n\n有人必須確保裂隙的影響不會擴及哈朗達的其他地方。因此我們才會出現在這裡。', '艾恩裂隙對哈拉尼爾很危險。在那裡，女神的聲音太過清晰，我們可能迷失在她的呼喚中。就連逃脫的生物也會分泌可能傷到我們的黏液。\n\n有人必須確保裂隙的影響不會擴及哈朗達的其他地方。因此我們才會出現在這裡。', 66384),
(290449, 'zhTW', '<壓制戴西蒙斯和洛斯拉賽恩已經讓阿拉特全神貫注。過程中，他咬緊牙關。>', '', 66384),
(290443, 'zhTW', '', '這裡的虛無密度極高，你甚至能直接吞下去。我擁抱這股力量，我歡迎它的考驗。這陣陰寒、混沌的強風讓我法喜充滿。\n\n一次又一次，我們術士突破其他人認為安全的極限。\n\n我站在這裡，未曾失控。', 66384),
(290440, 'zhTW', '迷霧結界消失了！我們快去找祖爾詹吧。', '', 66384),
(290439, 'zhTW', '<在瓶子裡，新鮮的血脈凝塊沉入灰燼之中。>', '', 66384),
(290437, 'zhTW', '<灰燼位於瓶子的底部。>', '', 66384),
(290436, 'zhTW', '<在瓶子裡，新鮮的骨殼尖牙躺在一層灰燼上。>', '', 66384),
(290434, 'zhTW', '<灰燼位於瓶子的底部。>', '', 66384),
(290425, 'zhTW', '', '自從這個地方變成半荒廢的狀態之後，我就沒看過這個數量的補給品進進出出過。\n\n管理者怎麼會覺得我能掌握好所有補給品的流向呢？', 66384),
(290424, 'zhTW', '這雖然不常見，但也沒人說不能找外援。過來吧，$c。', '', 66384),
(290423, 'zhTW', '', '把你的武器放在我看得到的地方。', 66384),
(290422, 'zhTW', '太弱了，太無力了…', '', 66384),
(290418, 'zhTW', '我們到那裡見。', '', 66384),
(290417, 'zhTW', '安諾里恩領主最看重人民的安危了。必須把這件事告訴他。', '', 66384),
(290414, 'zhTW', '我的導師要我在俯瞰裂隙的懸崖北緣與他會合。', '', 66384),
(290413, 'zhTW', '我先和其他人商討，之後再仔細考慮。', '', 66384),
(290412, 'zhTW', '', '<在你靠近時，法師嗅了嗅空氣，然後瞇起她僅存的好眼睛看著你。猶豫了一陣子後，她不情願地用流利的惡魔語說話。>\n\n你充滿惡魔的臭味。我們就跳過互噴髒話的環節吧，不過別把我誤認成曼那瑞。我們是德萊尼，流放者，倖存者。\n\n我是圖阿瑪。保護我的族人「虛空使」，讓他們順利回家，是我的責任。', 66384),
(290411, 'zhTW', '', '我失去了許多事物。先是巨樹，然後是庫札特和那些被感染的商人。\n\n至少，我很高興看到歐薇娜回來了。雖然我猜想女神很快就會再次要她離開。', 66384),
(290410, 'zhTW', '', '我們必須想辦法治癒那些被光綻感染的個體。這個村莊已經失去太多生命了。', 66384),
(290405, 'zhTW', '', '在下雖在綻放臺地生長，但一直都在艾恩裂隙收集種子。\n\n哈拉諾離我們的花園或裂隙很遠。', 66384),
(290374, 'zhTW', '', '<你感應到圖阿瑪周圍的空氣中響起熟悉的秘法嗡鳴聲。她就像你一樣，能夠利用秘法語言學家理解盟友的語言。她笑著，認出了你的能力。>\n\n一位同道的法師。真方便。這讓事情簡單多了。\n\n我是圖阿瑪。保護我的族人「虛空使」，讓他們順利回家，是我的責任。', 66384),
(290373, 'zhTW', '我們不死族與聖光的關係很複雜，而我又更甚於其他人。\n\n聖光灼燒著我。我學會忍受其痛苦，繼續從事牧師的工作，不過，擔任大主教這麼多年，聖光與我的共鳴比其他人都還要強大。\n\n太陽之井也不例外。光是站在外面，感官就無時無刻灼痛不已，強烈，但還能承受。\n\n不過，如果進去裡面，我一定會像飛蛾撲火一般，被聖光燃燒殆盡。', '', 66384),
(290370, 'zhTW', '我從未如此接近太陽之井…', '', 66384),
(290369, 'zhTW', '克隆娜，陌生人。抱歉，但我的手不能停下來。如果要保存我死去的族人，我的時間非常緊迫。', '', 66384),
(290368, 'zhTW', '根本不是那樣，不過已經夠了。\n\n我一直試著成為英雄。我成功了。他們甚至叫我『救贖者』阿拉特。\n\n舉起劍衝鋒，使用聖光…\n\n我不確定聖光本身是否跟我理解的一樣清晰或簡單。\n\n我還沒想明白，虛無就入侵了。\n\n於是，我覺得先聽法奧的命令行事就好，直到我找到自己的立足點。\n\n或者至少能夠再次釐清立場為止。', '', 66384),
(290366, 'zhTW', '$p。\n\n我很抱歉…我現在不太想說話。', '', 66384),
(290365, 'zhTW', '$p，謝謝你前來相助。聖光先鋒一直在維持這個儀式，不讓薩拉塔斯越雷池一步，不過，他們不像我那麼持久。\n\n你所做的一切都能讓我們得到更多時間。', '', 66384),
(290364, 'zhTW', '', '$p！我每天都在回想，你當初是怎麼讓我擺脫血色十字軍，給我第二次機會，真正地侍奉聖光。\n\n現在，你也給了我繼續這麼做的力量。再次謝謝你。', 66384),
(290363, 'zhTW', '', '$p，我不禁在想，薩拉塔斯是怎麼走到這個地步的。我在猜她的過去或許跟虛無本身一樣黑暗。\n\n但是，我想得更多的是每個被她傷害的人…那些因她的陰謀而死的人。因此，無論我們多麼精疲力竭，都必須利用太陽之井阻止她。', 66384),
(290362, 'zhTW', '', '老實說，$p，當我跟著我父親進入死亡的國度時，我以為那已經是我人生的巔峰。\n\n結果現在我們卻在跟更加詭異、更加不可思議的敵人對戰。太可怕了，不過，我很高興能夠盡一份心力。', 66384),
(290361, 'zhTW', '我必須研究凱西雅的筆記。我不會讓她白白喪命。', '', 66384),
(290360, 'zhTW', '', '自從我從外域來到這裡，太陽之井一直是我的聖光信標，並幫助我了解血精靈這個身分的意義。\n\n我很榮幸能夠助你一臂之力，$p。', 66384),
(290359, 'zhTW', '這些筆記…凱西雅？不！', '', 66384),
(290358, 'zhTW', '博學者，請節哀。我會請人好好處理遺體的。', '', 66384),
(290357, 'zhTW', '我見證了許多事，$p，從聖騎士的草創時期，到阿薩斯背棄了聖光…\n\n我本以為，隨著燃燒軍團落敗，以及提爾的回歸，我們能有更光明的未來，結果虛無又讓我們的世界即將墮入黑暗。\n\n謝謝你幫助我找到堅持下去的力量。', '', 66384),
(290355, 'zhTW', '', '$p，那是阿隆索斯的法杖嗎？當我脫離血色十字軍時，正是他接納我加入牧道會。\n\n如果他願意把法杖託付給你，我應該也能相信你。', 66384),
(290354, 'zhTW', '', '我不認為阿拉希帝國過去有像是太陽之井的東西，$p。\n\n我們必須保護它。謝謝你的幫忙。', 66384),
(290353, 'zhTW', '', '我的族人對於虛無的來犯並不陌生，正是我們對羅亞的信仰，幫助我們在過去贏得勝利。\n\n我對羅亞和提爾教誨的信仰，在今天將會指引我的手。希望這樣就足夠了。', 66384),
(290352, 'zhTW', '安希一定會要我們挺身對抗虛無。\n\n而且在你的幫助下，我還是能夠這麼做。', '', 66384),
(290351, 'zhTW', '', '這麼多年來，我見證了虛無奪走無數士兵的性命…\n\n吞噬一切、無窮無盡，就像燃燒軍團一樣。甚至還要更糟。\n\n$p，我祈禱這次衝突不會持續數千年。', 66384),
(290333, 'zhTW', '我們必須向銀月城回報。他們得知道這件事。', '', 66384),
(290329, 'zhTW', '', '魯坦尼…他們正受驅使而成長。你說的聖光可能就是原因。', 66384),
(290321, 'zhTW', '謝謝你幫忙，$p。我也會順便收集這些生物的毒液…希望不會因此昏迷。', '', 66384),
(290303, 'zhTW', '奇雅，別想著回去那裡，想都別想。', '奇雅，別想著回去那裡，想都別想。', 66384),
(290299, 'zhTW', '', '以太族，虛無之尖必將淪陷！', 66384),
(290298, 'zhTW', '為了找到聖光，我們選了不同的道路，但我們都為了相同的目標聚集在此。那就是保護艾澤拉斯！', '', 66384),
(290297, 'zhTW', '漫長的旅程讓在下有點枯萎。\n\n花時間欣賞這個生物身上的花瓣結構的確能恢復精神。', '', 66384),
(290296, 'zhTW', '', '你們被虛無奴役，而我因虛無而壯大！', 66384),
(290295, 'zhTW', '如果太陽之井陷落了，我們就沒辦法阻止吞噬之眾了！', '', 66384),
(290294, 'zhTW', '我知道你累了。堅持下去很艱難，但我們必須這麼做！', '', 66384),
(290291, 'zhTW', '請找到他，$p。叫他回家。', '請找到他，$p。叫他回家。', 66384),
(290288, 'zhTW', '黑暗、潮濕，腐敗會降臨於你！', '', 66384),
(290287, 'zhTW', '能見到友善的魯坦尼感覺真怪。', '', 66384),
(290286, 'zhTW', '很棒的派對。很高興看到薩瑟里還知道如何辦個好派對。\n\n此外，也可以趁這個機會，從這些死都不會出現在兇殺路的貴族當中，發掘一些客人。', '', 66384),
(290285, 'zhTW', '', '這裡有點悶。至少我們不在舞廳裡。', 66384),
(290283, 'zhTW', '儘管我鄙視這種浪費時間的無聊事，但血騎士有必要募集所需的資金，才能打贏這場仗。', '', 66384),
(290281, 'zhTW', '在下是米卡，是哈瑪拉這裡的魯坦尼負責人。', '', 66384),
(290280, 'zhTW', '願這個陌生人的根扎得更深。', '', 66384),
(290271, 'zhTW', '', '我聽說薩瑟里領主對你有很高的評價。他的青睞在這樣的圈子裡是不少人夢寐以求的。\n\n如果你能讓他將一部份的恩惠給予博學者，我相信我們可以達成互惠互利的協議。', 66384),
(290185, 'zhTW', '系統…故障。', '', 66384),
(290183, 'zhTW', '指令：至高之父拒絕所有存取。', '', 66384),
(290178, 'zhTW', '', '幾年前，當我還很年輕的時候，也經歷過這些試煉。當哈拉尼爾成長到一定年紀，擁有一定實力，都需要接受試煉。\n\n通過成年禮，就象徵我們正式進入成人階段，並為我們未來在部族中的發展奠下基礎。', 66384),
(290177, 'zhTW', '', '很高興看到你毫髮無傷地通過試煉，$n。當然，這都在我的預料之中。\n\n我知道你是個厲害又可靠的人，正因為如此，我多少認為很值得與你分享我們的歷史和秘密。', 66384),
(290175, 'zhTW', '曾遇到一些困難，但我都能一一克服。很高興看到你也順利撐了過來。\n\n我喜歡哈拉尼爾。他們與自然世界關係密切，並守護著它，就像遊俠一樣。\n\n很有魅力的一群人，而且透過壁畫傳承歷史是我前所未見的作法。\n\n哈嘉爾說過，哈拉尼爾各地還有更多壁畫，訴說更多他們的故事。我很想把它們找出來，進一步了解他們的歷史。', '', 66384),
(290174, 'zhTW', '哈拉尼爾的歷史真是太精采了。他們很可能是第一批聽見艾澤拉斯歌聲的人，他們稱其為艾恩哈拉。', '', 66384),
(290102, 'zhTW', '那種武器…還有光木…他們想做的不是征服永歌森林。他們是在從暮光之刃的手中保護自己。', '', 66384),
(290101, 'zhTW', '竟然叫我去鼓舞其他人？法奧的想法總是這麼獨樹一幟。', '', 66384),
(290097, 'zhTW', '很高興認識你，老闆。你想討論商業策略嗎？那我就是你的不二人選。', '', 66384),
(290096, 'zhTW', '', '所以你就是那個高貴的哥布林負責人。我想我們可以一起大賺一筆。你覺得呢？', 66384),
(290093, 'zhTW', '', '啊對，我差點就忘了。梅格斯要你選一個行銷夥伴，行嗎？\n\n拐杖糖和奇普在焦點小組中脫穎而出。在時尚、魅力和假戲真做這方面都拿到了最高分。\n\n不論是哪一人，都能很好地襯托出你殺人不眨眼的形象。這樣應該能讓普通的哥布林對你更有親切感。就像你私底下有軟弱的一面，有點類似爛掉的水蜜桃那樣。\n\n總而言之，你打算選誰當你的夥伴？', 66384),
(290092, 'zhTW', '法奧派你來的？他是個正派的人。\n\n你知道嗎？他成立了我待的聖騎士團。他訓練了我的…白銀之手正是他一手打造。\n\n非常好，$p。我會聽令行事。那正是我所追求的人生。', '', 66384),
(290090, 'zhTW', '喔，哈囉，$p。\n\n我只是…在看噴泉。我需要呼吸新鮮空氣。\n\n有人需要我嗎？你是為此而來嗎？', '', 66384),
(290088, 'zhTW', '我性感的執行長今天如何啊？就你現在經營企業的模式，我覺得你被稱為貿易$g親王:女王;$n都不為過！$B$B我已經等不及了！我要到健身房的游泳池把我的皮膚曬成古銅色。', '', 66384),
(290085, 'zhTW', '', '我…會好好考慮。但你必須了解，這些人…我的族人…我們已經有一個家了。他們有家人…有曾被奪走的摯愛。\n\n設身處地想一下：拋下一切，跟我們一起走，並且希望新世界比你已知且所愛的世界更安全。\n\n我們可以之後再來深入討論，但在我們說話的當下，我們其實身處險境。', 66384),
(290078, 'zhTW', '', '黑暗的天空，看看布羅席尼爾斯。如此自律。它脫離束縛而行。但願暗幽谷女士能明白自己有多幸運。\n\n<露西亞看向自己的虛無行者，然後露出厭惡的神情。>\n\n卡爾葛，這場風暴讓你變得任性蠻橫。相較之下，你簡直就是一條雜種狗。', 66384),
(290075, 'zhTW', '', '消失吧。', 66384),
(290072, 'zhTW', '<裘拉斯張大眼睛看著你。他似乎不太理解。>\n\n呃？呃？不，不！朋友！不懂古老的方言！太可怕了！', '', 66384),
(290071, 'zhTW', '謝謝你救了我，$G兄弟:姊妹;。我欠你一命，或至少欠你一個擁抱，哈。\n\n圖阿瑪一直在想辦法帶我們回家。請原諒她如此提防你。對於聖光，以及受聖光賜福的人…她不怎麼有好感。跟她不一樣，我仍堅守我的信仰。\n\n<裘拉斯握住他的那魯墜飾，深深吐出一口氣。>\n\n不過我不否認自己也有被遺忘的感覺。', '', 66384),
(290070, 'zhTW', '<裘拉斯對你露出大大的微笑，並豎起大拇指。>\n\n謝謝你，謝謝你！大抱抱！', '', 66384),
(290065, 'zhTW', '', '我怎麼可能忘得了！克庫、薩格萊背叛者，還有其他來歷讓你難以置信的人！我們都是倖存者，無一例外。他們也是德萊尼，而我會自豪地站在族人的背後！\n\n數千年來，我們在冷酷無情的星外暗界孤軍奮戰，被自己的族人、被聖光遺棄！彼此保護，對抗以太族綁架者、寄生變異怪，以及就連在我們說話的當下也在侵擾我們的虛無怪物。\n\n儘管如此，我們仍打造了我們珍愛的家園。那是我們必須回去的地方。', 66384),
(290063, 'zhTW', '', '我是一名埃雷達爾，但在那之前，我是德萊尼。我鄙視惡魔，他們跨越宇宙，追殺我的族人。暴君，曼那瑞…不過在我們說話的當下，他們並非威脅我族人的怪物。\n\n我的族人需要你的幫忙，$c。請你伸出援手。', 66384),
(290061, 'zhTW', '', '<圖阿瑪仔細聽你說明德萊尼在與她分開後的經歷。>\n\n我聽說過我們在阿古斯獲得勝利的消息。直到最近之前，我們碰巧遇見了數量比以往更多的受魔痕影響的族人，他們正在尋求救贖。我很遺憾沒能與你一起在那裡。\n\n我們有很多事要討論，$G兄弟:姊妹;。希望能有時間這麼做，不過我們在這裡很危險。我的族人必須回家。', 66384),
(290059, 'zhTW', '', '$G兄弟:姐妹;，能在這樣的地方見到你真是奇蹟。\n\n我是圖阿瑪。我的職責是保護我的族人「虛空使」，讓他們安全回家。', 66384),
(290058, 'zhTW', '', '與我們在真諾達號上的族人分開了數千年，我們之間已經出現巨大的鴻溝。我應該解釋一下。\n\n我們許多人追隨預言者費倫，一起乘著飛船逃離薩格拉斯的燃燒軍團。你或許聽過我們曾尋求庇護的許多世界。你或許曾親自踏上其中的一些世界，就像我們一樣：充滿冰雪的世界，迷霧和灌木密布的世界，擁有無盡大海的世界…沒有世界能讓我長久定居。\n\n一如往常，燃燒軍團來了，我和其他人來不及趕回次元飛船，就被留下。我們看著真諾達號一飛沖天，直到縮小成一個亮點。然後，消失不見。\n\n從那時起，我們在星外暗界掙扎求生，孤立無援。', 66384),
(290057, 'zhTW', '', '<圖阿瑪展示她的魔法。你們兩人出色的秘法造詣讓你們能夠正常溝通。>\n\n我曾在埃雷達斯發光的大廳中受過訓練。我的族人很少有人會這招。不管你來自哪裡，你的魔法顯然不容小覷。', 66384),
(290055, 'zhTW', '看看我帶了什麼回來。我們分開已久的族人！$G他:她;救了我。', '', 66384),
(290051, 'zhTW', '$n，等等！有埋伏！', '', 66384),
(290050, 'zhTW', '羅亞在災難將至時總會傾聽我們的聲音。祂們現在可能只願意聽正確的聲音…像是遵循哈謝之道的人！', '', 66384),
(290047, 'zhTW', '在祖爾賈拉小時候，她的祖父祖爾金還是酋長時，羅亞依然是阿曼尼文化的中心，從阿曼尼食人妖誕生之初便是如此。\n\n所有阿曼尼酋長都需要向羅亞證明自己。但只有少數人能得到所有羅亞的祝福，並成為哈謝…這不只是一名領袖，也不只是羅亞語者，而是令人敬畏的戰士和族群的支柱。\n\n羅亞在上，這就是祖爾賈拉必須踏上的旅程！這樣我們才能得救。\n\n而你…你願意幫助她嗎？沒錯，雖然你不是阿曼尼，但是你很強大。而且我能感覺得出來，過去阿奇爾森已經幫助你拿下了多次勝利。我想不出還有誰更適合成為她的哈巫拉。', '', 66384),
(290034, 'zhTW', '庫阿瑪拉，這裡需要你的戰力。', '', 66384),
(290023, 'zhTW', '', '見到以太族。是朋友。看到在…曼塔斯…呃…\n\n<圖阿瑪比出一個球形，然後用手指製造幾個秘法火花。>\n\n對我們很好。幫忙。然後掰掰。\n\n懂嗎？', 66384),
(290021, 'zhTW', '裘拉斯對你做手勢。圖阿瑪小心地打量你，其他難民則畏怯地竊竊私語。', '', 66384),
(290020, 'zhTW', '看看我帶了什麼回來。一個英勇的外來者！他救了我。', '', 66384),
(290017, 'zhTW', '裘拉斯感激地鞠躬，然後指向西北方的地平線。', '', 66384),
(290012, 'zhTW', '卡薩梅，回音之穴的祖拉夏。我會引導你接受一個又一個試煉。', '', 66384),
(290010, 'zhTW', '', '如果你能夠得到女神的認可，就能讓他們知道，外來者也可能被她召喚。希望這能讓他們理解你是來幫忙的…而我們也需要他們的幫忙。\n\n我的族人再也不能躲在樹根底下。對樹木有害的事物，自然也對樹根有害。我們不能再繼續忽視地表世界。', 66384),
(289995, 'zhTW', '', '去吧，$n！沒有時間了！我會…跟上你…呃…！\n\n<艾蘭里亞試著起身，不過隨即倒下，力氣盡失。>', 66384),
(289994, 'zhTW', '我不記得上次拉動弓弦是什麼時候。我還讓新加入的遠行者進行短距離衝刺。\n\n<賽德拉斯皺起眉頭，摸摸左前臂。>\n\n是虛無，空氣中的能量。我們都繃緊精神，只是繃得有點太緊了。', '', 66384),
(289993, 'zhTW', '洞穴中的壁畫看起來極為巨大。它該不會真的保存著哈拉尼爾人的回憶吧？', '', 66384),
(289991, 'zhTW', '', '我曾是泰達希爾的根莖守望者。我的職責已經隨著偉大世界之樹的毀滅而終結。\n\n我們哈拉尼爾世世代代過著與世隔絕的生活，但我們再也不能抱持著能繼續這樣下去的念頭。\n\n樹根只是世界之樹的一部分。真正的守望者必須要能夠守護並照顧整棵大樹，即使樹根才是他們的的職責所在。\n\n我這輩子都會不停思考，當初我是否能做什麼來阻止世界之樹的毀滅。我願意聽你述說的這份決心，誕生自那場摧毀了巨樹的大火。', 66384),
(289990, 'zhTW', '打從出來以來，就一直聽到我父母的故事。這讓我背負了很多的期待。\n\n看到我母親的一舉一動，善用我學到的一切…儘管這個地方危機四伏，但是能跟她在一起，感覺真好。', '', 66384),
(289989, 'zhTW', '', '我是哈嘉爾，是一位長老和前任根莖守望者。我來這裡是為了見證你在挑戰中展現的實力，並向其他人回報你是否成功。', 66384),
(289988, 'zhTW', '', '如果你真的聽見了女神的歌聲，那你在試煉中應該就沒什麼問題了。或許她也像呼喚了歐薇娜那樣，呼喚了你。', 66384),
(289987, 'zhTW', '', '回音之穴保存了我族人的回憶和歷史。如果你平安通過挑戰，就會學到很多東西。', 66384),
(289984, 'zhTW', '歐薇娜去和她的長老談了。$n，你準備好了就告訴我吧。', '', 66384),
(289980, 'zhTW', '議會召開會議，針對歐薇娜可能犯下的罪行審判她。等你準備好了，我們就去找她。', '', 66384),
(289946, 'zhTW', '這太可怕了…晴風村與之相比根本不算什麼。', '', 66384),
(289944, 'zhTW', '', '我們會抹除太陽之井的光輝！', 66384),
(289940, 'zhTW', '聖光會提供喘息之機！但你必須堅持下去！', '', 66384),
(289936, 'zhTW', '', '別遠離聖光，否則虛無會吞噬你。', 66384),
(289935, 'zhTW', '', '在毫無保護的情況下深入虛無是很危險的。', 66384),
(289934, 'zhTW', '', '聖光帶你回到我們身邊。小心別在虛無中迷失方向了。', 66384),
(289933, 'zhTW', '', '你們珍貴的文物現在是薩拉塔斯的了！', 66384),
(289932, 'zhTW', '如果你一定要去，你會需要蘇卡的協助。你對他的看法無法改變這個事實。', '', 66384),
(289922, 'zhTW', '銀月城必須知道這一切。', '', 66384),
(289919, 'zhTW', '魯亞是夏達希爾的根莖守望者。\n\n因為我最近才承擔起埃達希爾的根莖守望者職務，所以他一直在向我傳授知識。', '', 66384),
(289916, 'zhTW', '根莖守望者負責照顧和看管世界之樹的樹根。我是埃達希爾的根莖守望者，正因如此，我其實才剛上任不久。\n\n我們會照顧樹根，維持它們的健康。任何害蟲和想要傷害偉大樹根的人都會被我們驅離。', '', 66384),
(289912, 'zhTW', '謝謝你幫忙找到孩子們。但光是這樣還不足以讓你在我們的領土暢行無阻。\n\n與外界建立聯繫有違我們的傳統。歐薇娜不只洩露我們哈拉尼爾的存在，甚至連哈朗達也被曝光了。\n\n歐薇娜必須為她的罪行接受懲罰。你也一樣。', '', 66384),
(289911, 'zhTW', '', '我很想幫歐薇娜，但她一定不想做她不得不做的事。', 66384),
(289910, 'zhTW', '我不記得上次我被像這樣束縛是什麼時候。而且還以這麼新奇的方式！你覺得我們現在應該如何稱呼這種材料？光芽？\n\n<戴西蒙斯張口大笑，然後停了下來。他從頭到腳打量著你。>\n\n現在想來，這跟你的光鑄沒有什麼不同。我會高興地仔細審視你露出的背部的所有細節，也許有一天會輪到我來進行拷問。', '', 66384),
(289901, 'zhTW', '', '哈朗達位在地底深處。上面樹根虯結的地方是育所，那是與女神艾恩哈拉有關的聖地。\n\n下面則是哈拉希爾，壁畫匠人的村莊。我們在這裡停一下。離開了這麼久，我的眼睛和內心都想看看我的家鄉。', 66384),
(289900, 'zhTW', '我可以理解他們為什麼這麼有防衛心…這是多麼原始的美景啊。', '', 66384),
(289896, 'zhTW', '謝謝你，$n。少了你的幫忙我肯定沒辦法活下來。', '', 66384),
(289895, 'zhTW', '那怪物…根本就是夢魘裡跑出來的東西。阿瑪拉克說它很古老，而且帶著它殺死的所有蘇卡的精華。\n\n我們真的能打敗它嗎？', '', 66384),
(289887, 'zhTW', '無論結果如何，感謝你的幫忙，$n。若最糟的情況發生，請幫我轉告奇雅。', '', 66384),
(289886, 'zhTW', '我們面臨生死關頭。恩萊亞不是順利完成儀式，就是永遠墜入瘋狂。', '', 66384),
(289884, 'zhTW', '我都不知道風行者女士自己有個黑暗那魯。這真是非常有趣…', '', 66384),
(289880, 'zhTW', '', '讓船長休個人生長假吧…', 66384),
(289876, 'zhTW', '現在對恩萊亞來說非常危險。如果他沒辦法完成儀式，斷開和艾恩哈拉的連結，他就會被裂隙的瘋狂吞沒。\n\n還好他有你在身邊陪著他。這並非蘇卡的作風，我們只會給建議而不會直接插手。', '', 66384),
(289873, 'zhTW', '$c，你懂了嗎？邪教徒焚燒光木是因為畏懼它的力量。', '', 66384),
(289871, 'zhTW', '你、還有你，把剩下的弩砲箭帶去祭壇那裡。', '', 66384),
(289865, 'zhTW', '', '聖騎士先生，拜託救救我的貓咪！', 66384),
(289858, 'zhTW', '我必須完成這場儀式，切斷與女神之間的聯繫…否則祂殘破的歌聲將使我陷入瘋狂、迎來死亡，或遭受更可怕的命運。', '', 66384),
(289848, 'zhTW', '', '符石…我們可以抵擋這些植物，但這些怪物…就沒辦法了！', 66384),
(289846, 'zhTW', '', '與外界接觸違背了哈拉尼爾的傳統。我不認為我們會受到熱烈歡迎，不過光綻的威脅並非源自於地表世界。\n\n該是我的族人參戰的時候了。說服他們會是極具挑戰的任務，前提是他們沒一見面就殺了我們。', 66384),
(289845, 'zhTW', '', '回家和碰觸哈朗達根部的感覺真好。我已經離開太久了。', 66384),
(289843, 'zhTW', '大博學者洛摩斯要求我到哈朗達與你和歐薇娜會合。藉由遠行者遊俠的能力，我能夠察覺光綻。\n\n歐薇娜懷疑感染可能源自於她的家鄉，而我會陪你們找到源頭。', '', 66384),
(289841, 'zhTW', '我是銀月城的遊俠將軍，赫杜倫‧亮翼。我帶領著遠行者，他們是能力出眾的遊俠，在艾澤拉斯無人能出其右，甚至在其他地方也無人能及。', '', 66384),
(289840, 'zhTW', '這是千載難逢的機會，居然能見到哈拉尼爾的故鄉。他們一直行事隱密，就連關於哈朗達的低語都不會透過世界之樹的樹根傳來我們這裡。', '', 66384),
(289836, 'zhTW', '<阿拉特一臉苦相。>\n\n現在不行，$n。我才剛剛找到她。\n\n我會告訴她。一定會。只是，需要等到我們到安全的地方。等到情緒變得沒那麼激動。\n\n我最不想看到她對我父親大發雷霆。\n\n所以，拜託了，$n，先別說出去。等到時機恰當，我會自己告訴我母親。\n\n現在，我們有一場仗要打。', '', 66384),
(289834, 'zhTW', '她活著！她還活著！\n\n我打從心底知道她還活著，去了某個地方狩獵…就像以前一樣。\n\n<阿拉特露出有點哀傷的微笑。>\n\n不過，這次我們也在這裡。這次我們共進退。', '', 66384),
(289832, 'zhTW', '<阿拉特面露猙獰。>\n\n我的內心感到一股壓力，心中出現前所未知的恐懼…', '', 66384),
(289815, 'zhTW', '前方有麻煩了！保持警戒！', '', 66384),
(289804, 'zhTW', '<這具保衛者的屍體遭到鳥喙和利爪的蹂躪。在你檢查傷口時，一條植物觸手從屍體內部萌發。>', '<這具保衛者的屍體遭到鳥喙和利爪的蹂躪。在你檢查傷口時，一條植物觸手從屍體內部捲出。>', 66384),
(289780, 'zhTW', '我這裡已經分身乏術，急需你的援手，拜託了。\n\n我在艾恩裂隙逗留太久，殘破的歌聲已經無所不在。\n\n<年輕的哈拉尼爾咳了一聲。>\n\n那聲音正緩慢侵蝕我的性命，也快把我逼瘋了。我不知道哪一個會先發生。', '', 66384),
(289779, 'zhTW', '怪物！牠們是因為光綻誕生的！', '怪物！牠們是因為光綻誕生的！', 66384),
(289778, 'zhTW', '', '暗影因怯懦者的罪行而綿延伸長…', 66384),
(289775, 'zhTW', '你休想再靠近了！', '你休想再靠近了！', 66384),
(289765, 'zhTW', '艾恩哈拉之根啊！你是誰？', '', 66384),
(289759, 'zhTW', '你來自哪裡？我有生以來，從未見過像你一樣的生物！', '', 66384),
(289757, 'zhTW', '', '跟著蹤跡走。我們應該能找到答案。', 66384),
(289743, 'zhTW', '', '入侵者，你怎麼來到這裡的？嚴禁外來者進入哈朗達！', 66384),
(289735, 'zhTW', '', '誰…你是什麼東西？我警告你，退後！', 66384),
(289729, 'zhTW', '這個地方…我們彷彿回到了過去。', '', 66384),
(289725, 'zhTW', '我必須找到我的哥哥。我知道他還活著！', '我必須找到我的哥哥。我知道他還活著！', 66384),
(289718, 'zhTW', '', '喂！在這裡！', 66384),
(289710, 'zhTW', '我向祖先發誓，要是你不趕快離開，我會直接把你扛走。', '', 66384),
(289708, 'zhTW', '哈！你小時候我也常常這樣說！', '', 66384),
(289705, 'zhTW', '', '那是大主教的太太嗎？我是說女朋友。我還以為她長得更高呢。她體內真的有黑暗那魯嗎？', 66384),
(289704, 'zhTW', '', '你不是聖光先鋒吧。雖然我不介意你來救我就是了。跟你一起的那位女士是誰？', 66384),
(289703, 'zhTW', '', '喔不！別又來一道傳送門！', 66384),
(289700, 'zhTW', '', '我的虛無行者對我低語，訴說虛無風暴的事。其中迴旋著瘋狂與暴力。\n\n我很想利用它來試試自己的能耐。', 66384),
(289698, 'zhTW', '阿拉特，別管它。去找艾蘭里亞。挽救這個任務現在是我的責任了。', '', 66384),
(289694, 'zhTW', '', '攻擊減緩了。做得好！', 66384),
(289693, 'zhTW', '你無法逃離…聖光。', '', 66384),
(289691, 'zhTW', '聖光會解決你！', '', 66384),
(289689, 'zhTW', '', '聖光存續…', 66384),
(289686, 'zhTW', '', '聖光會制裁一切！', 66384),
(289683, 'zhTW', '我滋養了…大、大地。', '', 66384),
(289680, 'zhTW', '這麼多…聖光！', '', 66384),
(289666, 'zhTW', '', '那些商人要不是在說謊，就是不知道自己已經受到光綻的感染，現在他們開始在村莊各處散播光綻了。\n\n我們必須在感染擴大之前，阻止這場光綻爆發！', 66384),
(289655, 'zhTW', '出發！願聖光祝福你！', '', 66384),
(289653, 'zhTW', '', '恭喜你成功通過試煉，$n。我的族人行事隱密，但是很高興能與你分享我們的歷史，朋友。', 66384),
(289594, 'zhTW', '', '真美好的一天，不是嗎？', 66384),
(289593, 'zhTW', '最近的光綻離村子很遠。那些植物是怎麼一路長到這裡的？', '', 66384),
(289592, 'zhTW', '你有空的話去找阿拉特吧。他就在營地的另一端治療傷者。', '', 66384),
(289591, 'zhTW', '或許光綻的爆發增長與太陽之井的強化有關。我想我是對的…光綻或許可以用來協助聖光先鋒。', '', 66384),
(289590, 'zhTW', '好幾年前，在太陽之井恢復之後，光綻就出現了。不過它從來沒有像這樣在城市附近生長。', '', 66384),
(289581, 'zhTW', '這裡發生了什麼事？', '', 66384),
(289580, 'zhTW', '', '陸行鷹…暴走了…', 66384),
(289579, 'zhTW', '普通的占測方法在虛無風暴裡效果不彰。我製造了這個特殊的平台，能夠偵測我們面對的威脅。', '', 66384),
(289576, 'zhTW', '我們被包圍了！我們需要重新檢視戰況。奧姆里克！$n可以協助你。', '', 66384),
(289567, 'zhTW', '這樣就對了…別讓他跑遠了！', '', 66384),
(289566, 'zhTW', '那魯殞落了！所有力量…都給了薩拉塔斯…我卻落得一場空！', '', 66384),
(289565, 'zhTW', '', '被感染的魯坦尼讓光綻現象擴散開來了！艾歐卡在哪？', 66384),
(289556, 'zhTW', '', '薩哈達爾，完成你的任務，再回到虛無之尖。你就能獲得當初說好的力量。', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(289552, 'zhTW', '小事一件。', '', 66384),
(289551, 'zhTW', '牠們很快就不會再惹麻煩了。', '', 66384),
(289550, 'zhTW', '', '謝謝你。那些陸行鷹真可怕！', 66384),
(289549, 'zhTW', '', '$n，你可以幫我看看聖光先鋒指揮官的狀況嗎？我必須向將軍說明太陽之井為什麼不能陷落。', 66384),
(289547, 'zhTW', '', '$n，你要一起去嗎？隨時歡迎你加入。', 66384),
(289414, 'zhTW', '我可憐的小貓剛才傷得很重！謝謝你。', '', 66384),
(289409, 'zhTW', '小傢伙，聖光會治療那些傷口。', '', 66384),
(289404, 'zhTW', '老頭，羅亞幾十年前就不再給我們恩寵了。沒了祂們，我們反而過得更好。', '', 66384),
(289403, 'zhTW', '', '他們都因為恐懼而發瘋了！', 66384),
(289402, 'zhTW', '<洛斯拉賽恩沉下臉。>\n\n所有獸人都是嗜血的狂戰士嗎？所有熊貓人都是醉酒的武僧嗎？所有精靈都是傲慢的勢利鬼嗎？\n\n我們的選擇造就了自己，而不是出身。這個道理適用於你們凡人，難道就不適用於我們納斯雷茲姆嗎？\n\n我已經拋下我的過去。我拒絕說謊、變形或背叛。那不是聖光之道。\n\n聖光讓我徹底改邪歸正。我在它的光輝下煥然一新，成為聖光先鋒的士兵。', '', 66384),
(289399, 'zhTW', '', '那個懦夫…我們由衷感謝你。', 66384),
(289398, 'zhTW', '', '黃昏…在召喚我…', 66384),
(289397, 'zhTW', '我們必須馬上摧毀那道屏障！', '', 66384),
(289393, 'zhTW', '大約在我們刃多雷被流放的時候，艾蘭里亞‧風行者終於回到銀月城。她花了無數歲月，踏遍許多界域，對抗惡魔，並希望沐浴在太陽之井的溫暖中。\n\n不過，她在旅途中吸收了黑暗那魯「路拉」的精華。這使她經歷了與刃多雷大同小異的轉化。她成為了一種虛無生物。\n\n聖光與虛無彼此密不可分。\n\n當她靠近太陽之井時，其中的聖光與她的虛無劇烈交鋒。黑暗生物隨即現身。如果我們最偉大的英雄當時不在現場，太陽之井可能早就徹底化為虛無。\n\n因此，許多人要我們永遠被放逐。因此，我們必須小心再小心。', '', 66384),
(289391, 'zhTW', '快！把這則消息傳給薩拉塔斯！', '', 66384),
(289388, 'zhTW', '', '我還沒看過光綻。但裂隙會永遠保護我們。', 66384),
(289381, 'zhTW', '在下是吉姆，來自哈拉諾。', '', 66384),
(289379, 'zhTW', '虛無之尖十分堅固，不過凡是人造建物，都能人為拆除。\n\n它當然也不例外。', '', 66384),
(289377, 'zhTW', '', '你知道的，今天一開始不怎麼順利，最後的結果卻相當美好。再次感謝你！', 66384),
(289375, 'zhTW', '別這麼誇張。你還活著，不是嗎？', '', 66384),
(289374, 'zhTW', '我可能會死在外面，老頭。', '', 66384),
(289372, 'zhTW', '所有魯坦尼都在光明中綻放。只有蘑菇人會在黑暗中生長。', '', 66384),
(289371, 'zhTW', '', '該來給他好看了！', 66384),
(289369, 'zhTW', '', '就是那個大塊頭把我帶到這來的。', 66384),
(289347, 'zhTW', '為什麼陌生人要來打擾在下？', '', 66384),
(289330, 'zhTW', '或許吧。不過那就不有趣了。別再發牢騷了。', '', 66384),
(289329, 'zhTW', '如果你幫我鬆綁，事情會容易很多。', '', 66384),
(289328, 'zhTW', '我…必須回去，向他道謝。我誤會了很多事。', '', 66384),
(289327, 'zhTW', '今天不是你的殞命之日！', '', 66384),
(289326, 'zhTW', '聖光會保護你！', '', 66384),
(289319, 'zhTW', '', '我的聖光啊，真的是你！這、真是、太、讚、啦！', 66384),
(289318, 'zhTW', '', '$n，你辦到了。而且還成功救出了這位軍官。', 66384),
(289317, 'zhTW', '但我必須導正這一切。暮光之刃會為我妹妹的死付出代價！', '', 66384),
(289315, 'zhTW', '<梅拉緊握她的劍，用力到指節都已經發白。>\n\n我不會讓這個地方再奪走我任何一個同伴。', '<梅拉緊握她的劍，用力到指節都已經發白。>\n\n我不會讓這個地方再奪走我任何一個同伴。', 66384),
(289314, 'zhTW', '<賽德拉斯向你露出諷刺的微笑，然後一臉猙獰地抓緊自己的身側。>\n\n從沒想過我會為另一個風行者效力。一切似乎就跟上次一樣順利。', '', 66384),
(289313, 'zhTW', '<暗幽谷女士怒視著洛斯拉賽恩。>\n\n那個混蛋運氣很好，艾蘭里亞在這裡。等到事情辦完，他會馬上為西爾朗的遭遇付出代價。', '<暗幽谷女士怒視著洛斯拉賽恩。>\n\n那個混蛋運氣很好，艾蘭里亞在這裡。等到事情辦完，他會馬上為西爾朗的遭遇付出代價。', 66384),
(289312, 'zhTW', '兩個人都毫髮無傷，是嗎？\n\n<他慢慢點頭。>\n\n非常好，$n。也許那個男孩學到了這堂課的第二部分。\n\n還保住了小命。', '', 66384),
(289309, 'zhTW', '等等！回來，你這個魯莽的小子！', '', 66384),
(289307, 'zhTW', '<阿拉特用繃帶蓋住賽德拉斯胸口的猙獰傷口。>\n\n要是我們晚一分鐘到，他就沒命了。', '', 66384),
(289306, 'zhTW', '嗯。我沒料到一個外來者居然能這麼快就學會。\n\n我一定是個好老師。\n\n<他的嘴角幾乎揚起一絲笑意，向你微微頷首，表示讚賞。>', '', 66384),
(289305, 'zhTW', '一個總是很飢渴的多曼納爾。別誤會我，朋友，飢渴是賽維朗的權利。不過，想要品味獨一無二的珍饈，就需要有一顆心。但賽維朗單純只是一個無底洞。老實說，我認為特蒙諾斯留著他只是為了激怒托倫提亞。她無法忍受一個無腦的傢伙地位居然比她高。', '', 66384),
(289303, 'zhTW', '親愛的托倫提亞，多曼納爾的悲劇人物。你知道嗎？她曾經試圖將披肩佔為己有。特蒙諾斯覺得她的舉動非常有趣，於是放她一馬，還讓她成為他的副官。托倫提亞必須永遠看守她因實力不足而無法擁有的東西。現在，看看她的地盤。塞滿嗜血野獸和弱小虛無生物的地穴，輕易就會消失。但她卻還是緊抓不放，就像垂死的凡人對生命緊抓不放。', '', 66384),
(289300, 'zhTW', '聞到了嗎？朧暗堡壘屍橫遍野的美味惡臭。以我的品味來看，有點不夠精緻，不過有一種暴戾的魅力。', '', 66384),
(289299, 'zhTW', '我…沒看到他們。\n\n聽著，有人攻擊我們。他們是從祖阿曼的方向來的。\n\n如果不是阿曼尼食人妖，還會是誰？\n\n對吧？\n\n<他看向別處。>', '', 66384),
(289295, 'zhTW', '蕾妮亞死了。\n\n<他被綁起來的手用力握緊。>\n\n他們就像黑夜裡的鬼魅…\n\n那是阿曼尼食人妖，我很清楚。\n\n攻擊很隨機。所以，何不再來一次？任何阿曼尼食人妖都行。\n\n他們何不再來一次？', '', 66384),
(289293, 'zhTW', '死了好多人…這是暮光之刃做的？', '', 66384),
(289290, 'zhTW', '', '哈囉？有人在嗎？快來幫我！', 66384),
(289289, 'zhTW', '', '$n，快！我撐開裂隙，你跳過去救她。', 66384),
(289287, 'zhTW', '我們把穿山甲脂肪製成的油跟龍鷹巢的灰燼混在一起，用來密封光木。這就是處理光木的秘方。\n\n如果沒對聖光進行保留處理，武器很快就會燒掉或喪失聖光。在對付暮光之刃時，黯淡的光木武器跟普通刀刃毫無差異。', '', 66384),
(289286, 'zhTW', '還剩最後一個試煉。哈嘉爾在前面等你。願艾恩哈拉與你同在，$n。', '', 66384),
(289285, 'zhTW', '哈。利用羅亞的魔法來保留聖光…真聰明。', '', 66384),
(289283, 'zhTW', '', '自從上次分別後，我踏上遙遠的旅程，同時傾聽著女神的聲音。地表上有許多事物需要學習。\n\n我還不清楚她為什麼要指引我來這裡。不過…能再次見到你真好，$p。', 66384),
(289281, 'zhTW', '', '我是哈拉尼爾的歐薇娜。我們一族很少會遠離家園，但世界之歌向我傾訴。我會完成我的女神要求我做的事，不論要我去哪裡。', 66384),
(289275, 'zhTW', '真是精采的鬧劇。相信所有信仰聖光的傢伙都擁護團結和沉著是我錯了嗎？太美味了。這實在太有趣了。', '', 66384),
(289273, 'zhTW', '希望只有我們的世界會被虛無的飢渴吞噬是件蠢事嗎？\n\n看看我們四周…太陽之井的聖騎士，銀月城的防衛者，不過也有其他人。穿著我不認識的衣服的外界者。\n\n我們要如何擊敗像虛無這樣飢渴又不挑食的敵人呢？', '', 66384),
(289272, 'zhTW', '這個地方是罪惡的淵藪。', '', 66384),
(289271, 'zhTW', '', '備好武器，$p。這個世界的唯一語言是暴力，我們必須做好以暴制暴的準備。', 66384),
(289270, 'zhTW', '這是因為太過好奇，還是因為你起了疑心呢？你讓我受傷了，朋友。我一直是毫無保留的，就像從傷口流出的鮮血。\n\n掠食披肩人人都想要，卻不是人人都能得到。只有登上宇宙之梯的人，才能從薩拉塔斯那裡得到，梯子的每一階都是由他們獵物的骸骨構成。\n\n唉，那是一件麻煩的禮物。力量招致力量，所以它的擁有者必須處處提防，隨時等著獠牙刺入他們的頸部。也許這就是為什麼薩拉塔斯會送出它。還有其他更好的方式讓她的僕人保持敏銳和執著嗎？', '', 66384),
(289268, 'zhTW', '以如此稀少的兵力入侵薩拉塔斯的大本營。該說是有勇無謀，還是自尋死路呢？', '', 66384),
(289267, 'zhTW', '不要被表面上的客套給騙了。這座「宅邸」肯定和這裡的其他地方一樣汙穢不堪。', '', 66384),
(289266, 'zhTW', '看看周圍的那些尖塔和建築物吧。這些不是人工建造，都是形塑而成的。虛無魔法塑造了所有土石。\n\n多曼納爾掌控虛無的能力真是非常可觀。我們可以從他們身上學到許多知識。', '', 66384),
(289260, 'zhTW', '純粹的秘法…這應該不會太難。', '', 66384),
(289259, 'zhTW', '<小嗶抬頭盯著你，張大眼睛，然後發出介於嗶嗶聲和叭叭聲之間的怪聲。>', '<小嗶抬頭盯著你，張大眼睛，然後發出介於嗶嗶聲和叭叭聲之間的怪聲。>', 66384),
(289255, 'zhTW', '', '博學者晨焰微微一笑，嚐了一口酒。', 66384),
(289253, 'zhTW', '記住了，你的頭上也有賞金。', '', 66384),
(289251, 'zhTW', '', '聽到殺人為生的賞金獵人義正詞嚴，還真有趣。', 66384),
(289250, 'zhTW', '我是在保護兇殺路。那本應是你們該做的事，而不是說要保護銀月城，卻把我們排除在外。', '', 66384),
(289248, 'zhTW', '', '當然順利。阿拉迪斯不再是我的肉中刺，而兇殺路牽涉其中，也讓你很便宜地得到工作。', 66384),
(289247, 'zhTW', '這些道路必須保持安全。這個傀儡能提供必要的威嚇力。', '', 66384),
(289245, 'zhTW', '', '太陽之井在上，你真的必須讓那東西通過這裡嗎？\n\n看看牠們！羽毛凌亂，還嚇破了膽！你上次巡邏後，我花了好幾個小時才讓牠們平靜下來。', 66384),
(289244, 'zhTW', '我們會支持這場戰爭中正義的一方！', '', 66384),
(289242, 'zhTW', '', '聖光啊…滾開，你這野獸！', 66384),
(289241, 'zhTW', '', '血跡還很新…等等，$n。你聽見了嗎？', 66384),
(289238, 'zhTW', '有什麼好說，你的光鑄德萊尼朋友給予的評價非常貼切，我們多曼納爾不過是邪惡與黑暗的產物！\n\n沒錯，我們滿腦子想的就是吞噬從你的凡心產生的每一滴負面情緒，那對我們是無上的美味。\n\n我們的邪惡心靈根本無力建造精緻的建築，照料美麗的花園，或訴說我們去過的遙遠世界的故事來自娛娛人。\n\n<戴西蒙斯靠向前，一臉高興地看著你的武器。>\n\n以及那裡的居民製作的精美工藝品。\n\n不不。我們只渴望帶領薩拉塔斯的吞噬宿主，以她的名字殺死勇敢的英雄。\n\n<戴西蒙斯打量著你，露出貪婪的笑容。>\n\n我們怎麼可能拒絕如此美味的大餐呢？', '', 66384),
(289235, 'zhTW', '聖光先鋒已經分身乏術。沒辦法再派出任何士兵。\n\n圖拉揚必須留下來，繼續帶領我們的部隊。幸好，我執行過不少致命的精英任務。\n\n我們不會失敗的。', '', 66384),
(289234, 'zhTW', '', '博學者晨焰露出微笑。', 66384),
(289233, 'zhTW', '我非常樂意響應洛索瑪的號召，參加這個進攻虛無風暴的任務，直擊困擾聖光先鋒已久的黑暗中樞。\n\n我們會突破它，替我們的軍隊解圍。\n\n而且…\n\n<阿拉特移開視線。>\n\n而且我已經很久沒有接到我母親的消息。我的…直覺告訴我，如果想要找到艾蘭里亞，就必須去那裡，向薩拉塔斯開戰。', '', 66384),
(289213, 'zhTW', '哪裡順利了？我的一個朋友死了。', '', 66384),
(289212, 'zhTW', '', '很高興這個小狀況能夠順利解決。', 66384),
(289211, 'zhTW', '', '阿拉迪斯一事的後續發展令人遺憾。', 66384),
(289209, 'zhTW', '', '這個屍體被吃掉一半，被食腐者撕成碎片。', 66384),
(289197, 'zhTW', '', '這是聖光先鋒的士兵。肯定是從軍床上被拖走，然後在峽谷這裡被吃掉的。', 66384),
(289190, 'zhTW', '', '到劍刃地穴找我們。', 66384),
(289183, 'zhTW', '歡迎來到育所。', '', 66384),
(289179, 'zhTW', '那個男孩把跟我們無關的殺戮怪罪到我們頭上。\n\n我不確定他妹妹是不是真的被阿曼尼人殺害。就算是真的，那也不是我們這裡的人做的。\n\n如果他現在看不清這點，也許他總有一天會明白。在他悲痛萬分的時候，給他一個機會，我們也沒有什麼損失。', '', 66384),
(289178, 'zhTW', '裝上刀刃，$n。穩穩拿好，孩子。', '', 66384),
(289176, 'zhTW', '現在把它磨平，孩子。別再抱怨，別讓$n分心。', '', 66384),
(289171, 'zhTW', '什麼？我還被綁著！我是要怎麼幫忙？', '', 66384),
(289163, 'zhTW', '愚蠢的$r！你失心瘋了嗎？那傢伙是一隻怪物！你居然幫助它逃避聖光的制裁！\n\n等到這個任務結束，我得跟你好好談談。', '', 66384),
(289162, 'zhTW', '在衛兵趕來前，回到兇殺路。$n，我們去領賞吧。', '', 66384),
(289160, 'zhTW', '賈厄斯，你該不會…', '賈厄斯，你該不會…', 66384),
(289159, 'zhTW', '他的頭上有賞金。我們一起平分我的賞金吧。', '', 66384),
(289158, 'zhTW', '對，他死了。他再也沒辦法綁架任何人了。', '', 66384),
(289157, 'zhTW', '那個博學者死了嗎？', '那個博學者死了嗎？', 66384),
(289153, 'zhTW', '我得去看看其他人的情況。等你從他的屍體拿到想要的東西後，就到樓上找我。', '', 66384),
(289152, 'zhTW', '噁…真希望能親自動手…不過，至少他死了。', '', 66384),
(289147, 'zhTW', '<阿拉特上氣不接下氣，大口呼吸。他的臉上全是汗水。>\n\n我不確定那會不會有用…謝謝你，$n。', '', 66384),
(289145, 'zhTW', '我們必須阻止他們！把散落在戰場上的神聖能量帶來給我，我應該能用來擊潰他們！快點！', '', 66384),
(289144, 'zhTW', '我會再把你開腸破肚，混帳！', '', 66384),
(289142, 'zhTW', '又見面了，$n。還有一隻新老鼠來取代你放走的那些。真是太體貼了。', '', 66384),
(289133, 'zhTW', '好…餓啊…', '好…餓啊…', 66384),
(289132, 'zhTW', '他要讓我當他的學徒。', '他要讓我當他的學徒。', 66384),
(289130, 'zhTW', '我…我想我還能走。', '我…我想我還能走。', 66384),
(289129, 'zhTW', '他說…他能讓我離開兇殺路…', '他說…他能讓我離開兇殺路…', 66384),
(289126, 'zhTW', '我還以為自己死定了…', '我還以為自己死定了…', 66384),
(289123, 'zhTW', '該死！快把所有人從那些水晶救出來。我會…薩維，快醒醒！', '', 66384),
(289122, 'zhTW', '這是什麼…', '', 66384),
(289121, 'zhTW', '來吧！別浪費時間了。', '', 66384),
(289119, 'zhTW', '來讓他後悔把那根法杖交給你吧。', '', 66384),
(289118, 'zhTW', '還沒有阿拉迪斯的蹤跡，不過，我聽到這個結界後面傳來一些聲音。保持警惕。', '', 66384),
(289116, 'zhTW', '我會把一切都告訴你。來吧，$n。我們得去割開某個人的喉嚨。', '', 66384),
(289115, 'zhTW', '明天，我將會津津有味地聽著阿拉迪斯的「有趣」故事。', '', 66384),
(289114, 'zhTW', '魔能是一種工具，能夠賦予強大又危險的力量。辛多雷都很清楚這點。', '', 66384),
(289113, 'zhTW', '把結界破除裝置放在祭壇上。我們會從這些物品抽取魔法，將其重新同調。', '', 66384),
(289112, 'zhTW', '殺死這個術士更是價值非凡。我們只是需要將那東西同調，破除他的結界。', '', 66384),
(289111, 'zhTW', '正常運作的結界破除裝置，是嗎？它們可價值不菲。', '', 66384),
(289110, 'zhTW', '', '$n，保持警戒。這些生物隨時可能發動攻擊。', 66384),
(289108, 'zhTW', '在這裡。跟先前的策略一樣：你找他們搭話，我趁機潛入。', '', 66384),
(289107, 'zhTW', '最後一個目標。這傢伙的耳目又更多了，不過我可以避開他們。繼續幫我引開工人。', '', 66384),
(289106, 'zhTW', '我們會從這裡開始。引開那裡的工人，讓我能夠順利潛入。', '', 66384),
(289101, 'zhTW', '', '流通於這片土地的虛無能量意味著無窮的力量。但代價是什麼？', 66384),
(289100, 'zhTW', '', '我把我們的發現交給奧姆里克。他也認為這個地方對我們所有人都是威脅。\n\n不過，我們必須承受虛無風暴對我們族人帶來的危險。\n\n這關係到艾澤拉斯的安危。', 66384),
(289086, 'zhTW', '哈！我們大殺四方，卻沒引來任何注意。看來他們很習慣這種混亂。 ', '', 66384),
(289085, 'zhTW', '所有生物似乎都沉浸於虛無之中，就連最小的蟲子也不例外。保持警戒。 ', '', 66384),
(289076, 'zhTW', '所以暗影也能轉為聖光。母親，我懂了。我們能利用他們的材料，抓住那個多曼納爾。 ', '', 66384),
(289075, 'zhTW', '', '聖光與暗影是一體兩面的。只要推力足夠，聖光也能變為暗影。', 66384),
(289071, 'zhTW', '', '向你們無用的井祈禱吧。薩拉塔斯依舊會把你們解決掉！', 66384),
(289070, 'zhTW', '我們鎖定的商店都專門服務銀月城的上層階級。這意味著他們會有好東西，而且我根本不在乎他們會不會損失慘重。', '', 66384),
(289068, 'zhTW', '賈厄斯瞪視著文件，然後朝地上吐口水。', '', 66384),
(289066, 'zhTW', '不清楚他的名字，但我的確認識這個混帳術士。幾個月來，他綁走了許多人。那些人都一去不回。', '', 66384),
(289064, 'zhTW', '如果她認為我有特殊的癖好，叫她拿出證據。', '', 66384),
(289062, 'zhTW', '', '阿拉特，$p！在儀式進行的時候保護我們！', 66384),
(289061, 'zhTW', '交給我們！我們會淨空大廳！', '', 66384),
(289060, 'zhTW', '', '你們是最後一批成功撤退的聖光先鋒成員。', 66384),
(289059, 'zhTW', '如果你想聊天，我們就去酒吧聊。進去的時候，別再製造更多麻煩。', '', 66384),
(289058, 'zhTW', '到此為止了。你在找我？好吧，你逮到我了。', '', 66384),
(289043, 'zhTW', '該死！聖光先鋒，撤退！', '', 66384),
(289041, 'zhTW', '', '圖拉揚！我們必須在太陽之井重整部隊，不然就來不及了！', 66384),
(289038, 'zhTW', '$p，快！我們需要你協助對抗那個巨獸！', '', 66384),
(289037, 'zhTW', '艾哲很有肚量，饒了那個精靈。\n\n拉卡妮卻視而不見，總是被憤怒蒙蔽，被過去的痛苦折磨。\n\n跟那個精靈很像。\n\n她看不出這是他學習的機會，改變的機會。\n\n對我們而言也是。', '', 66384),
(289036, 'zhTW', '', '艾哲早該殺了那個血精靈。\n\n這裡不歡迎陌生人。尤其是來製造麻煩的傢伙。', 66384),
(289035, 'zhTW', '', '帶著這些文件的複本。務必讓他知道我願意割捨一大筆金幣，讓情況得到補救。', 66384),
(289034, 'zhTW', '', '賈厄斯幫我做了一些…前置工作。我恰好知道他可能對阿拉迪斯特別感興趣。', 66384),
(289033, 'zhTW', '我們都很不安，不過暮光之刃…一直緊迫盯人。\n\n他們步步進逼，甚至到了只要我們踏出營地一步，就會被襲擊的地步，這種情況下根本沒辦法好好工作。\n\n我們暫時被困在這裡，束手無策。', '', 66384),
(289032, 'zhTW', '', '你也覺得很無聊，對嗎？\n\n我們被困在這裡，直到艾哲讓我們把貨物帶去村莊。\n\n在上一批人一去不返後，他只是試著確保我們的安全。不過，在我們的人等著這批武器時，我寧願對上暮光之刃，也不想站在這裡無所事事。', 66384),
(289030, 'zhTW', '母親…', '', 66384),
(289029, 'zhTW', '', '根據你手中的文件，我猜是阿拉迪斯唆使你的。過來這裡，我不會叫守衛。', 66384),
(289028, 'zhTW', '', '啊，你來了。極度顯眼的竊賊正在驅散我的結界。', 66384),
(289026, 'zhTW', '為了聖光！', '', 66384),
(289025, 'zhTW', '聖光先鋒！跟緊我！把這些入侵者趕回虛無去！', '', 66384),
(289022, 'zhTW', '最重要的是回收那些文件。別讓我失望。', '', 66384),
(289021, 'zhTW', '啊，她失去保護了。我的魔法原本無法觸及這裡，但現在情況不一樣了。', '', 66384),
(289020, 'zhTW', '', '感謝聖光！你取回了文物。', 66384),
(289018, 'zhTW', '', '我們不能放任這些以太族奪取我們神聖的文物！', 66384),
(289017, 'zhTW', '完全同意。阿拉特，堅守陣線。$p，奪下那些武器！', '', 66384),
(289016, 'zhTW', '太棒了。這個導體會帶你到下一個連結。請盡量不要失敗。', '', 66384),
(289015, 'zhTW', '結界破除裝置已經與守護這個導體的秘法魔法同調。使用它，就能打破結界。', '', 66384),
(289014, 'zhTW', '看來那就是我們的第一個目標。我們必須削弱風暴和敵方的戰力！出發！', '', 66384),
(289013, 'zhTW', '', '受薩拉塔斯的命令，稱為多曼納爾的強大生物指揮著吞噬之眾。其中一個監視著附近的奧核點，但我沒辦法靠近。', 66384),
(289012, 'zhTW', '', '很好，因為沒我幫忙你很可能會喪命。現在聽好了。', 66384),
(289009, 'zhTW', '阿拉特！你打亂陣型了。', '', 66384),
(289008, 'zhTW', '還是很可怕，不過我想結界破除裝置已經充能完畢。過來這裡。', '', 66384),
(289007, 'zhTW', '呃，你的姿勢太糟糕了。它在吸取時，請不要移動。否則會扭曲以太流動。', '', 66384),
(289006, 'zhTW', '為了避免被取代，她偽造黑函抹黑我。你應該看得出來，這很不公平。', '', 66384),
(289005, 'zhTW', '她並未針對辛多雷面臨的新挑戰做出改變。因此我才提出要取而代之。', '', 66384),
(289004, 'zhTW', '就像我說的，結界師是由博學者晨焰領導。她在戰爭後遞補上位，但一直以來都被認為不適任。', '', 66384),
(289003, 'zhTW', '帶著結界破除裝置，然後用我書房周圍的儲能裝置為它充能。相信你一定能完成這個超簡單的任務。', '', 66384),
(289002, 'zhTW', '', '$p，你不必為我的理智擔心。我和我的手下都很熟悉這種瘋狂。 ', 66384),
(289000, 'zhTW', '', '記得告訴他，你是薩維派去的。我可不想吃虧。', 66384),
(288995, 'zhTW', '我們不能加派更多兵力了！那些以太火砲讓我們動彈不得。', '', 66384),
(288987, 'zhTW', '儘管那個怪物威猛無比，但它卻十分痛苦。當我被憤怒吞噬時，也一樣在痛苦中掙扎。原來虛無和聖光是一樣的嗎？', '', 66384),
(288982, 'zhTW', '我的父親急著想消滅吞噬之眾，但一昧衝鋒也只是徒勞。我們必須解決掉那座高塔。', '', 66384),
(288981, 'zhTW', '聖光先鋒，列陣！守住這扇大門！', '', 66384),
(288979, 'zhTW', '$n，上坐騎。我們必須在聖光先鋒攻擊之前趕去大門那裡！', '', 66384),
(288977, 'zhTW', '', '該死，他強行突破了。', 66384),
(288976, 'zhTW', '', '還不錯，但是時候做個了斷了。', 66384),
(288975, 'zhTW', '你好啊，小不點。你是怎麼漂到這來的？', '', 66384),
(288964, 'zhTW', '圖拉揚忘了，要是我們損失一切，這場勝利也毫無意義。', '', 66384),
(288958, 'zhTW', '你把他們都救起來了！感謝聖光！', '', 66384),
(288957, 'zhTW', '他們把船擊沉了！把繩子丟給倖存者！', '', 66384),
(288956, 'zhTW', '掃蕩天空，盡力拯救所有倖存者！', '', 66384),
(288955, 'zhTW', '要是我們不保護船艦，就是在送船上的人走上死路！', '', 66384),
(288954, 'zhTW', '<西爾朗回頭看了你一眼，露出淡淡的微笑。>\n\n真抱歉。等到事情了結，我會在銀月城向你們兩個泡茶賠罪。', '', 66384),
(288953, 'zhTW', '阿拉特、$p！撤離的船艦受到攻擊了！', '', 66384),
(288951, 'zhTW', '讓聖光指引你。', '', 66384),
(288950, 'zhTW', '讓聖光治療你的傷口。', '', 66384),
(288949, 'zhTW', '聖光會消除你的痛苦。', '', 66384),
(288948, 'zhTW', '以聖光之名，願你不再受苦。', '', 66384),
(288947, 'zhTW', '', '在那，塔的基座。掌管者就在那裡。', 66384),
(288946, 'zhTW', '結束了，道路清空了。', '', 66384),
(288936, 'zhTW', '$p，快點。我們去幫倖存者清出一條路吧！', '', 66384),
(288931, 'zhTW', '不！我不會讓我的人民無人保護！', '', 66384),
(288930, 'zhTW', '我們必須趁還有機會的時候反擊！', '', 66384),
(288929, 'zhTW', '我們去找剩下的聖光先鋒吧。不能讓大主教失望。', '', 66384),
(288928, 'zhTW', '$n！這裡！', '', 66384),
(288926, 'zhTW', '大主教號召我們為榮耀而戰，至死方休！', '', 66384),
(288925, 'zhTW', '虛無的邪惡生物！準備好受死吧！', '', 66384),
(288924, 'zhTW', '弟兄們，讓你們的心靈之火熊熊燃燒！我們受到召喚來攻打虛無！', '', 66384),
(288923, 'zhTW', '薩拉塔斯！要是我能找到辦法摧毀那把該死的刀刃就好了！', '', 66384),
(288922, 'zhTW', '', '必須有人守住太陽之井！要是失守，一切都完了！', 66384),
(288921, 'zhTW', '$n，去找阿拉特！我會召集聖光先鋒，準備發動攻擊！', '', 66384),
(288920, 'zhTW', '我們的部隊四散潰逃。我們快被吞噬之眾擊垮了！', '', 66384),
(288918, 'zhTW', '', '就算有援軍的協助，我們也無法長久抵禦吞噬之眾的侵襲。$p，動作快。', 66384),
(288917, 'zhTW', '在我的聖光護佑下治療吧！我們會保護你的！', '', 66384),
(288912, 'zhTW', '', '特蒙諾斯，你現在開心了嗎？有膽就下來吧。', 66384),
(288910, 'zhTW', '', '$p，我看過你戰鬥。我知道你的能耐不只如此。', 66384),
(288905, 'zhTW', '', '在這。西爾朗太謙虛了。你可以告訴他是我說的。', 66384),
(288901, 'zhTW', '', '刃多雷，振作起來。你還沒有屈服。', 66384),
(288899, 'zhTW', '是、是誰？快滾開！', '是、是誰？快滾開！', 66384),
(288898, 'zhTW', '你說得對。我應該跟其他人待在一起。', '你說得對。我應該跟其他人待在一起。', 66384),
(288754, 'zhTW', '', '別賣關子了。博學者阿拉迪斯的情況如何？', 66384),
(288738, 'zhTW', '', '多咬了幾口…胃口真不錯！這是個好兆頭。', 66384),
(288685, 'zhTW', '我們必須充分把握這次機會，卡莉雅。', '', 66384),
(288684, 'zhTW', '在我們的研究中，謹慎永遠不會帶來進步！', '', 66384),
(288683, 'zhTW', '不只換了水，乾草也堆好了。又在獸欄度過平凡的一天。', '', 66384),
(288682, 'zhTW', '', '虛無風暴讓我們的內心蠢蠢欲動。這種時候更需要謹慎。', 66384),
(288672, 'zhTW', '', '動作快。我們得趁特蒙諾斯回到堡壘前取得披肩。', 66384),
(288671, 'zhTW', '借用我寵物的視野吧。我會告訴你該怎麼削弱風暴。', '', 66384),
(288655, 'zhTW', '聖光是我們對抗虛無最強力的武器。記住這點，否則就會屈服於腐化。 ', '', 66384),
(288654, 'zhTW', '年輕的阿拉特已經證明他有足夠資格了。我們並肩作戰，希望他的聖光能讓各位在暗影中穩住陣腳。 ', '', 66384),
(288649, 'zhTW', '', '薩拉塔斯和她的吞噬之眾攻擊了奎爾達納斯之島上的太陽之井。$p，聖光召喚你出手相助。', 66384),
(288626, 'zhTW', '', '拜託，$n！在麥崔恩造成更多破壞之前阻止他。', 66384),
(288621, 'zhTW', '成為進步的推手是最高的科學榮譽。我們不能現在放棄。', '', 66384),
(288413, 'zhTW', '吞噬…或被…', '', 66384),
(288412, 'zhTW', '無限…的…飢餓…', '', 66384),
(288410, 'zhTW', '不！我要殺了你！', '', 66384),
(288409, 'zhTW', '終於…解脫了…', '', 66384),
(288408, 'zhTW', '竟然有凡人！你的靈魂能讓我的創作大放異彩！', '', 66384),
(288401, 'zhTW', '謝謝，歐薇娜。這是莫大的榮幸，真的。謝謝你讓我…讓我們…進來。', '', 66384),
(288400, 'zhTW', '', '你的印記被繪製在數代以前的人留下的印記旁。你現在是哈朗達的一部分了。', 66384),
(288398, 'zhTW', '$c，要是你太粗心，不記得自己把夥伴丟在哪裡，別忘了我擁有幫你找回失物的本領。我還可以幫你照顧寵物。', '', 66384),
(288397, 'zhTW', '$c，要是你太粗心，不記得自己把夥伴丟在哪裡，別忘了我擁有幫你找回失物的本領。', '', 66384),
(288396, 'zhTW', '奎爾薩拉斯很龐大，但是我的陸行鷹對空域很熟悉。我們要帶你去哪裡呢？', '', 66384),
(288394, 'zhTW', '', '並非所有旅人都值得享有這般寧靜，但你看起來…還算可以。就當作是你走運了吧。', 66384),
(288393, 'zhTW', '', '並非所有旅人都值得享有這般寧靜，但你看起來有資格。你想的話就留下來吧。', 66384),
(288387, 'zhTW', '哈，來啊！這些我等等再嚐嚐。你還有什麼想讓我看的？', '', 66384),
(288386, 'zhTW', '', '我們花了無數世代，針對蘑菇鑽研香料和草藥的完美平衡。不過，小心一點，它可能不知不覺來到你身邊。', 66384),
(288385, 'zhTW', '呃，裡面放了什麼？有點辣，又不會太辣。', '', 66384),
(288384, 'zhTW', '嘿，有人喜歡火藥，有人喜歡腐蝕劑。有人則偏好老式的動能。', '', 66384),
(288383, 'zhTW', '', '這些是其中一些為我打造的第一批武器。我試了很多不同類型的武器，但爪類感覺最順手。', 66384),
(288362, 'zhTW', '阿瑪瑟說，有更多枯木食譜會用到毒素。我想她對有東西可以獵捕感到很興奮。每次我嘗試新東西，她都會興奮不已！\n\n<古舒眉開眼笑。>\n\n我的寰宇烹飪書有一個很好的開始！', '', 66384),
(288361, 'zhTW', '我嚐過一大堆贊達拉料理，但我還沒嚐過任何阿曼尼料理！', '', 66384),
(288360, 'zhTW', '哈！要是它能撐過她的食譜，那就什麼都難不倒它了。或許我會順道去拿點樣本，老追尋者！', '哈！要是它能撐過她的食譜，那就什麼都難不倒它了。或許我會順道去拿點樣本，老追尋者！', 66384),
(288359, 'zhTW', '你應該把它交給你的女兒。是叫阿瑪瑟，對吧？她叫營地的所有人嚐嚐新料理。', '', 66384),
(288358, 'zhTW', '帶殼者，我們的物品能承受長年的使用。或許我們重視的事物是一樣的。', '帶殼者，我們的物品能承受長年的使用。或許我們重視的事物是一樣的。', 66384),
(288357, 'zhTW', '嘿。這個鍋子…以它的古老程度而言，它跟我們一樣狀況良好！', '', 66384),
(288356, 'zhTW', '然後現在你要把它給我？你在打什麼主意，托爾托人？你到底為什麼要來這裡？', '然後現在你要把它給我？你在打什麼主意，托爾托人？你到底為什麼要來這裡？', 66384),
(288355, 'zhTW', '一個老舊鍋子？你寄了好幾封信給我，只是為了舊鍋子？', '一個老舊鍋子？你寄了好幾封信給我，只是為了舊鍋子？', 66384),
(288353, 'zhTW', '萊杉長老，我們在淺水區發現了一個枯木部族的老舊鍋子，我是來還給你的。', '', 66384),
(288352, 'zhTW', '一個那魯，被薩拉塔斯的部隊俘虜…我們必須做點什麼，$n。', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(288344, 'zhTW', '', '這個托爾托人不會死。\n\n<阿瑪瑟有點沮喪，但她笑得讓人不寒而慄。>\n\n想想看，要是我有他的胃，我就能嘗試多少致命料理！\n\n我會找到他的極限，這樣我們就能平等地共享一頓飯！', 66384),
(288338, 'zhTW', '', '我會研發一個食譜，幫助你感受到完整的效果。', 66384),
(288337, 'zhTW', '太神奇了！我會把這點記在我的烹飪書中。', '', 66384),
(288336, 'zhTW', '', '真有意思…它幾乎對你無效。那麼多的泡捲肉醬，應該足以讓我麻痺兩天。', 66384),
(288335, 'zhTW', '啊！我的手腳好刺痛！阿瑪瑟，那就是你說的麻痺感嗎？', '', 66384),
(288334, 'zhTW', '古舒一口咬下泡捲野豬肉。', '', 66384),
(288333, 'zhTW', '好，乾杯！', '', 66384),
(288332, 'zhTW', '', '看起來很不錯。你烹調得夠久了。', 66384),
(288331, 'zhTW', '啊，就是這股刺鼻的味道！', '', 66384),
(288330, 'zhTW', '', '現在把所有東西加入串燒。烹調一陣子，讓兩種毒混合在一起。', 66384),
(288329, 'zhTW', '', '我帶來一隻野豬供你屠宰。我們會抹上泡捲肉醬當作調味料。', 66384),
(288328, 'zhTW', '', '現在搗爛灼皮海藻。只使用葉子的前端部分。那裡含有最多毒液。', 66384),
(288327, 'zhTW', '', '先從鰻魚胃袋開始。擠壓胃袋，直到擠出裡面的汁液。', 66384),
(288321, 'zhTW', '這些材料蘊藏著許多魔力。走吧。我們還要去一個地方。', '', 66384),
(288318, 'zhTW', '你好，$c。你在找什麼東西嗎？', '', 66384),
(288306, 'zhTW', '這把劍裡面似乎有一些能量。我們回去兇殺路吧。', '', 66384),
(288302, 'zhTW', '', '我呼喚聖光的幫助，而你響應了我的祈禱。毫無疑問，是它的聖輝將你引導到這裡。', 66384),
(288300, 'zhTW', '', '你不是還有一個關於戰鬥的故事？', 66384),
(288299, 'zhTW', '我超愛那個故事！', '', 66384),
(288298, 'zhTW', '牛頭人就是這樣編出他們最精美的籃子。', '', 66384),
(288293, 'zhTW', '你好。你在找採礦的指示嗎？', '', 66384),
(288281, 'zhTW', '聖光與我們同在。薩拉塔斯將在這裡被阻止！', '', 66384),
(288276, 'zhTW', '', '我們祈求幫助，而太陽之井回應了。現在我們必須證明自己有相應的價值。', 66384),
(288231, 'zhTW', '偉南緊握著敵人的遺骸，引領盟友來到充滿魔法粉塵的洞穴。在那裡，遺骸結合成一個護符，平衡兼存於手中與心中。', '', 66384),
(288228, 'zhTW', '你展現出了極佳的工作效率！\n\n我們接近我的秘密地下事業了，那是一個隱藏的倉庫，裡面存放著我最大膽卻又最巧妙的設備！\n\n我正好有個點子，可以幫我們擺脫這個黏液威脅。\n\n首先！切除這些擋住入口的異象寄生物！進到裡面之後，你需要收集建造裝置所需的材料，利用裝置把這些黑血轟到連渣都不剩！！', '', 66384),
(288223, 'zhTW', '若沒人記取這個教訓，它很快就會被遺忘。為了製作一個紀念護符，偉南撿起了敵人的遺骸。', '', 66384),
(288222, 'zhTW', '殘破的野獸和偉南殞命的族人倒臥在一起。他們究竟是死於野獸利爪，還是死於自己之手？狂怒麻痺了他，直到故鄉的氣息把他從深淵拉出來。', '', 66384),
(288221, 'zhTW', '偉南找到了族人遇襲的源頭。於是，獵物變成了獵人，為了尋求真相來到一座寧靜的洞穴。', '', 66384),
(288220, 'zhTW', '雙方爆發大戰，尖牙利爪與藤蔓荊棘相互對抗…但戰鬥的狂熱差點讓他們陷入瘋狂。', '', 66384),
(288219, 'zhTW', '當哈拉尼爾第一次踏足這片土地時，沒有人歡迎他們，只有利齒和憤怒。野獸蓄意發動攻擊，卻不知是為了什麼。', '', 66384),
(288215, 'zhTW', '', '殺了他。結束這一切，艾哲。', 66384),
(288213, 'zhTW', '我們必須盡可能把人送到銀月城的安全處。$p，我需要你的幫忙。', '', 66384),
(288210, 'zhTW', '<露瑪站在一大堆飾品和寶物的旁邊。看來這就是她想讓你看的東西。\n\n露瑪喘著氣，給你一個大大的露齒笑容，她的眉毛表露出太陽般的笑意。\n\n她滿懷期望地看著你，似乎對自己感到非常驕傲。>', '<露瑪站在一大堆飾品和寶物的旁邊。看來這就是她想讓你看的東西。\n\n露瑪喘著氣，給你一個大大的露齒笑容，她的眉毛表露出太陽般的笑意。\n\n她滿懷期望地看著你，似乎對自己感到非常驕傲。>', 66384),
(288203, 'zhTW', '找到了應該有用的魔法項鍊。我們離開這裡吧。', '', 66384),
(288199, 'zhTW', '有了這個裝置，你就能在相對安全的環境下檢視戰況。', '', 66384),
(288197, 'zhTW', '', '麥崔恩永遠不會讓理論未經驗證。', 66384),
(288196, 'zhTW', '很高興再見到你，勇士。', '', 66384),
(288194, 'zhTW', '好了！我們準備按下按鈕了！退後！', '', 66384),
(288193, 'zhTW', '按下按鈕！', '按下按鈕！', 66384),
(288192, 'zhTW', '動手吧！', '動手吧！', 66384),
(288189, 'zhTW', '這樣不對。我們再試一次。', '', 66384),
(288187, 'zhTW', '看到你這個聞土異類協助解決掉那個蠻卒，我真是不敢相信！', '', 66384),
(288186, 'zhTW', '哪門子的博學者遇上大貓會逃跑？你這三流廢物…', '', 66384),
(288184, 'zhTW', '麗娜率領大軍對抗燃燒軍團。為什麼她的聖物會是像這樣的東西？', '', 66384),
(288183, 'zhTW', '瑪拉的英勇事蹟促成了白銀之手的成立。不過她的聖物是一本難民祈禱書。', '', 66384),
(288182, 'zhTW', '瑪銳德的武藝十分高超，但他的聖物卻是一顆冥想水晶。', '', 66384),
(288181, 'zhTW', '克洛姆保護了羅德隆的人民。但這個聖物是把鍛造錘，不是武器。', '', 66384),
(288180, 'zhTW', '烏瑟是白銀之手的第一位，也是最偉大的聖騎士。雖然沒有找到他的錘子，但找到他的治療包還真令人意外。', '', 66384),
(288172, 'zhTW', '洛斯拉賽恩，如果你想羞辱我的話，至少得再努力一點。', '', 66384),
(288135, 'zhTW', '想要升級你的護甲或武器嗎？我們有很多工匠可以幫你。', '', 66384),
(288134, 'zhTW', '比起蠻力行事，我更偏好運用智慧，祝你好運。', '', 66384),
(288133, 'zhTW', '就這一次，我贊成梅勒鐸說的。抱歉，不過我還是不打算幫忙。', '', 66384),
(288131, 'zhTW', '今天不會再更糟了…', '', 66384),
(288130, 'zhTW', '我真不敢相信…', '', 66384),
(288127, 'zhTW', '', '那些山中原生動物的後代非常稀少，我們也非常尊敬牠們。歡迎來到哈朗達，蒙特。我帶你去見見其他人。', 66384),
(288126, 'zhTW', '沒有刺針熊在附近亂晃了，對吧？', '', 66384),
(288125, 'zhTW', '去找歐薇娜吧！我暫時沒事了。這隻小動物很不錯。很不錯的、長滿刺針的、熊一樣的…小動物。', '', 66384),
(288124, 'zhTW', '謝天謝地！總算解脫了！謝謝幫忙。', '', 66384),
(288104, 'zhTW', '有鑑於歐薇娜在幽坑城幫了我們的忙，我就想說到她的家鄉拜訪她一下。\n\n不過，我似乎沒辦法通過前門。你或許以為我現在已經習慣了，才沒有。每次我試著掙脫的時候，這隻野獸就會低聲咆哮。\n\n所以我打算先動也不動，去看看歐薇娜有什麼辦法。', '', 66384),
(288101, 'zhTW', '嘿，夥計！我吊在這裡，希望能夠看到一個好心人。\n\n<加茲魯維笑得有點猙獰，可以看出他身體不適。>', '', 66384),
(288100, 'zhTW', '', '加茲魯維來我的家園拜訪了？他到這裡能不惹上麻煩還真教人意外。', 66384),
(288097, 'zhTW', '', '怎麼了？發生什麼事了嗎？', 66384),
(288075, 'zhTW', '其實不是我的。只是我大多數的時間都在這裡。\n\n亞肯提納是由從前的祈倫托法師建立。\n\n不過，在遠征德拉諾的艱難歲月中，我和洛薩之子會來到這裡，把它當成可以暫時回憶家鄉氛圍的地方。\n\n多年來，越來越多人受邀來到這裡，現在它作為魔法避難所，供老朋友和老兵聚會。', '', 66384),
(288073, 'zhTW', '啊，真高興見到你，$p。你對亞肯提納有什麼看法？', '', 66384),
(288072, 'zhTW', '阿拉特，老實說，我們一直想帶你來這裡。很高興終於有機會了。', '', 66384),
(288054, 'zhTW', '是暮光之刃。我沒料到他們會想辦法進到永歌森林。我不會讓他們就這麼逃掉的。\n\n他們會為他們的所作所為付出代價。', '', 66384),
(288053, 'zhTW', '你們這些盲目的蠢貨…', '', 66384),
(288052, 'zhTW', '銀月城有提供什麼協助嗎？沒有！', '', 66384),
(288051, 'zhTW', '', '我是…對的…？', 66384),
(288050, 'zhTW', '', '虛無拯救我們！', 66384),
(288014, 'zhTW', '這些托爾托人說的故事都又臭又長。我寧願他們跟我打一架。', '這些托爾托人說的故事都又臭又長。我寧願他們跟我打一架。', 66384),
(288013, 'zhTW', '你傳達故事的時候，怎麼可以只透過文字呢？你應該加入動作！', '你傳達故事的時候，怎麼可以只透過文字呢？你應該加入動作！', 66384),
(288012, 'zhTW', '你嚐過那個旅店老闆的酒了嗎？我感覺不到我的獠牙了。', '你嚐過那個旅店老闆的酒了嗎？我感覺不到我的獠牙了。', 66384),
(288011, 'zhTW', '$c，沒看到我在忙嗎？', '$c，沒看到我在忙嗎？', 66384),
(288010, 'zhTW', '以前從沒看過托爾托人。不知道他們為什麼想要了解我們？', '以前從沒看過托爾托人。不知道他們為什麼想要了解我們？', 66384),
(288009, 'zhTW', '克里凱仕要我告訴他一個故事，但他沒讓我說完。真是的，我都把劍架到他脖子上了！', '克里凱仕要我告訴他一個故事，但他沒讓我說完。真是的，我都把劍架到他脖子上了！', 66384),
(288007, 'zhTW', '如果你想聽故事，就必須準備好戰鬥。枯木部族可不是為了作秀才戰鬥的。', '如果你想聽故事，就必須準備好戰鬥。枯木部族可不是為了作秀才戰鬥的。', 66384),
(288006, 'zhTW', '需要什麼嗎？', '需要什麼嗎？', 66384),
(287985, 'zhTW', '', '如果你可以接受那個苦味，長在水裡的深根海藻可以讓你閉氣更輕鬆。', 66384),
(287981, 'zhTW', '斯特吉逃去安全的地方。', '斯特吉逃去安全的地方。', 66384),
(287980, 'zhTW', '斯特吉全身都是藍的，就像古舒一樣！不過小小的。她需要吃東西，拜託快去找她！', '', 66384),
(287954, 'zhTW', '', '你也做得很好。但別太急著打響自己的名聲。', 66384),
(287953, 'zhTW', '母親，你的確不負自己的名聲啊', '', 66384),
(287939, 'zhTW', '', '我們什麼問題也沒解決。這些魯坦尼發生了異變。我必須回到哈朗達展開調查。', 66384),
(287936, 'zhTW', '$n，去找奧姆里克。我會守在這裡。', '', 66384),
(287916, 'zhTW', '跟我們來！', '', 66384),
(287915, 'zhTW', '快！追上那條髒兮兮的狗！', '', 66384),
(287914, 'zhTW', '…日誌？！', '', 66384),
(287913, 'zhTW', '那是…', '', 66384),
(287912, 'zhTW', '要是我們能掌握一個實際的線索，而不是捕風捉影就好了…', '', 66384),
(287911, 'zhTW', '太優秀了。據我們所知，日誌就這麼長出腳跑掉了！', '', 66384),
(287902, 'zhTW', '能夠看到我父親最初的起點，真是讓人大開眼界，$p。\n\n他那時的樣子，正是我想成為的那種聖騎士。而不是他後來的樣子。\n\n你會幫我嗎？', '', 66384),
(287890, 'zhTW', '$p，我幾乎認不出他們所描述的，這個時期的圖拉揚。他聽起來像是一個我完全不認識的人。', '', 66384),
(287883, 'zhTW', '', '其他部族沒有響應我們的戰鼓。怎麼會這樣？', 66384),
(287874, 'zhTW', '我…我是訓練中的追尋者！我正在編纂一本食譜大全，這樣才能得到我的第一個卷軸。', '', 66384),
(287873, 'zhTW', '', '我們的…料理？為什麼？', 66384),
(287872, 'zhTW', '太好了。既然我們認識彼此了，追尋者古舒可以問關於你料理的事了。', '', 66384),
(287871, 'zhTW', '', '如果父親說你能留下，我們會讓你在這裡紮營。我會負責監視你。', 66384),
(287868, 'zhTW', '喔，讓人意想不到，年輕人。我們會耐心等待。', '', 66384),
(287867, 'zhTW', '', '$p，你的協助無疑是個祝福。我必須把這孩子送去安全的地方！', 66384),
(287866, 'zhTW', '', '不准動！', 66384),
(287865, 'zhTW', '去找枯木部族的萊杉長老。這之中一定有什麼誤會。', '', 66384),
(287864, 'zhTW', '', '信？我們的長老可沒有說要讓巨殼入侵者待在這裡。你們必須離開！', 66384),
(287863, 'zhTW', '朋友，不用這麼緊張。我們收到你們長老的來信，允許我們研究這裡的文物。', '', 66384),
(287858, 'zhTW', '萊杉長老暗自發笑。', '萊杉長老暗自發笑。', 66384),
(287857, 'zhTW', '', '骯髒的菜鳥！你會跟其他人一樣把血流乾。', 66384),
(287854, 'zhTW', '凡人救星竟然出現在這裡？看來一切還有希望。', '凡人救星竟然出現在這裡？看來一切還有希望。', 66384),
(287852, 'zhTW', '那個托爾托人可以暫時留下。對於我這麼頑固的人來說，這可是難得一見！', '那個托爾托人可以暫時留下。對於我這麼頑固的人來說，這可是難得一見！', 66384),
(287851, 'zhTW', '薩哈達爾，這就是你想要的嗎？', '薩哈達爾，這就是你想要的嗎？', 66384),
(287848, 'zhTW', '虛無會吞噬同族。我們什麼都不剩了。', '虛無會吞噬同族。我們什麼都不剩了。', 66384),
(287847, 'zhTW', '那個托爾托人是認真的嗎？他真的跑來這裡露面了？\n\n<萊杉長老開懷大笑。>\n\n他一直寄信過來！我也一直無視他。到最後，我要他想做什麼就做什麼，不要等待批准。但是他說他會繼續等下去！\n\n這樣你要我怎麼拒絕？我寄了一封「批准信」給他。我已經好幾年沒這麼做了！\n\n他贏得我的尊敬。追尋者本來就是為所欲為。不過，枯木部族還是會盯著那些托爾托人…就像我們對待所有踏上我們領土的訪客那樣。', '那個托爾托人是認真的嗎？他真的跑來這裡露面了？\n\n<萊杉長老開懷大笑。>\n\n他一直寄信過來！我也一直無視他。到最後，我要他想做什麼就做什麼，不要等待批准。但是他說他會繼續等下去！\n\n這樣你要我怎麼拒絕？我寄了一封「批准信」給他。我已經好幾年沒這麼做了！\n\n他贏得我的尊敬。追尋者本來就是為所欲為。不過，枯木部族還是會盯著那些托爾托人…就像我們對待所有踏上我們領土的訪客那樣。', 66384),
(287845, 'zhTW', '$c，需要幫忙嗎？', '$c，需要幫忙嗎？', 66384),
(287833, 'zhTW', '你想讓入侵者在阿塔阿曼作戰？', '', 66384),
(287831, 'zhTW', '', '我們需要戰士才能保護城市。詹，還有誰能夠幫助我們？', 66384),
(287826, 'zhTW', '', '我會跟聖匣守護者合作，因為他們更加深入敵陣。有你需要的東西嗎？', 66384),
(287808, 'zhTW', '非常好。還差一半就能取得披肩了。', '', 66384),
(287807, 'zhTW', '吞噬它。感受她的力量化為你自己的。', '', 66384),
(287701, 'zhTW', '', '讓我們進入祖阿曼！暮光正逼近邊境，我們不能坐以待斃！', 66384),
(287693, 'zhTW', '', '光綻殺死動植物後，接著又會重獲新生。這個惡劣的循環不能持續下去。', 66384),
(287692, 'zhTW', '', '看來要是沒人保護，就算是你的符石也無法阻止光綻蔓延。', 66384),
(287691, 'zhTW', '', '這些植物被迫生長，但我也不清楚是什麼原因。', 66384),
(287605, 'zhTW', '', '查娜陷入猶豫。', 66384),
(287604, 'zhTW', '', '我姪女？好吧，我會去。', 66384),
(287603, 'zhTW', '其實，那是你姪女的第一次狩獵。', '', 66384),
(287602, 'zhTW', '那是家族狩獵。而你是家人。', '', 66384),
(287601, 'zhTW', '', '你確定他們會歡迎我？', 66384),
(287600, 'zhTW', '下個月，我要在我的地盤舉辦一場狩獵活動。也許你可以加入我們？', '', 66384),
(287599, 'zhTW', '', '我很抱歉沒讓你有機會幫我。', 66384),
(287598, 'zhTW', '我很抱歉把她丟給你。', '', 66384),
(287597, 'zhTW', '', '現在我們要向火焰表達自己的悔恨。任何我們從未在她生前告訴她的事。', 66384),
(287596, 'zhTW', '', '他們從未相信我。', 66384),
(287595, 'zhTW', '你從沒告訴他們？', '', 66384),
(287594, 'zhTW', '', '部族的人依然愛戴她。', 66384),
(287593, 'zhTW', '為什麼我們要像這樣給她哀榮？', '', 66384),
(287592, 'zhTW', '', '只有善意的謊言。', 66384),
(287591, 'zhTW', '她…有留下遺言嗎？', '', 66384),
(287590, 'zhTW', '', '她生病了。我們都知道她會死，只是早晚的問題。', 66384),
(287589, 'zhTW', '她怎麼死的？', '', 66384),
(287588, 'zhTW', '', '因為我知道她影響不了你。', 66384),
(287587, 'zhTW', '因為你再也不用彌補我的錯誤？', '', 66384),
(287586, 'zhTW', '', '不。反而更糟了。不過，老實說，我很高興你擺脫了我們。', 66384),
(287585, 'zhTW', '在我離開後，她情況有好轉過嗎？', '', 66384),
(287584, 'zhTW', '其實，很不錯。我現在過得很好。', '', 66384),
(287583, 'zhTW', '', '你在樹林中過得如何？', 66384),
(287582, 'zhTW', '', '不過，我還是對救了你時留下的每一條疤痕感到驕傲。', 66384),
(287581, 'zhTW', '', '不知道。', 66384),
(287580, 'zhTW', '當你因為我的錯誤而被處罰時，你知道我有多內疚嗎？', '', 66384),
(287579, 'zhTW', '', '你是我的弟弟。我有責任要保護你。', 66384),
(287578, 'zhTW', '你也一樣。', '', 66384),
(287577, 'zhTW', '看來有些事永遠不會變。', '', 66384),
(287576, 'zhTW', '', '伊茲坎，採集孢子的時候小心一點。你不會想激怒野豬的。', 66384),
(287533, 'zhTW', '噢。哈。哈哈哈。', '', 66384),
(287532, 'zhTW', '噢。還不錯嘛。', '', 66384),
(287531, 'zhTW', '夠了、夠了。在這樣的表現之後我怎麼能拒絕你呢？', '', 66384),
(287530, 'zhTW', '憐憫心在這可派不上用場。不過我會把這當作是你的善意。', '', 66384),
(287529, 'zhTW', '哎呀。那就開始吧。', '', 66384),
(287511, 'zhTW', '是來幫忙，還是來確保我們不會互相殘殺？', '', 66384),
(287510, 'zhTW', '', '沒想到會看到你。他來幫忙準備儀式。', 66384),
(287509, 'zhTW', '我聽說母親死了。這個$r是誰？', '', 66384),
(287508, 'zhTW', '', '弟弟，是你嗎？', 66384),
(287491, 'zhTW', '讓大海抹去我們的痕跡。', '讓大海抹去我們的痕跡。', 66384),
(287490, 'zhTW', '知道了！沉入深海吧。', '知道了！沉入深海吧。', 66384),
(287489, 'zhTW', '快把它們扔進水裡！我們不能冒著被發現的風險。', '快把它們扔進水裡！我們不能冒著被發現的風險。', 66384),
(287472, 'zhTW', '確實如此。我們越是勤奮，對各方就越有利。', '確實如此。我們越是勤奮，對各方就越有利。', 66384),
(287464, 'zhTW', '有趣的地方是，他們的貨物是在有人開始詢問的時候消失的。', '有趣的地方是，他們的貨物是在有人開始詢問的時候消失的。', 66384),
(287462, 'zhTW', '嗯…我不太喜歡看到他們拿我們的事閒話家常。', '嗯…我不太喜歡看到他們拿我們的事閒話家常。', 66384),
(287446, 'zhTW', '長久以來，這裡的獸人和巨魔一直是我們的心腹之患，$p。', '', 66384),
(287438, 'zhTW', '你有什麼情報？', '', 66384),
(287422, 'zhTW', '', '嗯，也許是太陽之井火光沖天，捲入那個漩渦裡的時候？…抱歉，我有點累了。', 66384),
(287411, 'zhTW', '這個謎題一定是讓我們逃出去的關鍵。', '', 66384),
(287408, 'zhTW', '在哈拉提抵達之前，我們只能盡力降低損失。森林原本可能受到重創。\n\n但藉由這裡的大量哈拉尼爾，以及他們驅使的艾恩魔法，我們或許有機會擊退這股暴走的力量。', '', 66384),
(287406, 'zhTW', '', '議會拒絕了我們的請求。哈拉提不會起身對抗光綻。\n\n但我會。絕對會。利用我身上的艾恩之塵，我們會盡可能消除影響。', 66384),
(287405, 'zhTW', '嗯，你們還真的是弄得一片狼藉。', '', 66384),
(287402, 'zhTW', '你在看什麼?', '你在看什麼?', 66384),
(287380, 'zhTW', '', '$p。洛索瑪派我來幫忙抓住你在追捕的那個鼠輩。', 66384),
(287371, 'zhTW', '其中一個虛無樣本！看看這附近還有沒有其他的。', '', 66384),
(287367, 'zhTW', '管理者安諾里恩與我聯繫，並提供給我這個用來研究虛無風暴的空間。\n\n看來至少還是有明智之人的。這場危機對我們所有人都是個威脅。', '', 66384),
(287333, 'zhTW', '$n，清理和送貨就交給你了。阿拉特可以幫我做其他粗重的工作。', '', 66384),
(287332, 'zhTW', '各位，抱歉了，我必須去找伊崔格。我還有些事需要處理。', '', 66384),
(287330, 'zhTW', '', '我看得夠多了，麥崔恩。這些方式完全超出常理。', 66384),
(287329, 'zhTW', '', '去查出是哪一家公司弄髒了這些海岸。調查結束後再回來這裡找我。', 66384),
(287294, 'zhTW', '', '我必須把消息帶回去給奧姆里克，以免更多刃多雷落入同樣的下場。Shorel\'aran。(再會)', 66384),
(287293, 'zhTW', '', '我們的研究已經讓我做好迎接最糟結果的準備。謝謝你幫我，$n。', 66384),
(287292, 'zhTW', '', '必須讓長老知道這件事。乘風前行！', 66384),
(287291, 'zhTW', '', '這幅景象讓我心痛不已。我美麗的家園，不在了…', 66384),
(287290, 'zhTW', '', '樹根已經被光綻侵蝕了。我們必須阻止這一切。', 66384),
(287279, 'zhTW', '女神不再停留在她的育所，但她的影響力還在。艾恩裂隙太危險了，不適合哈拉尼爾進入。\n\n我切斷我與女神的連結，以便貢獻己力。你最好聽從我的指示，除非你急著想在裂隙裡送命。', '', 66384),
(287263, 'zhTW', '那我們就會摧毀他們。以太族會提供我們軍火。', '', 66384),
(287257, 'zhTW', '我太蠢了。你們只是平民，像我們一樣。那晚發動攻擊的是暮光之刃！', '', 66384),
(287244, 'zhTW', '凱西雅，我就差一點點了…她的那些筆記記載的是將事物從虛無風暴提取出來的方式。我以為我可以扭轉通道，把我們送進去，但內容就是不完整。缺少的地方太多了。\n\n我需要那些缺失的頁面…而我能夠合理推斷偷走它們的是誰。', '', 66384),
(287238, 'zhTW', '我們是至尊掠食者。我們是虛無！', '', 66384),
(287230, 'zhTW', '鮮血…\n\n虛無…\n\n至尊掠食者…\n\n我們看清了一切是如何串連起來。現在我們了解自己的使命了。', '', 66384),
(287227, 'zhTW', '風的低語承諾給予力量。\n\n而我永遠不會將它拒於門外。', '', 66384),
(287179, 'zhTW', '我們會對付援軍，你跟瓦麗拉一起去吧！', '', 66384),
(287177, 'zhTW', '$n，我相信你。找到安諾里恩，取得我們需要的情報，然後把他擊敗。', '', 66384),
(287172, 'zhTW', '凱西雅的研究蘊藏著拯救銀月城的首要步驟，但安諾里恩把遺失的書頁拿走了。我敢拿性命打賭。', '', 66384),
(287171, 'zhTW', '火焰之翼再度起飛了！\n\n這是多年來第一次，賈納雷翱翔於天際，將暖意送入我們的心中。雙翼的餘燼指引我們的武器，與阿曼尼一同將其直刺暗影籠罩之敵的胸膛！', '', 66384),
(287170, 'zhTW', '$p，很高興再次見到你。\n\n哈拉齊已經代表你和我們的長老溝通過了。我很榮幸能有機會再次為了我們帝國的傳承拿起武器。', '', 66384),
(287169, 'zhTW', '', '我是佩爾娜，我是斷齒頭銜的持有者，惡齒部族的戰士。\n\n無論發生什麼事，我們的心都還是牽掛著祖阿曼。\n\n我們是來為家園而戰的！', 66384),
(287165, 'zhTW', '這個巢穴…受到光綻的破壞。我們把它修好吧。', '', 66384),
(287164, 'zhTW', '噁！看起來，也聞起來像當地的生物已經劃分好各自的地盤了。他們一定很焦慮。', '', 66384),
(287163, 'zhTW', '這片樹叢被踐踏過，這裡的野生動物一定嚇壞了。', '', 66384),
(287076, 'zhTW', '不，我從沒看過魯坦尼有這樣的行為。', '', 66384),
(287049, 'zhTW', '這就是護符的由來。警告與提醒我們：不能只依靠本能。', '', 66384),
(287038, 'zhTW', '', '永歌森林的聖光竟然能在哈朗達造成這麼大的破壞。', 66384),
(287033, 'zhTW', '不！我們就差一點…', '', 66384),
(287028, 'zhTW', '$n！把那些虛無裂片帶到傳送門的中心。如果我猜得沒錯，這能逆轉路徑，開啟通往虛無風暴的通道。', '', 66384),
(287027, 'zhTW', '我們會修好這些舊傀儡，然後把我們發現的教徒除掉。', '', 66384),
(287026, 'zhTW', '我會再次解讀凱西雅的筆記。它們可能是解開虛無風暴謎團的關鍵。', '', 66384),
(287024, 'zhTW', '竟然跑了？真是個懦夫。我們勝券在握的！', '', 66384),
(287005, 'zhTW', '我族人的回憶、經驗和智慧都在這些牆上。\n\n等你準備好開始，就碰觸壁畫。', '', 66384),
(287004, 'zhTW', '觸碰壁畫。其中的艾恩之塵會揭露我們的真相。', '', 66384),
(287003, 'zhTW', '', '願艾恩哈拉指引你。祝你好運。', 66384),
(286998, 'zhTW', '這張永歌森林的地圖上標滿了暮光之刃的目標，還包括風行者村！', '', 66384),
(286970, 'zhTW', '', '長老做了決定。他們希望重溫過去能讓你認清自己愚蠢的行徑。', 66384),
(286969, 'zhTW', '謝謝你讓我認清真正的敵人是誰。還教會我三思而後行。', '', 66384),
(286961, 'zhTW', '馬上前往大巢穴！議會會決定你的命運。', '', 66384),
(286957, 'zhTW', '太驚人了。$n，快來看。', '', 66384),
(286956, 'zhTW', '太驚人了。樹根的末端藏著一整個世界。哈朗達居然能成功隱世無數個年頭，簡直是史無前例的壯舉。\n\n雖然光綻是我們的主要目標，但我承認，我很想進一步了解哈拉尼爾，以及他們建立的封閉世界。', '', 66384),
(286955, 'zhTW', '歐薇娜太衝動，也太魯莽了。在哈朗達外有了豐富的閱歷後，我認為她現在會認同。\n\n只可惜，長老們或許太謹慎了。', '', 66384),
(286895, 'zhTW', '部落早在很久以前就放下這段黑暗的過去了。要是所有人都能照做就好了。', '', 66384),
(286884, 'zhTW', '', '精靈，跟我來。我們靠近過去，分散他的注意力。', 66384),
(286883, 'zhTW', '$n，快過來！我裝填箭矢，你負責發射。', '', 66384),
(286878, 'zhTW', '到旅店集合，那裡比較安全！', '', 66384),
(286838, 'zhTW', '', '$p，薩拉塔斯和吞噬之眾圍攻了太陽之井。聖光選擇你擔任它的保衛者。', 66384),
(286837, 'zhTW', '呿！黑暗部落。他們還想著要贏第二次大戰的時候，我們已經在第四次大戰談和了。能不能跟上時代啊！', '', 66384),
(286836, 'zhTW', '來吧，庫德蘭。我們必須找出黑暗部落的其他營地。', '', 66384),
(286828, 'zhTW', '相信歐薇娜的人比她以為的還多。我會跟隨她到底。', '相信歐薇娜的人比她以為的還多。我會跟隨她到底。', 66384),
(286827, 'zhTW', '我準備好戰鬥了！他們休想破壞我最愛的哈朗達。', '我準備好戰鬥了！他們休想破壞我最愛的哈朗達。', 66384),
(286826, 'zhTW', '我們必須盡我們所能，幫助我們的生態系統。', '我們必須盡我們所能，幫助我們的生態系統。', 66384),
(286825, 'zhTW', '這個詭異的光綻是如何在我們的土地擴散？我一直以為我們在哈朗達這裡很安全。', '這個詭異的光綻是如何在我們的土地擴散？我一直以為我們在哈朗達這裡很安全。', 66384),
(286824, 'zhTW', '我痛恨被迫離開自己的家，就像這些可憐的魯坦尼。我想幫助他們。', '我痛恨被迫離開自己的家，就像這些可憐的魯坦尼。我想幫助他們。', 66384),
(286813, 'zhTW', '讓我們好好工作，不然就拿起斧頭，讓自己派上用場。', '', 66384),
(286811, 'zhTW', '那個男孩面對的試煉將會塑造性格。這正是他需要的。\n\n不過，去確保他不會在過程中把自己害死。愚蠢的男孩…', '', 66384),
(286809, 'zhTW', '我原先是來這裡復仇。\n\n結果，我找到了始料未及的答案。\n\n謝謝你，$n。如果不是你適時介入，我早就被自己的愚蠢行徑害死了。', '', 66384),
(286808, 'zhTW', '<凱勒滿身是血，傷痕累累，意識不清，不斷輕聲呻吟。>', '', 66384),
(286807, 'zhTW', '你…你來幫我？我猜是那個老木匠派你來的…', '', 66384),
(286804, 'zhTW', '', '我已經甦醒，不會再變異了。', 66384),
(286750, 'zhTW', '那個帶鎖箱裡有什麼？', '', 66384),
(286749, 'zhTW', '我們盡力拯救了其他人，但我的研究…', '', 66384),
(286748, 'zhTW', '在這裡的這段期間，安諾里恩總是能搶先我一步。我們回去研究室吧。', '', 66384),
(286745, 'zhTW', '', '真是好騙！', 66384),
(286743, 'zhTW', '你沒事啊！你有看到奧姆里克嗎？', '', 66384),
(286740, 'zhTW', '去照顧平民。我去找安諾里恩…讓他付出代價。', '', 66384),
(286739, 'zhTW', '我不會眼睜睜看著教團奪走這座城鎮！', '', 66384),
(286725, 'zhTW', '我因為光綻失去了許多。如果你們能給予希望，我會聽你們說的。', '', 66384),
(286708, 'zhTW', '', '你來了。壞消息是，我們的擔憂是有根據的。', 66384),
(286702, 'zhTW', '', '歡迎來到我的故鄉「哈瑪拉」。我曾經作為泰達希爾的根莖守望者住在這裡。', 66384),
(286700, 'zhTW', '', '艾恩之塵。這或許是艾歐卡不受光綻影響的原因。', 66384),
(286699, 'zhTW', '這顆種子…竟然被包覆在…', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(286698, 'zhTW', '', '我們會在這裡保護哈嘉爾和其他人。', 66384),
(286695, 'zhTW', '', '你消滅了許多邪惡生長物。那些來自哈拉諾的雜草現在會滋養土地。\n\n在下希望戰鬥到此為止。', 66384),
(286693, 'zhTW', '哦，女神啊…', '', 66384),
(286681, 'zhTW', '我必將親自斬殺祖爾詹！', '', 66384),
(286677, 'zhTW', '', '光綻是在太陽之井重新點燃一段時間之後開始的。單純只是會到處生長幾片不尋常的植物，沒什麼好擔心的。在太陽之井將聖光注入我們體內的同時，它似乎也對植物進行了灌注。真的非常神奇！\n\n我們一向能夠塑造我們周圍的森林，但光綻似乎更加固執。它更加狂野…較不具有可塑性，幾乎就像它有自己的意識…當然了，這只是個愚蠢的想法。畢竟它們只是植物。植物是不會思考的。', 66384),
(286666, 'zhTW', '', '歡迎來到晴風村。', 66384),
(286656, 'zhTW', '我比你早一點抵達哈拉諾。這裡顯然有很大的問題。如果我們要舒緩周圍那些人的痛苦，我們有一大堆工作要做。\n\n事情怎麼會變得這麼嚴重？', '', 66384),
(286645, 'zhTW', '', '圖阿瑪。\n\n<她指向自己。>\n\n我的工作，讓兄弟姐妹安全。回家。', 66384),
(286641, 'zhTW', '$p，快收集艾恩之塵。動作快。', '', 66384),
(286640, 'zhTW', '不…憤怒高漲…吞噬了我。我不會…不能…讓它再次發生。', '不…憤怒高漲…吞噬了我。我不會…不能…讓它再次發生。', 66384),
(286632, 'zhTW', '將聖光保存在紋理中，搭配龍鷹燼油。', '', 66384),
(286612, 'zhTW', '', '我看過形形色色的花。花開是好事，對吧？', 66384),
(286595, 'zhTW', '', '一旦我們開始儀式，薩拉塔斯就會派她的部隊來這個入口阻止我們。\n\n你必須在儀式完成之前逼退他們。', 66384),
(286594, 'zhTW', '那些虛無魔法披風…我以前看過！', '', 66384),
(286593, 'zhTW', '', '我們沒有拋棄阿曼尼，是阿曼尼背叛了我們。\n\n妖術領主瑪拉克雷斯說服督軍祖爾金用盡一切手段打造出強力的戰士。\n\n他們找到了一種褻瀆手段，抽取我們的力量，將其注入四名阿曼尼化身。像你一樣的入侵者阻止了他們…殺死化身、瑪拉克雷斯和祖爾金。\n\n我捨棄了我的神廟。哈拉齊撤退回迷霧之中休養治療。賈納雷承受最多痛苦，祂的火焰最終熄滅，並被瑪拉克雷斯吞噬。納羅拉克成為憤怒的化身，只能透過在山裡深度冬眠才能舒緩。\n\n如果祖爾賈拉想成為哈謝並摧毀暮光之刃，那她需要所有羅亞的祝福，不只是我一個。\n\n羅亞與阿曼尼的羈絆必須再次變得強大。', 66384),
(286591, 'zhTW', '', '我把阿曼尼食人妖當作我的孩子。但孩子偶爾就是會誤入歧途。', 66384),
(286576, 'zhTW', '誰能想到在世界之樹的樹根匯聚地有一整個世界？真是太驚人了。', '', 66384),
(286565, 'zhTW', '', '暗影之握！他被虛無控制了！', 66384),
(286561, 'zhTW', '', '我們花了太多時間追趕這隻野獸，麥崔恩！我們應該把消息帶回去。', 66384),
(286527, 'zhTW', '暗影…會吞噬你…', '', 66384),
(286526, 'zhTW', '太好了…等等，那個發光的東西是什麼？', '', 66384),
(286525, 'zhTW', '暮光之刃偷走了我對虛無風暴的所有研究！', '', 66384),
(286517, 'zhTW', '這真是一趟精采的旅程，$p。準備好展開下一段旅程了嗎？', '', 66384),
(286516, 'zhTW', '戴斯可，謝謝你。你在這裡做的事讓我很佩服。我一定會回來的。', '', 66384),
(286515, 'zhTW', '我必須占用一點阿拉特和$n的時間。尋找最後一個聖物的事宜已經安排好了。', '', 66384),
(286499, 'zhTW', '不，卡莉雅。我們了解低語。我們了解它們的可能性。', '', 66384),
(286495, 'zhTW', '這份工作糟透了。我不幹了！', '', 66384),
(286490, 'zhTW', '戰場上的金屬碎塊清乾淨了！我們會把它們拿來廢物利用。', '', 66384),
(286487, 'zhTW', '', '從小時候開始，我就再也沒回去過神廟。那裡只有小鳥跟藤蔓而已。', 66384),
(286478, 'zhTW', '', '讓我面對自己靈魂中潛藏的羞愧之心吧。', 66384),
(286462, 'zhTW', '確實。我們必須趕在光芒消逝以前盡快回到碼頭。', '確實。我們必須趕在光芒消逝以前盡快回到碼頭。', 66384),
(286461, 'zhTW', '他們的帳簿看似乾淨，但他們幹的勾當卻比污水還要臭。', '他們的帳簿看似乾淨，但他們幹的勾當卻比污水還要臭。', 66384),
(286459, 'zhTW', '最好別和他們扯上關係。他們的口風比洛索瑪的錢包還要鬆。', '最好別和他們扯上關係。他們的口風比洛索瑪的錢包還要鬆。', 66384),
(286448, 'zhTW', '$p！騎上坐騎！退回太陽之井！', '', 66384),
(286435, 'zhTW', '銬住他。讓他掙扎扭動。', '', 66384),
(286434, 'zhTW', '不要衝動行事。專心一點。完美就是要無微不至。', '', 66384),
(286433, 'zhTW', '拉卡妮想要那個精靈的血。\n\n在你來之前，那個男孩製造了不少麻煩，不過，他其實對我們構不成威脅。一個農夫的小孩，跟我們一樣是平民…\n\n儘管如此，如果他不能在行動受限的情況下跟上你，最後死在敵人手中，那也是他的命。', '', 66384),
(286412, 'zhTW', '', '讓他們通過。那個$c身上沾有我們敵人的鮮血。', 66384),
(286404, 'zhTW', '繼續前進！別屈服於黑暗！', '', 66384),
(286397, 'zhTW', '', '懦夫！就因為你害怕隻身面對，才會接納別人的援手！', 66384),
(286388, 'zhTW', '', '前進！我們會把暗影逼退！', 66384),
(286387, 'zhTW', '恰恰相反。我們要去見一位正在成就偉業的人。那是我未能完成的壯舉。', '', 66384),
(286386, 'zhTW', '落錘鎮？這和紅色黎明有關嗎？', '', 66384),
(286374, 'zhTW', '', '歡迎。你會在下面迎來最終的試煉。\n\n如果你順利生還，就能被我的族人接納。等你準備好開始，就進入探究。', 66384),
(286368, 'zhTW', '', '這一切都歸功於艾恩之塵。這也是它被我們視為聖物的原因之一。', 66384),
(286367, 'zhTW', '這些繪畫…我從沒看過這樣的魔法。', '', 66384),
(286366, 'zhTW', '這一切都不該發生！我們走吧。', '', 66384),
(286361, 'zhTW', '來自世界深處的歌聲回應了我們的渴望。', '', 66384),
(286360, 'zhTW', '我們必須知道更多詳情。', '', 66384),
(286359, 'zhTW', '稍等，這個木樁還真難搞。', '', 66384),
(286356, 'zhTW', '謝謝你援助落錘鎮，$p。', '', 66384),
(286355, 'zhTW', '', '祖爾詹…不…', 66384),
(286354, 'zhTW', '', '先倒下的會是你。受死吧！', 66384),
(286353, 'zhTW', '我可以建立傳送門，把我們送回銀月城，$p，使用這本卡德加借給我的魔典。', '', 66384),
(286337, 'zhTW', '這永遠不會結束，對不對？總會有人來繼承這股仇恨。', '', 66384),
(286336, 'zhTW', '這把劍早在十字軍的仇恨前就已經鑄造完成。或許可以把它交還給一位公正之人。', '', 66384),
(286335, 'zhTW', '這些新教徒會永遠透過仇恨召喚聖光嗎？', '', 66384),
(286333, 'zhTW', '聖光會為我們的十字軍…選擇…一個新領袖…', '', 66384),
(286331, 'zhTW', '你們這些異教徒竟敢擾亂我的彌撒？', '', 66384),
(286330, 'zhTW', '滾吧！如果你們想投降，就把武器交給我們，離開這個詛咒之地，永遠別回來。', '', 66384),
(286329, 'zhTW', '', '入侵者…看來為十字軍犧牲的時候到了。', 66384),
(286328, 'zhTW', '誰會來教導他們…如何遵循聖光？', '', 66384),
(286327, 'zhTW', '我會讓新教徒見識該如何懲戒不信者！', '', 66384),
(286326, 'zhTW', '', '已經發生的事情。將會發生的事情。我只會說那些事情。', 66384),
(286324, 'zhTW', '', '在夏達希爾附近，我們的樹根才能充分休息。我的林地一定會復生。', 66384),
(286323, 'zhTW', '', '我們的家在發光。對魯坦尼來說不安全。等到聖光消逝時，我們一定會回來。', 66384),
(286322, 'zhTW', '', '我是魯坦尼尊者。我代表我的林地發言。', 66384),
(286311, 'zhTW', '太陽之井是聖光的導體！因為那魯「穆魯」的犧牲而成為神聖的象徵！', '', 66384),
(286310, 'zhTW', '', '我現在可以聽見女神的聲音了，但都只是低語。蘇卡是怎麼忍受這種空虛感的？', 66384),
(286308, 'zhTW', '', '自從虛無風暴出現後，又有三名斥侯在南方失蹤了！', 66384),
(286307, 'zhTW', '', '你們是…你們有什麼事嗎？', 66384),
(286305, 'zhTW', '有新兵？太好了！', '', 66384),
(286303, 'zhTW', '', '我有好多年沒看過安寧地的情勢這麼緊張了。', 66384),
(286302, 'zhTW', '', '詹，不論有沒有光木，我們的族人都需要救援。帶上精靈，去尋找倖存者。', 66384),
(286300, 'zhTW', '好吧。$C，拿武器。讓你看到的所有阿曼尼武裝備戰。', '', 66384),
(286288, 'zhTW', '我們清楚在虛無風暴的龐大深淵之下卻無能為力的感覺。\n\n閱讀這封書信是你邁向覺醒的第一步。\n\n繼續向南吧，疲憊的旅人。安寧地不過是旅途中的一個歇腳處。\n\n我們摯愛的領袖會為我們指明道路。', '我們清楚在虛無風暴的龐大深淵之下卻無能為力的感覺。\n\n閱讀這封書信是你邁向覺醒的第一步。\n\n繼續向南吧，疲憊的旅人。安寧地不過是旅途中的一個歇腳處。\n\n我們摯愛的領袖會為我們指明道路。', 66384),
(286287, 'zhTW', '風暴近在咫尺，但銀月城卻沒有採取任何行動。現在我們只能靠自己想辦法了。\n\n在安寧地有你的一席之地。齊心協力，我們就會平安無事。團結一心，我們就能保護好自己。\n\n如果你感興趣，請洽管理者安諾里恩的辦公室。\n\n我們歡迎所有人，尤其鼓勵有參軍經驗的人加入。', '風暴近在咫尺，但銀月城卻沒有採取任何行動。現在我們只能靠自己想辦法了。\n\n在安寧地有你的一席之地。齊心協力，我們就會平安無事。團結一心，我們就能保護好自己。\n\n如果你感興趣，請洽管理者安諾里恩的辦公室。\n\n我們歡迎所有人，尤其鼓勵有參軍經驗的人加入。', 66384),
(286286, 'zhTW', '<一份附有城鎮地圖的迎賓手冊，其中標出了幾個重要地點：管理者的辦公室、守衛哨站以及奧姆里克的實驗室。>\n\n安寧地歡迎所有新來客！\n\n你的追求是什麼？和平？安全？真相？上述的我們全都能提供，而且還不只這些。\n\n管理者會認真看待你的擔憂！他的雙眼守望著我們。', '<一份附有城鎮地圖的迎賓手冊，其中標出了幾個重要地點：管理者的辦公室、守衛哨站以及奧姆里克的實驗室。>\n\n安寧地歡迎所有新來客！\n\n你的追求是什麼？和平？安全？真相？上述的我們全都能提供，而且還不只這些。\n\n管理者會認真看待你的擔憂！他的雙眼守望著我們。', 66384),
(286262, 'zhTW', '我不在乎那些食人妖說了什麼。\n\n他們不是伐木工，他們是怪物。\n\n他們在夜色的掩護下到來，殺了我的妹妹，燒毀我們家的農場！\n\n對對，你們都想為我上一課。手無寸鐵、綁手綁腳地上戰場，到底能學到什麼？\n\n你們只是想讓我去送死。', '', 66384),
(286261, 'zhTW', '在一切太遲之前，幫我解決問題。', '', 66384),
(286257, 'zhTW', '托倫多派你來了解光木武器為什麼延誤出貨？你來對地方了。\n\n暮光之刃發現我們的營地，他們知道我們為阿曼尼供應強大的光木武器。他們開始一天到晚攻擊我們，中斷我們的工作。\n\n而現在，這個男孩跑來我們的營地，大吼大叫著什麼妹妹。我沒有時間處理暮光之刃，更沒有時間照顧某個精靈農夫走丟的憤怒孩童！\n\n他很年輕，不知天高地厚。這種年輕人我也見過不少…\n\n也許你可以幫我解決這兩個問題。', '', 66384),
(286255, 'zhTW', '我不禁思考，我們的族人能不能從分享這類技藝獲益…\n\n這個知識有助於讓我的家人免於虛無的威脅…我僅存的家人。', '', 66384),
(286231, 'zhTW', '對不起。我知道我不該做出這麼輕率的假設。', '', 66384),
(286230, 'zhTW', '不客氣，孩子。現在，快回你的農場。祖阿曼可不是你這樣的精靈孩子該來的地方。', '', 66384),
(286226, 'zhTW', '你的同類攻擊我們的農場，殺死我的妹妹。我知道這些就夠了。', '', 66384),
(286224, 'zhTW', '光是一小片光木就蘊藏龐大力量。食人妖比我們想的還要聰明。', '', 66384),
(286223, 'zhTW', '我沒想到暮光之刃居然在這裡…或者沒想到他們人數眾多。', '', 66384),
(286222, 'zhTW', '去吧。消滅斥候指揮官，別讓他殺了那個孩子。', '', 66384),
(286221, 'zhTW', '孩子，幫助$n。去砍伐木材。', '', 66384),
(286216, 'zhTW', '光木很有用。你根本不了解這裡真正的威脅，孩子。', '', 66384),
(286193, 'zhTW', '光木會讓他們現形！還會擊昏他們？', '', 66384),
(286191, 'zhTW', '讓這個孩子見識真正的敵人。', '', 66384),
(286168, 'zhTW', '歡迎來到我的避風港。有需要什麼就告訴我。', '', 66384),
(286135, 'zhTW', '', '托倫多，我需要你的報告。我們的士兵什麼時候可以上戰場？', 66384),
(286134, 'zhTW', '這是我的第二個教誨。聖光是透過信仰和信念引導出來的。就算受到誤導也是如此。', '', 66384),
(286133, 'zhTW', '這個地方具備了聖光教會的所有表徵，卻轉而被邪惡利用。', '', 66384),
(286129, 'zhTW', '當這個地方還在聖光教堂的眷顧下時，不是這個樣子的。\n\n原本在賽丹和亞歷山卓斯的帶領下，它對羅德隆帶來許多好處。\n\n但隨著時間經過，血色十字軍對彼此的仇恨漸行漸遠，數十年來，他們早已背離初衷。', '', 66384),
(286125, 'zhTW', '啊，沒錯，梅勒鐸。雖然你的優秀魔法毀掉了一本完好無損的日誌，至少我們可以說你已經精通了製造災難的技藝。', '', 66384),
(286123, 'zhTW', '嗯，瓦迪斯，這次要感謝你。你沒效率的作法引起的混亂倒是跟我預期的一樣。', '', 66384),
(286119, 'zhTW', '$n，你來了。我們該去裡面與阿拉特會合。對這些狂熱分子布道根本是在對牛彈琴。', '', 66384),
(286118, 'zhTW', '他們佔領我的教堂時，也奪走了許多聖物。那些聖物還是用來對抗薩拉塔斯比較好。', '', 66384),
(286104, 'zhTW', '', '歐薇娜搖了搖頭。', 66384),
(286099, 'zhTW', '', '那就阻止邪枝趁夜綁走我們的人！', 66384),
(286081, 'zhTW', '願森林為你指明最迅捷的路徑，因為我們的法師鐵定幫不上忙。', '', 66384),
(286077, 'zhTW', '長老事先傳話，表示准許你接受試煉。我們會看看你是不是真的是艾恩哈拉叫來的。\n\n你得到一個千載難逢的機會，能夠了解我們的族人、文化和歷史。\n\n等你準備好開始，就告訴我一聲。', '', 66384),
(286071, 'zhTW', '祝你好運。我們會先去搜索，但帶上瓦迪斯一點用都沒有。', '', 66384),
(286065, 'zhTW', '薩拉塔斯低估了聖光先鋒和辛多雷的決心。今天我們不會倒下，而是會在對抗虛無的戰鬥中贏得決定性的勝利！', '', 66384),
(286053, 'zhTW', '<阿拉特靜止不動，用手勢示意你照做。>\n\n等等。有人來了。', '', 66384),
(286050, 'zhTW', '謝謝你。天譴軍團被擊退了。帶著你需要的聖物，去支援太陽之井吧。', '', 66384),
(286049, 'zhTW', '自從我加入白銀之手後就一直努力在做這件事。', '', 66384),
(286048, 'zhTW', '我的第一個教誨，就是從過去受人景仰的英雄身上學習，了解是什麼激發了他們的聖光。', '', 66384),
(286037, 'zhTW', '還真是個適合讓我忘記聖騎士煩惱的好地方。', '', 66384),
(286035, 'zhTW', '到聖光之願收集聖物，提振聖光先鋒的士氣。', '', 66384),
(286029, 'zhTW', '嗯哼。這些保衛者過於疲憊，耗盡了自己的信仰與力量。我們可以為他們補充能量。', '', 66384),
(286028, 'zhTW', '這就是你的解決方法？用你的法杖電他們？', '', 66384),
(286018, 'zhTW', '', '攝政王…阿曼尼入侵了永歌森林。遊俠將軍帶領我們的部隊要把他們擊退。', 66384),
(286006, 'zhTW', '啊，太好了！你們都在。有一場信仰危機等著我們去修復！', '', 66384),
(286005, 'zhTW', '真是個憂心忡忡的孩子。要是你的父親在你的胸口留下傷痕，自然會變成這樣。不用擔心，我有個計畫。', '', 66384),
(286003, 'zhTW', '薩拉奈爾，虛無已經突破防線了！我們…我們太遲了…', '', 66384),
(285998, 'zhTW', '', '我始終害怕我的力量會傷害到我所關心的人們。但在我的心中，這就像顯露出一瞬間的軟弱，讓我體內的黑暗那魯找到空隙滲透其中。\n\n我從沒想過自己的手會被陪伴我最久的戰友之一控制。', 66384),
(285997, 'zhTW', '洛斯拉賽恩！', '', 66384),
(285994, 'zhTW', '我知道這個謎團的真相就藏在這裡的某處。我們只是需要把它找出來。', '', 66384),
(285983, 'zhTW', '投降吧，地面來的！你們的聖光會反噬你們！', '', 66384),
(285979, 'zhTW', '好好休息，凡人。尋求救濟。', '', 66384),
(285977, 'zhTW', '這裡的虛無好像…比較微弱。或許是戴西蒙斯做的？', '', 66384),
(285959, 'zhTW', '你不必擔心我。但是，提拉的痛苦…我感同身受。相信你也一樣。\n\n我知道踏上這條路，必定要付出代價，不過，我不曾切身體會，直到現在。', '', 66384),
(285955, 'zhTW', '$n。我們必須去看看其他人。', '', 66384),
(285937, 'zhTW', '', '赫杜倫，$n，跟我來。', 66384),
(285936, 'zhTW', '一想到我們就在巨大世界樹的樹根底下，就讓人震驚不已。我們從來不知道這裡藏著一整個世界。\n\n這可是艾澤拉斯的其他人不曾擁有的寶貴機會。\n\n只要你準備好了，我隨時都能出發。', '', 66384),
(285929, 'zhTW', '他們砍倒的那棵樹引發了日冠村的毀滅！阿曼尼會為此付出代價！', '', 66384),
(285928, 'zhTW', '', '現階段，我們已經完成我們能做的事了。\n\n我不能沉浸在悲傷之中…工作才剛開始。', 66384),
(285927, 'zhTW', '所以是倒塌引發了光綻的蔓延…謝謝你。好好休息，我們會解決這件事。', '', 66384),
(285923, 'zhTW', '啊，對了。祖爾賈拉說他希望某個$c來參加這場會議！看來這個人就是你了，那個幫助我逃跑的$c。\n\n很好。阿曼尼需要更多的盟友，也就是你和在場的部族首領。\n\n至於莉雅德倫在這裡…我不怎麼喜歡，但我沒有資格對祖爾賈拉的決定說三道四。', '', 66384),
(285922, 'zhTW', '', '因為暮光之刃，我們惡齒部族失去了長老和村莊，包括我的父親和祖父。\n\n現在惡齒部族由我領導。', 66384),
(285909, 'zhTW', '', '我相信我們正在做對的事。無論有什麼風險，我們都會有始有終。', 66384),
(285908, 'zhTW', '', '只要劑量正確，就連最有效的良藥都能變成毒藥。', 66384),
(285907, 'zhTW', '雖然博學者進行了實驗，但我不認為這完全是受他的影響所導致的。', '', 66384),
(285906, 'zhTW', '', '我敢說真正的怪物是將聖光逼到這種地步的那個人。', 66384),
(285905, 'zhTW', '那個異形到底是什麼？聖光真的能創造出那樣的怪物嗎？', '', 66384),
(285900, 'zhTW', '', '你是來幫忙的嗎？', 66384),
(285896, 'zhTW', '哈嘉爾或許不再是根莖守望者，但她還是擁有高深的智慧。相信她不會將歐薇娜引入歧途。', '', 66384),
(285889, 'zhTW', '', '這裡的根莖守望者倍受尊敬，她可以告訴你更多事。', 66384),
(285885, 'zhTW', '我們的傳統會延續下來是有原因的。它們保護了我們和這片土地。年輕一代不該提出質疑。', '', 66384),
(285882, 'zhTW', '你可以在這個世界的邊陲找到奧核點。就是這些據點讓風暴持續翻騰。', '', 66384),
(285825, 'zhTW', '戴西蒙斯的臉上露出微笑。', '', 66384),
(285824, 'zhTW', '虛無生物，告訴我們怎麼破除風暴。', '', 66384),
(285822, 'zhTW', '天啊，我已經很久沒遇過舉止這麼粗魯的客人了，自從…嗯。我不該說。\n\n我不想被暴力對待。現在，我們都有修養一點。', '', 66384),
(285818, 'zhTW', '啊，沒錯，這話竟然出自同一個弄丟它的「優秀」人才之口！真是愚蠢至極！', '', 66384),
(285817, 'zhTW', '如果你的「敏銳雙眼」真的有用的話，我們現在早就找到日誌了！', '', 66384),
(285816, 'zhTW', '年輕人的無畏永遠讓我嘖嘖稱奇。', '', 66384),
(285813, 'zhTW', '', '長老決不會犧牲一點艾恩之塵。我們得另尋他法。', 66384),
(285811, 'zhTW', '血色十字軍？竟然偏偏是你，想散播他們的聖光？', '', 66384),
(285808, 'zhTW', '$p！我們要去拯救太陽之井。更重要的是，我們要治癒那個受傷的年輕人。', '', 66384),
(285793, 'zhTW', '', '有了哈拉提的幫助，以及心中的艾恩之賜，我們一定能驅逐狂亂。\n\n不過，我們要做的不只這些。還有魯亞，他必須為他的行為負責。', 66384),
(285786, 'zhTW', '', '啊。如果你想暫時避開來訪的…朋友，你可以去尋找城市中的紅色旌旗。我們不會讓聯盟的人進到那些區域。', 66384),
(285785, 'zhTW', '', 'Bal\'a dash，malanore。\n\n在這種時期，皇家交易所能帶給人們一種歲月靜好的感覺。你在商店街能找到的服務，在這裡都能找到，不過只向特定客戶開放。', 66384),
(285784, 'zhTW', '', '我被召喚來這裡是有原因的。', 66384),
(285779, 'zhTW', '我身後的大門只會為部落的成員敞開。遠離紅色旌旗和樹叢，否則後果自負。', '', 66384),
(285778, 'zhTW', '這道門不歡迎聯盟成員通過。你不能再往前了，「英雄」。', '', 66384),
(285777, 'zhTW', '不好意思，我沒有時間分心。\n\n聯盟或許被允許在市集走動，但這不代表我們不該保持警惕。他們可能會想試探一下我們的底線。', '', 66384),
(285761, 'zhTW', '', '我早該猜到祖爾詹會這麼做。\n\n江山易改，本性難移…\n\n但他是我的弟弟，我以為他能學到教訓…\n\n要是他能聽我這麼一次！\n\n要是祖爾詹帶大家走上死路，連羅亞都救不了我們，那踏上哈謝之道又有什麼用？', 66384),
(285760, 'zhTW', '', '現在我有了納羅拉克的祝福還有重擔，我們能夠率領族人，徹底終結莫爾頓了！', 66384),
(285754, 'zhTW', '在下叫做提忒，從哈拉諾來這裡交易。', '', 66384),
(285753, 'zhTW', '', '你確定你弟弟會聽從命令嗎？', 66384),
(285751, 'zhTW', '<博學者梅勒鐸和遊俠瓦迪斯看起來正在用餐。\n\n那本遺失的日誌已經不見了。日誌一定是在這段時間弄丟的。>', '<博學者梅勒鐸和遊俠瓦迪斯看起來正在用餐。\n\n那本遺失的日誌已經不見了。日誌一定是在這段時間弄丟的。>', 66384),
(285750, 'zhTW', '<博學者梅勒鐸和遊俠瓦迪斯看起來正一邊沿著路走一邊聊天。\n\n那本遺失的日誌分明就擺在眼前。日誌一定是在不同的時間點弄丟的。>', '<博學者梅勒鐸和遊俠瓦迪斯看起來正一邊沿著路走一邊聊天。\n\n那本遺失的日誌分明就擺在眼前。日誌一定是在不同的時間點弄丟的。>', 66384),
(285748, 'zhTW', '<博學者梅勒鐸和遊俠瓦迪斯看起來正在切磋。\n\n那本遺失的日誌分明就擺在眼前。日誌一定是在不同的時間點弄丟的。>', '<博學者梅勒鐸和遊俠瓦迪斯看起來正在切磋。\n\n那本遺失的日誌分明就擺在眼前。日誌一定是在不同的時間點弄丟的。>', 66384),
(285736, 'zhTW', '在下是莉札，從哈拉諾來這裡交易。', '', 66384),
(285733, 'zhTW', '銀月城和整個艾澤拉斯的命運，可能都取決於這次任務的結果。Anu belore dela\'na（願永恆的太陽指引我們）。', '', 66384),
(285717, 'zhTW', '如果苦澀花在此扎根，哈瑪拉就會被摧毀！', '', 66384),
(285706, 'zhTW', '虛無的勢力低估了聖光的力量。', '', 66384),
(285703, 'zhTW', '', '弟弟，我們都是優秀的阿曼尼。我們只需要對彼此更寬容一點。', 66384),
(285702, 'zhTW', '又來指出我犯的錯嗎，姐姐？為什麼？你怕我是比你更優秀的阿曼尼嗎？', '', 66384),
(285701, 'zhTW', '我可以嚐到大屠殺的味道！', '', 66384),
(285699, 'zhTW', '', '不！祖父，我絕不會重蹈你的覆轍！就算要毀了我們的「家族驕傲」也一樣。', 66384),
(285698, 'zhTW', '傻女孩！竟然跟精靈站在一起？你讓我跟家族的驕傲蒙羞！', '', 66384),
(285694, 'zhTW', '低語讓我喪失知覺。', '低語讓我喪失知覺。', 66384),
(285692, 'zhTW', '這個光綻和我想像的不太一樣。', '', 66384),
(285689, 'zhTW', '真是無聊的同伴精神。你該像戴西蒙斯一樣，搞清楚自己的身分。', '', 66384),
(285688, 'zhTW', '', '大多數魯坦尼有很強的領地意識。這裡是少數幾個能和他們和平互動的地方。', 66384),
(285685, 'zhTW', '', '到聖壇跟我碰面。我會帶著柴薪。我的靈魂準備好面對任何挑戰了。', 66384),
(285680, 'zhTW', '', '羅亞語者，你自己小心點！', 66384),
(285678, 'zhTW', '', '雖然他滿口胡言，但似乎對羅亞有很深的理解。$n，把柴薪拿著，看看我們能不能進行試煉。', 66384),
(285672, 'zhTW', '', '叔叔，羅亞都好幾年沒跟你說過話了。你為什麼覺得現在祂們會想說？', 66384),
(285671, 'zhTW', '你從未見識過羅亞存在的世界。祂們是我們的力量和希望。', '', 66384),
(285667, 'zhTW', '', '那你願意幫我們追獵莫爾頓和暮光之刃嗎，狩獵的主宰？', 66384),
(285665, 'zhTW', '年輕的阿曼尼，他們會是我的獵物。願你常受暗影守護。', '', 66384),
(285664, 'zhTW', '', '等你恢復精神之後就下來吧。其他人都在等你。', 66384),
(285662, 'zhTW', '', '你在哈瑪拉會發現，魯坦尼和蘑菇人竟然能和平共處。', 66384),
(285661, 'zhTW', '', '我們向前推進。哈謝聖壇會引領我們前往哈拉齊神廟。', 66384),
(285660, 'zhTW', '', '我們現在該怎麼辦？這霧…簡直伸手不見五指。', 66384),
(285659, 'zhTW', '', '啊，你醒了。歡迎來到哈瑪拉。', 66384),
(285656, 'zhTW', '聖光與我們同在。希望猶存。', '', 66384),
(285630, 'zhTW', '你似乎好多了。它一定是修好了！', '', 66384),
(285627, 'zhTW', '這個古董塑形裝置在運送時損壞。看你能不能修好它。', '', 66384),
(285603, 'zhTW', '', '有五個！南方情況不對，但我們人數不足，無法過去巡視。', 66384),
(285599, 'zhTW', '阿拉特，洛索瑪可以處理撤離的事。聖光先鋒需要你！', '', 66384),
(285597, 'zhTW', '我去四處打聽，看看有沒有什麼線索。', '', 66384),
(285589, 'zhTW', '', '在墓穴的時候，我注意到邪枝也受迷霧蒙蔽了。嗯…', 66384),
(285585, 'zhTW', '', '我們會把戰士們帶回來，然後找到通往哈拉齊神廟的路。', 66384),
(285584, 'zhTW', '', '祖爾賈拉，當心迷霧。這不太自然，我們懷疑邪枝可能在策劃某種陰謀。', 66384),
(285580, 'zhTW', '', '史琦德不知道自己為什麼會在這裡，但蠟燭可以保護我的安全。\n\n$p，你的頭上需要安全蠟燭嗎？', 66384),
(285574, 'zhTW', '', '接著你必須尋求哈拉齊的祝福。祂潛藏在暗影中，但羅亞語者可以幫你找到祂。', 66384),
(285573, 'zhTW', '', '枯木部族的羅亞語者都死了。但也許庫阿瑪拉可以幫上忙。', 66384),
(285551, 'zhTW', '', '我會把它的樣本帶回去給遠行者。或許那裡有人可以透過研究它，找出某些用途。', 66384),
(285550, 'zhTW', '', '這朵花…充斥著聖光。除了光綻之外，我從來沒有看過這樣的東西。如果我伸手去觸碰，它幾乎會讓我無法看清。', 66384),
(285546, 'zhTW', '去吧。我留在這裡等，看看有沒有人回來。', '', 66384),
(285545, 'zhTW', '哈利斯嘆了口氣。', '', 66384),
(285544, 'zhTW', '賽狄娜…！', '', 66384),
(285543, 'zhTW', '', '跟我來！如果有人需要幫助，傻傻等待是救不了他們的！', 66384),
(285528, 'zhTW', '', '試煉…我還小的時候金德魯帶我來過…我還記得！', 66384),
(285517, 'zhTW', '', '關於你父親。他…等等。你聽見了嗎？', 66384),
(285514, 'zhTW', '我們在樹根之中殺出血路，最終抵達哈朗達。但那是另一個更長也更危險的故事了。', '', 66384),
(285510, 'zhTW', '看來只有我理解現狀的嚴重性。', '', 66384),
(285509, 'zhTW', '', '你不覺得我們的敵人已經夠多了嗎？現在任何盟友我都樂意接受。', 66384),
(285508, 'zhTW', '目標就快達成了。我們應該在這卑鄙傢伙背叛之前先殺了他。', '', 66384),
(285507, 'zhTW', '', '麥崔恩，那只是用來分析！', 66384),
(285505, 'zhTW', '', '準備好了嗎？我們很靠近了，但我也覺得更加不安。', 66384),
(285504, 'zhTW', '', '這個地方有自己的法則…虛無可以利用的法則，我們必須學著利用的法則。', 66384),
(285503, 'zhTW', '沒有…其他辦法了嗎…？', '沒有…其他辦法了嗎…？', 66384),
(285502, 'zhTW', '虛無…毀了我們…', '虛無…毀了我們…', 66384),
(285501, 'zhTW', '', '奈薩斯王薩哈達爾統轄著剩下的影衛，也就是魯莽地運用虛無的以太族。他曾是迪曼修斯最忠心的追隨者。\n\n我們在法力熔爐歐美加擊敗他後，薩拉塔斯把他帶去了某個遙遠的界域。他和他的以太族曾暫時脫離，但很快又自願重新加入她的麾下。\n\n薩哈達爾或許曾一度自詡為征服者，但如今的他只不過是薩拉塔斯的落魄手下。', 66384),
(285500, 'zhTW', '', '我們從來沒試過把這麼多的力量注入龍鷹體內。我確定不會有事的。', 66384),
(285499, 'zhTW', '', '騎上去！她準備好出發了！', 66384),
(285498, 'zhTW', '有了你的幫忙，許多人能平安前往銀月城！', '', 66384),
(285481, 'zhTW', '戴西蒙斯似乎…過於急切地想幫我們。我並不喜歡跟動機不明的人合作。', '', 66384),
(285480, 'zhTW', '', '<艾蘭里亞先是短暫分心，然後凝視著你。>\n\n很高興能在這裡獲得支援。我們必須破壞薩拉塔斯的計畫。', 66384),
(285478, 'zhTW', '', '艾恩之塵是女神殘存的意志，化為實體。它能強化我們的魔法，讓我們能在世界之間穿梭。', 66384),
(285477, 'zhTW', '我起了雞皮疙瘩。這是怎麼回事？', '', 66384),
(285476, 'zhTW', '這裡就連天空也像是血盆大口。', '這裡就連天空也像是血盆大口。', 66384),
(285475, 'zhTW', '$p，小心。這隻野獸看起來很餓。', '$p，小心。這隻野獸看起來很餓。', 66384),
(285470, 'zhTW', '', '看啊，我們到哈朗達了。', 66384),
(285464, 'zhTW', '', '我先警告你們：我的族人不歡迎外來者。他們可能也不歡迎我了。', 66384),
(285459, 'zhTW', '我的同伴死了？這怎麼可能？', '', 66384),
(285454, 'zhTW', '筆記本？好多頁都不見了…真奇怪。我們去找奧姆里克，把這件事告訴他。', '', 66384),
(285450, 'zhTW', '', '…我老實跟你說吧。我們確實需要幫忙。我不信任你，但如果你想殺死暮光之刃，我可以跟你合作。', 66384),
(285449, 'zhTW', '姐姐，別管他們了。我們有光木。我們不需要阿曼尼之外的部族。', '', 66384),
(285432, 'zhTW', '', '就算不回答一些陌生人的問題，我也已經夠忙了。\n\n你想怎樣？', 66384),
(285428, 'zhTW', '停下來！', '', 66384),
(285426, 'zhTW', '', '納爾丁快摧毀這些聖壇了。還有在這裡棲息的鷹巢。', 66384),
(285425, 'zhTW', '聖光…燃燒著洛斯拉賽恩的憤怒…就像我父親一樣…', '', 66384),
(285424, 'zhTW', '', '那我們就必須擊敗他們。', 66384),
(285423, 'zhTW', '$n，用聖光強化我，我會試著束縛他們！', '', 66384),
(285422, 'zhTW', '', '納爾丁這種巨人通常都居住在北邊的森林洞穴裡。要是他們能乖乖待著就好了。\n\n如今他們妨礙到我，而我們時間也不多了。必須把他們解決掉。', 66384),
(285421, 'zhTW', '', '阿拉特！阻止他們！', 66384),
(285420, 'zhTW', '點亮通往神廟路上的聖壇吧。別忘了把祭品獻給阿奇爾森！', '', 66384),
(285418, 'zhTW', '', '神廟正遭到納爾丁糟蹋。殺光他們正好可以在路上消磨時間。來吧，「哈巫拉」。', 66384),
(285408, 'zhTW', '', '這對我們的研究到底有什麼幫助？', 66384),
(285407, 'zhTW', '結果太驚人了…', '', 66384),
(285377, 'zhTW', '', '艾恩之塵…長老是不會輕易交出來的。不過我們還是得試一試。', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(285370, 'zhTW', '擔心我正在計劃逃跑嗎？事實正好相反。照這種速度，你永遠擺脫不了我。', '', 66384),
(285369, 'zhTW', '', '<乍看之下，這似乎只是一朵從樹上冒出的古怪花朵。仔細一看，卻發現這朵花已經掌控所生長的屍體。那棵樹本身也似乎也是從屍體長出，而非周圍的土地。>', 66384),
(285367, 'zhTW', '<洛斯拉賽恩緊盯著前方。>', '', 66384),
(285366, 'zhTW', '這股熟悉的陰寒。它在呼喚我…', '', 66384),
(285360, 'zhTW', '', '那是…我的…一切。', 66384),
(285357, 'zhTW', '我很抱歉，但我得暫時留在這幫他。去找梅拉。畢竟她的報告比我的更完善。', '', 66384),
(285354, 'zhTW', '<西爾朗太過擔心奧斯崔，以至於沒注意到你接近。>', '', 66384),
(285353, 'zhTW', '', '$n。看到你和風行者女士回來，真是讓我鬆了一口氣。\n\n我們發現我們族人特別適合在虛無風暴生存和作戰。缺點就是我們也特別容易受到虛無之力的誘惑。', 66384),
(285351, 'zhTW', '沒關係，你慢慢休息！雖然眼前正有一支飢餓的樹人大軍正準備渡河，過來吞噬我們。', '', 66384),
(285345, 'zhTW', '', '$n，謝謝你。你幫助我的族人回到這個世界。我想女神一定很欣慰。', 66384),
(285344, 'zhTW', '歐薇娜，你今天的努力拯救了永歌森林。只要哈拉尼爾願意，他們在銀月城永遠都有一席之地。', '', 66384),
(285342, 'zhTW', '歐薇娜，你的族人拯救了我們的家園，你們也付出了慘痛的代價。我們不會忘記你做出的犧牲。', '', 66384),
(285341, 'zhTW', '我堅持你到銀月城和我一起行動。', '', 66384),
(285335, 'zhTW', '放肆的傢伙。你的反抗到此為止了。', '', 66384),
(285334, 'zhTW', '', '魯亞！艾恩哈拉的意志會與你為敵！停止你瘋狂的行徑！', 66384),
(285333, 'zhTW', '', '別怕。魯亞雖然強大，但他只有一個人。一切到此為止。', 66384),
(285332, 'zhTW', '我們從來沒有和哈拉尼爾根莖守望者戰鬥過。有什麼要注意的嗎？', '', 66384),
(285323, 'zhTW', '', '艾恩哈拉的祝福強化了我們。我們今天將為她的造物奮戰！', 66384),
(285322, 'zhTW', '阻止儀式！準備作戰！永歌森林今天不會被焚毀！', '', 66384),
(285321, 'zhTW', '', '小幼苗，援軍到了。 ', 66384),
(285320, 'zhTW', '', '哈嘉爾長老？', 66384),
(285318, 'zhTW', '可悲的歐薇娜。你無法一個人阻止光綻。', '', 66384),
(285316, 'zhTW', '', '他們的攻勢兇猛無情！艾恩哈拉，請賜給我力量！', 66384),
(285312, 'zhTW', '這不是普通的咒語！繼續發射，千萬別死了！', '', 66384),
(285311, 'zhTW', '洛摩斯，動作快啊！', '', 66384),
(285308, 'zhTW', '天真的歐薇娜。這股狂潮再也無法侵擾我們的神聖家園了。我已經讓光綻反噬它的創造者！', '', 66384),
(285307, 'zhTW', '', '根莖守望者魯亞？這是怎麼回事？', 66384),
(285304, 'zhTW', '光綻已經蔓延到河邊了。願太陽的光芒保佑我們。我們時間不多了。', '', 66384),
(285302, 'zhTW', '', '若你引爆符石，整片森林都會著火的。', 66384),
(285301, 'zhTW', '永歌森林一定會存續下去。即使它必須從自身的灰燼中重生。', '', 66384),
(285300, 'zhTW', '', '要是我能幫上更多忙…', 66384),
(285299, 'zhTW', '赫杜倫，你確定嗎？讓符石超載會將一切燒毀。', '', 66384),
(285296, 'zhTW', '這樣根本無濟於事。傳話給洛摩斯。讓博學者盡快趕到日冠樹那裡。', '', 66384),
(285295, 'zhTW', '做我該做的事。', '', 66384),
(285294, 'zhTW', '', '我們把收集來的艾恩之塵用完了。赫杜倫，你接下來打算怎麼做？', 66384),
(285291, 'zhTW', '我把能找到的助力都帶來了。', '', 66384),
(285290, 'zhTW', '', '沒有艾恩之塵，我們將面臨艱難的戰鬥。做好準備。', 66384),
(285277, 'zhTW', '沒有哈拉尼爾和他們的魔法，我們對付光綻的手段有限。', '', 66384),
(285232, 'zhTW', '', '不對。大錯特錯。', 66384),
(285231, 'zhTW', '我以為光綻能幫助聖光先鋒…但引發這一切的難道是他們？', '', 66384),
(285225, 'zhTW', '', '是魯坦尼。他們是來自我家鄉的生物。他們不該出現在這裡。', 66384),
(285224, 'zhTW', '快，這附近有個符石。我們去安全的地方好好觀察吧。', '', 66384),
(285222, 'zhTW', '我們分頭行動吧，這樣才能看到更廣的範圍。我之後再和你們會合。', '', 66384),
(285221, 'zhTW', '', '$p，我們必須找出這些生物會繁衍這麼快的原因。', 66384),
(285220, 'zhTW', '', '牠們把這裡當成自己的地盤。我們現在算是入侵者。', 66384),
(285219, 'zhTW', '這些生物似乎受到聖光的祝福，但牠們卻很…兇殘。', '', 66384),
(285217, 'zhTW', '', '那些生物…讓我想起了家園，但牠們卻生活在地表上。根本不該如此。', 66384),
(285216, 'zhTW', '母親說你對荒野很熟悉。你對這種現象有什麼看法？', '', 66384),
(285212, 'zhTW', '', '你描述的光綻顯然已經失控了。我們必須找出背後的原因。', 66384),
(285211, 'zhTW', '', '博學者，你是從什麼時候開始注意到光綻的弊端？', 66384),
(285203, 'zhTW', '你是歐薇娜，對吧？我的母親艾蘭里亞有跟我提過你。', '', 66384),
(285202, 'zhTW', '用這個秘法投射器來和我們聯絡。', '', 66384),
(285201, 'zhTW', '阿拉特，太陽之井這裡可能需要你。', '', 66384),
(285179, 'zhTW', '我們根本不需要你！', '', 66384),
(285178, 'zhTW', '這輪不到你來決定！', '', 66384),
(285156, 'zhTW', '', '成功了！我們終於有機會反擊了。', 66384),
(285154, 'zhTW', '', '有了艾恩哈拉的恩賜，艾恩之塵能像保護艾歐卡一樣，保護這些魯坦尼。', 66384),
(285153, 'zhTW', '它來自上空。幾天之內就控制了整個夏達希爾。', '', 66384),
(285149, 'zhTW', '', '阿瑪拉克，謝謝你。我欠你很大的人情。', 66384),
(285145, 'zhTW', '這些能讓我們有機會擊敗化身。', '', 66384),
(285143, 'zhTW', '那些化身帶來極大的威脅，但它們也是獲得艾恩之塵的主要來源。', '', 66384),
(285142, 'zhTW', '在裂隙的黑暗深處，艾恩之塵會在你面前凝聚成怪物。', '', 66384),
(285140, 'zhTW', '不見了。被偷走了！她去哪了？', '', 66384),
(285139, 'zhTW', '', '昂錫爾？天哪！', 66384),
(285138, 'zhTW', '', '不！女神啊！她…她…阿瑪拉克？$n？', 66384),
(285137, 'zhTW', '你找到了自我。很好。但你的朋友就沒那麼幸運了。', '', 66384),
(285136, 'zhTW', '焦黑的樹根。歐薇娜，專心點！聆聽我的聲音！', '', 66384),
(285133, 'zhTW', '', '朋友，我跟隨著聲音飄盪。她安撫我。她接納我。我…', 66384),
(285132, 'zhTW', '', '他不在這裡。這個結界…$n，我需要更多艾恩之塵。動作快。', 66384),
(285131, 'zhTW', '', '這只是個模仿蘇卡獻祭的儀式。它的效果並非永久，也稱不上完美。我們必須盡快找到阿瑪拉克。', 66384),
(285129, 'zhTW', '', '她的聲音消失了。我從未感到如此孤獨。這就是阿瑪拉克的日常嗎？', 66384),
(285122, 'zhTW', '如果你堅持這麼做，那就需要艾恩之塵來保護你的心智與靈魂。', '', 66384),
(285118, 'zhTW', '過了這麼久，你回來只是為了進到裂隙裡？歐薇娜，你一點都沒變。', '', 66384),
(285115, 'zhTW', '當女神被從育所強行分離時，留下了無法治癒的傷痕。', '', 66384),
(285114, 'zhTW', '她痛苦的尖叫聲讓無形的恐懼化為實體，那些膽敢進入的人也因此發瘋。', '', 66384),
(285112, 'zhTW', '她比任何人都清楚，收集艾恩之塵要付出的代價。如果她想這樣浪費，那她可以自己去裂隙收集。', '', 66384),
(285110, 'zhTW', '你要我們把艾恩之塵分給外來者？太荒謬了！', '', 66384),
(285109, 'zhTW', '', '到大巢穴周遭問問看。看能不能取得什麼情報。', 66384),
(285104, 'zhTW', '我們其他人會回到銀月城。還有很多事…要討論。', '', 66384),
(285103, 'zhTW', '莉雅德倫女士，守住小徑。無論結果好壞，我們都在這裡奮戰過了。我們必須守住這裡。', '', 66384),
(285102, 'zhTW', '勇士！我們包圍祖爾詹了。是時候終結這場入侵了！', '', 66384),
(285101, 'zhTW', '可惡的阿曼尼！我會以聖光之名淨化這些怪物！', '', 66384),
(285098, 'zhTW', '這場殺戮…太瘋狂了。我的父親在哪？他肯定看到這一切了！', '', 66384),
(285097, 'zhTW', '是暮光之刃！他們才是真正的威脅！', '', 66384),
(285093, 'zhTW', '', '阿拉特，已經太遲了。但我們可以治療其他人。', 66384),
(285092, 'zhTW', '我們必須阻止他們！', '', 66384),
(285086, 'zhTW', '如果你不想戰鬥，那就別來礙事！', '', 66384),
(285083, 'zhTW', '快，我們必須趕到阿曼尼小徑，然後告訴他們事情的真相！', '', 66384),
(285080, 'zhTW', '哈！你成功了！', '', 66384),
(285079, 'zhTW', '更多的魔法障礙。這些石磚或許有什麼蹊蹺。', '', 66384),
(285073, 'zhTW', '我想阿曼尼根本不希望見到任何不速之客。幸好這些結界都很老舊。', '', 66384),
(285072, 'zhTW', '如果他們的戒備這麼森嚴，那我們就得謹慎行事。跟我來，別出聲。', '', 66384),
(285071, 'zhTW', '就是這裡…看來這裡受到符文和結界的保護。', '', 66384),
(285043, 'zhTW', '莉雅德倫，謝謝你。希望赫杜倫能告訴我們發生什麼事。', '', 66384),
(285042, 'zhTW', '', '我會安置好這裡的倖存者。', 66384),
(285041, 'zhTW', '', '北方傳來倒塌聲，然後…四處就都是光綻了！', 66384),
(285040, 'zhTW', '聽起來好像有人把樹砍倒了。遠行者已經去調查了。', '', 66384),
(285039, 'zhTW', '', '光綻原本在河的另一端。怎麼會蔓延到這裡？', 66384),
(285038, 'zhTW', '', '這裡就像被荒野吞噬了一樣。', 66384),
(285037, 'zhTW', '', '聖光啊…', 66384),
(284695, 'zhTW', '', '我們…我們是朋友。他不信任虛無是合情合理的。我只希望他願意信任我。', 66384),
(284694, 'zhTW', '我還以為你和洛斯拉賽恩是朋友。', '', 66384),
(284693, 'zhTW', '準備好你的武器。不要相信虛無的一切。', '', 66384),
(284689, 'zhTW', '', '安諾里恩領主不在。我可以代為效勞。', 66384),
(284688, 'zhTW', '感覺事有蹊蹺。去看看她剛才在把玩的帶鎖箱裡有什麼。', '', 66384),
(284686, 'zhTW', '', '安諾里恩領主是個大忙人。在我們周圍的奎爾薩拉斯地區全部淪為廢墟的時候，還有誰能保障安寧地的安全呢？\n\n或許我可以代替他幫助你？', 66384),
(284685, 'zhTW', '昨晚有個虛無女精靈從這裡跑出去，好像在逃離什麼一樣。', '', 66384),
(284684, 'zhTW', '這聽起來是凱西雅沒錯。不知道她有沒有留下什麼東西？我們去看看吧。', '', 66384),
(284681, 'zhTW', '旅行者，希望安寧地能給你你在尋找的一切。', '', 66384),
(284664, 'zhTW', '', '世界的歌聲請我來到這裡。我暫時只知道這麼多。', 66384),
(284658, 'zhTW', '', '我聽見世界的歌聲，於是我響應了。', 66384),
(284646, 'zhTW', '我們把這些帶回我的研究室吧。', '', 66384),
(284645, 'zhTW', '這是最後一個樣本了。這一切究竟是為了什麼？', '', 66384),
(284644, 'zhTW', '成功了！看看那個東西有多大！', '', 66384),
(284642, 'zhTW', '凱西雅…妳到底打算做什麼？', '', 66384),
(284632, 'zhTW', '我們去看看最後一個地點。', '', 66384),
(284631, 'zhTW', '她想透過虛無風暴本身來召喚嗎？但是為了什麼？', '', 66384),
(284630, 'zhTW', '有更多怪物！', '', 66384),
(284628, 'zhTW', '虛無風暴對這裡的影響更強烈。情況可能會變得很危險。', '', 66384),
(284358, 'zhTW', '感謝你為族人提供的幫助。', '感謝你為族人提供的幫助。', 66384),
(284357, 'zhTW', '歡迎，陌生人。把這裡當自己家。', '歡迎，陌生人。把這裡當自己家。', 66384),
(284347, 'zhTW', '是虛無能量的樣本。很好。先收好這個，我們再去別的地方看看。', '', 66384),
(284346, 'zhTW', '有裂隙！', '', 66384),
(284345, 'zhTW', '凱西雅的筆記似乎都和…召喚有關？我們來瞧瞧。', '', 66384),
(284343, 'zhTW', '我們並肩作戰吧。我不會丟下你的。', '', 66384),
(284342, 'zhTW', '', '我真希望圖拉揚也在這。洛斯拉賽恩可能會聽他說的話。', 66384),
(284341, 'zhTW', '洛斯拉賽恩的那個眼神，跟我在父親眼中看到的一樣。', '', 66384),
(284340, 'zhTW', '', '沒時間閒聊了。我們必須趕快行動！ ', 66384),
(284339, 'zhTW', '別急，你這禽獸。你騙過了艾蘭里亞，但我能看透你。', '', 66384),
(284338, 'zhTW', '你感覺到了嗎？披肩就近在咫尺。', '', 66384),
(284335, 'zhTW', '死了！而且發瘋的不只庫札特！', '', 66384),
(284334, 'zhTW', '', '薩拉塔斯利用黑暗之心和這個領域的力量，打造出她的虛無之尖。\n\n所有這些能量的湧動形成了虛無風暴。我很快就發現她將風暴引向太陽之井。\n\n當然，我想前去援助銀月城，但那裡不歡迎我…而且我在這裡能發揮更多作用。', 66384),
(284332, 'zhTW', '', '自從我們第一次知道黑暗之心以來，我一直在追捕薩拉塔斯。在她離開卡茲阿爾加後，我追著她到凱瑞西，在那裡，她試圖防止迪曼修斯的回歸。\n\n即使在艾澤拉斯的英雄被調去防守銀月城時，我還是繼續追著她。我不會放過她。\n\n她讓以太族影衛重回她的麾下。當她打開道路，讓他們來到這個陌生的地方時，我也趁機過來。\n\n在這個風暴的混亂中，我找不到回去的路。但我也不需要回去。因為我的獵物在這裡。', 66384),
(284328, 'zhTW', '我有很多身分，凡人。我是納斯雷茲姆，是惡魔，也是死亡。但最重要的是，我是光鑄德萊尼。\n\n我們一族，納斯雷茲姆，或稱驚懼領主，最為人熟知的是我們的變形術、詐欺，還有…多變的忠誠。\n\n有一段時間，我在燃燒軍團與我的族人並肩作戰。我聽從我們真正的、致命的主人的命令，盡責地將報告送給他。我們什麼都不在乎，只關心虛無的毀滅，即便是以世界為代價。\n\n然後我遇見德萊尼。我看見他們的聖光。我才明白，徹底擊敗虛無的唯一方式是擁抱虛無的對立面。與聖光合而為一。\n\n其他的納斯雷茲姆未能理解。於是我離開他們。聖光才是我唯一的道路。', '', 66384),
(284324, 'zhTW', '艾歐卡，生長在綻放臺地。交易來自艾恩裂隙的種子正是在下在這裡的原因。', '', 66384),
(284323, 'zhTW', '你好。願這個陌生人的根扎得更深。帶了種子來進行交易嗎？', '', 66384),
(284321, 'zhTW', '沒有光綻。這個陌生人該交換點東西，不然就走開。', '', 66384),
(284320, 'zhTW', '陌生人是來跟在下交易嗎？', '', 66384),
(284315, 'zhTW', '如果陌生人有東西想交易，就找在下。', '', 66384),
(284303, 'zhTW', '這是我第三次被搶了！', '', 66384),
(284301, 'zhTW', '鎮上的所有人都在擔心天上的那個東西。', '', 66384),
(284298, 'zhTW', '可疑？你是指籠罩在我們上面的巨大虛無風暴嗎？我也不清楚。', '', 66384),
(284296, 'zhTW', '怎麼了？最近我有很多事要忙。', '', 66384),
(284289, 'zhTW', '我在星外暗界見識了數百個，不，數千個世界。\n\n我們對抗燃燒軍團。而這些世界陷入戰火和黑暗。\n\n不過還是沒有一個像這個一樣。這個令人不愉快的感受，這股陰寒。\n\n這裡有更加黑暗的事物。薩拉塔斯。', '', 66384),
(284286, 'zhTW', '', '跟我來。森林部族的領袖們已經集結，來討論我們的戰爭計畫了。', 66384),
(284285, 'zhTW', '許多人會質疑我允許刃多雷進入銀月城的決定，更不用說還讓他們離太陽之井這麼近。對於他們對那些選擇追尋達克汗‧崔希爾腳步的人的憤怒和恐懼，我比任何人都還要了解。\n\n達克汗曾經是我的朋友。他的背叛所帶來的痛苦仍讓我心如刀割。\n\n然而，也有許多人質疑當初流放刃多雷的決定。這些精靈有家人，有朋友。並非所有人都認為他們迷失了。\n\n今非昔比，我們禁不起分裂。', '', 66384),
(284279, 'zhTW', '不管你出身哪裡，我賣東西一視同仁。', '', 66384),
(284270, 'zhTW', '我們不會讓陌生人留在這裡。但我想我可以破例一次。', '', 66384),
(284260, 'zhTW', '包括我自己在內，許多刃多雷都曾在博學者殿堂研究魔法。那曾是我們的家。洛摩斯曾是我的同學。\n\n我覺得我們必須了解我們的敵人，才能擊敗他們。於是我帶領一群研究人員研究虛無。我們發現了達克汗‧崔希爾的日誌，也就是那個背叛銀月城、投靠巫妖王的精靈。在第三次大戰中，他的行動導致許多我們珍視的事物毀於一旦。而他對虛無的研究促成了這個結果。\n\n所以，你可以理解，即使血精靈使用魔能等危險魔法的歷史很漫長，我的研究卻還是遭到指責。我們拒絕停止，於是就遭到流放。\n\n我不後悔自己的選擇，雖然這讓我的同伴飽受折磨。', '', 66384),
(284258, 'zhTW', '', '虛無和聖光並不一定一直彼此對立。我的信念讓我不受虛無的邪惡影響。\n\n而且它會讓我不受風暴另一邊的事物影響。這點你可以相信我。', 66384),
(284257, 'zhTW', '<你靠近時，安靜檢查同伴裝備的西爾朗抬頭看向你。>\n\n啊，$n。我們的秘密武器。你讓我確信我們不會都被派去送死。銀月城一大半的人很可能會認可那個計畫。虛無最近太落伍了，不論是虛無風暴或虛無精靈都一樣。\n\n我個人希望他們會改變立場。對我們的立場。我們來給他們改變的理由吧。', '', 66384),
(284256, 'zhTW', '不久之前，我還把這個地方當成家。大家都對我深負厚望。我被重視，被需要…直到我的天賦讓我的人生偏離原本為我規劃好的道路。直到我對他們吐露真正的自我的那一刻。\n\n<奧斯崔一臉苦澀地看向天空。>\n\n我不是來這裡救他們。我要他們親眼見證，知道當初他們錯了。', '', 66384),
(284255, 'zhTW', '我上次看見銀月城被戰火波及的時候，那時我是遠行者的副官。我記得自己與同袍就像這樣，肩並著肩一起站在城牆上。前線傳來消息：遊俠將軍死了。我們沒半個人相信。直到不死族從林地傾巢而出…\n\n<賽德拉斯搖搖頭。>\n\n現在的感覺也一樣。$p，有些事是不是永遠不會變？', '', 66384),
(284254, 'zhTW', '', '我曾經是破法者。博學者殿堂是我的家。\n\n為了幫助我的族人，我研究虛無，但我從未想過與它融為一體。我從未想過離開我的家。\n\n洛摩斯聽了嗎？其他博學者理解嗎？沒有。\n\n<梅拉沉下臉。>', 66384),
(284252, 'zhTW', '戴西蒙斯彎曲手指，悄悄地示意你。', '', 66384),
(284248, 'zhTW', '特別是你，$r。別以為我把你給忘了。', '', 66384),
(284216, 'zhTW', '光綻的擴散突如其來。你懷疑是商人搞的鬼嗎？它感受到威脅嗎？它有感覺能力嗎？\n\n有許許多多的問題，不過，我覺得我們離答案越來越近了。', '', 66384),
(284178, 'zhTW', '', '庫札特平常很老實，但一受到刺激就會變得很危險。$n，要小心。', 66384),
(284160, 'zhTW', '剩下的就交給秘境的員工。秘境護罩很敏感。有空再來，到時候可能又需要你幫忙了。', '', 66384),
(284159, 'zhTW', '來得正好！虛無孢子再次穿過我們的護罩。我們必須清除乾淨，以免生態系受到感染。', '', 66384),
(284116, 'zhTW', '雖然我的家園被摧毀，但我是不會坐以待斃的！', '', 66384),
(284092, 'zhTW', '我們不能留在這裡，我必須去銀月城！', '我們不能留在這裡，我必須去銀月城！', 66384),
(284078, 'zhTW', '', '我們本來打算離開這裡，但卻被從四面八方夾擊。\n\n我不想知道那底下的究竟是什麼東西，但那是我們唯一的出路了！', 66384),
(284072, 'zhTW', '外面那頭沉睡的野獸？牠看起來那麼溫馴…我總覺得事有蹊蹺。', '', 66384),
(284071, 'zhTW', '庫札特發狂了！', '', 66384),
(284068, 'zhTW', '需要的都到手了。拯救城市之後再為你的朋友哀悼吧。', '', 66384),
(284066, 'zhTW', '', '你準備好了嗎？', 66384),
(284038, 'zhTW', '發生什麼事了？這也太恐怖了！', '發生什麼事了？這也太恐怖了！', 66384),
(284037, 'zhTW', '拜託幫幫我，我得離開這裡！', '拜託幫幫我，我得離開這裡！', 66384),
(284034, 'zhTW', '有一艘船要出發去銀月城了。我不能留在這裡，我必須上船！', '有一艘船要出發去銀月城了。我不能留在這裡，我必須上船！', 66384),
(283974, 'zhTW', '這些夢魘無所不在！我覺得我撐不下去了！', '這些夢魘無所不在！我覺得我撐不下去了！', 66384),
(283970, 'zhTW', '', '我的家園…現在怎麼辦？', 66384),
(283963, 'zhTW', '我先去探路，等你準備好了再跟上。', '', 66384),
(283956, 'zhTW', '滾！我不會再讓你進到城裡工作了！', '', 66384),
(283954, 'zhTW', '$n，等等。這裡有一具遺體。她手裡握著的是什麼？', '', 66384),
(283921, 'zhTW', '餓！好…餓啊…', '', 66384),
(283920, 'zhTW', '更多大餐！', '', 66384),
(283916, 'zhTW', '如果你想繼續送那魯去奧核點，請自便。', '', 66384),
(283857, 'zhTW', '我們在前線之外的地方也能做出更多貢獻，或許還能防止一些傷亡。我知道虛無的運作方式，而你是一名傳奇人物。', '', 66384),
(283852, 'zhTW', '歡迎來到銀月城。', '', 66384),
(283851, 'zhTW', '<洛摩斯用鄙視的目光瞪著你。>', '', 66384),
(283845, 'zhTW', '銀月城感謝你的支援。', '', 66384),
(283832, 'zhTW', '聖光過去曾經照耀這個地方嗎？\n\n如此邪惡的黑暗。這裡的生物在其中狂歡。我們必須保持警戒，確保我們受虛無影響的盟友不會臣服於此處力量的誘惑…', '', 66384),
(283796, 'zhTW', '法林，你去支援聖光先鋒吧！我會護送大家到太陽之井。', '', 66384),
(283795, 'zhTW', '我們必須撤離傷患！', '', 66384),
(283794, 'zhTW', '', '安杜因，謝謝你。願聖焰保護我們。', 66384),
(283793, 'zhTW', '', '聖光會守護先祖的土地！', 66384),
(283775, 'zhTW', '我確定洛斯拉賽恩也這麼覺得。', '', 66384),
(283774, 'zhTW', '', '把我的報告帶去給洛索瑪。告訴他…我們做了該做的事。', 66384),
(283771, 'zhTW', '阻止那個聖光中毒的傻子吧。之後我再和你們會合，用披肩削弱風暴。', '', 66384),
(283766, 'zhTW', '小哈巫拉，你不知道為了等我的玩伴向我證明自己後回歸，我已經等多久了。\n\n祖爾金和瑪拉克雷斯在多年前背叛了我，我回到這裡之後一直在觀察、等待、治癒…祈禱一位哈謝的到來…\n\n之後我的玩伴遭到攻擊。還有我的幼崽。\n\n我本已經放棄希望了。', '', 66384),
(283755, 'zhTW', '', '找到那個老糊塗。我會好好唸唸他，叫他別再逞英雄了。', 66384),
(283754, 'zhTW', '', '我跟西爾朗和暗幽谷女士走散了。你得找到他們。', 66384),
(283753, 'zhTW', '太好了。告訴奧斯崔我很抱歉。我可能沒辦法回去喝茶了。', '', 66384),
(283752, 'zhTW', '', '不，你別想奪走！', 66384),
(283751, 'zhTW', '', '我會把你餵給野獸。', 66384),
(283749, 'zhTW', '摧毀她的玩具，直搗食物鏈頂端。我們親愛的托倫提亞會把這當作是個挑戰。', '', 66384),
(283748, 'zhTW', '你進來了。找到貨物。', '', 66384),
(283739, 'zhTW', '', '許多人看到那魯，都會認為那是聖光的化身。不過，我很清楚，不能如此輕易定義他們。\n\n你看到我使用的魔法能力並非我與生俱來。我從黑暗的那魯路拉那裡取得真正的力量，而她現在就寄宿在我體內。她是我虛無力量的主要來源。\n\n駕馭她是一段漫長又艱難的旅程，一段賜予我力量保護所珍視的一切的旅程。\n\n洛斯拉賽恩認為有那魯站在我們這邊，就能在對抗薩拉塔斯時佔上風，這個想法是對的。', 66384),
(283738, 'zhTW', '', '經過這麼長一段時間，再次與兒子相聚。我很高興。但是我希望…\n\n<艾蘭里亞突然移開視線，瑟縮了一下。她嘆了口氣，擺脫情緒。>\n\n沒有時間了。我們所有人都必須專注在任務上。', 66384),
(283735, 'zhTW', '', '<艾蘭里亞的眼睛來回探查。>\n\n注意天空！這裡沒有一個安全的地方。\n\n我感應到騷動，以為還有更多薩拉塔斯的部隊。結果，居然是你…還有阿拉特。\n\n不久前，我追著薩拉塔斯和她的以太族來到這個奇怪的地方。我一直在追殺她，不過…\n\n<艾蘭里亞陷入沉思，你注意到她散發淡淡的紫色光暈。>\n\n這裡的虛無如此強大。令人…分心。令人陶醉。\n\n不過你在這裡。阿拉特也在這裡。我們必須小心一點。', 66384),
(283721, 'zhTW', '不！我們必須集中兵力發起反攻！', '', 66384),
(283713, 'zhTW', '旅途既漫長又艱難。一路上，我們面對許多險阻。', '', 66384),
(283712, 'zhTW', '並非所有人都回應了女神的召喚，但是哈拉提選擇跟隨歌聲。', '', 66384),
(283695, 'zhTW', '太多…太多虛無了！', '', 66384),
(283691, 'zhTW', '這裡是設置傳送門最穩定的地點了，但有戴西蒙斯的野獸擋路。', '', 66384),
(283686, 'zhTW', '我需要我的法杖。要是我在戰鬥中拋下法杖，阿奇爾森就不會祝福我了！', '', 66384),
(283685, 'zhTW', '陌生人，謝謝你的幫忙。', '', 66384),
(283684, 'zhTW', '', '希望祖爾詹有帶更多光木回來。我不想再靠剩下的碎片做事了。', 66384),
(283682, 'zhTW', '嗯。我應該祈求阿奇爾森或哈拉齊的銳眼來驅散遮蔽視線的東西？\n\n何不兩者都祈求呢？對，沒錯。何不呢？', '', 66384),
(283676, 'zhTW', '<托倫多用懷疑的目光看著你，並且挪動著身體，彷彿在隱藏身後的東西。>\n\n你又是誰？\n\n離開阿塔阿曼的時候到了嗎？', '', 66384),
(283675, 'zhTW', '', '<多魯長老正忙於從一輛被拋棄的貨車上收集光木武器。>\n\n我聽到了戰鼓聲，但我們不能丟下這些武器。', 66384),
(283664, 'zhTW', '', '我們可以分頭行動，擴大範圍。$n和我會…', 66384),
(283662, 'zhTW', '', '不。精靈要是踏進祖阿曼，隨時有可能被殺掉。你跟我來。詹，盯好她的朋友。', 66384),
(283656, 'zhTW', '', '暮光之刃把納爾丁趕進我們的領地。我們得殺出一條通往神廟的生路。', 66384),
(283632, 'zhTW', '在和平的時代，我們感覺到空虛。我們渴望有個目標。', '', 66384),
(283630, 'zhTW', '', '我們筋疲力盡、遭受重創。我們贏下了和莫爾頓的戰鬥，但也有所損失。我們該怎麼打贏下一場戰鬥？', 66384),
(283628, 'zhTW', '孩子，戰爭容不下脆弱的心靈。', '', 66384),
(283627, 'zhTW', '$p，西爾朗在哪裡？難道他…？', '', 66384),
(283620, 'zhTW', '我們和最凶狠的掠食者搏鬥，最終將牠們馴服。', '', 66384),
(283619, 'zhTW', '我們成為了森林裡最強大的獵人。', '', 66384),
(283615, 'zhTW', '當務之急是撤離平民！', '', 66384),
(283614, 'zhTW', '', '我們祈禱奇蹟發生，而聖光先鋒回應了號召。但戰鬥還沒有結束。', 66384),
(283604, 'zhTW', '沒有人知道我們的存在。就連能撼動大地的巨人…或龐大的野獸都不知道。', '', 66384),
(283603, 'zhTW', '好幾個世代以前，我們的族人就生活在巨山的樹下。', '', 66384),
(283589, 'zhTW', '你看過那張紙條了嗎？看來我們有另一件…事務要去處理。', '你看過那張紙條了嗎？看來我們有另一件…事務要去處理。', 66384),
(283549, 'zhTW', '我試著替其他人爭取生機。\n\n<西爾朗重重地喘息著。>\n\n如果不是最後又出現了一些，不然我差點就成功了。他們順利逃生了嗎？', '', 66384),
(283540, 'zhTW', '$n，我已經聽說你會來了。我們開始吧。', '', 66384),
(283531, 'zhTW', '', '如果不是西爾朗引開牠們，我早就被極限獸襲擊了。\n\n他揭開的虛無，就像是一道陰影。', 66384),
(283529, 'zhTW', '', '我們一通過主門，極限獸就立刻聞到我們的氣味。我們被隔開了，洛斯拉賽恩甚至沒回頭看。', 66384),
(283528, 'zhTW', '你聽說了嗎？薄暮飛行出口現在就停泊在碼頭。', '你聽說了嗎？薄暮飛行出口現在就停泊在碼頭。', 66384),
(283527, 'zhTW', '你見過沒有渾身上下都是秘密的潮裔船員嗎？', '你見過沒有渾身上下都是秘密的潮裔船員嗎？', 66384),
(283503, 'zhTW', '更多的力量。萬物都會回歸虛無。', '', 66384),
(283462, 'zhTW', '', '我了解光綻帶來的威脅，但我們必須安撫長老，否則你們在哈朗達會腹背受敵。', 66384),
(283437, 'zhTW', '那魯自聖光誕生，能為凡人脆弱的內心帶來希望和力量。他們是人世中的神，地位高於你和我。\n\n我不清楚以太族或吞噬之眾是從哪裡抓到那魯。也許是從遙遠的世界竊取，或是從無比古老的德萊尼分支陣營俘虜。該死的變節者。不過，比起眼前的狀況，那個異端不值一提。\n\n我們必須出手援助這個那魯，以免發生更糟糕的事。只要那魯的光輝與我們同在，虛無風暴的終結就是必然的結果。', '', 66384),
(283434, 'zhTW', '不能浪費時間了。再拖下去，可能就無力回天。', '', 66384),
(283426, 'zhTW', '這個「光綻」根本就不算威脅。它不能成為你異端行為的藉口。', '', 66384),
(283423, 'zhTW', '', '$n會找到他們。我們必須把你送到安全處。', 66384),
(283416, 'zhTW', '歐薇娜？這些人是…你做了什麼？', '', 66384),
(283414, 'zhTW', '我不記得上次我被像這樣束縛是什麼時候。而且還以這麼新奇的方式！\n\n你覺得我們現在應該如何稱呼這種材料？光芽？現在想來，這跟你朋友的光鑄沒有什麼不同。', '', 66384),
(283411, 'zhTW', '我應該問你同樣的問題！在已知的記憶中，從來沒有外來者踏足樹根的深處。\n\n<他瞇起眼睛，然後看了歐薇娜一眼。>\n\n我是庫帕爾，哈拉希爾的根莖守望者。我的職責是照顧新長出來的巨大樹根…直至世界之樹的最遠端，也就是地表居民所說的埃達希爾。', '', 66384),
(283407, 'zhTW', '噢，我也才剛暖好身而已。', '', 66384),
(283406, 'zhTW', '', '好吧，但那些獵物都是我的！可別搶走我的功勞。', 66384),
(283404, 'zhTW', '', '當你在咆哮峰的時候，我們擅自進行了偵察。這裡聚集了不少虛無生物，讓人很不安。', 66384),
(283403, 'zhTW', '', '這些樹根是由哈拉希爾的居民照顧的。算是一條捷徑。', 66384),
(283402, 'zhTW', '', '小心行事。你會被視為入侵者。', 66384),
(283398, 'zhTW', '你做了正確，也是唯一的決定。現在我們可以展開反擊了。', '', 66384),
(283379, 'zhTW', '', '我們必須阻止他。梅拉，讓其他人回去咆哮峰。', 66384),
(283378, 'zhTW', '如果他傷了奧核點，產生的能量脈衝就會摧毀你們寶貴的銀月城。', '', 66384),
(283368, 'zhTW', '艾蘭里亞，你瘋了嗎？', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(283367, 'zhTW', '', '這全是戴西蒙斯的計畫。讓特蒙諾斯顧著監視我們，$p。', 66384),
(283364, 'zhTW', '互相殘殺，或者受死。我會剷除這些弱小的障礙。', '', 66384),
(283363, 'zhTW', '我就知道你們完全沒有察覺虛無的詭計！', '', 66384),
(283362, 'zhTW', '', '事情不太對勁。戴西蒙斯不可能會錯過這種景象。', 66384),
(283361, 'zhTW', '我不明白。他明明隨時可以背叛我們的。', '', 66384),
(283360, 'zhTW', '信任戴西蒙斯簡直是瘋了！', '', 66384),
(283357, 'zhTW', '', '準備好武器。我們得殺出一條生路，事後再找戴西蒙斯算帳。', 66384),
(283356, 'zhTW', '', '我遺漏什麼了嗎？為什麼他等到現在才背叛我們？', 66384),
(283349, 'zhTW', '取得披肩吧。我們會掩護你的。', '', 66384),
(283348, 'zhTW', '', '一起行動。不要單獨作戰，也不會有人落單。', 66384),
(283347, 'zhTW', '那就別對犧牲麻木了！我們都為了相同的目的而戰。', '', 66384),
(283346, 'zhTW', '我侍奉聖光上千年了。我比你還要更加了解所謂的犧牲。', '', 66384),
(283345, 'zhTW', '聖光也不是完美無害的。我感受過它的憤怒。也見識過聖光讓我們做出的犧牲。', '', 66384),
(283344, 'zhTW', '它只會造成腐化，讓盟友反目、扭曲是非和對錯。', '', 66384),
(283343, 'zhTW', '虛無不為任何人效忠！', '', 66384),
(283342, 'zhTW', '危險？比起我，你更信任一個多曼納爾。', '', 66384),
(283341, 'zhTW', '', '洛斯拉賽恩，待在這吧。你已經讓這次任務陷入危險了。', 66384),
(283339, 'zhTW', '這是可以接受的損失。虛無精靈很清楚風險。', '', 66384),
(283338, 'zhTW', '', '你拋棄了他們？', 66384),
(283337, 'zhTW', '真是感人。友善建議：永遠別相信假裝順從的多曼納爾。', '', 66384),
(283336, 'zhTW', '', '等等！我認輸。讓我侍奉你吧。我們能一起…', 66384),
(283335, 'zhTW', '', '挑戰托倫提亞，奪取她的符印。阿拉特，我們去堡壘上層跟其他人會合吧。', 66384),
(283333, 'zhTW', '有些俘虜不是艾澤拉斯來的。究竟有多少世界受到虛無的殘忍侵略？', '', 66384),
(283332, 'zhTW', '', '女士，我們會跟著他的。刃多雷，跟我來。', 66384),
(283331, 'zhTW', '', '現在不是讓你獨自行動的時候！', 66384),
(283330, 'zhTW', '我去獵捕賽維朗。你跟這個虛無生物負責攻略戰壕。', '', 66384),
(283329, 'zhTW', '', '托倫提亞控制著戰壕，賽維朗負責守衛堡壘上層。', 66384),
(283328, 'zhTW', '', '特蒙諾斯不在時，由他的副官負責看守保險庫。', 66384),
(283327, 'zhTW', '宇宙是場盛宴，聖光小子。為何不盡情享受？', '', 66384),
(283326, 'zhTW', '某些人的目的可比飢餓更崇高，禽獸。', '', 66384),
(283325, 'zhTW', '我不需要主人。所有人都應該順從自己的胃口。', '', 66384),
(283324, 'zhTW', '虛無毫無忠誠可言，你因為無聊就想背叛主人？', '', 66384),
(283323, 'zhTW', '她會讓一切都變成空無。還有什麼比這更無趣的嗎？', '', 66384),
(283322, 'zhTW', '薩拉塔斯會吞噬你們的世界。所有的世界。連繁星也是。', '', 66384),
(283321, 'zhTW', '看你們這樣燃燒生命，拼命對抗無情的宇宙…太美妙了。', '', 66384),
(283320, 'zhTW', '空虛無意義的生物。就跟其他虛無惡魔一樣。', '', 66384),
(283319, 'zhTW', '我是激情構成的生物。', '', 66384),
(283318, 'zhTW', '你為何這麼積極幫我們？', '', 66384),
(283316, 'zhTW', '偷取掠食披肩，進入奧核點，削弱風暴。特蒙諾斯將會蒙羞。', '', 66384),
(283315, 'zhTW', '運氣不錯，他在這有事忙著，保險庫沒人看守。', '', 66384),
(283314, 'zhTW', '特蒙諾斯「領主」。他把披肩藏在朧暗堡壘。', '', 66384),
(283313, 'zhTW', '有了它，你就能進入奧核點，直接將它關閉。同時也能讓其他的奧核點跟著關閉。', '', 66384),
(283312, 'zhTW', '削弱風暴的關鍵，是一個稱為掠食披肩的神器。', '', 66384),
(283311, 'zhTW', '然後釋放能量脈衝消滅銀月城？安全關掉奧核點，饒過你的城市吧。', '', 66384),
(283310, 'zhTW', '為什麼只是關閉奧核點？我們應該從內部展開攻擊。', '', 66384),
(283307, 'zhTW', '$p，來吧，我有好多東西要讓你看看。', '', 66384),
(283306, 'zhTW', '把這裡當自己家吧。我們再來談怎麼削弱風暴。', '', 66384),
(283305, 'zhTW', '啊，大家都到齊了。要是時間允許，我真想邀請各位共進晚餐。', '', 66384),
(283303, 'zhTW', '你想跟著這個生物去它可怕的巢穴？', '', 66384),
(283197, 'zhTW', '我們的人都被薩拉塔斯控制了。', '我們的人都被薩拉塔斯控制了。', 66384),
(283190, 'zhTW', '', '詹，當戰鼓聲一響，援軍就會進攻中央祭壇。', 66384),
(283179, 'zhTW', '', '聖焰在上，我們差點就被吞噬之眾擊垮了。我成功擊退了黑暗的浪潮，好讓安杜因可以治療傷員。\n\n我很高興能看到還有其他人受到召喚，前來保衛這個聖地。我能幫上什麼忙？', 66384),
(283177, 'zhTW', '$p，真高興見到你！\n\n聖光在這片黑暗和虛無之中燃燒得格外耀眼，你說是吧？我的不死族皮膚總是能感受到聖光帶來的痛楚，但比起我，吞噬宿主更容易受到它的怒火所影響。', '', 66384),
(283169, 'zhTW', '$p！看來聖光召喚來的不只有它的追隨者，還有艾澤拉斯的勇士。\n\n我本以為自己陷入了孤立無援、寡不敵眾的局面，不過只要有你在，我們或許能轉而發動攻擊！', '', 66384),
(283168, 'zhTW', '', '有隻虛無獸！小心！', 66384),
(283159, 'zhTW', '這座城市會畏懼虛無風暴是有原因的。', '', 66384),
(283125, 'zhTW', '要是敢擅自亂動，我就用聖光燒死你，惡魔。', '', 66384),
(283123, 'zhTW', '真是強大的力量與智慧！看來反抗似乎不太明智！', '', 66384),
(283120, 'zhTW', '不！別讓它跑了！ ', '', 66384),
(283119, 'zhTW', '哎呀，真是場美妙的浴血之戰！但我必須先告辭了。', '', 66384),
(283118, 'zhTW', '$p，拿下它的寵物！ ', '', 66384),
(283117, 'zhTW', '艾澤拉斯人！噢，你們會是精美的戰利品。', '', 66384),
(283113, 'zhTW', '你想抓它當俘虜？我看不如直接燒了它。', '', 66384),
(283112, 'zhTW', '', '他們還會銬住同類？有意思。有些看起來甚至心甘情願。 ', 66384),
(283111, 'zhTW', '$p，這些邪惡的生物不是我們的對手！ ', '', 66384),
(283110, 'zhTW', '$p，就在眼前了！一起擊倒它吧！', '', 66384),
(283109, 'zhTW', '', '我們必須小心一點。我之前獨自嘗試潛入都沒有成功。', 66384),
(283108, 'zhTW', '小心行事的階段結束了。我們會找到他們的領袖，直接挖出我們要的情報！', '', 66384),
(283107, 'zhTW', '', '阿拉特，你不該來這裡的。虛無太過強大了。', 66384),
(283105, 'zhTW', '艾蘭里亞，你得了解負責領導這項任務的是我。但我隨時歡迎你的協助。 ', '', 66384),
(283099, 'zhTW', '阿拉特，這就是艾蘭里亞不想讓你接觸的東西。無邊無際的黑暗。 ', '', 66384),
(283097, 'zhTW', '情況更糟…比我們在特洛古斯被虛無扭曲的時候還糟。但我…我會撐過去的，西爾朗。 ', '', 66384),
(283096, 'zhTW', '', '這就像溺水一樣，把雙手四處亂揮…我們會學會該怎麼游泳的。 ', 66384),
(283095, 'zhTW', '', '永晨！不！可惡！', 66384),
(283094, 'zhTW', '', '我們必須偵察…沒錯。對，偵察前方…', 66384),
(283093, 'zhTW', '我們必須先了解環境。來吧！ ', '', 66384),
(283088, 'zhTW', '傳送門開啟了。拿出你的勇氣吧…另一端只有黑暗等著我們。', '', 66384),
(283085, 'zhTW', '刃多雷可能是我們對抗虛無最強大的武器。我發誓會保護你們所有人。 ', '', 66384),
(283078, 'zhTW', '高階指揮官洛斯拉賽恩曾征戰無數個遙遠國度，所以我請他來領導這次的任務。 ', '', 66384),
(283077, 'zhTW', '$p，來吧，幫我校正法術。萬一情況不對，這能幫我們重新定位，回到博學者殿堂。', '', 66384),
(283076, 'zhTW', '奧姆里克，你做了該做的事。如果要阻止虛無風暴的話，我們必須深入其中。 ', '', 66384),
(283070, 'zhTW', '我已經很久沒看過這些城牆了。', '', 66384),
(283069, 'zhTW', '攝政王，確實很冒險，但這是阻止銀月城被圍攻的唯一辦法了。 ', '', 66384),
(283068, 'zhTW', '奧姆里克，利用虛無聖物闖入風暴…聽起來很冒險。', '', 66384),
(283067, 'zhTW', '$p，我找到深入風暴的方法了，但要進去…會很困難。', '', 66384),
(283055, 'zhTW', '真不可思議。你的表現不斷超出我的期待。', '', 66384),
(283054, 'zhTW', '', '戴西蒙斯，你想追尋力量。你想要的，薩拉塔斯沒辦法給你，但擊敗她就有機會。加入我們吧。', 66384),
(283053, 'zhTW', '…我露出馬腳了，對吧？', '', 66384),
(283052, 'zhTW', '', '我們不必創造更多衝突，甚至能從中找到盟友。戴西蒙斯很有潛力。', 66384),
(283051, 'zhTW', '聖光慈悲，我命令你們兩人放下武器！我們的敵人已經夠多了！', '', 66384),
(283050, 'zhTW', '我受過聖光的洗禮！你對真相則視而不見！', '', 66384),
(283049, 'zhTW', '因為害怕被欺騙而對暗影發動攻擊？洛斯拉賽恩，你這個納斯雷茲姆還真特別。', '', 66384),
(283048, 'zhTW', '阿拉特，你可是個聖騎士啊！你必須看清戴西蒙斯是個什麼樣的怪物！', '', 66384),
(283046, 'zhTW', '我們該走了！', '', 66384),
(283045, 'zhTW', '你一直在破壞我們的行動！戴西蒙斯，消失吧！', '', 66384),
(283044, 'zhTW', '$n，你一定也感覺到了。有人想背叛我們。我知道該怎麼做。', '', 66384),
(283043, 'zhTW', '情況怎麼變這麼糟？聖光之力降臨的世界還離我們很遙遠。', '', 66384),
(283042, 'zhTW', '我等不及想看你還會造成什麼破壞了。', '', 66384),
(283041, 'zhTW', '你和風行者女士真是太厲害了。在我無數的旅途中，我從未遇過這麼有才幹的凡人。', '', 66384),
(283040, 'zhTW', '奧斯崔，堅持住。抓緊我的手。', '', 66384),
(283038, 'zhTW', '', '低語越來越誘人，但我們意志堅定。我們必須完成任務。', 66384),
(283023, 'zhTW', '我會的。我相信你。', '', 66384),
(283022, 'zhTW', '', '阿拉特，你必須確保戴西蒙斯不會受到傷害。他握有我們需要的解答。相信我。', 66384),
(283021, 'zhTW', '母親，你付出了這麼大的代價…我們得撤退，養精蓄銳。', '', 66384),
(283014, 'zhTW', '', '阿拉特！不！', 66384),
(283013, 'zhTW', '虛無！力量太強了！', '', 66384),
(283012, 'zhTW', '', '死的不是她就是我們！我們必須奮戰！', 66384),
(283010, 'zhTW', '不！你…必須…！', '', 66384),
(283009, 'zhTW', '', '就算是明亮的聖光，也會照出陰影。', 66384),
(283008, 'zhTW', '想都別想！', '', 66384),
(283004, 'zhTW', '', '不，洛斯拉賽恩！$n，我們需要你的雙眼。', 66384),
(283003, 'zhTW', '這樣拖太久了。讓開，我來敲碎這該死的東西。', '', 66384),
(283002, 'zhTW', '薩拉塔斯，別再威脅我了！你會得到那魯，我也會拿到應得的報酬！', '', 66384),
(283001, 'zhTW', '', '薩哈達爾，你的敵人已經快速展開行動了。你最好努力讓那魯轉化，不要又錯失先機了。', 66384),
(283000, 'zhTW', '', '可惜艾蘭里亞必須死。她的黑暗那魯會是更強力的武器。', 66384),
(282998, 'zhTW', '他們休想阻止我！不可能！影衛，殺光他們！', '', 66384),
(282996, 'zhTW', '', '洛斯拉賽恩，讓敵人見識你的滿腔熱血吧。也別忘了，我和他們不一樣。', 66384),
(282995, 'zhTW', '阿拉特，多加留意你的母親和她的鷹犬。我可不想讓它失去聖光的庇護。', '', 66384),
(282994, 'zhTW', '在那裡！它被關在屏障裡面！', '', 66384),
(282993, 'zhTW', '虛無生物，離那魯遠點。你沒有資格受它的光輝照耀！', '', 66384),
(282991, 'zhTW', '我們不能坐視不管。洛斯拉賽恩，我會助你一臂之力。', '', 66384),
(282990, 'zhTW', '他們囚禁了那魯？我們不能讓這些怪物掌握純潔的聖光生物！', '', 66384),
(282989, 'zhTW', '風行者無法阻止我把那魯轉化為虛無。我會得到許諾給我的力量！', '', 66384),
(282988, 'zhTW', '聖光必勝。我預估戴西蒙斯連像樣的反抗都做不到。', '', 66384),
(282987, 'zhTW', '蠢貨，在聖光之下燃燒吧！', '', 66384),
(282986, 'zhTW', '', '那你最好趕快消滅她，是吧？你已經讓她逍遙太久了。', 66384),
(282985, 'zhTW', '你以為我沒發現你設下的陷阱？要是在米達爾的行動失敗，我的人民將面對多大的危險？', '', 66384),
(282984, 'zhTW', '', '薩哈達爾，你竟然如此忘恩負義。我給了你一份天大的禮物，一個證明自己有權統治的機會。', 66384),
(282983, 'zhTW', '這跟說好的不一樣！我們不停地工作，一舉一動都被你的怪物監視！', '', 66384),
(282982, 'zhTW', '那又怎麼樣？搜刮我們需要的資源之後，把這座熔爐夷為平地吧。他們最好跟秘密一同燒成灰燼。', '', 66384),
(282981, 'zhTW', '', '薩拉塔斯不會平白放過她的敵人。查出以太族在這裡做些什麼。', 66384),
(282977, 'zhTW', '我正想說一樣的話。', '', 66384),
(282976, 'zhTW', '', '我們會奪取那些容器，干擾他們的行動。阿拉特，跟緊我。', 66384),
(282974, 'zhTW', '啊，以太族。薩拉塔斯不久前才將他們納入麾下。', '', 66384),
(282970, 'zhTW', '', '我們的斥侯在南邊發現一座以太法力熔爐，但還不確定他們在計畫什麼。', 66384),
(282950, 'zhTW', '', '哈朗達是個危險的地方。', 66384),
(282688, 'zhTW', '', '日擊，你很幸運，這麼久了，我們都還沒把你的公寓收回來。', 66384),
(282683, 'zhTW', '', '我需要通知你，拔毛鳳凰再也不歡迎你光顧。祝你有美好的一天。', 66384),
(282544, 'zhTW', '呃，差不多。\n\n<他翻到日誌後面。貼滿了基德溫和塔瑞納爾在各個景點、觀光名勝和酒吧拍下的照片。每張照片下面都有簡短的標題。>\n\n它也是一本旅行日誌。', '', 66384),
(282531, 'zhTW', '喔，那個啊。你看。\n\n<基德溫拿出日誌，隨意翻到某一頁。>\n\n我們記錄了我們點的每一杯酒…至少我們記得的都記下來了。\n\n<他自豪地指著某一項。>\n\n這週我有三天都喝得比塔瑞納爾多！', '', 66384),
(282529, 'zhTW', '你看到不動產的價格了嗎？我在利率很低的時候買了這個地方。現在萬物齊漲，它變得比我買下時值錢了不少。\n\n不過，當我們到處旅行的時候，很難讓它保持整潔。基德溫認為我應該賣掉它。\n\n也許我能把它短期出租。我可以叫它「飛行租賃」。\n\n不行，那聽起來像是馬戲表演。我會想個更好的說法。', '', 66384),
(282522, 'zhTW', '再次謝謝你的幫忙，$p。我們寄出所有紀念品。現在，我們只需要讓這個地方恢復原貌。', '', 66384),
(282516, 'zhTW', '我們正在清掃這個地方。我們其實收到了一張支票，賣掉那條項鍊抵償債務後，居然還剩下一些金幣。真讓人不敢相信。\n\n<塔瑞納爾大笑。>\n\n我猜它的來歷讓市場的一些人很興奮。', '', 66384),
(282515, 'zhTW', '你是說，為什麼我們拋下它，或是說，為什麼沒人收回一切？\n\n<基德溫想了一下。>\n\n為什麼他還沒賣掉這個地方？我們幾乎沒來過這裡。在它閒置的時候，該付的錢還是得付。\n\n總而言之，第四次大戰爆發時，我們不得不逃離銀月城。沒太多時間好好打掃。\n\n<他回頭看著那隻蜘蛛。>\n\n那該死的傢伙一定到處尋找我們存放的藥水。', '', 66384),
(282512, 'zhTW', '我不打算把一切清理乾淨。只是需要找到值錢的東西，抵償欠下的酒錢。', '', 66384),
(282498, 'zhTW', '喔，我們進去裡面吧！喝了酒，你的挖苦就沒那麼討人厭了。', '', 66384),
(282497, 'zhTW', '嗯…他們也許會讓我進去，但你大概不行。你沒達到身高限制。', '', 66384),
(282496, 'zhTW', '是啊。我們上次來這裡已經是很久以前的事了。鉤刺之泉會放我們進去嗎？', '', 66384),
(282495, 'zhTW', '喔！那裡面記錄了不少美好的回憶。還有一些慘事。', '', 66384),
(282494, 'zhTW', '這間公寓簡直一團亂。不過，我找到我們以前的旅行日誌了。', '', 66384),
(282492, 'zhTW', '基德溫充滿防備地低聲碎唸。', '', 66384),
(282491, 'zhTW', '所以…發生了什麼事？基德溫，你鬍子上的是蜘蛛網嗎？', '', 66384),
(282490, 'zhTW', '', '太讚了。謝謝你。那應該能抵銷你的欠款。', 66384),
(282487, 'zhTW', '拿去。這應該足夠抵償我們的欠債…外加很多年的利息。', '', 66384),
(282408, 'zhTW', '我的意識當時被佔據，那並非是虛無所為，而是聖光本身。我什麼都看不見，隨後釋放出了一股力量…那感覺是一種火焰。等我恢復知覺的時候，它們全都被消滅了。\n\n抱歉，$p。那種感覺已經消退了。我們必須盡全力幫助銀月城的居民。', '', 66384),
(282366, 'zhTW', '怎樣？我得到教訓啦！得要隨時小心蛛網的黏液。', '', 66384),
(282365, 'zhTW', '噢，這樣好多了。', '', 66384),
(282338, 'zhTW', '我的這個朋友會幫基德溫找到那筆錢。應該很快就會找到。', '', 66384),
(282318, 'zhTW', '$p，你需要我的協助嗎？\n\n我可以在這場戰鬥中幫助你！只要我們同心協力，就能擊退這個吞噬宿主！', '$p，你需要我的協助嗎？\n\n我可以在這場戰鬥中幫助你！只要我們同心協力，就能擊退這個吞噬宿主！', 66384),
(282078, 'zhTW', '你看起來不像是學生。你在這裡做什麼？', '你看起來不像是學生。你在這裡做什麼？', 66384),
(282077, 'zhTW', '你沒看到我很忙嗎？', '你沒看到我很忙嗎？', 66384),
(282076, 'zhTW', '唉，真希望泰塔勒能注意到我！或許我還能升到資深追隨者II！', '唉，真希望泰塔勒能注意到我！或許我還能升到資深追隨者II！', 66384),
(282075, 'zhTW', '哼，所以你是泰塔勒的新寵兒嗎？', '哼，所以你是泰塔勒的新寵兒嗎？', 66384),
(282074, 'zhTW', '像你這樣的烏合之眾找我做什麼？', '像你這樣的烏合之眾找我做什麼？', 66384),
(282073, 'zhTW', '沒看到我很忙嗎？你想做什麼？', '沒看到我很忙嗎？你想做什麼？', 66384),
(281893, 'zhTW', '啊，那魯…他們實在是難以解釋。他們並不來自於這個世界，恐怕我對他們的起源也所知甚少。但解釋那魯最簡單的方式就是，他們是聖光的展現，也是具有神聖能量的有意識實體。\n\n他們最親近的盟友就屬德萊尼。很久以前，當薩格拉斯抵達埃雷達爾的阿古斯家園時，預言者費倫感知到事情不太對勁。他祈求幫助，而那魯也回應了他的祈求，將費倫和他志同道合的埃雷達爾帶往安全處所。\n\n在那魯的協助下，這些埃雷達爾逃離了他們的世界，最終將自己重新命名為德萊尼，或是「被放逐者」。自此之後，那魯與德萊尼便建立起不可分割的關係。', '', 66384),
(281891, 'zhTW', '凱爾薩斯‧逐日者是安納斯提安‧逐日者國王膝下的獨子，但他可不只是一名王子。他同時是一名強大的法師，在達拉然的統治議會「六法議會」中也佔有一席之地。沒錯，他大部分的時間都是在達拉然度過的。\n\n但當他的父王在第三次大戰中被殺後，凱爾薩斯只能孤身接下領導者的重擔。因為太陽之井受到汙染，凱爾薩斯不得不將其摧毀。凱爾薩斯回來之後召集了剩餘的族人，將他們命名為血精靈，以紀念他們死去的同胞。\n\n不幸的是，凱爾薩斯最終為了拯救他的人民，而踏上了黑暗的不歸路。', '', 66384),
(281794, 'zhTW', '', '你想剝奪這座城市渴望的力量？先吃我這招！', 66384),
(281787, 'zhTW', '', '卑鄙小人！', 66384),
(281780, 'zhTW', '莉希爾，到此為止了！', '', 66384),
(281764, 'zhTW', '', '只要銀月城有需要，我就會給人們魔能。', 66384),
(281459, 'zhTW', '就這樣嗎？', '', 66384),
(281458, 'zhTW', '現在是什麼狀況？', '', 66384),
(281425, 'zhTW', '', '把他們收拾掉！要是他們跟來，你就死定了！', 66384),
(281394, 'zhTW', '我還沒真正被打敗…是我自己選擇撤退的！', '', 66384),
(281393, 'zhTW', '不！你…你給我記住！', '', 66384),
(281391, 'zhTW', '你是誰？誰讓你進來的？', '', 66384),
(281390, 'zhTW', '', '贊恩，真散漫。把這裡收拾乾淨後到樓上找我。', 66384),
(281369, 'zhTW', '', '你們就盡力反抗吧。', 66384),
(281368, 'zhTW', '', '你會是個很好的示範。', 66384),
(281223, 'zhTW', '', '你真以為會這麼簡單嗎？', 66384),
(280973, 'zhTW', '博學者殿堂。\n\n我在這裡渡過我的年輕歲月。在這裡學會第一個法術，在仲夏舞廳與莎蘿法‧金幕共舞，感覺…\n\n<奧姆里克嘆了口氣。>\n\n那些歲月已成往事追憶。這個地方變了，我也變了。我和我的族人不再受到歡迎。\n\n過往一去不復返。刃多雷必須打造自己的傳統，自己的家庭。\n\n自己的未來。', '', 66384),
(280965, 'zhTW', '讓我們族人的回憶永不磨滅的地方。接受挑戰和試煉的地方。\n\n那裡能浸沐在艾恩哈拉的恩賜之中。或被她摧毀。', '', 66384),
(280963, 'zhTW', '歐薇娜打破了我們的律法和習俗。回音之穴會教你我們的行事風格，並要你接受挑戰，證明自己。\n\n如果你順利回來，就代表艾恩哈拉准許你留下來。我不認為會再次見到你。', '', 66384),
(280955, 'zhTW', '回音之穴是一個存放庫，裡面充滿我族人的回憶。透過重溫祖先的言行和試煉，我們學習、成長，並確保歷史不會重演。\n\n那些壁畫是體驗這些回憶和試煉的途徑。如果你成功生還，就能進一步了解哈朗達和我的族人。\n\n碰觸石頭就會引發幻象。願艾恩哈拉與你同在。', '', 66384),
(280860, 'zhTW', '', '就連虛無也無法與這股力量相抗衡！', 66384),
(280686, 'zhTW', '這裡比平常還要繁忙。我們必須盡快行動。', '', 66384),
(280669, 'zhTW', '<祝福祭壇在你接近時進入了活化狀態。>', '<祝福祭壇在你接近時進入了活化狀態。>', 66384),
(280626, 'zhTW', '我沒想到血色十字軍會在這裡動作頻頻，$p。\n\n血色十字軍經歷過不少挫折，不過很顯然他們又重新崛起了。', '', 66384),
(280596, 'zhTW', '', '我們繼續前往哈拉希爾吧。我不認為我們會受到熱烈歡迎。\n\n去找赫杜倫，看看他能不能馬上啟程。', 66384),
(280528, 'zhTW', '兇殺路比平常更繁忙。我們得謹慎一點。\n\n我們必須終結這個走私事業。為此，我們必須追蹤禁忌之雨。有人私下透露，這一區某些異類可能對最近活絡起來的魔能市場有所了解。\n\n找出他們，看看你能有什麼發現。小心一點。兇殺路的混混一點都不值得信任。', '', 66384),
(280415, 'zhTW', '$p，你為太陽之井提供了難能可貴的幫助。但我們還必須做更多，才能幫助阿拉特。\n\n你願意跟我們一起到落錘鎮拜訪一個朋友嗎？', '', 66384),
(280390, 'zhTW', '<霍在火前跳舞，沐浴在溫暖中。他為你找到了他而高興！>', '', 66384),
(280340, 'zhTW', '', '虛無賦予我們力量，但代價是什麼？', 66384),
(280227, 'zhTW', '', '是誰在四處打探？快給我出來，鬼鬼祟祟的傢伙！', 66384),
(280214, 'zhTW', '未來捉摸不定…你確定已經準備好探索你的命運了嗎？', '未來捉摸不定…你確定已經準備好探索你的命運了嗎？', 66384),
(280009, 'zhTW', '你真沒用！', '', 66384),
(280008, 'zhTW', '太完美了！報酬？你可以透過這件事來提高曝光度！', '', 66384),
(279817, 'zhTW', '在暴風城擊殺恩若司的精英爪牙，強化這個貢品。', '在暴風城擊殺恩若司的精英爪牙，強化這個貢品。', 66384),
(279791, 'zhTW', '除掉一個擋路的傢伙了。很好。前往禁忌之雨。\n\n不過，你這個樣子一定會被拒於門外。幸好，我順利幫你…弄到一些偽裝。\n\n穿上這些，然後進去裡面。我會在這裡擋住所有潛在的刺客。', '', 66384),
(279591, 'zhTW', '那些動物沒受到永久性的傷害。謝謝你把牠們找回來。', '', 66384),
(279589, 'zhTW', '有不少生物逃出秘境。牠們在外面無法存活，馬上去把牠們找回來！', '', 66384),
(279487, 'zhTW', '你遲到了。你看不到有顧客在等嗎？快點開工。', '', 66384),
(279110, 'zhTW', '至於我自己…我會持續彈奏，直到她們回家為止。各位勇士，謝謝。', '', 66384),
(279109, 'zhTW', '我希望我的姐姐們有天也能放下重擔。', '', 66384),
(279108, 'zhTW', '流連在這個殿堂裡的靈魂終於能安息了。', '', 66384),
(279102, 'zhTW', '就在那！是那顆糾纏我們的躁動之心！請讓它安息吧。', '', 66384),
(279051, 'zhTW', '我會用這些文物讓風行者塔回歸平靜。這樣我的姐姐們或許就會回到我身邊了。', '', 66384),
(279050, 'zhTW', '我們成功了！現在只剩一件事要做。', '', 66384),
(279049, 'zhTW', '艾蘭里亞的其中一張偵察地圖就在裡面。它似乎召喚了過去的復仇鬼魂。我們需要從它們那裡奪走那張地圖。', '', 66384),
(279014, 'zhTW', '這是有正當理由的。他們奪走我的性命，蹂躪我們的家園。', '', 66384),
(279013, 'zhTW', '艾蘭里亞獵殺舊部落時展現的兇猛，幾乎到了著魔的地步。', '', 66384),
(279011, 'zhTW', '來吧，我們還有一個文物要找。', '', 66384),
(278997, 'zhTW', '太棒了！她讓我想起凡蕾莎。當家人受到威脅時，我的姐姐也會挺身而出。', '', 66384),
(278992, 'zhTW', '不過…那頭龍鷹把我的豎琴偷走了。她可不會輕易讓你靠近。', '', 66384),
(278991, 'zhTW', '豎琴柔和的旋律能為凡蕾莎帶來無與倫比的喜悅。我需要那個文物。', '', 66384),
(278990, 'zhTW', '凡蕾莎是我們家族的守護者。她會在這裡花上好幾天的時間照料花園，但現在這個地方已經被荒野吞噬了。', '', 66384),
(278985, 'zhTW', '我們來找下一個文物吧。', '', 66384),
(278983, 'zhTW', '雖然希瓦娜斯有時很自負，喜歡成為眾人的焦點，但她從來都不想被人崇拜。', '', 66384),
(278964, 'zhTW', '曾經，母親的弓對希瓦娜斯意義重大。我會需要它。', '', 66384),
(278959, 'zhTW', '她曾用母親贈與的弓進行訓練。但在瘋狂的不死族入侵後，這把弓和她的所有東西就被搶走了。', '', 66384),
(278952, 'zhTW', '希瓦娜斯不是自願擔任遊俠將軍的，但她為此獻出了一切…包括她的性命。', '', 66384),
(278951, 'zhTW', '遊俠將軍機警堅定，守護者則沉著冷靜。你會選擇哪條道路？', '', 66384),
(278948, 'zhTW', '我的姐姐們是最後造訪這裡的人，但她們拋棄了家園，也拋棄了家族的羈絆。如果我們能安撫這裡的靈魂，她們或許就會回來了。', '', 66384),
(278747, 'zhTW', '你就這麼點本事？', '你就這麼點本事？', 66384),
(278746, 'zhTW', '不許逃跑！', '不許逃跑！', 66384),
(278738, 'zhTW', '戰！戰！戰！', '戰！戰！戰！', 66384),
(278737, 'zhTW', '嘿！快回去裡面！', '嘿！快回去裡面！', 66384),
(275545, 'zhTW', '', '噢，就在…好吧，是無所不在！', 66384),
(275540, 'zhTW', '', '這次要打得有趣一點！', 66384),
(273693, 'zhTW', '歡迎回來，$p。你把溫暖帶回了我們的家。', '', 66384),
(268910, 'zhTW', '我不知道把最新的發現放去哪裡了。你可以等等再來嗎？', '', 66384),
(268724, 'zhTW', '喔，我早就送給她三百隻了。不過，我相信宮廷那邊一定會感謝你的「付出」。', '喔，我早就送給她三百隻了。不過，我相信宮廷那邊一定會感謝你的「付出」。', 66384),
(268723, 'zhTW', '你響應了女王獻上幼蛛的要求嗎？我已經貢獻30隻了。', '你響應了女王獻上幼蛛的要求嗎？我已經貢獻30隻了。', 66384),
(267595, 'zhTW', '', '我覺得我們浪費太多時間呆站著了。如果土靈要戰鬥，那就讓他們戰鬥吧。我不了解這場集會的意義是什麼。', 66384),
(262893, 'zhTW', '', '寒冰殲滅一切。', 66384),
(262886, 'zhTW', '', '讓我來吧。', 66384),
(262675, 'zhTW', '魯夫厄斯，你真以為你可以這樣奪走我的礦車嗎？可悲！', '', 66384),
(262374, 'zhTW', '入侵者全數消滅。我的職責已盡。', '', 66384),
(262372, 'zhTW', '我的力量無人能敵！', '', 66384),
(260466, 'zhTW', '幹得好，隊員。烏茲傑克斯的手下應該知道別亂動我們的礦車了！', '', 66384),
(250694, 'zhTW', '', '這可能是個大發現！我要告訴大家這件事…現在就要！', 66384),
(250693, 'zhTW', '', '好像有個大東西鬆動了。這絕對是世紀大發現。我們開始挖吧！', 66384),
(244906, 'zhTW', '', '哇，這些真不錯，在我們交出去之前，先偷吃個一、二朵，應該不會有人發現吧？', 66384),
(244905, 'zhTW', '', '一碗豐盛的湯應該可以提振大家的精神。我們找到了美味又可食用的蘑菇，你可以去採一些回來嗎？', 66384),
(236457, 'zhTW', '<各式各樣的硬幣和寶石四處散落在祭品堆附近。許多追隨者來此致敬，但是卻少了某些寶石，這可能會讓人認為，今天的儀式還沒完成。>', '<各式各樣的硬幣和寶石四處散落在祭品堆附近。許多追隨者來此致敬，但是卻少了某些寶石，這可能會讓人認為，今天的儀式還沒完成。>', 66384),
(235955, 'zhTW', '你好，虛空領主。\n\n我們術士很少受邀參加這麼高級的場合。我們習慣在暗影中悄悄行動，很少有人會表揚我們為了守護艾澤拉斯與部落安危的努力。\n\n我想，能有這樣的改變都歸功於你。', '', 66384),
(222843, 'zhTW', '', '這樣應該能爭取到時間喘口氣，紅龍軍團感激你。', 66384),
(222842, 'zhTW', '', '由於洪荒使者多次進攻，晶紅生命聖殿的防線拉得很長、變得很脆弱，請去支援他們。', 66384);
